        private void OpenLayersDialog()
        {
            EnsureObjectLayerAssignments();
            List<LayerDefinition> originalLayers = documentLayers.Select(layer => layer.Clone()).ToList();
            string originalActiveLayerId = activeLayerId;

            using (var dialog = new LayerManagementDialog(
                documentLayers.Select(layer => layer.Clone()).ToList(),
                activeLayerId,
                exportVisibleLayersOnly,
                BuildLayerUsageCounts(),
                CurrentTheme.BorderColor,
                CurrentTheme.SelectionBackColor,
                CurrentTheme.SectionBackColor))
            {
                dialog.PreviewChanged += (previewLayers, previewActiveLayerId) =>
                    ApplyLayerConfiguration(previewLayers, previewActiveLayerId, markProjectChanged: false);

                if (dialog.ShowDialog(this) != DialogResult.OK)
                {
                    ApplyLayerConfiguration(originalLayers, originalActiveLayerId, markProjectChanged: false);
                    return;
                }

                List<LayerDefinition> updatedLayers = dialog.GetLayers();
                ApplyLayerDeletionActions(dialog.GetLayerDeletionActions(), updatedLayers);
                exportVisibleLayersOnly = dialog.GetExportVisibleLayersOnly();
                ApplyLayerConfiguration(updatedLayers, dialog.GetActiveLayerId(), markProjectChanged: true);
            }
        }

        private void ApplyLayerDeletionActions(
            IEnumerable<LayerManagementDialog.LayerDeletionAction> actions,
            IEnumerable<LayerDefinition> resultingLayers)
        {
            List<LayerManagementDialog.LayerDeletionAction> actionList = (actions ?? Enumerable.Empty<LayerManagementDialog.LayerDeletionAction>())
                .Where(action => action != null)
                .Select(action => action.Clone())
                .Where(action => action != null && !string.IsNullOrWhiteSpace(action.SourceLayerId))
                .ToList();
            if (actionList.Count == 0)
            {
                return;
            }

            var targetLayerIds = new HashSet<string>(
                (resultingLayers ?? Enumerable.Empty<LayerDefinition>())
                    .Where(layer => layer != null)
                    .Select(layer => NormalizeLayerIdValue(layer.Id)),
                StringComparer.OrdinalIgnoreCase);

            string fallbackTargetLayerId = targetLayerIds.Contains(WorkLayerId)
                ? WorkLayerId
                : (targetLayerIds.Contains(DefaultLayerId) ? DefaultLayerId : WorkLayerId);

            void MoveObjects(string sourceLayerId, string targetLayerId)
            {
                foreach (RedactionBlock block in redactionBlocks.Where(block => block != null && string.Equals(NormalizeLayerIdValue(block.LayerId), sourceLayerId, StringComparison.OrdinalIgnoreCase)))
                {
                    block.LayerId = targetLayerId;
                }

                foreach (CommentAnnotation comment in commentAnnotations.Where(comment => comment != null && string.Equals(NormalizeLayerIdValue(comment.LayerId), sourceLayerId, StringComparison.OrdinalIgnoreCase)))
                {
                    comment.LayerId = targetLayerId;
                }

                foreach (TextAnnotation annotation in textAnnotations.Where(annotation => annotation != null && string.Equals(NormalizeLayerIdValue(annotation.LayerId), sourceLayerId, StringComparison.OrdinalIgnoreCase)))
                {
                    annotation.LayerId = targetLayerId;
                }

                foreach (RasterObject rasterObject in rasterObjects.Where(rasterObject => rasterObject != null && string.Equals(NormalizeLayerIdValue(rasterObject.LayerId), sourceLayerId, StringComparison.OrdinalIgnoreCase)))
                {
                    rasterObject.LayerId = targetLayerId;
                }

                foreach (ArrowObject arrowObject in arrowObjects.Where(arrowObject => arrowObject != null && string.Equals(NormalizeLayerIdValue(arrowObject.LayerId), sourceLayerId, StringComparison.OrdinalIgnoreCase)))
                {
                    arrowObject.LayerId = targetLayerId;
                }

                foreach (VectorShapeObject vectorShape in vectorShapes.Where(vectorShape => vectorShape != null && string.Equals(NormalizeLayerIdValue(vectorShape.LayerId), sourceLayerId, StringComparison.OrdinalIgnoreCase)))
                {
                    vectorShape.LayerId = targetLayerId;
                }
            }

            void DeleteObjects(string sourceLayerId)
            {
                redactionBlocks.RemoveAll(block => block != null && string.Equals(NormalizeLayerIdValue(block.LayerId), sourceLayerId, StringComparison.OrdinalIgnoreCase));
                commentAnnotations.RemoveAll(comment => comment != null && string.Equals(NormalizeLayerIdValue(comment.LayerId), sourceLayerId, StringComparison.OrdinalIgnoreCase));
                textAnnotations.RemoveAll(annotation => annotation != null && string.Equals(NormalizeLayerIdValue(annotation.LayerId), sourceLayerId, StringComparison.OrdinalIgnoreCase));
                rasterObjects.RemoveAll(rasterObject => rasterObject != null && string.Equals(NormalizeLayerIdValue(rasterObject.LayerId), sourceLayerId, StringComparison.OrdinalIgnoreCase));
                arrowObjects.RemoveAll(arrowObject => arrowObject != null && string.Equals(NormalizeLayerIdValue(arrowObject.LayerId), sourceLayerId, StringComparison.OrdinalIgnoreCase));
                vectorShapes.RemoveAll(vectorShape => vectorShape != null && string.Equals(NormalizeLayerIdValue(vectorShape.LayerId), sourceLayerId, StringComparison.OrdinalIgnoreCase));
            }

            foreach (LayerManagementDialog.LayerDeletionAction action in actionList)
            {
                string sourceLayerId = NormalizeLayerIdValue(action.SourceLayerId);
                if (string.IsNullOrWhiteSpace(sourceLayerId))
                {
                    continue;
                }

                if (action.Action == LayerManagementDialog.LayerDeleteAction.DeleteObjects)
                {
                    DeleteObjects(sourceLayerId);
                    continue;
                }

                if (action.Action != LayerManagementDialog.LayerDeleteAction.MoveObjects)
                {
                    continue;
                }

                string targetLayerId = NormalizeLayerIdValue(action.TargetLayerId);
                if (string.IsNullOrWhiteSpace(targetLayerId) ||
                    string.Equals(targetLayerId, sourceLayerId, StringComparison.OrdinalIgnoreCase) ||
                    !targetLayerIds.Contains(targetLayerId))
                {
                    targetLayerId = fallbackTargetLayerId;
                }

                if (string.IsNullOrWhiteSpace(targetLayerId) || string.Equals(targetLayerId, sourceLayerId, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                MoveObjects(sourceLayerId, targetLayerId);
            }

            selectedTextAnnotation = null;
            selectedRasterObject = null;
            selectedArrowObject = null;
            selectedVectorShape = null;
            ClearGroupSelection();
            RefreshRedactionPreviewForCurrentPage(keepCurrentOverlay: true);
        }

        private void InitializeLayersTab()
        {
            if (layersTabPlaceholderPanel == null || layersPanelView != null)
            {
                return;
            }

            layersPanelView = new LayerPanelControl
            {
                Dock = DockStyle.Fill,
                Cursor = Cursors.Default
            };
            layersPanelView.CellClick += LayersPanelView_CellClick;
            layersPanelView.CellDoubleClick += LayersPanelView_CellDoubleClick;
            layersPanelView.MouseEnter += LayersInteractionSurface_MouseEnter;
            layersPanelView.MouseMove += LayersInteractionSurface_MouseMove;

            layersTabPlaceholderPanel.Controls.Clear();
            layersTabPlaceholderPanel.Cursor = Cursors.Default;
            layersTabPlaceholderPanel.MouseEnter += LayersInteractionSurface_MouseEnter;
            layersTabPlaceholderPanel.MouseMove += LayersInteractionSurface_MouseMove;
            layersTabPlaceholderPanel.Resize += (_, __) =>
            {
                layersTabPlaceholderPanel.Invalidate(true);
                layersPanelView?.Invalidate(true);
            };
            layersTabPlaceholderPanel.Controls.Add(layersPanelView);
            ApplyLayersTabLocalization();
            ApplyThemeToLayersGrid(CurrentTheme);
            RefreshLayersTab();
        }

        private void LayersInteractionSurface_MouseEnter(object sender, EventArgs e)
        {
            if (IsViewportPanningActive())
            {
                EndViewportPan();
            }

            Cursor = Cursors.Default;
        }

        private void LayersInteractionSurface_MouseMove(object sender, MouseEventArgs e)
        {
            if (!IsViewportPanningActive() && Cursor != Cursors.Default)
            {
                Cursor = Cursors.Default;
            }
        }

        private void PdfViewer_MouseEnter(object sender, EventArgs e)
        {
            UpdatePdfViewerToolCursor();
        }

        private void PdfViewer_MouseLeave(object sender, EventArgs e)
        {
            if (!IsViewportPanningActive())
            {
                this.Cursor = Cursors.Default;
            }

            if (pdfViewer != null)
            {
                pdfViewer.Cursor = Cursors.Default;
            }
        }

        private void UpdatePdfViewerToolCursor()
        {
            if (pdfViewer == null)
            {
                return;
            }

            if (isVectorShapeCreationMode)
            {
                pdfViewer.Cursor = Cursors.Cross;
                if (!IsViewportPanningActive())
                {
                    this.Cursor = Cursors.Cross;
                }
                return;
            }

            if (isCommentCreationMode || IsRedactionSelectionModeEnabled())
            {
                pdfViewer.Cursor = Cursors.IBeam;
                if (!IsViewportPanningActive())
                {
                    this.Cursor = Cursors.IBeam;
                }
                return;
            }

            pdfViewer.Cursor = Cursors.Default;
            if (!IsViewportPanningActive())
            {
                this.Cursor = Cursors.Default;
            }
        }

        private void SyncPdfViewerCursorWithFormCursor()
        {
            if (pdfViewer == null)
            {
                return;
            }

            pdfViewer.Cursor = this.Cursor;
        }

        private void ApplyLayerConfiguration(IEnumerable<LayerDefinition> layers, string nextActiveLayerId, bool markProjectChanged)
        {
            List<LayerDefinition> previousLayers = documentLayers
                .Select(layer => layer?.Clone())
                .Where(layer => layer != null)
                .ToList();
            List<LayerDefinition> normalizedLayers = NormalizeLayerDefinitions((layers ?? Enumerable.Empty<LayerDefinition>())
                .Select(layer => layer?.Clone())
                .Where(layer => layer != null)
                .ToList());
            bool visibilityChanged = HasLayerVisibilityChanged(previousLayers, normalizedLayers);
            bool previewNeedsRefresh = visibilityChanged && DoesLayerVisibilityChangeAffectCurrentPreview(previousLayers, normalizedLayers);
            documentLayers = normalizedLayers;
            activeLayerId = NormalizeLayerIdValue(nextActiveLayerId);
            EnsureObjectLayerAssignments();
            PruneInvisibleLayerInteractionState();
            delayCommentAndSelectionOverlayUntilPreviewReady = previewNeedsRefresh;
            RefreshLayersTab();
            if (previewNeedsRefresh)
            {
                ShowRedactPreview();
            }
            pagesListView?.Invalidate();
            thumbnailsListView?.Invalidate();
            pdfViewer?.Invalidate();

            if (markProjectChanged)
            {
                projectWasChangedAfterLastSave = true;
                SyncProjectChangedFlagWithStateSignature();
            }
        }

        private void QueueLayerPanelApply(IEnumerable<LayerDefinition> layers, string nextActiveLayerId)
        {
            pendingLayerPanelApplyLayers = (layers ?? Enumerable.Empty<LayerDefinition>())
                .Select(layer => layer?.Clone())
                .Where(layer => layer != null)
                .ToList();
            pendingLayerPanelApplyActiveLayerId = NormalizeLayerIdValue(nextActiveLayerId);
            LogDebug($"LayerPanel queue active={pendingLayerPanelApplyActiveLayerId} pendingCount={pendingLayerPanelApplyLayers.Count}");
            RefreshLayersTab();

            if (layerPanelApplyTimer == null)
            {
                layerPanelApplyTimer = new Timer
                {
                    Interval = 160
                };
                layerPanelApplyTimer.Tick += (_, __) =>
                {
                    layerPanelApplyTimer.Stop();
                    List<LayerDefinition> layersToApply = pendingLayerPanelApplyLayers;
                    string activeLayerToApply = pendingLayerPanelApplyActiveLayerId;

                    if (layersToApply == null)
                    {
                        return;
                    }

                    LogDebug($"LayerPanel apply active={activeLayerToApply} pendingCount={layersToApply.Count}");
                    ApplyLayerConfiguration(layersToApply, activeLayerToApply, markProjectChanged: true);
                    pendingLayerPanelApplyLayers = null;
                    pendingLayerPanelApplyActiveLayerId = null;
                    RefreshLayersTab();
                };
            }

            layerPanelApplyTimer.Stop();
            layerPanelApplyTimer.Start();
        }

        private IEnumerable<LayerDefinition> GetLayerPanelSourceLayers()
        {
            return pendingLayerPanelApplyLayers ?? documentLayers;
        }

        private string GetLayerPanelSourceActiveLayerId()
        {
            return string.IsNullOrWhiteSpace(pendingLayerPanelApplyActiveLayerId)
                ? activeLayerId
                : pendingLayerPanelApplyActiveLayerId;
        }

        private enum LayerPanelRowKind
        {
            Group,
            Layer
        }

        private sealed class LayerPanelRowTag
        {
            public LayerPanelRowKind Kind { get; set; }
            public string LayerId { get; set; }
            public string GroupName { get; set; }
        }

        private sealed class LayerPanelDisplayRow
        {
            public LayerPanelRowTag Tag { get; set; }
            public bool ShowActive { get; set; }
            public bool Active { get; set; }
            public CheckState VisibleState { get; set; }
            public CheckState LockedState { get; set; }
            public string Name { get; set; }
            public bool BoldName { get; set; }
            public int NameIndent { get; set; }
        }

        private enum LayerGroupVisibilityState
        {
            NoneVisible,
            AllVisible,
            Mixed
        }

        private sealed class LayerPanelGroupEntry
        {
            public string GroupName { get; set; }
            public int Order { get; set; }
            public List<LayerDefinition> Layers { get; } = new List<LayerDefinition>();
        }

        private static bool HasLayerVisibilityChanged(IEnumerable<LayerDefinition> previousLayers, IEnumerable<LayerDefinition> nextLayers)
        {
            var previousMap = (previousLayers ?? Enumerable.Empty<LayerDefinition>())
                .Where(layer => layer != null)
                .ToDictionary(layer => NormalizeLayerIdValue(layer.Id), layer => layer.IsVisible, StringComparer.OrdinalIgnoreCase);

            foreach (LayerDefinition layer in nextLayers ?? Enumerable.Empty<LayerDefinition>())
            {
                if (layer == null)
                {
                    continue;
                }

                string layerId = NormalizeLayerIdValue(layer.Id);
                bool previousVisible = previousMap.TryGetValue(layerId, out bool value) ? value : true;
                if (previousVisible != layer.IsVisible)
                {
                    return true;
                }
            }

            return false;
        }

        private bool DoesLayerVisibilityChangeAffectCurrentPreview(IEnumerable<LayerDefinition> previousLayers, IEnumerable<LayerDefinition> nextLayers)
        {
            if (currentPage <= 0)
            {
                return false;
            }

            var previousVisibility = (previousLayers ?? Enumerable.Empty<LayerDefinition>())
                .Where(layer => layer != null)
                .ToDictionary(layer => NormalizeLayerIdValue(layer.Id), layer => layer.IsVisible, StringComparer.OrdinalIgnoreCase);

            var changedLayerIds = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            foreach (LayerDefinition layer in nextLayers ?? Enumerable.Empty<LayerDefinition>())
            {
                if (layer == null)
                {
                    continue;
                }

                string layerId = NormalizeLayerIdValue(layer.Id);
                bool oldVisible = previousVisibility.TryGetValue(layerId, out bool previousValue) ? previousValue : true;
                if (oldVisible != layer.IsVisible)
                {
                    changedLayerIds.Add(layerId);
                }
            }

            if (changedLayerIds.Count == 0)
            {
                return false;
            }

            return redactionBlocks.Any(block =>
                       block != null &&
                       block.PageNumber == currentPage &&
                       changedLayerIds.Contains(NormalizeLayerIdValue(block.LayerId)))
                   || commentAnnotations.Any(comment =>
                       comment != null &&
                       comment.PageNumber == currentPage &&
                       changedLayerIds.Contains(NormalizeLayerIdValue(comment.LayerId)));
        }

        private static string NormalizeLayerGroupName(string groupName, bool forceNone = false)
        {
            if (forceNone)
            {
                return null;
            }

            string normalized = (groupName ?? string.Empty).Trim();
            return string.IsNullOrWhiteSpace(normalized) ? null : normalized;
        }

        private LayerGroupVisibilityState GetLayerGroupVisibilityState(string groupName, IEnumerable<LayerDefinition> sourceLayers = null)
        {
            string normalizedGroupName = NormalizeLayerGroupName(groupName);
            if (string.IsNullOrWhiteSpace(normalizedGroupName))
            {
                return LayerGroupVisibilityState.NoneVisible;
            }

            List<LayerDefinition> groupedLayers = (sourceLayers ?? documentLayers)
                .Where(layer => string.Equals(NormalizeLayerGroupName(layer.GroupName, string.Equals(NormalizeLayerIdValue(layer.Id), WorkLayerId, StringComparison.OrdinalIgnoreCase)), normalizedGroupName, StringComparison.CurrentCultureIgnoreCase))
                .ToList();
            if (groupedLayers.Count == 0)
            {
                return LayerGroupVisibilityState.NoneVisible;
            }

            if (groupedLayers.All(layer => layer.IsVisible))
            {
                LogDebug($"LayerPanel groupVisible group={normalizedGroupName} state=all values=[{string.Join(",", groupedLayers.Select(layer => layer.IsVisible ? "1" : "0"))}]");
                return LayerGroupVisibilityState.AllVisible;
            }

            if (groupedLayers.All(layer => !layer.IsVisible))
            {
                LogDebug($"LayerPanel groupVisible group={normalizedGroupName} state=none values=[{string.Join(",", groupedLayers.Select(layer => layer.IsVisible ? "1" : "0"))}]");
                return LayerGroupVisibilityState.NoneVisible;
            }

            LogDebug($"LayerPanel groupVisible group={normalizedGroupName} state=mixed values=[{string.Join(",", groupedLayers.Select(layer => layer.IsVisible ? "1" : "0"))}]");
            return LayerGroupVisibilityState.Mixed;
        }

        private LayerGroupVisibilityState GetLayerGroupLockedState(string groupName, IEnumerable<LayerDefinition> sourceLayers = null)
        {
            string normalizedGroupName = NormalizeLayerGroupName(groupName);
            if (string.IsNullOrWhiteSpace(normalizedGroupName))
            {
                return LayerGroupVisibilityState.NoneVisible;
            }

            List<LayerDefinition> groupedLayers = (sourceLayers ?? documentLayers)
                .Where(layer => string.Equals(NormalizeLayerGroupName(layer.GroupName, string.Equals(NormalizeLayerIdValue(layer.Id), WorkLayerId, StringComparison.OrdinalIgnoreCase)), normalizedGroupName, StringComparison.CurrentCultureIgnoreCase))
                .ToList();
            if (groupedLayers.Count == 0)
            {
                return LayerGroupVisibilityState.NoneVisible;
            }

            if (groupedLayers.All(layer => layer.IsLocked))
            {
                return LayerGroupVisibilityState.AllVisible;
            }

            if (groupedLayers.All(layer => !layer.IsLocked))
            {
                return LayerGroupVisibilityState.NoneVisible;
            }

            return LayerGroupVisibilityState.Mixed;
        }

        private bool SetLayerGroupVisibility(List<LayerDefinition> layers, string groupName, bool visible)
        {
            string normalizedGroupName = NormalizeLayerGroupName(groupName);
            if (string.IsNullOrWhiteSpace(normalizedGroupName))
            {
                return false;
            }

            bool changed = false;
            foreach (LayerDefinition layer in layers.Where(layer =>
                         string.Equals(NormalizeLayerGroupName(layer.GroupName, string.Equals(NormalizeLayerIdValue(layer.Id), WorkLayerId, StringComparison.OrdinalIgnoreCase)), normalizedGroupName, StringComparison.CurrentCultureIgnoreCase)))
            {
                if (layer.IsVisible != visible)
                {
                    layer.IsVisible = visible;
                    changed = true;
                }
            }

            return changed;
        }

        private bool SetLayerGroupLocked(List<LayerDefinition> layers, string groupName, bool locked)
        {
            string normalizedGroupName = NormalizeLayerGroupName(groupName);
            if (string.IsNullOrWhiteSpace(normalizedGroupName))
            {
                return false;
            }

            bool changed = false;
            foreach (LayerDefinition layer in layers.Where(layer =>
                         string.Equals(NormalizeLayerGroupName(layer.GroupName, string.Equals(NormalizeLayerIdValue(layer.Id), WorkLayerId, StringComparison.OrdinalIgnoreCase)), normalizedGroupName, StringComparison.CurrentCultureIgnoreCase)))
            {
                if (layer.IsLocked != locked)
                {
                    layer.IsLocked = locked;
                    changed = true;
                }
            }

            return changed;
        }

        private List<object> BuildLayerPanelEntries()
        {
            var orderedLayers = GetLayerPanelSourceLayers()
                .OrderBy(layer => layer.Order)
                .ToList();
            var entries = new List<object>();
            var groupedEntries = orderedLayers
                .Where(layer => !string.IsNullOrWhiteSpace(NormalizeLayerGroupName(layer.GroupName, string.Equals(NormalizeLayerIdValue(layer.Id), WorkLayerId, StringComparison.OrdinalIgnoreCase))))
                .GroupBy(layer => NormalizeLayerGroupName(layer.GroupName, string.Equals(NormalizeLayerIdValue(layer.Id), WorkLayerId, StringComparison.OrdinalIgnoreCase)), StringComparer.CurrentCultureIgnoreCase)
                .Select(group =>
                {
                    var entry = new LayerPanelGroupEntry
                    {
                        GroupName = group.Key,
                        Order = group.Min(layer => layer.Order)
                    };
                    entry.Layers.AddRange(group.OrderBy(layer => layer.Order));
                    return entry;
                })
                .OrderBy(entry => entry.Order)
                .ToList();
            var groupedNames = new HashSet<string>(groupedEntries.Select(entry => entry.GroupName), StringComparer.CurrentCultureIgnoreCase);

            foreach (LayerDefinition layer in orderedLayers)
            {
                string normalizedGroupName = NormalizeLayerGroupName(layer.GroupName, string.Equals(NormalizeLayerIdValue(layer.Id), WorkLayerId, StringComparison.OrdinalIgnoreCase));
                if (string.IsNullOrWhiteSpace(normalizedGroupName))
                {
                    entries.Add(layer);
                    continue;
                }

                if (!groupedNames.Remove(normalizedGroupName))
                {
                    continue;
                }

                LayerPanelGroupEntry groupEntry = groupedEntries.FirstOrDefault(entry =>
                    string.Equals(entry.GroupName, normalizedGroupName, StringComparison.CurrentCultureIgnoreCase));
                if (groupEntry == null)
                {
                    continue;
                }

                entries.Add(groupEntry);
                entries.AddRange(groupEntry.Layers);
            }

            return entries;
        }

        private void RefreshLayersTab()
        {
            if (layersPanelView == null)
            {
                return;
            }

            string sourceActiveLayerId = GetLayerPanelSourceActiveLayerId();
            LogDebug($"LayerPanel refresh pending={(pendingLayerPanelApplyLayers != null ? 1 : 0)} active={sourceActiveLayerId}");
            IEnumerable<LayerDefinition> sourceLayers = GetLayerPanelSourceLayers();
            List<LayerPanelDisplayRow> rows = new List<LayerPanelDisplayRow>();
            foreach (object entry in BuildLayerPanelEntries())
            {
                if (entry is LayerPanelGroupEntry group)
                {
                    LayerGroupVisibilityState visibleState = GetLayerGroupVisibilityState(group.GroupName, sourceLayers);
                    LayerGroupVisibilityState lockedState = GetLayerGroupLockedState(group.GroupName, sourceLayers);
                    rows.Add(new LayerPanelDisplayRow
                    {
                        Tag = new LayerPanelRowTag
                        {
                            Kind = LayerPanelRowKind.Group,
                            GroupName = group.GroupName
                        },
                        ShowActive = false,
                        Active = false,
                        VisibleState = visibleState == LayerGroupVisibilityState.Mixed
                            ? CheckState.Indeterminate
                            : (visibleState == LayerGroupVisibilityState.AllVisible ? CheckState.Checked : CheckState.Unchecked),
                        LockedState = lockedState == LayerGroupVisibilityState.Mixed
                            ? CheckState.Indeterminate
                            : (lockedState == LayerGroupVisibilityState.AllVisible ? CheckState.Checked : CheckState.Unchecked),
                        Name = group.GroupName,
                        BoldName = true,
                        NameIndent = 0
                    });
                    continue;
                }

                LayerDefinition layer = entry as LayerDefinition;
                if (layer == null)
                {
                    continue;
                }

                bool inGroup = !string.IsNullOrWhiteSpace(NormalizeLayerGroupName(
                    layer.GroupName,
                    string.Equals(NormalizeLayerIdValue(layer.Id), WorkLayerId, StringComparison.OrdinalIgnoreCase)));
                rows.Add(new LayerPanelDisplayRow
                {
                    Tag = new LayerPanelRowTag
                    {
                        Kind = LayerPanelRowKind.Layer,
                        LayerId = NormalizeLayerIdValue(layer.Id),
                        GroupName = NormalizeLayerGroupName(layer.GroupName, string.Equals(NormalizeLayerIdValue(layer.Id), WorkLayerId, StringComparison.OrdinalIgnoreCase))
                    },
                    ShowActive = true,
                    Active = string.Equals(NormalizeLayerIdValue(sourceActiveLayerId), NormalizeLayerIdValue(layer.Id), StringComparison.OrdinalIgnoreCase),
                    VisibleState = layer.IsVisible ? CheckState.Checked : CheckState.Unchecked,
                    LockedState = layer.IsLocked ? CheckState.Checked : CheckState.Unchecked,
                    Name = layer.Name,
                    BoldName = false,
                    NameIndent = inGroup ? 14 : 0
                });
            }

            layersPanelView.SetRows(rows);
        }

        private void LayersPanelView_CellDoubleClick(object sender, LayerPanelCellEventArgs e)
        {
            if (layersPanelView == null || e == null)
            {
                return;
            }

            if (!string.Equals(e.ColumnName, "LayersNameColumn", StringComparison.Ordinal))
            {
                return;
            }

            LayerPanelRowTag rowTag = e.RowTag;
            if (rowTag == null)
            {
                return;
            }

            if (rowTag.Kind == LayerPanelRowKind.Group)
            {
                if (!PromptForLayerGroupNameFromMainForm(rowTag.GroupName, out string updatedGroupName))
                {
                    RefreshLayersTab();
                    return;
                }

                List<LayerDefinition> updatedLayers = documentLayers.Select(layer => layer.Clone()).ToList();
                string sourceGroupName = NormalizeLayerGroupName(rowTag.GroupName);
                string targetGroupName = NormalizeLayerGroupName(updatedGroupName);
                bool changed = false;
                foreach (LayerDefinition layer in updatedLayers.Where(layer =>
                             string.Equals(NormalizeLayerGroupName(layer.GroupName, string.Equals(NormalizeLayerIdValue(layer.Id), WorkLayerId, StringComparison.OrdinalIgnoreCase)), sourceGroupName, StringComparison.CurrentCultureIgnoreCase)))
                {
                    if (!string.Equals(NormalizeLayerGroupName(layer.GroupName), targetGroupName, StringComparison.CurrentCulture))
                    {
                        layer.GroupName = targetGroupName;
                        changed = true;
                    }
                }

                if (changed)
                {
                    ApplyLayerConfiguration(updatedLayers, activeLayerId, markProjectChanged: true);
                }
                else
                {
                    RefreshLayersTab();
                }

                return;
            }

            string layerId = rowTag.LayerId;
            if (string.IsNullOrWhiteSpace(layerId))
            {
                return;
            }

            LayerDefinition targetLayer = documentLayers.FirstOrDefault(layer =>
                string.Equals(NormalizeLayerIdValue(layer.Id), NormalizeLayerIdValue(layerId), StringComparison.OrdinalIgnoreCase));
            if (targetLayer == null || string.Equals(targetLayer.Id, WorkLayerId, StringComparison.OrdinalIgnoreCase))
            {
                return;
            }

            if (PromptForLayerNameFromMainForm(targetLayer.Name, out string newName))
            {
                if (string.IsNullOrWhiteSpace(newName) || string.Equals(newName, targetLayer.Name, StringComparison.CurrentCulture))
                {
                    RefreshLayersTab();
                    return;
                }

                List<LayerDefinition> updatedLayers = documentLayers.Select(layer => layer.Clone()).ToList();
                LayerDefinition editableLayer = updatedLayers.FirstOrDefault(layer =>
                    string.Equals(NormalizeLayerIdValue(layer.Id), NormalizeLayerIdValue(layerId), StringComparison.OrdinalIgnoreCase));
                if (editableLayer == null)
                {
                    RefreshLayersTab();
                    return;
                }

                editableLayer.Name = newName;
                ApplyLayerConfiguration(updatedLayers, activeLayerId, markProjectChanged: true);
            }
            else
            {
                RefreshLayersTab();
            }
        }

        private void LayersPanelView_CellClick(object sender, LayerPanelCellEventArgs e)
        {
            if (layersPanelView == null || e == null)
            {
                return;
            }

            LayerPanelRowTag rowTag = e.RowTag;
            if (rowTag == null)
            {
                return;
            }

            string columnName = e.ColumnName;
            List<LayerDefinition> sourceLayers = GetLayerPanelSourceLayers()
                .Select(layer => layer?.Clone())
                .Where(layer => layer != null)
                .ToList();
            string sourceActiveLayerId = GetLayerPanelSourceActiveLayerId();
            LogDebug($"LayerPanel click row={(rowTag.Kind == LayerPanelRowKind.Group ? "group" : "layer")} col={columnName} group={rowTag.GroupName ?? "-"} layer={rowTag.LayerId ?? "-"} pending={(pendingLayerPanelApplyLayers != null ? 1 : 0)}");
            if (rowTag.Kind == LayerPanelRowKind.Group)
            {
                bool changed = false;
                if (string.Equals(columnName, "LayersVisibleColumn", StringComparison.Ordinal))
                {
                    bool nextVisible = GetLayerGroupVisibilityState(rowTag.GroupName, sourceLayers) != LayerGroupVisibilityState.AllVisible;
                    changed = SetLayerGroupVisibility(sourceLayers, rowTag.GroupName, nextVisible);
                }
                else if (string.Equals(columnName, "LayersLockedColumn", StringComparison.Ordinal))
                {
                    bool nextLocked = GetLayerGroupLockedState(rowTag.GroupName, sourceLayers) != LayerGroupVisibilityState.AllVisible;
                    changed = SetLayerGroupLocked(sourceLayers, rowTag.GroupName, nextLocked);
                }

                if (!changed)
                {
                    RefreshLayersTab();
                    return;
                }

                QueueLayerPanelApply(sourceLayers, sourceActiveLayerId);
                return;
            }

            if (!string.Equals(columnName, "LayersActiveColumn", StringComparison.Ordinal) &&
                !string.Equals(columnName, "LayersVisibleColumn", StringComparison.Ordinal) &&
                !string.Equals(columnName, "LayersLockedColumn", StringComparison.Ordinal))
            {
                return;
            }

            LayerDefinition targetLayer = sourceLayers.FirstOrDefault(layer =>
                string.Equals(NormalizeLayerIdValue(layer.Id), NormalizeLayerIdValue(rowTag.LayerId), StringComparison.OrdinalIgnoreCase));
            if (targetLayer == null)
            {
                RefreshLayersTab();
                return;
            }

            string nextActiveLayerId = sourceActiveLayerId;
            bool layerChanged = false;
            if (string.Equals(columnName, "LayersActiveColumn", StringComparison.Ordinal))
            {
                if (!string.Equals(NormalizeLayerIdValue(sourceActiveLayerId), NormalizeLayerIdValue(targetLayer.Id), StringComparison.OrdinalIgnoreCase))
                {
                    nextActiveLayerId = targetLayer.Id;
                    layerChanged = true;
                }
            }
            else if (string.Equals(columnName, "LayersVisibleColumn", StringComparison.Ordinal))
            {
                targetLayer.IsVisible = !targetLayer.IsVisible;
                layerChanged = true;
            }
            else if (string.Equals(columnName, "LayersLockedColumn", StringComparison.Ordinal))
            {
                targetLayer.IsLocked = !targetLayer.IsLocked;
                layerChanged = true;
            }

            if (!layerChanged)
            {
                RefreshLayersTab();
                return;
            }

            QueueLayerPanelApply(sourceLayers, nextActiveLayerId);
        }

        private bool PromptForLayerNameFromMainForm(string initialValue, out string layerName)
        {
            return PromptForLayerValueFromMainForm(
                LocalizedText("Dialog_Layers_Rename_Title"),
                LocalizedText("Dialog_Layers_Rename_Label"),
                initialValue,
                out layerName);
        }

        private static void DrawThemedGridCheckBox(Graphics graphics, Rectangle bounds, DataGridViewElementStates state, object value, UiThemePalette theme, Font font)
        {
            if (graphics == null || theme == null)
            {
                return;
            }

            bool enabled = true;
            CheckState checkState = CheckState.Unchecked;
            switch (value)
            {
                case CheckState stateValue:
                    checkState = stateValue;
                    break;
                case bool boolValue:
                    checkState = boolValue ? CheckState.Checked : CheckState.Unchecked;
                    break;
            }

            int side = Math.Max(13, Math.Min(18, (font?.Height ?? SystemFonts.DefaultFont.Height) - 1));
            var glyphRect = new Rectangle(
                bounds.Left + (bounds.Width - side) / 2,
                bounds.Top + (bounds.Height - side) / 2,
                side,
                side);

            graphics.SmoothingMode = System.Drawing.Drawing2D.SmoothingMode.AntiAlias;

            System.Drawing.Color normalBorderColor = LayerCheckboxDarkenColor(theme.BorderColor, 0.18f);
            System.Drawing.Color borderColor = enabled ? normalBorderColor : ControlPaint.Light(normalBorderColor);
            System.Drawing.Color accentColor = enabled ? theme.SelectionBackColor : ControlPaint.Light(theme.SelectionBackColor);
            System.Drawing.Color boxBackColor = enabled ? theme.SectionBackColor : ControlPaint.Light(theme.SectionBackColor);

            using (var backBrush = new SolidBrush(boxBackColor))
            using (var borderPen = new Pen(borderColor, 1f))
            {
                graphics.FillRectangle(backBrush, glyphRect);
                graphics.DrawRectangle(borderPen, glyphRect.X, glyphRect.Y, glyphRect.Width - 1, glyphRect.Height - 1);
            }

            if (checkState == CheckState.Indeterminate)
            {
                Rectangle indeterminateRect = Rectangle.Inflate(glyphRect, -3, -3);
                using (var accentBrush = new SolidBrush(accentColor))
                {
                    graphics.FillRectangle(accentBrush, indeterminateRect);
                }
                System.Drawing.Color minusColor = LayerCheckboxGetContrastColor(accentColor);
                using (var minusPen = new Pen(minusColor, 2f))
                {
                    minusPen.StartCap = System.Drawing.Drawing2D.LineCap.Round;
                    minusPen.EndCap = System.Drawing.Drawing2D.LineCap.Round;
                    int y = glyphRect.Top + glyphRect.Height / 2;
                    int x1 = glyphRect.Left + (int)(glyphRect.Width * 0.24f);
                    int x2 = glyphRect.Right - (int)(glyphRect.Width * 0.24f) - 1;
                    graphics.DrawLine(minusPen, x1, y, x2, y);
                }
                return;
            }

            if (checkState != CheckState.Checked)
            {
                return;
            }

            Rectangle fillRect = Rectangle.Inflate(glyphRect, -2, -2);
            using (var accentBrush = new SolidBrush(accentColor))
            {
                graphics.FillRectangle(accentBrush, fillRect);
            }

            System.Drawing.Color checkColor = LayerCheckboxGetContrastColor(accentColor);
            using (var checkPen = new Pen(checkColor, 2f))
            {
                checkPen.StartCap = System.Drawing.Drawing2D.LineCap.Round;
                checkPen.EndCap = System.Drawing.Drawing2D.LineCap.Round;

                int x1 = glyphRect.Left + (int)(glyphRect.Width * 0.24f);
                int y1 = glyphRect.Top + (int)(glyphRect.Height * 0.55f);
                int x2 = glyphRect.Left + (int)(glyphRect.Width * 0.44f);
                int y2 = glyphRect.Top + (int)(glyphRect.Height * 0.74f);
                int x3 = glyphRect.Left + (int)(glyphRect.Width * 0.76f);
                int y3 = glyphRect.Top + (int)(glyphRect.Height * 0.30f);

                graphics.DrawLines(checkPen, new[]
                {
                    new Point(x1, y1),
                    new Point(x2, y2),
                    new Point(x3, y3)
                });
            }
        }

        private static System.Drawing.Color LayerCheckboxGetContrastColor(System.Drawing.Color color)
        {
            double luminance = ((0.299 * color.R) + (0.587 * color.G) + (0.114 * color.B)) / 255d;
            return luminance > 0.55 ? System.Drawing.Color.Black : System.Drawing.Color.White;
        }

        private static System.Drawing.Color LayerCheckboxDarkenColor(System.Drawing.Color color, float amount)
        {
            amount = Math.Max(0f, Math.Min(1f, amount));
            int r = (int)Math.Round(color.R * (1f - amount));
            int g = (int)Math.Round(color.G * (1f - amount));
            int b = (int)Math.Round(color.B * (1f - amount));
            return System.Drawing.Color.FromArgb(color.A, Math.Max(0, r), Math.Max(0, g), Math.Max(0, b));
        }

        private static System.Drawing.Color BlendLayerPanelColor(System.Drawing.Color primary, System.Drawing.Color secondary, float primaryWeight)
        {
            primaryWeight = Math.Max(0f, Math.Min(1f, primaryWeight));
            float secondaryWeight = 1f - primaryWeight;
            int a = (int)Math.Round((primary.A * primaryWeight) + (secondary.A * secondaryWeight));
            int r = (int)Math.Round((primary.R * primaryWeight) + (secondary.R * secondaryWeight));
            int g = (int)Math.Round((primary.G * primaryWeight) + (secondary.G * secondaryWeight));
            int b = (int)Math.Round((primary.B * primaryWeight) + (secondary.B * secondaryWeight));
            return System.Drawing.Color.FromArgb(
                Math.Max(0, Math.Min(255, a)),
                Math.Max(0, Math.Min(255, r)),
                Math.Max(0, Math.Min(255, g)),
                Math.Max(0, Math.Min(255, b)));
        }

        private sealed class LayerPanelCellEventArgs : EventArgs
        {
            public LayerPanelRowTag RowTag { get; set; }
            public string ColumnName { get; set; }
        }

        private sealed class LayerPanelControl : Control
        {
            private const int HeaderHeight = 24;
            private const int RowHeight = 24;
            private const int CheckColumnWidth = 28;
            private const int TextPadding = 6;
            private readonly VScrollBar verticalScrollBar;
            private readonly ToolTip headerToolTip;
            private List<LayerPanelDisplayRow> rows = new List<LayerPanelDisplayRow>();
            private string activeHeaderToolTip;
            private string visibleHeaderToolTip;
            private string lockedHeaderToolTip;
            private string currentToolTipText;
            private UiThemePalette theme;
            private Image headerActiveImage;
            private Image headerVisibleImage;
            private Image headerLockedImage;

            public LayerPanelControl()
            {
                DoubleBuffered = true;
                ResizeRedraw = true;
                SetStyle(ControlStyles.AllPaintingInWmPaint | ControlStyles.OptimizedDoubleBuffer | ControlStyles.UserPaint, true);
                UpdateStyles();

                verticalScrollBar = new VScrollBar
                {
                    Dock = DockStyle.Right,
                    Visible = false,
                    SmallChange = RowHeight,
                    LargeChange = RowHeight * 4
                };
                verticalScrollBar.Scroll += (_, __) => Invalidate();
                Controls.Add(verticalScrollBar);

                headerToolTip = new ToolTip();
            }

            public UiThemePalette Theme
            {
                get => theme;
                set
                {
                    theme = value;
                    Invalidate();
                }
            }

            public string HeaderNameText { get; set; } = string.Empty;

            public string ActiveHeaderToolTip
            {
                get => activeHeaderToolTip;
                set
                {
                    activeHeaderToolTip = value;
                    headerToolTip.SetToolTip(this, string.Empty);
                }
            }

            public string VisibleHeaderToolTip
            {
                get => visibleHeaderToolTip;
                set
                {
                    visibleHeaderToolTip = value;
                    headerToolTip.SetToolTip(this, string.Empty);
                }
            }

            public string LockedHeaderToolTip
            {
                get => lockedHeaderToolTip;
                set
                {
                    lockedHeaderToolTip = value;
                    headerToolTip.SetToolTip(this, string.Empty);
                }
            }

            public event EventHandler<LayerPanelCellEventArgs> CellClick;
            public event EventHandler<LayerPanelCellEventArgs> CellDoubleClick;

            public void SetHeaderIcons(Image activeImage, Image visibleImage, Image lockedImage)
            {
                headerActiveImage?.Dispose();
                headerVisibleImage?.Dispose();
                headerLockedImage?.Dispose();

                headerActiveImage = activeImage;
                headerVisibleImage = visibleImage;
                headerLockedImage = lockedImage;
                Invalidate();
            }

            public void SetRows(IEnumerable<LayerPanelDisplayRow> newRows)
            {
                rows = (newRows ?? Enumerable.Empty<LayerPanelDisplayRow>()).ToList();
                UpdateScrollBar();
                Invalidate();
            }

            protected override void OnResize(EventArgs e)
            {
                base.OnResize(e);
                UpdateScrollBar();
            }

            protected override void OnMouseWheel(MouseEventArgs e)
            {
                if (verticalScrollBar.Visible)
                {
                    int deltaRows = Math.Max(1, SystemInformation.MouseWheelScrollLines);
                    int step = RowHeight * deltaRows;
                    int nextValue = verticalScrollBar.Value - (e.Delta > 0 ? step : -step);
                    verticalScrollBar.Value = Math.Max(verticalScrollBar.Minimum, Math.Min(GetScrollMaximumValue(), nextValue));
                    Invalidate();
                }

                base.OnMouseWheel(e);
            }

            protected override void OnMouseMove(MouseEventArgs e)
            {
                base.OnMouseMove(e);

                string tooltipText = null;
                LayerPanelHitInfo hit = HitTest(e.Location);
                if (hit.IsHeader)
                {
                    if (string.Equals(hit.ColumnName, "LayersActiveColumn", StringComparison.Ordinal))
                    {
                        tooltipText = ActiveHeaderToolTip;
                    }
                    else if (string.Equals(hit.ColumnName, "LayersVisibleColumn", StringComparison.Ordinal))
                    {
                        tooltipText = VisibleHeaderToolTip;
                    }
                    else if (string.Equals(hit.ColumnName, "LayersLockedColumn", StringComparison.Ordinal))
                    {
                        tooltipText = LockedHeaderToolTip;
                    }
                }

                if (!string.Equals(currentToolTipText, tooltipText, StringComparison.Ordinal))
                {
                    currentToolTipText = tooltipText ?? string.Empty;
                    headerToolTip.SetToolTip(this, currentToolTipText);
                }
            }

            protected override void OnMouseLeave(EventArgs e)
            {
                currentToolTipText = string.Empty;
                headerToolTip.SetToolTip(this, string.Empty);
                base.OnMouseLeave(e);
            }

            protected override void OnMouseClick(MouseEventArgs e)
            {
                base.OnMouseClick(e);

                if (e.Button != MouseButtons.Left)
                {
                    return;
                }

                LayerPanelHitInfo hit = HitTest(e.Location);
                if (hit.Row == null || string.IsNullOrWhiteSpace(hit.ColumnName))
                {
                    return;
                }

                if (!string.Equals(hit.ColumnName, "LayersActiveColumn", StringComparison.Ordinal) &&
                    !string.Equals(hit.ColumnName, "LayersVisibleColumn", StringComparison.Ordinal) &&
                    !string.Equals(hit.ColumnName, "LayersLockedColumn", StringComparison.Ordinal))
                {
                    return;
                }

                CellClick?.Invoke(this, new LayerPanelCellEventArgs
                {
                    RowTag = hit.Row.Tag,
                    ColumnName = hit.ColumnName
                });
            }

            protected override void OnMouseDoubleClick(MouseEventArgs e)
            {
                base.OnMouseDoubleClick(e);

                if (e.Button != MouseButtons.Left)
                {
                    return;
                }

                LayerPanelHitInfo hit = HitTest(e.Location);
                if (hit.Row == null || !string.Equals(hit.ColumnName, "LayersNameColumn", StringComparison.Ordinal))
                {
                    return;
                }

                CellDoubleClick?.Invoke(this, new LayerPanelCellEventArgs
                {
                    RowTag = hit.Row.Tag,
                    ColumnName = hit.ColumnName
                });
            }

            protected override void OnPaint(PaintEventArgs e)
            {
                base.OnPaint(e);

                UiThemePalette currentTheme = Theme;
                if (currentTheme == null)
                {
                    return;
                }

                e.Graphics.Clear(currentTheme.SectionBackColor);
                e.Graphics.SmoothingMode = System.Drawing.Drawing2D.SmoothingMode.AntiAlias;

                int contentWidth = GetContentWidth();
                if (contentWidth <= 0)
                {
                    return;
                }

                DrawHeader(e.Graphics, contentWidth, currentTheme);

                Rectangle bodyClip = new Rectangle(0, HeaderHeight, contentWidth, Math.Max(0, Height - HeaderHeight));
                Region oldClip = e.Graphics.Clip;
                e.Graphics.SetClip(bodyClip);

                int scrollOffset = verticalScrollBar.Visible ? verticalScrollBar.Value : 0;
                int startIndex = Math.Max(0, scrollOffset / RowHeight);
                int visibleRowCount = Math.Max(1, (bodyClip.Height + RowHeight - 1) / RowHeight + 1);
                int endIndex = Math.Min(rows.Count - 1, startIndex + visibleRowCount);

                for (int i = startIndex; i <= endIndex; i++)
                {
                    DrawRow(e.Graphics, rows[i], i, contentWidth, scrollOffset, currentTheme);
                }

                e.Graphics.Clip = oldClip;
            }

            protected override void Dispose(bool disposing)
            {
                if (disposing)
                {
                    headerActiveImage?.Dispose();
                    headerVisibleImage?.Dispose();
                    headerLockedImage?.Dispose();
                    headerToolTip?.Dispose();
                }

                base.Dispose(disposing);
            }

            private void DrawHeader(Graphics graphics, int contentWidth, UiThemePalette currentTheme)
            {
                Rectangle headerBounds = new Rectangle(0, 0, contentWidth, HeaderHeight);
                using (var backBrush = new SolidBrush(currentTheme.SectionBackColor))
                using (var borderPen = new Pen(currentTheme.BorderColor, 1f))
                {
                    graphics.FillRectangle(backBrush, headerBounds);
                    graphics.DrawRectangle(borderPen, 0, 0, contentWidth - 1, HeaderHeight - 1);
                    graphics.DrawLine(borderPen, 0, HeaderHeight - 1, contentWidth, HeaderHeight - 1);
                }

                DrawHeaderCellIcon(graphics, GetColumnBounds(0, contentWidth), headerActiveImage, "\u25C9", currentTheme);
                DrawHeaderCellIcon(graphics, GetColumnBounds(1, contentWidth), headerVisibleImage, "\U0001F441", currentTheme);
                DrawHeaderCellIcon(graphics, GetColumnBounds(2, contentWidth), headerLockedImage, "\U0001F512", currentTheme);
                DrawHeaderCellText(graphics, GetColumnBounds(3, contentWidth), HeaderNameText ?? string.Empty, currentTheme, alignLeft: true);
            }

            private void DrawHeaderCellText(Graphics graphics, Rectangle bounds, string text, UiThemePalette currentTheme, bool alignLeft = false, bool iconLike = false, string iconFontFamilyName = null)
            {
                TextFormatFlags flags = TextFormatFlags.VerticalCenter | TextFormatFlags.NoPrefix | TextFormatFlags.EndEllipsis;
                flags |= alignLeft ? TextFormatFlags.Left : TextFormatFlags.HorizontalCenter;
                Rectangle drawBounds = alignLeft ? Rectangle.Inflate(bounds, -TextPadding, 0) : bounds;
                Font drawFont = Font;
                if (iconLike)
                {
                    try
                    {
                        drawFont = !string.IsNullOrWhiteSpace(iconFontFamilyName)
                            ? new Font(iconFontFamilyName, Font.Size + 2.0f, FontStyle.Regular, GraphicsUnit.Point)
                            : new Font(Font.FontFamily, Font.Size + 2.0f, FontStyle.Regular, GraphicsUnit.Point);
                    }
                    catch
                    {
                        drawFont = new Font(Font.FontFamily, Font.Size + 2.0f, FontStyle.Regular, GraphicsUnit.Point);
                    }
                }

                try
                {
                    TextRenderer.DrawText(graphics, text ?? string.Empty, drawFont, drawBounds, currentTheme.TextPrimaryColor, flags);
                }
                finally
                {
                    if (iconLike && drawFont != null && !ReferenceEquals(drawFont, Font))
                    {
                        drawFont.Dispose();
                    }
                }
            }

            private void DrawHeaderCellIcon(Graphics graphics, Rectangle bounds, Image image, string fallbackText, UiThemePalette currentTheme)
            {
                if (image != null)
                {
                    int x = bounds.Left + ((bounds.Width - image.Width) / 2);
                    int y = bounds.Top + ((bounds.Height - image.Height) / 2);
                    graphics.DrawImage(image, x, y, image.Width, image.Height);
                    return;
                }

                DrawHeaderCellText(graphics, bounds, fallbackText, currentTheme, alignLeft: false, iconLike: true);
            }

            private void DrawRow(Graphics graphics, LayerPanelDisplayRow row, int rowIndex, int contentWidth, int scrollOffset, UiThemePalette currentTheme)
            {
                int y = HeaderHeight + (rowIndex * RowHeight) - scrollOffset;
                Rectangle rowBounds = new Rectangle(0, y, contentWidth, RowHeight);
                if (rowBounds.Bottom < HeaderHeight || rowBounds.Top > Height)
                {
                    return;
                }

                bool isGroupRow = row?.Tag?.Kind == LayerPanelRowKind.Group;
                System.Drawing.Color rowBackColor = isGroupRow
                    ? BlendLayerPanelColor(currentTheme.SectionBackColor, currentTheme.PanelBackColor, 0.55f)
                    : currentTheme.SectionBackColor;

                using (var backBrush = new SolidBrush(rowBackColor))
                using (var borderPen = new Pen(currentTheme.BorderColor, 1f))
                {
                    graphics.FillRectangle(backBrush, rowBounds);
                    graphics.DrawLine(borderPen, rowBounds.Left, rowBounds.Bottom - 1, rowBounds.Right, rowBounds.Bottom - 1);
                }

                DrawVerticalSeparators(graphics, contentWidth, y, currentTheme);

                if (row.ShowActive)
                {
                    DrawThemedGridCheckBox(graphics, GetCellBounds(0, y, contentWidth), DataGridViewElementStates.None, row.Active, currentTheme, Font);
                }

                DrawThemedGridCheckBox(graphics, GetCellBounds(1, y, contentWidth), DataGridViewElementStates.None, row.VisibleState, currentTheme, Font);
                DrawThemedGridCheckBox(graphics, GetCellBounds(2, y, contentWidth), DataGridViewElementStates.None, row.LockedState, currentTheme, Font);

                Rectangle textBounds = GetCellBounds(3, y, contentWidth);
                textBounds = new Rectangle(textBounds.Left + TextPadding + row.NameIndent, textBounds.Top, Math.Max(0, textBounds.Width - TextPadding - row.NameIndent), textBounds.Height);
                Font rowFont = row.BoldName ? new Font(Font, FontStyle.Bold) : Font;
                try
                {
                    TextRenderer.DrawText(
                        graphics,
                        row.Name ?? string.Empty,
                        rowFont,
                        textBounds,
                        currentTheme.TextPrimaryColor,
                        TextFormatFlags.Left | TextFormatFlags.VerticalCenter | TextFormatFlags.EndEllipsis | TextFormatFlags.NoPrefix);
                }
                finally
                {
                    if (row.BoldName && rowFont != null && !ReferenceEquals(rowFont, Font))
                    {
                        rowFont.Dispose();
                    }
                }
            }

            private void DrawVerticalSeparators(Graphics graphics, int contentWidth, int y, UiThemePalette currentTheme)
            {
                using (var borderPen = new Pen(currentTheme.BorderColor, 1f))
                {
                    Rectangle col0 = GetColumnBounds(0, contentWidth);
                    Rectangle col1 = GetColumnBounds(1, contentWidth);
                    Rectangle col2 = GetColumnBounds(2, contentWidth);
                    graphics.DrawLine(borderPen, col0.Right - 1, y, col0.Right - 1, y + RowHeight - 1);
                    graphics.DrawLine(borderPen, col1.Right - 1, y, col1.Right - 1, y + RowHeight - 1);
                    graphics.DrawLine(borderPen, col2.Right - 1, y, col2.Right - 1, y + RowHeight - 1);
                }
            }

            private LayerPanelHitInfo HitTest(Point location)
            {
                int contentWidth = GetContentWidth();
                if (contentWidth <= 0 || location.X < 0 || location.X >= contentWidth || location.Y < 0)
                {
                    return LayerPanelHitInfo.None;
                }

                string columnName = GetColumnNameAt(location.X, contentWidth);
                if (string.IsNullOrWhiteSpace(columnName))
                {
                    return LayerPanelHitInfo.None;
                }

                if (location.Y < HeaderHeight)
                {
                    return new LayerPanelHitInfo
                    {
                        IsHeader = true,
                        ColumnName = columnName
                    };
                }

                int rowIndex = ((location.Y - HeaderHeight) + (verticalScrollBar.Visible ? verticalScrollBar.Value : 0)) / RowHeight;
                if (rowIndex < 0 || rowIndex >= rows.Count)
                {
                    return LayerPanelHitInfo.None;
                }

                return new LayerPanelHitInfo
                {
                    Row = rows[rowIndex],
                    RowIndex = rowIndex,
                    ColumnName = columnName
                };
            }

            private string GetColumnNameAt(int x, int contentWidth)
            {
                if (GetColumnBounds(0, contentWidth).Contains(x, HeaderHeight / 2))
                {
                    return "LayersActiveColumn";
                }

                if (GetColumnBounds(1, contentWidth).Contains(x, HeaderHeight / 2))
                {
                    return "LayersVisibleColumn";
                }

                if (GetColumnBounds(2, contentWidth).Contains(x, HeaderHeight / 2))
                {
                    return "LayersLockedColumn";
                }

                if (GetColumnBounds(3, contentWidth).Contains(x, HeaderHeight / 2))
                {
                    return "LayersNameColumn";
                }

                return null;
            }

            private Rectangle GetCellBounds(int columnIndex, int rowTop, int contentWidth)
            {
                Rectangle column = GetColumnBounds(columnIndex, contentWidth);
                return new Rectangle(column.Left, rowTop, column.Width, RowHeight);
            }

            private Rectangle GetColumnBounds(int columnIndex, int contentWidth)
            {
                int nameColumnLeft = CheckColumnWidth * 3;
                int nameColumnWidth = Math.Max(20, contentWidth - nameColumnLeft);
                switch (columnIndex)
                {
                    case 0:
                        return new Rectangle(0, 0, CheckColumnWidth, HeaderHeight);
                    case 1:
                        return new Rectangle(CheckColumnWidth, 0, CheckColumnWidth, HeaderHeight);
                    case 2:
                        return new Rectangle(CheckColumnWidth * 2, 0, CheckColumnWidth, HeaderHeight);
                    default:
                        return new Rectangle(nameColumnLeft, 0, nameColumnWidth, HeaderHeight);
                }
            }

            private int GetContentWidth()
            {
                return Math.Max(0, ClientSize.Width - (verticalScrollBar.Visible ? verticalScrollBar.Width : 0));
            }

            private void UpdateScrollBar()
            {
                int viewportHeight = Math.Max(0, ClientSize.Height - HeaderHeight);
                int contentHeight = rows.Count * RowHeight;
                bool shouldShow = contentHeight > viewportHeight && viewportHeight > 0;
                verticalScrollBar.Visible = shouldShow;
                if (!shouldShow)
                {
                    verticalScrollBar.Value = 0;
                    return;
                }

                verticalScrollBar.Minimum = 0;
                verticalScrollBar.LargeChange = Math.Max(RowHeight, viewportHeight);
                verticalScrollBar.SmallChange = RowHeight;
                verticalScrollBar.Maximum = Math.Max(0, contentHeight - 1);
                verticalScrollBar.Value = Math.Max(0, Math.Min(GetScrollMaximumValue(), verticalScrollBar.Value));
            }

            private int GetScrollMaximumValue()
            {
                return Math.Max(verticalScrollBar.Minimum, verticalScrollBar.Maximum - verticalScrollBar.LargeChange + 1);
            }

            private sealed class LayerPanelHitInfo
            {
                public static readonly LayerPanelHitInfo None = new LayerPanelHitInfo();
                public bool IsHeader { get; set; }
                public LayerPanelDisplayRow Row { get; set; }
                public int RowIndex { get; set; }
                public string ColumnName { get; set; }
            }
        }


        private bool PromptForLayerGroupNameFromMainForm(string initialValue, out string groupName)
        {
            return PromptForLayerValueFromMainForm(
                LocalizedText("Dialog_Layers_Group_Title"),
                LocalizedText("Dialog_Layers_Group_Label"),
                initialValue,
                out groupName);
        }

        private bool PromptForLayerValueFromMainForm(string title, string labelText, string initialValue, out string value)
        {
            value = initialValue ?? string.Empty;

            using (Form prompt = new Form())
            using (TextBox inputTextBox = new TextBox())
            using (Label label = new Label())
            using (Button okButton = new Button())
            using (Button cancelButton = new Button())
            {
                prompt.Text = title;
                prompt.StartPosition = FormStartPosition.CenterParent;
                prompt.FormBorderStyle = FormBorderStyle.FixedDialog;
                prompt.MinimizeBox = false;
                prompt.MaximizeBox = false;
                prompt.ShowInTaskbar = false;
                prompt.ClientSize = new Size(420, 125);

                label.AutoSize = true;
                label.Left = 12;
                label.Top = 14;
                label.Text = labelText;

                inputTextBox.Left = 12;
                inputTextBox.Top = 38;
                inputTextBox.Width = 396;
                inputTextBox.Text = value;

                okButton.Text = LocalizedText("Dialog_Button_Save");
                okButton.Width = 100;
                okButton.Height = 28;
                okButton.Left = 206;
                okButton.Top = 82;
                okButton.DialogResult = DialogResult.OK;

                cancelButton.Text = LocalizedText("Dialog_Button_Cancel");
                cancelButton.Width = 100;
                cancelButton.Height = 28;
                cancelButton.Left = 308;
                cancelButton.Top = 82;
                cancelButton.DialogResult = DialogResult.Cancel;

                prompt.Controls.Add(label);
                prompt.Controls.Add(inputTextBox);
                prompt.Controls.Add(okButton);
                prompt.Controls.Add(cancelButton);
                prompt.AcceptButton = okButton;
                prompt.CancelButton = cancelButton;

                prompt.Shown += (_, __) =>
                {
                    inputTextBox.Focus();
                    inputTextBox.SelectAll();
                };

                if (prompt.ShowDialog(this) != DialogResult.OK)
                {
                    return false;
                }

                value = (inputTextBox.Text ?? string.Empty).Trim();
                return true;
            }
        }

        private void ApplyLayersTabLocalization()
        {
            if (layersPanelView == null)
            {
                return;
            }

            layersPanelView.HeaderNameText = LocalizedText("Layers_Tab_Header_Name");
            layersPanelView.ActiveHeaderToolTip = LocalizedText("Layers_Tab_Header_Active_Tooltip");
            layersPanelView.VisibleHeaderToolTip = LocalizedText("Layers_Tab_Header_Visible_Tooltip");
            layersPanelView.LockedHeaderToolTip = LocalizedText("Layers_Tab_Header_Locked_Tooltip");
            layersPanelView.Invalidate();
        }

        private void ApplyThemeToLayersGrid(UiThemePalette theme)
        {
            if (layersPanelView == null || theme == null)
            {
                return;
            }

            layersPanelView.Theme = theme;
            layersPanelView.BackColor = theme.SectionBackColor;
            layersPanelView.ForeColor = theme.TextPrimaryColor;
            Bitmap activeHeaderBitmap = null;
            Bitmap visibleHeaderBitmap = null;
            Bitmap lockedHeaderBitmap = null;
            TryCreateMaterialIconBitmap(LayersHeaderActiveIconCodePoint, 16, theme.TextPrimaryColor, out activeHeaderBitmap);
            TryCreateMaterialIconBitmap(LayersHeaderVisibleIconCodePoint, 16, theme.TextPrimaryColor, out visibleHeaderBitmap);
            TryCreateMaterialIconBitmap(LayersHeaderLockedIconCodePoint, 16, theme.TextPrimaryColor, out lockedHeaderBitmap);
            layersPanelView.SetHeaderIcons(activeHeaderBitmap, visibleHeaderBitmap, lockedHeaderBitmap);
            layersPanelView.Invalidate();
        }

        private void PruneInvisibleLayerInteractionState()
        {
            selectedTextAnnotations.RemoveWhere(annotation => annotation == null || !IsLayerVisible(annotation.LayerId));
            selectedRasterObjectIds.RemoveWhere(id =>
            {
                RasterObject rasterObject = rasterObjects.FirstOrDefault(r => r != null && string.Equals(r.Id, id, StringComparison.Ordinal));
                return rasterObject == null || !IsLayerVisible(rasterObject.LayerId);
            });
            selectedArrowObjectIds.RemoveWhere(id =>
            {
                ArrowObject arrowObject = arrowObjects.FirstOrDefault(a => a != null && string.Equals(a.Id, id, StringComparison.Ordinal));
                return arrowObject == null || !IsLayerVisible(arrowObject.LayerId);
            });
            selectedVectorShapeIds.RemoveWhere(id =>
            {
                VectorShapeObject vectorShape = vectorShapes.FirstOrDefault(v => v != null && string.Equals(v.Id, id, StringComparison.Ordinal));
                return vectorShape == null || !IsLayerVisible(vectorShape.LayerId);
            });

            if (selectedTextAnnotation != null && !IsLayerVisible(selectedTextAnnotation.LayerId))
            {
                selectedTextAnnotation = null;
            }

            if (selectedRasterObject != null && !IsLayerVisible(selectedRasterObject.LayerId))
            {
                selectedRasterObject = null;
            }

            if (selectedArrowObject != null && !IsLayerVisible(selectedArrowObject.LayerId))
            {
                selectedArrowObject = null;
            }

            if (selectedVectorShape != null && !IsLayerVisible(selectedVectorShape.LayerId))
            {
                selectedVectorShape = null;
            }

            if (selectedCommentAnnotation != null && !IsLayerVisible(selectedCommentAnnotation.LayerId))
            {
                selectedCommentAnnotation = null;
            }

            if ((annotationToRotate != null && !IsLayerVisible(annotationToRotate.LayerId)) ||
                (annotationToScale != null && !IsLayerVisible(annotationToScale.LayerId)) ||
                (annotationToAdjustLeader != null && !IsLayerVisible(annotationToAdjustLeader.LayerId)))
            {
                ResetTextRotationInteractionState();
            }

            if ((commentNoteToMove != null && !IsLayerVisible(commentNoteToMove.LayerId)) ||
                (commentNoteToResize != null && !IsLayerVisible(commentNoteToResize.LayerId)))
            {
                ResetCommentNoteMoveState();
            }

            if ((rasterObjectToMove != null && !IsLayerVisible(rasterObjectToMove.LayerId)) ||
                (rasterObjectToRotate != null && !IsLayerVisible(rasterObjectToRotate.LayerId)) ||
                (rasterObjectToResize != null && !IsLayerVisible(rasterObjectToResize.LayerId)))
            {
                ResetRasterInteractionState();
            }

            if ((arrowObjectToMove != null && !IsLayerVisible(arrowObjectToMove.LayerId)) ||
                (arrowObjectToAdjust != null && !IsLayerVisible(arrowObjectToAdjust.LayerId)) ||
                (arrowObjectToScale != null && !IsLayerVisible(arrowObjectToScale.LayerId)))
            {
                ResetArrowInteractionState();
            }

            if ((vectorShapeToMove != null && !IsLayerVisible(vectorShapeToMove.LayerId)) ||
                (vectorShapeToAdjust != null && !IsLayerVisible(vectorShapeToAdjust.LayerId)) ||
                (vectorShapeToRotate != null && !IsLayerVisible(vectorShapeToRotate.LayerId)) ||
                (vectorShapeToScale != null && !IsLayerVisible(vectorShapeToScale.LayerId)))
            {
                ResetVectorInteractionState();
            }

            if (groupMoveEntries.Any(entry => entry != null && !IsGroupMoveEntryLayerVisible(entry)))
            {
                ResetGroupMoveState();
            }

            CollapseGroupSelectionToSingleIfNeeded();
        }

        private bool IsGroupMoveEntryLayerVisible(GroupMoveEntry entry)
        {
            if (entry == null)
            {
                return true;
            }

            if (entry.Text != null)
            {
                return IsLayerVisible(entry.Text.LayerId);
            }

            if (entry.Raster != null)
            {
                return IsLayerVisible(entry.Raster.LayerId);
            }

            if (entry.Arrow != null)
            {
                return IsLayerVisible(entry.Arrow.LayerId);
            }

            if (entry.VectorShape != null)
            {
                return IsLayerVisible(entry.VectorShape.LayerId);
            }

            return true;
        }

        private Dictionary<string, int> BuildLayerUsageCounts()
        {
            var counts = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

            void AddCount(string layerId)
            {
                string normalized = NormalizeLayerIdValue(layerId);
                counts[normalized] = counts.TryGetValue(normalized, out int existing) ? existing + 1 : 1;
            }

            foreach (RedactionBlock block in redactionBlocks.Where(block => block != null))
            {
                AddCount(block.LayerId);
            }

            foreach (CommentAnnotation comment in commentAnnotations.Where(comment => comment != null))
            {
                AddCount(comment.LayerId);
            }

            foreach (TextAnnotation annotation in textAnnotations.Where(annotation => annotation != null))
            {
                AddCount(annotation.LayerId);
            }

            foreach (RasterObject rasterObject in rasterObjects.Where(rasterObject => rasterObject != null))
            {
                AddCount(rasterObject.LayerId);
            }

            foreach (ArrowObject arrowObject in arrowObjects.Where(arrowObject => arrowObject != null))
            {
                AddCount(arrowObject.LayerId);
            }

            foreach (VectorShapeObject vectorShape in vectorShapes.Where(vectorShape => vectorShape != null))
            {
                AddCount(vectorShape.LayerId);
            }

            return counts;
        }

        private void LegalBasesDictionaryToolStripMenuItem_Click(object sender, EventArgs e)
        {
            OpenLegalBasesDictionary();
        }

        private void ExclusionAuthorityToolStripMenuItem_Click(object sender, EventArgs e)
        {
            string initialValue = GetPreferredExclusionAuthority();
            if (!PromptForExclusionAuthority(initialValue, true, out string authorityValue))
            {
                return;
            }

            string previousAuthority = exclusionAuthorityName ?? string.Empty;
            exclusionAuthorityName = authorityValue;
            SaveExclusionAuthorityUserSetting(exclusionAuthorityName, verified: true);
            bool changed = !string.Equals(previousAuthority.Trim(), exclusionAuthorityName.Trim(), StringComparison.Ordinal);
            changed = ApplyInterestSubjectToRequiredBlocks(authorityValue, onlyMissing: true) || changed;
            if (changed)
            {
                projectWasChangedAfterLastSave = true;
                saveProjectButton.Enabled = true;
                saveProjectMenuItem.Enabled = true;
            }

            pdfViewer.Invalidate();
        }

        private void OpenLegalBasesDictionary()
        {
            string globalPath = GetGlobalLegalBasesFilePath();
            string localPath = GetLocalLegalBasesFilePath();
            string globalScopesPath = GetGlobalExclusionScopesFilePath();
            string localScopesPath = GetLocalExclusionScopesFilePath();

            bool canEditGlobal = HasWriteAccessToTarget(globalPath);
            bool canEditLocal = HasWriteAccessToTarget(localPath);
            bool canEditGlobalScopes = HasWriteAccessToTarget(globalScopesPath);
            bool canEditLocalScopes = HasWriteAccessToTarget(localScopesPath);

            if (!TryLoadLegalBasesForEditor(globalPath, LegalBasisSource.Global, out List<LegalBasisDefinition> globalBases, out string globalLoadError))
            {
                ShowInfoMessage(globalLoadError);
                return;
            }

            if (!TryLoadLegalBasesForEditor(localPath, LegalBasisSource.Local, out List<LegalBasisDefinition> localBases, out string localLoadError))
            {
                ShowInfoMessage(localLoadError);
                return;
            }

            if (!TryLoadExclusionScopesForEditor(globalScopesPath, ExclusionScopeSource.Global, out List<ExclusionScopeDefinition> globalScopes, out string globalScopesVersion, out string globalScopesLoadError))
            {
                ShowInfoMessage(globalScopesLoadError);
                return;
            }

            if (!TryLoadExclusionScopesForEditor(localScopesPath, ExclusionScopeSource.Local, out List<ExclusionScopeDefinition> localScopes, out string localScopesVersion, out string localScopesLoadError))
            {
                ShowInfoMessage(localScopesLoadError);
                return;
            }

            using (var dialog = new LegalBasesDictionaryDialog(
                globalBases,
                localBases,
                globalScopes,
                localScopes,
                canEditGlobal,
                canEditLocal,
                canEditGlobalScopes,
                canEditLocalScopes,
                globalPath,
                localPath))
            {
                if (dialog.ShowDialog(this) != DialogResult.OK)
                {
                    return;
                }

                if (canEditGlobal &&
                    !TrySaveLegalBasesForEditor(globalPath, "GLOBAL", LegalBasisSource.Global, dialog.GetGlobalLegalBases(), out string globalSaveError))
                {
                    ShowInfoMessage(globalSaveError);
                    return;
                }

                if (canEditLocal &&
                    !TrySaveLegalBasesForEditor(localPath, "LOCAL", LegalBasisSource.Local, dialog.GetLocalLegalBases(), out string localSaveError))
                {
                    ShowInfoMessage(localSaveError);
                    return;
                }

                if (canEditGlobalScopes &&
                    !TrySaveExclusionScopesForEditor(
                        globalScopesPath,
                        globalScopesVersion,
                        ExclusionScopeSource.Global,
                        dialog.GetGlobalExclusionScopes(),
                        out string globalScopesSaveError))
                {
                    ShowInfoMessage(globalScopesSaveError);
                    return;
                }

                if (canEditLocalScopes &&
                    !TrySaveExclusionScopesForEditor(
                        localScopesPath,
                        localScopesVersion,
                        ExclusionScopeSource.Local,
                        dialog.GetLocalExclusionScopes(),
                        out string localScopesSaveError))
                {
                    ShowInfoMessage(localScopesSaveError);
                    return;
                }
            }

            LoadFootnotesCatalog();
            bool removedInvalidBasisReferences = RemoveInvalidLegalBasisReferencesFromRedactions();
            if (removedInvalidBasisReferences)
            {
                projectWasChangedAfterLastSave = true;
                saveProjectButton.Enabled = true;
                saveProjectMenuItem.Enabled = true;
            }

            ApplyAutomaticFootnotesMenuState();
            ApplyAddObjectsByPageRotationMenuState();
            pdfViewer.Invalidate();
            ShowInfoMessage(GetLegalBasesSavedMessage());
        }
        
        private string GetExclusionAuthorityMenuText()
        {
            return LocalizedText("Footnotes_ExclusionAuthority_Menu");
        }

        private string GetExclusionAuthorityDialogTitleText()
        {
            return GetExclusionAuthorityMenuText();
        }

        private string GetExclusionAuthorityDialogLabelText()
        {
            return LocalizedText("Footnotes_ExclusionAuthority_Label");
        }

        private string GetExclusionAuthorityRequiredMessage()
        {
            return LocalizedText("Footnotes_ExclusionAuthority_Required");
        }

        private string GetExclusionAuthoritySummaryLine(string authority)
        {
            string value = string.IsNullOrWhiteSpace(authority) ? "-" : authority.Trim();
            return LocalizedFormat("Footnotes_ExclusionAuthority_SummaryLine", value);
        }

        private string GetPreferredExclusionAuthority()
        {
            if (!string.IsNullOrWhiteSpace(exclusionAuthorityName))
            {
                return exclusionAuthorityName.Trim();
            }

            foreach (var block in redactionBlocks)
            {
                if (!string.IsNullOrWhiteSpace(block?.InterestSubject))
                {
                    return block.InterestSubject.Trim();
                }
            }

            return string.Empty;
        }

        private void BootstrapExclusionAuthorityFromLicenseIfMissing()
        {
            if (!string.IsNullOrWhiteSpace(exclusionAuthorityName))
            {
                return;
            }

            string customerName = (LicenseManager.Current?.Payload?.CustomerName ?? string.Empty).Trim();
            if (string.IsNullOrWhiteSpace(customerName))
            {
                return;
            }

            exclusionAuthorityName = customerName;
            SaveExclusionAuthorityUserSetting(exclusionAuthorityName, verified: false);
        }

        private bool BlockRequiresInterestSubject(RedactionBlock block)
        {
            if (block == null || block.BasisIds == null || block.BasisIds.Count == 0)
            {
                return false;
            }

            foreach (string basisId in block.BasisIds)
            {
                if (string.IsNullOrWhiteSpace(basisId))
                {
                    continue;
                }

                if (legalBasesById.TryGetValue(basisId.Trim(), out LegalBasisDefinition basis) &&
                    basis != null &&
                    basis.RequiresInterestSubject)
                {
                    return true;
                }
            }

            return false;
        }

        private bool ApplyInterestSubjectToRequiredBlocks(string authorityValue, bool onlyMissing)
        {
            if (string.IsNullOrWhiteSpace(authorityValue))
            {
                return false;
            }

            string normalized = authorityValue.Trim();
            bool changed = false;
            foreach (var block in redactionBlocks)
            {
                if (!BlockRequiresInterestSubject(block))
                {
                    continue;
                }

                if (onlyMissing && !string.IsNullOrWhiteSpace(block.InterestSubject))
                {
                    continue;
                }

                string current = string.IsNullOrWhiteSpace(block.InterestSubject) ? string.Empty : block.InterestSubject.Trim();
                if (string.Equals(current, normalized, StringComparison.Ordinal))
                {
                    continue;
                }

                block.InterestSubject = normalized;
                changed = true;
            }

            return changed;
        }

        private bool EnsureInterestSubjectForRequiredBases()
        {
            var requiredBlocks = redactionBlocks
                .Where(block => block != null && BlockRequiresInterestSubject(block))
                .ToList();
            if (requiredBlocks.Count == 0)
            {
                return true;
            }

            var missingBlocks = requiredBlocks
                .Where(block => string.IsNullOrWhiteSpace(block.InterestSubject))
                .ToList();

            bool requiresVerification = !Properties.Settings.Default.ExclusionAuthorityVerified;
            if (!requiresVerification)
            {
                string persistedAuthority = GetPreferredExclusionAuthority();
                bool persistedApplyChanged = false;
                if (!string.IsNullOrWhiteSpace(persistedAuthority))
                {
                    persistedApplyChanged = ApplyInterestSubjectToRequiredBlocks(persistedAuthority, onlyMissing: true);
                }

                if (persistedApplyChanged)
                {
                    projectWasChangedAfterLastSave = true;
                    saveProjectButton.Enabled = true;
                    saveProjectMenuItem.Enabled = true;
                }

                // User already confirmed authority once. Do not prompt again.
                // If required blocks are still missing and there is no persisted authority,
                // ask user now to recover a valid value.
                if (missingBlocks.Count == 0 || !string.IsNullOrWhiteSpace(persistedAuthority))
                {
                    return true;
                }
            }

            string initialValue = GetPreferredExclusionAuthority();
            if (!PromptForExclusionAuthority(initialValue, true, out string authorityValue))
            {
                return false;
            }

            string previousAuthority = exclusionAuthorityName ?? string.Empty;
            exclusionAuthorityName = authorityValue;
            SaveExclusionAuthorityUserSetting(exclusionAuthorityName, verified: true);
            bool changed = !string.Equals(previousAuthority.Trim(), exclusionAuthorityName.Trim(), StringComparison.Ordinal);
            foreach (var block in missingBlocks)
            {
                string normalized = authorityValue.Trim();
                if (string.Equals((block.InterestSubject ?? string.Empty).Trim(), normalized, StringComparison.Ordinal))
                {
                    continue;
                }

                block.InterestSubject = normalized;
                changed = true;
            }

            if (changed)
            {
                projectWasChangedAfterLastSave = true;
                saveProjectButton.Enabled = true;
                saveProjectMenuItem.Enabled = true;
            }

            return true;
        }

        private bool TryApplyPersistedInterestSubjectToBlock(RedactionBlock block)
        {
            if (block == null || !Properties.Settings.Default.ExclusionAuthorityVerified)
            {
                return false;
            }

            if (!BlockRequiresInterestSubject(block))
            {
                return false;
            }

            if (!string.IsNullOrWhiteSpace(block.InterestSubject))
            {
                return false;
            }

            string persistedAuthority = GetPreferredExclusionAuthority();
            if (string.IsNullOrWhiteSpace(persistedAuthority))
            {
                return false;
            }

            string normalized = persistedAuthority.Trim();
            block.InterestSubject = normalized;
            return true;
        }

        private bool PromptForExclusionAuthority(string initialValue, bool required, out string authorityValue)
        {
            authorityValue = string.Empty;
            string currentValue = initialValue ?? string.Empty;

            while (true)
            {
                using (Form prompt = new Form())
                {
                    prompt.Width = 620;
                    prompt.Height = 180;
                    prompt.StartPosition = FormStartPosition.CenterParent;
                    prompt.FormBorderStyle = FormBorderStyle.FixedDialog;
                    prompt.MinimizeBox = false;
                    prompt.MaximizeBox = false;
                    prompt.ShowInTaskbar = false;
                    prompt.Text = GetExclusionAuthorityDialogTitleText();

                    Label textLabel = new Label
                    {
                        Left = 10,
                        Top = 16,
                        AutoSize = true,
                        Text = GetExclusionAuthorityDialogLabelText()
                    };

                    TextBox inputBox = new TextBox
                    {
                        Left = 10,
                        Top = 44,
                        Width = 582,
                        Text = currentValue
                    };

                    Button confirmation = new Button
                    {
                        Text = "OK",
                        Left = 432,
                        Width = 78,
                        Top = 82,
                        DialogResult = DialogResult.OK
                    };

                    Button cancel = new Button
                    {
                        Text = GetCancelButtonText(),
                        Left = 514,
                        Width = 78,
                        Top = 82,
                        DialogResult = DialogResult.Cancel
                    };

                    prompt.Controls.Add(textLabel);
                    prompt.Controls.Add(inputBox);
                    prompt.Controls.Add(confirmation);
                    prompt.Controls.Add(cancel);
                    prompt.AcceptButton = confirmation;
                    prompt.CancelButton = cancel;

                    DialogResult result = prompt.ShowDialog(this);
                    if (result != DialogResult.OK)
                    {
                        return false;
                    }

                    string normalized = (inputBox.Text ?? string.Empty).Trim();
                    if (required && string.IsNullOrWhiteSpace(normalized))
                    {
                        MessageBox.Show(
                            this,
                            GetExclusionAuthorityRequiredMessage(),
                            Resources.Title_Warning,
                            MessageBoxButtons.OK,
                            MessageBoxIcon.Warning);
                        currentValue = normalized;
                        continue;
                    }

                    authorityValue = normalized;
                    return true;
                }
            }
        }

        private string GetCancelButtonText()
        {
            return LocalizedText("Dialog_Button_Cancel");
        }

        private void SaveExclusionAuthorityUserSetting(string authorityValue, bool? verified = null)
        {
            try
            {
                Properties.Settings.Default.ExclusionAuthorityName = string.IsNullOrWhiteSpace(authorityValue)
                    ? string.Empty
                    : authorityValue.Trim();
                if (verified.HasValue)
                {
                    Properties.Settings.Default.ExclusionAuthorityVerified = verified.Value;
                }

                Properties.Settings.Default.Save();
            }
            catch (Exception ex)
            {
                LogDebug("Save exclusion authority user setting failed: " + ex.Message);
            }
        }

        private void AddLegalBasisFromContextMenu(RedactionBlock block)
        {
            string globalPath = GetGlobalLegalBasesFilePath();
            string localPath = GetLocalLegalBasesFilePath();
            string globalScopesPath = GetGlobalExclusionScopesFilePath();
            string localScopesPath = GetLocalExclusionScopesFilePath();

            bool canEditGlobal = HasWriteAccessToTarget(globalPath);
            bool canEditLocal = HasWriteAccessToTarget(localPath);
            bool canEditGlobalScopes = HasWriteAccessToTarget(globalScopesPath);
            bool canEditLocalScopes = HasWriteAccessToTarget(localScopesPath);
            string addedBasisId = null;

            if (!canEditGlobal && !canEditLocal)
            {
                ShowInfoMessage(GetLegalBasesNoWriteAccessMessage());
                return;
            }

            if (!TryLoadLegalBasesForEditor(globalPath, LegalBasisSource.Global, out List<LegalBasisDefinition> globalBases, out string globalLoadError))
            {
                ShowInfoMessage(globalLoadError);
                return;
            }

            if (!TryLoadLegalBasesForEditor(localPath, LegalBasisSource.Local, out List<LegalBasisDefinition> localBases, out string localLoadError))
            {
                ShowInfoMessage(localLoadError);
                return;
            }

            if (!TryLoadExclusionScopesForEditor(globalScopesPath, ExclusionScopeSource.Global, out List<ExclusionScopeDefinition> globalScopes, out string globalScopesVersion, out string globalScopesLoadError))
            {
                ShowInfoMessage(globalScopesLoadError);
                return;
            }

            if (!TryLoadExclusionScopesForEditor(localScopesPath, ExclusionScopeSource.Local, out List<ExclusionScopeDefinition> localScopes, out string localScopesVersion, out string localScopesLoadError))
            {
                ShowInfoMessage(localScopesLoadError);
                return;
            }

            LegalBasisSource targetSource = ResolveTargetSourceForNewLegalBasis(block, canEditGlobal, canEditLocal);
            bool canEditTargetScopeAssignments;
            List<ExclusionScopeDefinition> availableScopes;
            List<ExclusionScopeDefinition> scopesToUpdate;
            if (targetSource == LegalBasisSource.Global)
            {
                availableScopes = globalScopes;
                scopesToUpdate = globalScopes;
                canEditTargetScopeAssignments = canEditGlobalScopes;
            }
            else if (localScopes.Count > 0)
            {
                availableScopes = localScopes;
                scopesToUpdate = localScopes;
                canEditTargetScopeAssignments = canEditLocalScopes;
            }
            else
            {
                availableScopes = globalScopes;
                scopesToUpdate = globalScopes;
                canEditTargetScopeAssignments = canEditGlobalScopes;
            }

            string nextId = GenerateNextLegalBasisIdForSource(globalBases, localBases, targetSource);
            using (var dialog = new LegalBasisEditDialog(
                null,
                targetSource,
                nextId,
                availableScopes,
                Enumerable.Empty<string>(),
                canEditTargetScopeAssignments))
            {
                if (dialog.ShowDialog(this) != DialogResult.OK)
                {
                    return;
                }

                LegalBasisDefinition newEntry = CloneLegalBasisDefinition(dialog.Result);
                if (!NormalizeLegalBasisDefinition(newEntry, targetSource))
                {
                    ShowInfoMessage(GetLegalBasesSaveInvalidEntryMessage());
                    return;
                }

                if (globalBases.Concat(localBases).Any(item =>
                    string.Equals(item?.Id, newEntry.Id, StringComparison.OrdinalIgnoreCase)))
                {
                    ShowInfoMessage(string.Format(GetLegalBasesSaveDuplicateIdMessage(), newEntry.Id));
                    return;
                }

                if (IsDuplicateLegalBasisTitle(newEntry.Title, globalBases, localBases))
                {
                    ShowInfoMessage(string.Format(GetLegalBasesSaveDuplicateTitleMessage(), newEntry.Title));
                    return;
                }

                if (targetSource == LegalBasisSource.Global)
                {
                    globalBases.Add(newEntry);
                }
                else
                {
                    localBases.Add(newEntry);
                }

                if (canEditTargetScopeAssignments)
                {
                    ApplyBasisAssignmentsToScopeList(newEntry.Id, dialog.SelectedScopeIds, scopesToUpdate);
                }

                if (canEditGlobal &&
                    !TrySaveLegalBasesForEditor(globalPath, "GLOBAL", LegalBasisSource.Global, globalBases, out string globalSaveError))
                {
                    ShowInfoMessage(globalSaveError);
                    return;
                }

                if (canEditLocal &&
                    !TrySaveLegalBasesForEditor(localPath, "LOCAL", LegalBasisSource.Local, localBases, out string localSaveError))
                {
                    ShowInfoMessage(localSaveError);
                    return;
                }

                if (canEditGlobalScopes &&
                    !TrySaveExclusionScopesForEditor(
                        globalScopesPath,
                        globalScopesVersion,
                        ExclusionScopeSource.Global,
                        globalScopes,
                        out string globalScopesSaveError))
                {
                    ShowInfoMessage(globalScopesSaveError);
                    return;
                }

                if (canEditLocalScopes &&
                    !TrySaveExclusionScopesForEditor(
                        localScopesPath,
                        localScopesVersion,
                        ExclusionScopeSource.Local,
                        localScopes,
                        out string localScopesSaveError))
                {
                    ShowInfoMessage(localScopesSaveError);
                    return;
                }

                addedBasisId = newEntry.Id;
            }

            AssignLegalBasisToBlock(block, addedBasisId);
            LoadFootnotesCatalog();
            ApplyAutomaticFootnotesMenuState();
            ApplyAddObjectsByPageRotationMenuState();
            pdfViewer.Invalidate();
            ShowInfoMessage(GetLegalBasesSavedMessage());
        }

        private LegalBasisSource ResolveTargetSourceForNewLegalBasis(RedactionBlock block, bool canEditGlobal, bool canEditLocal)
        {
            if (block != null && !string.IsNullOrWhiteSpace(block.ScopeId))
            {
                if (exclusionScopesById.TryGetValue(block.ScopeId.Trim(), out ExclusionScopeDefinition scope))
                {
                    if (scope.SourceKind == ExclusionScopeSource.Local && canEditLocal)
                    {
                        return LegalBasisSource.Local;
                    }

                    if (scope.SourceKind == ExclusionScopeSource.Global && canEditGlobal)
                    {
                        return LegalBasisSource.Global;
                    }
                }
            }

            if (canEditLocal)
            {
                return LegalBasisSource.Local;
            }

            return LegalBasisSource.Global;
        }

        private static bool IsDuplicateLegalBasisTitle(string title, IEnumerable<LegalBasisDefinition> globalBases, IEnumerable<LegalBasisDefinition> localBases)
        {
            if (string.IsNullOrWhiteSpace(title))
            {
                return false;
            }

            string targetTitle = title.Trim();
            return (globalBases ?? Enumerable.Empty<LegalBasisDefinition>())
                .Concat(localBases ?? Enumerable.Empty<LegalBasisDefinition>())
                .Any(item => string.Equals((item?.Title ?? string.Empty).Trim(), targetTitle, StringComparison.OrdinalIgnoreCase));
        }

        private void AssignLegalBasisToBlock(RedactionBlock block, string basisId)
        {
            if (block == null || string.IsNullOrWhiteSpace(basisId))
            {
                return;
            }

            if (block.BasisIds == null)
            {
                block.BasisIds = new List<string>();
            }

            string normalizedBasisId = basisId.Trim();
            bool alreadyAssigned = block.BasisIds.Any(id => string.Equals(id, normalizedBasisId, StringComparison.OrdinalIgnoreCase));
            if (alreadyAssigned)
            {
                return;
            }

            block.BasisIds.Add(normalizedBasisId);
            block.ClassificationSource = ClassificationSourceManual;
            block.MatchedTag = null;
            block.FootnoteNumber = null;
            TryApplyPersistedInterestSubjectToBlock(block);

            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
        }

        private static void ApplyBasisAssignmentsToScopeList(string basisId, IEnumerable<string> selectedScopeIds, IList<ExclusionScopeDefinition> scopes)
        {
            if (string.IsNullOrWhiteSpace(basisId) || scopes == null)
            {
                return;
            }

            string targetId = basisId.Trim();
            var selected = new HashSet<string>(
                (selectedScopeIds ?? Enumerable.Empty<string>())
                    .Where(id => !string.IsNullOrWhiteSpace(id))
                    .Select(id => id.Trim()),
                StringComparer.OrdinalIgnoreCase);

            foreach (var scope in scopes)
            {
                if (scope == null)
                {
                    continue;
                }

                var defaultIds = (scope.DefaultBasisIds ?? new List<string>())
                    .Where(id => !string.IsNullOrWhiteSpace(id))
                    .Select(id => id.Trim())
                    .Where(id => !string.Equals(id, targetId, StringComparison.OrdinalIgnoreCase))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToList();

                if (selected.Contains((scope.ScopeId ?? string.Empty).Trim()))
                {
                    defaultIds.Add(targetId);
                }

                scope.DefaultBasisIds = defaultIds.Distinct(StringComparer.OrdinalIgnoreCase).ToList();
            }
        }

        private static string GenerateNextLegalBasisIdForSource(
            IEnumerable<LegalBasisDefinition> globalBases,
            IEnumerable<LegalBasisDefinition> localBases,
            LegalBasisSource sourceKind)
        {
            string prefix = sourceKind == LegalBasisSource.Global ? "G_BASE_" : "L_BASE_";
            var allEntries = (globalBases ?? Enumerable.Empty<LegalBasisDefinition>())
                .Concat(localBases ?? Enumerable.Empty<LegalBasisDefinition>())
                .ToList();

            int maxNumber = 0;
            foreach (var entry in allEntries)
            {
                string id = (entry?.Id ?? string.Empty).Trim();
                if (!id.StartsWith(prefix, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                string numericPart = id.Substring(prefix.Length);
                if (int.TryParse(numericPart, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsed) && parsed > maxNumber)
                {
                    maxNumber = parsed;
                }
            }

            int nextNumber = Math.Max(1, maxNumber + 1);
            while (true)
            {
                string candidate = prefix + nextNumber.ToString("00", CultureInfo.InvariantCulture);
                bool exists = allEntries.Any(entry =>
                    string.Equals((entry?.Id ?? string.Empty).Trim(), candidate, StringComparison.OrdinalIgnoreCase));
                if (!exists)
                {
                    return candidate;
                }

                nextNumber++;
            }
        }

