        private void EnsureObjectLayerOrder()
        {
            if (objectLayerOrder == null)
            {
                objectLayerOrder = new List<ObjectLayerEntry>();
            }

            foreach (var annotation in textAnnotations)
            {
                EnsureTextAnnotationId(annotation);
                EnsureTextAnnotationTimestamps(annotation);
            }
            foreach (var rasterObject in rasterObjects)
            {
                EnsureRasterObjectId(rasterObject);
            }
            foreach (var arrowObject in arrowObjects)
            {
                EnsureArrowObjectId(arrowObject);
            }
            foreach (var vectorShape in vectorShapes)
            {
                EnsureVectorShapeId(vectorShape);
            }

            var existingKeys = new HashSet<string>(StringComparer.Ordinal);
            foreach (var annotation in textAnnotations.Where(a => a != null))
            {
                existingKeys.Add($"Text:{annotation.Id}");
            }
            foreach (var rasterObject in rasterObjects.Where(r => r != null))
            {
                existingKeys.Add($"Raster:{rasterObject.Id}");
            }
            foreach (var arrowObject in arrowObjects.Where(a => a != null))
            {
                existingKeys.Add($"Arrow:{arrowObject.Id}");
            }
            foreach (var vectorShape in vectorShapes.Where(v => v != null))
            {
                existingKeys.Add($"VectorShape:{vectorShape.Id}");
            }

            objectLayerOrder = objectLayerOrder
                .Where(entry => entry != null && !string.IsNullOrWhiteSpace(entry.Id))
                .Where(entry => existingKeys.Contains(GetLayerKey(entry.Type, entry.Id)))
                .GroupBy(entry => GetLayerKey(entry.Type, entry.Id), StringComparer.Ordinal)
                .Select(group => group.First())
                .ToList();

            var currentKeys = new HashSet<string>(
                objectLayerOrder.Select(entry => GetLayerKey(entry.Type, entry.Id)),
                StringComparer.Ordinal);

            foreach (var rasterObject in rasterObjects.Where(r => r != null))
            {
                RegisterLayerIfMissing(LayerObjectType.Raster, rasterObject.Id, currentKeys);
            }
            foreach (var arrowObject in arrowObjects.Where(a => a != null))
            {
                RegisterLayerIfMissing(LayerObjectType.Arrow, arrowObject.Id, currentKeys);
            }
            foreach (var vectorShape in vectorShapes.Where(v => v != null))
            {
                RegisterLayerIfMissing(LayerObjectType.VectorShape, vectorShape.Id, currentKeys);
            }
            foreach (var annotation in textAnnotations.Where(a => a != null))
            {
                RegisterLayerIfMissing(LayerObjectType.Text, annotation.Id, currentKeys);
            }
        }

        private void RegisterLayerIfMissing(LayerObjectType type, string id, ISet<string> currentKeys)
        {
            if (string.IsNullOrWhiteSpace(id))
            {
                return;
            }

            string key = GetLayerKey(type, id);
            if (currentKeys.Contains(key))
            {
                return;
            }

            objectLayerOrder.Add(new ObjectLayerEntry { Type = type, Id = id });
            currentKeys.Add(key);
        }

        private static string GetLayerKey(LayerObjectType type, string id)
        {
            return $"{type}:{id?.Trim()}";
        }

        private int GetLayerIndex(LayerObjectType type, string id)
        {
            EnsureObjectLayerOrder();
            string key = GetLayerKey(type, id);
            for (int i = 0; i < objectLayerOrder.Count; i++)
            {
                if (string.Equals(GetLayerKey(objectLayerOrder[i].Type, objectLayerOrder[i].Id), key, StringComparison.Ordinal))
                {
                    return i;
                }
            }

            return -1;
        }

        private string GetObjectLayerId(ObjectLayerEntry entry)
        {
            if (entry == null || string.IsNullOrWhiteSpace(entry.Id))
            {
                return DefaultLayerId;
            }

            string entryId = entry.Id.Trim();
            switch (entry.Type)
            {
                case LayerObjectType.Text:
                    return NormalizeLayerIdValue(textAnnotations.FirstOrDefault(a => a != null && string.Equals(a.Id, entryId, StringComparison.Ordinal))?.LayerId);
                case LayerObjectType.Raster:
                    return NormalizeLayerIdValue(rasterObjects.FirstOrDefault(r => r != null && string.Equals(r.Id, entryId, StringComparison.Ordinal))?.LayerId);
                case LayerObjectType.Arrow:
                    return NormalizeLayerIdValue(arrowObjects.FirstOrDefault(a => a != null && string.Equals(a.Id, entryId, StringComparison.Ordinal))?.LayerId);
                case LayerObjectType.VectorShape:
                    return NormalizeLayerIdValue(vectorShapes.FirstOrDefault(v => v != null && string.Equals(v.Id, entryId, StringComparison.Ordinal))?.LayerId);
                default:
                    return DefaultLayerId;
            }
        }

        private bool BringLayerToFront(LayerObjectType type, string id)
        {
            int index = GetLayerIndex(type, id);
            if (index < 0)
            {
                return false;
            }

            var entry = objectLayerOrder[index];
            string sourceLayerId = GetObjectLayerId(entry);
            objectLayerOrder.RemoveAt(index);
            int targetIndex = objectLayerOrder.FindLastIndex(candidate => string.Equals(GetObjectLayerId(candidate), sourceLayerId, StringComparison.OrdinalIgnoreCase));
            if (targetIndex < 0)
            {
                objectLayerOrder.Insert(index, entry);
                return false;
            }

            objectLayerOrder.Insert(targetIndex + 1, entry);
            return true;
        }

        private bool SendLayerToBack(LayerObjectType type, string id)
        {
            int index = GetLayerIndex(type, id);
            if (index < 0)
            {
                return false;
            }

            var entry = objectLayerOrder[index];
            string sourceLayerId = GetObjectLayerId(entry);
            objectLayerOrder.RemoveAt(index);
            int targetIndex = objectLayerOrder.FindIndex(candidate => string.Equals(GetObjectLayerId(candidate), sourceLayerId, StringComparison.OrdinalIgnoreCase));
            if (targetIndex < 0)
            {
                objectLayerOrder.Insert(index, entry);
                return false;
            }

            objectLayerOrder.Insert(targetIndex, entry);
            return true;
        }

        private bool MoveLayerForward(LayerObjectType type, string id)
        {
            int index = GetLayerIndex(type, id);
            if (index < 0 || index >= objectLayerOrder.Count - 1)
            {
                return false;
            }

            ObjectLayerEntry sourceEntry = objectLayerOrder[index];
            string sourceLayerId = GetObjectLayerId(sourceEntry);
            if (!TryGetLayerEntryPageAndBounds(sourceEntry, out int sourcePage, out RectangleF sourceBounds))
            {
                return false;
            }

            int targetIndex = -1;
            for (int i = index + 1; i < objectLayerOrder.Count; i++)
            {
                ObjectLayerEntry candidate = objectLayerOrder[i];
                if (!TryGetLayerEntryPageAndBounds(candidate, out int candidatePage, out RectangleF candidateBounds))
                {
                    continue;
                }

                if (!string.Equals(GetObjectLayerId(candidate), sourceLayerId, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                if (candidatePage != sourcePage)
                {
                    continue;
                }

                if (!DoLayerBoundsOverlap(sourceBounds, candidateBounds))
                {
                    continue;
                }

                targetIndex = i;
                break;
            }

            if (targetIndex < 0)
            {
                return false;
            }

            ObjectLayerEntry targetEntry = objectLayerOrder[targetIndex];
            objectLayerOrder[index] = targetEntry;
            objectLayerOrder[targetIndex] = sourceEntry;
            return true;
        }

        private bool MoveLayerBackward(LayerObjectType type, string id)
        {
            int index = GetLayerIndex(type, id);
            if (index <= 0)
            {
                return false;
            }

            ObjectLayerEntry sourceEntry = objectLayerOrder[index];
            string sourceLayerId = GetObjectLayerId(sourceEntry);
            if (!TryGetLayerEntryPageAndBounds(sourceEntry, out int sourcePage, out RectangleF sourceBounds))
            {
                return false;
            }

            int targetIndex = -1;
            for (int i = index - 1; i >= 0; i--)
            {
                ObjectLayerEntry candidate = objectLayerOrder[i];
                if (!TryGetLayerEntryPageAndBounds(candidate, out int candidatePage, out RectangleF candidateBounds))
                {
                    continue;
                }

                if (!string.Equals(GetObjectLayerId(candidate), sourceLayerId, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                if (candidatePage != sourcePage)
                {
                    continue;
                }

                if (!DoLayerBoundsOverlap(sourceBounds, candidateBounds))
                {
                    continue;
                }

                targetIndex = i;
                break;
            }

            if (targetIndex < 0)
            {
                return false;
            }

            ObjectLayerEntry targetEntry = objectLayerOrder[targetIndex];
            objectLayerOrder[index] = targetEntry;
            objectLayerOrder[targetIndex] = sourceEntry;
            return true;
        }

        private static RectangleF NormalizeLayerBounds(RectangleF bounds)
        {
            if (bounds.Width < 0f)
            {
                bounds = new RectangleF(bounds.X + bounds.Width, bounds.Y, -bounds.Width, bounds.Height);
            }

            if (bounds.Height < 0f)
            {
                bounds = new RectangleF(bounds.X, bounds.Y + bounds.Height, bounds.Width, -bounds.Height);
            }

            float normalizedWidth = bounds.Width;
            float normalizedHeight = bounds.Height;
            float normalizedX = bounds.X;
            float normalizedY = bounds.Y;

            if (normalizedWidth < 1f)
            {
                float delta = 1f - normalizedWidth;
                normalizedX -= delta / 2f;
                normalizedWidth = 1f;
            }

            if (normalizedHeight < 1f)
            {
                float delta = 1f - normalizedHeight;
                normalizedY -= delta / 2f;
                normalizedHeight = 1f;
            }

            return new RectangleF(normalizedX, normalizedY, normalizedWidth, normalizedHeight);
        }

        private static bool DoLayerBoundsOverlap(RectangleF sourceBounds, RectangleF candidateBounds)
        {
            RectangleF normalizedSource = NormalizeLayerBounds(sourceBounds);
            RectangleF normalizedCandidate = NormalizeLayerBounds(candidateBounds);
            return normalizedSource.IntersectsWith(normalizedCandidate);
        }

        private bool TryGetLayerEntryPageAndBounds(ObjectLayerEntry entry, out int pageNumber, out RectangleF bounds)
        {
            pageNumber = 0;
            bounds = RectangleF.Empty;

            if (entry == null || string.IsNullOrWhiteSpace(entry.Id))
            {
                return false;
            }

            string entryId = entry.Id.Trim();
            switch (entry.Type)
            {
                case LayerObjectType.Text:
                {
                    TextAnnotation annotation = textAnnotations.FirstOrDefault(a => a != null && string.Equals(a.Id, entryId, StringComparison.Ordinal));
                    if (annotation == null)
                    {
                        return false;
                    }

                    pageNumber = annotation.PageNumber;
                    bounds = annotation.AnnotationBounds;
                    return true;
                }
                case LayerObjectType.Raster:
                {
                    RasterObject raster = rasterObjects.FirstOrDefault(r => r != null && string.Equals(r.Id, entryId, StringComparison.Ordinal));
                    if (raster == null)
                    {
                        return false;
                    }

                    int rotation = NormalizeRotation(raster.Rotation);
                    RectangleF rasterBounds = raster.Bounds;
                    if (rasterBounds.Width <= 0f || rasterBounds.Height <= 0f)
                    {
                        return false;
                    }

                    GetRotatedHalfExtents(rasterBounds.Width, rasterBounds.Height, rotation, out float halfExtentX, out float halfExtentY);
                    float centerX = rasterBounds.X + (rasterBounds.Width / 2f);
                    float centerY = rasterBounds.Y + (rasterBounds.Height / 2f);
                    pageNumber = raster.PageNumber;
                    bounds = RectangleF.FromLTRB(
                        centerX - halfExtentX,
                        centerY - halfExtentY,
                        centerX + halfExtentX,
                        centerY + halfExtentY);
                    return true;
                }
                case LayerObjectType.Arrow:
                {
                    ArrowObject arrow = arrowObjects.FirstOrDefault(a => a != null && string.Equals(a.Id, entryId, StringComparison.Ordinal));
                    if (arrow == null)
                    {
                        return false;
                    }

                    pageNumber = arrow.PageNumber;
                    bounds = RectangleF.FromLTRB(
                        Math.Min(arrow.Start.X, arrow.End.X),
                        Math.Min(arrow.Start.Y, arrow.End.Y),
                        Math.Max(arrow.Start.X, arrow.End.X),
                        Math.Max(arrow.Start.Y, arrow.End.Y));
                    return true;
                }
                case LayerObjectType.VectorShape:
                {
                    VectorShapeObject vectorShape = vectorShapes.FirstOrDefault(v => v != null && string.Equals(v.Id, entryId, StringComparison.Ordinal));
                    if (vectorShape == null)
                    {
                        return false;
                    }

                    pageNumber = vectorShape.PageNumber;
                    bounds = GetVectorShapeBounds(vectorShape.Points);
                    return !bounds.IsEmpty || (bounds.Width == 0f && bounds.Height == 0f);
                }
                default:
                    return false;
            }
        }

        private IEnumerable<ObjectLayerEntry> EnumerateObjectLayerEntriesInVisualOrder(Func<ObjectLayerEntry, bool> predicate = null)
        {
            EnsureSystemLayers();
            EnsureObjectLayerOrder();

            var layerOrderLookup = documentLayers
                .Select((layer, index) => new { LayerId = NormalizeLayerIdValue(layer.Id), Index = index })
                .ToDictionary(item => item.LayerId, item => item.Index, StringComparer.OrdinalIgnoreCase);

            IEnumerable<ObjectLayerEntry> orderedEntries = objectLayerOrder
                .Where(entry => entry != null && !string.IsNullOrWhiteSpace(entry.Id))
                .OrderBy(entry =>
                {
                    string layerId = GetObjectLayerId(entry);
                    return layerOrderLookup.TryGetValue(layerId, out int index) ? -index : int.MinValue;
                })
                .ThenBy(entry => objectLayerOrder.IndexOf(entry));

            if (predicate != null)
            {
                orderedEntries = orderedEntries.Where(predicate);
            }

            return orderedEntries;
        }

        private IEnumerable<object> GetOrderedObjectsForCurrentPage()
        {
            foreach (var entry in EnumerateObjectLayerEntriesInVisualOrder())
            {
                switch (entry.Type)
                {
                    case LayerObjectType.Text:
                    {
                        var annotation = textAnnotations.FirstOrDefault(a => a != null && a.PageNumber == currentPage && string.Equals(a.Id, entry.Id, StringComparison.Ordinal));
                        if (annotation != null && IsLayerVisible(annotation.LayerId))
                        {
                            yield return annotation;
                        }
                        break;
                    }
                    case LayerObjectType.Raster:
                    {
                        var rasterObject = rasterObjects.FirstOrDefault(r => r != null && r.PageNumber == currentPage && string.Equals(r.Id, entry.Id, StringComparison.Ordinal));
                        if (rasterObject != null && IsLayerVisible(rasterObject.LayerId))
                        {
                            yield return rasterObject;
                        }
                        break;
                    }
                    case LayerObjectType.Arrow:
                    {
                        var arrowObject = arrowObjects.FirstOrDefault(a => a != null && a.PageNumber == currentPage && string.Equals(a.Id, entry.Id, StringComparison.Ordinal));
                        if (arrowObject != null && IsLayerVisible(arrowObject.LayerId))
                        {
                            yield return arrowObject;
                        }
                        break;
                    }
                    case LayerObjectType.VectorShape:
                    {
                        var vectorShape = vectorShapes.FirstOrDefault(v => v != null && v.PageNumber == currentPage && string.Equals(v.Id, entry.Id, StringComparison.Ordinal));
                        if (vectorShape != null && IsLayerVisible(vectorShape.LayerId))
                        {
                            yield return vectorShape;
                        }
                        break;
                    }
                }
            }
        }

        private IEnumerable<object> GetOrderedObjectsForPage(int pageNumber, Func<string, bool> layerPredicate)
        {
            layerPredicate = layerPredicate ?? (_ => true);

            foreach (var entry in EnumerateObjectLayerEntriesInVisualOrder(entry =>
                entry.Type == LayerObjectType.Text ||
                entry.Type == LayerObjectType.Raster ||
                entry.Type == LayerObjectType.Arrow ||
                entry.Type == LayerObjectType.VectorShape))
            {
                switch (entry.Type)
                {
                    case LayerObjectType.Text:
                    {
                        var annotation = textAnnotations.FirstOrDefault(a => a != null && a.PageNumber == pageNumber && string.Equals(a.Id, entry.Id, StringComparison.Ordinal));
                        if (annotation != null && layerPredicate(annotation.LayerId))
                        {
                            yield return annotation;
                        }
                        break;
                    }
                    case LayerObjectType.Raster:
                    {
                        var rasterObject = rasterObjects.FirstOrDefault(r => r != null && r.PageNumber == pageNumber && string.Equals(r.Id, entry.Id, StringComparison.Ordinal));
                        if (rasterObject != null && layerPredicate(rasterObject.LayerId))
                        {
                            yield return rasterObject;
                        }
                        break;
                    }
                    case LayerObjectType.Arrow:
                    {
                        var arrowObject = arrowObjects.FirstOrDefault(a => a != null && a.PageNumber == pageNumber && string.Equals(a.Id, entry.Id, StringComparison.Ordinal));
                        if (arrowObject != null && layerPredicate(arrowObject.LayerId))
                        {
                            yield return arrowObject;
                        }
                        break;
                    }
                    case LayerObjectType.VectorShape:
                    {
                        var vectorShape = vectorShapes.FirstOrDefault(v => v != null && v.PageNumber == pageNumber && string.Equals(v.Id, entry.Id, StringComparison.Ordinal));
                        if (vectorShape != null && layerPredicate(vectorShape.LayerId))
                        {
                            yield return vectorShape;
                        }
                        break;
                    }
                }
            }
        }

        private IEnumerable<string> EnumerateLayerIdsInVisualOrder()
        {
            EnsureSystemLayers();
            return (documentLayers ?? new List<LayerDefinition>())
                .Where(layer => layer != null)
                .Select(layer => NormalizeLayerIdValue(layer.Id))
                .Where(layerId => !string.IsNullOrWhiteSpace(layerId))
                .Reverse();
        }

        private IEnumerable<object> GetOrderedGraphicObjectsForExport()
        {
            foreach (var entry in EnumerateObjectLayerEntriesInVisualOrder(entry =>
                entry.Type == LayerObjectType.Text ||
                entry.Type == LayerObjectType.Raster ||
                entry.Type == LayerObjectType.Arrow ||
                entry.Type == LayerObjectType.VectorShape))
            {
                if (entry.Type == LayerObjectType.Text)
                {
                    var annotation = textAnnotations.FirstOrDefault(a => a != null && string.Equals(a.Id, entry.Id, StringComparison.Ordinal));
                    if (annotation != null && ShouldExportLayer(annotation.LayerId))
                    {
                        yield return annotation;
                    }
                }
                else if (entry.Type == LayerObjectType.Raster)
                {
                    var rasterObject = rasterObjects.FirstOrDefault(r => r != null && string.Equals(r.Id, entry.Id, StringComparison.Ordinal));
                    if (rasterObject != null && ShouldExportLayer(rasterObject.LayerId))
                    {
                        yield return rasterObject;
                    }
                }
                else if (entry.Type == LayerObjectType.Arrow)
                {
                    var arrowObject = arrowObjects.FirstOrDefault(a => a != null && string.Equals(a.Id, entry.Id, StringComparison.Ordinal));
                    if (arrowObject != null && ShouldExportLayer(arrowObject.LayerId))
                    {
                        yield return arrowObject;
                    }
                }
                else if (entry.Type == LayerObjectType.VectorShape)
                {
                    var vectorShape = vectorShapes.FirstOrDefault(v => v != null && string.Equals(v.Id, entry.Id, StringComparison.Ordinal));
                    if (vectorShape != null && ShouldExportLayer(vectorShape.LayerId))
                    {
                        yield return vectorShape;
                    }
                }
            }
        }

        private List<ProjectObjectLayer> BuildProjectObjectLayersSnapshot()
        {
            EnsureObjectLayerOrder();
            return objectLayerOrder
                .Where(entry => entry != null && !string.IsNullOrWhiteSpace(entry.Id))
                .Select(entry => new ProjectObjectLayer
                {
                    Type = entry.Type.ToString(),
                    Id = entry.Id
                })
                .ToList();
        }

        private void LoadProjectObjectLayerOrder(List<ProjectObjectLayer> layers)
        {
            if (layers == null)
            {
                objectLayerOrder = new List<ObjectLayerEntry>();
                EnsureObjectLayerOrder();
                return;
            }

            objectLayerOrder = layers
                .Where(layer => layer != null && !string.IsNullOrWhiteSpace(layer.Id))
                .Select(layer => new ObjectLayerEntry
                {
                    Type = ParseLayerObjectType(layer.Type),
                    Id = layer.Id.Trim()
                })
                .ToList();

            EnsureObjectLayerOrder();
        }

        private static LayerObjectType ParseLayerObjectType(string value)
        {
            if (!string.IsNullOrWhiteSpace(value) &&
                Enum.TryParse(value.Trim(), true, out LayerObjectType parsed))
            {
                return parsed;
            }

            return LayerObjectType.Raster;
        }

        private List<object> GetSelectedObjectsOnCurrentPage()
        {
            var selectedObjects = new HashSet<object>();
            var orderedSelectedObjects = new List<object>();

            void RegisterSelectedObject(object candidate)
            {
                if (candidate == null)
                {
                    return;
                }

                if (selectedObjects.Add(candidate))
                {
                    orderedSelectedObjects.Add(candidate);
                }
            }

            foreach (TextAnnotation text in selectedTextAnnotations.Where(t => t != null && t.PageNumber == currentPage))
            {
                RegisterSelectedObject(text);
            }

            if (selectedTextAnnotation != null && selectedTextAnnotation.PageNumber == currentPage)
            {
                RegisterSelectedObject(selectedTextAnnotation);
            }

            foreach (string rasterId in selectedRasterObjectIds)
            {
                RasterObject raster = rasterObjects.FirstOrDefault(r => r != null && r.PageNumber == currentPage && r.Id == rasterId);
                if (raster != null)
                {
                    RegisterSelectedObject(raster);
                }
            }

            if (selectedRasterObject != null && selectedRasterObject.PageNumber == currentPage)
            {
                RegisterSelectedObject(selectedRasterObject);
            }

            foreach (string arrowId in selectedArrowObjectIds)
            {
                ArrowObject arrow = arrowObjects.FirstOrDefault(a => a != null && a.PageNumber == currentPage && a.Id == arrowId);
                if (arrow != null)
                {
                    RegisterSelectedObject(arrow);
                }
            }

            if (selectedArrowObject != null && selectedArrowObject.PageNumber == currentPage)
            {
                RegisterSelectedObject(selectedArrowObject);
            }

            if (selectedVectorShape != null && selectedVectorShape.PageNumber == currentPage)
            {
                RegisterSelectedObject(selectedVectorShape);
            }

            foreach (string vectorId in selectedVectorShapeIds)
            {
                VectorShapeObject vectorShape = vectorShapes.FirstOrDefault(v => v != null && v.PageNumber == currentPage && v.Id == vectorId);
                if (vectorShape != null)
                {
                    RegisterSelectedObject(vectorShape);
                }
            }

            return orderedSelectedObjects;
        }

        private object GetCurrentSingleSelectedObject()
        {
            List<object> selectedObjects = GetSelectedObjectsOnCurrentPage();
            return selectedObjects.Count == 1 ? selectedObjects[0] : null;
        }

        private int GetTotalSelectedObjectsCount()
        {
            return GetSelectedObjectsOnCurrentPage().Count;
        }

        private string BuildObjectSelectionInfoText()
        {
            if (isVectorShapeCreationMode)
            {
                return BuildVectorShapeCreationInfoText();
            }

            List<object> selectedObjects = GetSelectedObjectsOnCurrentPage();
            int selectedCount = selectedObjects.Count;
            if (selectedCount <= 0)
            {
                if (selectedCommentAnnotation == null ||
                    selectedCommentAnnotation.PageNumber != currentPage ||
                    !IsLayerVisible(selectedCommentAnnotation.LayerId))
                {
                    return null;
                }

                string commentLayerInfoText = GetSelectionInfoLayerText(new[] { GetSelectionInfoLayerId(selectedCommentAnnotation) });
                string commentTypeText = GetSelectionInfoObjectTypeText(selectedCommentAnnotation);
                return AppendSelectionInfoLayerText(commentLayerInfoText, commentTypeText);
            }

            List<string> selectedLayerIds = GetSelectionInfoLayerIds(selectedObjects);
            string layerInfoText = GetSelectionInfoLayerText(selectedLayerIds);

            if (selectedCount == 1)
            {
                string objectTypeText = GetSelectionInfoObjectTypeText(selectedObjects[0]);
                return AppendSelectionInfoLayerText(layerInfoText, objectTypeText);
            }

            string countText = GetSelectionInfoCountText(selectedCount);
            return AppendSelectionInfoLayerText(layerInfoText, countText);
        }

        private string BuildVectorShapeCreationInfoText()
        {
            string shapeName = GetShapeTypeDisplayName(activeVectorShapeType);
            string language = (Resources.Culture ?? CultureInfo.CurrentUICulture).TwoLetterISOLanguageName?.ToLowerInvariant() ?? string.Empty;
            int pointCount = vectorShapeDraftPoints?.Count ?? 0;

            switch (activeVectorShapeType)
            {
                case VectorShapeType.Polyline:
                case VectorShapeType.Region:
                    switch (language)
                    {
                        case "pl":
                            return $"{shapeName} | Punkty: {pointCount} | LPM: dodaj punkt | PPM: zakończ rysowanie";
                        case "de":
                            return $"{shapeName} | Punkte: {pointCount} | LMT: Punkt hinzufügen | RMT: Zeichnen beenden";
                        default:
                            return $"{shapeName} | Points: {pointCount} | LMB: add point | RMB: finish drawing";
                    }

                case VectorShapeType.Arc:
                    switch (language)
                    {
                        case "pl":
                            return $"{shapeName} | Punkty: {Math.Min(pointCount, 3)}/3 | LPM: wskaż 3 punkty";
                        case "de":
                            return $"{shapeName} | Punkte: {Math.Min(pointCount, 3)}/3 | LMT: 3 Punkte angeben";
                        default:
                            return $"{shapeName} | Points: {Math.Min(pointCount, 3)}/3 | LMB: choose 3 points";
                    }

                default:
                    switch (language)
                    {
                        case "pl":
                            return $"{shapeName} | Punkty: {Math.Min(pointCount, 2)}/2 | LPM: wskaż 2 punkty";
                        case "de":
                            return $"{shapeName} | Punkte: {Math.Min(pointCount, 2)}/2 | LMT: 2 Punkte angeben";
                        default:
                            return $"{shapeName} | Points: {Math.Min(pointCount, 2)}/2 | LMB: choose 2 points";
                    }
            }
        }

        private string GetSelectionInfoCountText(int selectedCount)
        {
            string language = (Resources.Culture ?? CultureInfo.CurrentUICulture).TwoLetterISOLanguageName?.ToLowerInvariant() ?? string.Empty;
            switch (language)
            {
                case "pl":
                    return $"Obiekty: {selectedCount}";
                case "de":
                    return $"Objekte: {selectedCount}";
                default:
                    return $"Objects: {selectedCount}";
            }
        }

        private string GetSelectionInfoObjectTypeText(object selectedObject)
        {
            string language = (Resources.Culture ?? CultureInfo.CurrentUICulture).TwoLetterISOLanguageName?.ToLowerInvariant() ?? string.Empty;

            switch (selectedObject)
            {
                case TextAnnotation _:
                    switch (language)
                    {
                        case "pl":
                            return "Napis";
                        case "de":
                            return "Text";
                        default:
                            return "Text";
                    }

                case RasterObject _:
                    switch (language)
                    {
                        case "pl":
                            return "Obraz";
                        case "de":
                            return "Bild";
                        default:
                            return "Image";
                    }

                case CommentAnnotation _:
                    return LocalizedText("Comment_DefaultText");

                case ArrowObject _:
                    switch (language)
                    {
                        case "pl":
                            return "Strzałka";
                        case "de":
                            return "Pfeil";
                        default:
                            return "Arrow";
                    }

                case VectorShapeObject vectorShape:
                    return GetShapeTypeDisplayName(ParseVectorShapeType(vectorShape.ShapeType));

                default:
                    return null;
            }
        }

        private List<string> GetSelectionInfoLayerIds(IEnumerable<object> selectedObjects)
        {
            return (selectedObjects ?? Enumerable.Empty<object>())
                .Select(GetSelectionInfoLayerId)
                .Where(layerId => !string.IsNullOrWhiteSpace(layerId))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();
        }

        private string GetSelectionInfoLayerId(object selectedObject)
        {
            switch (selectedObject)
            {
                case TextAnnotation textAnnotation:
                    return NormalizeLayerIdValue(textAnnotation.LayerId);
                case RasterObject rasterObject:
                    return NormalizeLayerIdValue(rasterObject.LayerId);
                case CommentAnnotation commentAnnotation:
                    return NormalizeLayerIdValue(commentAnnotation.LayerId);
                case ArrowObject arrowObject:
                    return NormalizeLayerIdValue(arrowObject.LayerId);
                case VectorShapeObject vectorShape:
                    return NormalizeLayerIdValue(vectorShape.LayerId);
                default:
                    return null;
            }
        }

        private string GetSelectionInfoLayerText(IReadOnlyList<string> layerIds)
        {
            if (layerIds == null || layerIds.Count <= 0)
            {
                return null;
            }

            string language = (Resources.Culture ?? CultureInfo.CurrentUICulture).TwoLetterISOLanguageName?.ToLowerInvariant() ?? string.Empty;
            if (layerIds.Count == 1)
            {
                return GetSelectionInfoLayerDisplayName(layerIds[0]);
            }

            switch (language)
            {
                case "pl":
                    return $"Warstwy: {layerIds.Count}";
                case "de":
                    return $"Ebenen: {layerIds.Count}";
                default:
                    return $"Layers: {layerIds.Count}";
            }
        }

        private string GetSelectionInfoLayerDisplayName(string layerId)
        {
            string normalizedLayerId = NormalizeLayerIdValue(layerId);
            LayerDefinition layer = documentLayers.FirstOrDefault(candidate =>
                string.Equals(NormalizeLayerIdValue(candidate?.Id), normalizedLayerId, StringComparison.OrdinalIgnoreCase));
            return NormalizeLayerDisplayName(layer?.Name, normalizedLayerId);
        }

        private static string AppendSelectionInfoLayerText(string layerText, string baseText)
        {
            if (string.IsNullOrWhiteSpace(layerText))
            {
                return baseText;
            }

            if (string.IsNullOrWhiteSpace(baseText))
            {
                return layerText;
            }

            return $"{layerText} | {baseText}";
        }

        private static Font CloneFontSafe(Font source)
        {
            if (source == null)
            {
                return new Font("Arial", 12f);
            }

            try
            {
                return (Font)source.Clone();
            }
            catch
            {
                return new Font(source.FontFamily, source.Size, source.Style, source.Unit);
            }
        }

        private static TextAnnotation CloneTextAnnotation(TextAnnotation source)
        {
            if (source == null)
            {
                return null;
            }

            return new TextAnnotation
            {
                Id = source.Id,
                PageNumber = source.PageNumber,
                LayerId = NormalizeLayerIdValue(source.LayerId),
                AnnotationText = source.AnnotationText,
                AnnotationFont = CloneFontSafe(source.AnnotationFont),
                AnnotationColor = source.AnnotationColor,
                AnnotationBackgroundColorArgb = source.AnnotationBackgroundColorArgb,
                AnnotationBorderColorArgb = source.AnnotationBorderColorArgb,
                AnnotationBorderWidth = source.AnnotationBorderWidth,
                AnnotationFrameMargin = source.AnnotationFrameMargin,
                HasLeaderArrow = source.HasLeaderArrow,
                LeaderLineWidth = NormalizeLeaderLineWidth(source.LeaderLineWidth),
                LeaderAnchorKind = NormalizeTextLeaderAnchorKind(source.LeaderAnchorKind),
                LeaderEndPoint = source.LeaderEndPoint,
                LeaderHeadLength = NormalizeTextLeaderHeadLength(source.LeaderHeadLength),
                LeaderHeadWidth = NormalizeTextLeaderHeadWidth(source.LeaderHeadWidth),
                AnnotationContentMode = source.AnnotationContentMode,
                AnnotationRichText = source.AnnotationRichText,
                AnnotationAlignment = source.AnnotationAlignment,
                AnnotationRotation = source.AnnotationRotation,
                AnnotationBounds = source.AnnotationBounds,
                AnnotationIsLocked = source.AnnotationIsLocked,
                DuplicateGroupId = source.DuplicateGroupId,
                CreatedAtUtc = source.CreatedAtUtc,
                UpdatedAtUtc = source.UpdatedAtUtc
            };
        }

        private static void RestoreTextAnnotationFromSnapshot(TextAnnotation target, TextAnnotation snapshot)
        {
            if (target == null || snapshot == null)
            {
                return;
            }

            target.AnnotationText = snapshot.AnnotationText;
            target.AnnotationFont = CloneFontSafe(snapshot.AnnotationFont);
            target.AnnotationColor = snapshot.AnnotationColor;
            target.AnnotationBackgroundColorArgb = snapshot.AnnotationBackgroundColorArgb;
            target.AnnotationBorderColorArgb = snapshot.AnnotationBorderColorArgb;
            target.AnnotationBorderWidth = snapshot.AnnotationBorderWidth;
            target.AnnotationFrameMargin = snapshot.AnnotationFrameMargin;
            target.HasLeaderArrow = snapshot.HasLeaderArrow;
            target.LeaderLineWidth = NormalizeLeaderLineWidth(snapshot.LeaderLineWidth);
            target.LeaderAnchorKind = NormalizeTextLeaderAnchorKind(snapshot.LeaderAnchorKind);
            target.LeaderEndPoint = snapshot.LeaderEndPoint;
            target.LeaderHeadLength = NormalizeTextLeaderHeadLength(snapshot.LeaderHeadLength);
            target.LeaderHeadWidth = NormalizeTextLeaderHeadWidth(snapshot.LeaderHeadWidth);
            target.AnnotationContentMode = snapshot.AnnotationContentMode;
            target.AnnotationRichText = snapshot.AnnotationRichText;
            target.AnnotationAlignment = snapshot.AnnotationAlignment;
            target.AnnotationRotation = snapshot.AnnotationRotation;
            target.AnnotationBounds = snapshot.AnnotationBounds;
            target.AnnotationIsLocked = snapshot.AnnotationIsLocked;
            target.DuplicateGroupId = snapshot.DuplicateGroupId;
            target.CreatedAtUtc = snapshot.CreatedAtUtc;
            target.UpdatedAtUtc = snapshot.UpdatedAtUtc;
        }

        private bool TryGetObjectBoundsForClipboard(object selectedObject, out RectangleF bounds)
        {
            bounds = RectangleF.Empty;
            if (selectedObject is TextAnnotation textAnnotation)
            {
                bounds = TryGetTextAnnotationVisualDocBounds(textAnnotation, out RectangleF textBounds)
                    ? textBounds
                    : textAnnotation.AnnotationBounds;
                return bounds.Width > 0f || bounds.Height > 0f;
            }

            if (selectedObject is RasterObject rasterObject)
            {
                bounds = rasterObject.Bounds;
                return bounds.Width > 0f || bounds.Height > 0f;
            }

            if (selectedObject is ArrowObject arrowObject)
            {
                float minX = Math.Min(arrowObject.Start.X, arrowObject.End.X);
                float minY = Math.Min(arrowObject.Start.Y, arrowObject.End.Y);
                float maxX = Math.Max(arrowObject.Start.X, arrowObject.End.X);
                float maxY = Math.Max(arrowObject.Start.Y, arrowObject.End.Y);
                bounds = RectangleF.FromLTRB(minX, minY, maxX, maxY);
                return bounds.Width > 0f || bounds.Height > 0f;
            }

            if (selectedObject is VectorShapeObject vectorShapeObject)
            {
                bounds = GetVectorShapeBounds(vectorShapeObject.Points);
                return !bounds.IsEmpty;
            }

            return false;
        }

        private List<object> GetSelectedObjectsOnCurrentPageInLayerOrder()
        {
            var orderedSelection = new List<object>();
            var addedKeys = new HashSet<string>(StringComparer.Ordinal);

            string BuildKey(ObjectClipboardItemType type, string id)
            {
                return $"{type}:{id}";
            }

            foreach (ObjectLayerEntry layer in EnumerateObjectLayerEntriesInVisualOrder())
            {
                switch (layer.Type)
                {
                    case LayerObjectType.Text:
                    {
                        TextAnnotation text = textAnnotations.FirstOrDefault(a =>
                            a != null &&
                            a.PageNumber == currentPage &&
                            string.Equals(a.Id, layer.Id, StringComparison.Ordinal));
                        if (text == null || !IsTextAnnotationSelected(text))
                        {
                            continue;
                        }

                        EnsureTextAnnotationId(text);
                        string key = BuildKey(ObjectClipboardItemType.Text, text.Id);
                        if (addedKeys.Add(key))
                        {
                            orderedSelection.Add(text);
                        }
                        break;
                    }
                    case LayerObjectType.Raster:
                    {
                        RasterObject raster = rasterObjects.FirstOrDefault(r =>
                            r != null &&
                            r.PageNumber == currentPage &&
                            string.Equals(r.Id, layer.Id, StringComparison.Ordinal));
                        if (raster == null || !IsRasterObjectSelected(raster))
                        {
                            continue;
                        }

                        EnsureRasterObjectId(raster);
                        string key = BuildKey(ObjectClipboardItemType.Raster, raster.Id);
                        if (addedKeys.Add(key))
                        {
                            orderedSelection.Add(raster);
                        }
                        break;
                    }
                    case LayerObjectType.Arrow:
                    {
                        ArrowObject arrow = arrowObjects.FirstOrDefault(a =>
                            a != null &&
                            a.PageNumber == currentPage &&
                            string.Equals(a.Id, layer.Id, StringComparison.Ordinal));
                        if (arrow == null || !IsArrowObjectSelected(arrow))
                        {
                            continue;
                        }

                        EnsureArrowObjectId(arrow);
                        string key = BuildKey(ObjectClipboardItemType.Arrow, arrow.Id);
                        if (addedKeys.Add(key))
                        {
                            orderedSelection.Add(arrow);
                        }
                        break;
                    }
                    case LayerObjectType.VectorShape:
                    {
                        VectorShapeObject vector = vectorShapes.FirstOrDefault(v =>
                            v != null &&
                            v.PageNumber == currentPage &&
                            string.Equals(v.Id, layer.Id, StringComparison.Ordinal));
                        if (vector == null || !IsVectorShapeSelected(vector))
                        {
                            continue;
                        }

                        EnsureVectorShapeId(vector);
                        string key = BuildKey(ObjectClipboardItemType.VectorShape, vector.Id);
                        if (addedKeys.Add(key))
                        {
                            orderedSelection.Add(vector);
                        }
                        break;
                    }
                }
            }

            foreach (TextAnnotation text in selectedTextAnnotations.Where(a => a != null && a.PageNumber == currentPage))
            {
                EnsureTextAnnotationId(text);
                if (addedKeys.Add(BuildKey(ObjectClipboardItemType.Text, text.Id)))
                {
                    orderedSelection.Add(text);
                }
            }
            if (selectedTextAnnotation != null && selectedTextAnnotation.PageNumber == currentPage)
            {
                EnsureTextAnnotationId(selectedTextAnnotation);
                if (addedKeys.Add(BuildKey(ObjectClipboardItemType.Text, selectedTextAnnotation.Id)))
                {
                    orderedSelection.Add(selectedTextAnnotation);
                }
            }

            foreach (string rasterId in selectedRasterObjectIds)
            {
                RasterObject raster = rasterObjects.FirstOrDefault(r => r != null && r.PageNumber == currentPage && string.Equals(r.Id, rasterId, StringComparison.Ordinal));
                if (raster == null)
                {
                    continue;
                }
                EnsureRasterObjectId(raster);
                if (addedKeys.Add(BuildKey(ObjectClipboardItemType.Raster, raster.Id)))
                {
                    orderedSelection.Add(raster);
                }
            }
            if (selectedRasterObject != null && selectedRasterObject.PageNumber == currentPage)
            {
                EnsureRasterObjectId(selectedRasterObject);
                if (addedKeys.Add(BuildKey(ObjectClipboardItemType.Raster, selectedRasterObject.Id)))
                {
                    orderedSelection.Add(selectedRasterObject);
                }
            }

            foreach (string arrowId in selectedArrowObjectIds)
            {
                ArrowObject arrow = arrowObjects.FirstOrDefault(a => a != null && a.PageNumber == currentPage && string.Equals(a.Id, arrowId, StringComparison.Ordinal));
                if (arrow == null)
                {
                    continue;
                }
                EnsureArrowObjectId(arrow);
                if (addedKeys.Add(BuildKey(ObjectClipboardItemType.Arrow, arrow.Id)))
                {
                    orderedSelection.Add(arrow);
                }
            }
            if (selectedArrowObject != null && selectedArrowObject.PageNumber == currentPage)
            {
                EnsureArrowObjectId(selectedArrowObject);
                if (addedKeys.Add(BuildKey(ObjectClipboardItemType.Arrow, selectedArrowObject.Id)))
                {
                    orderedSelection.Add(selectedArrowObject);
                }
            }

            foreach (string vectorId in selectedVectorShapeIds)
            {
                VectorShapeObject vector = vectorShapes.FirstOrDefault(v => v != null && v.PageNumber == currentPage && string.Equals(v.Id, vectorId, StringComparison.Ordinal));
                if (vector == null)
                {
                    continue;
                }
                EnsureVectorShapeId(vector);
                if (addedKeys.Add(BuildKey(ObjectClipboardItemType.VectorShape, vector.Id)))
                {
                    orderedSelection.Add(vector);
                }
            }
            if (selectedVectorShape != null && selectedVectorShape.PageNumber == currentPage)
            {
                EnsureVectorShapeId(selectedVectorShape);
                if (addedKeys.Add(BuildKey(ObjectClipboardItemType.VectorShape, selectedVectorShape.Id)))
                {
                    orderedSelection.Add(selectedVectorShape);
                }
            }

            return orderedSelection;
        }

        private bool TryBuildObjectClipboardSnapshot(out ObjectClipboardSnapshot snapshot)
        {
            snapshot = null;
            if (pdf == null || numPages <= 0)
            {
                return false;
            }

            List<object> selectedObjects = GetSelectedObjectsOnCurrentPageInLayerOrder();
            if (selectedObjects.Count == 0)
            {
                return false;
            }

            float minX = float.MaxValue;
            float minY = float.MaxValue;
            float maxX = float.MinValue;
            float maxY = float.MinValue;
            foreach (object selectedObject in selectedObjects)
            {
                if (!TryGetObjectBoundsForClipboard(selectedObject, out RectangleF bounds))
                {
                    continue;
                }

                minX = Math.Min(minX, bounds.Left);
                minY = Math.Min(minY, bounds.Top);
                maxX = Math.Max(maxX, bounds.Right);
                maxY = Math.Max(maxY, bounds.Bottom);
            }

            if (minX == float.MaxValue || minY == float.MaxValue || maxX == float.MinValue || maxY == float.MinValue)
            {
                return false;
            }

            snapshot = new ObjectClipboardSnapshot
            {
                SourceBounds = RectangleF.FromLTRB(minX, minY, maxX, maxY)
            };
            var sourcePageSize = GetPageSizeWithOffset(currentPage);
            snapshot.SourcePageWidth = sourcePageSize.Width;
            snapshot.SourcePageHeight = sourcePageSize.Height;

            RectangleF snapshotSourceBounds = snapshot.SourceBounds;

            foreach (object selectedObject in selectedObjects)
            {
                if (selectedObject is TextAnnotation textAnnotation)
                {
                    RectangleF textBounds = TryGetTextAnnotationVisualDocBounds(textAnnotation, out RectangleF visualBounds)
                        ? visualBounds
                        : textAnnotation.AnnotationBounds;
                    snapshot.Items.Add(new ObjectClipboardItem
                    {
                        Type = ObjectClipboardItemType.Text,
                        Bounds = new RectangleF(
                            textBounds.X - snapshotSourceBounds.X,
                            textBounds.Y - snapshotSourceBounds.Y,
                            textBounds.Width,
                            textBounds.Height),
                        Text = new TextAnnotation
                        {
                            LayerId = NormalizeLayerIdValue(textAnnotation.LayerId),
                            AnnotationText = textAnnotation.AnnotationText,
                            AnnotationFont = CloneFontSafe(textAnnotation.AnnotationFont),
                            AnnotationColor = textAnnotation.AnnotationColor,
                            AnnotationBackgroundColorArgb = textAnnotation.AnnotationBackgroundColorArgb,
                            AnnotationBorderColorArgb = textAnnotation.AnnotationBorderColorArgb,
                            AnnotationBorderWidth = textAnnotation.AnnotationBorderWidth,
                            AnnotationFrameMargin = textAnnotation.AnnotationFrameMargin,
                            HasLeaderArrow = textAnnotation.HasLeaderArrow,
                            LeaderLineWidth = NormalizeLeaderLineWidth(textAnnotation.LeaderLineWidth),
                            LeaderAnchorKind = NormalizeTextLeaderAnchorKind(textAnnotation.LeaderAnchorKind),
                            LeaderEndPoint = new PointF(
                                textAnnotation.LeaderEndPoint.X - snapshotSourceBounds.X,
                                textAnnotation.LeaderEndPoint.Y - snapshotSourceBounds.Y),
                            LeaderHeadLength = NormalizeTextLeaderHeadLength(textAnnotation.LeaderHeadLength),
                            LeaderHeadWidth = NormalizeTextLeaderHeadWidth(textAnnotation.LeaderHeadWidth),
                            AnnotationContentMode = textAnnotation.AnnotationContentMode,
                            AnnotationRichText = textAnnotation.AnnotationRichText,
                            AnnotationAlignment = textAnnotation.AnnotationAlignment,
                            AnnotationRotation = textAnnotation.AnnotationRotation,
                            AnnotationIsLocked = textAnnotation.AnnotationIsLocked,
                            AnnotationBounds = new RectangleF(
                                textAnnotation.AnnotationBounds.X - snapshotSourceBounds.X,
                                textAnnotation.AnnotationBounds.Y - snapshotSourceBounds.Y,
                                textAnnotation.AnnotationBounds.Width,
                                textAnnotation.AnnotationBounds.Height)
                        }
                    });
                    continue;
                }

                if (selectedObject is RasterObject rasterObject)
                {
                    snapshot.Items.Add(new ObjectClipboardItem
                    {
                        Type = ObjectClipboardItemType.Raster,
                        Bounds = new RectangleF(
                            rasterObject.Bounds.X - snapshotSourceBounds.X,
                            rasterObject.Bounds.Y - snapshotSourceBounds.Y,
                            rasterObject.Bounds.Width,
                            rasterObject.Bounds.Height),
                        Raster = new RasterObject
                        {
                            LayerId = NormalizeLayerIdValue(rasterObject.LayerId),
                            Rotation = rasterObject.Rotation,
                            Opacity = rasterObject.Opacity,
                            TransparentBackground = rasterObject.TransparentBackground,
                            LockAspect = rasterObject.LockAspect,
                            IsLocked = rasterObject.IsLocked,
                            SourceType = rasterObject.SourceType,
                            FilePath = rasterObject.FilePath,
                            EmbeddedBytes = rasterObject.EmbeddedBytes == null ? null : (byte[])rasterObject.EmbeddedBytes.Clone(),
                            MimeType = rasterObject.MimeType
                        }
                    });
                    continue;
                }

                if (selectedObject is ArrowObject arrowObject)
                {
                    snapshot.Items.Add(new ObjectClipboardItem
                    {
                        Type = ObjectClipboardItemType.Arrow,
                        Arrow = new ArrowObject
                        {
                            LayerId = NormalizeLayerIdValue(arrowObject.LayerId),
                            Start = new PointF(
                                arrowObject.Start.X - snapshotSourceBounds.X,
                                arrowObject.Start.Y - snapshotSourceBounds.Y),
                            End = new PointF(
                                arrowObject.End.X - snapshotSourceBounds.X,
                                arrowObject.End.Y - snapshotSourceBounds.Y),
                            LineColorArgb = arrowObject.LineColorArgb,
                            Thickness = NormalizeArrowThickness(arrowObject.Thickness),
                            BorderColorArgb = arrowObject.BorderColorArgb,
                            BorderWidth = NormalizeArrowBorderWidth(arrowObject.BorderWidth),
                            HeadLength = NormalizeArrowHeadLength(arrowObject.HeadLength),
                            HeadWidth = NormalizeArrowHeadWidth(arrowObject.HeadWidth),
                            IsLocked = arrowObject.IsLocked
                        }
                    });
                    continue;
                }

                if (selectedObject is VectorShapeObject vectorShapeObject)
                {
                    snapshot.Items.Add(new ObjectClipboardItem
                    {
                        Type = ObjectClipboardItemType.VectorShape,
                        VectorShape = new VectorShapeObject
                        {
                            LayerId = NormalizeLayerIdValue(vectorShapeObject.LayerId),
                            ShapeType = vectorShapeObject.ShapeType,
                            IsRasterClip = vectorShapeObject.IsRasterClip,
                            Points = (vectorShapeObject.Points ?? new List<PointF>())
                                .Select(point => new PointF(point.X - snapshotSourceBounds.X, point.Y - snapshotSourceBounds.Y))
                                .ToList(),
                            StrokeColorArgb = vectorShapeObject.StrokeColorArgb,
                            StrokeWidth = NormalizeVectorStrokeWidth(vectorShapeObject.StrokeWidth),
                            FillColorArgb = vectorShapeObject.FillColorArgb,
                            FillPatternColorArgb = vectorShapeObject.FillPatternColorArgb,
                            FillOpacity = NormalizeVectorFillOpacity(vectorShapeObject.FillOpacity),
                            StrokeStyle = vectorShapeObject.StrokeStyle,
                            FillPattern = vectorShapeObject.FillPattern,
                            StartLineEnding = vectorShapeObject.StartLineEnding,
                            EndLineEnding = vectorShapeObject.EndLineEnding,
                            StartLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(vectorShapeObject.StartLineEndingPrimarySize),
                            StartLineEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(vectorShapeObject.StartLineEndingSecondarySize),
                            EndLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(vectorShapeObject.EndLineEndingPrimarySize),
                            EndLineEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(vectorShapeObject.EndLineEndingSecondarySize),
                            IsLocked = vectorShapeObject.IsLocked
                        }
                    });
                }
            }

            if (snapshot.Items.Count == 0)
            {
                snapshot = null;
                return false;
            }

            return true;
        }

        private void ClearInternalObjectClipboard()
        {
            objectClipboardSnapshot = null;
            objectClipboardPasteCount = 0;
            preferObjectClipboardPaste = false;
            clipboardSequenceAtLastInternalObjectCopy = 0;
        }

        private void SetInternalObjectClipboardFallback(ObjectClipboardSnapshot snapshot)
        {
            objectClipboardSnapshot = snapshot;
            objectClipboardPasteCount = 0;
            preferObjectClipboardPaste = snapshot != null;
            clipboardSequenceAtLastInternalObjectCopy = TryGetClipboardSequenceNumberSafe();
        }

        private bool TryCopySelectedObjectsToClipboard()
        {
            if (!TryBuildObjectClipboardSnapshot(out ObjectClipboardSnapshot snapshot) || snapshot == null)
            {
                return false;
            }

            if (TryWriteObjectSnapshotToSystemClipboard(snapshot))
            {
                ClearInternalObjectClipboard();
                preferObjectClipboardPaste = true;
                clipboardSequenceAtLastInternalObjectCopy = TryGetClipboardSequenceNumberSafe();
                return true;
            }

            SetInternalObjectClipboardFallback(snapshot);
            return true;
        }

        private bool TryWriteObjectSnapshotToSystemClipboard(ObjectClipboardSnapshot snapshot)
        {
            if (snapshot == null || snapshot.Items.Count == 0)
            {
                return false;
            }

            try
            {
                string serialized = SerializeObjectClipboardSnapshot(snapshot);
                if (string.IsNullOrWhiteSpace(serialized))
                {
                    return false;
                }

                var dataObject = new DataObject();
                dataObject.SetData(AppObjectClipboardFormat, false, serialized);
                Clipboard.SetDataObject(dataObject, true);

                ObjectClipboardSnapshot verification;
                return TryReadObjectSnapshotFromSystemClipboard(out verification) &&
                       verification != null &&
                       verification.Items.Count > 0;
            }
            catch (ExternalException)
            {
                return false;
            }
            catch (Exception ex)
            {
                LogDebug("Object clipboard system copy failed: " + ex.Message);
                return false;
            }
        }

        private bool TryReadObjectSnapshotFromSystemClipboard(out ObjectClipboardSnapshot snapshot)
        {
            snapshot = null;

            try
            {
                IDataObject clipboardData = Clipboard.GetDataObject();
                if (clipboardData == null || !clipboardData.GetDataPresent(AppObjectClipboardFormat))
                {
                    return false;
                }

                object rawData = clipboardData.GetData(AppObjectClipboardFormat);
                string serialized = rawData as string;
                if (string.IsNullOrWhiteSpace(serialized))
                {
                    return false;
                }

                snapshot = DeserializeObjectClipboardSnapshot(serialized);
                return snapshot != null && snapshot.Items.Count > 0;
            }
            catch (ExternalException)
            {
                return false;
            }
            catch (Exception ex)
            {
                LogDebug("Object clipboard system read failed: " + ex.Message);
                snapshot = null;
                return false;
            }
        }

        private static string SerializeObjectClipboardSnapshot(ObjectClipboardSnapshot snapshot)
        {
            if (snapshot == null)
            {
                return null;
            }

            var root = new JObject
            {
                ["Version"] = 1,
                ["SourceBounds"] = SerializeRectangleF(snapshot.SourceBounds),
                ["SourcePageWidth"] = snapshot.SourcePageWidth,
                ["SourcePageHeight"] = snapshot.SourcePageHeight
            };

            var items = new JArray();
            foreach (ObjectClipboardItem item in snapshot.Items.Where(i => i != null))
            {
                var itemJson = new JObject
                {
                    ["Type"] = item.Type.ToString()
                };

                if (item.Type == ObjectClipboardItemType.Text)
                {
                    itemJson["Bounds"] = SerializeRectangleF(item.Bounds);
                    itemJson["Text"] = SerializeTextAnnotationForClipboard(item.Text);
                }
                else if (item.Type == ObjectClipboardItemType.Raster)
                {
                    itemJson["Bounds"] = SerializeRectangleF(item.Bounds);
                    itemJson["Raster"] = SerializeRasterObjectForClipboard(item.Raster);
                }
                else if (item.Type == ObjectClipboardItemType.Arrow)
                {
                    itemJson["Arrow"] = SerializeArrowObjectForClipboard(item.Arrow);
                }
                else if (item.Type == ObjectClipboardItemType.VectorShape)
                {
                    itemJson["VectorShape"] = SerializeVectorShapeObjectForClipboard(item.VectorShape);
                }

                items.Add(itemJson);
            }

            root["Items"] = items;
            return root.ToString(Formatting.None);
        }

        private static ObjectClipboardSnapshot DeserializeObjectClipboardSnapshot(string serialized)
        {
            if (string.IsNullOrWhiteSpace(serialized))
            {
                return null;
            }

            JObject root = JObject.Parse(serialized);
            var snapshot = new ObjectClipboardSnapshot
            {
                SourceBounds = DeserializeRectangleF(root["SourceBounds"]),
                SourcePageWidth = root.Value<float?>("SourcePageWidth") ?? 0f,
                SourcePageHeight = root.Value<float?>("SourcePageHeight") ?? 0f
            };

            foreach (JObject itemJson in root["Items"] as JArray ?? new JArray())
            {
                if (itemJson == null)
                {
                    continue;
                }

                string typeText = itemJson.Value<string>("Type");
                ObjectClipboardItemType type;
                if (!Enum.TryParse(typeText, true, out type))
                {
                    continue;
                }

                var item = new ObjectClipboardItem
                {
                    Type = type
                };

                switch (type)
                {
                    case ObjectClipboardItemType.Text:
                        item.Bounds = DeserializeRectangleF(itemJson["Bounds"]);
                        item.Text = DeserializeTextAnnotationForClipboard(itemJson["Text"] as JObject);
                        break;
                    case ObjectClipboardItemType.Raster:
                        item.Bounds = DeserializeRectangleF(itemJson["Bounds"]);
                        item.Raster = DeserializeRasterObjectForClipboard(itemJson["Raster"] as JObject);
                        break;
                    case ObjectClipboardItemType.Arrow:
                        item.Arrow = DeserializeArrowObjectForClipboard(itemJson["Arrow"] as JObject);
                        break;
                    case ObjectClipboardItemType.VectorShape:
                        item.VectorShape = DeserializeVectorShapeObjectForClipboard(itemJson["VectorShape"] as JObject);
                        break;
                }

                if (item.Text != null || item.Raster != null || item.Arrow != null || item.VectorShape != null)
                {
                    snapshot.Items.Add(item);
                }
            }

            return snapshot;
        }

        private static JObject SerializeRectangleF(RectangleF rect)
        {
            return new JObject
            {
                ["X"] = rect.X,
                ["Y"] = rect.Y,
                ["Width"] = rect.Width,
                ["Height"] = rect.Height
            };
        }

        private static RectangleF DeserializeRectangleF(JToken token)
        {
            if (!(token is JObject rect))
            {
                return RectangleF.Empty;
            }

            return new RectangleF(
                rect.Value<float?>("X") ?? 0f,
                rect.Value<float?>("Y") ?? 0f,
                rect.Value<float?>("Width") ?? 0f,
                rect.Value<float?>("Height") ?? 0f);
        }

        private static JObject SerializePointF(PointF point)
        {
            return new JObject
            {
                ["X"] = point.X,
                ["Y"] = point.Y
            };
        }

        private static PointF DeserializePointF(JToken token)
        {
            if (!(token is JObject point))
            {
                return PointF.Empty;
            }

            return new PointF(
                point.Value<float?>("X") ?? 0f,
                point.Value<float?>("Y") ?? 0f);
        }

        private static JObject SerializeFont(Font font)
        {
            Font source = font ?? SystemFonts.DefaultFont;
            return new JObject
            {
                ["Family"] = source.FontFamily.Name,
                ["Size"] = source.Size,
                ["Style"] = (int)source.Style
            };
        }

        private static Font DeserializeFont(JObject fontJson)
        {
            if (fontJson == null)
            {
                return (Font)SystemFonts.DefaultFont.Clone();
            }

            string family = fontJson.Value<string>("Family") ?? SystemFonts.DefaultFont.FontFamily.Name;
            float size = fontJson.Value<float?>("Size") ?? SystemFonts.DefaultFont.Size;
            FontStyle style = (FontStyle)(fontJson.Value<int?>("Style") ?? (int)SystemFonts.DefaultFont.Style);

            try
            {
                return new Font(family, size, style);
            }
            catch
            {
                return (Font)SystemFonts.DefaultFont.Clone();
            }
        }

        private static JObject SerializeTextAnnotationForClipboard(TextAnnotation text)
        {
            if (text == null)
            {
                return null;
            }

            return new JObject
            {
                ["AnnotationText"] = text.AnnotationText ?? string.Empty,
                ["AnnotationFont"] = SerializeFont(text.AnnotationFont),
                ["AnnotationColorArgb"] = text.AnnotationColor.ToArgb(),
                ["AnnotationBackgroundColorArgb"] = text.AnnotationBackgroundColorArgb,
                ["AnnotationBorderColorArgb"] = text.AnnotationBorderColorArgb,
                ["AnnotationBorderWidth"] = text.AnnotationBorderWidth,
                ["AnnotationFrameMargin"] = text.AnnotationFrameMargin,
                ["HasLeaderArrow"] = text.HasLeaderArrow,
                ["LeaderLineWidth"] = NormalizeLeaderLineWidth(text.LeaderLineWidth),
                ["LeaderAnchorKind"] = (int)NormalizeTextLeaderAnchorKind(text.LeaderAnchorKind),
                ["LeaderEndPointX"] = text.LeaderEndPoint.X,
                ["LeaderEndPointY"] = text.LeaderEndPoint.Y,
                ["LeaderHeadLength"] = NormalizeTextLeaderHeadLength(text.LeaderHeadLength),
                ["LeaderHeadWidth"] = NormalizeTextLeaderHeadWidth(text.LeaderHeadWidth),
                ["AnnotationBoundsX"] = text.AnnotationBounds.X,
                ["AnnotationBoundsY"] = text.AnnotationBounds.Y,
                ["AnnotationBoundsWidth"] = text.AnnotationBounds.Width,
                ["AnnotationBoundsHeight"] = text.AnnotationBounds.Height,
                ["AnnotationContentMode"] = text.AnnotationContentMode,
                ["AnnotationRichText"] = text.AnnotationRichText,
                ["AnnotationAlignment"] = (int)text.AnnotationAlignment,
                ["AnnotationRotation"] = text.AnnotationRotation,
                ["AnnotationIsLocked"] = text.AnnotationIsLocked
            };
        }

        private static TextAnnotation DeserializeTextAnnotationForClipboard(JObject textJson)
        {
            if (textJson == null)
            {
                return null;
            }

            return new TextAnnotation
            {
                AnnotationText = textJson.Value<string>("AnnotationText") ?? string.Empty,
                AnnotationFont = DeserializeFont(textJson["AnnotationFont"] as JObject),
                AnnotationColor = System.Drawing.Color.FromArgb(textJson.Value<int?>("AnnotationColorArgb") ?? System.Drawing.Color.Black.ToArgb()),
                AnnotationBackgroundColorArgb = textJson.Value<int?>("AnnotationBackgroundColorArgb") ?? System.Drawing.Color.Transparent.ToArgb(),
                AnnotationBorderColorArgb = textJson.Value<int?>("AnnotationBorderColorArgb") ?? System.Drawing.Color.Black.ToArgb(),
                AnnotationBorderWidth = NormalizeAnnotationBorderWidth(textJson.Value<float?>("AnnotationBorderWidth") ?? 0f),
                AnnotationFrameMargin = NormalizeAnnotationFrameMargin(textJson.Value<float?>("AnnotationFrameMargin") ?? 0f),
                HasLeaderArrow = textJson.Value<bool?>("HasLeaderArrow") ?? false,
                LeaderLineWidth = NormalizeLeaderLineWidth(textJson.Value<float?>("LeaderLineWidth") ?? 1.5f),
                LeaderAnchorKind = NormalizeTextLeaderAnchorKind((TextLeaderAnchorKind)(textJson.Value<int?>("LeaderAnchorKind") ?? (int)TextLeaderAnchorKind.RightCenter)),
                LeaderEndPoint = new PointF(
                    textJson.Value<float?>("LeaderEndPointX") ?? 0f,
                    textJson.Value<float?>("LeaderEndPointY") ?? 0f),
                LeaderHeadLength = NormalizeTextLeaderHeadLength(textJson.Value<float?>("LeaderHeadLength") ?? DefaultArrowHeadLength),
                LeaderHeadWidth = NormalizeTextLeaderHeadWidth(textJson.Value<float?>("LeaderHeadWidth") ?? DefaultArrowHeadWidth),
                AnnotationBounds = new RectangleF(
                    textJson.Value<float?>("AnnotationBoundsX") ?? 0f,
                    textJson.Value<float?>("AnnotationBoundsY") ?? 0f,
                    textJson.Value<float?>("AnnotationBoundsWidth") ?? 100f,
                    textJson.Value<float?>("AnnotationBoundsHeight") ?? 30f),
                AnnotationContentMode = textJson.Value<string>("AnnotationContentMode") ?? "plain",
                AnnotationRichText = textJson.Value<string>("AnnotationRichText"),
                AnnotationAlignment = (System.Windows.Forms.HorizontalAlignment)(textJson.Value<int?>("AnnotationAlignment") ?? (int)System.Windows.Forms.HorizontalAlignment.Left),
                AnnotationRotation = textJson.Value<int?>("AnnotationRotation") ?? 0,
                AnnotationIsLocked = textJson.Value<bool?>("AnnotationIsLocked") ?? false
            };
        }

        private static JObject SerializeRasterObjectForClipboard(RasterObject raster)
        {
            if (raster == null)
            {
                return null;
            }

            return new JObject
            {
                ["Rotation"] = raster.Rotation,
                ["Opacity"] = raster.Opacity,
                ["TransparentBackground"] = raster.TransparentBackground,
                ["LockAspect"] = raster.LockAspect,
                ["IsLocked"] = raster.IsLocked,
                ["SourceType"] = raster.SourceType,
                ["FilePath"] = raster.FilePath,
                ["MimeType"] = raster.MimeType,
                ["EmbeddedBytesBase64"] = raster.EmbeddedBytes == null ? null : Convert.ToBase64String(raster.EmbeddedBytes)
            };
        }

        private static RasterObject DeserializeRasterObjectForClipboard(JObject rasterJson)
        {
            if (rasterJson == null)
            {
                return null;
            }

            string embeddedBase64 = rasterJson.Value<string>("EmbeddedBytesBase64");
            byte[] embeddedBytes = null;
            if (!string.IsNullOrWhiteSpace(embeddedBase64))
            {
                try
                {
                    embeddedBytes = Convert.FromBase64String(embeddedBase64);
                }
                catch
                {
                    embeddedBytes = null;
                }
            }

            return new RasterObject
            {
                Rotation = rasterJson.Value<int?>("Rotation") ?? 0,
                Opacity = rasterJson.Value<float?>("Opacity") ?? 1f,
                TransparentBackground = rasterJson.Value<bool?>("TransparentBackground") ?? false,
                LockAspect = rasterJson.Value<bool?>("LockAspect") ?? false,
                IsLocked = rasterJson.Value<bool?>("IsLocked") ?? false,
                SourceType = rasterJson.Value<string>("SourceType"),
                FilePath = rasterJson.Value<string>("FilePath"),
                MimeType = rasterJson.Value<string>("MimeType"),
                EmbeddedBytes = embeddedBytes
            };
        }

        private static JObject SerializeArrowObjectForClipboard(ArrowObject arrow)
        {
            if (arrow == null)
            {
                return null;
            }

            return new JObject
            {
                ["Start"] = SerializePointF(arrow.Start),
                ["End"] = SerializePointF(arrow.End),
                ["LineColorArgb"] = arrow.LineColorArgb,
                ["Thickness"] = arrow.Thickness,
                ["BorderColorArgb"] = arrow.BorderColorArgb,
                ["BorderWidth"] = arrow.BorderWidth,
                ["HeadLength"] = arrow.HeadLength,
                ["HeadWidth"] = arrow.HeadWidth,
                ["IsLocked"] = arrow.IsLocked
            };
        }

        private static ArrowObject DeserializeArrowObjectForClipboard(JObject arrowJson)
        {
            if (arrowJson == null)
            {
                return null;
            }

            return new ArrowObject
            {
                Start = DeserializePointF(arrowJson["Start"]),
                End = DeserializePointF(arrowJson["End"]),
                LineColorArgb = arrowJson.Value<int?>("LineColorArgb") ?? System.Drawing.Color.Red.ToArgb(),
                Thickness = NormalizeArrowThickness(arrowJson.Value<float?>("Thickness") ?? DefaultArrowThickness),
                BorderColorArgb = arrowJson.Value<int?>("BorderColorArgb") ?? System.Drawing.Color.Black.ToArgb(),
                BorderWidth = NormalizeArrowBorderWidth(arrowJson.Value<float?>("BorderWidth") ?? 0f),
                HeadLength = NormalizeArrowHeadLength(arrowJson.Value<float?>("HeadLength") ?? DefaultArrowHeadLength),
                HeadWidth = NormalizeArrowHeadWidth(arrowJson.Value<float?>("HeadWidth") ?? DefaultArrowHeadWidth),
                IsLocked = arrowJson.Value<bool?>("IsLocked") ?? false
            };
        }

        private static JObject SerializeVectorShapeObjectForClipboard(VectorShapeObject vectorShape)
        {
            if (vectorShape == null)
            {
                return null;
            }

            return new JObject
            {
                ["ShapeType"] = vectorShape.ShapeType,
                ["Points"] = new JArray((vectorShape.Points ?? new List<PointF>()).Select(SerializePointF)),
                ["StrokeColorArgb"] = vectorShape.StrokeColorArgb,
                ["StrokeWidth"] = vectorShape.StrokeWidth,
                ["FillColorArgb"] = vectorShape.FillColorArgb,
                ["FillPatternColorArgb"] = vectorShape.FillPatternColorArgb,
                ["FillOpacity"] = vectorShape.FillOpacity,
                ["StrokeStyle"] = vectorShape.StrokeStyle,
                ["FillPattern"] = vectorShape.FillPattern,
                ["IsRasterClip"] = vectorShape.IsRasterClip,
                ["StartLineEnding"] = vectorShape.StartLineEnding,
                ["EndLineEnding"] = vectorShape.EndLineEnding,
                ["StartLineEndingPrimarySize"] = vectorShape.StartLineEndingPrimarySize,
                ["StartLineEndingSecondarySize"] = vectorShape.StartLineEndingSecondarySize,
                ["EndLineEndingPrimarySize"] = vectorShape.EndLineEndingPrimarySize,
                ["EndLineEndingSecondarySize"] = vectorShape.EndLineEndingSecondarySize,
                ["IsLocked"] = vectorShape.IsLocked
            };
        }

        private static VectorShapeObject DeserializeVectorShapeObjectForClipboard(JObject vectorJson)
        {
            if (vectorJson == null)
            {
                return null;
            }

            return new VectorShapeObject
            {
                ShapeType = vectorJson.Value<string>("ShapeType"),
                Points = (vectorJson["Points"] as JArray ?? new JArray())
                    .Select(DeserializePointF)
                    .ToList(),
                StrokeColorArgb = vectorJson.Value<int?>("StrokeColorArgb") ?? System.Drawing.Color.Blue.ToArgb(),
                StrokeWidth = NormalizeVectorStrokeWidth(vectorJson.Value<float?>("StrokeWidth") ?? 2f),
                FillColorArgb = vectorJson.Value<int?>("FillColorArgb") ?? System.Drawing.Color.Gold.ToArgb(),
                FillPatternColorArgb = vectorJson.Value<int?>("FillPatternColorArgb") ?? System.Drawing.Color.Transparent.ToArgb(),
                FillOpacity = NormalizeVectorFillOpacity(vectorJson.Value<float?>("FillOpacity") ?? 0.18f),
                StrokeStyle = vectorJson.Value<string>("StrokeStyle") ?? "solid",
                FillPattern = vectorJson.Value<string>("FillPattern") ?? "solid",
                IsRasterClip = vectorJson.Value<bool?>("IsRasterClip") ?? false,
                StartLineEnding = vectorJson.Value<string>("StartLineEnding") ?? "None",
                EndLineEnding = vectorJson.Value<string>("EndLineEnding") ?? "None",
                StartLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(vectorJson.Value<float?>("StartLineEndingPrimarySize") ?? 0f),
                StartLineEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(vectorJson.Value<float?>("StartLineEndingSecondarySize") ?? 0f),
                EndLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(vectorJson.Value<float?>("EndLineEndingPrimarySize") ?? 0f),
                EndLineEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(vectorJson.Value<float?>("EndLineEndingSecondarySize") ?? 0f),
                IsLocked = vectorJson.Value<bool?>("IsLocked") ?? false
            };
        }

        private void CutSelectedObjectsFromContext(bool useGroupSelection, object hitObject = null)
        {
            if (useGroupSelection)
            {
                if (GetTotalSelectedObjectsCount() <= 0)
                {
                    return;
                }

                if (!TryCopySelectedObjectsToClipboard())
                {
                    return;
                }

                DeleteSelectedGroupObjectsWithConfirmation();
                return;
            }

            if (hitObject == null)
            {
                return;
            }

            if (!TryCopySelectedObjectsToClipboard())
            {
                return;
            }

            DeleteObjectFromContext(hitObject);
        }

        private static uint TryGetClipboardSequenceNumberSafe()
        {
            try
            {
                return GetClipboardSequenceNumber();
            }
            catch
            {
                return 0;
            }
        }

        private bool HasNewerExternalClipboardData(bool externalClipboardContentAvailable)
        {
            if (!externalClipboardContentAvailable || !preferObjectClipboardPaste)
            {
                return false;
            }

            uint currentSequence = TryGetClipboardSequenceNumberSafe();
            if (currentSequence == 0 || clipboardSequenceAtLastInternalObjectCopy == 0)
            {
                return false;
            }

            return currentSequence != clipboardSequenceAtLastInternalObjectCopy;
        }

        private bool TryPasteObjectsFromSystemClipboard()
        {
            ObjectClipboardSnapshot snapshot;
            if (!TryReadObjectSnapshotFromSystemClipboard(out snapshot) || snapshot == null)
            {
                return false;
            }

            preferObjectClipboardPaste = true;
            clipboardSequenceAtLastInternalObjectCopy = TryGetClipboardSequenceNumberSafe();
            return TryPasteObjectsFromSnapshot(snapshot);
        }

        private bool BringTextAnnotationToFront(TextAnnotation annotation)
        {
            if (annotation == null)
            {
                return false;
            }

            EnsureTextAnnotationId(annotation);
            return BringLayerToFront(LayerObjectType.Text, annotation.Id);
        }

        private bool SendTextAnnotationToBack(TextAnnotation annotation)
        {
            if (annotation == null)
            {
                return false;
            }

            EnsureTextAnnotationId(annotation);
            return SendLayerToBack(LayerObjectType.Text, annotation.Id);
        }

        private bool MoveTextAnnotationForward(TextAnnotation annotation)
        {
            if (annotation == null)
            {
                return false;
            }

            EnsureTextAnnotationId(annotation);
            return MoveLayerForward(LayerObjectType.Text, annotation.Id);
        }

        private bool MoveTextAnnotationBackward(TextAnnotation annotation)
        {
            if (annotation == null)
            {
                return false;
            }

            EnsureTextAnnotationId(annotation);
            return MoveLayerBackward(LayerObjectType.Text, annotation.Id);
        }

        private bool TryReorderTextAnnotation(TextAnnotation annotation, Func<TextAnnotation, bool> reorderAction)
        {
            if (annotation == null || reorderAction == null)
            {
                return false;
            }

            EnsureTextAnnotationId(annotation);

            if (!EnsureCurrentPageEditable(true))
            {
                return true;
            }

            if (IsTextAnnotationEffectivelyLocked(annotation))
            {
                ShowLockedLayerInfo();
                return true;
            }

            if (!reorderAction(annotation))
            {
                return true;
            }

            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            pdfViewer.Invalidate();
            return true;
        }

        private void ShowTextOrderMenu(TextAnnotation annotation)
        {
            if (annotation == null)
            {
                return;
            }

            var menu = new ContextMenuStrip();
            menu.Items.Add(LocalizedText("Order_BringToFront"), null, (_, __) => TryReorderTextAnnotation(annotation, BringTextAnnotationToFront));
            menu.Items.Add(LocalizedText("Order_MoveForward"), null, (_, __) => TryReorderTextAnnotation(annotation, MoveTextAnnotationForward));
            menu.Items.Add(LocalizedText("Order_MoveBackward"), null, (_, __) => TryReorderTextAnnotation(annotation, MoveTextAnnotationBackward));
            menu.Items.Add(LocalizedText("Order_SendToBack"), null, (_, __) => TryReorderTextAnnotation(annotation, SendTextAnnotationToBack));

            Point location = pdfViewer.PointToClient(Cursor.Position);
            menu.Show(pdfViewer, location);
        }

        private bool TryPasteObjectsFromSnapshot(ObjectClipboardSnapshot snapshot)
        {
            if (snapshot == null || snapshot.Items.Count == 0)
            {
                return false;
            }

            if (pdf == null || numPages <= 0)
            {
                return false;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return true;
            }

            bool isSingleRasterPaste =
                snapshot.Items.Count == 1 &&
                snapshot.Items[0] != null &&
                snapshot.Items[0].Type == ObjectClipboardItemType.Raster &&
                snapshot.Items[0].Raster != null;

            var targetPageSize = GetPageSizeWithOffset(currentPage);
            float sourcePageWidth = snapshot.SourcePageWidth > 0f ? snapshot.SourcePageWidth : targetPageSize.Width;
            float sourcePageHeight = snapshot.SourcePageHeight > 0f ? snapshot.SourcePageHeight : targetPageSize.Height;
            float sourceBoundsWidth = Math.Max(1f, snapshot.SourceBounds.Width);
            float sourceBoundsHeight = Math.Max(1f, snapshot.SourceBounds.Height);
            const float pasteMarginDoc = 4f;
            float availableWidth = Math.Max(1f, targetPageSize.Width - (pasteMarginDoc * 2f));
            float availableHeight = Math.Max(1f, targetPageSize.Height - (pasteMarginDoc * 2f));
            float pasteScale = 1f;
            if (sourceBoundsWidth > availableWidth || sourceBoundsHeight > availableHeight)
            {
                pasteScale = Math.Min(availableWidth / sourceBoundsWidth, availableHeight / sourceBoundsHeight);
                pasteScale = Math.Max(0.05f, Math.Min(1f, pasteScale));
            }

            float scaledBoundsWidth = sourceBoundsWidth * pasteScale;
            float scaledBoundsHeight = sourceBoundsHeight * pasteScale;
            float relativeBaseX = sourcePageWidth > 0f ? snapshot.SourceBounds.X / sourcePageWidth : 0f;
            float relativeBaseY = sourcePageHeight > 0f ? snapshot.SourceBounds.Y / sourcePageHeight : 0f;
            float baseX = targetPageSize.Width * relativeBaseX;
            float baseY = targetPageSize.Height * relativeBaseY;
            baseX = Math.Max(pasteMarginDoc, Math.Min(targetPageSize.Width - pasteMarginDoc - scaledBoundsWidth, baseX));
            baseY = Math.Max(pasteMarginDoc, Math.Min(targetPageSize.Height - pasteMarginDoc - scaledBoundsHeight, baseY));
            DateTime now = DateTime.UtcNow;
            string targetLayerId = GetResolvedActiveLayerId();

            var pastedTextAnnotations = new List<TextAnnotation>();
            var pastedRasterObjects = new List<RasterObject>();
            var pastedArrowObjects = new List<ArrowObject>();
            var pastedVectorShapes = new List<VectorShapeObject>();
            var pastedObjectsInSourceOrder = new List<object>();

            foreach (ObjectClipboardItem item in snapshot.Items)
            {
                if (item == null)
                {
                    continue;
                }

                switch (item.Type)
                {
                    case ObjectClipboardItemType.Text:
                    {
                        if (item.Text == null)
                        {
                            break;
                        }

                        RectangleF sourceAnnotationBounds = item.Text.AnnotationBounds;
                        if (sourceAnnotationBounds.Width <= 0f || sourceAnnotationBounds.Height <= 0f)
                        {
                            sourceAnnotationBounds = item.Bounds;
                        }

                        RectangleF visualBounds = new RectangleF(
                            baseX + (item.Bounds.X * pasteScale),
                            baseY + (item.Bounds.Y * pasteScale),
                            item.Bounds.Width * pasteScale,
                            item.Bounds.Height * pasteScale);
                        RectangleF bounds = new RectangleF(
                            visualBounds.X + ((sourceAnnotationBounds.X - item.Bounds.X) * pasteScale),
                            visualBounds.Y + ((sourceAnnotationBounds.Y - item.Bounds.Y) * pasteScale),
                            sourceAnnotationBounds.Width * pasteScale,
                            sourceAnnotationBounds.Height * pasteScale);
                        RectangleF unconstrainedBounds = bounds;
                        bounds = ConstrainAnnotationBoundsToViewer(bounds);
                        float boundsDeltaX = bounds.X - unconstrainedBounds.X;
                        float boundsDeltaY = bounds.Y - unconstrainedBounds.Y;
                        var textCopy = new TextAnnotation
                        {
                            Id = Guid.NewGuid().ToString("N"),
                            PageNumber = currentPage,
                            LayerId = targetLayerId,
                            AnnotationText = item.Text.AnnotationText,
                            AnnotationFont = CloneFontSafe(item.Text.AnnotationFont),
                            AnnotationColor = item.Text.AnnotationColor,
                            AnnotationBackgroundColorArgb = item.Text.AnnotationBackgroundColorArgb,
                            AnnotationBorderColorArgb = item.Text.AnnotationBorderColorArgb,
                            AnnotationBorderWidth = item.Text.AnnotationBorderWidth,
                            AnnotationFrameMargin = item.Text.AnnotationFrameMargin,
                            HasLeaderArrow = item.Text.HasLeaderArrow,
                            LeaderLineWidth = NormalizeLeaderLineWidth(item.Text.LeaderLineWidth),
                            LeaderAnchorKind = NormalizeTextLeaderAnchorKind(item.Text.LeaderAnchorKind),
                            LeaderEndPoint = new PointF(
                                baseX + (item.Text.LeaderEndPoint.X * pasteScale) + boundsDeltaX,
                                baseY + (item.Text.LeaderEndPoint.Y * pasteScale) + boundsDeltaY),
                            LeaderHeadLength = NormalizeTextLeaderHeadLength(item.Text.LeaderHeadLength),
                            LeaderHeadWidth = NormalizeTextLeaderHeadWidth(item.Text.LeaderHeadWidth),
                            AnnotationContentMode = item.Text.AnnotationContentMode,
                            AnnotationRichText = item.Text.AnnotationRichText,
                            AnnotationAlignment = item.Text.AnnotationAlignment,
                            AnnotationRotation = item.Text.AnnotationRotation,
                            AnnotationBounds = bounds,
                            AnnotationIsLocked = item.Text.AnnotationIsLocked
                        };
                        if (textCopy.AnnotationFont != null && Math.Abs(pasteScale - 1f) > 0.0001f)
                        {
                            textCopy.AnnotationFont = new Font(
                                textCopy.AnnotationFont.FontFamily,
                                Math.Max(4f, textCopy.AnnotationFont.Size * pasteScale),
                                textCopy.AnnotationFont.Style,
                                textCopy.AnnotationFont.Unit);
                        }
                        textCopy.AnnotationBorderWidth = Math.Max(0f, textCopy.AnnotationBorderWidth * pasteScale);
                        textCopy.AnnotationFrameMargin = Math.Max(0f, textCopy.AnnotationFrameMargin * pasteScale);
                        textCopy.LeaderLineWidth = NormalizeLeaderLineWidth(textCopy.LeaderLineWidth * pasteScale);
                        textCopy.LeaderHeadLength = NormalizeTextLeaderHeadLength(textCopy.LeaderHeadLength * pasteScale);
                        textCopy.LeaderHeadWidth = NormalizeTextLeaderHeadWidth(textCopy.LeaderHeadWidth * pasteScale);
                        StampTextAnnotationCreated(textCopy);
                        textAnnotations.Add(textCopy);
                        pastedTextAnnotations.Add(textCopy);
                        pastedObjectsInSourceOrder.Add(textCopy);
                        break;
                    }
                    case ObjectClipboardItemType.Raster:
                    {
                        if (item.Raster == null)
                        {
                            break;
                        }

                        RectangleF bounds;
                        if (isSingleRasterPaste)
                        {
                            var pageSize = GetPageSizeWithOffset(currentPage);
                            float centerX = pageSize.Width / 2f;
                            float centerY = pageSize.Height / 2f;
                            bounds = new RectangleF(
                                centerX - ((item.Bounds.Width * pasteScale) / 2f),
                                centerY - ((item.Bounds.Height * pasteScale) / 2f),
                                item.Bounds.Width * pasteScale,
                                item.Bounds.Height * pasteScale);
                        }
                        else
                        {
                            bounds = new RectangleF(
                                baseX + (item.Bounds.X * pasteScale),
                                baseY + (item.Bounds.Y * pasteScale),
                                item.Bounds.Width * pasteScale,
                                item.Bounds.Height * pasteScale);
                        }

                        var rasterCopy = new RasterObject
                        {
                            Id = Guid.NewGuid().ToString("N"),
                            PageNumber = currentPage,
                            LayerId = targetLayerId,
                            Bounds = bounds,
                            InitialBounds = bounds,
                            Rotation = item.Raster.Rotation,
                            Opacity = item.Raster.Opacity,
                            TransparentBackground = item.Raster.TransparentBackground,
                            LockAspect = item.Raster.LockAspect,
                            IsLocked = item.Raster.IsLocked,
                            SourceType = item.Raster.SourceType,
                            FilePath = item.Raster.FilePath,
                            EmbeddedBytes = item.Raster.EmbeddedBytes == null ? null : (byte[])item.Raster.EmbeddedBytes.Clone(),
                            MimeType = item.Raster.MimeType,
                            CreatedAtUtc = now,
                            UpdatedAtUtc = now
                        };
                        ConstrainRasterObjectToPage(rasterCopy);
                        rasterCopy.InitialBounds = rasterCopy.Bounds;
                        rasterObjects.Add(rasterCopy);
                        pastedRasterObjects.Add(rasterCopy);
                        pastedObjectsInSourceOrder.Add(rasterCopy);
                        break;
                    }
                    case ObjectClipboardItemType.Arrow:
                    {
                        if (item.Arrow == null)
                        {
                            break;
                        }

                        var arrowCopy = new ArrowObject
                        {
                            Id = Guid.NewGuid().ToString("N"),
                            PageNumber = currentPage,
                            LayerId = targetLayerId,
                            Start = new PointF(baseX + (item.Arrow.Start.X * pasteScale), baseY + (item.Arrow.Start.Y * pasteScale)),
                            End = new PointF(baseX + (item.Arrow.End.X * pasteScale), baseY + (item.Arrow.End.Y * pasteScale)),
                            LineColorArgb = item.Arrow.LineColorArgb,
                            Thickness = NormalizeArrowThickness(item.Arrow.Thickness * pasteScale),
                            BorderColorArgb = item.Arrow.BorderColorArgb,
                            BorderWidth = NormalizeArrowBorderWidth(item.Arrow.BorderWidth * pasteScale),
                            HeadLength = NormalizeArrowHeadLength(item.Arrow.HeadLength * pasteScale),
                            HeadWidth = NormalizeArrowHeadWidth(item.Arrow.HeadWidth * pasteScale),
                            IsLocked = item.Arrow.IsLocked,
                            CreatedAtUtc = now,
                            UpdatedAtUtc = now
                        };
                        ConstrainArrowToPage(arrowCopy);
                        arrowObjects.Add(arrowCopy);
                        pastedArrowObjects.Add(arrowCopy);
                        pastedObjectsInSourceOrder.Add(arrowCopy);
                        break;
                    }
                    case ObjectClipboardItemType.VectorShape:
                    {
                        if (item.VectorShape == null)
                        {
                            break;
                        }

                        var vectorCopy = new VectorShapeObject
                        {
                            Id = Guid.NewGuid().ToString("N"),
                            PageNumber = currentPage,
                            LayerId = targetLayerId,
                            ShapeType = item.VectorShape.ShapeType,
                            IsRasterClip = item.VectorShape.IsRasterClip,
                            Points = (item.VectorShape.Points ?? new List<PointF>())
                                .Select(point => new PointF(baseX + (point.X * pasteScale), baseY + (point.Y * pasteScale)))
                                .ToList(),
                            StrokeColorArgb = item.VectorShape.StrokeColorArgb,
                            StrokeWidth = NormalizeVectorStrokeWidth(item.VectorShape.StrokeWidth * pasteScale),
                            FillColorArgb = item.VectorShape.FillColorArgb,
                            FillPatternColorArgb = item.VectorShape.FillPatternColorArgb,
                            FillOpacity = NormalizeVectorFillOpacity(item.VectorShape.FillOpacity),
                            StrokeStyle = item.VectorShape.StrokeStyle,
                            FillPattern = item.VectorShape.FillPattern,
                            StartLineEnding = item.VectorShape.StartLineEnding,
                            EndLineEnding = item.VectorShape.EndLineEnding,
                            StartLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(item.VectorShape.StartLineEndingPrimarySize * pasteScale),
                            StartLineEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(item.VectorShape.StartLineEndingSecondarySize),
                            EndLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(item.VectorShape.EndLineEndingPrimarySize * pasteScale),
                            EndLineEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(item.VectorShape.EndLineEndingSecondarySize),
                            IsLocked = item.VectorShape.IsLocked,
                            CreatedAtUtc = now,
                            UpdatedAtUtc = now
                        };
                        NormalizeVectorShape(vectorCopy);
                        ConstrainVectorShapeToPage(vectorCopy);
                        vectorShapes.Add(vectorCopy);
                        pastedVectorShapes.Add(vectorCopy);
                        pastedObjectsInSourceOrder.Add(vectorCopy);
                        break;
                    }
                }
            }

            int pastedCount = pastedTextAnnotations.Count + pastedRasterObjects.Count + pastedArrowObjects.Count + pastedVectorShapes.Count;
            if (pastedCount <= 0)
            {
                return true;
            }

            EnsureObjectLayerOrder();
            foreach (object pastedObject in pastedObjectsInSourceOrder)
            {
                if (pastedObject is TextAnnotation textAnnotation)
                {
                    BringTextAnnotationToFront(textAnnotation);
                }
                else if (pastedObject is RasterObject rasterObject)
                {
                    BringRasterObjectToFront(rasterObject);
                }
                else if (pastedObject is ArrowObject arrowObject)
                {
                    BringArrowObjectToFront(arrowObject);
                }
                else if (pastedObject is VectorShapeObject vectorShapeObject)
                {
                    BringVectorShapeToFront(vectorShapeObject);
                }
            }

            ClearGroupSelection();
            selectedTextAnnotation = null;
            selectedRasterObject = null;
            selectedArrowObject = null;
            selectedVectorShape = null;
            ResetTextRotationInteractionState();
            ResetRasterInteractionState();
            ResetArrowInteractionState();
            ResetVectorInteractionState();
            ResetGroupMoveState();

            if (pastedCount == 1)
            {
                if (pastedTextAnnotations.Count == 1)
                {
                    selectedTextAnnotation = pastedTextAnnotations[0];
                }
                else if (pastedRasterObjects.Count == 1)
                {
                    selectedRasterObject = pastedRasterObjects[0];
                }
                else if (pastedArrowObjects.Count == 1)
                {
                    selectedArrowObject = pastedArrowObjects[0];
                }
                else if (pastedVectorShapes.Count == 1)
                {
                    selectedVectorShape = pastedVectorShapes[0];
                }
            }
            else
            {
                foreach (TextAnnotation textAnnotation in pastedTextAnnotations)
                {
                    selectedTextAnnotations.Add(textAnnotation);
                }
                foreach (RasterObject rasterObject in pastedRasterObjects)
                {
                    selectedRasterObjectIds.Add(rasterObject.Id);
                }
                foreach (ArrowObject arrowObject in pastedArrowObjects)
                {
                    selectedArrowObjectIds.Add(arrowObject.Id);
                }
                foreach (VectorShapeObject vectorShape in pastedVectorShapes)
                {
                    selectedVectorShapeIds.Add(vectorShape.Id);
                }
            }

            objectClipboardPasteCount++;
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            UpdateCurrentPageObjectsMarker();
            pdfViewer.Invalidate();
            return true;
        }

        private void ClearGroupSelection()
        {
            selectedTextAnnotations.Clear();
            selectedRasterObjectIds.Clear();
            selectedArrowObjectIds.Clear();
            selectedVectorShapeIds.Clear();
            UpdateObjectSelectionInfoLabel();
        }

        private bool SelectAllObjectsOnCurrentPage()
        {
            string activeLayer = GetResolvedActiveLayerId();
            List<object> visibleObjects = GetOrderedObjectsForCurrentPage()
                .Where(obj => string.Equals(GetLayerIdForGenericObject(obj), activeLayer, StringComparison.OrdinalIgnoreCase))
                .ToList();
            if (visibleObjects.Count == 0)
            {
                return false;
            }

            ResetTextRotationInteractionState();
            ResetRasterInteractionState();
            ResetArrowInteractionState();
            ResetVectorInteractionState();
            ResetCommentNoteMoveState();
            ResetGroupMoveState();

            selectedTextAnnotation = null;
            selectedRasterObject = null;
            selectedArrowObject = null;
            selectedVectorShape = null;
            ClearGroupSelection();

            foreach (object visibleObject in visibleObjects)
            {
                if (visibleObject is TextAnnotation textAnnotation)
                {
                    selectedTextAnnotations.Add(textAnnotation);
                }
                else if (visibleObject is RasterObject rasterObject && !string.IsNullOrWhiteSpace(rasterObject.Id))
                {
                    selectedRasterObjectIds.Add(rasterObject.Id);
                }
                else if (visibleObject is ArrowObject arrowObject && !string.IsNullOrWhiteSpace(arrowObject.Id))
                {
                    selectedArrowObjectIds.Add(arrowObject.Id);
                }
                else if (visibleObject is VectorShapeObject vectorShapeObject && !string.IsNullOrWhiteSpace(vectorShapeObject.Id))
                {
                    selectedVectorShapeIds.Add(vectorShapeObject.Id);
                }
            }

            CollapseGroupSelectionToSingleIfNeeded();
            UpdateObjectSelectionInfoLabel();
            pdfViewer?.Invalidate();
            return true;
        }

        private bool TryPasteObjectsFromInternalClipboard()
        {
            return TryPasteObjectsFromSnapshot(objectClipboardSnapshot);
        }

        private void ResetGroupMoveState()
        {
            isMovingObjectGroup = false;
            isScalingObjectGroup = false;
            groupMoveChanged = false;
            groupScaleChanged = false;
            groupMoveEntries.Clear();
            groupMoveStartMouseDoc = PointF.Empty;
            groupMoveInitialBounds = RectangleF.Empty;
            groupScaleStartScreenBounds = RectangleF.Empty;
            groupMoveMinDx = 0f;
            groupMoveMaxDx = 0f;
            groupMoveMinDy = 0f;
            groupMoveMaxDy = 0f;
        }

        private void PromoteSingleSelectionsToGroup()
        {
            if (selectedTextAnnotation != null && selectedTextAnnotation.PageNumber == currentPage)
            {
                selectedTextAnnotations.Add(selectedTextAnnotation);
            }

            if (selectedRasterObject != null && selectedRasterObject.PageNumber == currentPage && !string.IsNullOrWhiteSpace(selectedRasterObject.Id))
            {
                selectedRasterObjectIds.Add(selectedRasterObject.Id);
            }

            if (selectedArrowObject != null && selectedArrowObject.PageNumber == currentPage && !string.IsNullOrWhiteSpace(selectedArrowObject.Id))
            {
                selectedArrowObjectIds.Add(selectedArrowObject.Id);
            }

            if (selectedVectorShape != null && selectedVectorShape.PageNumber == currentPage && !string.IsNullOrWhiteSpace(selectedVectorShape.Id))
            {
                selectedVectorShapeIds.Add(selectedVectorShape.Id);
            }

            selectedTextAnnotation = null;
            selectedRasterObject = null;
            selectedArrowObject = null;
            selectedVectorShape = null;
            UpdateObjectSelectionInfoLabel();
        }

        private void CollapseGroupSelectionToSingleIfNeeded()
        {
            if (GetGroupSelectionCount() != 1)
            {
                UpdateObjectSelectionInfoLabel();
                return;
            }

            TextAnnotation onlyText = selectedTextAnnotations.FirstOrDefault();
            if (onlyText != null)
            {
                selectedTextAnnotation = onlyText;
                selectedRasterObject = null;
                selectedArrowObject = null;
                ClearGroupSelection();
                return;
            }

            string rasterId = selectedRasterObjectIds.FirstOrDefault();
            if (!string.IsNullOrWhiteSpace(rasterId))
            {
                selectedRasterObject = rasterObjects.FirstOrDefault(r => r != null && r.Id == rasterId);
                selectedTextAnnotation = null;
                selectedArrowObject = null;
                ClearGroupSelection();
                return;
            }

            string arrowId = selectedArrowObjectIds.FirstOrDefault();
            if (!string.IsNullOrWhiteSpace(arrowId))
            {
                selectedArrowObject = arrowObjects.FirstOrDefault(a => a != null && a.Id == arrowId);
                selectedTextAnnotation = null;
                selectedRasterObject = null;
                ClearGroupSelection();
                return;
            }

            string vectorId = selectedVectorShapeIds.FirstOrDefault();
            if (!string.IsNullOrWhiteSpace(vectorId))
            {
                selectedVectorShape = vectorShapes.FirstOrDefault(v => v != null && v.Id == vectorId);
                selectedTextAnnotation = null;
                selectedRasterObject = null;
                selectedArrowObject = null;
                ClearGroupSelection();
            }
        }

        private bool TryGetHitArrowAtPoint(Point location, out ArrowObject hitArrow)
        {
            hitArrow = arrowObjects
                .Where(obj => obj != null && obj.PageNumber == currentPage && IsLayerVisible(obj.LayerId))
                .Reverse()
                .FirstOrDefault(obj => IsPointNearArrowLine(obj, location) || TryGetArrowHandleAtPoint(obj, location, out _));
            return hitArrow != null;
        }

        private void ResetObjectSelectionCycle()
        {
            objectSelectionCyclePoint = Point.Empty;
            objectSelectionCyclePage = -1;
            objectSelectionCycleScale = -1f;
            objectSelectionCycleTimestampUtc = DateTime.MinValue;
            objectSelectionCycleTopKey = string.Empty;
            objectSelectionCycleCurrentKey = string.Empty;
            objectSelectionCycleVisitedKeys.Clear();
        }

        private static string BuildSelectableObjectCycleKey(object candidate)
        {
            switch (candidate)
            {
                case TextAnnotation textAnnotation:
                    return "text:" + (string.IsNullOrWhiteSpace(textAnnotation.Id)
                        ? RuntimeHelpers.GetHashCode(textAnnotation).ToString(CultureInfo.InvariantCulture)
                        : textAnnotation.Id);
                case RasterObject rasterObject:
                    return "raster:" + (string.IsNullOrWhiteSpace(rasterObject.Id)
                        ? RuntimeHelpers.GetHashCode(rasterObject).ToString(CultureInfo.InvariantCulture)
                        : rasterObject.Id);
                case ArrowObject arrowObject:
                    return "arrow:" + (string.IsNullOrWhiteSpace(arrowObject.Id)
                        ? RuntimeHelpers.GetHashCode(arrowObject).ToString(CultureInfo.InvariantCulture)
                        : arrowObject.Id);
                case VectorShapeObject vectorShapeObject:
                    return "vector:" + (string.IsNullOrWhiteSpace(vectorShapeObject.Id)
                        ? RuntimeHelpers.GetHashCode(vectorShapeObject).ToString(CultureInfo.InvariantCulture)
                        : vectorShapeObject.Id);
                default:
                    return candidate?.GetType().FullName + ":" + RuntimeHelpers.GetHashCode(candidate).ToString(CultureInfo.InvariantCulture);
            }
        }

        private List<object> GetSelectableObjectsAtPoint(Point location, float dpiX, float dpiY)
        {
            var result = new List<object>();
            foreach (object candidate in GetOrderedObjectsForCurrentPage().Reverse())
            {
                if (candidate is TextAnnotation textAnnotation &&
                    IsPointNearTextAnnotation(textAnnotation, location, dpiX, dpiY))
                {
                    result.Add(textAnnotation);
                    continue;
                }

                if (candidate is RasterObject rasterObject &&
                    IsPointInsideRasterObject(rasterObject, location))
                {
                    result.Add(rasterObject);
                    continue;
                }

                if (candidate is ArrowObject arrowObject &&
                    (IsPointNearArrowLine(arrowObject, location) || TryGetArrowHandleAtPoint(arrowObject, location, out _)))
                {
                    result.Add(arrowObject);
                    continue;
                }

                if (candidate is VectorShapeObject vectorShapeObject &&
                    IsPointNearVectorShape(vectorShapeObject, location))
                {
                    result.Add(vectorShapeObject);
                }
            }

            return result;
        }

        private bool TryGetCycledSelectableObjectAtPoint(Point location, float dpiX, float dpiY, bool advanceCycle, out object hitObject)
        {
            hitObject = null;
            List<object> candidates = GetSelectableObjectsAtPoint(location, dpiX, dpiY);
            if (candidates.Count == 0)
            {
                ResetObjectSelectionCycle();
                return false;
            }

            List<string> candidateKeys = candidates.Select(BuildSelectableObjectCycleKey).ToList();
            string topKey = candidateKeys[0];
            bool sameCycleContext =
                objectSelectionCyclePage == currentPage &&
                Math.Abs(objectSelectionCycleScale - scaleFactor) <= 0.0001f &&
                (DateTime.UtcNow - objectSelectionCycleTimestampUtc) <= TimeSpan.FromSeconds(2) &&
                string.Equals(objectSelectionCycleTopKey, topKey, StringComparison.Ordinal);

            string nextKey;
            if (!sameCycleContext)
            {
                objectSelectionCycleVisitedKeys.Clear();
                nextKey = topKey;
                objectSelectionCycleVisitedKeys.Add(nextKey);
            }
            else if (advanceCycle)
            {
                nextKey = candidateKeys.FirstOrDefault(key => !objectSelectionCycleVisitedKeys.Contains(key));
                if (string.IsNullOrWhiteSpace(nextKey))
                {
                    objectSelectionCycleVisitedKeys.Clear();
                    nextKey = topKey;
                    objectSelectionCycleVisitedKeys.Add(nextKey);
                }
                else if (!objectSelectionCycleVisitedKeys.Contains(nextKey))
                {
                    objectSelectionCycleVisitedKeys.Add(nextKey);
                }
            }
            else
            {
                nextKey = candidateKeys.FirstOrDefault(key => string.Equals(key, objectSelectionCycleCurrentKey, StringComparison.Ordinal));
                if (string.IsNullOrWhiteSpace(nextKey))
                {
                    nextKey = topKey;
                    objectSelectionCycleVisitedKeys.Clear();
                    objectSelectionCycleVisitedKeys.Add(nextKey);
                }
            }

            int nextIndex = candidateKeys.FindIndex(key => string.Equals(key, nextKey, StringComparison.Ordinal));
            if (nextIndex < 0)
            {
                nextIndex = 0;
                nextKey = topKey;
            }

            objectSelectionCyclePoint = location;
            objectSelectionCyclePage = currentPage;
            objectSelectionCycleScale = scaleFactor;
            objectSelectionCycleTimestampUtc = DateTime.UtcNow;
            objectSelectionCycleTopKey = topKey;
            objectSelectionCycleCurrentKey = nextKey;
            hitObject = candidates[nextIndex];
            return true;
        }

        private void SelectSingleObject(object hitObject)
        {
            DisableRedactionSelectionMode();
            selectedTextAnnotation = null;
            selectedRasterObject = null;
            selectedArrowObject = null;
            selectedVectorShape = null;
            ClearGroupSelection();

            switch (hitObject)
            {
                case TextAnnotation textAnnotation:
                    EnsureTextAnnotationId(textAnnotation);
                    selectedTextAnnotation = textAnnotation;
                    break;
                case RasterObject rasterObject:
                    EnsureRasterObjectId(rasterObject);
                    selectedRasterObject = rasterObject;
                    break;
                case ArrowObject arrowObject:
                    EnsureArrowObjectId(arrowObject);
                    selectedArrowObject = arrowObject;
                    break;
                case VectorShapeObject vectorShapeObject:
                    EnsureVectorShapeId(vectorShapeObject);
                    selectedVectorShape = vectorShapeObject;
                    break;
            }

            UpdateObjectSelectionInfoLabel();
        }

        private bool ToggleGroupSelectionForObject(object hitObject)
        {
            if (hitObject == null)
            {
                return false;
            }

            DisableRedactionSelectionMode();
            PromoteSingleSelectionsToGroup();
            switch (hitObject)
            {
                case TextAnnotation textAnnotation:
                    if (!selectedTextAnnotations.Add(textAnnotation))
                    {
                        selectedTextAnnotations.Remove(textAnnotation);
                    }
                    break;
                case RasterObject rasterObject:
                    EnsureRasterObjectId(rasterObject);
                    if (!string.IsNullOrWhiteSpace(rasterObject.Id) && !selectedRasterObjectIds.Add(rasterObject.Id))
                    {
                        selectedRasterObjectIds.Remove(rasterObject.Id);
                    }
                    break;
                case ArrowObject arrowObject:
                    EnsureArrowObjectId(arrowObject);
                    if (!string.IsNullOrWhiteSpace(arrowObject.Id) && !selectedArrowObjectIds.Add(arrowObject.Id))
                    {
                        selectedArrowObjectIds.Remove(arrowObject.Id);
                    }
                    break;
                case VectorShapeObject vectorShapeObject:
                    EnsureVectorShapeId(vectorShapeObject);
                    if (!string.IsNullOrWhiteSpace(vectorShapeObject.Id) && !selectedVectorShapeIds.Add(vectorShapeObject.Id))
                    {
                        selectedVectorShapeIds.Remove(vectorShapeObject.Id);
                    }
                    break;
                default:
                    return false;
            }

            CollapseGroupSelectionToSingleIfNeeded();
            UpdateObjectSelectionInfoLabel();
            return true;
        }

        private bool TryGetHitRasterAtPoint(Point location, out RasterObject hitRaster)
        {
            hitRaster = rasterObjects
                .Where(obj => obj != null && obj.PageNumber == currentPage && IsLayerVisible(obj.LayerId))
                .Reverse()
                .FirstOrDefault(obj => IsPointInsideRasterObject(obj, location));
            return hitRaster != null;
        }

        private bool TryGetHitTextAtPoint(Point location, float dpiX, float dpiY, out TextAnnotation hitText)
        {
            hitText = textAnnotations
                .Where(a => a != null && a.PageNumber == currentPage && IsLayerVisible(a.LayerId))
                .Reverse()
                .FirstOrDefault(a => GetAnnotationScreenRect(a, dpiX, dpiY).Contains(location));
            return hitText != null;
        }

        private static RectangleF GetVectorShapeBounds(IList<PointF> points)
        {
            if (points == null || points.Count == 0)
            {
                return RectangleF.Empty;
            }

            float minX = float.MaxValue;
            float minY = float.MaxValue;
            float maxX = float.MinValue;
            float maxY = float.MinValue;
            foreach (PointF point in points)
            {
                minX = Math.Min(minX, point.X);
                minY = Math.Min(minY, point.Y);
                maxX = Math.Max(maxX, point.X);
                maxY = Math.Max(maxY, point.Y);
            }

            if (minX == float.MaxValue || minY == float.MaxValue || maxX == float.MinValue || maxY == float.MinValue)
            {
                return RectangleF.Empty;
            }

            return RectangleF.FromLTRB(minX, minY, maxX, maxY);
        }

        private bool IsPointNearVectorShape(VectorShapeObject vectorShape, Point location)
        {
            if (vectorShape == null || vectorShape.PageNumber != currentPage || vectorShape.Points == null || vectorShape.Points.Count < 2)
            {
                return false;
            }

            VectorShapeType shapeType = ParseVectorShapeType(vectorShape.ShapeType);
            PointF[] points = BuildVectorShapeRenderPoints(shapeType, vectorShape.Points)
                .Select(p => new PointF(p.X * scaleFactor, p.Y * scaleFactor))
                .ToArray();
            if (points.Length < 2)
            {
                return false;
            }

            float tolerance = Math.Max(6f, (NormalizeVectorStrokeWidth(vectorShape.StrokeWidth) * scaleFactor) + 2f);
            var locationF = new PointF(location.X, location.Y);
            bool closedShape = IsShapeClosed(shapeType);
            using (var path = new GraphicsPath())
            using (var outlinePen = new Pen(System.Drawing.Color.Black, tolerance * 2f))
            {
                outlinePen.LineJoin = LineJoin.Round;
                outlinePen.StartCap = LineCap.Round;
                outlinePen.EndCap = LineCap.Round;

                if (closedShape && points.Length >= 3)
                {
                    path.AddPolygon(points);
                    if (path.IsVisible(locationF))
                    {
                        return true;
                    }

                    return path.IsOutlineVisible(locationF, outlinePen);
                }

                path.AddLines(points);
                if (path.IsOutlineVisible(locationF, outlinePen))
                {
                    return true;
                }

                for (int i = 1; i < points.Length; i++)
                {
                    if (DistancePointToSegment(locationF, points[i - 1], points[i]) <= tolerance)
                    {
                        return true;
                    }
                }
            }

            return false;
        }

        private bool TryGetHitVectorShapeAtPoint(Point location, out VectorShapeObject hitVectorShape)
        {
            hitVectorShape = null;
            EnsureObjectLayerOrder();

            foreach (var layer in objectLayerOrder.AsEnumerable().Reverse())
            {
                if (layer == null || layer.Type != LayerObjectType.VectorShape || string.IsNullOrWhiteSpace(layer.Id))
                {
                    continue;
                }

                VectorShapeObject candidate = vectorShapes.FirstOrDefault(v => v != null && v.PageNumber == currentPage && string.Equals(v.Id, layer.Id, StringComparison.Ordinal));
                if (candidate == null || !IsLayerVisible(candidate.LayerId))
                {
                    continue;
                }

                if (IsPointNearVectorShape(candidate, location))
                {
                    hitVectorShape = candidate;
                    return true;
                }
            }

            return false;
        }

        private bool TryHandleObjectDoubleClick(Point location)
        {
            if (TryGetHitVectorShapeAtPoint(location, out VectorShapeObject hitVectorShape) && hitVectorShape != null)
            {
                EditVectorShapeObject(hitVectorShape);
                return true;
            }

            if (TryGetHitArrowAtPoint(location, out ArrowObject hitArrow) && hitArrow != null)
            {
                EditArrowObject(hitArrow);
                return true;
            }

            if (TryGetHitRasterAtPoint(location, out RasterObject hitRaster) && hitRaster != null)
            {
                EditRasterObject(hitRaster);
                return true;
            }

            return false;
        }

        private bool TryToggleGroupSelectionAtPoint(Point location, float dpiX, float dpiY)
        {
            if (!TryGetCycledSelectableObjectAtPoint(location, dpiX, dpiY, advanceCycle: true, out object hitObject))
            {
                return false;
            }

            return ToggleGroupSelectionForObject(hitObject);
        }

        private bool TryBeginGroupMove(Point location, float dpiX, float dpiY)
        {
            if (GetGroupSelectionCount() < 2)
            {
                return false;
            }

            bool hitSelected = false;
            if (TryGetHitVectorShapeAtPoint(location, out VectorShapeObject hitVectorShape) &&
                hitVectorShape != null &&
                !string.IsNullOrWhiteSpace(hitVectorShape.Id) &&
                selectedVectorShapeIds.Contains(hitVectorShape.Id))
            {
                hitSelected = true;
            }
            else if (TryGetHitArrowAtPoint(location, out ArrowObject hitArrow) &&
                hitArrow != null &&
                !string.IsNullOrWhiteSpace(hitArrow.Id) &&
                selectedArrowObjectIds.Contains(hitArrow.Id))
            {
                hitSelected = true;
            }
            else if (TryGetHitRasterAtPoint(location, out RasterObject hitRaster) &&
                hitRaster != null &&
                !string.IsNullOrWhiteSpace(hitRaster.Id) &&
                selectedRasterObjectIds.Contains(hitRaster.Id))
            {
                hitSelected = true;
            }
            else if (TryGetHitTextAtPoint(location, dpiX, dpiY, out TextAnnotation hitText) &&
                hitText != null &&
                selectedTextAnnotations.Contains(hitText))
            {
                hitSelected = true;
            }

            if (!hitSelected)
            {
                return false;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return true;
            }

            bool hasLockedSelection =
                selectedTextAnnotations.Any(t => t != null && t.PageNumber == currentPage && IsTextAnnotationEffectivelyLocked(t)) ||
                selectedRasterObjectIds.Any(id => rasterObjects.Any(r => r != null && r.PageNumber == currentPage && r.Id == id && IsRasterObjectEffectivelyLocked(r))) ||
                selectedArrowObjectIds.Any(id => arrowObjects.Any(a => a != null && a.PageNumber == currentPage && a.Id == id && IsArrowObjectEffectivelyLocked(a))) ||
                selectedVectorShapeIds.Any(id => vectorShapes.Any(v => v != null && v.PageNumber == currentPage && v.Id == id && IsVectorShapeEffectivelyLocked(v)));

            if (hasLockedSelection)
            {
                MessageBox.Show(
                    this,
                    string.Format(LocalizedText("Msg_TextPositionInfo"), LocalizedText("Msg_TextAnnotation_Locked")),
                    Resources.Title_Info,
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Information);
                return true;
            }

            groupMoveEntries.Clear();
            float minX = float.MaxValue;
            float minY = float.MaxValue;
            float maxX = float.MinValue;
            float maxY = float.MinValue;

            foreach (var text in selectedTextAnnotations.Where(t => t != null && t.PageNumber == currentPage && !IsTextAnnotationEffectivelyLocked(t)))
            {
                RectangleF visualBounds = TryGetTextAnnotationVisualDocBounds(text, out RectangleF textVisualBounds)
                    ? textVisualBounds
                    : text.AnnotationBounds;
                groupMoveEntries.Add(new GroupMoveEntry
                {
                    Type = GroupMoveObjectType.Text,
                    Text = text,
                    Bounds = text.AnnotationBounds,
                    VisualBounds = visualBounds,
                    TextLeaderEndPoint = text.LeaderEndPoint
                });

                minX = Math.Min(minX, visualBounds.Left);
                minY = Math.Min(minY, visualBounds.Top);
                maxX = Math.Max(maxX, visualBounds.Right);
                maxY = Math.Max(maxY, visualBounds.Bottom);
            }

            foreach (var rasterId in selectedRasterObjectIds)
            {
                RasterObject raster = rasterObjects.FirstOrDefault(r => r != null && r.PageNumber == currentPage && r.Id == rasterId && !IsRasterObjectEffectivelyLocked(r));
                if (raster == null)
                {
                    continue;
                }

                RectangleF bounds = raster.Bounds;
                groupMoveEntries.Add(new GroupMoveEntry
                {
                    Type = GroupMoveObjectType.Raster,
                    Raster = raster,
                    Bounds = bounds
                });

                minX = Math.Min(minX, bounds.Left);
                minY = Math.Min(minY, bounds.Top);
                maxX = Math.Max(maxX, bounds.Right);
                maxY = Math.Max(maxY, bounds.Bottom);
            }

            var addedVectorIds = new HashSet<string>(
                selectedVectorShapeIds.Where(id => !string.IsNullOrWhiteSpace(id)),
                StringComparer.Ordinal);

            foreach (var rasterId in selectedRasterObjectIds)
            {
                RasterObject raster = rasterObjects.FirstOrDefault(r => r != null && r.PageNumber == currentPage && r.Id == rasterId && !IsRasterObjectEffectivelyLocked(r));
                if (raster == null)
                {
                    continue;
                }

                foreach (VectorShapeObject clipShape in GetRasterClipShapesForMove(raster))
                {
                    if (clipShape == null || string.IsNullOrWhiteSpace(clipShape.Id) || !addedVectorIds.Add(clipShape.Id))
                    {
                        continue;
                    }

                    RectangleF bounds = GetVectorShapeBounds(clipShape.Points);
                    if (bounds.IsEmpty)
                    {
                        continue;
                    }

                    groupMoveEntries.Add(new GroupMoveEntry
                    {
                        Type = GroupMoveObjectType.VectorShape,
                        VectorShape = clipShape,
                        Points = (clipShape.Points ?? new List<PointF>()).Select(p => new PointF(p.X, p.Y)).ToList(),
                        Bounds = bounds
                    });

                    minX = Math.Min(minX, bounds.Left);
                    minY = Math.Min(minY, bounds.Top);
                    maxX = Math.Max(maxX, bounds.Right);
                    maxY = Math.Max(maxY, bounds.Bottom);
                }
            }

            foreach (var arrowId in selectedArrowObjectIds)
            {
                ArrowObject arrow = arrowObjects.FirstOrDefault(a => a != null && a.PageNumber == currentPage && a.Id == arrowId && !IsArrowObjectEffectivelyLocked(a));
                if (arrow == null)
                {
                    continue;
                }

                groupMoveEntries.Add(new GroupMoveEntry
                {
                    Type = GroupMoveObjectType.Arrow,
                    Arrow = arrow,
                    Start = arrow.Start,
                    End = arrow.End
                });

                float arrowMinX = Math.Min(arrow.Start.X, arrow.End.X);
                float arrowMaxX = Math.Max(arrow.Start.X, arrow.End.X);
                float arrowMinY = Math.Min(arrow.Start.Y, arrow.End.Y);
                float arrowMaxY = Math.Max(arrow.Start.Y, arrow.End.Y);
                minX = Math.Min(minX, arrowMinX);
                minY = Math.Min(minY, arrowMinY);
                maxX = Math.Max(maxX, arrowMaxX);
                maxY = Math.Max(maxY, arrowMaxY);
            }

            foreach (var vectorId in selectedVectorShapeIds)
            {
                VectorShapeObject vector = vectorShapes.FirstOrDefault(v => v != null && v.PageNumber == currentPage && v.Id == vectorId && !IsVectorShapeEffectivelyLocked(v));
                if (vector == null)
                {
                    continue;
                }

                RectangleF bounds = GetVectorShapeBounds(vector.Points);
                if (bounds.IsEmpty)
                {
                    continue;
                }
                groupMoveEntries.Add(new GroupMoveEntry
                {
                    Type = GroupMoveObjectType.VectorShape,
                    VectorShape = vector,
                    Points = (vector.Points ?? new List<PointF>()).Select(p => p).ToList(),
                    Bounds = bounds
                });

                minX = Math.Min(minX, bounds.Left);
                minY = Math.Min(minY, bounds.Top);
                maxX = Math.Max(maxX, bounds.Right);
                maxY = Math.Max(maxY, bounds.Bottom);
            }

            if (groupMoveEntries.Count == 0 || minX == float.MaxValue || minY == float.MaxValue)
            {
                return true;
            }

            groupMoveInitialBounds = RectangleF.FromLTRB(minX, minY, maxX, maxY);
            groupMoveMinDx = float.NegativeInfinity;
            groupMoveMaxDx = float.PositiveInfinity;
            groupMoveMinDy = float.NegativeInfinity;
            groupMoveMaxDy = float.PositiveInfinity;

            float clientWidth = pdfViewer.ClientSize.Width;
            float clientHeight = pdfViewer.ClientSize.Height;
            var pageSize = GetPageSizeWithOffset(currentPage);

            foreach (GroupMoveEntry entry in groupMoveEntries)
            {
                switch (entry.Type)
                {
                    case GroupMoveObjectType.Text:
                        RectangleF textConstraintBounds = entry.VisualBounds.IsEmpty ? entry.Bounds : entry.VisualBounds;
                        float textMinX = -(textConstraintBounds.Width * 72f / dpiX / 2f);
                        float textMaxX = (clientWidth / scaleFactor) - (textConstraintBounds.Width * 72f / dpiX / 2f);
                        float textMinY = -(textConstraintBounds.Height * 72f / dpiX / 2f);
                        float textMaxY = (clientHeight / scaleFactor) - (textConstraintBounds.Height * 72f / dpiX / 2f);
                        groupMoveMinDx = Math.Max(groupMoveMinDx, textMinX - textConstraintBounds.X);
                        groupMoveMaxDx = Math.Min(groupMoveMaxDx, textMaxX - textConstraintBounds.X);
                        groupMoveMinDy = Math.Max(groupMoveMinDy, textMinY - textConstraintBounds.Y);
                        groupMoveMaxDy = Math.Min(groupMoveMaxDy, textMaxY - textConstraintBounds.Y);
                        break;
                    case GroupMoveObjectType.Raster:
                        groupMoveMinDx = Math.Max(groupMoveMinDx, -entry.Bounds.Left);
                        groupMoveMaxDx = Math.Min(groupMoveMaxDx, pageSize.Width - entry.Bounds.Right);
                        groupMoveMinDy = Math.Max(groupMoveMinDy, -entry.Bounds.Top);
                        groupMoveMaxDy = Math.Min(groupMoveMaxDy, pageSize.Height - entry.Bounds.Bottom);
                        break;
                    case GroupMoveObjectType.Arrow:
                        float arrowMinX = Math.Min(entry.Start.X, entry.End.X);
                        float arrowMaxX = Math.Max(entry.Start.X, entry.End.X);
                        float arrowMinY = Math.Min(entry.Start.Y, entry.End.Y);
                        float arrowMaxY = Math.Max(entry.Start.Y, entry.End.Y);
                        groupMoveMinDx = Math.Max(groupMoveMinDx, -arrowMinX);
                        groupMoveMaxDx = Math.Min(groupMoveMaxDx, pageSize.Width - arrowMaxX);
                        groupMoveMinDy = Math.Max(groupMoveMinDy, -arrowMinY);
                        groupMoveMaxDy = Math.Min(groupMoveMaxDy, pageSize.Height - arrowMaxY);
                        break;
                    case GroupMoveObjectType.VectorShape:
                        groupMoveMinDx = Math.Max(groupMoveMinDx, -entry.Bounds.Left);
                        groupMoveMaxDx = Math.Min(groupMoveMaxDx, pageSize.Width - entry.Bounds.Right);
                        groupMoveMinDy = Math.Max(groupMoveMinDy, -entry.Bounds.Top);
                        groupMoveMaxDy = Math.Min(groupMoveMaxDy, pageSize.Height - entry.Bounds.Bottom);
                        break;
                }
            }

            groupMoveStartMouseDoc = new PointF(location.X / scaleFactor, location.Y / scaleFactor);
            BeginUndoCapture("Move object group");
            isMovingObjectGroup = true;
            groupMoveChanged = false;
            this.Cursor = Cursors.SizeAll;
            return true;
        }

        private bool CanInteractWithCurrentGroupSelection()
        {
            if (GetGroupSelectionCount() < 2)
            {
                return false;
            }

            bool hasLockedSelection =
                selectedTextAnnotations.Any(t => t != null && t.PageNumber == currentPage && IsTextAnnotationEffectivelyLocked(t)) ||
                selectedRasterObjectIds.Any(id => rasterObjects.Any(r => r != null && r.PageNumber == currentPage && r.Id == id && IsRasterObjectEffectivelyLocked(r))) ||
                selectedArrowObjectIds.Any(id => arrowObjects.Any(a => a != null && a.PageNumber == currentPage && a.Id == id && IsArrowObjectEffectivelyLocked(a))) ||
                selectedVectorShapeIds.Any(id => vectorShapes.Any(v => v != null && v.PageNumber == currentPage && v.Id == id && IsVectorShapeEffectivelyLocked(v)));
            return !hasLockedSelection;
        }

        private bool TryGetCurrentGroupSelectionScreenBounds(float dpiX, float dpiY, out RectangleF bounds)
        {
            bounds = RectangleF.Empty;
            if (GetGroupSelectionCount() < 2)
            {
                return false;
            }

            float minX = float.MaxValue;
            float minY = float.MaxValue;
            float maxX = float.MinValue;
            float maxY = float.MinValue;

            void includeBounds(RectangleF rect)
            {
                if (rect.Width <= 0f || rect.Height <= 0f)
                {
                    return;
                }

                minX = Math.Min(minX, rect.Left);
                minY = Math.Min(minY, rect.Top);
                maxX = Math.Max(maxX, rect.Right);
                maxY = Math.Max(maxY, rect.Bottom);
            }

            foreach (TextAnnotation text in selectedTextAnnotations.Where(t => t != null && t.PageNumber == currentPage && IsLayerVisible(t.LayerId)))
            {
                if (TryGetTextAnnotationVisualScreenBounds(text, dpiX, dpiY, out RectangleF textBounds))
                {
                    includeBounds(textBounds);
                }
            }

            foreach (string rasterId in selectedRasterObjectIds)
            {
                RasterObject raster = rasterObjects.FirstOrDefault(r => r != null && r.PageNumber == currentPage && r.Id == rasterId && IsLayerVisible(r.LayerId));
                if (raster != null)
                {
                    includeBounds(GetRasterObjectScreenFrameBounds(raster));
                }
            }

            foreach (string arrowId in selectedArrowObjectIds)
            {
                ArrowObject arrow = arrowObjects.FirstOrDefault(a => a != null && a.PageNumber == currentPage && a.Id == arrowId && IsLayerVisible(a.LayerId));
                if (arrow != null && TryGetArrowScreenBounds(arrow, out RectangleF arrowBounds))
                {
                    includeBounds(arrowBounds);
                }
            }

            foreach (string vectorId in selectedVectorShapeIds)
            {
                VectorShapeObject vector = vectorShapes.FirstOrDefault(v => v != null && v.PageNumber == currentPage && v.Id == vectorId && IsLayerVisible(v.LayerId));
                if (vector != null && TryGetVectorShapeScreenBounds(vector, out RectangleF vectorBounds))
                {
                    includeBounds(vectorBounds);
                }
            }

            if (minX == float.MaxValue || minY == float.MaxValue || maxX == float.MinValue || maxY == float.MinValue)
            {
                return false;
            }

            bounds = RectangleF.FromLTRB(minX, minY, maxX, maxY);
            return bounds.Width > 0f && bounds.Height > 0f;
        }

        private bool TryUpdateGroupHoverCursor(Point location, float dpiX, float dpiY)
        {
            if (!CanInteractWithCurrentGroupSelection())
            {
                return false;
            }

            if (!TryGetCurrentGroupSelectionScreenBounds(dpiX, dpiY, out RectangleF bounds))
            {
                return false;
            }

            if (TryGetObjectScaleHandleAtPoint(bounds, location, out ObjectScaleHandleCorner handleCorner))
            {
                this.Cursor = GetCursorForObjectScaleHandle(handleCorner);
                return true;
            }

            return false;
        }

        private bool TryBuildCurrentGroupSelectionEntries(float dpiX, float dpiY)
        {
            groupMoveEntries.Clear();
            float minX = float.MaxValue;
            float minY = float.MaxValue;
            float maxX = float.MinValue;
            float maxY = float.MinValue;

            foreach (var text in selectedTextAnnotations.Where(t => t != null && t.PageNumber == currentPage && !IsTextAnnotationEffectivelyLocked(t)))
            {
                RectangleF visualBounds = TryGetTextAnnotationVisualDocBounds(text, out RectangleF textVisualBounds)
                    ? textVisualBounds
                    : text.AnnotationBounds;
                groupMoveEntries.Add(new GroupMoveEntry
                {
                    Type = GroupMoveObjectType.Text,
                    Text = text,
                    Bounds = text.AnnotationBounds,
                    VisualBounds = visualBounds,
                    TextFontFamily = text.AnnotationFont?.FontFamily,
                    TextFontStyle = text.AnnotationFont?.Style ?? FontStyle.Regular,
                    TextFontUnit = text.AnnotationFont?.Unit ?? GraphicsUnit.Point,
                    TextFontSize = text.AnnotationFont?.Size ?? 12f,
                    TextBorderWidth = text.AnnotationBorderWidth,
                    TextFrameMargin = text.AnnotationFrameMargin,
                    TextLeaderEndPoint = text.LeaderEndPoint,
                    TextLeaderLineWidth = NormalizeLeaderLineWidth(text.LeaderLineWidth),
                    TextLeaderHeadLength = NormalizeTextLeaderHeadLength(text.LeaderHeadLength),
                    TextLeaderHeadWidth = NormalizeTextLeaderHeadWidth(text.LeaderHeadWidth)
                });

                minX = Math.Min(minX, visualBounds.Left);
                minY = Math.Min(minY, visualBounds.Top);
                maxX = Math.Max(maxX, visualBounds.Right);
                maxY = Math.Max(maxY, visualBounds.Bottom);
            }

            foreach (var rasterId in selectedRasterObjectIds)
            {
                RasterObject raster = rasterObjects.FirstOrDefault(r => r != null && r.PageNumber == currentPage && r.Id == rasterId && !IsRasterObjectEffectivelyLocked(r));
                if (raster == null)
                {
                    continue;
                }

                RectangleF bounds = raster.Bounds;
                groupMoveEntries.Add(new GroupMoveEntry
                {
                    Type = GroupMoveObjectType.Raster,
                    Raster = raster,
                    Bounds = bounds
                });

                minX = Math.Min(minX, bounds.Left);
                minY = Math.Min(minY, bounds.Top);
                maxX = Math.Max(maxX, bounds.Right);
                maxY = Math.Max(maxY, bounds.Bottom);
            }

            foreach (var arrowId in selectedArrowObjectIds)
            {
                ArrowObject arrow = arrowObjects.FirstOrDefault(a => a != null && a.PageNumber == currentPage && a.Id == arrowId && !IsArrowObjectEffectivelyLocked(a));
                if (arrow == null)
                {
                    continue;
                }

                groupMoveEntries.Add(new GroupMoveEntry
                {
                    Type = GroupMoveObjectType.Arrow,
                    Arrow = arrow,
                    Start = arrow.Start,
                    End = arrow.End,
                    ArrowThickness = arrow.Thickness,
                    ArrowBorderWidth = arrow.BorderWidth,
                    ArrowHeadLength = arrow.HeadLength,
                    ArrowHeadWidth = arrow.HeadWidth
                });

                float arrowMinX = Math.Min(arrow.Start.X, arrow.End.X);
                float arrowMaxX = Math.Max(arrow.Start.X, arrow.End.X);
                float arrowMinY = Math.Min(arrow.Start.Y, arrow.End.Y);
                float arrowMaxY = Math.Max(arrow.Start.Y, arrow.End.Y);
                minX = Math.Min(minX, arrowMinX);
                minY = Math.Min(minY, arrowMinY);
                maxX = Math.Max(maxX, arrowMaxX);
                maxY = Math.Max(maxY, arrowMaxY);
            }

            foreach (var vectorId in selectedVectorShapeIds)
            {
                VectorShapeObject vector = vectorShapes.FirstOrDefault(v => v != null && v.PageNumber == currentPage && v.Id == vectorId && !IsVectorShapeEffectivelyLocked(v));
                if (vector == null)
                {
                    continue;
                }

                RectangleF bounds = GetVectorShapeBounds(vector.Points);
                if (bounds.IsEmpty)
                {
                    continue;
                }

                groupMoveEntries.Add(new GroupMoveEntry
                {
                    Type = GroupMoveObjectType.VectorShape,
                    VectorShape = vector,
                    Points = (vector.Points ?? new List<PointF>()).Select(p => p).ToList(),
                    Bounds = bounds,
                    VectorStrokeWidth = vector.StrokeWidth,
                    VectorStartEndingPrimarySize = vector.StartLineEndingPrimarySize,
                    VectorStartEndingSecondarySize = vector.StartLineEndingSecondarySize,
                    VectorEndEndingPrimarySize = vector.EndLineEndingPrimarySize,
                    VectorEndEndingSecondarySize = vector.EndLineEndingSecondarySize
                });

                minX = Math.Min(minX, bounds.Left);
                minY = Math.Min(minY, bounds.Top);
                maxX = Math.Max(maxX, bounds.Right);
                maxY = Math.Max(maxY, bounds.Bottom);
            }

            if (groupMoveEntries.Count == 0 || minX == float.MaxValue || minY == float.MaxValue)
            {
                return false;
            }

            groupMoveInitialBounds = RectangleF.FromLTRB(minX, minY, maxX, maxY);
            return true;
        }

        private bool TryBeginGroupScale(Point location, float dpiX, float dpiY)
        {
            if (!CanInteractWithCurrentGroupSelection())
            {
                return false;
            }

            if (!TryGetCurrentGroupSelectionScreenBounds(dpiX, dpiY, out RectangleF screenBounds))
            {
                return false;
            }

            if (!TryGetObjectScaleHandleAtPoint(screenBounds, location, out ObjectScaleHandleCorner handleCorner))
            {
                return false;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return true;
            }

            if (!TryBuildCurrentGroupSelectionEntries(dpiX, dpiY))
            {
                return true;
            }

            BeginUndoCapture("Scale object group");
            isScalingObjectGroup = true;
            groupScaleChanged = false;
            activeGroupScaleHandleCorner = handleCorner;
            groupScaleStartScreenBounds = screenBounds;
            this.Cursor = GetCursorForObjectScaleHandle(handleCorner);
            return true;
        }

        private static RectangleF ScaleRectangleFromScreenBounds(RectangleF initialDocBounds, RectangleF initialScreenBounds, RectangleF newScreenBounds, float scaleFactor)
        {
            PointF topLeft = ScalePointFromScreenBounds(new PointF(initialDocBounds.Left, initialDocBounds.Top), initialScreenBounds, newScreenBounds, scaleFactor);
            PointF bottomRight = ScalePointFromScreenBounds(new PointF(initialDocBounds.Right, initialDocBounds.Bottom), initialScreenBounds, newScreenBounds, scaleFactor);
            return RectangleF.FromLTRB(
                Math.Min(topLeft.X, bottomRight.X),
                Math.Min(topLeft.Y, bottomRight.Y),
                Math.Max(topLeft.X, bottomRight.X),
                Math.Max(topLeft.Y, bottomRight.Y));
        }

        private static RectangleF ScaleRectangleUniformFromHandle(RectangleF initialBounds, ObjectScaleHandleCorner handleCorner, float scale, bool scaleFromCenter)
        {
            scale = Math.Max(0.05f, scale);

            if (scaleFromCenter)
            {
                float centerX = initialBounds.Left + (initialBounds.Width / 2f);
                float centerY = initialBounds.Top + (initialBounds.Height / 2f);
                float newWidth = Math.Max(1f, initialBounds.Width * scale);
                float newHeight = Math.Max(1f, initialBounds.Height * scale);
                return new RectangleF(
                    centerX - (newWidth / 2f),
                    centerY - (newHeight / 2f),
                    newWidth,
                    newHeight);
            }

            float width = Math.Max(1f, initialBounds.Width * scale);
            float height = Math.Max(1f, initialBounds.Height * scale);
            PointF anchor = GetObjectScaleAnchorPoint(initialBounds, handleCorner);
            switch (handleCorner)
            {
                case ObjectScaleHandleCorner.TopLeft:
                    return new RectangleF(anchor.X - width, anchor.Y - height, width, height);
                case ObjectScaleHandleCorner.TopRight:
                    return new RectangleF(anchor.X, anchor.Y - height, width, height);
                case ObjectScaleHandleCorner.BottomRight:
                    return new RectangleF(anchor.X, anchor.Y, width, height);
                case ObjectScaleHandleCorner.BottomLeft:
                    return new RectangleF(anchor.X - width, anchor.Y, width, height);
                default:
                    return initialBounds;
            }
        }

        private bool TryApplyGroupScaleFromMouse(Point location)
        {
            if (!isScalingObjectGroup || groupMoveEntries.Count == 0 || groupScaleStartScreenBounds.IsEmpty)
            {
                return false;
            }

            bool preserveAspectRatio = (Control.ModifierKeys & Keys.Shift) == Keys.Shift;
            bool scaleFromCenter = (Control.ModifierKeys & Keys.Alt) == Keys.Alt;
            RectangleF newScreenBounds = BuildScaledBoundsFromAnchor(groupScaleStartScreenBounds, activeGroupScaleHandleCorner, location, preserveAspectRatio, scaleFromCenter);
            float scaleX = newScreenBounds.Width / Math.Max(1f, groupScaleStartScreenBounds.Width);
            float scaleY = newScreenBounds.Height / Math.Max(1f, groupScaleStartScreenBounds.Height);
            float uniformScale = GetUniformScaleFactor(scaleX, scaleY);

            foreach (GroupMoveEntry entry in groupMoveEntries)
            {
                if (entry == null)
                {
                    continue;
                }

                switch (entry.Type)
                {
                    case GroupMoveObjectType.Text:
                        if (entry.Text != null)
                        {
                            entry.Text.AnnotationBounds = ScaleRectangleFromScreenBounds(entry.Bounds, groupScaleStartScreenBounds, newScreenBounds, scaleFactor);
                            FontFamily fontFamily = entry.TextFontFamily ?? entry.Text.AnnotationFont?.FontFamily ?? FontFamily.GenericSansSerif;
                            entry.Text.AnnotationFont = new Font(fontFamily, Math.Max(4f, entry.TextFontSize * uniformScale), entry.TextFontStyle, entry.TextFontUnit);
                            entry.Text.AnnotationBorderWidth = Math.Max(0f, entry.TextBorderWidth * uniformScale);
                            entry.Text.AnnotationFrameMargin = Math.Max(0f, entry.TextFrameMargin * uniformScale);
                            if (entry.Text.HasLeaderArrow)
                            {
                                entry.Text.LeaderEndPoint = ScalePointFromScreenBounds(entry.TextLeaderEndPoint, groupScaleStartScreenBounds, newScreenBounds, scaleFactor);
                                entry.Text.LeaderLineWidth = NormalizeLeaderLineWidth(entry.TextLeaderLineWidth * uniformScale);
                                entry.Text.LeaderHeadLength = NormalizeTextLeaderHeadLength(entry.TextLeaderHeadLength * uniformScale);
                                entry.Text.LeaderHeadWidth = NormalizeTextLeaderHeadWidth(entry.TextLeaderHeadWidth * uniformScale);
                                entry.Text.LeaderAnchorKind = GetClosestTextLeaderAnchorKind(entry.Text, entry.Text.LeaderEndPoint);
                            }
                            TouchTextAnnotation(entry.Text);
                        }
                        break;
                    case GroupMoveObjectType.Raster:
                        if (entry.Raster != null)
                        {
                            entry.Raster.Bounds = ScaleRectangleFromScreenBounds(entry.Bounds, groupScaleStartScreenBounds, newScreenBounds, scaleFactor);
                            ConstrainRasterObjectToPage(entry.Raster);
                            entry.Raster.UpdatedAtUtc = DateTime.UtcNow;
                        }
                        break;
                    case GroupMoveObjectType.Arrow:
                        if (entry.Arrow != null)
                        {
                            entry.Arrow.Start = ScalePointFromScreenBounds(entry.Start, groupScaleStartScreenBounds, newScreenBounds, scaleFactor);
                            entry.Arrow.End = ScalePointFromScreenBounds(entry.End, groupScaleStartScreenBounds, newScreenBounds, scaleFactor);
                            entry.Arrow.Thickness = NormalizeArrowThickness(entry.ArrowThickness * uniformScale);
                            entry.Arrow.BorderWidth = NormalizeArrowBorderWidth(entry.ArrowBorderWidth * uniformScale);
                            entry.Arrow.HeadLength = NormalizeArrowHeadLength(entry.ArrowHeadLength * uniformScale);
                            entry.Arrow.HeadWidth = NormalizeArrowHeadWidth(entry.ArrowHeadWidth * uniformScale);
                            ConstrainArrowToPage(entry.Arrow);
                            entry.Arrow.UpdatedAtUtc = DateTime.UtcNow;
                        }
                        break;
                    case GroupMoveObjectType.VectorShape:
                        if (entry.VectorShape != null && entry.Points != null && entry.Points.Count > 0)
                        {
                            entry.VectorShape.Points = entry.Points
                                .Select(point => ScalePointFromScreenBounds(point, groupScaleStartScreenBounds, newScreenBounds, scaleFactor))
                                .ToList();
                            entry.VectorShape.StrokeWidth = NormalizeVectorStrokeWidth(entry.VectorStrokeWidth * uniformScale);
                            entry.VectorShape.StartLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(entry.VectorStartEndingPrimarySize * uniformScale);
                            entry.VectorShape.StartLineEndingSecondarySize = entry.VectorStartEndingSecondarySize;
                            entry.VectorShape.EndLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(entry.VectorEndEndingPrimarySize * uniformScale);
                            entry.VectorShape.EndLineEndingSecondarySize = entry.VectorEndEndingSecondarySize;
                            NormalizeVectorShape(entry.VectorShape);
                            ConstrainVectorShapeToPage(entry.VectorShape);
                            entry.VectorShape.UpdatedAtUtc = DateTime.UtcNow;
                        }
                        break;
                }
            }

            groupScaleChanged = true;
            this.Cursor = GetCursorForObjectScaleHandle(activeGroupScaleHandleCorner);
            pdfViewer.Invalidate();
            return true;
        }

