        private static SizeF GetAnnotationSize(string text, Font font, int rotation)
        {
            return RotateSize(GetAnnotationPlainContentSize(text, font), rotation);
        }

        private static SizeF GetAnnotationPlainContentSize(string text, Font font)
        {
            if (text == null)
                text = string.Empty;

            string normalized = text.Replace("\r\n", "\n").Replace("\r", "\n");
            string[] lines = normalized.Split(new[] { '\n' }, StringSplitOptions.None);
            float maxWidth = 0f;
            float lineHeight;

            using (Graphics g = Graphics.FromHwnd(IntPtr.Zero))
            using (StringFormat format = (StringFormat)StringFormat.GenericTypographic.Clone())
            {
                format.FormatFlags |= StringFormatFlags.NoWrap | StringFormatFlags.MeasureTrailingSpaces;
                format.Trimming = StringTrimming.None;
                lineHeight = font.GetHeight(g);
                foreach (string line in lines)
                {
                    SizeF size = g.MeasureString(line, font, int.MaxValue, format);
                    if (size.Width > maxWidth)
                        maxWidth = size.Width;
                }
            }

            float height = Math.Max(lineHeight * Math.Max(lines.Length, 1), lineHeight);
            return new SizeF(maxWidth, height);
        }

        private static SizeF RotateSize(SizeF size, int rotation)
        {
            rotation = NormalizeRotation(rotation);
            if (rotation == 0)
            {
                return size;
            }

            float angle = (float)(rotation * Math.PI / 180.0);
            float cos = Math.Abs((float)Math.Cos(angle));
            float sin = Math.Abs((float)Math.Sin(angle));
            float rotatedWidth = (size.Width * cos) + (size.Height * sin);
            float rotatedHeight = (size.Width * sin) + (size.Height * cos);
            return new SizeF(rotatedWidth, rotatedHeight);
        }

        private static SizeF GetRichAnnotationSize(string plainText, string richText, Font fallbackFont, int rotation)
        {
            return RotateSize(GetRichAnnotationContentSize(plainText, richText, fallbackFont), rotation);
        }

        private static SizeF GetRichAnnotationContentSize(string plainText, string richText, Font fallbackFont)
        {
            if (fallbackFont == null)
            {
                fallbackFont = SystemFonts.DefaultFont;
            }

            // Deterministic sizing: rich mode uses the same bounds model as plain mode.
            // This keeps preview stable across font-size changes and alignment switches.
            string content = plainText ?? string.Empty;
            if (string.IsNullOrWhiteSpace(content) && !string.IsNullOrWhiteSpace(richText))
            {
                try
                {
                    using (var rtb = new RichTextBox())
                    {
                        rtb.Rtf = richText;
                        content = rtb.Text ?? string.Empty;
                    }
                }
                catch
                {
                    content = string.Empty;
                }
            }

            SizeF baseSize = GetAnnotationPlainContentSize(content, fallbackFont);
            using (Graphics g = Graphics.FromHwnd(IntPtr.Zero))
            using (StringFormat format = (StringFormat)StringFormat.GenericTypographic.Clone())
            {
                format.FormatFlags |= StringFormatFlags.NoWrap | StringFormatFlags.MeasureTrailingSpaces;
                format.Trimming = StringTrimming.None;

                // Add one character (width) and one line (height), scaled by current font.
                float extraWidth = g.MeasureString("M", fallbackFont, int.MaxValue, format).Width;
                float extraHeight = fallbackFont.GetHeight(g);
                SizeF paddedSize = new SizeF(
                    Math.Max(1f, baseSize.Width + extraWidth),
                    Math.Max(1f, baseSize.Height + extraHeight));
                return paddedSize;
            }
        }

        private static float NormalizeAnnotationBorderWidth(float value)
        {
            if (float.IsNaN(value) || float.IsInfinity(value))
            {
                return 0f;
            }

            return Math.Max(0f, Math.Min(24f, value));
        }

        private static float NormalizeAnnotationFrameMargin(float value)
        {
            if (float.IsNaN(value) || float.IsInfinity(value))
            {
                return 0f;
            }

            return Math.Max(0f, Math.Min(120f, value));
        }

        internal static float NormalizeLeaderHeadLength(float value)
        {
            if (float.IsNaN(value) || float.IsInfinity(value))
            {
                return PDFForm.DefaultArrowHeadLength;
            }

            return Math.Max(4f, Math.Min(120f, value));
        }

        internal static float NormalizeLeaderHeadWidth(float value)
        {
            if (float.IsNaN(value) || float.IsInfinity(value))
            {
                return PDFForm.DefaultArrowHeadWidth;
            }

            return Math.Max(4f, Math.Min(120f, value));
        }

        internal static float NormalizeLeaderLineWidth(float value)
        {
            if (float.IsNaN(value) || float.IsInfinity(value))
            {
                return 1.5f;
            }

            return Math.Max(0.5f, Math.Min(24f, value));
        }

        private static PointF GetDefaultLeaderEndPoint(RectangleF annotationBounds)
        {
            float offsetX = Math.Max(30f, annotationBounds.Width * 0.35f);
            float offsetY = Math.Max(24f, annotationBounds.Height * 0.35f);
            return new PointF(annotationBounds.Left - offsetX, annotationBounds.Bottom + offsetY);
        }

        private static void ResetTextLeaderToDefault(TextAnnotation annotation)
        {
            if (annotation == null)
            {
                return;
            }

            annotation.LeaderAnchorKind = TextLeaderAnchorKind.BottomLeft;
            annotation.LeaderEndPoint = GetDefaultLeaderEndPoint(annotation.AnnotationBounds);
        }

