                    MessageBox.Show(this, string.Format(Resources.Msg_OpenPdfError, ex.Message),
                                    Resources.Title_Error, MessageBoxButtons.OK, MessageBoxIcon.Error);
                    return;
                }
            }

            pdfDoc.Close();
