        private static int GetScrollMaximum(ScrollProperties scroll)
        {
            int max = scroll.Maximum - scroll.LargeChange + 1;
            return max < scroll.Minimum ? scroll.Minimum : max;
        }

        private static int ClampScrollValue(int value, int min, int max)
        {
            if (value < min)
            {
                return min;
            }

            if (value > max)
            {
                return max;
            }

            return value;
        }

        private static bool ArePathsEqual(string left, string right)
        {
            if (string.IsNullOrWhiteSpace(left) || string.IsNullOrWhiteSpace(right))
            {
                return false;
            }

            try
            {
                string normalizedLeft = Path.GetFullPath(left.Trim());
                string normalizedRight = Path.GetFullPath(right.Trim());
                return string.Equals(normalizedLeft, normalizedRight, StringComparison.OrdinalIgnoreCase);
            }
            catch
            {
                return string.Equals(left.Trim(), right.Trim(), StringComparison.OrdinalIgnoreCase);
            }
        }

        private static string ResolveProjectPdfPath(string savedPdfPath, string projectPath)
        {
            if (string.IsNullOrWhiteSpace(savedPdfPath))
            {
                return savedPdfPath;
            }

            if (File.Exists(savedPdfPath))
            {
                return savedPdfPath;
            }

            if (string.IsNullOrWhiteSpace(projectPath))
            {
                return savedPdfPath;
            }

            try
            {
                string projectDirectory = Path.GetDirectoryName(Path.GetFullPath(projectPath));
                string pdfFileName = Path.GetFileName(savedPdfPath);
                if (string.IsNullOrWhiteSpace(projectDirectory) || string.IsNullOrWhiteSpace(pdfFileName))
                {
                    return savedPdfPath;
                }

                string fallbackPath = Path.Combine(projectDirectory, pdfFileName);
                if (File.Exists(fallbackPath))
                {
                    return fallbackPath;
                }
            }
            catch
            {
                // ignore and fall back to saved path
            }

            return savedPdfPath;
        }

