        private void LoadFootnotesCatalog()
        {
            exclusionScopesCatalog.Clear();
            exclusionScopesById.Clear();
            legalBasesCatalog.Clear();
            legalBasesById.Clear();
            footnotesCatalogLoadWarnings.Clear();

            globalExclusionScopesPath = GetGlobalExclusionScopesFilePath();
            localExclusionScopesPath = GetLocalExclusionScopesFilePath();
            globalLegalBasesPath = GetGlobalLegalBasesFilePath();
            localLegalBasesPath = GetLocalLegalBasesFilePath();

            canWriteGlobalExclusionScopes = HasWriteAccessToTarget(globalExclusionScopesPath);
            canWriteGlobalLegalBases = HasWriteAccessToTarget(globalLegalBasesPath);

            LoadMergedExclusionScopesCatalog();
            LoadMergedLegalBasesCatalog();

            if (footnotesCatalogLoadWarnings.Count > 0)
            {
                LogDebug("Footnotes catalog warnings: " + string.Join(" | ", footnotesCatalogLoadWarnings));
            }

            LogDebug(
                $"Footnotes catalog loaded scopes={exclusionScopesCatalog.Count} legalBases={legalBasesCatalog.Count} " +
                $"globalScopesWritable={canWriteGlobalExclusionScopes} globalLegalWritable={canWriteGlobalLegalBases}");
        }

        private void LoadMergedExclusionScopesCatalog()
        {
            if (TryLoadCatalogFile(globalExclusionScopesPath, out ExclusionScopesCatalogFile globalFile, out string globalError))
            {
                AddExclusionScopesToCatalog(globalFile.ExclusionScopes, ExclusionScopeSource.Global, globalExclusionScopesPath);
            }
            else if (!string.IsNullOrWhiteSpace(globalError))
            {
                footnotesCatalogLoadWarnings.Add(globalError);
            }

            if (TryLoadCatalogFile(localExclusionScopesPath, out ExclusionScopesCatalogFile localFile, out string localError))
            {
                AddExclusionScopesToCatalog(localFile.ExclusionScopes, ExclusionScopeSource.Local, localExclusionScopesPath);
            }
            else if (!string.IsNullOrWhiteSpace(localError))
            {
                footnotesCatalogLoadWarnings.Add(localError);
            }
        }

        private void AddExclusionScopesToCatalog(IEnumerable<ExclusionScopeDefinition> scopes, ExclusionScopeSource source, string sourcePath)
        {
            if (scopes == null)
            {
                return;
            }

            foreach (var scope in scopes)
            {
                if (!NormalizeScopeDefinition(scope, source))
                {
                    continue;
                }

                if (exclusionScopesById.ContainsKey(scope.ScopeId))
                {
                    footnotesCatalogLoadWarnings.Add($"Duplicate scope_id '{scope.ScopeId}' in {sourcePath}. Entry skipped.");
                    continue;
                }

                exclusionScopesCatalog.Add(scope);
                exclusionScopesById[scope.ScopeId] = scope;
            }
        }

        private void LoadMergedLegalBasesCatalog()
        {
            if (TryLoadCatalogFile(globalLegalBasesPath, out LegalBasesCatalogFile globalFile, out string globalError))
            {
                AddLegalBasesToCatalog(globalFile.LegalBases, LegalBasisSource.Global, globalLegalBasesPath);
            }
            else if (!string.IsNullOrWhiteSpace(globalError))
            {
                footnotesCatalogLoadWarnings.Add(globalError);
            }

            if (TryLoadCatalogFile(localLegalBasesPath, out LegalBasesCatalogFile localFile, out string localError))
            {
                AddLegalBasesToCatalog(localFile.LegalBases, LegalBasisSource.Local, localLegalBasesPath);
            }
            else if (!string.IsNullOrWhiteSpace(localError))
            {
                footnotesCatalogLoadWarnings.Add(localError);
            }
        }

        private bool TryLoadLegalBasesForEditor(
            string path,
            LegalBasisSource source,
            out List<LegalBasisDefinition> legalBases,
            out string errorMessage)
        {
            legalBases = new List<LegalBasisDefinition>();
            errorMessage = string.Empty;

            if (string.IsNullOrWhiteSpace(path) || !File.Exists(path))
            {
                return true;
            }

            if (!TryLoadCatalogFile(path, out LegalBasesCatalogFile catalogFile, out string loadError))
            {
                string prefix = source == LegalBasisSource.Global
                    ? GetLegalBasesLoadGlobalErrorPrefix()
                    : GetLegalBasesLoadLocalErrorPrefix();
                errorMessage = $"{prefix}\n{loadError}";
                return false;
            }

            foreach (var entry in catalogFile.LegalBases ?? new List<LegalBasisDefinition>())
            {
                var clonedEntry = CloneLegalBasisDefinition(entry);
                if (NormalizeLegalBasisDefinition(clonedEntry, source))
                {
                    legalBases.Add(clonedEntry);
                }
            }

            return true;
        }

        private bool TrySaveLegalBasesForEditor(
            string path,
            string sourceName,
            LegalBasisSource sourceKind,
            IEnumerable<LegalBasisDefinition> legalBases,
            out string errorMessage)
        {
            errorMessage = string.Empty;
            var normalizedEntries = new List<LegalBasisDefinition>();
            var usedIds = new HashSet<string>(StringComparer.OrdinalIgnoreCase);

            foreach (var entry in legalBases ?? Enumerable.Empty<LegalBasisDefinition>())
            {
                var clonedEntry = CloneLegalBasisDefinition(entry);
                if (!NormalizeLegalBasisDefinition(clonedEntry, sourceKind))
                {
                    errorMessage = GetLegalBasesSaveInvalidEntryMessage();
                    return false;
                }

                if (!usedIds.Add(clonedEntry.Id))
                {
                    errorMessage = string.Format(GetLegalBasesSaveDuplicateIdMessage(), clonedEntry.Id);
                    return false;
                }

                normalizedEntries.Add(clonedEntry);
            }

            try
            {
                string directoryPath = Path.GetDirectoryName(path);
                if (!string.IsNullOrWhiteSpace(directoryPath))
                {
                    Directory.CreateDirectory(directoryPath);
                }

                var catalogFile = new LegalBasesCatalogFile
                {
                    Source = sourceName,
                    LegalBases = normalizedEntries
                };

                string json = JsonConvert.SerializeObject(catalogFile, Formatting.Indented);
                File.WriteAllText(path, json);
                return true;
            }
            catch (Exception ex)
            {
                string prefix = sourceKind == LegalBasisSource.Global
                    ? GetLegalBasesSaveGlobalErrorPrefix()
                    : GetLegalBasesSaveLocalErrorPrefix();
                errorMessage = $"{prefix}\n{ex.Message}";
                return false;
            }
        }

        private bool TryLoadExclusionScopesForEditor(
            string path,
            ExclusionScopeSource source,
            out List<ExclusionScopeDefinition> scopes,
            out string version,
            out string errorMessage)
        {
            scopes = new List<ExclusionScopeDefinition>();
            version = "1.0";
            errorMessage = string.Empty;

            if (string.IsNullOrWhiteSpace(path) || !File.Exists(path))
            {
                return true;
            }

            if (!TryLoadCatalogFile(path, out ExclusionScopesCatalogFile catalogFile, out string loadError))
            {
                string prefix = source == ExclusionScopeSource.Global
                    ? GetExclusionScopesLoadGlobalErrorPrefix()
                    : GetExclusionScopesLoadLocalErrorPrefix();
                errorMessage = $"{prefix}\n{loadError}";
                return false;
            }

            if (!string.IsNullOrWhiteSpace(catalogFile.Version))
            {
                version = catalogFile.Version.Trim();
            }

            foreach (var entry in catalogFile.ExclusionScopes ?? new List<ExclusionScopeDefinition>())
            {
                var clonedEntry = CloneExclusionScopeDefinition(entry);
                if (NormalizeScopeDefinition(clonedEntry, source))
                {
                    scopes.Add(clonedEntry);
                }
            }

            return true;
        }

        private bool TrySaveExclusionScopesForEditor(
            string path,
            string version,
            ExclusionScopeSource source,
            IEnumerable<ExclusionScopeDefinition> scopes,
            out string errorMessage)
        {
            errorMessage = string.Empty;
            var normalizedScopes = new List<ExclusionScopeDefinition>();
            var usedScopeIds = new HashSet<string>(StringComparer.OrdinalIgnoreCase);

            foreach (var entry in scopes ?? Enumerable.Empty<ExclusionScopeDefinition>())
            {
                var clonedEntry = CloneExclusionScopeDefinition(entry);
                if (!NormalizeScopeDefinition(clonedEntry, source))
                {
                    errorMessage = GetExclusionScopesSaveInvalidEntryMessage();
                    return false;
                }

                if (!usedScopeIds.Add(clonedEntry.ScopeId))
                {
                    errorMessage = string.Format(GetExclusionScopesSaveDuplicateIdMessage(), clonedEntry.ScopeId);
                    return false;
                }

                normalizedScopes.Add(clonedEntry);
            }

            try
            {
                string directoryPath = Path.GetDirectoryName(path);
                if (!string.IsNullOrWhiteSpace(directoryPath))
                {
                    Directory.CreateDirectory(directoryPath);
                }

                var catalogFile = new ExclusionScopesCatalogFile
                {
                    Version = string.IsNullOrWhiteSpace(version) ? "1.0" : version.Trim(),
                    ExclusionScopes = normalizedScopes
                };

                string json = JsonConvert.SerializeObject(catalogFile, Formatting.Indented);
                File.WriteAllText(path, json);
                return true;
            }
            catch (Exception ex)
            {
                string prefix = source == ExclusionScopeSource.Global
                    ? GetExclusionScopesSaveGlobalErrorPrefix()
                    : GetExclusionScopesSaveLocalErrorPrefix();
                errorMessage = $"{prefix}\n{ex.Message}";
                return false;
            }
        }

        private static LegalBasisDefinition CloneLegalBasisDefinition(LegalBasisDefinition source)
        {
            if (source == null)
            {
                return new LegalBasisDefinition();
            }

            return new LegalBasisDefinition
            {
                Id = source.Id,
                Title = source.Title,
                FullCitation = source.FullCitation,
                RequiresInterestSubject = source.RequiresInterestSubject,
                DescriptionHint = source.DescriptionHint,
                SourceKind = source.SourceKind
            };
        }

        private static ExclusionScopeDefinition CloneExclusionScopeDefinition(ExclusionScopeDefinition source)
        {
            if (source == null)
            {
                return new ExclusionScopeDefinition();
            }

            return new ExclusionScopeDefinition
            {
                ScopeId = source.ScopeId,
                FriendlyName = source.FriendlyName,
                Category = source.Category,
                Description = source.Description,
                AutoDetectTags = new List<string>(source.AutoDetectTags ?? new List<string>()),
                DefaultBasisIds = new List<string>(source.DefaultBasisIds ?? new List<string>()),
                UiColor = source.UiColor,
                SourceKind = source.SourceKind
            };
        }

        private void AddLegalBasesToCatalog(IEnumerable<LegalBasisDefinition> legalBases, LegalBasisSource source, string sourcePath)
        {
            if (legalBases == null)
            {
                return;
            }

            foreach (var legalBasis in legalBases)
            {
                if (!NormalizeLegalBasisDefinition(legalBasis, source))
                {
                    continue;
                }

                if (legalBasesById.ContainsKey(legalBasis.Id))
                {
                    footnotesCatalogLoadWarnings.Add($"Duplicate legal base id '{legalBasis.Id}' in {sourcePath}. Entry skipped.");
                    continue;
                }

                legalBasesCatalog.Add(legalBasis);
                legalBasesById[legalBasis.Id] = legalBasis;
            }
        }

        private static bool NormalizeScopeDefinition(ExclusionScopeDefinition scope, ExclusionScopeSource source)
        {
            if (scope == null)
            {
                return false;
            }

            scope.ScopeId = string.IsNullOrWhiteSpace(scope.ScopeId) ? null : scope.ScopeId.Trim();
            if (string.IsNullOrWhiteSpace(scope.ScopeId))
            {
                return false;
            }

            scope.FriendlyName = string.IsNullOrWhiteSpace(scope.FriendlyName) ? scope.ScopeId : scope.FriendlyName.Trim();
            scope.Category = string.IsNullOrWhiteSpace(scope.Category) ? string.Empty : scope.Category.Trim();
            scope.Description = string.IsNullOrWhiteSpace(scope.Description) ? string.Empty : scope.Description.Trim();
            scope.UiColor = string.IsNullOrWhiteSpace(scope.UiColor) ? string.Empty : scope.UiColor.Trim();

            scope.AutoDetectTags = (scope.AutoDetectTags ?? new List<string>())
                .Where(tag => !string.IsNullOrWhiteSpace(tag))
                .Select(tag => tag.Trim())
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            scope.DefaultBasisIds = (scope.DefaultBasisIds ?? new List<string>())
                .Where(id => !string.IsNullOrWhiteSpace(id))
                .Select(id => id.Trim())
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            scope.SourceKind = source;

            return true;
        }

        private static bool NormalizeLegalBasisDefinition(LegalBasisDefinition legalBasis, LegalBasisSource source)
        {
            if (legalBasis == null)
            {
                return false;
            }

            legalBasis.Id = string.IsNullOrWhiteSpace(legalBasis.Id) ? null : legalBasis.Id.Trim();
            if (string.IsNullOrWhiteSpace(legalBasis.Id))
            {
                return false;
            }

            legalBasis.Title = string.IsNullOrWhiteSpace(legalBasis.Title) ? legalBasis.Id : legalBasis.Title.Trim();
            legalBasis.FullCitation = string.IsNullOrWhiteSpace(legalBasis.FullCitation) ? string.Empty : legalBasis.FullCitation.Trim();
            legalBasis.DescriptionHint = string.IsNullOrWhiteSpace(legalBasis.DescriptionHint) ? string.Empty : legalBasis.DescriptionHint.Trim();
            legalBasis.SourceKind = source;
            return true;
        }

        private static bool TryLoadCatalogFile<T>(string path, out T data, out string error)
            where T : class
        {
            data = null;
            error = string.Empty;

            if (string.IsNullOrWhiteSpace(path) || !File.Exists(path))
            {
                return false;
            }

            try
            {
                string json = File.ReadAllText(path);
                data = JsonConvert.DeserializeObject<T>(json);
                if (data == null)
                {
                    error = $"File '{path}' contains empty or invalid JSON object.";
                    return false;
                }

                return true;
            }
            catch (Exception ex)
            {
                error = $"Cannot load '{path}': {ex.Message}";
                return false;
            }
        }

        private static bool HasWriteAccessToTarget(string targetPath)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(targetPath))
                {
                    return false;
                }

                if (File.Exists(targetPath))
                {
                    using (FileStream fs = File.Open(targetPath, FileMode.Open, FileAccess.Write, FileShare.ReadWrite))
                    {
                    }
                    return true;
                }

                string directoryPath = Path.GetDirectoryName(targetPath);
                if (string.IsNullOrWhiteSpace(directoryPath))
                {
                    return false;
                }

                if (!Directory.Exists(directoryPath))
                {
                    Directory.CreateDirectory(directoryPath);
                }

                string probeFilePath = Path.Combine(directoryPath, $".write_probe_{Guid.NewGuid():N}.tmp");
                File.WriteAllText(probeFilePath, "probe");
                File.Delete(probeFilePath);
                return true;
            }
            catch
            {
                return false;
            }
        }

        private bool IsAutoResumeProjectPath(string path)
        {
            return ArePathsEqual(path, GetAutoResumeProjectFilePath());
        }

        private string GetCurrentProjectPath()
        {
            if (!string.IsNullOrWhiteSpace(lastSavedProjectName))
            {
                return lastSavedProjectName;
            }

            return inputProjectPath;
        }

        private bool HasAnyProjectContent()
        {
            return redactionBlocks.Count > 0
                || commentAnnotations.Count > 0
                || textAnnotations.Count > 0
                || rasterObjects.Count > 0
                || arrowObjects.Count > 0
                || vectorShapes.Count > 0
                || pagesToRemove.Count > 0
                || pageRotationOffsets.Count > 0
                || hasCustomSignatureSelection
                || HasLayerProjectContent();
        }

        private bool HasLayerProjectContent()
        {
            EnsureSystemLayers();

            if (!string.Equals(GetResolvedActiveLayerId(), DefaultLayerId, StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }

            List<LayerDefinition> normalizedLayers = NormalizeLayerDefinitions(documentLayers);
            if (normalizedLayers.Count != 2)
            {
                return true;
            }

            LayerDefinition workLayer = normalizedLayers.FirstOrDefault(layer => string.Equals(layer.Id, WorkLayerId, StringComparison.OrdinalIgnoreCase));
            LayerDefinition defaultLayer = normalizedLayers.FirstOrDefault(layer => string.Equals(layer.Id, DefaultLayerId, StringComparison.OrdinalIgnoreCase));
            if (workLayer == null || defaultLayer == null)
            {
                return true;
            }

            bool workMatchesDefault =
                string.Equals(workLayer.Name, GetDefaultLayerDisplayName(WorkLayerId), StringComparison.CurrentCulture) &&
                workLayer.Order == 0 &&
                workLayer.IsVisible &&
                !workLayer.IsLocked &&
                workLayer.ExcludeFromExport &&
                workLayer.IsSystem;

            bool defaultMatchesDefault =
                string.Equals(defaultLayer.Name, GetDefaultLayerDisplayName(DefaultLayerId), StringComparison.CurrentCulture) &&
                defaultLayer.Order == 1 &&
                defaultLayer.IsVisible &&
                !defaultLayer.IsLocked &&
                !defaultLayer.ExcludeFromExport &&
                defaultLayer.IsSystem;

            return !workMatchesDefault || !defaultMatchesDefault;
        }

        private static string NormalizeLayerIdValue(string layerId)
        {
            string normalized = (layerId ?? string.Empty).Trim();
            return string.IsNullOrWhiteSpace(normalized) ? DefaultLayerId : normalized;
        }

        internal static string NormalizeLayerIdForExternalUse(string layerId)
        {
            return NormalizeLayerIdValue(layerId);
        }

        private static string NormalizeLayerDisplayName(string name, string layerId)
        {
            string normalizedName = (name ?? string.Empty).Trim();
            if (!string.IsNullOrWhiteSpace(normalizedName))
            {
                return normalizedName;
            }

            return GetDefaultLayerDisplayName(layerId);
        }

        private static string GetDefaultLayerDisplayName(string layerId)
        {
            string resourceKey = string.Equals(layerId, WorkLayerId, StringComparison.OrdinalIgnoreCase)
                ? "Layer_Work_DefaultName"
                : string.Equals(layerId, DefaultLayerId, StringComparison.OrdinalIgnoreCase)
                    ? "Layer_Default_DefaultName"
                    : null;

            if (!string.IsNullOrWhiteSpace(resourceKey))
            {
                CultureInfo culture = Resources.Culture ?? CultureInfo.CurrentUICulture;
                string localized = Resources.ResourceManager.GetString(resourceKey, culture);
                if (!string.IsNullOrWhiteSpace(localized))
                {
                    return localized;
                }
            }

            return layerId;
        }

        private static LayerDefinition CreateSystemLayer(string layerId, string name, int order, bool excludeFromExport)
        {
            return new LayerDefinition
            {
                Id = layerId,
                Name = name,
                Order = order,
                IsVisible = true,
                IsLocked = false,
                ExcludeFromExport = excludeFromExport,
                IsSystem = true
            };
        }

        private void EnsureSystemLayers()
        {
            documentLayers = NormalizeLayerDefinitions(documentLayers);
            activeLayerId = NormalizeLayerIdValue(activeLayerId);
            if (!documentLayers.Any(layer => string.Equals(layer.Id, activeLayerId, StringComparison.OrdinalIgnoreCase)))
            {
                activeLayerId = DefaultLayerId;
            }
        }

        private static List<LayerDefinition> NormalizeLayerDefinitions(IEnumerable<LayerDefinition> layers)
        {
            var normalizedLayers = new List<LayerDefinition>();
            var byId = new Dictionary<string, LayerDefinition>(StringComparer.OrdinalIgnoreCase);
            LayerDefinition workCandidate = null;
            LayerDefinition defaultCandidate = null;

            if (layers != null)
            {
                foreach (LayerDefinition layer in layers.Where(layer => layer != null))
                {
                    string layerId = NormalizeLayerIdValue(layer.Id);
                    if (string.Equals(layerId, WorkLayerId, StringComparison.OrdinalIgnoreCase))
                    {
                        workCandidate ??= layer;
                        continue;
                    }

                    if (string.Equals(layerId, DefaultLayerId, StringComparison.OrdinalIgnoreCase))
                    {
                        defaultCandidate ??= layer;
                        continue;
                    }

                    if (byId.ContainsKey(layerId))
                    {
                        continue;
                    }

                    var normalized = new LayerDefinition
                    {
                        Id = layerId,
                        Name = NormalizeLayerDisplayName(layer.Name, layerId),
                        GroupName = NormalizeLayerGroupName(layer.GroupName),
                        Order = layer.Order,
                        IsVisible = layer.IsVisible,
                        IsLocked = layer.IsLocked,
                        ExcludeFromExport = layer.ExcludeFromExport,
                        IsSystem = false
                    };
                    byId[layerId] = normalized;
                    normalizedLayers.Add(normalized);
                }
            }

            normalizedLayers = normalizedLayers
                .OrderBy(layer => layer.Order)
                .ThenBy(layer => layer.Name, StringComparer.CurrentCultureIgnoreCase)
                .ToList();

            var workLayer = CreateSystemLayer(WorkLayerId, GetDefaultLayerDisplayName(WorkLayerId), 0, excludeFromExport: true);
            if (workCandidate != null)
            {
                workLayer.IsVisible = workCandidate.IsVisible;
                workLayer.IsLocked = workCandidate.IsLocked;
            }

            var orderedNonWorkLayers = new List<LayerDefinition>
            {
                new LayerDefinition
                {
                    Id = DefaultLayerId,
                    Name = NormalizeLayerDisplayName(defaultCandidate?.Name, DefaultLayerId),
                    GroupName = NormalizeLayerGroupName(defaultCandidate?.GroupName),
                    Order = defaultCandidate?.Order ?? 0,
                    IsVisible = defaultCandidate?.IsVisible ?? true,
                    IsLocked = defaultCandidate?.IsLocked ?? false,
                    ExcludeFromExport = defaultCandidate?.ExcludeFromExport ?? false,
                    IsSystem = true
                }
            };
            orderedNonWorkLayers.AddRange(normalizedLayers);

            orderedNonWorkLayers = orderedNonWorkLayers
                .OrderBy(layer => layer.Order)
                .ThenBy(layer => layer.Name, StringComparer.CurrentCultureIgnoreCase)
                .ToList();

            var result = new List<LayerDefinition> { workLayer };

            int nextOrder = 1;
            foreach (LayerDefinition layer in orderedNonWorkLayers)
            {
                layer.Order = nextOrder++;
                result.Add(layer);
            }

            return result;
        }

        private void EnsureObjectLayerAssignments()
        {
            EnsureSystemLayers();

            void RegisterLayerId(string layerId)
            {
                string normalized = NormalizeLayerIdValue(layerId);
                if (documentLayers.Any(layer => string.Equals(layer.Id, normalized, StringComparison.OrdinalIgnoreCase)))
                {
                    return;
                }

                int nextOrder = documentLayers.Count == 0 ? 0 : documentLayers.Max(layer => layer.Order) + 1;
                documentLayers.Add(new LayerDefinition
                {
                    Id = normalized,
                    Name = NormalizeLayerDisplayName(normalized, normalized),
                    Order = nextOrder,
                    IsVisible = true,
                    IsLocked = false,
                    ExcludeFromExport = false,
                    IsSystem = false
                });
            }

            foreach (RedactionBlock block in redactionBlocks ?? Enumerable.Empty<RedactionBlock>())
            {
                block.LayerId = NormalizeLayerIdValue(block.LayerId);
                RegisterLayerId(block.LayerId);
            }

            foreach (CommentAnnotation comment in commentAnnotations ?? Enumerable.Empty<CommentAnnotation>())
            {
                comment.LayerId = NormalizeLayerIdValue(comment.LayerId);
                RegisterLayerId(comment.LayerId);
            }

            foreach (TextAnnotation annotation in textAnnotations ?? Enumerable.Empty<TextAnnotation>())
            {
                annotation.LayerId = NormalizeLayerIdValue(annotation.LayerId);
                RegisterLayerId(annotation.LayerId);
            }

            foreach (RasterObject rasterObject in rasterObjects ?? Enumerable.Empty<RasterObject>())
            {
                rasterObject.LayerId = NormalizeLayerIdValue(rasterObject.LayerId);
                RegisterLayerId(rasterObject.LayerId);
            }

            foreach (ArrowObject arrowObject in arrowObjects ?? Enumerable.Empty<ArrowObject>())
            {
                arrowObject.LayerId = NormalizeLayerIdValue(arrowObject.LayerId);
                RegisterLayerId(arrowObject.LayerId);
            }

            foreach (VectorShapeObject vectorShape in vectorShapes ?? Enumerable.Empty<VectorShapeObject>())
            {
                vectorShape.LayerId = NormalizeLayerIdValue(vectorShape.LayerId);
                RegisterLayerId(vectorShape.LayerId);
            }

            documentLayers = NormalizeLayerDefinitions(documentLayers);
            activeLayerId = NormalizeLayerIdValue(activeLayerId);
            if (!documentLayers.Any(layer => string.Equals(layer.Id, activeLayerId, StringComparison.OrdinalIgnoreCase)))
            {
                activeLayerId = DefaultLayerId;
            }
        }

        private string GetResolvedActiveLayerId()
        {
            EnsureSystemLayers();
            string normalized = NormalizeLayerIdValue(activeLayerId);
            if (!documentLayers.Any(layer => string.Equals(layer.Id, normalized, StringComparison.OrdinalIgnoreCase)))
            {
                normalized = DefaultLayerId;
                activeLayerId = normalized;
            }

            return normalized;
        }

        private LayerDefinition GetLayerDefinition(string layerId)
        {
            string normalized = NormalizeLayerIdValue(layerId);
            EnsureSystemLayers();
            return documentLayers.FirstOrDefault(layer => string.Equals(layer.Id, normalized, StringComparison.OrdinalIgnoreCase));
        }

        private bool IsLayerVisible(string layerId)
        {
            LayerDefinition layer = GetLayerDefinition(layerId);
            return layer == null || layer.IsVisible;
        }

        private bool ShouldExportLayer(string layerId)
        {
            LayerDefinition layer = GetLayerDefinition(layerId);
            if (layer == null)
            {
                return true;
            }

            if (exportVisibleLayersOnly)
            {
                return layer.IsVisible;
            }

            return !layer.ExcludeFromExport;
        }

        private bool IsLayerLocked(string layerId)
        {
            LayerDefinition layer = GetLayerDefinition(layerId);
            return layer != null && layer.IsLocked;
        }

        private bool IsObjectLayerVisible(object targetObject)
        {
            return targetObject == null || IsLayerVisible(GetLayerIdForGenericObject(targetObject));
        }

        private bool IsTextAnnotationEffectivelyLocked(TextAnnotation annotation)
        {
            return annotation != null && (annotation.AnnotationIsLocked || IsLayerLocked(annotation.LayerId));
        }

        private bool IsRasterObjectEffectivelyLocked(RasterObject rasterObject)
        {
            return rasterObject != null && (rasterObject.IsLocked || IsLayerLocked(rasterObject.LayerId));
        }

        private bool IsArrowObjectEffectivelyLocked(ArrowObject arrowObject)
        {
            return arrowObject != null && (arrowObject.IsLocked || IsLayerLocked(arrowObject.LayerId));
        }

        private bool IsVectorShapeEffectivelyLocked(VectorShapeObject vectorShape)
        {
            return vectorShape != null && (vectorShape.IsLocked || IsLayerLocked(vectorShape.LayerId));
        }

        private bool IsCommentAnnotationEffectivelyLocked(CommentAnnotation comment)
        {
            return comment != null && IsLayerLocked(comment.LayerId);
        }

        private bool IsRedactionBlockEffectivelyLocked(RedactionBlock block)
        {
            return block != null && IsLayerLocked(block.LayerId);
        }

        private void ShowLockedLayerInfo()
        {
            MessageBox.Show(
                this,
                string.Format(LocalizedText("Msg_TextPositionInfo"), LocalizedText("Msg_TextAnnotation_Locked")),
                Resources.Title_Info,
                MessageBoxButtons.OK,
                MessageBoxIcon.Information);
        }

        private string GetMoveToLayerContextMenuText()
        {
            return LocalizedText("Layers_Context_MoveToLayer");
        }

        private ToolStripMenuItem BuildMoveToLayerMenuItem(string currentLayerId, Action<string> moveAction)
        {
            EnsureObjectLayerAssignments();

            var menuItem = new ToolStripMenuItem(GetMoveToLayerContextMenuText());
            foreach (LayerDefinition layer in documentLayers.OrderBy(layer => layer.Order))
            {
                string layerId = NormalizeLayerIdValue(layer.Id);
                var layerItem = new ToolStripMenuItem(layer.Name)
                {
                    Checked = !string.IsNullOrWhiteSpace(currentLayerId) &&
                              string.Equals(layerId, NormalizeLayerIdValue(currentLayerId), StringComparison.OrdinalIgnoreCase),
                    Enabled = !IsLayerLocked(layerId) &&
                              (string.IsNullOrWhiteSpace(currentLayerId) ||
                               !string.Equals(layerId, NormalizeLayerIdValue(currentLayerId), StringComparison.OrdinalIgnoreCase))
                };
                layerItem.Click += (_, __) => moveAction(layerId);
                menuItem.DropDownItems.Add(layerItem);
            }

            return menuItem;
        }

        private bool TrySetObjectLayer(object targetObject, string targetLayerId)
        {
            string normalizedLayerId = NormalizeLayerIdValue(targetLayerId);
            if (IsLayerLocked(normalizedLayerId))
            {
                return false;
            }

            switch (targetObject)
            {
                case TextAnnotation annotation:
                    if (string.Equals(NormalizeLayerIdValue(annotation.LayerId), normalizedLayerId, StringComparison.OrdinalIgnoreCase))
                    {
                        return false;
                    }

                    annotation.LayerId = normalizedLayerId;
                    return true;
                case RasterObject rasterObject:
                    if (string.Equals(NormalizeLayerIdValue(rasterObject.LayerId), normalizedLayerId, StringComparison.OrdinalIgnoreCase))
                    {
                        return false;
                    }

                    rasterObject.LayerId = normalizedLayerId;
                    return true;
                case ArrowObject arrowObject:
                    if (string.Equals(NormalizeLayerIdValue(arrowObject.LayerId), normalizedLayerId, StringComparison.OrdinalIgnoreCase))
                    {
                        return false;
                    }

                    arrowObject.LayerId = normalizedLayerId;
                    return true;
                case VectorShapeObject vectorShape:
                    if (string.Equals(NormalizeLayerIdValue(vectorShape.LayerId), normalizedLayerId, StringComparison.OrdinalIgnoreCase))
                    {
                        return false;
                    }

                    vectorShape.LayerId = normalizedLayerId;
                    return true;
                case CommentAnnotation comment:
                    if (string.Equals(NormalizeLayerIdValue(comment.LayerId), normalizedLayerId, StringComparison.OrdinalIgnoreCase))
                    {
                        return false;
                    }

                    comment.LayerId = normalizedLayerId;
                    return true;
                case RedactionBlock block:
                    if (string.Equals(NormalizeLayerIdValue(block.LayerId), normalizedLayerId, StringComparison.OrdinalIgnoreCase))
                    {
                        return false;
                    }

                    block.LayerId = normalizedLayerId;
                    return true;
                default:
                    return false;
            }
        }

        private string GetLayerIdForGenericObject(object targetObject)
        {
            switch (targetObject)
            {
                case TextAnnotation annotation:
                    return NormalizeLayerIdValue(annotation.LayerId);
                case RasterObject rasterObject:
                    return NormalizeLayerIdValue(rasterObject.LayerId);
                case ArrowObject arrowObject:
                    return NormalizeLayerIdValue(arrowObject.LayerId);
                case VectorShapeObject vectorShape:
                    return NormalizeLayerIdValue(vectorShape.LayerId);
                case CommentAnnotation comment:
                    return NormalizeLayerIdValue(comment.LayerId);
                case RedactionBlock block:
                    return NormalizeLayerIdValue(block.LayerId);
                default:
                    return DefaultLayerId;
            }
        }

        private void RefreshAfterLayerAssignmentChange()
        {
            PruneInvisibleLayerInteractionState();
            RebuildPageStatusesFromCurrentModel();
            ShowRedactPreview();
            UpdateCurrentPageObjectsMarker();
            pagesListView?.Invalidate();
            thumbnailsListView?.Invalidate();
            pdfViewer?.Invalidate();
            projectWasChangedAfterLastSave = true;
            SyncProjectChangedFlagWithStateSignature();
        }

        private void MoveObjectToLayerFromContext(object targetObject, string targetLayerId)
        {
            if (!TrySetObjectLayer(targetObject, targetLayerId))
            {
                return;
            }

            RefreshAfterLayerAssignmentChange();
        }

        private void MoveSelectedObjectsToLayerFromContext(IEnumerable<object> objects, string targetLayerId)
        {
            bool changed = false;
            foreach (object targetObject in objects ?? Enumerable.Empty<object>())
            {
                changed = TrySetObjectLayer(targetObject, targetLayerId) || changed;
            }

            if (!changed)
            {
                return;
            }

            RefreshAfterLayerAssignmentChange();
        }

        private ProjectData BuildCurrentProjectDataSnapshot(bool includeViewState)
        {
            float? zoomFactor = null;
            int? scrollX = null;
            int? scrollY = null;
            int? pagesListTopPage = null;
            int? thumbnailsTopPage = null;

            if (includeViewState)
            {
                CaptureCurrentViewState(out float zf, out int sx, out int sy);
                CaptureRightPanelsViewState(out pagesListTopPage, out thumbnailsTopPage);
                zoomFactor = zf > 0 ? zf : (float?)null;
                scrollX = sx;
                scrollY = sy;
            }

            foreach (RedactionBlock block in redactionBlocks ?? Enumerable.Empty<RedactionBlock>())
            {
                StampRedactionBlockCreated(block);
            }

            foreach (TextAnnotation annotation in textAnnotations ?? Enumerable.Empty<TextAnnotation>())
            {
                StampTextAnnotationCreated(annotation);
            }

            EnsureObjectLayerAssignments();

            return new ProjectData
            {
                RedactionBlocks = redactionBlocks ?? new List<RedactionBlock>(),
                CommentAnnotations = commentAnnotations ?? new List<CommentAnnotation>(),
                PagesToRemove = pagesToRemove ?? new HashSet<int>(),
                TextAnnotations = textAnnotations ?? new List<TextAnnotation>(),
                RasterObjects = rasterObjects ?? new List<RasterObject>(),
                ArrowObjects = arrowObjects ?? new List<ArrowObject>(),
                VectorShapes = vectorShapes ?? new List<VectorShapeObject>(),
                Layers = documentLayers.Select(layer => layer.Clone()).ToList(),
                ActiveLayerId = activeLayerId,
                ObjectLayers = BuildProjectObjectLayersSnapshot(),
                PageRotationOffsets = pageRotationOffsets == null
                    ? new Dictionary<int, int>()
                    : new Dictionary<int, int>(pageRotationOffsets),
                FilePath = inputPdfPath,
                CurrentPage = Math.Max(1, Math.Min(currentPage, Math.Max(1, numPages))),
                ZoomFactor = zoomFactor,
                ScrollX = scrollX,
                ScrollY = scrollY,
                PagesListTopPage = pagesListTopPage,
                ThumbnailsTopPage = thumbnailsTopPage,
                SignaturesMode = GetSignatureModeForProject(),
                SignaturesToRemove = hasCustomSignatureSelection ? new List<string>(signaturesToRemove) : null,
                AutoFootnotesEnabled = autoFootnotesEnabled,
                ExclusionAuthority = exclusionAuthorityName,
                ExportVisibleLayersOnly = exportVisibleLayersOnly
            };
        }

        private string BuildProjectStateSignature()
        {
            var snapshot = BuildCurrentProjectDataSnapshot(includeViewState: false);
            snapshot.CurrentPage = 0;
            snapshot.ZoomFactor = null;
            snapshot.ScrollX = null;
            snapshot.ScrollY = null;
            snapshot.PagesListTopPage = null;
            snapshot.ThumbnailsTopPage = null;
            snapshot.FilePath = string.Empty;
            return JsonConvert.SerializeObject(snapshot, Formatting.None);
        }

        private void SyncProjectChangedFlagWithStateSignature()
        {
            if (suppressUndoRedoCapture)
            {
                return;
            }

            if (string.IsNullOrEmpty(savedProjectStateSignature))
            {
                projectWasChangedAfterLastSave = HasAnyProjectContent();
            }
            else
            {
                projectWasChangedAfterLastSave = !string.Equals(
                    BuildProjectStateSignature(),
                    savedProjectStateSignature,
                    StringComparison.Ordinal);
            }

            saveProjectButton.Enabled = projectWasChangedAfterLastSave;
            saveProjectMenuItem.Enabled = projectWasChangedAfterLastSave;
        }

        private void ResetUndoRedoHistory(bool resetSavedStateSignature = false)
        {
            pendingUndoCapture = null;
            undoHistory.Clear();
            redoHistory.Clear();
            if (resetSavedStateSignature)
            {
                savedProjectStateSignature = BuildProjectStateSignature();
            }
        }

        private void MarkCurrentStateAsSavedBaseline()
        {
            savedProjectStateSignature = BuildProjectStateSignature();
            SyncProjectChangedFlagWithStateSignature();
        }

        private void BeginUndoCapture(string actionName)
        {
            if (suppressUndoRedoCapture || pdf == null || numPages <= 0)
            {
                return;
            }

            if (pendingUndoCapture != null)
            {
                return;
            }

            pendingUndoCapture = new UndoCaptureContext
            {
                ActionName = string.IsNullOrWhiteSpace(actionName) ? "Edit" : actionName.Trim(),
                BeforeStateJson = BuildProjectStateSignature()
            };
        }

        private void CancelUndoCapture()
        {
            pendingUndoCapture = null;
        }

        private void CommitUndoCapture()
        {
            if (suppressUndoRedoCapture || pendingUndoCapture == null)
            {
                return;
            }

            string afterState = BuildProjectStateSignature();
            if (string.Equals(pendingUndoCapture.BeforeStateJson, afterState, StringComparison.Ordinal))
            {
                pendingUndoCapture = null;
                return;
            }

            undoHistory.Push(new UndoHistoryEntry
            {
                ActionName = pendingUndoCapture.ActionName,
                BeforeStateJson = pendingUndoCapture.BeforeStateJson,
                AfterStateJson = afterState
            });

            if (undoHistory.Count > UndoHistoryLimit)
            {
                List<UndoHistoryEntry> newestEntries = undoHistory
                    .Take(UndoHistoryLimit)
                    .Reverse()
                    .ToList();
                undoHistory.Clear();
                foreach (UndoHistoryEntry entry in newestEntries)
                {
                    undoHistory.Push(entry);
                }
            }

            redoHistory.Clear();
            pendingUndoCapture = null;
            SyncProjectChangedFlagWithStateSignature();
        }

        private bool UndoLastAction()
        {
            if (undoHistory.Count == 0 || pdf == null || numPages <= 0)
            {
                return false;
            }

            CancelUndoCapture();
            UndoHistoryEntry entry = undoHistory.Pop();
            if (entry == null || string.IsNullOrWhiteSpace(entry.BeforeStateJson))
            {
                return false;
            }

            if (!TryApplyProjectStateFromSignature(entry.BeforeStateJson))
            {
                return false;
            }

            redoHistory.Push(entry);
            SyncProjectChangedFlagWithStateSignature();
            return true;
        }

        private bool RedoLastAction()
        {
            if (redoHistory.Count == 0 || pdf == null || numPages <= 0)
            {
                return false;
            }

            CancelUndoCapture();
            UndoHistoryEntry entry = redoHistory.Pop();
            if (entry == null || string.IsNullOrWhiteSpace(entry.AfterStateJson))
            {
                return false;
            }

            if (!TryApplyProjectStateFromSignature(entry.AfterStateJson))
            {
                return false;
            }

            undoHistory.Push(entry);
            SyncProjectChangedFlagWithStateSignature();
            return true;
        }

        private bool TryApplyProjectStateFromSignature(string stateJson)
        {
            if (string.IsNullOrWhiteSpace(stateJson) || pdf == null || numPages <= 0)
            {
                return false;
            }

            ProjectData snapshot;
            try
            {
                snapshot = JsonConvert.DeserializeObject<ProjectData>(stateJson);
            }
            catch (Exception ex)
            {
                LogDebug("Undo state deserialize failed: " + ex.Message);
                return false;
            }

            if (snapshot == null)
            {
                return false;
            }

            GetThumbnailRefreshPlan(snapshot, out HashSet<int> thumbnailPagesToRefresh, out HashSet<int> thumbnailPagesToRegenerate);

            suppressUndoRedoCapture = true;
            try
            {
                ApplyProjectSnapshotToCurrentDocument(snapshot);
            }
            finally
            {
                suppressUndoRedoCapture = false;
            }

            foreach (int page in thumbnailPagesToRefresh.OrderBy(p => p))
            {
                InvalidateThumbnailPage(page, thumbnailPagesToRegenerate.Contains(page));
            }

            return true;
        }

        private HashSet<int> CollectThumbnailRelevantPages(ProjectData projectData)
        {
            var pages = new HashSet<int>();
            if (projectData == null)
            {
                return pages;
            }

            void AddPage(int page)
            {
                if (page >= 1 && page <= numPages)
                {
                    pages.Add(page);
                }
            }

            foreach (RedactionBlock block in projectData.RedactionBlocks ?? Enumerable.Empty<RedactionBlock>())
            {
                if (block != null)
                {
                    AddPage(block.PageNumber);
                }
            }

            foreach (CommentAnnotation comment in projectData.CommentAnnotations ?? Enumerable.Empty<CommentAnnotation>())
            {
                if (comment != null)
                {
                    AddPage(comment.PageNumber);
                }
            }

            foreach (TextAnnotation annotation in projectData.TextAnnotations ?? Enumerable.Empty<TextAnnotation>())
            {
                if (annotation != null)
                {
                    AddPage(annotation.PageNumber);
                }
            }

            foreach (RasterObject raster in projectData.RasterObjects ?? Enumerable.Empty<RasterObject>())
            {
                if (raster != null)
                {
                    AddPage(raster.PageNumber);
                }
            }

            foreach (ArrowObject arrow in projectData.ArrowObjects ?? Enumerable.Empty<ArrowObject>())
            {
                if (arrow != null)
                {
                    AddPage(arrow.PageNumber);
                }
            }

            foreach (VectorShapeObject vector in projectData.VectorShapes ?? Enumerable.Empty<VectorShapeObject>())
            {
                if (vector != null)
                {
                    AddPage(vector.PageNumber);
                }
            }

            foreach (int page in projectData.PagesToRemove ?? Enumerable.Empty<int>())
            {
                AddPage(page);
            }

            foreach (int page in (projectData.PageRotationOffsets ?? new Dictionary<int, int>()).Keys)
            {
                AddPage(page);
            }

            AddPage(projectData.CurrentPage);
            return pages;
        }

        private void GetThumbnailRefreshPlan(ProjectData targetSnapshot, out HashSet<int> pagesToRefresh, out HashSet<int> pagesToRegenerateBaseImage)
        {
            ProjectData currentSnapshot = BuildCurrentProjectDataSnapshot(includeViewState: false);
            pagesToRefresh = CollectThumbnailRelevantPages(currentSnapshot);
            pagesToRefresh.UnionWith(CollectThumbnailRelevantPages(targetSnapshot));

            pagesToRegenerateBaseImage = new HashSet<int>();
            Dictionary<int, int> currentRotations = currentSnapshot.PageRotationOffsets ?? new Dictionary<int, int>();
            Dictionary<int, int> targetRotations = targetSnapshot?.PageRotationOffsets ?? new Dictionary<int, int>();

            foreach (int page in currentRotations.Keys.Union(targetRotations.Keys))
            {
                int currentRotation = currentRotations.TryGetValue(page, out int currentValue) ? NormalizeRotation(currentValue) : 0;
                int targetRotation = targetRotations.TryGetValue(page, out int targetValue) ? NormalizeRotation(targetValue) : 0;
                if (currentRotation != targetRotation && page >= 1 && page <= numPages)
                {
                    pagesToRegenerateBaseImage.Add(page);
                    pagesToRefresh.Add(page);
                }
            }
        }

        private void ApplyProjectSnapshotToCurrentDocument(ProjectData projectData)
        {
            if (projectData == null || pdf == null || numPages <= 0)
            {
                return;
            }

            List<RedactionBlock> blocks = (projectData.RedactionBlocks ?? new List<RedactionBlock>())
                .Where(block => block != null && block.PageNumber >= 1 && block.PageNumber <= numPages)
                .ToList();
            foreach (RedactionBlock block in blocks)
            {
                NormalizeRedactionBlockMetadata(block);
                EnsureRedactionBlockTimestamps(block);
            }

            List<CommentAnnotation> comments = (projectData.CommentAnnotations ?? new List<CommentAnnotation>())
                .Where(comment => comment != null && comment.PageNumber >= 1 && comment.PageNumber <= numPages)
                .ToList();
            foreach (CommentAnnotation comment in comments)
            {
                NormalizeCommentAnnotation(comment);
            }

            List<TextAnnotation> texts = (projectData.TextAnnotations ?? new List<TextAnnotation>())
                .Where(annotation => annotation != null && annotation.PageNumber >= 1 && annotation.PageNumber <= numPages)
                .ToList();
            foreach (TextAnnotation annotation in texts)
            {
                EnsureTextAnnotationTimestamps(annotation);
            }

            List<RasterObject> rasters = (projectData.RasterObjects ?? new List<RasterObject>())
                .Where(obj => obj != null && obj.PageNumber >= 1 && obj.PageNumber <= numPages)
                .ToList();
            foreach (RasterObject raster in rasters)
            {
                raster.Rotation = NormalizeRotation(raster.Rotation);
                raster.Opacity = NormalizeOpacity(raster.Opacity);
                GetResolvedRasterInitialBounds(raster);
                ConstrainRasterObjectToPage(raster);
            }

            List<ArrowObject> arrows = (projectData.ArrowObjects ?? new List<ArrowObject>())
                .Where(obj => obj != null && obj.PageNumber >= 1 && obj.PageNumber <= numPages)
                .ToList();
            foreach (ArrowObject arrow in arrows)
            {
                if (string.IsNullOrWhiteSpace(arrow.Id))
                {
                    arrow.Id = Guid.NewGuid().ToString("N");
                }

                if (!IsArrowColorValid(arrow))
                {
                    arrow.LineColorArgb = DefaultArrowColor.ToArgb();
                }

                arrow.Thickness = NormalizeArrowThickness(arrow.Thickness);
                arrow.BorderWidth = NormalizeArrowBorderWidth(arrow.BorderWidth);
                arrow.HeadLength = NormalizeArrowHeadLength(arrow.HeadLength);
                arrow.HeadWidth = NormalizeArrowHeadWidth(arrow.HeadWidth);
                ConstrainArrowToPage(arrow);
            }

            List<VectorShapeObject> vectors = (projectData.VectorShapes ?? new List<VectorShapeObject>())
                .Where(obj => obj != null && obj.PageNumber >= 1 && obj.PageNumber <= numPages)
                .ToList();
            foreach (VectorShapeObject vector in vectors)
            {
                NormalizeVectorShape(vector);
            }

            redactionBlocks = blocks;
            commentAnnotations = comments;
            textAnnotations = texts;
            rasterObjects = rasters;
            arrowObjects = arrows;
            vectorShapes = vectors;

            pagesToRemove = new HashSet<int>(
                (projectData.PagesToRemove ?? new HashSet<int>())
                    .Where(page => page >= 1 && page <= numPages));

            pageRotationOffsets = (projectData.PageRotationOffsets ?? new Dictionary<int, int>())
                .Where(kvp => kvp.Key >= 1 && kvp.Key <= numPages)
                .Select(kvp => new KeyValuePair<int, int>(kvp.Key, NormalizeRotation(kvp.Value)))
                .Where(kvp => kvp.Value != 0)
                .ToDictionary(kvp => kvp.Key, kvp => kvp.Value);

            hasCustomSignatureSelection = projectData.SignaturesToRemove != null;
            signaturesToRemove = projectData.SignaturesToRemove ?? new List<string>();
            SyncSignatureSelectionWithAvailableSignatures();
            UpdateSignatureSelectionMenuState();
            ApplySignatureModeFromProject(projectData.SignaturesMode);

            autoFootnotesEnabled = projectData.AutoFootnotesEnabled ?? Properties.Settings.Default.AutoFootnotesEnabled;
            if (!string.IsNullOrWhiteSpace(projectData.ExclusionAuthority))
            {
                exclusionAuthorityName = projectData.ExclusionAuthority.Trim();
            }
            ApplyAutomaticFootnotesMenuState();
            ApplyAddObjectsByPageRotationMenuState();

            ClearGroupSelection();
            selectedTextAnnotation = null;
            selectedRasterObject = null;
            selectedArrowObject = null;
            selectedVectorShape = null;
            ResetGroupMoveState();
            ResetTextRotationInteractionState();
            ResetRasterInteractionState();
            ResetArrowInteractionState();
            ResetVectorInteractionState();
            ResetCommentNoteMoveState();
            commentNoteRectsDoc.Clear();
            ClearCommentPreviewRects();
            isDrawing = false;
            isMarkerCtrlBoxMode = false;
            currentSelection = RectangleF.Empty;

            currentPage = Math.Max(1, Math.Min(projectData.CurrentPage > 0 ? projectData.CurrentPage : currentPage, numPages));

            RebuildPageStatusesFromCurrentModel();
            ReloadRefreshCurrentPage();
            UpdateCurrentPageObjectsMarker();
            UpdateSelectionNavigationButtons();
            UpdateSearchNavigationButtons();
            UpdateNavigationButtons(currentPage);
            BeginInvoke(new MethodInvoker(() =>
            {
                RestoreRightPanelsViewState(projectData.PagesListTopPage, projectData.ThumbnailsTopPage);
            }));
            renderTimer.Stop();
            renderTimer.Start();
            pdfViewer.Invalidate();
        }

        private void RebuildPageStatusesFromCurrentModel()
        {
            if (numPages <= 0)
            {
                return;
            }

            if (allPageStatuses == null)
            {
                allPageStatuses = new List<PageItemStatus>();
            }

            while (allPageStatuses.Count < numPages)
            {
                allPageStatuses.Add(new PageItemStatus { PageNumber = allPageStatuses.Count + 1 });
            }

            if (allPageStatuses.Count > numPages)
            {
                allPageStatuses.RemoveRange(numPages, allPageStatuses.Count - numPages);
            }

            HashSet<int> pagesWithSelections = new HashSet<int>(
                redactionBlocks
                    .Where(block => block != null && block.PageNumber >= 1 && block.PageNumber <= numPages)
                    .Select(block => block.PageNumber));
            HashSet<int> pagesWithObjects = new HashSet<int>(
                textAnnotations.Where(annotation => annotation != null).Select(annotation => annotation.PageNumber)
                .Concat(commentAnnotations.Where(comment => comment != null).Select(comment => comment.PageNumber))
                .Concat(rasterObjects.Where(obj => obj != null).Select(obj => obj.PageNumber))
                .Concat(arrowObjects.Where(obj => obj != null).Select(obj => obj.PageNumber))
                .Concat(vectorShapes.Where(obj => obj != null).Select(obj => obj.PageNumber))
                .Where(page => page >= 1 && page <= numPages));
            HashSet<int> pagesWithSearch = new HashSet<int>(
                searchLocations
                    .Where(location => location != null && location.PageNumber >= 1 && location.PageNumber <= numPages)
                    .Select(location => location.PageNumber));
            HashSet<int> pagesWithRotation = new HashSet<int>(pageRotationOffsets.Keys.Where(page => page >= 1 && page <= numPages));

            for (int page = 1; page <= numPages; page++)
            {
                PageItemStatus status = allPageStatuses[page - 1];
                status.PageNumber = page;
                status.MarkedForDeletion = pagesToRemove.Contains(page);
                status.HasSearchResults = pagesWithSearch.Contains(page);
                status.HasSelections = pagesWithSelections.Contains(page);
                status.HasObjects = pagesWithObjects.Contains(page);
                status.HasRotation = pagesWithRotation.Contains(page);
            }

            string selectedFilter = (string)filterComboBox.SelectedItem ?? allComboItem;
            if (string.Equals(selectedFilter, allComboItem, StringComparison.Ordinal))
            {
                int limit = Math.Min(pagesListView.Items.Count, numPages);
                for (int index = 0; index < limit; index++)
                {
                    int page = index + 1;
                    PageItemStatus status = allPageStatuses[index];
                    ListViewItem pageItem = pagesListView.Items[index];
                    UpdateItemTag(pageItem, page, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                }
            }
            else
            {
                ApplyFilter(selectedFilter);
            }

            if ((string)filterComboBox.SelectedItem == allComboItem)
            {
                if (currentPage >= 1 && currentPage <= pagesListView.Items.Count)
                {
                    pagesListView.SelectedItems.Clear();
                    pagesListView.Items[currentPage - 1].Selected = true;
                    pagesListView.Items[currentPage - 1].EnsureVisible();
                }
            }
            else
            {
                ListViewItem currentItem = FindListViewItemByPageNumber(currentPage);
                if (currentItem != null)
                {
                    pagesListView.SelectedItems.Clear();
                    currentItem.Selected = true;
                    currentItem.EnsureVisible();
                }
            }

            SelectThumbnailItemForCurrentPage(ensureVisible: true);
        }

        private bool TrySaveAutoResumeProjectSnapshot(out string savedPath)
        {
            savedPath = string.Empty;
            if (pdf == null || numPages <= 0 || string.IsNullOrWhiteSpace(inputPdfPath))
            {
                return false;
            }

            if (!string.IsNullOrWhiteSpace(lastSavedProjectName) || !string.IsNullOrWhiteSpace(inputProjectPath))
            {
                return false;
            }

            if (!HasAnyProjectContent())
            {
                return false;
            }

            try
            {
                string autoPath = GetAutoResumeProjectFilePath();
                string dir = Path.GetDirectoryName(autoPath);
                if (!string.IsNullOrWhiteSpace(dir))
                {
                    Directory.CreateDirectory(dir);
                }

                var projectData = BuildCurrentProjectDataSnapshot(includeViewState: true);
                string json = JsonConvert.SerializeObject(projectData, Formatting.Indented);
                File.WriteAllText(autoPath, json);
                savedPath = autoPath;
                return true;
            }
            catch (Exception ex)
            {
                LogDebug("Auto resume project save failed: " + ex.Message);
                return false;
            }
        }

        private void CaptureCurrentViewState(out float zoomFactor, out int scrollX, out int scrollY)
        {
            zoomFactor = scaleFactor;
            scrollX = 0;
            scrollY = 0;

            ZoomPanel panel = GetZoomPanel();
            if (panel is ZoomPanel)
            {
                scrollX = panel.HorizontalScroll.Value;
                scrollY = panel.VerticalScroll.Value;
            }
        }

        private void CaptureRightPanelsViewState(out int? pagesListTopPage, out int? thumbnailsTopPage)
        {
            pagesListTopPage = GetTopVisiblePageNumber(pagesListView);
            thumbnailsTopPage = GetTopVisiblePageNumber(thumbnailsListView);
        }

        private int? GetTopVisiblePageNumber(ListView listView)
        {
            if (listView == null || listView.IsDisposed || listView.Items.Count == 0 || !listView.IsHandleCreated)
            {
                return null;
            }

            try
            {
                ListViewItem topItem = listView.TopItem;
                int? topPage = GetPageNumberFromListViewItem(topItem);
                if (topPage.HasValue)
                {
                    return topPage.Value;
                }
            }
            catch
            {
                // Fallback to bounds-based detection.
            }

            try
            {
                DrawingRectangle client = listView.ClientRectangle;
                int bestTop = int.MaxValue;
                int bestLeft = int.MaxValue;
                int? bestPage = null;

                for (int i = 0; i < listView.Items.Count; i++)
                {
                    DrawingRectangle itemRect = listView.GetItemRect(i, ItemBoundsPortion.Entire);
                    if (itemRect.Bottom <= client.Top || itemRect.Top >= client.Bottom)
                    {
                        continue;
                    }

                    int? page = GetPageNumberFromListViewItem(listView.Items[i]);
                    if (!page.HasValue)
                    {
                        continue;
                    }

                    if (itemRect.Top < bestTop || (itemRect.Top == bestTop && itemRect.Left < bestLeft))
                    {
                        bestTop = itemRect.Top;
                        bestLeft = itemRect.Left;
                        bestPage = page.Value;
                    }
                }

                return bestPage;
            }
            catch
            {
                return null;
            }
        }

        private static int? GetPageNumberFromListViewItem(ListViewItem item)
        {
            if (item == null)
            {
                return null;
            }

            if (item.Tag is PageItemStatus status)
            {
                return status.PageNumber;
            }

            if (item.Tag is int page && page > 0)
            {
                return page;
            }

            return null;
        }

        private void RestoreRightPanelsViewState(int? pagesListTopPage, int? thumbnailsTopPage)
        {
            if (pagesListTopPage.HasValue)
            {
                ListViewItem pageItem = FindListViewItemByPageNumber(pagesListTopPage.Value);
                RestoreListViewTopItem(pagesListView, pageItem);
            }

            if (thumbnailsTopPage.HasValue)
            {
                ListViewItem thumbnailItem = FindThumbnailListItemByPageNumber(thumbnailsTopPage.Value);
                RestoreListViewTopItem(thumbnailsListView, thumbnailItem);
            }
        }

        private static void RestoreListViewTopItem(ListView listView, ListViewItem item)
        {
            if (listView == null || listView.IsDisposed || item == null || item.ListView != listView || !listView.IsHandleCreated)
            {
                return;
            }

            try
            {
                item.EnsureVisible();

                bool topItemApplied = false;
                try
                {
                    listView.TopItem = item;
                    topItemApplied = true;
                }
                catch
                {
                    // Some view modes do not support setting TopItem directly.
                }

                if (!topItemApplied)
                {
                    TryAlignListViewItemToTop(listView, item);
                }
            }
            catch
            {
                // Ignore scroll restoration errors.
            }
        }

        private static void TryAlignListViewItemToTop(ListView listView, ListViewItem item)
        {
            if (listView == null || item == null || listView.Items.Count == 0 || !listView.IsHandleCreated)
            {
                return;
            }

            int itemIndex = item.Index;
            if (itemIndex < 0 || itemIndex >= listView.Items.Count)
            {
                return;
            }

            DrawingRectangle client = listView.ClientRectangle;
            DrawingRectangle beforeRect = listView.GetItemRect(itemIndex, ItemBoundsPortion.Entire);
            int beforeDelta = beforeRect.Top - client.Top;
            if (beforeDelta == 0)
            {
                return;
            }

            SendMessage(listView.Handle, LVM_SCROLL, IntPtr.Zero, (IntPtr)beforeDelta);

            DrawingRectangle afterRect = listView.GetItemRect(itemIndex, ItemBoundsPortion.Entire);
            int afterDelta = afterRect.Top - client.Top;

            if (Math.Abs(afterDelta) > Math.Abs(beforeDelta))
            {
                // Direction was opposite on this control/view mode - retry with the inverted value.
                SendMessage(listView.Handle, LVM_SCROLL, IntPtr.Zero, (IntPtr)(-beforeDelta));
                SendMessage(listView.Handle, LVM_SCROLL, IntPtr.Zero, (IntPtr)(-beforeDelta));
            }
        }

        private void QueuePendingViewScrollRestore(int scrollX, int scrollY)
        {
            pendingViewScrollX = Math.Max(0, scrollX);
            pendingViewScrollY = Math.Max(0, scrollY);
        }

        private void ApplyPendingViewScrollRestore()
        {
            if (!pendingViewScrollX.HasValue && !pendingViewScrollY.HasValue)
            {
                return;
            }

            ZoomPanel panel = GetZoomPanel();
            if (!(panel is ZoomPanel))
            {
                pendingViewScrollX = null;
                pendingViewScrollY = null;
                return;
            }

            int targetX = pendingViewScrollX ?? panel.HorizontalScroll.Minimum;
            int targetY = pendingViewScrollY ?? panel.VerticalScroll.Minimum;

            targetX = ClampScrollValue(targetX, panel.HorizontalScroll.Minimum, GetScrollMaximum(panel.HorizontalScroll));
            targetY = ClampScrollValue(targetY, panel.VerticalScroll.Minimum, GetScrollMaximum(panel.VerticalScroll));

            panel.AutoScrollPosition = new Point(targetX, targetY);
            pendingViewScrollX = null;
            pendingViewScrollY = null;
        }

        private void PersistResumeState()
        {
            if (pdf == null || numPages <= 0 || string.IsNullOrWhiteSpace(inputPdfPath))
            {
                return;
            }

            try
            {
                CaptureCurrentViewState(out float zoomFactor, out int scrollX, out int scrollY);
                var state = new ResumeState
                {
                    PdfPath = inputPdfPath,
                    ProjectPath = GetCurrentProjectPath(),
                    CurrentPage = Math.Max(1, Math.Min(currentPage, numPages)),
                    ZoomFactor = zoomFactor > 0 ? zoomFactor : (float?)null,
                    ScrollX = scrollX,
                    ScrollY = scrollY
                };

                string stateFilePath = GetResumeStateFilePath();
                string stateDirectory = Path.GetDirectoryName(stateFilePath);
                if (!string.IsNullOrWhiteSpace(stateDirectory))
                {
                    Directory.CreateDirectory(stateDirectory);
                }

                string json = JsonConvert.SerializeObject(state, Formatting.Indented);
                File.WriteAllText(stateFilePath, json);
                LogDebug($"Resume state saved pdf={state.PdfPath} project={state.ProjectPath} page={state.CurrentPage} zoom={(state.ZoomFactor.HasValue ? state.ZoomFactor.Value.ToString(CultureInfo.InvariantCulture) : "-")} scroll={state.ScrollX},{state.ScrollY}");
            }
            catch
            {
                // Keep close flow even if resume-state update fails.
            }
        }

        private static ResumeState LoadResumeState()
        {
            try
            {
                string stateFilePath = GetResumeStateFilePath();
                if (!File.Exists(stateFilePath))
                {
                    return null;
                }

                string json = File.ReadAllText(stateFilePath);
                return JsonConvert.DeserializeObject<ResumeState>(json);
            }
            catch
            {
                return null;
            }
        }

        private void SelectPageInListView(int pageNumber)
        {
            if (pageNumber < 1 || pageNumber > numPages)
            {
                return;
            }

            if ((string)filterComboBox.SelectedItem == allComboItem)
            {
                if (pageNumber - 1 < pagesListView.Items.Count)
                {
                    pagesListView.Items[pageNumber - 1].Selected = true;
                    pagesListView.Items[pageNumber - 1].EnsureVisible();
                }
            }
            else
            {
                ListViewItem currentItem = FindListViewItemByPageNumber(pageNumber);
                if (currentItem != null)
                {
                    currentItem.Selected = true;
                    currentItem.EnsureVisible();
                }
            }
        }

        private void RestoreViewFromResumeStateIfMatches(ResumeState state)
        {
            if (state == null || pdf == null || numPages <= 0 || string.IsNullOrWhiteSpace(inputPdfPath))
            {
                return;
            }

            string currentProjectPath = GetCurrentProjectPath();
            bool projectMatch = !string.IsNullOrWhiteSpace(currentProjectPath) && ArePathsEqual(state.ProjectPath, currentProjectPath);
            bool pdfMatch = ArePathsEqual(state.PdfPath, inputPdfPath);
            if (!projectMatch && !pdfMatch)
            {
                LogDebug($"Resume state skipped (path mismatch) statePdf={state.PdfPath} stateProject={state.ProjectPath} currentPdf={inputPdfPath} currentProject={currentProjectPath}");
                return;
            }

            if (state.CurrentPage > 0)
            {
                currentPage = Math.Max(1, Math.Min(state.CurrentPage, numPages));
            }

            if (state.ZoomFactor.HasValue && state.ZoomFactor.Value > 0)
            {
                scaleFactor = state.ZoomFactor.Value;
                pendingScaleFactor = scaleFactor;
                minScaleButton = false;
                maxScaleButton = false;
            }

            QueuePendingViewScrollRestore(state.ScrollX, state.ScrollY);
            SelectPageInListView(currentPage);
            ReloadRefreshCurrentPage();
            UpdateNavigationButtons(currentPage);
            LogDebug($"Resume state applied page={currentPage} zoom={scaleFactor.ToString(CultureInfo.InvariantCulture)} scroll={state.ScrollX},{state.ScrollY}");
        }

        private bool TryBeginViewportPan(MouseButtons button)
        {
            ZoomPanel panel = GetZoomPanel();
            if (!(panel is ZoomPanel))
            {
                return false;
            }

            bool canPanX = panel.HorizontalScroll.Visible && GetScrollMaximum(panel.HorizontalScroll) > panel.HorizontalScroll.Minimum;
            bool canPanY = panel.VerticalScroll.Visible && GetScrollMaximum(panel.VerticalScroll) > panel.VerticalScroll.Minimum;
            if (!canPanX && !canPanY)
            {
                return false;
            }

            if (button == MouseButtons.Middle)
            {
                isMiddleMousePanning = true;
            }
            else if (button == MouseButtons.Right)
            {
                isRightMousePanning = true;
            }
            else
            {
                return false;
            }

            middlePanStartCursorScreen = Cursor.Position;
            middlePanStartScrollX = panel.HorizontalScroll.Value;
            middlePanStartScrollY = panel.VerticalScroll.Value;
            middlePanPreviousCursor = this.Cursor;
            this.Cursor = Cursors.SizeAll;
            pdfViewer.Capture = true;
            return true;
        }

        private void UpdateViewportPan()
        {
            if (!IsViewportPanningActive())
            {
                return;
            }

            bool middlePressed = (Control.MouseButtons & MouseButtons.Middle) == MouseButtons.Middle;
            bool rightPressed = (Control.MouseButtons & MouseButtons.Right) == MouseButtons.Right;
            if ((isMiddleMousePanning && !middlePressed) || (isRightMousePanning && !rightPressed))
            {
                EndViewportPan();
                return;
            }

            ZoomPanel panel = GetZoomPanel();
            if (!(panel is ZoomPanel))
            {
                EndViewportPan();
                return;
            }

            Point cursorScreen = Cursor.Position;
            int deltaX = cursorScreen.X - middlePanStartCursorScreen.X;
            int deltaY = cursorScreen.Y - middlePanStartCursorScreen.Y;

            int targetX = ClampScrollValue(
                middlePanStartScrollX - deltaX,
                panel.HorizontalScroll.Minimum,
                GetScrollMaximum(panel.HorizontalScroll));
            int targetY = ClampScrollValue(
                middlePanStartScrollY - deltaY,
                panel.VerticalScroll.Minimum,
                GetScrollMaximum(panel.VerticalScroll));

            bool horizontalChanged = panel.HorizontalScroll.Visible && panel.HorizontalScroll.Value != targetX;
            bool verticalChanged = panel.VerticalScroll.Visible && panel.VerticalScroll.Value != targetY;
            if (!horizontalChanged && !verticalChanged)
            {
                return;
            }

            panel.AutoScrollPosition = new Point(targetX, targetY);
            panel.Refresh();
        }

        private void EndViewportPan()
        {
            if (!IsViewportPanningActive())
            {
                return;
            }

            isMiddleMousePanning = false;
            isRightMousePanning = false;
            pdfViewer.Capture = false;
            this.Cursor = middlePanPreviousCursor ?? Cursors.Default;
            middlePanPreviousCursor = null;
        }

        private void PdfViewer_MouseCaptureChanged(object sender, EventArgs e)
        {
            if (!IsViewportPanningActive())
            {
                return;
            }

            bool middlePressed = (Control.MouseButtons & MouseButtons.Middle) == MouseButtons.Middle;
            bool rightPressed = (Control.MouseButtons & MouseButtons.Right) == MouseButtons.Right;
            if ((isMiddleMousePanning && !middlePressed) || (isRightMousePanning && !rightPressed))
            {
                EndViewportPan();
            }
        }

