                }

                void UpdateLineEndingSizeControls()
                {
                    if (suppressLineEndingSizeControlEvents)
                    {
                        return;
                    }

                    suppressLineEndingSizeControlEvents = true;
                    try
                    {
                        float strokeWidth = NormalizeVectorStrokeWidth((float)numericStrokeWidth.Value);
                        VectorLineEndingKind startKind = GetSelectedStartEndingKind();
                        VectorLineEndingKind endKind = GetSelectedEndEndingKind();

                        string startPrimaryKey = GetVectorLineEndingPrimaryLabelKey(startKind);
                        string startSecondaryKey = GetVectorLineEndingSecondaryLabelKey(startKind);
                        string endPrimaryKey = GetVectorLineEndingPrimaryLabelKey(endKind);
                        string endSecondaryKey = GetVectorLineEndingSecondaryLabelKey(endKind);

                        bool startPrimaryEnabled = VectorLineEndingSupportsPrimarySize(startKind);
                        bool startSecondaryEnabled = VectorLineEndingSupportsSecondarySize(startKind);
                        bool endPrimaryEnabled = VectorLineEndingSupportsPrimarySize(endKind);
                        bool endSecondaryEnabled = VectorLineEndingSupportsSecondarySize(endKind);

                        labelStartEndingPrimary.Text = startPrimaryEnabled ? EnsureLabelEndsWithColon(LocalizedText(startPrimaryKey)) : string.Empty;
                        labelStartEndingSecondary.Text = startSecondaryEnabled ? EnsureLabelEndsWithColon(LocalizedText(startSecondaryKey)) : string.Empty;
                        labelEndEndingPrimary.Text = endPrimaryEnabled ? EnsureLabelEndsWithColon(LocalizedText(endPrimaryKey)) : string.Empty;
                        labelEndEndingSecondary.Text = endSecondaryEnabled ? EnsureLabelEndsWithColon(LocalizedText(endSecondaryKey)) : string.Empty;

                        decimal startPrimaryValue = (decimal)GetVectorLineEndingEffectivePrimarySize(startKind, strokeWidth, startPrimarySizeCustomized ? working.StartEndingPrimarySize : 0f);
                        decimal startSecondaryValue = (decimal)GetVectorLineEndingEffectiveSecondarySize(startKind, strokeWidth, startPrimarySizeCustomized ? working.StartEndingPrimarySize : 0f, startSecondarySizeCustomized ? working.StartEndingSecondarySize : 0f);
                        decimal endPrimaryValue = (decimal)GetVectorLineEndingEffectivePrimarySize(endKind, strokeWidth, endPrimarySizeCustomized ? working.EndEndingPrimarySize : 0f);
                        decimal endSecondaryValue = (decimal)GetVectorLineEndingEffectiveSecondarySize(endKind, strokeWidth, endPrimarySizeCustomized ? working.EndEndingPrimarySize : 0f, endSecondarySizeCustomized ? working.EndEndingSecondarySize : 0f);

                        numericStartEndingPrimary.Value = Math.Min(numericStartEndingPrimary.Maximum, Math.Max(numericStartEndingPrimary.Minimum, startPrimaryValue));
                        numericStartEndingSecondary.Value = Math.Min(numericStartEndingSecondary.Maximum, Math.Max(numericStartEndingSecondary.Minimum, startSecondaryValue));
                        numericEndEndingPrimary.Value = Math.Min(numericEndEndingPrimary.Maximum, Math.Max(numericEndEndingPrimary.Minimum, endPrimaryValue));
                        numericEndEndingSecondary.Value = Math.Min(numericEndEndingSecondary.Maximum, Math.Max(numericEndEndingSecondary.Minimum, endSecondaryValue));

                        bool supportsLineEndings = selectedShape == VectorShapeType.Polyline;
                        bool hasStroke = !checkNoStrokeColor.Checked;
                        labelStartEndingPrimary.Enabled = supportsLineEndings && hasStroke && startPrimaryEnabled;
                        numericStartEndingPrimary.Enabled = supportsLineEndings && hasStroke && startPrimaryEnabled;
                        labelStartEndingSecondary.Enabled = supportsLineEndings && hasStroke && startSecondaryEnabled;
                        numericStartEndingSecondary.Enabled = supportsLineEndings && hasStroke && startSecondaryEnabled;
                        labelEndEndingPrimary.Enabled = supportsLineEndings && hasStroke && endPrimaryEnabled;
                        numericEndEndingPrimary.Enabled = supportsLineEndings && hasStroke && endPrimaryEnabled;
                        labelEndEndingSecondary.Enabled = supportsLineEndings && hasStroke && endSecondaryEnabled;
                        numericEndEndingSecondary.Enabled = supportsLineEndings && hasStroke && endSecondaryEnabled;
                    }
                    finally
                    {
                        suppressLineEndingSizeControlEvents = false;
                    }
                }

                buildShapeDefaultsFromControls = () =>
                {
                    var result = working.Clone();
                    result.ShapeType = selectedShape;
                    System.Drawing.Color selectedStroke = buttonStrokeColor.BackColor;
                    result.StrokeColorArgb = checkNoStrokeColor.Checked
                        ? System.Drawing.Color.FromArgb(0, selectedStroke.R, selectedStroke.G, selectedStroke.B).ToArgb()
                        : System.Drawing.Color.FromArgb(255, selectedStroke.R, selectedStroke.G, selectedStroke.B).ToArgb();
                    result.StrokeWidth = NormalizeVectorStrokeWidth((float)numericStrokeWidth.Value);

                    System.Drawing.Color selectedFill = buttonFillColor.BackColor;
                    bool supportsFillForShape = ShapeTypeSupportsFill(selectedShape);
                    bool noFill = !supportsFillForShape || checkNoFillColor.Checked;
                    result.FillColorArgb = noFill
                        ? System.Drawing.Color.FromArgb(0, selectedFill.R, selectedFill.G, selectedFill.B).ToArgb()
                        : System.Drawing.Color.FromArgb(255, selectedFill.R, selectedFill.G, selectedFill.B).ToArgb();
                    result.FillOpacity = NormalizeVectorFillOpacity((float)(numericFillOpacity.Value / 100m));

                    switch (comboFillPattern.SelectedIndex)
                    {
                        case 1:
                            result.FillPattern = VectorFillPatternKind.Diagonal;
                            break;
                        case 2:
                            result.FillPattern = VectorFillPatternKind.Cross;
                            break;
                        case 3:
                            result.FillPattern = VectorFillPatternKind.Dot;
                            break;
                        default:
                            result.FillPattern = VectorFillPatternKind.Solid;
                            break;
                    }

                    System.Drawing.Color selectedPatternColor = buttonFillPatternColor.BackColor;
                    bool hasPatternColor = !noFill && comboFillPattern.SelectedIndex > 0;
                    result.FillPatternColorArgb = hasPatternColor
                        ? System.Drawing.Color.FromArgb(255, selectedPatternColor.R, selectedPatternColor.G, selectedPatternColor.B).ToArgb()
                        : System.Drawing.Color.FromArgb(0, selectedPatternColor.R, selectedPatternColor.G, selectedPatternColor.B).ToArgb();
                    result.LimitsRasterView = checkLimitRasterView.Checked && ShapeTypeSupportsRasterClip(selectedShape);

                    switch (comboStrokeStyle.SelectedIndex)
                    {
                        case 1:
                            result.StrokeKind = VectorShapeStrokeKind.Dash;
                            break;
                        case 2:
                            result.StrokeKind = VectorShapeStrokeKind.Dot;
                            break;
                        case 3:
                            result.StrokeKind = VectorShapeStrokeKind.DashDot;
                            break;
                        case 4:
                            result.StrokeKind = VectorShapeStrokeKind.DashDotDot;
                            break;
                        default:
                            result.StrokeKind = VectorShapeStrokeKind.Solid;
                            break;
                    }

                    result.StartEnding = ParseVectorLineEndingKind(GetSelectedVectorLineEndingValue(comboStartEnding));
                    result.EndEnding = ParseVectorLineEndingKind(GetSelectedVectorLineEndingValue(comboEndEnding));
                    result.StartEndingPrimarySize = startPrimarySizeCustomized ? NormalizeVectorLineEndingPrimarySize((float)numericStartEndingPrimary.Value) : 0f;
                    result.StartEndingSecondarySize = startSecondarySizeCustomized ? NormalizeVectorLineEndingSecondarySize((float)numericStartEndingSecondary.Value) : 0f;
                    result.EndEndingPrimarySize = endPrimarySizeCustomized ? NormalizeVectorLineEndingPrimarySize((float)numericEndEndingPrimary.Value) : 0f;
                    result.EndEndingSecondarySize = endSecondarySizeCustomized ? NormalizeVectorLineEndingSecondarySize((float)numericEndEndingSecondary.Value) : 0f;

                    if (!VectorLineEndingSupportsPrimarySize(result.StartEnding))
                    {
                        result.StartEndingPrimarySize = 0f;
                    }
                    if (!VectorLineEndingSupportsSecondarySize(result.StartEnding))
                    {
                        result.StartEndingSecondarySize = 0f;
                    }
                    if (!VectorLineEndingSupportsPrimarySize(result.EndEnding))
                    {
                        result.EndEndingPrimarySize = 0f;
                    }
                    if (!VectorLineEndingSupportsSecondarySize(result.EndEnding))
                    {
                        result.EndEndingSecondarySize = 0f;
                    }
                    if (selectedShape != VectorShapeType.Polyline || checkNoStrokeColor.Checked)
                    {
                        result.StartEnding = VectorLineEndingKind.None;
                        result.EndEnding = VectorLineEndingKind.None;
                        result.StartEndingPrimarySize = 0f;
                        result.StartEndingSecondarySize = 0f;
                        result.EndEndingPrimarySize = 0f;
                        result.EndEndingSecondarySize = 0f;
                    }

                    return result;
                };

                notifyShapePreviewChanged = () =>
                {
                    if (previewChanges == null || buildShapeDefaultsFromControls == null)
                    {
                        return;
                    }

                    previewChanges(buildShapeDefaultsFromControls());
                };

                numericStartEndingPrimary.ValueChanged += (_, __) =>
                {
                    if (suppressLineEndingSizeControlEvents)
                    {
                        return;
                    }

                    startPrimarySizeCustomized = numericStartEndingPrimary.Value > 0m;
                    working.StartEndingPrimarySize = startPrimarySizeCustomized ? NormalizeVectorLineEndingPrimarySize((float)numericStartEndingPrimary.Value) : 0f;
                    UpdateLineEndingSizeControls();
                    notifyShapePreviewChanged?.Invoke();
                };
                numericStartEndingSecondary.ValueChanged += (_, __) =>
                {
                    if (suppressLineEndingSizeControlEvents)
                    {
                        return;
                    }

                    startSecondarySizeCustomized = numericStartEndingSecondary.Value > 0m;
                    working.StartEndingSecondarySize = startSecondarySizeCustomized ? NormalizeVectorLineEndingSecondarySize((float)numericStartEndingSecondary.Value) : 0f;
                    UpdateLineEndingSizeControls();
                    notifyShapePreviewChanged?.Invoke();
                };
                numericEndEndingPrimary.ValueChanged += (_, __) =>
                {
                    if (suppressLineEndingSizeControlEvents)
                    {
                        return;
                    }

                    endPrimarySizeCustomized = numericEndEndingPrimary.Value > 0m;
                    working.EndEndingPrimarySize = endPrimarySizeCustomized ? NormalizeVectorLineEndingPrimarySize((float)numericEndEndingPrimary.Value) : 0f;
                    UpdateLineEndingSizeControls();
                    notifyShapePreviewChanged?.Invoke();
                };
                numericEndEndingSecondary.ValueChanged += (_, __) =>
                {
                    if (suppressLineEndingSizeControlEvents)
                    {
                        return;
                    }

                    endSecondarySizeCustomized = numericEndEndingSecondary.Value > 0m;
                    working.EndEndingSecondarySize = endSecondarySizeCustomized ? NormalizeVectorLineEndingSecondarySize((float)numericEndEndingSecondary.Value) : 0f;
                    UpdateLineEndingSizeControls();
                    notifyShapePreviewChanged?.Invoke();
                };
                comboStartEnding.SelectedIndexChanged += (_, __) =>
                {
                    startPrimarySizeCustomized = working.StartEndingPrimarySize > 0f;
                    startSecondarySizeCustomized = working.StartEndingSecondarySize > 0f;
                    UpdateLineEndingSizeControls();
                    notifyShapePreviewChanged?.Invoke();
                };
                comboEndEnding.SelectedIndexChanged += (_, __) =>
                {
                    endPrimarySizeCustomized = working.EndEndingPrimarySize > 0f;
                    endSecondarySizeCustomized = working.EndEndingSecondarySize > 0f;
                    UpdateLineEndingSizeControls();
                    notifyShapePreviewChanged?.Invoke();
                };

                refreshVectorStyleControls = () =>
                {
                    bool supportsFill = ShapeTypeSupportsFill(selectedShape);
                    bool supportsLineEndings = selectedShape == VectorShapeType.Polyline;
                    bool supportsRasterClip = ShapeTypeSupportsRasterClip(selectedShape);
                    bool hasStroke = !checkNoStrokeColor.Checked;
                    bool hasFill = supportsFill && !checkNoFillColor.Checked;
                    bool hasPattern = hasFill && comboFillPattern.SelectedIndex > 0;

                    buttonStrokeColor.Enabled = hasStroke;
                    labelStrokeWidth.Enabled = hasStroke;
                    numericStrokeWidth.Enabled = hasStroke;
                    labelStrokeStyle.Enabled = hasStroke;
                    comboStrokeStyle.Enabled = hasStroke;

                    labelFillColor.Enabled = supportsFill;
                    checkNoFillColor.Enabled = supportsFill;
                    buttonFillColor.Enabled = hasFill;
                    labelFillOpacity.Enabled = hasFill;
                    numericFillOpacity.Enabled = hasFill;
                    labelFillPattern.Enabled = hasFill;
                    comboFillPattern.Enabled = hasFill;
                    labelFillPatternColor.Enabled = hasPattern;
                    buttonFillPatternColor.Enabled = hasPattern;
                    labelStartEnding.Enabled = supportsLineEndings && hasStroke;
                    comboStartEnding.Enabled = supportsLineEndings && hasStroke;
                    labelEndEnding.Enabled = supportsLineEndings && hasStroke;
                    comboEndEnding.Enabled = supportsLineEndings && hasStroke;
                    checkLimitRasterView.Enabled = supportsRasterClip;
                    if (!supportsRasterClip)
                    {
                        checkLimitRasterView.Checked = false;
                    }
                    UpdateLineEndingSizeControls();
                };

                refreshShapeButtons = () =>
                {
                    foreach (var pair in shapeButtons)
                    {
                        bool isSelected = pair.Key == selectedShape;
                        Button currentButton = pair.Value;
                        currentButton.BackColor = isSelected
                            ? theme.SelectionBackColor
                            : theme.SecondaryButtonBackColor;
                        currentButton.FlatAppearance.BorderColor = isSelected
                            ? theme.BorderColor
                            : theme.BorderColor;
                        currentButton.FlatAppearance.BorderSize = isSelected ? 2 : 1;
                        currentButton.Padding = isSelected
                            ? new Padding(1, 1, 0, 0)
                            : new Padding(0);
                        currentButton.ForeColor = currentButton.Enabled ? theme.SecondaryButtonForeColor : theme.TextSecondaryColor;
                    }
                };

                Action<VectorShapeDefaults> applyDefaultsToControls = defaults =>
                {
                    if (defaults == null)
                    {
                        return;
                    }

                    selectedShape = lockShapeType ? selectedShape : defaults.ShapeType;
                    checkNoStrokeColor.Checked = !HasVisibleVectorColor(defaults.StrokeColorArgb);
                    System.Drawing.Color strokeColor = System.Drawing.Color.FromArgb(defaults.StrokeColorArgb);
                    buttonStrokeColor.BackColor = System.Drawing.Color.FromArgb(strokeColor.R, strokeColor.G, strokeColor.B);
                    numericStrokeWidth.Value = (decimal)NormalizeVectorStrokeWidth(defaults.StrokeWidth);
                    comboStrokeStyle.SelectedIndex = (int)defaults.StrokeKind;
                    checkNoFillColor.Checked = !HasVisibleVectorColor(defaults.FillColorArgb);
                    System.Drawing.Color fillColor = System.Drawing.Color.FromArgb(defaults.FillColorArgb);
                    buttonFillColor.BackColor = System.Drawing.Color.FromArgb(fillColor.R, fillColor.G, fillColor.B);
                    numericFillOpacity.Value = (decimal)Math.Round(NormalizeVectorFillOpacity(defaults.FillOpacity) * 100f);
                    comboFillPattern.SelectedIndex = (int)defaults.FillPattern;
                    System.Drawing.Color patternColor = System.Drawing.Color.FromArgb(defaults.FillPatternColorArgb);
                    if (patternColor.A == 0)
                    {
                        patternColor = System.Drawing.Color.Black;
                    }
                    buttonFillPatternColor.BackColor = System.Drawing.Color.FromArgb(patternColor.R, patternColor.G, patternColor.B);
                    checkLimitRasterView.Checked = defaults.LimitsRasterView && ShapeTypeSupportsRasterClip(selectedShape);
                    comboStartEnding.SelectedIndex = GetVectorLineEndingComboIndex(defaults.StartEnding);
                    comboEndEnding.SelectedIndex = GetVectorLineEndingComboIndex(defaults.EndEnding);
                    working.StartEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(defaults.StartEndingPrimarySize);
                    working.StartEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(defaults.StartEndingSecondarySize);
                    working.EndEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(defaults.EndEndingPrimarySize);
                    working.EndEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(defaults.EndEndingSecondarySize);
                    startPrimarySizeCustomized = working.StartEndingPrimarySize > 0f;
                    startSecondarySizeCustomized = working.StartEndingSecondarySize > 0f;
                    endPrimarySizeCustomized = working.EndEndingPrimarySize > 0f;
                    endSecondarySizeCustomized = working.EndEndingSecondarySize > 0f;
                    refreshShapeButtons?.Invoke();
                    refreshVectorStyleControls?.Invoke();
                };

                var buttonRestoreDefaults = new Button
                {
                    Left = 212,
                    Top = 368,
                    Width = 140,
                    Text = GetRestoreSettingsButtonText()
                };
                buttonRestoreDefaults.Click += (_, __) =>
                {
                    applyDefaultsToControls(VectorShapeDefaults.CreateDefault());
                    notifyShapePreviewChanged?.Invoke();
                };

                var buttonOk = new Button { Left = 364, Top = 368, Width = 110, Text = "OK", DialogResult = DialogResult.OK };
                var buttonCancel = new Button { Left = 486, Top = 368, Width = 110, Text = GetCancelButtonText(), DialogResult = DialogResult.Cancel };

                prompt.Controls.Add(labelShapes);
                prompt.Controls.Add(shapesPanel);
                prompt.Controls.Add(labelStrokeColor);
                prompt.Controls.Add(buttonStrokeColor);
                prompt.Controls.Add(labelStrokeWidth);
                prompt.Controls.Add(numericStrokeWidth);
                prompt.Controls.Add(labelStrokeStyle);
                prompt.Controls.Add(comboStrokeStyle);
                prompt.Controls.Add(checkNoStrokeColor);
                prompt.Controls.Add(labelFillColor);
                prompt.Controls.Add(buttonFillColor);
                prompt.Controls.Add(labelFillOpacity);
                prompt.Controls.Add(numericFillOpacity);
                prompt.Controls.Add(labelFillPattern);
                prompt.Controls.Add(comboFillPattern);
                prompt.Controls.Add(labelFillPatternColor);
                prompt.Controls.Add(buttonFillPatternColor);
                prompt.Controls.Add(checkNoFillColor);
                prompt.Controls.Add(labelStartEnding);
                prompt.Controls.Add(comboStartEnding);
                prompt.Controls.Add(labelEndEnding);
                prompt.Controls.Add(comboEndEnding);
                prompt.Controls.Add(labelStartEndingPrimary);
                prompt.Controls.Add(numericStartEndingPrimary);
                prompt.Controls.Add(labelStartEndingSecondary);
                prompt.Controls.Add(numericStartEndingSecondary);
                prompt.Controls.Add(labelEndEndingPrimary);
                prompt.Controls.Add(numericEndEndingPrimary);
                prompt.Controls.Add(labelEndEndingSecondary);
                prompt.Controls.Add(numericEndEndingSecondary);
                prompt.Controls.Add(checkLimitRasterView);
                prompt.Controls.Add(buttonRestoreDefaults);
                prompt.Controls.Add(buttonOk);
                prompt.Controls.Add(buttonCancel);
                prompt.AcceptButton = buttonOk;
                prompt.CancelButton = buttonCancel;

                refreshShapeButtons?.Invoke();
                refreshVectorStyleControls?.Invoke();

                if (lockShapeType)
                {
                    foreach (var pair in shapeButtons)
                    {
                        bool isSelected = pair.Key == selectedShape;
                        pair.Value.Enabled = isSelected;
                        pair.Value.BackColor = isSelected
                            ? theme.SelectionBackColor
                            : theme.SecondaryButtonBackColor;
                        pair.Value.FlatAppearance.BorderColor = isSelected
                            ? theme.BorderColor
                            : theme.BorderColor;
                        pair.Value.FlatAppearance.BorderSize = isSelected ? 2 : 1;
                        pair.Value.Padding = isSelected
                            ? new Padding(1, 1, 0, 0)
                            : new Padding(0);
                        pair.Value.ForeColor = pair.Value.Enabled ? theme.SecondaryButtonForeColor : theme.TextSecondaryColor;
                    }
                }

                if (prompt.ShowDialog(this) != DialogResult.OK)
                {
                    return false;
                }
                selectedDefaults = buildShapeDefaultsFromControls != null
                    ? buildShapeDefaultsFromControls()
                    : working.Clone();
                return true;
            }
        }

        private void BeginVectorShapeCreation(VectorShapeDefaults selectedDefaults)
        {
            if (selectedDefaults == null)
            {
                return;
            }

            DisableRedactionSelectionMode();
            activeVectorShapeDefaults = selectedDefaults.Clone();
            activeVectorShapeType = activeVectorShapeDefaults.ShapeType;
            isVectorShapeCreationMode = true;
            vectorShapeDraftPoints.Clear();
            vectorShapeDraftHoverActive = false;
            UpdatePdfViewerToolCursor();
            UpdateObjectSelectionInfoLabel();
            pdfViewer.Invalidate();
        }

        private void DeactivateObjectCreationModes()
        {
            if (isVectorShapeCreationMode)
            {
                EndVectorShapeCreationMode();
            }

            if (isCommentCreationMode)
            {
                EndCommentCreationMode();
            }

            isDrawing = false;
            isMarkerCtrlBoxMode = false;
            currentSelection = RectangleF.Empty;

            if (!IsViewportPanningActive() && !isVectorShapeCreationMode && !isCommentCreationMode)
            {
                this.Cursor = Cursors.Default;
            }

            UpdatePdfViewerToolCursor();
            pdfViewer.Invalidate();
        }

        private void DisableRedactionSelectionMode()
        {
            isDrawing = false;
            isMarkerCtrlBoxMode = false;
            currentSelection = RectangleF.Empty;
            suppressRedactionModeTracking = true;
            markerRadioButton.Checked = false;
            boxRadioButton.Checked = false;
            suppressRedactionModeTracking = false;
        }

        private bool TryRestoreRedactionSelectionModeFromHitBlock(Point location)
        {
            if (pdf == null || currentPage <= 0 || currentPage > numPages)
            {
                return false;
            }

            float docX = location.X / scaleFactor;
            float docY = location.Y / scaleFactor;
            RedactionBlock hitBlock = redactionBlocks
                .Where(block => block != null &&
                                block.PageNumber == currentPage &&
                                IsLayerVisible(block.LayerId) &&
                                block.Bounds.Contains(docX, docY))
                .LastOrDefault();
            if (hitBlock == null)
            {
                return false;
            }

            isMarkerCtrlBoxMode = false;
            bool restoreMarker = lastManualRedactionModeIsMarker ?? hitBlock.IsMarkerSelection;
            suppressRedactionModeTracking = true;
            markerRadioButton.Checked = restoreMarker;
            boxRadioButton.Checked = !restoreMarker;
            suppressRedactionModeTracking = false;
            return true;
        }

        private bool IsRedactionSelectionModeEnabled()
        {
            return markerRadioButton.Checked || boxRadioButton.Checked;
        }

        private static bool DoesGraphicsPathIntersectRectangle(GraphicsPath path, RectangleF rectangle)
        {
            if (path == null || path.PointCount == 0 || rectangle.Width <= 0f || rectangle.Height <= 0f)
            {
                return false;
            }

            using (var region = new Region(path))
            using (var identityMatrix = new System.Drawing.Drawing2D.Matrix())
            {
                region.Intersect(rectangle);
                RectangleF[] scans = region.GetRegionScans(identityMatrix);
                return scans != null && scans.Length > 0;
            }
        }

        private static bool DoesWidenedPathIntersectRectangle(GraphicsPath sourcePath, float width, RectangleF rectangle)
        {
            if (sourcePath == null || sourcePath.PointCount == 0)
            {
                return false;
            }

            using (var widenedPath = (GraphicsPath)sourcePath.Clone())
            using (var pen = new Pen(System.Drawing.Color.Black, Math.Max(1f, width)))
            {
                pen.LineJoin = LineJoin.Round;
                pen.StartCap = LineCap.Round;
                pen.EndCap = LineCap.Round;
                widenedPath.Widen(pen);
                return DoesGraphicsPathIntersectRectangle(widenedPath, rectangle);
            }
        }

        private bool TryGetRasterObjectScreenCorners(RasterObject rasterObject, out PointF[] corners)
        {
            corners = null;
            if (rasterObject == null || rasterObject.PageNumber != currentPage)
            {
                return false;
            }

            RectangleF bounds = GetRasterObjectScreenBounds(rasterObject);
            if (bounds.Width <= 0f || bounds.Height <= 0f)
            {
                return false;
            }

            PointF center = new PointF(bounds.X + (bounds.Width / 2f), bounds.Y + (bounds.Height / 2f));
            int rotation = NormalizeRotation(rasterObject.Rotation);
            PointF vx = RotateVector(new PointF(bounds.Width / 2f, 0f), rotation);
            PointF vy = RotateVector(new PointF(0f, bounds.Height / 2f), rotation);
            corners = new[]
            {
                new PointF(center.X - vx.X - vy.X, center.Y - vx.Y - vy.Y),
                new PointF(center.X + vx.X - vy.X, center.Y + vx.Y - vy.Y),
                new PointF(center.X + vx.X + vy.X, center.Y + vx.Y + vy.Y),
                new PointF(center.X - vx.X + vy.X, center.Y - vx.Y + vy.Y)
            };
            return true;
        }

        private bool DoesRasterObjectIntersectMarquee(RasterObject rasterObject, RectangleF marqueeScreenRect)
        {
            if (!TryGetRasterObjectScreenCorners(rasterObject, out PointF[] corners))
            {
                return false;
            }

            using (var path = new GraphicsPath())
            {
                path.AddPolygon(corners);
                return DoesGraphicsPathIntersectRectangle(path, marqueeScreenRect);
            }
        }

        private bool DoesArrowObjectIntersectMarquee(ArrowObject arrowObject, RectangleF marqueeScreenRect)
        {
            if (arrowObject == null || arrowObject.PageNumber != currentPage)
            {
                return false;
            }

            PointF startScreen = GetArrowScreenPoint(arrowObject.Start);
            PointF endScreen = GetArrowScreenPoint(arrowObject.End);
            PointF lineEndScreen = endScreen;
            float headLengthPx = Math.Max(4f, NormalizeArrowHeadLength(arrowObject.HeadLength) * scaleFactor);
            float headWidthPx = Math.Max(4f, NormalizeArrowHeadWidth(arrowObject.HeadWidth) * scaleFactor);
            if (TryBuildArrowHead(startScreen, endScreen, headLengthPx, headWidthPx, out PointF leftPoint, out PointF rightPoint, out PointF lineEndPoint))
            {
                using (var headPath = new GraphicsPath())
                {
                    headPath.AddPolygon(new[] { endScreen, leftPoint, rightPoint });
                    if (DoesGraphicsPathIntersectRectangle(headPath, marqueeScreenRect))
                    {
                        return true;
                    }
                }

                lineEndScreen = lineEndPoint;
            }

            float lineWidthPx = (NormalizeArrowThickness(arrowObject.Thickness) + (2f * NormalizeArrowBorderWidth(arrowObject.BorderWidth))) * scaleFactor;
            using (var linePath = new GraphicsPath())
            {
                linePath.AddLine(startScreen, lineEndScreen);
                return DoesWidenedPathIntersectRectangle(linePath, lineWidthPx, marqueeScreenRect);
            }
        }

        private static bool HasVisibleVectorFill(VectorShapeObject vectorShape, VectorShapeType shapeType)
        {
            if (vectorShape == null || !ShapeTypeSupportsFill(shapeType))
            {
                return false;
            }

            float fillOpacity = NormalizeVectorFillOpacity(vectorShape.FillOpacity);
            if (fillOpacity <= 0f)
            {
                return false;
            }

            bool hasFillColor = HasVisibleVectorColor(vectorShape.FillColorArgb);
            bool hasPatternColor = HasVisibleVectorColor(vectorShape.FillPatternColorArgb);
            VectorFillPatternKind fillPattern = ParseVectorFillPattern(vectorShape.FillPattern);
            return hasFillColor || (fillPattern != VectorFillPatternKind.Solid && hasPatternColor);
        }

        private static bool DoesVectorLineEndingIntersectMarquee(
            PointF anchor,
            PointF towardPoint,
            VectorLineEndingKind ending,
            float strokeWidthPx,
            float primarySize,
            float secondarySize,
            RectangleF marqueeScreenRect)
        {
            if (ending == VectorLineEndingKind.None)
            {
                return false;
            }

            PointF direction = new PointF(anchor.X - towardPoint.X, anchor.Y - towardPoint.Y);
            float length = (float)Math.Sqrt((direction.X * direction.X) + (direction.Y * direction.Y));
            if (length < 0.001f)
            {
                return false;
            }

            float ux = direction.X / length;
            float uy = direction.Y / length;
            float px = -uy;
            float py = ux;
            GetVectorLineEndingMetrics(ending, strokeWidthPx, primarySize, secondarySize, out float markerLength, out float markerWidth, out float radius);

            switch (ending)
            {
                case VectorLineEndingKind.Arrow:
                {
                    PointF baseCenter = new PointF(anchor.X - (ux * markerLength), anchor.Y - (uy * markerLength));
                    PointF left = new PointF(baseCenter.X + (px * (markerWidth / 2f)), baseCenter.Y + (py * (markerWidth / 2f)));
                    PointF right = new PointF(baseCenter.X - (px * (markerWidth / 2f)), baseCenter.Y - (py * (markerWidth / 2f)));
                    using (var path = new GraphicsPath())
                    {
                        path.AddPolygon(new[] { anchor, left, right });
                        return DoesGraphicsPathIntersectRectangle(path, marqueeScreenRect);
                    }
                }
                case VectorLineEndingKind.OpenArrow:
                {
                    PointF baseCenter = new PointF(anchor.X - (ux * markerLength), anchor.Y - (uy * markerLength));
                    PointF left = new PointF(baseCenter.X + (px * (markerWidth / 2f)), baseCenter.Y + (py * (markerWidth / 2f)));
                    PointF right = new PointF(baseCenter.X - (px * (markerWidth / 2f)), baseCenter.Y - (py * (markerWidth / 2f)));
                    using (var path = new GraphicsPath())
                    {
                        path.AddLine(anchor, left);
                        path.StartFigure();
                        path.AddLine(anchor, right);
                        return DoesWidenedPathIntersectRectangle(path, strokeWidthPx, marqueeScreenRect);
                    }
                }
                case VectorLineEndingKind.DoubleOpenArrow:
                {
                    PointF baseCenter = new PointF(anchor.X - (ux * markerLength), anchor.Y - (uy * markerLength));
                    PointF left = new PointF(baseCenter.X + (px * (markerWidth / 2f)), baseCenter.Y + (py * (markerWidth / 2f)));
                    PointF right = new PointF(baseCenter.X - (px * (markerWidth / 2f)), baseCenter.Y - (py * (markerWidth / 2f)));
                    float secondaryOffset = GetDoubleOpenArrowSecondaryOffset(markerLength, strokeWidthPx);
                    PointF secondAnchor = new PointF(anchor.X - (ux * secondaryOffset), anchor.Y - (uy * secondaryOffset));
                    PointF secondBaseCenter = new PointF(secondAnchor.X - (ux * markerLength), secondAnchor.Y - (uy * markerLength));
                    PointF secondLeft = new PointF(secondBaseCenter.X + (px * (markerWidth / 2f)), secondBaseCenter.Y + (py * (markerWidth / 2f)));
                    PointF secondRight = new PointF(secondBaseCenter.X - (px * (markerWidth / 2f)), secondBaseCenter.Y - (py * (markerWidth / 2f)));
                    using (var path = new GraphicsPath())
                    {
                        path.AddLine(anchor, left);
                        path.StartFigure();
                        path.AddLine(anchor, right);
                        path.StartFigure();
                        path.AddLine(secondAnchor, secondLeft);
                        path.StartFigure();
                        path.AddLine(secondAnchor, secondRight);
                        return DoesWidenedPathIntersectRectangle(path, strokeWidthPx, marqueeScreenRect);
                    }
                }
                case VectorLineEndingKind.Circle:
                case VectorLineEndingKind.FilledCircle:
                {
                    using (var path = new GraphicsPath())
                    {
                        path.AddEllipse(anchor.X - radius, anchor.Y - radius, radius * 2f, radius * 2f);
                        return ending == VectorLineEndingKind.FilledCircle
                            ? DoesGraphicsPathIntersectRectangle(path, marqueeScreenRect)
                            : DoesWidenedPathIntersectRectangle(path, strokeWidthPx, marqueeScreenRect);
                    }
                }
                case VectorLineEndingKind.Bar:
                {
                    PointF left = new PointF(anchor.X + (px * radius), anchor.Y + (py * radius));
                    PointF right = new PointF(anchor.X - (px * radius), anchor.Y - (py * radius));
                    using (var path = new GraphicsPath())
                    {
                        path.AddLine(left, right);
                        return DoesWidenedPathIntersectRectangle(path, strokeWidthPx, marqueeScreenRect);
                    }
                }
                default:
                    return false;
            }
        }

        private bool DoesVectorShapeIntersectMarquee(VectorShapeObject vectorShape, RectangleF marqueeScreenRect)
        {
            if (vectorShape == null || vectorShape.PageNumber != currentPage || vectorShape.Points == null || vectorShape.Points.Count < 2)
            {
                return false;
            }

            VectorShapeType shapeType = ParseVectorShapeType(vectorShape.ShapeType);
            PointF[] points = BuildVectorShapeRenderPoints(shapeType, vectorShape.Points)
                .Select(p => new PointF(p.X * scaleFactor, p.Y * scaleFactor))
                .ToArray();
            if (points.Length < 2)
            {
                return false;
            }

            bool closedShape = IsShapeClosed(shapeType);
            bool hasStroke = HasVisibleVectorColor(vectorShape.StrokeColorArgb);
            bool hasFill = HasVisibleVectorFill(vectorShape, shapeType) || (vectorShape.IsRasterClip && closedShape);
            float strokeWidthPx = NormalizeVectorStrokeWidth(vectorShape.StrokeWidth) * scaleFactor;

            if (closedShape && points.Length >= 3)
            {
                using (var polygonPath = new GraphicsPath())
                {
                    polygonPath.AddPolygon(points);
                    if (hasFill && DoesGraphicsPathIntersectRectangle(polygonPath, marqueeScreenRect))
                    {
                        return true;
                    }

                    if (hasStroke && DoesWidenedPathIntersectRectangle(polygonPath, strokeWidthPx, marqueeScreenRect))
                    {
                        return true;
                    }
                }

                return false;
            }

            if (hasStroke)
            {
                PointF[] strokePoints = shapeType == VectorShapeType.Polyline
                    ? GetPolylineStrokePointsWithEndings(
                        points,
                        ParseVectorLineEndingKind(vectorShape.StartLineEnding),
                        ParseVectorLineEndingKind(vectorShape.EndLineEnding),
                        strokeWidthPx,
                        vectorShape.StartLineEndingPrimarySize,
                        vectorShape.StartLineEndingSecondarySize,
                        vectorShape.EndLineEndingPrimarySize,
                        vectorShape.EndLineEndingSecondarySize)
                    : points;

                using (var linePath = new GraphicsPath())
                {
                    linePath.AddLines(strokePoints);
                    if (DoesWidenedPathIntersectRectangle(linePath, strokeWidthPx, marqueeScreenRect))
                    {
                        return true;
                    }
                }

                if (shapeType == VectorShapeType.Polyline && points.Length >= 2)
                {
                    if (DoesVectorLineEndingIntersectMarquee(
                            points[0],
                            points[1],
                            ParseVectorLineEndingKind(vectorShape.StartLineEnding),
                            strokeWidthPx,
                            vectorShape.StartLineEndingPrimarySize,
                            vectorShape.StartLineEndingSecondarySize,
                            marqueeScreenRect))
                    {
                        return true;
                    }

                    if (DoesVectorLineEndingIntersectMarquee(
                            points[points.Length - 1],
                            points[points.Length - 2],
                            ParseVectorLineEndingKind(vectorShape.EndLineEnding),
                            strokeWidthPx,
                            vectorShape.EndLineEndingPrimarySize,
                            vectorShape.EndLineEndingSecondarySize,
                            marqueeScreenRect))
                    {
                        return true;
                    }
                }
            }

            return false;
        }

        private bool DoesTextAnnotationIntersectMarquee(TextAnnotation annotation, RectangleF marqueeScreenRect, float dpiX, float dpiY)
        {
            if (annotation == null || annotation.PageNumber != currentPage || !IsLayerVisible(annotation.LayerId))
            {
                return false;
            }

            if (TryGetAnnotationTextFrameGeometry(annotation, dpiX, dpiY, out PointF[] frameCorners, out _, out _, out _))
            {
                using (var framePath = new GraphicsPath())
                {
                    framePath.AddPolygon(frameCorners);
                    if (DoesGraphicsPathIntersectRectangle(framePath, marqueeScreenRect))
                    {
                        return true;
                    }
                }
            }

            if (!annotation.HasLeaderArrow ||
                !TryGetAnnotationLeaderGeometry(annotation, dpiX, dpiY, out PointF anchorPoint, out PointF endPoint, out PointF leftPoint, out PointF rightPoint, out PointF lineEndPoint))
            {
                return false;
            }

            using (var headPath = new GraphicsPath())
            {
                headPath.AddPolygon(new[] { endPoint, leftPoint, rightPoint });
                if (DoesGraphicsPathIntersectRectangle(headPath, marqueeScreenRect))
                {
                    return true;
                }
            }

            using (var linePath = new GraphicsPath())
            {
                linePath.AddLine(anchorPoint, lineEndPoint);
                float lineWidthPx = GetEffectiveTextLeaderLineWidth(annotation) * scaleFactor;
                return DoesWidenedPathIntersectRectangle(linePath, lineWidthPx, marqueeScreenRect);
            }
        }

        private bool DoesObjectIntersectMarquee(object candidate, RectangleF marqueeScreenRect, float dpiX, float dpiY)
        {
            switch (candidate)
            {
                case TextAnnotation textAnnotation:
                    return DoesTextAnnotationIntersectMarquee(textAnnotation, marqueeScreenRect, dpiX, dpiY);
                case RasterObject rasterObject:
                    return DoesRasterObjectIntersectMarquee(rasterObject, marqueeScreenRect);
                case ArrowObject arrowObject:
                    return DoesArrowObjectIntersectMarquee(arrowObject, marqueeScreenRect);
                case VectorShapeObject vectorShapeObject:
                    return DoesVectorShapeIntersectMarquee(vectorShapeObject, marqueeScreenRect);
                default:
                    return false;
            }
        }

        private void DrawObjectMarqueeSelectionOverlay(Graphics graphics)
        {
            if (graphics == null || !isDrawing || currentSelection.Width <= 0 || currentSelection.Height <= 0)
            {
                return;
            }

            if (isCommentCreationMode || IsRedactionSelectionModeEnabled())
            {
                return;
            }

            System.Drawing.Color marqueeColor = ControlPaint.Dark(CurrentTheme.SelectionBackColor, 0.45f);
            using (Pen pen = new Pen(marqueeColor, 3f))
            {
                pen.DashStyle = DashStyle.Dash;
                pen.DashPattern = new[] { 5f, 3f };
                graphics.DrawRectangle(
                    pen,
                    currentSelection.X,
                    currentSelection.Y,
                    currentSelection.Width,
                    currentSelection.Height);
            }
        }

        private bool TrySelectObjectsInMarquee(RectangleF marqueeScreenRect, bool additiveSelection)
        {
            if (marqueeScreenRect.Width <= 0f || marqueeScreenRect.Height <= 0f)
            {
                return false;
            }

            var hits = new List<object>();
            float dpiX = 96f;
            float dpiY = 96f;
            using (Graphics graphics = pdfViewer.CreateGraphics())
            {
                dpiX = graphics.DpiX;
                dpiY = graphics.DpiY;
            }

            foreach (object candidate in GetOrderedObjectsForCurrentPage())
            {
                if (DoesObjectIntersectMarquee(candidate, marqueeScreenRect, dpiX, dpiY))
                {
                    hits.Add(candidate);
                }
            }

            if (hits.Count == 0)
            {
                if (!additiveSelection)
                {
                    selectedTextAnnotation = null;
                    selectedRasterObject = null;
                    selectedArrowObject = null;
                    selectedVectorShape = null;
                    ClearGroupSelection();
                    UpdateObjectSelectionInfoLabel();
                }
                return false;
            }

            if (additiveSelection)
            {
                PromoteSingleSelectionsToGroup();
            }
            else
            {
                selectedTextAnnotation = null;
                selectedRasterObject = null;
                selectedArrowObject = null;
                selectedVectorShape = null;
                ClearGroupSelection();
            }

            foreach (object hitObject in hits)
            {
                switch (hitObject)
                {
                    case TextAnnotation textAnnotation:
                        selectedTextAnnotations.Add(textAnnotation);
                        break;
                    case RasterObject rasterObject:
                        EnsureRasterObjectId(rasterObject);
                        if (!string.IsNullOrWhiteSpace(rasterObject.Id))
                        {
                            selectedRasterObjectIds.Add(rasterObject.Id);
                        }
                        break;
                    case ArrowObject arrowObject:
                        EnsureArrowObjectId(arrowObject);
                        if (!string.IsNullOrWhiteSpace(arrowObject.Id))
                        {
                            selectedArrowObjectIds.Add(arrowObject.Id);
                        }
                        break;
                    case VectorShapeObject vectorShapeObject:
                        EnsureVectorShapeId(vectorShapeObject);
                        if (!string.IsNullOrWhiteSpace(vectorShapeObject.Id))
                        {
                            selectedVectorShapeIds.Add(vectorShapeObject.Id);
                        }
                        break;
                }
            }

            CollapseGroupSelectionToSingleIfNeeded();
            UpdateObjectSelectionInfoLabel();
            return true;
        }

        private void MarkerRadioButton_CheckedChanged(object sender, EventArgs e)
        {
            if (!suppressRedactionModeTracking && markerRadioButton.Checked)
            {
                lastManualRedactionModeIsMarker = true;
            }

            if (markerRadioButton.Checked)
            {
                UpdatePdfViewerToolCursor();
            }
        }

        private void BoxRadioButton_CheckedChanged(object sender, EventArgs e)
        {
            if (!suppressRedactionModeTracking && boxRadioButton.Checked)
            {
                lastManualRedactionModeIsMarker = false;
            }

            if (boxRadioButton.Checked)
            {
                UpdatePdfViewerToolCursor();
            }
        }

        private void EndVectorShapeCreationMode(bool keepDefaults = true)
        {
            isVectorShapeCreationMode = false;
            vectorShapeDraftPoints.Clear();
            vectorShapeDraftHoverActive = false;
            this.Cursor = Cursors.Default;
            if (pdfViewer != null)
            {
                pdfViewer.Cursor = Cursors.Default;
            }
            if (!keepDefaults)
            {
                activeVectorShapeDefaults = VectorShapeDefaults.CreateDefault();
                activeVectorShapeType = activeVectorShapeDefaults.ShapeType;
            }
            UpdateObjectSelectionInfoLabel();
        }

        private bool TryFinalizeVectorShapeDraft()
        {
            int requiredPoints = GetRequiredPointsForShape(activeVectorShapeType);
            if (vectorShapeDraftPoints.Count < requiredPoints)
            {
                return false;
            }

            BeginUndoCapture("Add shape");

            var shape = new VectorShapeObject
            {
                Id = Guid.NewGuid().ToString("N"),
                PageNumber = currentPage,
                LayerId = GetResolvedActiveLayerId(),
                ShapeType = activeVectorShapeType.ToString(),
                IsRasterClip = activeVectorShapeDefaults.LimitsRasterView,
                Points = vectorShapeDraftPoints.ToList(),
                StrokeColorArgb = activeVectorShapeDefaults.StrokeColorArgb,
                StrokeWidth = NormalizeVectorStrokeWidth(activeVectorShapeDefaults.StrokeWidth),
                FillColorArgb = activeVectorShapeDefaults.FillColorArgb,
                FillPatternColorArgb = activeVectorShapeDefaults.FillPatternColorArgb,
                FillOpacity = NormalizeVectorFillOpacity(activeVectorShapeDefaults.FillOpacity),
                StrokeStyle = activeVectorShapeDefaults.StrokeKind.ToString(),
                FillPattern = activeVectorShapeDefaults.FillPattern.ToString(),
                StartLineEnding = activeVectorShapeDefaults.StartEnding.ToString(),
                EndLineEnding = activeVectorShapeDefaults.EndEnding.ToString(),
                StartLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(activeVectorShapeDefaults.StartEndingPrimarySize),
                StartLineEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(activeVectorShapeDefaults.StartEndingSecondarySize),
                EndLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(activeVectorShapeDefaults.EndEndingPrimarySize),
                EndLineEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(activeVectorShapeDefaults.EndEndingSecondarySize),
                CreatedAtUtc = DateTime.UtcNow,
                UpdatedAtUtc = DateTime.UtcNow
            };
            NormalizeVectorShape(shape);

            vectorShapes.Add(shape);
            vectorShapeDraftPoints.Clear();
            vectorShapeDraftHoverActive = false;

            PageItemStatus status = allPageStatuses[currentPage - 1];
            status.HasObjects = true;
            if ((string)filterComboBox.SelectedItem == allComboItem)
            {
                ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                pagesListView.Invalidate(currentItem.Bounds);
            }
            else
            {
                ApplyFilter((string)filterComboBox.SelectedItem);
            }

            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            UpdateObjectSelectionInfoLabel();
            pdfViewer.Invalidate();
            return true;
        }

        private static float DistanceBetweenPoints(PointF a, PointF b)
        {
            float dx = a.X - b.X;
            float dy = a.Y - b.Y;
            return (float)Math.Sqrt((dx * dx) + (dy * dy));
        }

        private void OnMouseDown(object sender, MouseEventArgs e)
        {
            if (pdf == null)
            {
                return;
            }

            FocusDocumentViewport();

            if (e.Button == MouseButtons.Middle)
            {
                isDrawing = false;
                isMarkerCtrlBoxMode = false;
                isMoving = false;
                annotationToMove = null;
                textMoveMouseOffset = PointF.Empty;
                ResetRasterInteractionState();
                ResetArrowInteractionState();
                ResetGroupMoveState();
                currentSelection = RectangleF.Empty;
                isClickOnIcon = false;
                clickedIconType = IconType.None;
                annotationForIcon = null;
                ClearRasterIconClickState();
                ClearArrowIconClickState();
                ClearVectorIconClickState();
                ResetCommentNoteMoveState();
                TryBeginViewportPan(MouseButtons.Middle);
                return;
            }

            if (e.Button == MouseButtons.Right &&
                !isVectorShapeCreationMode &&
                !isCommentCreationMode &&
                !IsPointOverInteractiveDocumentContent(e.Location))
            {
                isDrawing = false;
                isMarkerCtrlBoxMode = false;
                isMoving = false;
                annotationToMove = null;
                textMoveMouseOffset = PointF.Empty;
                ResetRasterInteractionState();
                ResetArrowInteractionState();
                ResetVectorInteractionState();
                ResetGroupMoveState();
                currentSelection = RectangleF.Empty;
                isClickOnIcon = false;
                clickedIconType = IconType.None;
                annotationForIcon = null;
                ClearRasterIconClickState();
                ClearArrowIconClickState();
                ClearVectorIconClickState();
                ResetCommentNoteMoveState();
                if (TryBeginViewportPan(MouseButtons.Right))
                {
                    return;
                }
            }

            if (isVectorShapeCreationMode)
            {
                if (!EnsureCurrentPageEditable(true))
                {
                    EndVectorShapeCreationMode();
                    return;
                }

                PointF rawDocPoint = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                PointF docPoint = NormalizeVectorShapeDraftInputPoint(rawDocPoint);
                int requiredPoints = GetRequiredPointsForShape(activeVectorShapeType);
                bool isFreeformShape = activeVectorShapeType == VectorShapeType.Polyline || activeVectorShapeType == VectorShapeType.Region;
                if (e.Button == MouseButtons.Left)
                {
                    if (isFreeformShape && e.Clicks > 1)
                    {
                        if (vectorShapeDraftPoints.Count == 0 || DistanceBetweenPoints(vectorShapeDraftPoints.Last(), docPoint) > 0.5f)
                        {
                            vectorShapeDraftPoints.Add(docPoint);
                        }
                        TryFinalizeVectorShapeDraft();
                        pdfViewer.Invalidate();
                        return;
                    }

                    vectorShapeDraftPoints.Add(docPoint);
                    vectorShapeDraftHoverPoint = docPoint;
                    vectorShapeDraftHoverActive = true;
                    if (!isFreeformShape && vectorShapeDraftPoints.Count >= requiredPoints)
                    {
                        TryFinalizeVectorShapeDraft();
                    }
                    UpdateObjectSelectionInfoLabel();
                    pdfViewer.Invalidate();
                    return;
                }

                if (e.Button == MouseButtons.Right)
                {
                    if (!TryFinalizeVectorShapeDraft())
                    {
                        if (vectorShapeDraftPoints.Count > 0)
                        {
                            vectorShapeDraftPoints.Clear();
                            vectorShapeDraftHoverActive = false;
                            UpdateObjectSelectionInfoLabel();
                        }
                        else
                        {
                            EndVectorShapeCreationMode();
                        }
                    }

                    UpdateObjectSelectionInfoLabel();
                    pdfViewer.Invalidate();
                    return;
                }
            }

            // Reset icon click flag
            isClickOnIcon = false;
            clickedIconType = IconType.None;
            annotationForIcon = null;
            ClearRasterIconClickState();
            ClearArrowIconClickState();
            ClearVectorIconClickState();
            ResetTextRotationInteractionState();
            rasterMouseActionInProgress = false;
            arrowMouseActionInProgress = false;
            vectorMouseActionInProgress = false;
            if (IsCurrentPageMarkedForDeletion() && (e.Button == MouseButtons.Left || e.Button == MouseButtons.Right))
            {
                textMoveMouseOffset = PointF.Empty;
                ResetRasterInteractionState();
                ResetArrowInteractionState();
                ResetVectorInteractionState();
                ResetTextRotationInteractionState();
                selectedVectorShape = null;
                ResetGroupMoveState();
                ClearArrowIconClickState();
                ClearVectorIconClickState();
                return;
            }

            if (e.Button == MouseButtons.Right)
            {
                isDrawing = false;
                startPoint = e.Location;
                if (isCommentCreationMode)
                {
                    EndCommentCreationMode();
                    pdfViewer.Invalidate();
                    return;
                }
            }
            else if (e.Button == MouseButtons.Left)
            {
                suppressNextLeftMouseUpAfterEscape = false;
                startPoint = e.Location;
                isMarkerCtrlBoxMode = false;

                float dpiX;
                float dpiY;
                using (Graphics g = pdfViewer.CreateGraphics())
                {
                    dpiX = g.DpiX;
                    dpiY = g.DpiY;
                }
                float docX = e.X / scaleFactor;
                float docY = e.Y / scaleFactor;
                bool commentHit = TryGetCommentAtPoint(e.Location, out CommentAnnotation hitComment, out RectangleF hitNoteRect);

                if (!commentHit)
                {
                    selectedCommentAnnotation = null;
                }

                if (!isCommentCreationMode &&
                    commentHit &&
                    hitComment != null &&
                    !hitNoteRect.IsEmpty &&
                    hitNoteRect.Contains(docX, docY))
                {
                    DisableRedactionSelectionMode();

                    if (e.Clicks >= 2)
                    {
                        EditCommentAnnotation(hitComment);
                        pdfViewer.Invalidate();
                        return;
                    }

                    isDrawing = false;
                    isMoving = false;
                    annotationToMove = null;
                    textMoveMouseOffset = PointF.Empty;
                    selectedTextAnnotation = null;
                    selectedRasterObject = null;
                    selectedArrowObject = null;
                    selectedVectorShape = null;
                    ResetRasterInteractionState();
                    ResetArrowInteractionState();
                    ResetVectorInteractionState();
                    ClearRasterIconClickState();
                    ClearArrowIconClickState();
                    ClearVectorIconClickState();
                    ClearGroupSelection();
                    ResetGroupMoveState();
                    selectedCommentAnnotation = hitComment;
                    UpdateObjectSelectionInfoLabel();

                    if (IsCommentAnnotationEffectivelyLocked(hitComment))
                    {
                        pdfViewer.Invalidate();
                        return;
                    }

                    if (IsPointInCommentResizeHandle(e.Location, hitNoteRect))
                    {
                        BeginUndoCapture("Resize comment");
                        isResizingCommentNote = true;
                        commentNoteResizeChanged = false;
                        commentNoteToResize = hitComment;
                        commentNoteStartRectDoc = hitNoteRect;
                        hitComment.NoteX = hitNoteRect.X;
                        hitComment.NoteY = hitNoteRect.Y;
                        commentNoteResizeAnchorDoc = new PointF(hitNoteRect.X, hitNoteRect.Y);
                        this.Cursor = Cursors.SizeNWSE;
                    }
                    else
                    {
                        BeginUndoCapture("Move comment");
                        isMovingCommentNote = true;
                        commentNoteMoveChanged = false;
                        commentNoteToMove = hitComment;
                        commentNoteStartRectDoc = hitNoteRect;
                        commentNoteMoveOffsetDoc = new PointF(docX - hitNoteRect.X, docY - hitNoteRect.Y);
                        this.Cursor = Cursors.SizeAll;
                    }
                    pdfViewer.Invalidate();
                    return;
                }

                if (!isCommentCreationMode && commentHit && hitComment != null)
                {
                    DisableRedactionSelectionMode();
                    isDrawing = false;
                    isMoving = false;
                    annotationToMove = null;
                    textMoveMouseOffset = PointF.Empty;
                    selectedTextAnnotation = null;
                    selectedRasterObject = null;
                    selectedArrowObject = null;
                    selectedVectorShape = null;
                    ResetRasterInteractionState();
                    ResetArrowInteractionState();
                    ResetVectorInteractionState();
                    ClearRasterIconClickState();
                    ClearArrowIconClickState();
                    ClearVectorIconClickState();
                    ClearGroupSelection();
                    ResetGroupMoveState();
                    selectedCommentAnnotation = hitComment;
                    UpdateObjectSelectionInfoLabel();
                    pdfViewer.Invalidate();
                    return;
                }

                if (isCommentCreationMode)
                {
                    BeginUndoCapture("Add comment");
                    selectedTextAnnotation = null;
                    annotationToMove = null;
                    isMoving = false;
                    textMoveMouseOffset = PointF.Empty;
                    selectedRasterObject = null;
                    selectedArrowObject = null;
                    selectedVectorShape = null;
                    selectedCommentAnnotation = null;
                    ResetRasterInteractionState();
                    ResetArrowInteractionState();
                    ResetVectorInteractionState();
                    ClearRasterIconClickState();
                    ClearArrowIconClickState();
                    ClearVectorIconClickState();
                    ClearGroupSelection();
                    ResetGroupMoveState();
                    isDrawing = true;
                    currentSelection = new RectangleF(startPoint, Size.Empty);
                    pdfViewer.Invalidate();
                    return;
                }

                bool additiveSelection = (Control.ModifierKeys & Keys.Control) == Keys.Control;
                if (additiveSelection)
                {
                    if (TryToggleGroupSelectionAtPoint(e.Location, dpiX, dpiY))
                    {
                        ResetRasterInteractionState();
                        ResetArrowInteractionState();
                        ResetVectorInteractionState();
                        ResetGroupMoveState();
                        isDrawing = false;
                        isMoving = false;
                        annotationToMove = null;
                        textMoveMouseOffset = PointF.Empty;
                        this.Cursor = Cursors.Default;
                        pdfViewer.Invalidate();
                        return;
                    }
                }
                else if (GetGroupSelectionCount() > 0)
                {
                    if (TryBeginGroupScale(e.Location, dpiX, dpiY))
                    {
                        ResetRasterInteractionState();
                        ResetArrowInteractionState();
                        ResetVectorInteractionState();
                        isDrawing = false;
                        isMoving = false;
                        annotationToMove = null;
                        textMoveMouseOffset = PointF.Empty;
                        pdfViewer.Invalidate();
                        return;
                    }

                    if (TryBeginGroupMove(e.Location, dpiX, dpiY))
                    {
                        ResetRasterInteractionState();
                        ResetArrowInteractionState();
                        ResetVectorInteractionState();
                        isDrawing = false;
                        isMoving = false;
                        annotationToMove = null;
                        textMoveMouseOffset = PointF.Empty;
                        pdfViewer.Invalidate();
                        return;
                    }

                    ClearGroupSelection();
                    ResetGroupMoveState();
                }

                if (TryHandleTextRotationMouseDown(e.Location, dpiX, dpiY))
                {
                    selectedArrowObject = null;
                    ResetArrowInteractionState();
                    ClearArrowIconClickState();
                    selectedVectorShape = null;
                    ResetVectorInteractionState();
                    selectedRasterObject = null;
                    ResetRasterInteractionState();
                    isDrawing = false;
                    isMoving = false;
                    annotationToMove = null;
                    textMoveMouseOffset = PointF.Empty;
                    pdfViewer.Invalidate();
                    return;
                }

                if (TryHandleTextScaleMouseDown(e.Location, dpiX, dpiY))
                {
                    selectedArrowObject = null;
                    ResetArrowInteractionState();
                    ClearArrowIconClickState();
                    selectedVectorShape = null;
                    ResetVectorInteractionState();
                    selectedRasterObject = null;
                    ResetRasterInteractionState();
                    isDrawing = false;
                    isMoving = false;
                    annotationToMove = null;
                    textMoveMouseOffset = PointF.Empty;
                    pdfViewer.Invalidate();
                    return;
                }

                if (TryHandleTextLeaderMouseDown(e.Location, dpiX, dpiY))
                {
                    selectedArrowObject = null;
                    ResetArrowInteractionState();
                    ClearArrowIconClickState();
                    selectedVectorShape = null;
                    ResetVectorInteractionState();
                    selectedRasterObject = null;
                    ResetRasterInteractionState();
                    isDrawing = false;
                    isMoving = false;
                    annotationToMove = null;
                    textMoveMouseOffset = PointF.Empty;
                    pdfViewer.Invalidate();
                    return;
                }

                if (TryHandleAnnotationIconMouseDown(e.Location, dpiX, dpiY))
                {
                    selectedArrowObject = null;
                    ResetArrowInteractionState();
                    ClearArrowIconClickState();
                    selectedVectorShape = null;
                    ResetVectorInteractionState();
                    isDrawing = false;
                    isMoving = false;
                    annotationToMove = null;
                    pdfViewer.Invalidate();
                    return;
                }

                if (TryHandleSelectedVectorShapeMouseDown(e.Location))
                {
                    selectedArrowObject = null;
                    ResetArrowInteractionState();
                    ClearArrowIconClickState();
                    selectedRasterObject = null;
                    ResetRasterInteractionState();
                    ClearRasterIconClickState();
                    selectedTextAnnotation = null;
                    arrowMouseActionInProgress = false;
                    rasterMouseActionInProgress = false;
                    isDrawing = false;
                    isMoving = false;
                    annotationToMove = null;
                    pdfViewer.Invalidate();
                    return;
                }

                if (TryHandleSelectedArrowMouseDown(e.Location))
                {
                    selectedTextAnnotation = null;
                    selectedRasterObject = null;
                    ResetRasterInteractionState();
                    selectedVectorShape = null;
                    ResetVectorInteractionState();
                    ClearArrowIconClickState();
                    arrowMouseActionInProgress = true;
                    arrowInteractionChanged = false;
                    isDrawing = false;
                    isMoving = false;
                    annotationToMove = null;
                    pdfViewer.Invalidate();
                    return;
                }

                if (TryHandleSelectedRasterMouseDown(e.Location))
                {
                    selectedArrowObject = null;
                    ResetArrowInteractionState();
                    ClearArrowIconClickState();
                    selectedVectorShape = null;
                    ResetVectorInteractionState();
                    selectedTextAnnotation = null;
                    rasterMouseActionInProgress = true;
                    isDrawing = false;
                    isMoving = false;
                    annotationToMove = null;
                    pdfViewer.Invalidate();
                    return;
                }

                if (TryHandleRasterIconMouseDown(e.Location))
                {
                    selectedArrowObject = null;
                    ResetArrowInteractionState();
                    ClearArrowIconClickState();
                    selectedVectorShape = null;
                    ResetVectorInteractionState();
                    ClearVectorIconClickState();
                    selectedTextAnnotation = null;
                    isDrawing = false;
                    isMoving = false;
                    annotationToMove = null;
                    pdfViewer.Invalidate();
                    return;
                }

                if (TryHandleArrowIconMouseDown(e.Location))
                {
                    selectedTextAnnotation = null;
                    selectedRasterObject = null;
                    ResetRasterInteractionState();
                    selectedVectorShape = null;
                    ResetVectorInteractionState();
                    ClearVectorIconClickState();
                    isDrawing = false;
                    isMoving = false;
                    annotationToMove = null;
                    pdfViewer.Invalidate();
                    return;
                }

                if (TryHandleVectorIconMouseDown(e.Location))
                {
                    selectedArrowObject = null;
                    ResetArrowInteractionState();
                    ClearArrowIconClickState();
                    selectedRasterObject = null;
                    ResetRasterInteractionState();
                    ClearRasterIconClickState();
                    selectedTextAnnotation = null;
                    isDrawing = false;
                    isMoving = false;
                    annotationToMove = null;
                    pdfViewer.Invalidate();
                    return;
                }

                bool advanceSelectionCycle = e.Clicks < 2;
                if (TryGetCycledSelectableObjectAtPoint(e.Location, dpiX, dpiY, advanceSelectionCycle, out object hitObject) &&
                    TryHandleCycledObjectMouseDown(hitObject, e.Location, e, dpiX, dpiY))
                {
                    isDrawing = false;
                    pdfViewer.Invalidate();
                    return;
                }

                ResetObjectSelectionCycle();
                selectedArrowObject = null;
                ResetArrowInteractionState();
                ClearArrowIconClickState();
                selectedVectorShape = null;
                ResetVectorInteractionState();
                selectedRasterObject = null;
                ResetRasterInteractionState();
                selectedTextAnnotation = null;
                annotationToMove = null;
                isMoving = false;
                textMoveMouseOffset = PointF.Empty;
                UpdateObjectSelectionInfoLabel();
                TryRestoreRedactionSelectionModeFromHitBlock(e.Location);
                isDrawing = true;
                if (IsRedactionSelectionModeEnabled())
                {
                    BeginUndoCapture(markerRadioButton.Checked ? "Add marker selection" : "Add box selection");
                }
                currentSelection = new System.Drawing.RectangleF(startPoint, Size.Empty);
                pdfViewer.Invalidate();
            }
        }

        private void OnMouseMove(object sender, MouseEventArgs e)
        {
            if (pdf == null)
            {
                return;
            }

            if (IsViewportPanningActive())
            {
                UpdateViewportPan();
                return;
            }

            if (IsCurrentPageMarkedForDeletion())
            {
                isDrawing = false;
                isMoving = false;
                annotationToMove = null;
                ResetTextRotationInteractionState();
                ResetRasterInteractionState();
                ResetArrowInteractionState();
                ResetVectorInteractionState();
                selectedVectorShape = null;
                ResetGroupMoveState();
                ResetCommentNoteMoveState();
                return;
            }

            if (isVectorShapeCreationMode)
            {
                PointF rawHover = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                vectorShapeDraftHoverPoint = NormalizeVectorShapeDraftInputPoint(rawHover);
                vectorShapeDraftHoverActive = true;
                pdfViewer.Invalidate();
                return;
            }

            if (isResizingCommentNote && commentNoteToResize != null)
            {
                if (commentNoteRectsDoc.Count == 0)
                {
                    RefreshCommentNoteLayoutCache();
                }

                PointF mouseDoc = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                float marginDoc = 6f;
                var pageSize = GetPageSizeWithOffset(commentNoteToResize.PageNumber);
                float maxWidth = Math.Max(40f, pageSize.Width - marginDoc - commentNoteResizeAnchorDoc.X);
                float maxHeight = Math.Max(12f, pageSize.Height - marginDoc - commentNoteResizeAnchorDoc.Y);
                float newWidth = Math.Max(40f, Math.Min(maxWidth, mouseDoc.X - commentNoteResizeAnchorDoc.X));
                float newHeight = Math.Max(12f, Math.Min(maxHeight, mouseDoc.Y - commentNoteResizeAnchorDoc.Y));

                if (!commentNoteToResize.NoteWidth.HasValue || !commentNoteToResize.NoteHeight.HasValue ||
                    Math.Abs(commentNoteToResize.NoteWidth.Value - newWidth) > 0.01f ||
                    Math.Abs(commentNoteToResize.NoteHeight.Value - newHeight) > 0.01f)
                {
                    commentNoteToResize.NoteWidth = newWidth;
                    commentNoteToResize.NoteHeight = newHeight;
                    commentNoteToResize.UpdatedAtUtc = DateTime.UtcNow;
                    commentNoteResizeChanged = true;
                }

                this.Cursor = Cursors.SizeNWSE;
                pdfViewer.Invalidate();
                return;
            }

            if (isMovingCommentNote && commentNoteToMove != null)
            {
                if (commentNoteRectsDoc.Count == 0)
                {
                    RefreshCommentNoteLayoutCache();
                }

                if (!commentNoteRectsDoc.TryGetValue(commentNoteToMove.Id, out RectangleF noteRectDoc))
                {
                    noteRectDoc = new RectangleF(0f, 0f, 80f, 14f);
                }

                PointF mouseDoc = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                float newX = mouseDoc.X - commentNoteMoveOffsetDoc.X;
                float newY = mouseDoc.Y - commentNoteMoveOffsetDoc.Y;

                var pageSize = GetPageSizeWithOffset(commentNoteToMove.PageNumber);
                float marginDoc = 6f;
                float maxX = Math.Max(marginDoc, pageSize.Width - marginDoc - noteRectDoc.Width);
                float maxY = Math.Max(marginDoc, pageSize.Height - marginDoc - noteRectDoc.Height);
                newX = Math.Max(marginDoc, Math.Min(maxX, newX));
                newY = Math.Max(marginDoc, Math.Min(maxY, newY));

                if (!commentNoteToMove.NoteX.HasValue || !commentNoteToMove.NoteY.HasValue ||
                    Math.Abs(commentNoteToMove.NoteX.Value - newX) > 0.01f ||
                    Math.Abs(commentNoteToMove.NoteY.Value - newY) > 0.01f)
                {
                    commentNoteToMove.NoteX = newX;
                    commentNoteToMove.NoteY = newY;
                    commentNoteToMove.UpdatedAtUtc = DateTime.UtcNow;
                    commentNoteMoveChanged = true;
                }

                this.Cursor = Cursors.SizeAll;
                pdfViewer.Invalidate();
                return;
            }

            if (isScalingObjectGroup)
            {
                TryApplyGroupScaleFromMouse(e.Location);
                return;
            }

            if (isMovingObjectGroup)
            {
                PointF mouseDoc = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                float dx = mouseDoc.X - groupMoveStartMouseDoc.X;
                float dy = mouseDoc.Y - groupMoveStartMouseDoc.Y;

                if (snapToGridEnabled)
                {
                    float snappedLeft = SnapValueToGrid(groupMoveInitialBounds.X + dx, SnapGridStep);
                    float snappedTop = SnapValueToGrid(groupMoveInitialBounds.Y + dy, SnapGridStep);
                    dx = snappedLeft - groupMoveInitialBounds.X;
                    dy = snappedTop - groupMoveInitialBounds.Y;
                }

                dx = Math.Max(groupMoveMinDx, Math.Min(groupMoveMaxDx, dx));
                dy = Math.Max(groupMoveMinDy, Math.Min(groupMoveMaxDy, dy));
                if (Math.Abs(dx) > 0.001f || Math.Abs(dy) > 0.001f)
                {
                    groupMoveChanged = true;
                }

                foreach (GroupMoveEntry entry in groupMoveEntries)
                {
                    switch (entry.Type)
                    {
                        case GroupMoveObjectType.Text:
                            if (entry.Text != null)
                            {
                                entry.Text.AnnotationBounds = new RectangleF(
                                    entry.Bounds.X + dx,
                                    entry.Bounds.Y + dy,
                                    entry.Bounds.Width,
                                    entry.Bounds.Height);
                                if (entry.Text.HasLeaderArrow)
                                {
                                    entry.Text.LeaderEndPoint = new PointF(
                                        entry.TextLeaderEndPoint.X + dx,
                                        entry.TextLeaderEndPoint.Y + dy);
                                }
                                TouchTextAnnotation(entry.Text);
                            }
                            break;
                        case GroupMoveObjectType.Raster:
                            if (entry.Raster != null)
                            {
                                entry.Raster.Bounds = new RectangleF(
                                    entry.Bounds.X + dx,
                                    entry.Bounds.Y + dy,
                                    entry.Bounds.Width,
                                    entry.Bounds.Height);
                                entry.Raster.UpdatedAtUtc = DateTime.UtcNow;
                            }
                            break;
                        case GroupMoveObjectType.Arrow:
                            if (entry.Arrow != null)
                            {
                                entry.Arrow.Start = new PointF(entry.Start.X + dx, entry.Start.Y + dy);
                                entry.Arrow.End = new PointF(entry.End.X + dx, entry.End.Y + dy);
                                entry.Arrow.UpdatedAtUtc = DateTime.UtcNow;
                            }
                            break;
                        case GroupMoveObjectType.VectorShape:
                            if (entry.VectorShape != null && entry.Points != null)
                            {
                                entry.VectorShape.Points = entry.Points
                                    .Select(point => new PointF(point.X + dx, point.Y + dy))
                                    .ToList();
                                entry.VectorShape.UpdatedAtUtc = DateTime.UtcNow;
                            }
                            break;
                    }
                }

                this.Cursor = Cursors.SizeAll;
                pdfViewer.Invalidate();
                return;
            }

            if (isRotatingTextAnnotation && annotationToRotate != null)
            {
                float dpiX;
                float dpiY;
                using (Graphics g = pdfViewer.CreateGraphics())
                {
                    dpiX = g.DpiX;
                    dpiY = g.DpiY;
                }

                PointF center = GetAnnotationScreenCenter(annotationToRotate, dpiX, dpiY);
                if (TryGetAnnotationTextFrameGeometry(
                        annotationToRotate,
                        dpiX,
                        dpiY,
                        out _,
                        out _,
                        out PointF frameCenter,
                        out _))
                {
                    center = frameCenter;
                }
                float currentAngle = GetAngleDegrees(center, e.Location);
                float delta = NormalizeAngleDelta(currentAngle - textRotationStartAngle);
                int updatedRotation = NormalizeRotation(textRotationStartValue + (int)Math.Round(delta));
                int previousRotation = NormalizeRotation(annotationToRotate.AnnotationRotation);
                annotationToRotate.AnnotationRotation = updatedRotation;
                SizeF contentSize = IsRichTextMode(annotationToRotate)
                    ? GetRichAnnotationContentSize(annotationToRotate.AnnotationText, annotationToRotate.AnnotationRichText, annotationToRotate.AnnotationFont)
                    : GetAnnotationPlainContentSize(annotationToRotate.AnnotationText, annotationToRotate.AnnotationFont);
                SizeF rotatedSize = GetAnnotationOuterSizeFromContent(
                    contentSize,
                    annotationToRotate.AnnotationBorderWidth,
                    annotationToRotate.AnnotationFrameMargin,
                    updatedRotation);
                annotationToRotate.AnnotationBounds = new RectangleF(
                    textRotationStartCenterDoc.X - (rotatedSize.Width / 2f),
                    textRotationStartCenterDoc.Y - (rotatedSize.Height / 2f),
                    rotatedSize.Width,
                    rotatedSize.Height);
                if (annotationToRotate.HasLeaderArrow)
                {
                    annotationToRotate.LeaderAnchorKind = GetClosestTextLeaderAnchorKind(annotationToRotate, annotationToRotate.LeaderEndPoint);
                }
                TouchTextAnnotation(annotationToRotate);
                if (updatedRotation != previousRotation)
                {
                    textRotationInteractionChanged = true;
                }

                this.Cursor = Cursors.Hand;
                pdfViewer.Invalidate();
                return;
            }

            if (isScalingTextAnnotation && annotationToScale != null)
            {
                TryApplyTextScaleFromMouse(e.Location);
                return;
            }

            if (isDraggingTextLeaderHandle && annotationToAdjustLeader != null)
            {
                TryApplyTextLeaderDragFromMouse(e.Location);
                return;
            }

            if (isAdjustingArrowHandle && arrowObjectToAdjust != null && arrowHandleType != ArrowHandleType.None)
            {
                PointF mousePoint = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                mousePoint = SnapPointToGrid(mousePoint);
                if (arrowHandleType == ArrowHandleType.Start)
                {
                    arrowObjectToAdjust.Start = mousePoint;
                }
                else if (arrowHandleType == ArrowHandleType.End)
                {
                    arrowObjectToAdjust.End = mousePoint;
                }

                ConstrainArrowToPage(arrowObjectToAdjust);
                arrowObjectToAdjust.Thickness = NormalizeArrowThickness(arrowObjectToAdjust.Thickness);
                arrowObjectToAdjust.BorderWidth = NormalizeArrowBorderWidth(arrowObjectToAdjust.BorderWidth);
                arrowObjectToAdjust.HeadLength = NormalizeArrowHeadLength(arrowObjectToAdjust.HeadLength);
                arrowObjectToAdjust.HeadWidth = NormalizeArrowHeadWidth(arrowObjectToAdjust.HeadWidth);
                arrowObjectToAdjust.UpdatedAtUtc = DateTime.UtcNow;
                arrowInteractionChanged = true;
                this.Cursor = GetArrowHandleCursor(arrowObjectToAdjust, arrowHandleType);
                pdfViewer.Invalidate();
                return;
            }

            if (isScalingArrowObject && arrowObjectToScale != null)
            {
                TryApplyArrowScaleFromMouse(e.Location);
                return;
            }

            if (isMovingArrowObject && arrowObjectToMove != null)
            {
                PointF mouseDoc = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                float dx = mouseDoc.X - arrowMoveStartMouseDoc.X;
                float dy = mouseDoc.Y - arrowMoveStartMouseDoc.Y;

                if (snapToGridEnabled)
                {
                    float snappedStartX = SnapValueToGrid(arrowMoveInitialStart.X + dx, SnapGridStep);
                    float snappedStartY = SnapValueToGrid(arrowMoveInitialStart.Y + dy, SnapGridStep);
                    dx = snappedStartX - arrowMoveInitialStart.X;
                    dy = snappedStartY - arrowMoveInitialStart.Y;
                }

                var pageSize = GetPageSizeWithOffset(arrowObjectToMove.PageNumber);
                if (pageSize.Width > 0f && pageSize.Height > 0f)
                {
                    float minBaseX = Math.Min(arrowMoveInitialStart.X, arrowMoveInitialEnd.X);
                    float maxBaseX = Math.Max(arrowMoveInitialStart.X, arrowMoveInitialEnd.X);
                    float minBaseY = Math.Min(arrowMoveInitialStart.Y, arrowMoveInitialEnd.Y);
                    float maxBaseY = Math.Max(arrowMoveInitialStart.Y, arrowMoveInitialEnd.Y);

                    float minDx = -minBaseX;
                    float maxDx = pageSize.Width - maxBaseX;
                    float minDy = -minBaseY;
                    float maxDy = pageSize.Height - maxBaseY;

                    dx = Math.Max(minDx, Math.Min(maxDx, dx));
                    dy = Math.Max(minDy, Math.Min(maxDy, dy));
                }

                PointF nextStart = new PointF(arrowMoveInitialStart.X + dx, arrowMoveInitialStart.Y + dy);
                PointF nextEnd = new PointF(arrowMoveInitialEnd.X + dx, arrowMoveInitialEnd.Y + dy);
                arrowObjectToMove.Start = nextStart;
                arrowObjectToMove.End = nextEnd;
                arrowObjectToMove.UpdatedAtUtc = DateTime.UtcNow;
                arrowInteractionChanged = true;
                this.Cursor = Cursors.SizeAll;
                pdfViewer.Invalidate();
                return;
            }

            if (isRotatingRasterObject && rasterObjectToRotate != null)
            {
                PointF center = GetRasterObjectScreenCenter(rasterObjectToRotate);
                float currentAngle = GetAngleDegrees(center, e.Location);
                float delta = NormalizeAngleDelta(currentAngle - rasterRotationStartAngle);
                rasterObjectToRotate.Rotation = NormalizeRotation(rasterRotationStartValue + (int)Math.Round(delta));
                ConstrainRasterObjectToPage(rasterObjectToRotate);
                rasterObjectToRotate.UpdatedAtUtc = DateTime.UtcNow;
                if (HasPositiveSize(rasterRotateStartBounds))
                {
                    PointF centerDoc = new PointF(
                        rasterRotateStartBounds.X + (rasterRotateStartBounds.Width / 2f),
                        rasterRotateStartBounds.Y + (rasterRotateStartBounds.Height / 2f));
                    ApplyRasterRotateAttachedClipDelta(delta, centerDoc);
                }
                pdfViewer.Invalidate();
                return;
            }

            if (isResizingRasterObject && rasterObjectToResize != null && rasterResizeHandle != RasterResizeHandleType.None)
            {
                this.Cursor = GetCursorForRasterResizeHandle(rasterResizeHandle, rasterObjectToResize.Rotation);
                PointF mousePoint = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                if (snapToGridEnabled)
                {
                    mousePoint = SnapPointToGrid(mousePoint);
                }
                float minWidth = 10f;
                float minHeight = 10f;
                RectangleF bounds = rasterObjectToResize.Bounds;
                bool cornerHandle =
                    rasterResizeHandle == RasterResizeHandleType.TopLeft ||
                    rasterResizeHandle == RasterResizeHandleType.TopRight ||
                    rasterResizeHandle == RasterResizeHandleType.BottomRight ||
                    rasterResizeHandle == RasterResizeHandleType.BottomLeft;
                bool symmetricResize = (Control.ModifierKeys & Keys.Alt) == Keys.Alt;

                if (symmetricResize)
                {
                    PointF center = new PointF(bounds.X + (bounds.Width / 2f), bounds.Y + (bounds.Height / 2f));
                    PointF deltaPoint = new PointF(mousePoint.X - center.X, mousePoint.Y - center.Y);
                    PointF local = RotateVector(deltaPoint, -NormalizeRotation(rasterObjectToResize.Rotation));
                    float newWidth = bounds.Width;
                    float newHeight = bounds.Height;

                    switch (rasterResizeHandle)
                    {
                        case RasterResizeHandleType.Left:
                        case RasterResizeHandleType.Right:
                            newWidth = Math.Max(minWidth, 2f * Math.Abs(local.X));
                            break;
                        case RasterResizeHandleType.Top:
                        case RasterResizeHandleType.Bottom:
                            newHeight = Math.Max(minHeight, 2f * Math.Abs(local.Y));
                            break;
                        default:
                            newWidth = Math.Max(minWidth, 2f * Math.Abs(local.X));
                            newHeight = Math.Max(minHeight, 2f * Math.Abs(local.Y));
                            break;
                    }

                    if (cornerHandle)
                    {
                        float aspect = bounds.Height <= 0f ? 1f : (bounds.Width / bounds.Height);
                        if (aspect <= 0f)
                        {
                            aspect = 1f;
                        }

                        float widthFromHeight = newHeight * aspect;
                        float heightFromWidth = newWidth / aspect;
                        if (widthFromHeight > newWidth)
                        {
                            newWidth = widthFromHeight;
                        }
                        else
                        {
                            newHeight = heightFromWidth;
                        }
                    }

                    rasterObjectToResize.Bounds = new RectangleF(
                        center.X - (newWidth / 2f),
                        center.Y - (newHeight / 2f),
                        newWidth,
                        newHeight);
                }
                else
                {
                    RectangleF baseBounds = HasPositiveSize(rasterResizeStartBounds) ? rasterResizeStartBounds : bounds;
                    int baseRotation = NormalizeRotation(rasterResizeStartRotation);
                    if (baseRotation != NormalizeRotation(rasterObjectToResize.Rotation))
                    {
                        baseRotation = NormalizeRotation(rasterObjectToResize.Rotation);
                    }

                    float width = baseBounds.Width;
                    float height = baseBounds.Height;
                    PointF sign = GetRasterResizeSign(rasterResizeHandle);
                    PointF anchorWorld = rasterResizeAnchorWorld;
                    if (!HasPositiveSize(rasterResizeStartBounds))
                    {
                        RasterResizeHandleType oppositeHandle = GetOppositeRasterResizeHandle(rasterResizeHandle);
                        anchorWorld = GetRasterResizeHandleWorldPoint(baseBounds, baseRotation, oppositeHandle);
                    }

                    PointF anchorLocalAbs = RotateVector(anchorWorld, -baseRotation);
                    PointF dragLocalAbs = RotateVector(mousePoint, -baseRotation);

                    switch (rasterResizeHandle)
                    {
                        case RasterResizeHandleType.Left:
                        case RasterResizeHandleType.Right:
                            dragLocalAbs.Y = anchorLocalAbs.Y;
                            width = Math.Max(minWidth, Math.Abs(dragLocalAbs.X - anchorLocalAbs.X));
                            break;
                        case RasterResizeHandleType.Top:
                        case RasterResizeHandleType.Bottom:
                            dragLocalAbs.X = anchorLocalAbs.X;
                            height = Math.Max(minHeight, Math.Abs(dragLocalAbs.Y - anchorLocalAbs.Y));
                            break;
                        default:
                            width = Math.Max(minWidth, Math.Abs(dragLocalAbs.X - anchorLocalAbs.X));
                            height = Math.Max(minHeight, Math.Abs(dragLocalAbs.Y - anchorLocalAbs.Y));
                            break;
                    }

                    if (cornerHandle)
                    {
                        float aspect = baseBounds.Height <= 0f ? 1f : (baseBounds.Width / baseBounds.Height);
                        if (aspect <= 0f)
                        {
                            aspect = 1f;
                        }

                        float widthFromHeight = height * aspect;
                        float heightFromWidth = width / aspect;
                        if (widthFromHeight > width)
                        {
                            width = widthFromHeight;
                        }
                        else
                        {
                            height = heightFromWidth;
                        }
                    }

                    float dragX = anchorLocalAbs.X;
                    float dragY = anchorLocalAbs.Y;
                    switch (rasterResizeHandle)
                    {
                        case RasterResizeHandleType.Left:
                        case RasterResizeHandleType.Right:
                            dragX = anchorLocalAbs.X + (sign.X * width);
                            dragY = anchorLocalAbs.Y;
                            break;
                        case RasterResizeHandleType.Top:
                        case RasterResizeHandleType.Bottom:
                            dragX = anchorLocalAbs.X;
                            dragY = anchorLocalAbs.Y + (sign.Y * height);
                            break;
                        default:
                            dragX = anchorLocalAbs.X + (sign.X * width);
                            dragY = anchorLocalAbs.Y + (sign.Y * height);
                            break;
                    }

                    PointF centerLocalAbs = new PointF(
                        (anchorLocalAbs.X + dragX) / 2f,
                        (anchorLocalAbs.Y + dragY) / 2f);
                    PointF centerWorld = RotateVector(centerLocalAbs, baseRotation);

                    rasterObjectToResize.Bounds = new RectangleF(
                        centerWorld.X - (width / 2f),
                        centerWorld.Y - (height / 2f),
                        width,
                        height);
                }

                ConstrainRasterObjectToPage(rasterObjectToResize);
                rasterObjectToResize.UpdatedAtUtc = DateTime.UtcNow;
                pdfViewer.Invalidate();
                return;
            }

            if (isMovingRasterObject && rasterObjectToMove != null)
            {
                RectangleF bounds = rasterObjectToMove.Bounds;
                PointF mouseDoc = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                float newX = mouseDoc.X - rasterMoveMouseOffset.X;
                float newY = mouseDoc.Y - rasterMoveMouseOffset.Y;
                if (snapToGridEnabled)
                {
                    newX = SnapValueToGrid(newX, SnapGridStep);
                    newY = SnapValueToGrid(newY, SnapGridStep);
                }
                rasterObjectToMove.Bounds = new RectangleF(newX, newY, bounds.Width, bounds.Height);
                ConstrainRasterObjectToPage(rasterObjectToMove);
                rasterObjectToMove.UpdatedAtUtc = DateTime.UtcNow;
                if (HasPositiveSize(rasterMoveStartBounds))
                {
                    float appliedDx = rasterObjectToMove.Bounds.X - rasterMoveStartBounds.X;
                    float appliedDy = rasterObjectToMove.Bounds.Y - rasterMoveStartBounds.Y;
                    ApplyRasterMoveAttachedClipDelta(appliedDx, appliedDy);
                }
                pdfViewer.Invalidate();
                return;
            }

            if (isRotatingVectorShape &&
                vectorShapeToRotate != null &&
                vectorRotateInitialPoints != null &&
                vectorRotateInitialPoints.Count > 0)
            {
                PointF centerScreen = new PointF(vectorRotateCenterDoc.X * scaleFactor, vectorRotateCenterDoc.Y * scaleFactor);
                float currentAngle = GetAngleDegrees(centerScreen, e.Location);
                float deltaDegrees = NormalizeAngleDelta(currentAngle - vectorRotationStartAngle);
                float radians = (float)(Math.PI * deltaDegrees / 180.0);
                float cos = (float)Math.Cos(radians);
                float sin = (float)Math.Sin(radians);

                var rotatedPoints = new List<PointF>(vectorRotateInitialPoints.Count);
                foreach (PointF point in vectorRotateInitialPoints)
                {
                    float localX = point.X - vectorRotateCenterDoc.X;
                    float localY = point.Y - vectorRotateCenterDoc.Y;
                    float rotatedX = (localX * cos) - (localY * sin);
                    float rotatedY = (localX * sin) + (localY * cos);
                    rotatedPoints.Add(new PointF(
                        vectorRotateCenterDoc.X + rotatedX,
                        vectorRotateCenterDoc.Y + rotatedY));
                }

                vectorShapeToRotate.Points = rotatedPoints;
                vectorShapeToRotate.UpdatedAtUtc = DateTime.UtcNow;
                vectorInteractionChanged = vectorInteractionChanged || Math.Abs(deltaDegrees) > 0.05f;
                this.Cursor = Cursors.Hand;
                pdfViewer.Invalidate();
                return;
            }

            if (isScalingVectorShape && vectorShapeToScale != null)
            {
                TryApplyVectorScaleFromMouse(e.Location);
                return;
            }

            if (isMovingVectorShape && vectorShapeToMove != null)
            {
                PointF mouseDoc = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                float dx = mouseDoc.X - vectorMoveStartMouseDoc.X;
                float dy = mouseDoc.Y - vectorMoveStartMouseDoc.Y;

                RectangleF initialBounds = GetVectorShapeBounds(vectorMoveInitialPoints);
                if (snapToGridEnabled && !initialBounds.IsEmpty)
                {
                    float snappedLeft = SnapValueToGrid(initialBounds.Left + dx, SnapGridStep);
                    float snappedTop = SnapValueToGrid(initialBounds.Top + dy, SnapGridStep);
                    dx = snappedLeft - initialBounds.Left;
                    dy = snappedTop - initialBounds.Top;
                }

                var pageSize = GetPageSizeWithOffset(vectorShapeToMove.PageNumber);
                if (pageSize.Width > 0f && pageSize.Height > 0f && !initialBounds.IsEmpty)
                {
                    float minDx = -initialBounds.Left;
                    float maxDx = pageSize.Width - initialBounds.Right;
                    float minDy = -initialBounds.Top;
                    float maxDy = pageSize.Height - initialBounds.Bottom;
                    dx = Math.Max(minDx, Math.Min(maxDx, dx));
                    dy = Math.Max(minDy, Math.Min(maxDy, dy));
                }

                vectorShapeToMove.Points = vectorMoveInitialPoints
                    .Select(point => new PointF(point.X + dx, point.Y + dy))
                    .ToList();
                vectorShapeToMove.UpdatedAtUtc = DateTime.UtcNow;
                vectorInteractionChanged = vectorInteractionChanged || Math.Abs(dx) > 0.001f || Math.Abs(dy) > 0.001f;
                this.Cursor = Cursors.SizeAll;
                pdfViewer.Invalidate();
                return;
            }

            if (isAdjustingVectorHandle &&
                vectorShapeToAdjust != null &&
                vectorHandlePointIndex >= 0 &&
                vectorMoveInitialPoints != null &&
                vectorMoveInitialPoints.Count > vectorHandlePointIndex)
            {
                PointF updatedPoint = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                if (snapToGridEnabled)
                {
                    updatedPoint.X = SnapValueToGrid(updatedPoint.X, SnapGridStep);
                    updatedPoint.Y = SnapValueToGrid(updatedPoint.Y, SnapGridStep);
                }

                var pageSize = GetPageSizeWithOffset(vectorShapeToAdjust.PageNumber);
                if (pageSize.Width > 0f && pageSize.Height > 0f)
                {
                    updatedPoint = new PointF(
                        Math.Max(0f, Math.Min(pageSize.Width, updatedPoint.X)),
                        Math.Max(0f, Math.Min(pageSize.Height, updatedPoint.Y)));
                }

                List<PointF> updatedPoints = vectorMoveInitialPoints.Select(p => p).ToList();
                updatedPoints[vectorHandlePointIndex] = updatedPoint;

                VectorShapeType shapeType = ParseVectorShapeType(vectorShapeToAdjust.ShapeType);
                if ((Control.ModifierKeys & Keys.Alt) == Keys.Alt &&
                    IsTwoPointConstrainedShape(shapeType) &&
                    updatedPoints.Count >= 2)
                {
                    if (vectorHandlePointIndex == 1)
                    {
                        updatedPoints[1] = ApplyAltConstraintToSecondPoint(shapeType, updatedPoints[0], updatedPoints[1]);
                    }
                    else if (vectorHandlePointIndex == 0)
                    {
                        updatedPoints[0] = ApplyAltConstraintToSecondPoint(shapeType, updatedPoints[1], updatedPoints[0]);
                    }
                }

                if (pageSize.Width > 0f && pageSize.Height > 0f)
                {
                    PointF constrainedPoint = updatedPoints[vectorHandlePointIndex];
                    updatedPoints[vectorHandlePointIndex] = new PointF(
                        Math.Max(0f, Math.Min(pageSize.Width, constrainedPoint.X)),
                        Math.Max(0f, Math.Min(pageSize.Height, constrainedPoint.Y)));
                }

                vectorShapeToAdjust.Points = updatedPoints;
                vectorShapeToAdjust.UpdatedAtUtc = DateTime.UtcNow;
                PointF initialPoint = vectorMoveInitialPoints[vectorHandlePointIndex];
                PointF currentPoint = updatedPoints[vectorHandlePointIndex];
                vectorInteractionChanged = vectorInteractionChanged ||
                                           Math.Abs(initialPoint.X - currentPoint.X) > 0.001f ||
                                           Math.Abs(initialPoint.Y - currentPoint.Y) > 0.001f;
                this.Cursor = GetVectorHandleCursor(vectorShapeToAdjust, vectorHandlePointIndex);
                pdfViewer.Invalidate();
                return;
            }

            if (Control.MouseButtons == MouseButtons.None)
            {
                if (isCommentCreationMode || IsRedactionSelectionModeEnabled())
                {
                    UpdatePdfViewerToolCursor();
                }
                else
                {
                    float dpiX;
                    float dpiY;
                    using (Graphics g = pdfViewer.CreateGraphics())
                    {
                        dpiX = g.DpiX;
                        dpiY = g.DpiY;
                    }

                    float docX = e.X / scaleFactor;
                    float docY = e.Y / scaleFactor;
                    bool overCommentNote = TryGetCommentAtPoint(e.Location, out CommentAnnotation hoverComment, out RectangleF hoverNoteRect) &&
                        hoverComment != null &&
                        !hoverNoteRect.IsEmpty &&
                        hoverNoteRect.Contains(docX, docY);

                    if (overCommentNote)
                    {
                        this.Cursor = IsPointInCommentResizeHandle(e.Location, hoverNoteRect)
                            ? Cursors.SizeNWSE
                            : Cursors.SizeAll;
                    }
                    else if (!TryUpdateGroupHoverCursor(e.Location, dpiX, dpiY) &&
                        !TryUpdateTextHoverCursor(e.Location, dpiX, dpiY) &&
                        !TryUpdateVectorHoverCursor(e.Location) &&
                        !TryUpdateArrowHoverCursor(e.Location) &&
                        !TryUpdateRasterHoverCursor(e.Location))
                    {
                        this.Cursor = Cursors.Default;
                    }

                    SyncPdfViewerCursorWithFormCursor();
                }
            }

            if (isDrawing)
            {
                float x = Math.Min(startPoint.X, e.X);
                float y;
                float width = Math.Abs(e.X - startPoint.X);
                float height;
                bool useMarkerStyle = markerRadioButton.Checked || isCommentCreationMode;
                if (useMarkerStyle)
                {
                    bool markerCtrlBoxMode = (Control.ModifierKeys & Keys.Control) == Keys.Control;
                    isMarkerCtrlBoxMode = markerCtrlBoxMode;
                    if (markerCtrlBoxMode)
                    {
                        y = Math.Min(startPoint.Y, e.Y);
                        height = Math.Abs(e.Y - startPoint.Y);
                    }
                    else
                    {
                        float deltaX = e.X - startPoint.X;
                        float deltaY = e.Y - startPoint.Y;
                        bool markerVerticalMode = IsMarkerVerticalByDrag(deltaX, deltaY);
                        if (markerVerticalMode)
                        {
                            x = startPoint.X - (markerWidth * scaleFactor / 2f);
                            width = markerWidth * scaleFactor;
                            y = Math.Min(startPoint.Y, e.Y);
                            height = Math.Abs(e.Y - startPoint.Y);
                        }
                        else
                        {
                            y = (startPoint.Y - (markerWidth * scaleFactor / 2));
                            height = (markerWidth * scaleFactor);
                        }
                    }
                }
                else
                {
                    isMarkerCtrlBoxMode = false;
                    y = Math.Min(startPoint.Y, e.Y);
                    height = Math.Abs(e.Y - startPoint.Y);
                }
                currentSelection = new System.Drawing.RectangleF(x, y, width, height);
                pdfViewer.Invalidate();
            } else if (isMoving && !isClickOnIcon)
            {
                if (annotationToMove != null && !IsTextAnnotationEffectivelyLocked(annotationToMove))
                {
                    // Get current annotation Bounds (in "scaled" units, i.e. independent of zoom)
                    RectangleF bounds = annotationToMove.AnnotationBounds;

                    // Calculate new position in units before scaling (e.g. PDF points)
                    PointF mouseDoc = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                    float newX = mouseDoc.X - textMoveMouseOffset.X;
                    float newY = mouseDoc.Y - textMoveMouseOffset.Y;
                    if (snapToGridEnabled)
                    {
                        newX = SnapValueToGrid(newX, SnapGridStep);
                        newY = SnapValueToGrid(newY, SnapGridStep);
                    }

                    // Pobierz DPI z pdfViewer
                    float dpiX, dpiY;
                    using (Graphics g = pdfViewer.CreateGraphics())
                    {
                        dpiX = g.DpiX;
                        dpiY = g.DpiY;
                    }

                    // Pobierz rozmiary obszaru pdfViewer (w pikselach)
                    float clientWidth = pdfViewer.ClientSize.Width;
                    float clientHeight = pdfViewer.ClientSize.Height;

                    // Limit so annotation doesn't go beyond left and right edge
                    if (newX < - (bounds.Width * 72f / dpiX / 2))
                    {
                        newX = -bounds.Width * 72f / dpiX / 2;
                    }
                    else if (newX > clientWidth / scaleFactor - bounds.Width * 72f / dpiX / 2)
                    {
                        newX = clientWidth / scaleFactor - bounds.Width * 72f / dpiX / 2;
                    }

                    if (newY < -bounds.Height * 72f / dpiX / 2)
                    {
                        newY = -bounds.Height * 72f / dpiX / 2;
                    }
                    else if (newY > clientHeight / scaleFactor - bounds.Height * 72f / dpiX / 2)
                    {
                        newY = clientHeight / scaleFactor - bounds.Height * 72f / dpiX / 2;
                    }

                    // Update annotation position
                    float deltaX = newX - bounds.X;
                    float deltaY = newY - bounds.Y;
                    annotationToMove.AnnotationBounds = new RectangleF(newX, newY, bounds.Width, bounds.Height);
                    if (annotationToMove.HasLeaderArrow)
                    {
                        annotationToMove.LeaderEndPoint = new PointF(
                            annotationToMove.LeaderEndPoint.X + deltaX,
                            annotationToMove.LeaderEndPoint.Y + deltaY);
                    }
                    TouchTextAnnotation(annotationToMove);
                    pdfViewer.Invalidate();
                }

            }
        }


        private void OnMouseUp(object sender, MouseEventArgs e)
        {
            if (pdf == null)
                return;

            if (e.Button == MouseButtons.Middle || (e.Button == MouseButtons.Right && isRightMousePanning))
            {
                EndViewportPan();
                return;
            }

            if (isVectorShapeCreationMode)
            {
                return;
            }

            if (e.Button == MouseButtons.Left && suppressNextLeftMouseUpAfterEscape)
            {
                suppressNextLeftMouseUpAfterEscape = false;
                CancelUndoCapture();
                isDrawing = false;
                isMarkerCtrlBoxMode = false;
                currentSelection = RectangleF.Empty;
                if (!IsViewportPanningActive() && !isVectorShapeCreationMode && !isCommentCreationMode)
                {
                    this.Cursor = Cursors.Default;
                }
                pdfViewer.Invalidate();
                return;
            }

             
            //if ((string)filterComboBox.SelectedItem == allComboItem)
            //{
            

            PageItemStatus status = allPageStatuses[currentPage - 1];
            if (IsCurrentPageMarkedForDeletion() && (e.Button == MouseButtons.Left || e.Button == MouseButtons.Right))
            {
                isDrawing = false;
                isMoving = false;
                annotationToMove = null;
                textMoveMouseOffset = PointF.Empty;
                ResetTextRotationInteractionState();
                ResetRasterInteractionState();
                ResetArrowInteractionState();
                ResetVectorInteractionState();
                selectedVectorShape = null;
                ResetGroupMoveState();
                ResetCommentNoteMoveState();
                currentSelection = RectangleF.Empty;
                isClickOnIcon = false;
                clickedIconType = IconType.None;
                annotationForIcon = null;
                ClearRasterIconClickState();
                ClearArrowIconClickState();
                ClearVectorIconClickState();
                pdfViewer.Invalidate();
                return;
            }


            if (e.Button == MouseButtons.Left)
            {
                if (isResizingCommentNote)
                {
                    bool changed = commentNoteResizeChanged;
                    ResetCommentNoteMoveState();
                    this.Cursor = Cursors.Default;
                    if (changed)
                    {
                        projectWasChangedAfterLastSave = true;
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                        commentNoteRectsDoc.Clear();
                    }
                    pdfViewer.Invalidate();
                    return;
                }

                if (isMovingCommentNote)
                {
                    bool changed = commentNoteMoveChanged;
                    ResetCommentNoteMoveState();
                    this.Cursor = Cursors.Default;
                    if (changed)
                    {
                        projectWasChangedAfterLastSave = true;
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                        commentNoteRectsDoc.Clear();
                    }
                    pdfViewer.Invalidate();
                    return;
                }

                if (isMovingObjectGroup)
                {
                    bool changed = groupMoveChanged;
                    ResetGroupMoveState();
                    this.Cursor = Cursors.Default;
                    if (changed)
                    {
                        projectWasChangedAfterLastSave = true;
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                        InvalidateThumbnailPage(currentPage);
                    }
                    pdfViewer.Invalidate();
                    return;
                }

                if (isScalingObjectGroup)
                {
                    bool changed = groupScaleChanged;
                    ResetGroupMoveState();
                    this.Cursor = Cursors.Default;
                    if (changed)
                    {
                        projectWasChangedAfterLastSave = true;
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                        InvalidateThumbnailPage(currentPage);
                    }
                    pdfViewer.Invalidate();
                    return;
                }

                if (arrowMouseActionInProgress)
                {
                    bool changed = arrowInteractionChanged;
                    ResetArrowInteractionState();
                    this.Cursor = Cursors.Default;
                    if (changed)
                    {
                        projectWasChangedAfterLastSave = true;
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                        InvalidateThumbnailPage(currentPage);
                    }
                    pdfViewer.Invalidate();
                    return;
                }

                if (rasterMouseActionInProgress)
                {
                    bool changed = isMovingRasterObject || isRotatingRasterObject || isResizingRasterObject;
                    ResetRasterInteractionState();
                    this.Cursor = Cursors.Default;
                    if (changed)
                    {
                        projectWasChangedAfterLastSave = true;
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                        InvalidateThumbnailPage(currentPage);
                    }
                    pdfViewer.Invalidate();
                    return;
                }

                if (vectorMouseActionInProgress)
                {
                    bool changed = vectorInteractionChanged;
                    ResetVectorInteractionState();
                    this.Cursor = Cursors.Default;
                    if (changed)
                    {
                        projectWasChangedAfterLastSave = true;
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                        InvalidateThumbnailPage(currentPage);
                    }
                    pdfViewer.Invalidate();
                    return;
                }

                if (isRotatingTextAnnotation)
                {
                    bool changed = textRotationInteractionChanged;
                    ResetTextRotationInteractionState();
                    this.Cursor = Cursors.Default;
                    if (changed)
                    {
                        projectWasChangedAfterLastSave = true;
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                        InvalidateThumbnailPage(currentPage);
                    }
                    pdfViewer.Invalidate();
                    return;
                }

                if (isScalingTextAnnotation)
                {
                    bool changed = textRotationInteractionChanged;
                    ResetTextRotationInteractionState();
                    this.Cursor = Cursors.Default;
                    if (changed)
                    {
                        projectWasChangedAfterLastSave = true;
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                        InvalidateThumbnailPage(currentPage);
                    }
                    pdfViewer.Invalidate();
                    return;
                }

                if (isDraggingTextLeaderHandle)
                {
                    bool changed = textRotationInteractionChanged;
                    ResetTextRotationInteractionState();
                    this.Cursor = Cursors.Default;
                    if (changed)
                    {
                        projectWasChangedAfterLastSave = true;
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                        InvalidateThumbnailPage(currentPage);
                    }
                    pdfViewer.Invalidate();
                    return;
                }

                if (isClickOnRasterIcon && rasterObjectForIcon != null)
                {
                    BeginUndoCapture("Edit object");
                    switch (clickedRasterIconType)
                    {
                        case RasterIconType.Edit:
                            EditRasterObject(rasterObjectForIcon);
                            break;
                        case RasterIconType.Lock:
                            if (EnsureCurrentPageEditable(true))
                            {
                                rasterObjectForIcon.IsLocked = !rasterObjectForIcon.IsLocked;
                                rasterObjectForIcon.UpdatedAtUtc = DateTime.UtcNow;
                                projectWasChangedAfterLastSave = true;
                                saveProjectButton.Enabled = true;
                                saveProjectMenuItem.Enabled = true;
                                string msg = rasterObjectForIcon.IsLocked
                                    ? LocalizedText("Msg_TextAnnotation_Locked")
                                    : LocalizedText("Msg_TextAnnotation_Unlocked");
                                MessageBox.Show(
                                    this,
                                    string.Format(LocalizedText("Msg_TextPositionInfo"), msg),
                                    Resources.Title_Info,
                                    MessageBoxButtons.OK,
                                    MessageBoxIcon.Information);
                            }
                            break;
                        case RasterIconType.Duplicate:
                            DuplicateRasterObject(rasterObjectForIcon);
                            break;
                        case RasterIconType.Order:
                            ShowRasterOrderMenu(rasterObjectForIcon);
                            break;
                        case RasterIconType.ResetSize:
                            ResetRasterObjectSize(rasterObjectForIcon);
                            break;
                        case RasterIconType.Delete:
                            DeleteRasterObjectWithConfirmation(rasterObjectForIcon);
                            break;
                    }

                    ClearRasterIconClickState();
                    pdfViewer.Invalidate();
                    return;
                }

                if (isClickOnArrowIcon && arrowObjectForIcon != null)
                {
                    BeginUndoCapture("Edit object");
                    switch (clickedArrowIconType)
                    {
                        case ArrowIconType.Edit:
                            EditArrowObject(arrowObjectForIcon);
                            break;
                        case ArrowIconType.Lock:
                            if (EnsureCurrentPageEditable(true))
                            {
                                arrowObjectForIcon.IsLocked = !arrowObjectForIcon.IsLocked;
                                arrowObjectForIcon.UpdatedAtUtc = DateTime.UtcNow;
                                projectWasChangedAfterLastSave = true;
                                saveProjectButton.Enabled = true;
                                saveProjectMenuItem.Enabled = true;
                                string msg = arrowObjectForIcon.IsLocked
                                    ? LocalizedText("Msg_TextAnnotation_Locked")
                                    : LocalizedText("Msg_TextAnnotation_Unlocked");
                                MessageBox.Show(
                                    this,
                                    string.Format(LocalizedText("Msg_TextPositionInfo"), msg),
                                    Resources.Title_Info,
                                    MessageBoxButtons.OK,
                                    MessageBoxIcon.Information);
                            }
                            break;
                        case ArrowIconType.Duplicate:
                            DuplicateArrowObject(arrowObjectForIcon);
                            break;
                        case ArrowIconType.Order:
                            ShowArrowOrderMenu(arrowObjectForIcon);
                            break;
                        case ArrowIconType.Delete:
                            DeleteArrowObjectWithConfirmation(arrowObjectForIcon);
                            break;
                    }

                    ClearArrowIconClickState();
                    pdfViewer.Invalidate();
                    return;
                }

                if (isClickOnVectorIcon && vectorShapeForIcon != null)
                {
                    BeginUndoCapture("Edit object");
                    switch (clickedVectorIconType)
                    {
                        case VectorIconType.Edit:
                            EditVectorShapeObject(vectorShapeForIcon);
                            break;
                        case VectorIconType.Lock:
                            if (EnsureCurrentPageEditable(true))
                            {
                                vectorShapeForIcon.IsLocked = !vectorShapeForIcon.IsLocked;
                                vectorShapeForIcon.UpdatedAtUtc = DateTime.UtcNow;
                                projectWasChangedAfterLastSave = true;
                                saveProjectButton.Enabled = true;
                                saveProjectMenuItem.Enabled = true;
                                string msg = vectorShapeForIcon.IsLocked
                                    ? LocalizedText("Msg_TextAnnotation_Locked")
                                    : LocalizedText("Msg_TextAnnotation_Unlocked");
                                MessageBox.Show(
                                    this,
                                    string.Format(LocalizedText("Msg_TextPositionInfo"), msg),
                                    Resources.Title_Info,
                                    MessageBoxButtons.OK,
                                    MessageBoxIcon.Information);
                            }
                            break;
                        case VectorIconType.Duplicate:
                            DuplicateVectorShape(vectorShapeForIcon);
                            break;
                        case VectorIconType.Order:
                            ShowVectorOrderMenu(vectorShapeForIcon);
                            break;
                        case VectorIconType.Delete:
                            DeleteVectorShapeWithConfirmation(vectorShapeForIcon);
                            break;
                    }

                    ClearVectorIconClickState();
                    pdfViewer.Invalidate();
                    return;
                }

                // If user clicked in icon button area
                if (isClickOnIcon && annotationForIcon != null)
                {
                    BeginUndoCapture("Edit object");
                    // Call appropriate action depending on clicked button
                    if (clickedIconType == IconType.Edit)
                    {
                        // For example: call annotation edit method
                        AddEditAnnotation(annotationForIcon);
                    }
                    else if (clickedIconType == IconType.Lock)
                    {
                        string msg;
                        if (annotationForIcon.AnnotationIsLocked)
                        {
                            annotationForIcon.AnnotationIsLocked = false;
                            pdfViewer.Invalidate();
                            msg = LocalizedText("Msg_TextAnnotation_Unlocked");
                        }
                        else
                        {
                            annotationForIcon.AnnotationIsLocked = true;
                            msg = LocalizedText("Msg_TextAnnotation_Locked");
                        }
                        TouchTextAnnotation(annotationForIcon);
                        pdfViewer.Invalidate();
                        MessageBox.Show(this, string.Format(Resources.Msg_TextPositionInfo, msg), Resources.Title_Info, MessageBoxButtons.OK, MessageBoxIcon.Information);
                    }
                    else if (clickedIconType == IconType.Delete)
                    {
                        DeleteTextObjectWithConfirmation(annotationForIcon);

                    }
                    else if (clickedIconType == IconType.Duplicate)
                    {
                        DuplicateAnnotation(annotationForIcon);
                    }
                    else if (clickedIconType == IconType.Order)
                    {
                        ShowTextOrderMenu(annotationForIcon);
                    }
                    // Refresh view
                    pdfViewer.Invalidate();
                }
                else
                {
                    if (isMoving)
                    {
                        isMoving = false;
                        textMoveStartBounds = RectangleF.Empty;
                        textMoveStartLeaderEndPoint = PointF.Empty;
                        textMoveMouseOffset = PointF.Empty;
                        this.Cursor = Cursors.Default;
                        projectWasChangedAfterLastSave = true;
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                        InvalidateThumbnailPage(currentPage);
                    }
                    else
                    {
                        System.Drawing.RectangleF rect = new System.Drawing.RectangleF((currentSelection.X / scaleFactor), (currentSelection.Y / scaleFactor), (currentSelection.Width / scaleFactor), (currentSelection.Height / scaleFactor));
                        if (isCommentCreationMode)
                        {
                            bool markerVerticalMode = !isMarkerCtrlBoxMode && currentSelection.Height > currentSelection.Width;
                            bool enoughWidth = markerVerticalMode
                                ? currentSelection.Height > markerHeight * scaleFactor
                                : currentSelection.Width > markerWidth * scaleFactor;
                            bool enoughHeightForCtrlBox = !isMarkerCtrlBoxMode || currentSelection.Height > markerHeight * scaleFactor;
                            if (isDrawing && enoughWidth && enoughHeightForCtrlBox)
                            {
                                if (PromptForCommentText(
                                    string.Empty,
                                    activeCommentDialogDefaults.HighlightColor,
                                    activeCommentDialogDefaults.TextColor,
                                    out string commentText,
                                    out System.Drawing.Color highlightColor,
                                    out System.Drawing.Color textColor))
                                {
                                    var comment = new CommentAnnotation
                                    {
                                        Id = Guid.NewGuid().ToString("N"),
                                        PageNumber = currentPage,
                                        LayerId = GetResolvedActiveLayerId(),
                                        Bounds = rect,
                                        CommentText = commentText,
                                        HighlightColorArgb = highlightColor.ToArgb(),
                                        TextColorArgb = textColor.ToArgb(),
                                        IsMarkerSelection = !isMarkerCtrlBoxMode,
                                        CreatedAtUtc = DateTime.UtcNow,
                                        UpdatedAtUtc = DateTime.UtcNow
                                    };
                                    AddCommentAnnotation(comment);
                                }
                            }
                            EndCommentCreationMode();
                        }
                        else if (markerRadioButton.Checked)
                        {
                            renderTimer.Stop();
                            bool markerVerticalMode = !isMarkerCtrlBoxMode && currentSelection.Height > currentSelection.Width;
                            bool enoughWidth = markerVerticalMode
                                ? currentSelection.Height > markerHeight * scaleFactor
                                : currentSelection.Width > markerWidth * scaleFactor;
                            bool enoughHeightForCtrlBox = !isMarkerCtrlBoxMode || currentSelection.Height > markerHeight * scaleFactor;
                            if (isDrawing && enoughWidth && enoughHeightForCtrlBox)
                            {
                                // Marker + CTRL temporarily switches to box behavior.
                                bool markerModeForBlock = !isMarkerCtrlBoxMode;
                                var createdBlock = CreateRedactionBlockWithAutomaticClassification(
                                    rect,
                                    currentPage,
                                    isMarkerSelection: markerModeForBlock);
                                redactionBlocks.Add(createdBlock);
                                TryComputeRedactionPreviewRects(createdBlock);
                                
                                

                                status.HasSelections = true;

                                if ((string)filterComboBox.SelectedItem == allComboItem)
                                {
                                    ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                                    UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                                    pagesListView.Invalidate(currentItem.Bounds);
                                }
                                else
                                {
                                    // rebuild list according to filter
                                    ApplyFilter((string)filterComboBox.SelectedItem);
                                }

                                projectWasChangedAfterLastSave = true;
                                saveProjectButton.Enabled = true;
                                saveProjectMenuItem.Enabled = true;
                                UpdateSelectionNavigationButtons();
                                renderTimer.Stop();
                                renderTimer.Start();
                            }
                        }
                        else if (boxRadioButton.Checked)
                        {
                            renderTimer.Stop();
                            if (isDrawing && currentSelection.Width > markerWidth * scaleFactor && currentSelection.Height > markerHeight * scaleFactor)
                            {
                                var createdBlock = CreateRedactionBlockWithAutomaticClassification(rect, currentPage, isMarkerSelection: false);
                                redactionBlocks.Add(createdBlock);
                                TryComputeRedactionPreviewRects(createdBlock);

                                
                                status.HasSelections = true;

                                if ((string)filterComboBox.SelectedItem == allComboItem)
                                {
                                    ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                                    UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                                    pagesListView.Invalidate(currentItem.Bounds);
                                }
                                else
                                {
                                    // rebuild list according to filter
                                    ApplyFilter((string)filterComboBox.SelectedItem);
                                }

                                
                                projectWasChangedAfterLastSave = true;
                                saveProjectButton.Enabled = true;
                                saveProjectMenuItem.Enabled = true;
                                UpdateSelectionNavigationButtons();
                                renderTimer.Stop();
                                renderTimer.Start();
                            }
                        }
                        else if (!IsRedactionSelectionModeEnabled())
                        {
                            bool additiveSelection = (Control.ModifierKeys & Keys.Control) == Keys.Control;
                            TrySelectObjectsInMarquee(currentSelection, additiveSelection);
                        }
                    }
                }

            }
            else if (e.Button == MouseButtons.Right)
            {
                if (isCommentCreationMode)
                {
                    EndCommentCreationMode();
                    pdfViewer.Invalidate();
                    return;
                }

                if (TryShowVectorNodeContextMenu(startPoint))
                {
                    return;
                }

                if (TryShowCommentContextMenu(startPoint))
                {
                    return;
                }
                if (TryShowObjectContextMenu(startPoint))
                {
                    return;
                }
                TryShowRedactionContextMenu(startPoint);
            }
            isDrawing = false;
            isMarkerCtrlBoxMode = false;
            currentSelection = System.Drawing.Rectangle.Empty;
            if (!isMovingCommentNote && !isResizingCommentNote)
            {
                commentNoteToMove = null;
            }
            pdfViewer.Invalidate();


            // Reset icon click flag
            isClickOnIcon = false;
            clickedIconType = IconType.None;
            annotationForIcon = null;
            ClearRasterIconClickState();
            ClearArrowIconClickState();
            ClearVectorIconClickState();
            if (!isMovingArrowObject && !isAdjustingArrowHandle)
            {
                arrowMouseActionInProgress = false;
            }

        }

