        private bool PromptForCommentText(
            string initialValue,
            System.Drawing.Color initialHighlightColor,
            System.Drawing.Color initialTextColor,
            out string commentText,
            out System.Drawing.Color highlightColor,
            out System.Drawing.Color textColor)
        {
            commentText = string.Empty;
            highlightColor = initialHighlightColor;
            textColor = initialTextColor;

            using (Form prompt = new Form())
            {
                prompt.Text = GetCommentDialogTitleText();
                prompt.StartPosition = FormStartPosition.CenterParent;
                prompt.FormBorderStyle = FormBorderStyle.FixedDialog;
                prompt.MinimizeBox = false;
                prompt.MaximizeBox = false;
                prompt.ShowInTaskbar = false;
                prompt.ClientSize = new Size(460, 310);

                var label = new Label
                {
                    Text = GetCommentDialogLabelText(),
                    AutoSize = true,
                    Location = new Point(12, 12)
                };

                var textBox = new TextBox
                {
                    Multiline = true,
                    AcceptsReturn = true,
                    ScrollBars = ScrollBars.Vertical,
                    Location = new Point(12, 34),
                    Size = new Size(prompt.ClientSize.Width - 24, 160),
                    Anchor = AnchorStyles.Top | AnchorStyles.Left | AnchorStyles.Right | AnchorStyles.Bottom,
                    Text = initialValue ?? string.Empty
                };

                var highlightLabel = new Label
                {
                    Text = GetCommentHighlightColorLabelText(),
                    AutoSize = true,
                    Location = new Point(12, 202)
                };

                var highlightPreview = new Panel
                {
                    BackColor = initialHighlightColor,
                    BorderStyle = BorderStyle.FixedSingle,
                    Location = new Point(160, 198),
                    Size = new Size(28, 24)
                };

                var highlightButton = new Button
                {
                    Text = GetChooseColorText(),
                    Size = new Size(98, 26),
                    Location = new Point(196, 197)
                };
                highlightButton.Click += (_, __) =>
                {
                    using (var colorDialog = new ColorDialog())
                    {
                        colorDialog.FullOpen = true;
                        colorDialog.Color = highlightPreview.BackColor;
                        if (colorDialog.ShowDialog(prompt) == DialogResult.OK)
                        {
                            highlightPreview.BackColor = colorDialog.Color;
                        }
                    }
                };

                var textColorLabel = new Label
                {
                    Text = GetCommentTextColorLabelText(),
                    AutoSize = true,
                    Location = new Point(12, 233)
                };

                var textColorPreview = new Panel
                {
                    BackColor = initialTextColor,
                    BorderStyle = BorderStyle.FixedSingle,
                    Location = new Point(160, 229),
                    Size = new Size(28, 24)
                };

                var textColorButton = new Button
                {
                    Text = GetChooseColorText(),
                    Size = new Size(98, 26),
                    Location = new Point(196, 228)
                };
                textColorButton.Click += (_, __) =>
                {
                    using (var colorDialog = new ColorDialog())
                    {
                        colorDialog.FullOpen = true;
                        colorDialog.Color = textColorPreview.BackColor;
                        if (colorDialog.ShowDialog(prompt) == DialogResult.OK)
                        {
                            textColorPreview.BackColor = colorDialog.Color;
                        }
                    }
                };

                var restoreButton = new Button
                {
                    Text = GetRestoreSettingsButtonText(),
                    Size = new Size(138, 32),
                    Location = new Point(12, prompt.ClientSize.Height - 44),
                    Anchor = AnchorStyles.Left | AnchorStyles.Bottom
                };
                restoreButton.Click += (_, __) =>
                {
                    textBox.Text = string.Empty;
                    highlightPreview.BackColor = DefaultCommentHighlightColor;
                    textColorPreview.BackColor = DefaultCommentTextColor;
                };

                var okButton = new Button
                {
                    Text = Resources.Merge_OK,
                    DialogResult = DialogResult.OK,
                    Size = new Size(100, 32),
                    Location = new Point(prompt.ClientSize.Width - 212, prompt.ClientSize.Height - 44),
                    Anchor = AnchorStyles.Right | AnchorStyles.Bottom
                };

                var cancelButton = new Button
                {
                    Text = Resources.Merge_Cancel,
                    DialogResult = DialogResult.Cancel,
                    Size = new Size(100, 32),
                    Location = new Point(prompt.ClientSize.Width - 106, prompt.ClientSize.Height - 44),
                    Anchor = AnchorStyles.Right | AnchorStyles.Bottom
                };

                prompt.Controls.Add(label);
                prompt.Controls.Add(textBox);
                prompt.Controls.Add(highlightLabel);
                prompt.Controls.Add(highlightPreview);
                prompt.Controls.Add(highlightButton);
                prompt.Controls.Add(textColorLabel);
                prompt.Controls.Add(textColorPreview);
                prompt.Controls.Add(textColorButton);
                prompt.Controls.Add(restoreButton);
                prompt.Controls.Add(okButton);
                prompt.Controls.Add(cancelButton);
                // Enter in multiline textbox inserts a new line instead of closing dialog.
                prompt.AcceptButton = null;
                prompt.CancelButton = cancelButton;

                if (prompt.ShowDialog(this) != DialogResult.OK)
                {
                    return false;
                }

                commentText = (textBox.Text ?? string.Empty).Trim();
                if (string.IsNullOrWhiteSpace(commentText))
                {
                    commentText = GetDefaultCommentText();
                }

                highlightColor = highlightPreview.BackColor;
                textColor = textColorPreview.BackColor;
                CaptureCommentDialogDefaults(highlightColor, textColor);
                return true;
            }
        }

        private void CaptureCommentDialogDefaults(System.Drawing.Color highlightColor, System.Drawing.Color textColor)
        {
            activeCommentDialogDefaults = new CommentDialogDefaults
            {
                HighlightColor = highlightColor,
                TextColor = textColor
            };
        }

        private void AddCommentAnnotation(CommentAnnotation comment)
        {
            if (comment == null)
            {
                return;
            }

            NormalizeCommentAnnotation(comment);
            commentAnnotations.Add(comment);
            DisableRedactionSelectionMode();
            ClearGroupSelection();
            selectedTextAnnotation = null;
            selectedRasterObject = null;
            selectedArrowObject = null;
            selectedVectorShape = null;

            if (currentPage >= 1 && currentPage <= allPageStatuses.Count)
            {
                PageItemStatus status = allPageStatuses[currentPage - 1];
                status.HasObjects = HasAnyObjectsOnPage(currentPage);
                if ((string)filterComboBox.SelectedItem == allComboItem)
                {
                    ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                    UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                    pagesListView.Invalidate(currentItem.Bounds);
                }
                else
                {
                    ApplyFilter((string)filterComboBox.SelectedItem);
                }
            }

            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            RefreshPreviewAfterCommentChange();
        }

        private void RemoveCommentAnnotation(CommentAnnotation comment)
        {
            if (comment == null)
            {
                return;
            }

            if (!commentAnnotations.Remove(comment))
            {
                return;
            }

            if (currentPage >= 1 && currentPage <= allPageStatuses.Count)
            {
                PageItemStatus status = allPageStatuses[currentPage - 1];
                status.HasObjects = HasAnyObjectsOnPage(currentPage);
                if ((string)filterComboBox.SelectedItem == allComboItem)
                {
                    ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                    UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                    pagesListView.Invalidate(currentItem.Bounds);
                }
                else
                {
                    ApplyFilter((string)filterComboBox.SelectedItem);
                }
            }

            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            RefreshPreviewAfterCommentChange();
        }

        private void EditCommentAnnotation(CommentAnnotation comment)
        {
            if (comment == null)
            {
                return;
            }

            DisableRedactionSelectionMode();
            ClearGroupSelection();
            selectedTextAnnotation = null;
            selectedRasterObject = null;
            selectedArrowObject = null;
            selectedVectorShape = null;

            if (!PromptForCommentText(
                comment.CommentText,
                GetCommentHighlightColor(comment),
                GetCommentTextColor(comment),
                out string updatedText,
                out System.Drawing.Color updatedHighlightColor,
                out System.Drawing.Color updatedTextColor))
            {
                return;
            }

            bool textChanged = !string.Equals(comment.CommentText ?? string.Empty, updatedText ?? string.Empty, StringComparison.Ordinal);
            bool highlightChanged = comment.HighlightColorArgb != updatedHighlightColor.ToArgb();
            bool textColorChanged = comment.TextColorArgb != updatedTextColor.ToArgb();
            if (!textChanged && !highlightChanged && !textColorChanged)
            {
                return;
            }

            comment.CommentText = updatedText;
            comment.HighlightColorArgb = updatedHighlightColor.ToArgb();
            comment.TextColorArgb = updatedTextColor.ToArgb();
            comment.UpdatedAtUtc = DateTime.UtcNow;
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            RefreshPreviewAfterCommentChange();
        }

        private void RefreshPreviewAfterCommentChange()
        {
            commentNoteRectsDoc.Clear();
            ClearCommentPreviewRects();

            if (IsDisposed || Disposing || pdf == null || numPages <= 0)
            {
                return;
            }

            if (IsHandleCreated)
            {
                BeginInvoke(new Action(() =>
                {
                    if (IsDisposed || Disposing || pdf == null || numPages <= 0)
                    {
                        return;
                    }

                    ShowRedactPreview();
                    pdfViewer.Invalidate();
                    InvalidateThumbnailPage(currentPage);
                }));
                return;
            }

            ShowRedactPreview();
            pdfViewer.Invalidate();
            InvalidateThumbnailPage(currentPage);
        }

        private bool TryShowCommentContextMenu(Point location)
        {
            if (!TryGetCommentAtPoint(location, out CommentAnnotation comment, out _))
            {
                return false;
            }

            var menu = new ContextMenuStrip();
            menu.Items.Add(GetEditCommentContextMenuText(), null, (_, __) => EditCommentAnnotation(comment));
            menu.Items.Add(BuildMoveToLayerMenuItem(comment.LayerId, targetLayerId => MoveObjectToLayerFromContext(comment, targetLayerId)));
            menu.Items.Add(new ToolStripSeparator());
            menu.Items.Add(GetDeleteObjectContextMenuText(), null, (_, __) => DeleteObjectFromContext(comment));
            menu.Show(pdfViewer, location);
            return true;
        }

        private bool TryShowObjectContextMenu(Point location)
        {
            if (pdf == null || numPages <= 0)
            {
                return false;
            }

            float dpiX;
            float dpiY;
            using (Graphics graphics = pdfViewer.CreateGraphics())
            {
                dpiX = graphics.DpiX;
                dpiY = graphics.DpiY;
            }

            object hitObject = null;
            foreach (object candidate in GetOrderedObjectsForCurrentPage().Reverse())
            {
                if (candidate is TextAnnotation textAnnotation &&
                    GetAnnotationScreenRect(textAnnotation, dpiX, dpiY).Contains(location))
                {
                    hitObject = textAnnotation;
                    break;
                }

                if (candidate is RasterObject rasterObject &&
                    IsPointInsideRasterObject(rasterObject, location))
                {
                    hitObject = rasterObject;
                    break;
                }

                if (candidate is ArrowObject arrowObject &&
                    (IsPointNearArrowLine(arrowObject, location) || TryGetArrowHandleAtPoint(arrowObject, location, out _)))
                {
                    hitObject = arrowObject;
                    break;
                }

                if (candidate is VectorShapeObject vectorShape &&
                    IsPointNearVectorShape(vectorShape, location))
                {
                    hitObject = vectorShape;
                    break;
                }
            }

            if (hitObject == null)
            {
                return false;
            }

            bool multiSelectionActive = GetTotalSelectedObjectsCount() > 1;
            bool hitObjectIsPartOfSelection = IsObjectSelectedInCurrentSelection(hitObject);
            if (multiSelectionActive && hitObjectIsPartOfSelection)
            {
                List<object> selectedObjects = GetSelectedObjectsOnCurrentPageInLayerOrder();
                string sharedLayerId = selectedObjects
                    .Select(GetLayerIdForGenericObject)
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .Take(2)
                    .Count() == 1
                    ? GetLayerIdForGenericObject(selectedObjects.FirstOrDefault())
                    : null;

                var groupMenu = new ContextMenuStrip();
                var copySelectedItem = new ToolStripMenuItem(Resources.Menu_CopyToClipboard);
                copySelectedItem.Click += (_, __) => TryCopySelectedObjectsToClipboard();
                groupMenu.Items.Add(copySelectedItem);

                var cutSelectedItem = new ToolStripMenuItem(GetCutObjectContextMenuText());
                cutSelectedItem.Click += (_, __) => CutSelectedObjectsFromContext(useGroupSelection: true);
                groupMenu.Items.Add(cutSelectedItem);

                groupMenu.Items.Add(new ToolStripSeparator());
                groupMenu.Items.Add(BuildMoveToLayerMenuItem(sharedLayerId, targetLayerId => MoveSelectedObjectsToLayerFromContext(selectedObjects, targetLayerId)));
                groupMenu.Items.Add(new ToolStripSeparator());
                groupMenu.Items.Add(GetDeleteSelectedObjectsContextMenuText(), null, (_, __) => DeleteSelectedGroupObjectsWithConfirmation());
                groupMenu.Show(pdfViewer, location);
                return true;
            }

            string duplicateGroupId = GetDuplicateGroupIdForObject(hitObject);

            var menu = new ContextMenuStrip();
            var duplicateObjectItem = new ToolStripMenuItem(GetDuplicateObjectContextMenuText())
            {
                Enabled = numPages > 1
            };

            if (hitObject is TextAnnotation hitText)
            {
                selectedTextAnnotation = hitText;
                selectedRasterObject = null;
                selectedArrowObject = null;
                selectedVectorShape = null;
                ClearGroupSelection();
                duplicateObjectItem.Click += (_, __) => DuplicateTextAnnotationAcrossPages(hitText);
            }
            else if (hitObject is RasterObject hitRaster)
            {
                selectedTextAnnotation = null;
                selectedRasterObject = hitRaster;
                selectedArrowObject = null;
                selectedVectorShape = null;
                ClearGroupSelection();
                duplicateObjectItem.Click += (_, __) => DuplicateRasterObjectAcrossPages(hitRaster);
            }
            else if (hitObject is ArrowObject hitArrow)
            {
                selectedTextAnnotation = null;
                selectedRasterObject = null;
                selectedArrowObject = hitArrow;
                selectedVectorShape = null;
                ClearGroupSelection();
                duplicateObjectItem.Click += (_, __) => DuplicateArrowObjectAcrossPages(hitArrow);
            }
            else if (hitObject is VectorShapeObject hitVector)
            {
                selectedTextAnnotation = null;
                selectedRasterObject = null;
                selectedArrowObject = null;
                selectedVectorShape = hitVector;
                ClearGroupSelection();
                duplicateObjectItem.Click += (_, __) => DuplicateVectorShapeAcrossPages(hitVector);
            }
            else
            {
                return false;
            }

            var copyObjectItem = new ToolStripMenuItem(Resources.Menu_CopyToClipboard);
            copyObjectItem.Click += (_, __) => TryCopySelectedObjectsToClipboard();
            menu.Items.Add(copyObjectItem);
            var cutObjectItem = new ToolStripMenuItem(GetCutObjectContextMenuText());
            cutObjectItem.Click += (_, __) => CutSelectedObjectsFromContext(useGroupSelection: false, hitObject: hitObject);
            menu.Items.Add(cutObjectItem);
            menu.Items.Add(new ToolStripSeparator());
            menu.Items.Add(BuildMoveToLayerMenuItem(GetLayerIdForGenericObject(hitObject), targetLayerId => MoveObjectToLayerFromContext(hitObject, targetLayerId)));
            menu.Items.Add(new ToolStripSeparator());
            menu.Items.Add(duplicateObjectItem);
            var deleteDuplicatedObjectsItem = new ToolStripMenuItem(GetDeleteDuplicatedObjectsContextMenuText())
            {
                Enabled = !string.IsNullOrWhiteSpace(duplicateGroupId)
            };
            deleteDuplicatedObjectsItem.Click += (_, __) => DeleteDuplicatedObjectsByGroupId(duplicateGroupId, currentPage);
            menu.Items.Add(deleteDuplicatedObjectsItem);
            menu.Items.Add(GetDeleteObjectContextMenuText(), null, (_, __) => DeleteObjectFromContext(hitObject));
            menu.Show(pdfViewer, location);
            return true;
        }

        private bool TryShowRedactionContextMenu(Point location)
        {
            if (pdf == null)
            {
                return false;
            }

            float docX = location.X / scaleFactor;
            float docY = location.Y / scaleFactor;
            var block = redactionBlocks
                .Where(b => b.PageNumber == currentPage && b.Bounds.Contains(docX, docY))
                .LastOrDefault();
            if (block == null)
            {
                return false;
            }

            var menu = new ContextMenuStrip();
            menu.Items.Add(GetDeleteSelectionContextMenuText(), null, (_, __) => RemoveRedactionBlock(block));
            menu.Items.Add(Resources.Menu_CopyToClipboard, null, (_, __) => CopyRedactionBlockToClipboard(block));
            var duplicateSelectionMenuItem = new ToolStripMenuItem(GetDuplicateSelectionContextMenuText())
            {
                Enabled = numPages > 1
            };
            duplicateSelectionMenuItem.Click += (_, __) => DuplicateRedactionBlock(block);
            menu.Items.Add(duplicateSelectionMenuItem);
            var deleteDuplicatedSelectionsItem = new ToolStripMenuItem(GetDeleteDuplicatedObjectsContextMenuText())
            {
                Enabled = !string.IsNullOrWhiteSpace(block.DuplicateGroupId)
            };
            deleteDuplicatedSelectionsItem.Click += (_, __) => DeleteDuplicatedObjectsByGroupId(block.DuplicateGroupId, block.PageNumber);
            menu.Items.Add(deleteDuplicatedSelectionsItem);
            menu.Items.Add(new ToolStripSeparator());
            menu.Items.Add(BuildMoveToLayerMenuItem(block.LayerId, targetLayerId => MoveObjectToLayerFromContext(block, targetLayerId)));
            menu.Items.Add(new ToolStripSeparator());

            bool hasDynamicScopes = exclusionScopesCatalog.Count > 0;
            bool hasDynamicBases = legalBasesCatalog.Count > 0;
            var scopeMenu = new ToolStripMenuItem(GetScopeContextMenuText());
            if (hasDynamicScopes)
            {
                var noScopeItem = new ToolStripMenuItem(GetScopeNoneContextMenuText())
                {
                    Checked = string.IsNullOrWhiteSpace(block.ScopeId)
                };
                noScopeItem.Click += (_, __) => SetRedactionBlockScope(block, null);
                scopeMenu.DropDownItems.Add(noScopeItem);
                scopeMenu.DropDownItems.Add(new ToolStripSeparator());

                foreach (var scope in exclusionScopesCatalog.OrderBy(s => s.FriendlyName, StringComparer.CurrentCultureIgnoreCase))
                {
                    string scopeId = scope.ScopeId;
                    var scopeItem = new ToolStripMenuItem(scope.FriendlyName)
                    {
                        Checked = string.Equals(block.ScopeId, scopeId, StringComparison.OrdinalIgnoreCase),
                        ToolTipText = string.IsNullOrWhiteSpace(scope.Description) ? scopeId : scope.Description
                    };
                    scopeItem.Click += (_, __) => SetRedactionBlockScope(block, scopeId);
                    scopeMenu.DropDownItems.Add(scopeItem);
                }
            }
            else
            {
                scopeMenu.DropDownItems.Add(new ToolStripMenuItem(GetCatalogUnavailableContextMenuText())
                {
                    Enabled = false
                });
            }

            menu.Items.Add(scopeMenu);
            menu.Items.Add(new ToolStripSeparator());

            var addBasisItem = new ToolStripMenuItem(GetLegalBasisAddContextMenuText());
            addBasisItem.Click += (_, __) => BeginInvoke(new Action(() => AddLegalBasisFromContextMenu(block)));
            menu.Items.Add(addBasisItem);
            menu.Items.Add(new ToolStripSeparator());

            if (hasDynamicBases)
            {
                var clearBasisItem = new ToolStripMenuItem(GetLegalBasisNoneContextMenuText())
                {
                    Checked = block.BasisIds == null || block.BasisIds.Count == 0
                };
                clearBasisItem.Click += (_, __) => ClearRedactionBlockBasis(block);
                menu.Items.Add(clearBasisItem);
                menu.Items.Add(new ToolStripSeparator());

                HashSet<string> selectedBasisIds = new HashSet<string>(
                    block.BasisIds ?? new List<string>(),
                    StringComparer.OrdinalIgnoreCase);

                var sortedBases = GetOrderedLegalBasesForIndexing();
                var basisNumberById = sortedBases
                    .Where(b => b != null && !string.IsNullOrWhiteSpace(b.Id))
                    .Select((basis, index) => new { BasisId = basis.Id.Trim(), Number = index + 1 })
                    .ToDictionary(item => item.BasisId, item => item.Number, StringComparer.OrdinalIgnoreCase);

                LegalBasisSource? previousSource = null;
                foreach (var legalBasis in sortedBases)
                {
                    if (previousSource.HasValue && previousSource.Value != legalBasis.SourceKind)
                    {
                        menu.Items.Add(new ToolStripSeparator());
                    }

                    previousSource = legalBasis.SourceKind;
                    string basisId = legalBasis.Id;
                    basisNumberById.TryGetValue((basisId ?? string.Empty).Trim(), out int basisNumber);
                    var basisItem = new ToolStripMenuItem(FormatLegalBasisMenuLabel(legalBasis, basisNumber))
                    {
                        Checked = selectedBasisIds.Contains(basisId),
                        ToolTipText = string.IsNullOrWhiteSpace(legalBasis.FullCitation)
                            ? legalBasis.Title
                            : legalBasis.FullCitation
                    };
                    basisItem.Click += (_, __) => ToggleRedactionBlockBasis(block, basisId);
                    menu.Items.Add(basisItem);
                }
            }
            else
            {
                menu.Items.Add(new ToolStripMenuItem(GetCatalogUnavailableContextMenuText())
                {
                    Enabled = false
                });
            }

            menu.Show(pdfViewer, location);
            return true;
        }

        private void CopyRedactionBlockToClipboard(RedactionBlock block)
        {
            if (block == null || string.IsNullOrWhiteSpace(inputPdfPath) || !File.Exists(inputPdfPath))
            {
                return;
            }

            string extractedText = string.Empty;
            try
            {
                extractedText = ExtractTextFromRectangle(inputPdfPath, block);
                if (string.IsNullOrWhiteSpace(extractedText))
                {
                    using (Bitmap bmp = ExtractBitmapFromRectangle(block.PageNumber, block.Bounds))
                    {
                        if (bmp != null)
                        {
                            extractedText = OcrFromBitmap(bmp);
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                LogDebug("Copy redaction block to clipboard failed: " + ex.Message);
            }

            if (string.IsNullOrWhiteSpace(extractedText))
            {
                ShowInfoMessage(Resources.Msg_NoTextFromSelections);
                return;
            }

            Clipboard.SetText(extractedText.Trim());
            preferObjectClipboardPaste = false;
        }

        private void SetRedactionBlockScope(RedactionBlock block, string scopeId)
        {
            if (block == null)
            {
                return;
            }

            string normalizedScopeId = string.IsNullOrWhiteSpace(scopeId) ? null : scopeId.Trim();
            var previousBasis = new HashSet<string>(block.BasisIds ?? new List<string>(), StringComparer.OrdinalIgnoreCase);
            bool changed = !string.Equals(block.ScopeId, normalizedScopeId, StringComparison.OrdinalIgnoreCase);
            bool hadLegacyFootnote = block.FootnoteNumber.HasValue;

            block.ScopeId = normalizedScopeId;
            block.MatchedTag = null;
            block.ClassificationSource = ClassificationSourceManual;
            block.FootnoteNumber = null;
            changed = changed || hadLegacyFootnote;

            if (string.IsNullOrWhiteSpace(normalizedScopeId))
            {
                block.BasisIds = new List<string>();
                changed = changed || previousBasis.Count > 0;
            }
            else if (exclusionScopesById.TryGetValue(normalizedScopeId, out ExclusionScopeDefinition scope))
            {
                block.BasisIds = (scope.DefaultBasisIds ?? new List<string>())
                    .Where(id => !string.IsNullOrWhiteSpace(id))
                    .Select(id => id.Trim())
                    .Where(id => legalBasesById.Count == 0 || legalBasesById.ContainsKey(id))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToList();

                var nextBasis = new HashSet<string>(block.BasisIds, StringComparer.OrdinalIgnoreCase);
                changed = changed || !previousBasis.SetEquals(nextBasis);
            }

            if (!changed)
            {
                return;
            }

            TryApplyPersistedInterestSubjectToBlock(block);
            TouchRedactionBlock(block);

            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            pdfViewer.Invalidate();
        }

        private void ToggleRedactionBlockBasis(RedactionBlock block, string basisId)
        {
            if (block == null || string.IsNullOrWhiteSpace(basisId))
            {
                return;
            }

            string normalizedBasisId = basisId.Trim();
            if (block.BasisIds == null)
            {
                block.BasisIds = new List<string>();
            }

            bool changed;
            int existingIndex = block.BasisIds.FindIndex(id => string.Equals(id, normalizedBasisId, StringComparison.OrdinalIgnoreCase));
            if (existingIndex >= 0)
            {
                block.BasisIds.RemoveAt(existingIndex);
                changed = true;
            }
            else
            {
                block.BasisIds.Add(normalizedBasisId);
                changed = true;
            }

            if (!changed)
            {
                return;
            }

            block.ClassificationSource = ClassificationSourceManual;
            block.MatchedTag = null;
            block.FootnoteNumber = null;
            TryApplyPersistedInterestSubjectToBlock(block);
            TouchRedactionBlock(block);
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            pdfViewer.Invalidate();
        }

        private void ClearRedactionBlockBasis(RedactionBlock block)
        {
            if (block == null)
            {
                return;
            }

            if (block.BasisIds == null || block.BasisIds.Count == 0)
            {
                return;
            }

            block.BasisIds.Clear();
            block.ClassificationSource = ClassificationSourceManual;
            block.MatchedTag = null;
            block.FootnoteNumber = null;
            TouchRedactionBlock(block);
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            pdfViewer.Invalidate();
        }

        private string FormatLegalBasisMenuLabel(LegalBasisDefinition legalBasis, int basisNumber = 0)
        {
            if (legalBasis == null)
            {
                return string.Empty;
            }

            string numberPrefix = basisNumber > 0 ? $"[{basisNumber}] " : string.Empty;
            return $"{numberPrefix}{legalBasis.Title}";
        }

        private List<LegalBasisDefinition> GetOrderedLegalBasesForIndexing()
        {
            return legalBasesCatalog
                .Where(b => b != null)
                .OrderBy(b => b.SourceKind == LegalBasisSource.Global ? 0 : 1)
                .ThenBy(b => b.Title, StringComparer.CurrentCultureIgnoreCase)
                .ThenBy(b => b.Id, StringComparer.CurrentCultureIgnoreCase)
                .ToList();
        }

