        private static string NormalizeClassificationSource(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
            {
                return ClassificationSourceNone;
            }

            string normalized = value.Trim().ToLowerInvariant();
            if (normalized == ClassificationSourceAuto || normalized == ClassificationSourceManual)
            {
                return normalized;
            }

            return ClassificationSourceNone;
        }

        private static void NormalizeRedactionBlockMetadata(RedactionBlock block)
        {
            if (block == null)
            {
                return;
            }

            block.ScopeId = string.IsNullOrWhiteSpace(block.ScopeId) ? null : block.ScopeId.Trim();
            block.MatchedTag = string.IsNullOrWhiteSpace(block.MatchedTag) ? null : block.MatchedTag.Trim();
            block.InterestSubject = string.IsNullOrWhiteSpace(block.InterestSubject) ? null : block.InterestSubject.Trim();
            block.ClassificationSource = NormalizeClassificationSource(block.ClassificationSource);

            if (block.BasisIds == null)
            {
                block.BasisIds = new List<string>();
            }
            else
            {
                block.BasisIds = block.BasisIds
                    .Where(id => !string.IsNullOrWhiteSpace(id))
                    .Select(id => id.Trim())
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToList();
            }

            EnsureRedactionBlockTimestamps(block);
        }

        private bool RemoveInvalidLegalBasisReferencesFromRedactions()
        {
            if (redactionBlocks == null || redactionBlocks.Count == 0)
            {
                return false;
            }

            var validBasisIds = new HashSet<string>(
                legalBasesById.Keys.Where(id => !string.IsNullOrWhiteSpace(id)),
                StringComparer.OrdinalIgnoreCase);

            bool changed = false;
            foreach (var block in redactionBlocks)
            {
                if (block == null)
                {
                    continue;
                }

                NormalizeRedactionBlockMetadata(block);
                if (block.BasisIds == null || block.BasisIds.Count == 0)
                {
                    continue;
                }

                List<string> filteredBasisIds = block.BasisIds
                    .Where(id => !string.IsNullOrWhiteSpace(id))
                    .Select(id => id.Trim())
                    .Where(id => validBasisIds.Contains(id))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToList();

                if (filteredBasisIds.Count == block.BasisIds.Count)
                {
                    continue;
                }

                block.BasisIds = filteredBasisIds;
                block.FootnoteNumber = null;
                TouchRedactionBlock(block);
                changed = true;
            }

            return changed;
        }

        private RedactionBlock CreateRedactionBlockWithAutomaticClassification(RectangleF bounds, int pageNumber, bool isMarkerSelection = false)
        {
            var block = new RedactionBlock(bounds, pageNumber);
            block.LayerId = GetResolvedActiveLayerId();
            block.IsMarkerSelection = isMarkerSelection;
            StampRedactionBlockCreated(block);
            NormalizeRedactionBlockMetadata(block);
            TryApplyAutomaticFootnoteClassification(block);
            return block;
        }

        private void InvalidateRedactionPreviewRects(RedactionBlock block)
        {
            if (block == null)
            {
                return;
            }

            block.PreviewTextRectsPdf = null;
        }

        private List<RectangleF> ComputeRedactionPreviewRects(
            iText.Kernel.Pdf.PdfPage page,
            RedactionBlock block,
            int rotation)
        {
            if (page == null || block == null)
            {
                return new List<RectangleF>();
            }

            RectangleF pdfCoords = ConvertToPdfCoordinates(block.Bounds, block.PageNumber, rotation);
            iText.Kernel.Geom.Rectangle sourceRect = ConvertToItTextRectangle(pdfCoords);
            List<iText.Kernel.Geom.Rectangle> pdfLineRects = GetVisualLineRectsForBlock(
                page,
                sourceRect,
                block.PageNumber,
                rotation,
                block.IsMarkerSelection ? "visual" : "box");

            return pdfLineRects
                .Where(r => r != null && r.GetWidth() > 0f && r.GetHeight() > 0f)
                .Select(ConvertToItTextRectangleF)
                .ToList();
        }

        private void QueueRedactionPreviewRectsForPage(int pageNumber)
        {
            if (pageNumber < 1 || string.IsNullOrWhiteSpace(inputPdfPath) || !File.Exists(inputPdfPath))
            {
                return;
            }

            foreach (var block in redactionBlocks.Where(b => b != null && b.PageNumber == pageNumber))
            {
                if (block.PreviewTextRectsPdf == null)
                {
                    block.PreviewTextRectsPdf = new List<RectangleF>();
                }
            }

            var blocksForPage = redactionBlocks
                .Where(b => b != null && b.PageNumber == pageNumber && IsLayerVisible(b.LayerId))
                .ToList();

            var previousCts = redactionPreviewRectsCts;
            redactionPreviewRectsCts = new System.Threading.CancellationTokenSource();
            int requestId = ++redactionPreviewRectsRequestId;
            string sourcePdfPath = inputPdfPath;
            string password = userPassword;
            var token = redactionPreviewRectsCts.Token;

            try
            {
                previousCts?.Cancel();
            }
            catch
            {
            }

            Task.Run(() =>
            {
                var results = new Dictionary<RedactionBlock, List<RectangleF>>();
                try
                {
                    var props = new ReaderProperties();
                    if (!string.IsNullOrEmpty(password))
                    {
                        props.SetPassword(System.Text.Encoding.UTF8.GetBytes(password));
                    }

                    using (var reader = new PdfReader(sourcePdfPath, props).SetUnethicalReading(Properties.Settings.Default.IgnorePdfRestrictions))
                    using (var pdfDoc = new iText.Kernel.Pdf.PdfDocument(reader))
                    {
                        if (pageNumber < 1 || pageNumber > pdfDoc.GetNumberOfPages())
                        {
                            return results;
                        }

                        var page = pdfDoc.GetPage(pageNumber);
                        int rotation = GetEffectiveRotationDegrees(pageNumber);
                        foreach (var block in blocksForPage)
                        {
                            if (token.IsCancellationRequested)
                            {
                                return null;
                            }

                            results[block] = ComputeRedactionPreviewRects(page, block, rotation);
                        }
                    }
                }
                catch (Exception ex)
                {
                    LogDebug($"QueueRedactionPreviewRectsForPage page={pageNumber} err={ex.Message}");
                }

                return results;
            }, token).ContinueWith(t =>
            {
                if (IsDisposed || token.IsCancellationRequested || t.IsCanceled || t.Result == null)
                {
                    return;
                }

                if (requestId != redactionPreviewRectsRequestId || currentPage != pageNumber)
                {
                    return;
                }

                foreach (var kvp in t.Result)
                {
                    if (redactionBlocks.Contains(kvp.Key))
                    {
                        kvp.Key.PreviewTextRectsPdf = kvp.Value ?? new List<RectangleF>();
                    }
                }

                QueueRedactionPreviewOverlayForPage(pageNumber);
                pdfViewer.Invalidate();
            }, TaskScheduler.FromCurrentSynchronizationContext());
        }

        private void TryComputeRedactionPreviewRects(RedactionBlock block)
        {
            if (block == null)
            {
                return;
            }

            InvalidateRedactionPreviewRects(block);
            if (block.PageNumber == currentPage)
            {
                QueueRedactionPreviewRectsForPage(block.PageNumber);
            }
        }

        private void EnsureRedactionPreviewRectsForPage(int pageNumber)
        {
            if (pageNumber < 1)
            {
                return;
            }
            QueueRedactionPreviewRectsForPage(pageNumber);
        }

        private void RefreshRedactionPreviewForCurrentPage(bool keepCurrentOverlay = false)
        {
            if (currentPage < 1)
            {
                return;
            }

            if (keepCurrentOverlay)
            {
                try
                {
                    redactionPreviewOverlayCts?.Cancel();
                }
                catch
                {
                }

                redactionPreviewOverlayCts = null;
                redactionPreviewOverlayRequestId++;
            }
            else
            {
                ClearRedactionPreviewOverlay();
            }

            QueueRedactionPreviewRectsForPage(currentPage);
            pdfViewer.Invalidate();
            InvalidateThumbnailPage(currentPage);
        }

        private bool TryApplyAutomaticFootnoteClassification(RedactionBlock block)
        {
            if (block == null || !autoFootnotesEnabled)
            {
                return false;
            }

            if (NormalizeClassificationSource(block.ClassificationSource) == ClassificationSourceManual)
            {
                return false;
            }

            if (string.IsNullOrWhiteSpace(inputPdfPath) || !File.Exists(inputPdfPath))
            {
                return false;
            }

            string extractedText;
            try
            {
                extractedText = ExtractTextFromRectangle(inputPdfPath, block);
            }
            catch (Exception ex)
            {
                LogDebug("Auto footnote classification text extraction failed: " + ex.Message);
                return false;
            }

            if (string.IsNullOrWhiteSpace(extractedText))
            {
                return false;
            }

            var detectedTags = PdfTextSearcher.DetectIdentifierTags(extractedText);
            if (detectedTags == null || detectedTags.Count == 0)
            {
                return false;
            }

            ExclusionScopeDefinition matchedScope = ResolveScopeForDetectedTags(detectedTags, out string matchedTag);
            if (matchedScope == null)
            {
                return false;
            }

            List<string> basisIds = (matchedScope.DefaultBasisIds ?? new List<string>())
                .Where(id => !string.IsNullOrWhiteSpace(id))
                .Select(id => id.Trim())
                .Where(id => legalBasesById.Count == 0 || legalBasesById.ContainsKey(id))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            block.ScopeId = matchedScope.ScopeId;
            block.BasisIds = basisIds;
            block.MatchedTag = matchedTag;
            block.ClassificationSource = ClassificationSourceAuto;
            TryApplyPersistedInterestSubjectToBlock(block);
            TouchRedactionBlock(block);

            if (DebugLogEnabled)
            {
                LogDebug(
                    $"AutoClassify page={block.PageNumber} scope={block.ScopeId} tag={block.MatchedTag} " +
                    $"basis={string.Join(",", block.BasisIds ?? new List<string>())} text='{TruncateForLog(extractedText, 80)}'");
            }

            return true;
        }

        private ExclusionScopeDefinition ResolveScopeForDetectedTags(
            IReadOnlyList<string> detectedTags,
            out string matchedTag)
        {
            matchedTag = null;
            if (detectedTags == null || detectedTags.Count == 0 || exclusionScopesCatalog.Count == 0)
            {
                return null;
            }

            foreach (string rawTag in detectedTags)
            {
                if (string.IsNullOrWhiteSpace(rawTag))
                {
                    continue;
                }

                string tag = rawTag.Trim();
                ExclusionScopeDefinition scope = exclusionScopesCatalog.FirstOrDefault(s =>
                    s != null &&
                    s.AutoDetectTags != null &&
                    s.AutoDetectTags.Any(scopeTag => string.Equals(scopeTag, tag, StringComparison.OrdinalIgnoreCase)));

                if (scope != null)
                {
                    matchedTag = tag;
                    return scope;
                }
            }

            return null;
        }

        private static string TruncateForLog(string value, int maxLength)
        {
            if (string.IsNullOrEmpty(value) || maxLength <= 0 || value.Length <= maxLength)
            {
                return value ?? string.Empty;
            }

            return value.Substring(0, maxLength) + "...";
        }

