        private void ApplyRightPanelTabSelectionFromSettings()
        {
            try
            {
                if (pagesTabControl == null || pagesListTabPage == null || thumbnailsTabPage == null || layersTabPage == null)
                {
                    return;
                }

                string selectedTabKey = Properties.Settings.Default.RightPanelSelectedTabKey;
                if (string.IsNullOrWhiteSpace(selectedTabKey))
                {
                    selectedTabKey = Properties.Settings.Default.UseThumbnailsTabInRightPanel
                        ? RightPanelTabThumbnailsKey
                        : RightPanelTabPagesKey;
                }

                switch (selectedTabKey)
                {
                    case RightPanelTabLayersKey:
                        pagesTabControl.SelectedTab = layersTabPage;
                        break;
                    case RightPanelTabThumbnailsKey:
                        pagesTabControl.SelectedTab = thumbnailsTabPage;
                        break;
                    default:
                        pagesTabControl.SelectedTab = pagesListTabPage;
                        break;
                }

                if (IsThumbnailsTabSelected())
                {
                    thumbnailViewportTimer?.Start();
                }
                else
                {
                    thumbnailViewportTimer?.Stop();
                }
            }
            catch (Exception ex)
            {
                LogDebug("Apply right-panel tab selection failed: " + ex.Message);
            }
        }

        private string GetSelectedRightPanelTabKey()
        {
            if (pagesTabControl == null || pagesTabControl.SelectedTab == null)
            {
                return RightPanelTabPagesKey;
            }

            if (pagesTabControl.SelectedTab == thumbnailsTabPage)
            {
                return RightPanelTabThumbnailsKey;
            }

            if (pagesTabControl.SelectedTab == layersTabPage)
            {
                return RightPanelTabLayersKey;
            }

            return RightPanelTabPagesKey;
        }

        private void SaveRightPanelTabSelectionUserSetting()
        {
            try
            {
                string selectedTabKey = GetSelectedRightPanelTabKey();
                Properties.Settings.Default.RightPanelSelectedTabKey = selectedTabKey;
                Properties.Settings.Default.UseThumbnailsTabInRightPanel = selectedTabKey == RightPanelTabThumbnailsKey;
                Properties.Settings.Default.Save();
            }
            catch (Exception ex)
            {
                LogDebug("Save right-panel tab selection failed: " + ex.Message);
            }
        }

        private void ApplyRightPanelDividerFromSettings()
        {
            try
            {
                if (formSplitContainer == null)
                {
                    return;
                }

                int desiredRightPanelWidth = Properties.Settings.Default.RightPanelWidth;
                if (desiredRightPanelWidth <= 0)
                {
                    return;
                }

                int totalWidth = formSplitContainer.ClientSize.Width;
                int splitterWidth = formSplitContainer.SplitterWidth;
                if (totalWidth <= splitterWidth)
                {
                    return;
                }

                int minRightWidth = Math.Max(1, formSplitContainer.Panel2MinSize);
                int maxRightWidth = Math.Max(minRightWidth, totalWidth - splitterWidth - formSplitContainer.Panel1MinSize);
                int rightWidth = Math.Max(minRightWidth, Math.Min(desiredRightPanelWidth, maxRightWidth));

                int desiredSplitterDistance = totalWidth - splitterWidth - rightWidth;
                int minSplitterDistance = Math.Max(0, formSplitContainer.Panel1MinSize);
                int maxSplitterDistance = Math.Max(minSplitterDistance, totalWidth - splitterWidth - minRightWidth);
                desiredSplitterDistance = Math.Max(minSplitterDistance, Math.Min(desiredSplitterDistance, maxSplitterDistance));

                if (formSplitContainer.SplitterDistance != desiredSplitterDistance)
                {
                    formSplitContainer.SplitterDistance = desiredSplitterDistance;
                }
            }
            catch (Exception ex)
            {
                LogDebug("Apply right-panel divider failed: " + ex.Message);
            }
        }

        private void SaveRightPanelDividerUserSetting()
        {
            try
            {
                if (formSplitContainer == null)
                {
                    return;
                }

                int currentRightPanelWidth = formSplitContainer.Panel2.Width;
                if (currentRightPanelWidth <= 0)
                {
                    return;
                }

                if (Properties.Settings.Default.RightPanelWidth == currentRightPanelWidth)
                {
                    return;
                }

                Properties.Settings.Default.RightPanelWidth = currentRightPanelWidth;
                Properties.Settings.Default.Save();
            }
            catch (Exception ex)
            {
                LogDebug("Save right-panel divider failed: " + ex.Message);
            }
        }

        private void FormSplitContainer_SplitterMoved(object sender, SplitterEventArgs e)
        {
            SaveRightPanelDividerUserSetting();
        }

        private bool IsThumbnailsTabSelected()
        {
            return pagesTabControl != null && thumbnailsTabPage != null && pagesTabControl.SelectedTab == thumbnailsTabPage;
        }

        private void PagesTabControl_SelectedIndexChanged(object sender, EventArgs e)
        {
            if (pagesTabControl == null || pagesTabControl.SelectedTab == null)
            {
                return;
            }

            SaveRightPanelTabSelectionUserSetting();
            UpdateRightPanelTabContentVisibility();

            if (IsThumbnailsTabSelected())
            {
                thumbnailViewportTimer?.Start();
                EnsureThumbnailGeneration();
                SelectThumbnailItemForCurrentPage(ensureVisible: true);
            }
            else
            {
                thumbnailViewportTimer?.Stop();
                CancelThumbnailGeneration();
                if (pagesTabControl.SelectedTab == pagesListTabPage)
                {
                    SyncPagesListSelectionToCurrentPage(ensureVisible: true);
                }
            }
        }

        private void UpdateRightPanelTabContentVisibility()
        {
            if (pagesTabControl == null)
            {
                return;
            }

            bool pagesVisible = pagesTabControl.SelectedTab == pagesListTabPage;
            bool thumbnailsVisible = pagesTabControl.SelectedTab == thumbnailsTabPage;
            bool layersVisible = pagesTabControl.SelectedTab == layersTabPage;

            if (pagesListView != null)
            {
                pagesListView.Visible = pagesVisible;
                if (pagesVisible)
                {
                    pagesListView.Invalidate();
                }
            }

            if (thumbnailsListView != null)
            {
                thumbnailsListView.Visible = thumbnailsVisible;
                if (thumbnailsVisible)
                {
                    thumbnailsListView.Invalidate();
                }
            }

            if (layersTabPlaceholderPanel != null)
            {
                layersTabPlaceholderPanel.Visible = layersVisible;
                if (layersVisible)
                {
                    layersTabPlaceholderPanel.Invalidate(true);
                }
            }
        }

        private void InitializeThumbnailPanelItems()
        {
            if (thumbnailsListView == null || thumbnailsImageList == null)
            {
                return;
            }

            CancelThumbnailGeneration();
            thumbnailGenerationSourcePdfPath = inputPdfPath ?? string.Empty;
            thumbnailContentSizeByPage.Clear();
            PrepareThumbnailCacheForCurrentDocument();
            lock (thumbnailGenerationSync)
            {
                thumbnailGenerationQueue.Clear();
                thumbnailQueuedPages.Clear();
                thumbnailRenderedPages.Clear();
            }

            thumbnailsListView.BeginUpdate();
            try
            {
                thumbnailsListView.Items.Clear();
                thumbnailsImageList.Images.Clear();
                Bitmap placeholder = CreateThumbnailPlaceholderImage(thumbnailsImageList.ImageSize);
                thumbnailsImageList.Images.Add("placeholder", placeholder);
                for (int i = 1; i <= numPages; i++)
                {
                    thumbnailContentSizeByPage[i] = thumbnailsImageList.ImageSize;
                }
            }
            finally
            {
                thumbnailsListView.EndUpdate();
            }

            var filteredPages = GetStatusesForFilter((string)filterComboBox.SelectedItem)
                .Select(s => s.PageNumber)
                .ToList();
            RebuildThumbnailsForFilter(filteredPages);
        }

        private void ResetThumbnailPanel()
        {
            thumbnailViewportTimer?.Stop();
            CancelThumbnailGeneration();
            thumbnailGenerationSourcePdfPath = string.Empty;
            thumbnailCacheDocumentDirectory = string.Empty;

            if (thumbnailsListView != null)
            {
                thumbnailsListView.Items.Clear();
            }

            if (thumbnailsImageList != null)
            {
                thumbnailsImageList.Images.Clear();
            }

            thumbnailContentSizeByPage.Clear();
            lock (thumbnailGenerationSync)
            {
                thumbnailGenerationQueue.Clear();
                thumbnailQueuedPages.Clear();
                thumbnailRenderedPages.Clear();
            }
        }

        private void PrepareThumbnailCacheForCurrentDocument()
        {
            try
            {
                thumbnailCacheDocumentDirectory = string.Empty;
                if (string.IsNullOrWhiteSpace(inputPdfPath) || !File.Exists(inputPdfPath))
                {
                    return;
                }

                string fullPath = Path.GetFullPath(inputPdfPath);
                var fileInfo = new FileInfo(fullPath);
                string keySource = string.Join("|",
                    "thumbcache-v1",
                    fullPath.ToLowerInvariant(),
                    fileInfo.Length.ToString(CultureInfo.InvariantCulture),
                    fileInfo.LastWriteTimeUtc.Ticks.ToString(CultureInfo.InvariantCulture),
                    thumbnailsImageList.ImageSize.Width.ToString(CultureInfo.InvariantCulture),
                    thumbnailsImageList.ImageSize.Height.ToString(CultureInfo.InvariantCulture));
                string key = ComputeSha256Hex(keySource);
                string root = LicenseManager.GetThumbnailCacheRootDirectory();
                string documentDir = Path.Combine(root, key);
                Directory.CreateDirectory(documentDir);
                thumbnailCacheDocumentDirectory = documentDir;
            }
            catch (Exception ex)
            {
                thumbnailCacheDocumentDirectory = string.Empty;
                LogDebug("Prepare thumbnail cache failed: " + ex.Message);
            }
        }

        private static string ComputeSha256Hex(string input)
        {
            using (var sha = SHA256.Create())
            {
                byte[] bytes = System.Text.Encoding.UTF8.GetBytes(input ?? string.Empty);
                byte[] hash = sha.ComputeHash(bytes);
                var sb = new System.Text.StringBuilder(hash.Length * 2);
                for (int i = 0; i < hash.Length; i++)
                {
                    sb.Append(hash[i].ToString("x2", CultureInfo.InvariantCulture));
                }

                return sb.ToString();
            }
        }

        private string GetThumbnailCacheFilePath(int pageNumber, int renderedWidth, int renderedHeight, int rotationOffset)
        {
            if (string.IsNullOrWhiteSpace(thumbnailCacheDocumentDirectory))
            {
                return string.Empty;
            }

            string fileName = string.Format(
                CultureInfo.InvariantCulture,
                "p{0:D5}_{1}x{2}_r{3:D3}.png",
                pageNumber,
                renderedWidth,
                renderedHeight,
                NormalizeRotation(rotationOffset));
            return Path.Combine(thumbnailCacheDocumentDirectory, fileName);
        }

        private void InvalidateThumbnailPage(int pageNumber, bool regenerateBaseImage = false)
        {
            if (thumbnailsListView == null || pageNumber < 1 || pageNumber > numPages)
            {
                return;
            }

            if (regenerateBaseImage)
            {
                lock (thumbnailGenerationSync)
                {
                    thumbnailRenderedPages.Remove(pageNumber);
                }

                QueueThumbnailPageForGeneration(pageNumber);
                StartThumbnailGenerationWorkerIfNeeded();
            }

            ListViewItem item = FindThumbnailListItemByPageNumber(pageNumber);
            if (item != null)
            {
                thumbnailsListView.Invalidate(item.Bounds);
            }
            else
            {
                thumbnailsListView.Invalidate();
            }
        }

        private static bool TryLoadThumbnailBitmapFromCache(string cachePath, out Bitmap bitmap)
        {
            bitmap = null;
            if (string.IsNullOrWhiteSpace(cachePath) || !File.Exists(cachePath))
            {
                return false;
            }

            try
            {
                using (var stream = new FileStream(cachePath, FileMode.Open, FileAccess.Read, FileShare.Read))
                using (var image = DrawingImage.FromStream(stream))
                {
                    bitmap = new Bitmap(image);
                }

                return true;
            }
            catch
            {
                try
                {
                    File.Delete(cachePath);
                }
                catch
                {
                    // ignore
                }

                return false;
            }
        }

        private static void TrySaveThumbnailBitmapToCache(string cachePath, Bitmap bitmap)
        {
            if (string.IsNullOrWhiteSpace(cachePath) || bitmap == null)
            {
                return;
            }

            try
            {
                string directory = Path.GetDirectoryName(cachePath);
                if (!string.IsNullOrWhiteSpace(directory))
                {
                    Directory.CreateDirectory(directory);
                }

                bitmap.Save(cachePath, ImageFormat.Png);
            }
            catch
            {
                // ignore cache write errors
            }
        }

        private void ApplyThumbnailIconSpacing()
        {
            try
            {
                if (thumbnailsListView == null || thumbnailsImageList == null || !thumbnailsListView.IsHandleCreated)
                {
                    return;
                }

                int iconWidth = Math.Max(1, thumbnailsImageList.ImageSize.Width);
                int iconHeight = Math.Max(1, thumbnailsImageList.ImageSize.Height);
                int horizontalSpacing = Math.Max(iconWidth + 8, iconWidth);
                int verticalSpacing = Math.Max(iconHeight + Math.Max(thumbnailsListView.Font.Height + 18, 34), iconHeight + 24);
                int lParam = (verticalSpacing << 16) | (horizontalSpacing & 0xFFFF);
                SendMessage(thumbnailsListView.Handle, LVM_SETICONSPACING, IntPtr.Zero, (IntPtr)lParam);
            }
            catch (Exception ex)
            {
                LogDebug("Apply thumbnail spacing failed: " + ex.Message);
            }
        }

        private void EnsureThumbnailGeneration()
        {
            if (!IsThumbnailsTabSelected() ||
                pdf == null ||
                numPages <= 0 ||
                string.IsNullOrWhiteSpace(inputPdfPath) ||
                !File.Exists(inputPdfPath))
            {
                return;
            }

            if (thumbnailsListView.Items.Count == 0)
            {
                RebuildThumbnailsForFilter(
                    GetStatusesForFilter((string)filterComboBox.SelectedItem)
                        .Select(s => s.PageNumber)
                        .ToList());
            }

            QueueVisibleThumbnailsForGeneration();
            StartThumbnailGenerationWorkerIfNeeded();
        }

        private void QueueVisibleThumbnailsForGeneration()
        {
            var candidatePages = GetThumbnailPagesAroundViewport();
            if (candidatePages.Count == 0)
            {
                return;
            }

            foreach (int page in candidatePages
                .OrderBy(p => Math.Abs(p - currentPage))
                .ThenBy(p => p))
            {
                QueueThumbnailPageForGeneration(page);
            }
        }

        private List<int> GetThumbnailPagesAroundViewport()
        {
            var result = new List<int>();
            if (thumbnailsListView == null || thumbnailsListView.Items.Count == 0)
            {
                return result;
            }

            DrawingRectangle client = thumbnailsListView.ClientRectangle;
            int firstVisible = int.MaxValue;
            int lastVisible = int.MinValue;

            for (int i = 0; i < thumbnailsListView.Items.Count; i++)
            {
                DrawingRectangle itemBounds = thumbnailsListView.GetItemRect(i, ItemBoundsPortion.Entire);
                if (itemBounds.IntersectsWith(client))
                {
                    firstVisible = Math.Min(firstVisible, i);
                    lastVisible = Math.Max(lastVisible, i);
                }
            }

            if (firstVisible == int.MaxValue || lastVisible == int.MinValue)
            {
                var fallbackItem = FindThumbnailListItemByPageNumber(currentPage);
                int fallback = fallbackItem != null
                    ? fallbackItem.Index
                    : Math.Max(0, Math.Min(thumbnailsListView.Items.Count - 1, 0));
                firstVisible = fallback;
                lastVisible = fallback;
            }

            int estimatedColumns = Math.Max(
                1,
                thumbnailsListView.ClientSize.Width / Math.Max(1, thumbnailsImageList.ImageSize.Width + 8));
            int buffer = Math.Max(4, estimatedColumns * 2);

            int startIndex = Math.Max(0, firstVisible - buffer);
            int endIndex = Math.Min(thumbnailsListView.Items.Count - 1, lastVisible + buffer);
            for (int i = startIndex; i <= endIndex; i++)
            {
                if (thumbnailsListView.Items[i].Tag is int page && page >= 1 && page <= numPages)
                {
                    result.Add(page);
                }
            }

            if (FindThumbnailListItemByPageNumber(currentPage) != null && !result.Contains(currentPage))
            {
                result.Add(currentPage);
            }

            return result;
        }

        private void QueueThumbnailPageForGeneration(int pageNumber)
        {
            if (pageNumber < 1 || pageNumber > numPages)
            {
                return;
            }

            lock (thumbnailGenerationSync)
            {
                string key = $"thumb_{pageNumber}";
                if (thumbnailRenderedPages.Contains(pageNumber) && !thumbnailsImageList.Images.ContainsKey(key))
                {
                    thumbnailRenderedPages.Remove(pageNumber);
                }

                if (thumbnailRenderedPages.Contains(pageNumber) || thumbnailQueuedPages.Contains(pageNumber))
                {
                    return;
                }

                thumbnailGenerationQueue.Enqueue(pageNumber);
                thumbnailQueuedPages.Add(pageNumber);
            }
        }

        private void CancelThumbnailGeneration()
        {
            lock (thumbnailGenerationSync)
            {
                thumbnailGenerationQueue.Clear();
                thumbnailQueuedPages.Clear();
            }

            var cts = thumbnailGenerationCts;
            thumbnailGenerationCts = null;

            try
            {
                cts?.Cancel();
            }
            catch
            {
                // ignore
            }
        }

        private void StartThumbnailGenerationWorkerIfNeeded()
        {
            if (thumbnailGenerationWorkerRunning)
            {
                return;
            }

            bool hasWork;
            lock (thumbnailGenerationSync)
            {
                hasWork = thumbnailGenerationQueue.Count > 0;
                if (hasWork)
                {
                    thumbnailGenerationWorkerRunning = true;
                }
            }

            if (!hasWork)
            {
                return;
            }

            var cts = new System.Threading.CancellationTokenSource();
            thumbnailGenerationCts = cts;
            string sourcePdfPath = inputPdfPath;
            string password = userPassword;
            thumbnailGenerationSourcePdfPath = sourcePdfPath ?? string.Empty;

            _ = Task.Run(() => ThumbnailGenerationWorkerAsync(sourcePdfPath, password, cts));
        }

        private async Task ThumbnailGenerationWorkerAsync(string sourcePdfPath, string password, System.Threading.CancellationTokenSource cts)
        {
            System.Threading.CancellationToken token = cts.Token;
            Size thumbnailSize = thumbnailsImageList.ImageSize;

            try
            {
                using (var thumbPdf = string.IsNullOrWhiteSpace(password)
                    ? new PDFiumSharp.PdfDocument(sourcePdfPath)
                    : new PDFiumSharp.PdfDocument(sourcePdfPath, password))
                {
                    while (true)
                    {
                        token.ThrowIfCancellationRequested();

                        int pageNumber;
                        lock (thumbnailGenerationSync)
                        {
                            if (thumbnailGenerationQueue.Count == 0)
                            {
                                break;
                            }

                            pageNumber = thumbnailGenerationQueue.Dequeue();
                            thumbnailQueuedPages.Remove(pageNumber);
                        }

                        if (pageNumber < 1 || pageNumber > thumbPdf.Pages.Count)
                        {
                            continue;
                        }

                        Bitmap thumbBitmap;
                        int renderedWidth = 1;
                        int renderedHeight = 1;
                        using (var page = thumbPdf.Pages[pageNumber - 1])
                        {
                            var displayPageSize = GetPageSizeWithOffset(pageNumber);
                            float pageWidth = Math.Max(1f, displayPageSize.Width);
                            float pageHeight = Math.Max(1f, displayPageSize.Height);
                            float scale = Math.Min(
                                thumbnailSize.Width / pageWidth,
                                thumbnailSize.Height / pageHeight);
                            int renderWidth = Math.Max(1, (int)Math.Round(pageWidth * scale));
                            int renderHeight = Math.Max(1, (int)Math.Round(pageHeight * scale));
                            int rotationOffset = NormalizeRotation(GetRotationOffset(pageNumber));
                            int sourceRenderWidth = renderWidth;
                            int sourceRenderHeight = renderHeight;
                            if (rotationOffset == 90 || rotationOffset == 270)
                            {
                                sourceRenderWidth = renderHeight;
                                sourceRenderHeight = renderWidth;
                            }
                            renderedWidth = renderWidth;
                            renderedHeight = renderHeight;
                            string cachePath = GetThumbnailCacheFilePath(pageNumber, renderWidth, renderHeight, rotationOffset);
                            if (!TryLoadThumbnailBitmapFromCache(cachePath, out thumbBitmap))
                            {
                                thumbBitmap = new Bitmap(thumbnailSize.Width, thumbnailSize.Height, PixelFormat.Format32bppArgb);
                                using (Graphics g = Graphics.FromImage(thumbBitmap))
                                {
                                    g.Clear(System.Drawing.Color.Transparent);
                                    int left = (thumbnailSize.Width - renderWidth) / 2;
                                    int top = (thumbnailSize.Height - renderHeight) / 2;
                                    using (var pdfBitmap = new PDFiumBitmap(sourceRenderWidth, sourceRenderHeight, false))
                                    {
                                        pdfBitmap.FillRectangle(0, 0, sourceRenderWidth, sourceRenderHeight, 0xFFFFFFFF);
                                        page.Render(renderTarget: pdfBitmap, flags: RenderingFlags.Annotations);
                                        using (var bmpStream = pdfBitmap.AsBmpStream())
                                        using (var rendered = new Bitmap(DrawingImage.FromStream(bmpStream)))
                                        {
                                            ApplyRotationOffset(rendered, rotationOffset);
                                            g.DrawImage(rendered, left, top, renderWidth, renderHeight);
                                        }
                                    }
                                }

                                TrySaveThumbnailBitmapToCache(cachePath, thumbBitmap);
                            }
                        }

                        if (!IsHandleCreated || IsDisposed || token.IsCancellationRequested)
                        {
                            thumbBitmap.Dispose();
                            break;
                        }

                        Invoke(new Action(() =>
                        {
                            if (thumbBitmap == null)
                            {
                                return;
                            }

                            if (!ArePathsEqual(sourcePdfPath, inputPdfPath) ||
                                pageNumber < 1 ||
                                pageNumber > numPages)
                            {
                                thumbBitmap.Dispose();
                                return;
                            }

                            var targetItem = FindThumbnailListItemByPageNumber(pageNumber);
                            string key = $"thumb_{pageNumber}";
                            if (thumbnailsImageList.Images.ContainsKey(key))
                            {
                                thumbnailsImageList.Images.RemoveByKey(key);
                            }

                            thumbnailsImageList.Images.Add(key, thumbBitmap);
                            if (targetItem != null)
                            {
                                targetItem.ImageKey = key;
                            }
                            thumbnailContentSizeByPage[pageNumber] = new Size(renderedWidth, renderedHeight);
                            lock (thumbnailGenerationSync)
                            {
                                thumbnailRenderedPages.Add(pageNumber);
                            }
                        }));

                        await Task.Yield();
                    }
                }
            }
            catch (OperationCanceledException)
            {
                // ignored
            }
            catch (Exception ex)
            {
                LogDebug("Thumbnail generation failed: " + ex.Message);
            }
            finally
            {
                if (ReferenceEquals(thumbnailGenerationCts, cts))
                {
                    thumbnailGenerationCts = null;
                }
                lock (thumbnailGenerationSync)
                {
                    thumbnailGenerationWorkerRunning = false;
                }
                cts.Dispose();

                if (IsHandleCreated && !IsDisposed)
                {
                    BeginInvoke(new Action(() =>
                    {
                        if (IsThumbnailsTabSelected())
                        {
                            QueueVisibleThumbnailsForGeneration();
                            StartThumbnailGenerationWorkerIfNeeded();
                        }
                    }));
                }
            }
        }

        private static Bitmap CreateThumbnailPlaceholderImage(Size size)
        {
            Bitmap bitmap = new Bitmap(Math.Max(1, size.Width), Math.Max(1, size.Height), PixelFormat.Format32bppArgb);
            using (Graphics g = Graphics.FromImage(bitmap))
            {
                g.Clear(System.Drawing.Color.Transparent);
            }

            return bitmap;
        }

        private RectangleF ConvertDocumentRectToThumbnailRectangle(RectangleF documentRect, int pageNumber, DrawingRectangle contentRect)
        {
            if (pdf == null || pageNumber < 1 || pageNumber > numPages || contentRect.Width <= 0 || contentRect.Height <= 0)
            {
                return RectangleF.Empty;
            }

            var pageSize = GetPageSizeWithOffset(pageNumber);
            if (pageSize.Width <= 0f || pageSize.Height <= 0f)
            {
                return RectangleF.Empty;
            }

            float scaleX = contentRect.Width / pageSize.Width;
            float scaleY = contentRect.Height / pageSize.Height;

            return new RectangleF(
                contentRect.X + (documentRect.X * scaleX),
                contentRect.Y + (documentRect.Y * scaleY),
                Math.Max(1f, documentRect.Width * scaleX),
                Math.Max(1f, documentRect.Height * scaleY));
        }

        private PointF ConvertDocumentPointToThumbnailPoint(PointF documentPoint, int pageNumber, DrawingRectangle contentRect)
        {
            if (pdf == null || pageNumber < 1 || pageNumber > numPages || contentRect.Width <= 0 || contentRect.Height <= 0)
            {
                return PointF.Empty;
            }

            var pageSize = GetPageSizeWithOffset(pageNumber);
            if (pageSize.Width <= 0f || pageSize.Height <= 0f)
            {
                return PointF.Empty;
            }

            float scaleX = contentRect.Width / pageSize.Width;
            float scaleY = contentRect.Height / pageSize.Height;
            return new PointF(
                contentRect.X + (documentPoint.X * scaleX),
                contentRect.Y + (documentPoint.Y * scaleY));
        }

        private void DrawThumbnailRedactionOverlays(Graphics graphics, int pageNumber, DrawingRectangle contentRect)
        {
            if (graphics == null || pageNumber < 1 || pageNumber > numPages)
            {
                return;
            }

            using (var fillBrush = new SolidBrush(System.Drawing.Color.FromArgb(110, 255, 0, 0)))
            using (var borderPen = new Pen(System.Drawing.Color.FromArgb(220, 200, 0, 0), 1.2f))
            {
                foreach (RedactionBlock block in redactionBlocks.Where(block => block != null && block.PageNumber == pageNumber && IsLayerVisible(block.LayerId)))
                {
                    RectangleF thumbnailRect = ConvertDocumentRectToThumbnailRectangle(block.Bounds, pageNumber, contentRect);
                    if (thumbnailRect.Width <= 0f || thumbnailRect.Height <= 0f)
                    {
                        continue;
                    }

                    graphics.FillRectangle(fillBrush, thumbnailRect);
                    graphics.DrawRectangle(borderPen, thumbnailRect.X, thumbnailRect.Y, thumbnailRect.Width, thumbnailRect.Height);
                }
            }
        }

        private void DrawThumbnailCommentOverlays(Graphics graphics, int pageNumber, DrawingRectangle contentRect)
        {
            if (graphics == null || pageNumber < 1 || pageNumber > numPages)
            {
                return;
            }

            using (var fillBrush = new SolidBrush(System.Drawing.Color.FromArgb(145, 255, 235, 59)))
            using (var borderPen = new Pen(System.Drawing.Color.FromArgb(220, 184, 134, 11), 1.1f))
            {
                foreach (CommentAnnotation comment in commentAnnotations.Where(comment => comment != null && comment.PageNumber == pageNumber && IsLayerVisible(comment.LayerId)))
                {
                    RectangleF thumbnailRect = ConvertDocumentRectToThumbnailRectangle(comment.Bounds, pageNumber, contentRect);
                    if (thumbnailRect.Width <= 0f || thumbnailRect.Height <= 0f)
                    {
                        continue;
                    }

                    graphics.FillRectangle(fillBrush, thumbnailRect);
                    graphics.DrawRectangle(borderPen, thumbnailRect.X, thumbnailRect.Y, thumbnailRect.Width, thumbnailRect.Height);
                }
            }
        }

        private void DrawThumbnailTextAnnotationOverlays(Graphics graphics, int pageNumber, DrawingRectangle contentRect)
        {
            if (graphics == null || pageNumber < 1 || pageNumber > numPages)
            {
                return;
            }

            foreach (TextAnnotation annotation in textAnnotations.Where(annotation => annotation != null && annotation.PageNumber == pageNumber && IsLayerVisible(annotation.LayerId)))
            {
                RectangleF textBounds;
                if (!TryGetAnnotationTextFrameGeometryDoc(annotation, out _, out RectangleF frameBounds, out _, out _))
                {
                    textBounds = annotation.AnnotationBounds;
                    if (textBounds.IsEmpty)
                    {
                        continue;
                    }
                }
                else
                {
                    textBounds = frameBounds;
                }

                RectangleF thumbnailRect = ConvertDocumentRectToThumbnailRectangle(textBounds, pageNumber, contentRect);
                if (thumbnailRect.Width <= 0f || thumbnailRect.Height <= 0f)
                {
                    continue;
                }

                System.Drawing.Color backColor = GetAnnotationBackgroundColor(annotation);
                System.Drawing.Color borderColor = GetAnnotationBorderColor(annotation);
                if (backColor.A > 0)
                {
                    int overlayAlpha = Math.Min(180, Math.Max(70, (int)backColor.A));
                    using (var fillBrush = new SolidBrush(System.Drawing.Color.FromArgb(overlayAlpha, backColor)))
                    {
                        graphics.FillRectangle(fillBrush, thumbnailRect);
                    }
                }

                System.Drawing.Color strokeColor = borderColor.A > 0 ? borderColor : annotation.AnnotationColor;
                using (var borderPen = new Pen(strokeColor, 1.1f))
                {
                    graphics.DrawRectangle(borderPen, thumbnailRect.X, thumbnailRect.Y, thumbnailRect.Width, thumbnailRect.Height);
                }

                if (annotation.HasLeaderArrow &&
                    TryGetAnnotationLeaderGeometryDoc(annotation, out PointF anchorPoint, out PointF endPoint, out PointF leftPoint, out PointF rightPoint, out PointF lineEndPoint))
                {
                    PointF anchorThumb = ConvertDocumentPointToThumbnailPoint(anchorPoint, pageNumber, contentRect);
                    PointF endThumb = ConvertDocumentPointToThumbnailPoint(endPoint, pageNumber, contentRect);
                    PointF leftThumb = ConvertDocumentPointToThumbnailPoint(leftPoint, pageNumber, contentRect);
                    PointF rightThumb = ConvertDocumentPointToThumbnailPoint(rightPoint, pageNumber, contentRect);
                    PointF lineEndThumb = ConvertDocumentPointToThumbnailPoint(lineEndPoint, pageNumber, contentRect);

                    float leaderThickness = Math.Max(
                        1f,
                        Math.Min(2.2f, NormalizeLeaderLineWidth(annotation.LeaderLineWidth) * (contentRect.Width / Math.Max(1f, GetPageSizeWithOffset(pageNumber).Width))));

                    using (var leaderPen = new Pen(strokeColor, leaderThickness))
                    {
                        leaderPen.StartCap = LineCap.Round;
                        leaderPen.EndCap = LineCap.Round;
                        graphics.DrawLine(leaderPen, anchorThumb, lineEndThumb);
                    }

                    using (var leaderBrush = new SolidBrush(strokeColor))
                    {
                        graphics.FillPolygon(leaderBrush, new[] { endThumb, leftThumb, rightThumb });
                    }
                }
            }
        }

        private void DrawThumbnailRasterOverlays(Graphics graphics, int pageNumber, DrawingRectangle contentRect)
        {
            if (graphics == null || pageNumber < 1 || pageNumber > numPages)
            {
                return;
            }

            using (var borderPen = new Pen(System.Drawing.Color.FromArgb(220, 42, 119, 219), 1.1f))
            {
                borderPen.DashStyle = DashStyle.Solid;
                foreach (RasterObject rasterObject in rasterObjects.Where(rasterObject => rasterObject != null && rasterObject.PageNumber == pageNumber && IsLayerVisible(rasterObject.LayerId)))
                {
                    RectangleF rasterBounds = GetRasterObjectDocFrameBounds(rasterObject);
                    RectangleF thumbnailRect = ConvertDocumentRectToThumbnailRectangle(rasterBounds, pageNumber, contentRect);
                    if (thumbnailRect.Width <= 0f || thumbnailRect.Height <= 0f)
                    {
                        continue;
                    }

                    graphics.DrawRectangle(borderPen, thumbnailRect.X, thumbnailRect.Y, thumbnailRect.Width, thumbnailRect.Height);
                }
            }
        }

        private void DrawThumbnailArrowOverlays(Graphics graphics, int pageNumber, DrawingRectangle contentRect)
        {
            if (graphics == null || pageNumber < 1 || pageNumber > numPages)
            {
                return;
            }

            foreach (ArrowObject arrowObject in arrowObjects.Where(arrowObject => arrowObject != null && arrowObject.PageNumber == pageNumber && IsLayerVisible(arrowObject.LayerId)))
            {
                PointF start = ConvertDocumentPointToThumbnailPoint(arrowObject.Start, pageNumber, contentRect);
                PointF end = ConvertDocumentPointToThumbnailPoint(arrowObject.End, pageNumber, contentRect);
                float thickness = Math.Max(1.1f, Math.Min(3.2f, NormalizeArrowThickness(arrowObject.Thickness) * (contentRect.Width / Math.Max(1f, GetPageSizeWithOffset(pageNumber).Width))));
                System.Drawing.Color lineColor = GetArrowColor(arrowObject);
                System.Drawing.Color borderColor = GetArrowBorderColor(arrowObject);

                if (borderColor.A > 0 && NormalizeArrowBorderWidth(arrowObject.BorderWidth) > 0f)
                {
                    using (var borderPen = new Pen(borderColor, thickness + 1.2f))
                    {
                        borderPen.StartCap = LineCap.Round;
                        borderPen.EndCap = LineCap.Round;
                        graphics.DrawLine(borderPen, start, end);
                    }
                }

                using (var linePen = new Pen(lineColor, thickness))
                {
                    linePen.StartCap = LineCap.Round;
                    linePen.EndCap = LineCap.Round;
                    graphics.DrawLine(linePen, start, end);
                }

                float headLength = Math.Max(5f, Math.Min(14f, NormalizeArrowHeadLength(arrowObject.HeadLength) * (contentRect.Width / Math.Max(1f, GetPageSizeWithOffset(pageNumber).Width))));
                float headWidth = Math.Max(4f, Math.Min(12f, NormalizeArrowHeadWidth(arrowObject.HeadWidth) * (contentRect.Width / Math.Max(1f, GetPageSizeWithOffset(pageNumber).Width))));
                if (TryBuildArrowHead(start, end, headLength, headWidth, out PointF leftPoint, out PointF rightPoint, out PointF lineEndPoint))
                {
                    PointF[] headPoints = { end, leftPoint, rightPoint };
                    if (borderColor.A > 0 && NormalizeArrowBorderWidth(arrowObject.BorderWidth) > 0f)
                    {
                        using (var borderBrush = new SolidBrush(borderColor))
                        {
                            graphics.FillPolygon(borderBrush, headPoints);
                        }
                    }

                    using (var headBrush = new SolidBrush(lineColor))
                    {
                        graphics.FillPolygon(headBrush, headPoints);
                    }
                }
            }
        }

        private void DrawThumbnailVectorShapeOverlays(Graphics graphics, int pageNumber, DrawingRectangle contentRect)
        {
            if (graphics == null || pageNumber < 1 || pageNumber > numPages)
            {
                return;
            }

            foreach (VectorShapeObject vectorShape in vectorShapes.Where(vectorShape => vectorShape != null && vectorShape.PageNumber == pageNumber && IsLayerVisible(vectorShape.LayerId)))
            {
                VectorShapeType shapeType = ParseVectorShapeType(vectorShape.ShapeType);
                PointF[] renderPoints = BuildVectorShapeRenderPoints(shapeType, vectorShape.Points)
                    .Select(point => ConvertDocumentPointToThumbnailPoint(point, pageNumber, contentRect))
                    .ToArray();
                if (renderPoints.Length < 2)
                {
                    continue;
                }

                bool closedShape = IsShapeClosed(shapeType) && renderPoints.Length >= 3;
                bool hasFill = HasVisibleVectorFill(vectorShape, shapeType) || (vectorShape.IsRasterClip && closedShape);
                bool hasStroke = HasVisibleVectorColor(vectorShape.StrokeColorArgb);
                System.Drawing.Color strokeColor = System.Drawing.Color.FromArgb(vectorShape.StrokeColorArgb);
                System.Drawing.Color fillColor = System.Drawing.Color.FromArgb(vectorShape.FillColorArgb);
                float strokeWidth = Math.Max(1f, Math.Min(3f, NormalizeVectorStrokeWidth(vectorShape.StrokeWidth) * (contentRect.Width / Math.Max(1f, GetPageSizeWithOffset(pageNumber).Width))));

                if (hasFill && closedShape)
                {
                    int fillAlpha = Math.Max(45, Math.Min(160, (int)Math.Round(NormalizeVectorFillOpacity(vectorShape.FillOpacity) * 255f)));
                    using (var fillBrush = new SolidBrush(System.Drawing.Color.FromArgb(fillAlpha, fillColor)))
                    {
                        graphics.FillPolygon(fillBrush, renderPoints);
                    }
                }

                if (hasStroke)
                {
                    using (var strokePen = new Pen(strokeColor, strokeWidth))
                    {
                        strokePen.LineJoin = LineJoin.Round;
                        strokePen.StartCap = LineCap.Round;
                        strokePen.EndCap = LineCap.Round;
                        if (closedShape)
                        {
                            graphics.DrawPolygon(strokePen, renderPoints);
                        }
                        else
                        {
                            graphics.DrawLines(strokePen, renderPoints);
                        }
                    }
                }
            }
        }

        private void DrawThumbnailDeletionOverlay(Graphics graphics, int pageNumber, DrawingRectangle contentRect)
        {
            if (graphics == null || pageNumber < 1 || pageNumber > allPageStatuses.Count)
            {
                return;
            }

            if (!allPageStatuses[pageNumber - 1].MarkedForDeletion)
            {
                return;
            }

            using (var strikePen = new Pen(System.Drawing.Color.Black, Math.Max(2f, Math.Min(contentRect.Width, contentRect.Height) / 18f)))
            {
                strikePen.StartCap = LineCap.Round;
                strikePen.EndCap = LineCap.Round;
                graphics.DrawLine(strikePen, contentRect.Left, contentRect.Top, contentRect.Right, contentRect.Bottom);
                graphics.DrawLine(strikePen, contentRect.Right, contentRect.Top, contentRect.Left, contentRect.Bottom);
            }
        }

        private void SelectThumbnailItemForCurrentPage(bool ensureVisible)
        {
            if (thumbnailsListView == null || currentPage < 1)
            {
                return;
            }

            if (syncThumbnailSelectionFromPage)
            {
                return;
            }

            syncThumbnailSelectionFromPage = true;
            try
            {
                var item = FindThumbnailListItemByPageNumber(currentPage);
                if (item == null)
                {
                    thumbnailsListView.SelectedItems.Clear();
                    return;
                }

                if (thumbnailsListView.SelectedItems.Count != 1 || thumbnailsListView.SelectedItems[0] != item)
                {
                    thumbnailsListView.SelectedItems.Clear();
                    item.Selected = true;
                }

                if (ensureVisible)
                {
                    item.EnsureVisible();
                }
            }
            finally
            {
                syncThumbnailSelectionFromPage = false;
            }
        }

        private ListViewItem FindThumbnailListItemByPageNumber(int pageNumber)
        {
            if (thumbnailsListView == null)
            {
                return null;
            }

            return thumbnailsListView.Items
                .Cast<ListViewItem>()
                .FirstOrDefault(item => item.Tag is int page && page == pageNumber);
        }

        private void ThumbnailsListView_SelectedIndexChanged(object sender, EventArgs e)
        {
            if (syncThumbnailSelectionFromPage || syncPageSelectionFromThumbnail)
            {
                return;
            }

            if (thumbnailsListView.SelectedItems.Count == 0)
            {
                return;
            }

            if (!(thumbnailsListView.SelectedItems[0].Tag is int selectedPage) || selectedPage < 1 || selectedPage > numPages)
            {
                return;
            }

            ListViewItem target = FindListViewItemByPageNumber(selectedPage);
            if (target != null)
            {
                syncPageSelectionFromThumbnail = true;
                try
                {
                    ForcePageListSelection(target);
                    target.EnsureVisible();
                }
                finally
                {
                    syncPageSelectionFromThumbnail = false;
                }
            }

            currentPage = selectedPage;
            ReloadRefreshCurrentPage();
            UpdateNavigationButtons(currentPage);
            UpdateSelectionNavigationButtons();
            UpdateSearchNavigationButtons();
            SyncPagesListSelectionToCurrentPage(ensureVisible: false);
        }

        private void SyncPagesListSelectionToCurrentPage(bool ensureVisible)
        {
            if (pagesListView == null || pagesListView.Items.Count == 0 || currentPage < 1)
            {
                return;
            }

            ListViewItem target = null;
            if ((string)filterComboBox.SelectedItem == allComboItem &&
                currentPage <= pagesListView.Items.Count)
            {
                target = pagesListView.Items[currentPage - 1];
            }
            else
            {
                target = FindListViewItemByPageNumber(currentPage);
            }

            if (target == null)
            {
                return;
            }

            ForcePageListSelection(target);
            if (ensureVisible)
            {
                target.EnsureVisible();
            }
        }

        private void ThumbnailViewportTimer_Tick(object sender, EventArgs e)
        {
            if (!IsThumbnailsTabSelected())
            {
                return;
            }

            EnsureThumbnailGeneration();
        }

        private void ThumbnailsListView_DrawItem(object sender, DrawListViewItemEventArgs e)
        {
            if (e?.Item == null)
            {
                return;
            }

            bool isSelected = e.Item.Selected;
            var theme = CurrentTheme;
            System.Drawing.Color itemBackColor = isSelected ? theme.SelectionBackColor : thumbnailsListView.BackColor;
            System.Drawing.Color itemTextColor = isSelected ? theme.TextPrimaryColor : thumbnailsListView.ForeColor;
            using (var backBrush = new SolidBrush(itemBackColor))
            {
                e.Graphics.FillRectangle(backBrush, e.Bounds);
            }

            Image image = null;
            if (e.Item.ImageIndex >= 0 && e.Item.ImageIndex < thumbnailsImageList.Images.Count)
            {
                image = thumbnailsImageList.Images[e.Item.ImageIndex];
            }
            else if (!string.IsNullOrEmpty(e.Item.ImageKey) && thumbnailsImageList.Images.ContainsKey(e.Item.ImageKey))
            {
                image = thumbnailsImageList.Images[e.Item.ImageKey];
            }

            int maxThumbWidth = Math.Max(1, e.Bounds.Width - 2);
            int maxThumbHeight = Math.Max(1, e.Bounds.Height - 32);
            int thumbWidth = Math.Min(image?.Width ?? thumbnailsImageList.ImageSize.Width, maxThumbWidth);
            int thumbHeight = Math.Min(image?.Height ?? thumbnailsImageList.ImageSize.Height, maxThumbHeight);
            int thumbX = e.Bounds.Left + Math.Max(0, (e.Bounds.Width - thumbWidth) / 2);
            int thumbY = e.Bounds.Top + 10;
            var thumbRect = new DrawingRectangle(thumbX, thumbY, thumbWidth, thumbHeight);

            if (image != null)
            {
                e.Graphics.DrawImage(image, thumbRect);
            }

            int pageNumber = e.Item.Tag is int taggedPage ? taggedPage : -1;
            Size contentSize = thumbnailContentSizeByPage.TryGetValue(pageNumber, out var cachedSize)
                ? cachedSize
                : thumbnailsImageList.ImageSize;
            int contentWidth = Math.Max(1, Math.Min(contentSize.Width, thumbRect.Width));
            int contentHeight = Math.Max(1, Math.Min(contentSize.Height, thumbRect.Height));
            int contentX = thumbRect.Left + (thumbRect.Width - contentWidth) / 2;
            int contentY = thumbRect.Top + (thumbRect.Height - contentHeight) / 2;
            var contentRect = new DrawingRectangle(contentX, contentY, contentWidth, contentHeight);

            using (var borderPen = new Pen(isSelected ? theme.DangerBackColor : theme.BorderColor, isSelected ? 2f : 1.25f))
            {
                e.Graphics.DrawRectangle(borderPen, contentRect.X, contentRect.Y, Math.Max(1, contentRect.Width - 1), Math.Max(1, contentRect.Height - 1));
            }

            if (pageNumber >= 1)
            {
                DrawThumbnailRedactionOverlays(e.Graphics, pageNumber, contentRect);
                DrawThumbnailTextAnnotationOverlays(e.Graphics, pageNumber, contentRect);
                DrawThumbnailRasterOverlays(e.Graphics, pageNumber, contentRect);
                DrawThumbnailArrowOverlays(e.Graphics, pageNumber, contentRect);
                DrawThumbnailVectorShapeOverlays(e.Graphics, pageNumber, contentRect);
                DrawThumbnailCommentOverlays(e.Graphics, pageNumber, contentRect);
                DrawThumbnailDeletionOverlay(e.Graphics, pageNumber, contentRect);
            }

            int fontHeight = (e.Item.Font ?? thumbnailsListView.Font).Height;
            int textHeight = Math.Max(fontHeight + 4, 20);
            int textY = Math.Min(thumbRect.Bottom + 8, e.Bounds.Bottom - textHeight - 2);
            var textRect = new DrawingRectangle(
                e.Bounds.Left + 2,
                textY,
                Math.Max(1, e.Bounds.Width - 4),
                textHeight);

            TextRenderer.DrawText(
                e.Graphics,
                e.Item.Text ?? string.Empty,
                e.Item.Font ?? thumbnailsListView.Font,
                textRect,
                itemTextColor,
                TextFormatFlags.HorizontalCenter | TextFormatFlags.VerticalCenter | TextFormatFlags.SingleLine | TextFormatFlags.EndEllipsis);

            if (isSelected)
            {
                using (var selectionBorderPen = new Pen(System.Drawing.Color.Black, 1f))
                {
                    e.Graphics.DrawRectangle(
                        selectionBorderPen,
                        e.Bounds.X,
                        e.Bounds.Y,
                        Math.Max(1, e.Bounds.Width - 1),
                        Math.Max(1, e.Bounds.Height - 1));
                }
            }

            if ((e.State & ListViewItemStates.Focused) == ListViewItemStates.Focused)
            {
                ControlPaint.DrawFocusRectangle(e.Graphics, e.Bounds, itemTextColor, itemBackColor);
            }
        }

        private void ReloadRefreshCurrentPage()
        {
            pageNumberTextBox.Text = currentPage.ToString();
            pageNumberTextBox.Refresh();

            CalculateMinScaleFactor(currentPage);
            CalculateMaxScaleFactor();

            if ((scaleFactor < minScaleFactor) || minScaleButton)
            {
                scaleFactor = minScaleFactor;
            }
            else if ((scaleFactor > maxScaleFactor) || maxScaleButton)
            {
                scaleFactor = maxScaleFactor;
            }
            pagingTimer.Stop();
            pagingTimer.Start();
            SelectThumbnailItemForCurrentPage(ensureVisible: IsThumbnailsTabSelected());
        }


        private void PagesListView_SelectedIndexChanged(object sender, EventArgs e)
        {
            // If at least one element is selected
            if (pagesListView.SelectedItems.Count > 0)
            {
                // Take the first selected item
                ListViewItem selectedItem = pagesListView.SelectedItems[0];
                // Item text, e.g. "Page 1"
                //string text = selectedItem.Text;


                // If we use Tag to store number:
                currentPage = ((PageItemStatus)selectedItem.Tag).PageNumber;

                ReloadRefreshCurrentPage();

                

                PageItemStatus status = allPageStatuses[currentPage - 1];
                // Check whether current page has selections
                bool hasSelectionsForThisPage = redactionBlocks.Any(rb => rb.PageNumber == currentPage);
                bool hasSearchResultsForThisPage = searchLocations.Any(sr => sr.PageNumber == currentPage);
                bool markedForDeletionForThisPage = pagesToRemove.Contains(currentPage);
                bool hasObjectsForThisPage = HasAnyObjectsOnPage(currentPage);

                status.HasSelections = hasSelectionsForThisPage;
                status.HasSearchResults = hasSearchResultsForThisPage;
                status.MarkedForDeletion = markedForDeletionForThisPage;
                status.HasObjects = hasObjectsForThisPage;
                status.HasRotation = pageRotationOffsets.ContainsKey(currentPage);

                //UpdateItemTag(selectedItem, pageNumber, hasSelectionsForThisPage, hasSearchResultsForThisPage, markedForDeletionForThisPage, hasObjectsForThisPage);

                //if ((string)filterComboBox.SelectedItem == allComboItem)
                //{
                    // only refresh this row
                    //ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                UpdateItemTag(selectedItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                //}
                //else
                //{
                    // rebuild list according to filter
                //    ApplyFilter((string)filterComboBox.SelectedItem);
                //}

                if (hasSearchResultsForThisPage)
                {
                    currentLocationIndex = searchLocations.FindIndex(location => location.PageNumber == currentPage);
                    pdfViewer.Invalidate();
                }

                // Enable/disable button depending on whether there are selections
                clearPageButton.Enabled = hasSelectionsForThisPage;
                UpdateNavigationButtons(currentPage);
                UpdateSelectionNavigationButtons();
                UpdateSearchNavigationButtons();
                //pagesListView.Invalidate();
                pagesListView.Invalidate(selectedItem.Bounds);
                return;
            }

        }

        private Font CreatePreviewBadgeFont(float sizeInPoints)
        {
            try
            {
                return new Font("Segoe UI", sizeInPoints, FontStyle.Bold, GraphicsUnit.Point);
            }
            catch
            {
                return new Font(this.Font.FontFamily, sizeInPoints, FontStyle.Bold, GraphicsUnit.Point);
            }
        }

        private void PagesListView_MouseUp(object sender, MouseEventArgs e)
        {
            if (e.Button != MouseButtons.Left)
            {
                return;
            }

            if (pagesListView.Items.Count == 0)
            {
                return;
            }

            ListViewItem hitItem = pagesListView.HitTest(e.Location).Item;

            // Let native ListView finish processing click first.
            BeginInvoke(new Action(() =>
            {
                if (pagesListView.IsDisposed)
                {
                    return;
                }

                if (pagesListView.SelectedItems.Count > 0)
                {
                    return;
                }

                // Keep stable selection for clicks in empty area / non-hit zones.
                ListViewItem target = hitItem
                    ?? FindListViewItemByPageNumber(currentPage)
                    ?? pagesListView.Items[0];

                ForcePageListSelection(target);
            }));
        }

        private void ForcePageListSelection(ListViewItem item)
        {
            if (item == null || item.ListView != pagesListView)
            {
                return;
            }

            if (pagesListView.SelectedItems.Count != 1 || pagesListView.SelectedItems[0] != item || !item.Selected)
            {
                pagesListView.SelectedItems.Clear();
                item.Selected = true;
            }

            item.Focused = true;
        }

        private void ZoomAtPanelCenter(bool zoomIn)
        {
            // Assume "panel" is mainAppSplitContainer.Panel2 
            // i ma AutoScroll = true.
            this.Cursor = Cursors.WaitCursor;
            ZoomPanel panel = mainAppSplitContainer.Panel2.Controls[0] as ZoomPanel;

            // (A) Calculate the center of the visible "panel" area in its layout (scroll + half client).
            // Note: panel.HorizontalScroll.Value + panel.ClientSize.Width/2 gives us
            // center *relative to top-left corner* in "ScrollValue" pixels.
            int centerScreenX = panel.HorizontalScroll.Value + (panel.ClientSize.Width / 2);
            int centerScreenY = panel.VerticalScroll.Value + (panel.ClientSize.Height / 2);

            // (B) Transform this to "document" coordinates (before changing scaleFactor).
            // Because docCoordX = screenX / oldScale (assuming pdfViewer.Location = (0,0)).
            float docCoordX = centerScreenX / scaleFactor;
            float docCoordY = centerScreenY / scaleFactor;

            // (C) Change scaleFactor (e.g. +/- 0.2)
            if (zoomIn)
                scaleFactor += percentScaleFactor;
            else
                scaleFactor -= percentScaleFactor;

            CalculateMinScaleFactor(currentPage);
            CalculateMaxScaleFactor();

            if (scaleFactor < minScaleFactor)
            {
                minScaleButton = true;
                maxScaleButton = false;
                scaleFactor = minScaleFactor;
            }
            else
            {
                minScaleButton = false;
            }

            if (scaleFactor > maxScaleFactor)
            {
                minScaleButton = false;
                maxScaleButton = true;
                scaleFactor = maxScaleFactor;
            }
            else
            {
                maxScaleButton = false;
            }


            // (D) Call page re-display
            //     (this method sets pdfViewer.Image = ... and pdfViewer.Size = ...)
            DisplayPdfPage(currentPage);

            // (E) Now we want to set scroll so that docCoordX/docCoordY
            //     is again in the center of the screen.
            int newScrollX = (int)(docCoordX * scaleFactor) - (panel.ClientSize.Width / 2);
            int newScrollY = (int)(docCoordY * scaleFactor) - (panel.ClientSize.Height / 2);

            // Protection against exceeding allowable scroll range
            if (newScrollX < panel.HorizontalScroll.Minimum) newScrollX = panel.HorizontalScroll.Minimum;
            if (newScrollX > panel.HorizontalScroll.Maximum) newScrollX = panel.HorizontalScroll.Maximum;
            if (newScrollY < panel.VerticalScroll.Minimum) newScrollY = panel.VerticalScroll.Minimum;
            if (newScrollY > panel.VerticalScroll.Maximum) newScrollY = panel.VerticalScroll.Maximum;

            // Set scroll:
            panel.AutoScrollPosition = new Point(newScrollX, newScrollY);
            // Or: panel.HorizontalScroll.Value = newScrollX; panel.VerticalScroll.Value = newScrollY;
            this.Cursor = Cursors.Default;
        }



        private void ZoomOutButton_Click(object sender, EventArgs e)
        {
            ZoomAtPanelCenter(false);
        }

        private void ZoomInButton_Click(object sender, EventArgs e)
        {
            ZoomAtPanelCenter(true);
        }


        private void ClearPagesToRemove()
        {
            foreach (int pageNum in pagesToRemove)
            {
                pagesListView.Items[pageNum - 1].BackColor = CurrentTheme.SectionBackColor;
                if (pagesListView.Items[pageNum - 1].ForeColor != System.Drawing.Color.Red)
                {
                    pagesListView.Items[pageNum - 1].ForeColor = CurrentTheme.TextPrimaryColor;
                }
            }
            pagesToRemove.Clear();
            UpdateRemovePageButtonVisual(false);
        }

        private void LoadRedactionBlocks(string inputProjectPathTemp, bool registerAsProject = true)
        {
            if (HasUnsavedProjectContent())
            {
                string msqOutText = Resources.Msg_Confirm_DiscardUnsavedRedactions;
                DialogResult result = MessageBox.Show(this,
                    msqOutText,
                    Resources.Title_Confirmation,
                    MessageBoxButtons.YesNo,
                    MessageBoxIcon.Exclamation,
                    MessageBoxDefaultButton.Button2
                );

                if (result == DialogResult.No)
                {
                    return;
                }
            }

            BeginBusyCursor();
            try
            {

            if (File.Exists(inputProjectPathTemp))
            {
                string json = File.ReadAllText(inputProjectPathTemp);

                try
                {
                    ProjectData projectData = JsonConvert.DeserializeObject<ProjectData>(json);
                    var filePath = ResolveProjectPdfPath(projectData.FilePath ?? "", inputProjectPathTemp);

                    if (filePath !="" && filePath != inputPdfPath)
                    {
                        inputPdfPath = filePath;
                        LoadPdf();
                    }

                    if (filePath == "")
                    {
                        MessageBox.Show(this,
                            Resources.Msg_OpenPdfFirst,
                            Resources.Title_Warning,
                            MessageBoxButtons.OK,
                            MessageBoxIcon.Exclamation
                        );
                        return;
                    }
                    List<RedactionBlock> redactionBlocksJson = projectData.RedactionBlocks ?? new List<RedactionBlock>();
                    List<CommentAnnotation> commentAnnotationsJson = (projectData.CommentAnnotations ?? new List<CommentAnnotation>())
                        .Where(obj => obj != null && obj.PageNumber >= 1 && obj.PageNumber <= numPages)
                        .ToList();
                    HashSet<int> pagesToRemoveJson = projectData.PagesToRemove ?? new HashSet<int>();
                    List<TextAnnotation> textAnnotationsJson = projectData.TextAnnotations ?? new List<TextAnnotation>();
                    List<RasterObject> rasterObjectsJson = (projectData.RasterObjects ?? new List<RasterObject>())
                        .Where(obj => obj != null && obj.PageNumber >= 1 && obj.PageNumber <= numPages)
                        .ToList();
                    List<ArrowObject> arrowObjectsJson = (projectData.ArrowObjects ?? new List<ArrowObject>())
                        .Where(obj => obj != null && obj.PageNumber >= 1 && obj.PageNumber <= numPages)
                        .ToList();
                    List<VectorShapeObject> vectorShapesJson = (projectData.VectorShapes ?? new List<VectorShapeObject>())
                        .Where(obj => obj != null && obj.PageNumber >= 1 && obj.PageNumber <= numPages)
                        .ToList();
                    Dictionary<int, int> rotationOffsetsJson = projectData.PageRotationOffsets ?? new Dictionary<int, int>();
                    List<LayerDefinition> layersJson = projectData.Layers ?? new List<LayerDefinition>();
                    string activeLayerIdJson = projectData.ActiveLayerId;
                    List<string> signaturesToRemoveJson = projectData.SignaturesToRemove;
                    string signaturesMode = projectData.SignaturesMode;
                    autoFootnotesEnabled = projectData.AutoFootnotesEnabled ?? Properties.Settings.Default.AutoFootnotesEnabled;
                    if (!string.IsNullOrWhiteSpace(projectData.ExclusionAuthority))
                    {
                        exclusionAuthorityName = projectData.ExclusionAuthority.Trim();
                        SaveExclusionAuthorityUserSetting(exclusionAuthorityName);
                    }
                    ApplyAutomaticFootnotesMenuState();
                    ApplyAddObjectsByPageRotationMenuState();

                    if (redactionBlocksJson.Count > 0)
                    {
                        int maxPageNumber = redactionBlocksJson.Max(rb => rb.PageNumber);
                        if (maxPageNumber > numPages)
                        {
                            MessageBox.Show(this, Resources.Err_SelectValidProjectFile, Resources.Title_Warning, MessageBoxButtons.OK, MessageBoxIcon.Exclamation);
                            return;
                        }
                    }
 
                    ClearRedactionBlocks();
                    redactionBlocks = redactionBlocksJson;
                    foreach (var block in redactionBlocks)
                    {
                        NormalizeRedactionBlockMetadata(block);
                        EnsureRedactionBlockTimestamps(block);
                    }

                    ClearCommentAnnotations();
                    commentAnnotations = commentAnnotationsJson;
                    foreach (var comment in commentAnnotations)
                    {
                        NormalizeCommentAnnotation(comment);
                    }

                    ClearPagesToRemove();
                    pagesToRemove = pagesToRemoveJson;

                    ClearTextAnnotations();
                    textAnnotations = textAnnotationsJson; 
                    foreach (var annotation in textAnnotations)
                    {
                        EnsureTextAnnotationTimestamps(annotation);
                    }

                    ClearRasterObjects();
                    rasterObjects = rasterObjectsJson;
                    foreach (var rasterObject in rasterObjects)
                    {
                        rasterObject.Rotation = NormalizeRotation(rasterObject.Rotation);
                        rasterObject.Opacity = NormalizeOpacity(rasterObject.Opacity);
                        GetResolvedRasterInitialBounds(rasterObject);
                        ConstrainRasterObjectToPage(rasterObject);
                    }

                    ClearArrowObjects();
                    arrowObjects = arrowObjectsJson;
                    foreach (var arrowObject in arrowObjects)
                    {
                        if (string.IsNullOrWhiteSpace(arrowObject.Id))
                        {
                            arrowObject.Id = Guid.NewGuid().ToString("N");
                        }

                        if (!IsArrowColorValid(arrowObject))
                        {
                            arrowObject.LineColorArgb = DefaultArrowColor.ToArgb();
                        }

                        arrowObject.Thickness = NormalizeArrowThickness(arrowObject.Thickness);
                        arrowObject.BorderWidth = NormalizeArrowBorderWidth(arrowObject.BorderWidth);
                        arrowObject.HeadLength = NormalizeArrowHeadLength(arrowObject.HeadLength);
                        arrowObject.HeadWidth = NormalizeArrowHeadWidth(arrowObject.HeadWidth);
                        ConstrainArrowToPage(arrowObject);
                    }

                    ClearVectorShapes();
                    vectorShapes = vectorShapesJson;
                    foreach (var vectorShape in vectorShapes)
                    {
                        NormalizeVectorShape(vectorShape);
                    }
                    documentLayers = NormalizeLayerDefinitions(layersJson);
                    activeLayerId = NormalizeLayerIdValue(activeLayerIdJson);
                    exportVisibleLayersOnly = projectData.ExportVisibleLayersOnly;
                    EnsureObjectLayerAssignments();
                    RefreshLayersTab();
                    LoadProjectObjectLayerOrder(projectData.ObjectLayers);

                    pageRotationOffsets = rotationOffsetsJson
                        .Where(kvp => kvp.Key >= 1 && kvp.Key <= numPages)
                        .Select(kvp => new KeyValuePair<int, int>(kvp.Key, NormalizeRotation(kvp.Value)))
                        .Where(kvp => kvp.Value != 0)
                        .ToDictionary(kvp => kvp.Key, kvp => kvp.Value);

                    hasCustomSignatureSelection = signaturesToRemoveJson != null;
                    signaturesToRemove = signaturesToRemoveJson ?? new List<string>();
                    SyncSignatureSelectionWithAvailableSignatures();
                    UpdateSignatureSelectionMenuState();

                    ApplySignatureModeFromProject(signaturesMode);

                    if (projectData.CurrentPage > 0)
                    {
                        currentPage = Math.Max(1, Math.Min(projectData.CurrentPage, numPages));
                    }

                    if (projectData.ZoomFactor.HasValue && projectData.ZoomFactor.Value > 0)
                    {
                        scaleFactor = projectData.ZoomFactor.Value;
                        pendingScaleFactor = scaleFactor;
                        minScaleButton = false;
                        maxScaleButton = false;
                    }

                    if (projectData.ScrollX.HasValue || projectData.ScrollY.HasValue)
                    {
                        QueuePendingViewScrollRestore(projectData.ScrollX ?? 0, projectData.ScrollY ?? 0);
                    }

                    foreach (var statusItem in allPageStatuses)
                    {
                        statusItem.HasRotation = false;
                    }
                    foreach (var kvp in pageRotationOffsets)
                    {
                        int pageNum = kvp.Key;
                        allPageStatuses[pageNum - 1].HasRotation = true;
                    }

                    ReloadRefreshCurrentPage();

                    pdfViewer.Invalidate();
                    UpdateSelectionNavigationButtons();

                    PageItemStatus status;

                    foreach (var block in redactionBlocks)
                    {
                        status = allPageStatuses[block.PageNumber - 1];
                        var item = pagesListView.Items[block.PageNumber - 1];
                        //bool hasSearchResults = ((PageItemStatus)item.Tag).HasSearchResults;
                        //bool markedForDeletion = ((PageItemStatus)item.Tag).MarkedForDeletion;
                        //bool hasObjects = ((PageItemStatus)item.Tag).HasObjects;
                        status.HasSelections = true;
                        //allPageStatuses.Add(status);
                        //UpdateItemTag(item, block.PageNumber, true, hasSearchResults, markedForDeletion, hasObjects);
                        UpdateItemTag(item, block.PageNumber, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                        pagesListView.Invalidate(item.Bounds);
                    }

                    foreach (var block in textAnnotations)
                    {
                        status = allPageStatuses[block.PageNumber - 1];
                        var item = pagesListView.Items[block.PageNumber - 1];
                        //bool hasSelections = ((PageItemStatus)item.Tag).HasSelections;
                        //bool hasSearchResults = ((PageItemStatus)item.Tag).HasSearchResults;
                        //bool markedForDeletion = ((PageItemStatus)item.Tag).MarkedForDeletion;
                        //UpdateItemTag(item, block.PageNumber, hasSelections, hasSearchResults, markedForDeletion, true);
                        status.HasObjects = true;
                        UpdateItemTag(item, block.PageNumber, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                        pagesListView.Invalidate(item.Bounds);
                    }

                    foreach (var comment in commentAnnotations)
                    {
                        status = allPageStatuses[comment.PageNumber - 1];
                        var item = pagesListView.Items[comment.PageNumber - 1];
                        status.HasObjects = true;
                        UpdateItemTag(item, comment.PageNumber, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                        pagesListView.Invalidate(item.Bounds);
                    }

                    foreach (var rasterObject in rasterObjects)
                    {
                        status = allPageStatuses[rasterObject.PageNumber - 1];
                        var item = pagesListView.Items[rasterObject.PageNumber - 1];
                        status.HasObjects = true;
                        UpdateItemTag(item, rasterObject.PageNumber, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                        pagesListView.Invalidate(item.Bounds);
                    }

                    foreach (var arrowObject in arrowObjects)
                    {
                        status = allPageStatuses[arrowObject.PageNumber - 1];
                        var item = pagesListView.Items[arrowObject.PageNumber - 1];
                        status.HasObjects = true;
                        UpdateItemTag(item, arrowObject.PageNumber, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                        pagesListView.Invalidate(item.Bounds);
                    }

                    foreach (var vectorShape in vectorShapes)
                    {
                        status = allPageStatuses[vectorShape.PageNumber - 1];
                        var item = pagesListView.Items[vectorShape.PageNumber - 1];
                        status.HasObjects = true;
                        UpdateItemTag(item, vectorShape.PageNumber, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                        pagesListView.Invalidate(item.Bounds);
                    }

                    foreach (var pageNum in pagesToRemove)
                    {
                        status = allPageStatuses[pageNum - 1];
                        if (pageNum == 1)
                        {
                            UpdateRemovePageButtonVisual(true);
                        }
                        var item = pagesListView.Items[pageNum - 1];

                        //bool hasSelections = ((PageItemStatus)item.Tag).HasSelections;
                        //bool hasSearchResults = ((PageItemStatus)item.Tag).HasSearchResults;
                        //bool hasObjects = ((PageItemStatus)item.Tag).HasObjects;
                        //UpdateItemTag(item, pageNum, hasSelections, hasSearchResults, true, hasObjects);
                        //pagesListView.Invalidate();
                        status.MarkedForDeletion = true;
                        UpdateItemTag(item, pageNum, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                        pagesListView.Invalidate(item.Bounds);
                    }

                    foreach (ListViewItem item in pagesListView.Items)
                    {
                        int pageNum = ((PageItemStatus)item.Tag).PageNumber;
                        PageItemStatus currentStatus = allPageStatuses[pageNum - 1];
                        UpdateItemTag(item, pageNum, currentStatus.HasSelections, currentStatus.HasSearchResults, currentStatus.MarkedForDeletion, currentStatus.HasObjects);
                        pagesListView.Invalidate(item.Bounds);
                    }

                    if (numPages > 0)
                    {
                        if ((string)filterComboBox.SelectedItem == allComboItem)
                        {
                            pagesListView.Items[currentPage - 1].Selected = true;
                            pagesListView.Items[currentPage - 1].EnsureVisible();
                        }
                        else
                        {
                            ListViewItem currentItem = FindListViewItemByPageNumber(currentPage);
                            if (currentItem != null)
                            {
                                currentItem.Selected = true;
                                currentItem.EnsureVisible();
                            }
                            else
                            {
                                pagesListView.SelectedItems.Clear();
                            }
                        }
                    }

                    BeginInvoke(new MethodInvoker(() =>
                    {
                        RestoreRightPanelsViewState(projectData.PagesListTopPage, projectData.ThumbnailsTopPage);
                    }));

                    if (registerAsProject)
                    {
                        inputProjectPath = inputProjectPathTemp;
                        //Properties.Settings.Default.LastPapPath = inputProjectPath;
                        //Properties.Settings.Default.Save();
                        projectWasChangedAfterLastSave = false;
                        ResetUndoRedoHistory(resetSavedStateSignature: true);
                        AddRecentFile(inputProjectPathTemp);
                    }
                    else
                    {
                        inputProjectPath = "";
                        lastSavedProjectName = "";
                        projectWasChangedAfterLastSave = true;
                        ResetUndoRedoHistory();
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                        saveProjectAsButton.Enabled = true;
                        saveProjectAsMenuItem.Enabled = true;
                    }

                    UpdateSelectionNavigationButtons();
                    UpdateWindowTitle();
                }
                catch (Exception)
                {
                    UpdateWindowTitle();
                    MessageBox.Show(this, Resources.Err_InvalidProjectFormat, Resources.Title_Error, MessageBoxButtons.OK, MessageBoxIcon.Error);
                    return;
                }
            }
            }
            finally
            {
                EndBusyCursor();
            }
        }

        private void SaveProjectAs()
        {
            using (SaveFileDialog saveFileDialog = new SaveFileDialog())
            {
                string filePapName = "";
                if (lastSavedProjectName != "")
                {
                    filePapName = lastSavedProjectName;
                }
                else if (inputProjectPath != "")
                {
                    filePapName = inputProjectPath;
                }
                else
                {
                    filePapName = inputPdfPath;
                }

                saveFileDialog.Filter = Resources.Dialog_Filter_PAP;
                saveFileDialog.Title = string.Format(Resources.Dialog_Title_SavePap, Branding.ProductName);
                saveFileDialog.FileName = $"{System.IO.Path.GetFileNameWithoutExtension(filePapName)}{ProjectFileExtension}";

                if (saveFileDialog.ShowDialog(this) == DialogResult.OK)
                {
                    try
                    {
                        var jsonSettings = new JsonSerializerSettings
                        {
                            Formatting = Formatting.Indented // prettier, indented format
                        };

                        ProjectData projectData = BuildCurrentProjectDataSnapshot(includeViewState: true);

                        // Serialize list to JSON string
                        string json = JsonConvert.SerializeObject(projectData, jsonSettings);

                        // Write to .app file (plain text)
                        lastSavedProjectName = saveFileDialog.FileName;
                        File.WriteAllText(lastSavedProjectName, json);

                        DialogResult result = MessageBox.Show(this,
                            Resources.Msg_ProjectSaved,
                            Resources.Title_Success,
                            MessageBoxButtons.OK,
                            MessageBoxIcon.Information
                        );
                        projectWasChangedAfterLastSave = false;
            saveProjectButton.Enabled = false;
            saveProjectMenuItem.Enabled = false;
                        MarkCurrentStateAsSavedBaseline();
                        Properties.Settings.Default.LastPapPath = lastSavedProjectName;
                        Properties.Settings.Default.Save();
                        UpdateWindowTitle();
                    }
                    catch (Exception ex)
                    {
                        MessageBox.Show(this, string.Format(Resources.Err_Save, ex.Message), Resources.Title_Error, MessageBoxButtons.OK, MessageBoxIcon.Error);
                    }
                }
            }

        }

        private void SaveProjectAsButton_Click(object sender, EventArgs e)
        {
            //if (redactionBlocks.Count == 0 && pagesToRemove.Count == 0)
            //{
            //    MessageBox.Show(this, "Select content or page to remove.", "Information", MessageBoxButtons.OK, MessageBoxIcon.Information);
            //    return;
            //}

            SaveProjectAs();
        }

