        private void AboutToolStripMenuItem_Click(object sender, EventArgs e)
        {
            // Build "About application" message using localized resources
            var assembly = Assembly.GetExecutingAssembly();
            var companyAttribute = assembly.GetCustomAttribute<AssemblyCompanyAttribute>();
            var companyName = companyAttribute?.Company ?? string.Empty;
            var copyrightAttribute = assembly.GetCustomAttribute<AssemblyCopyrightAttribute>();
            var copyright = Resources.ResourceManager.GetString("About_Copyright", Resources.Culture);
            if (string.IsNullOrWhiteSpace(copyright))
            {
                copyright = copyrightAttribute?.Copyright ?? string.Empty;
            }
            var descriptionAttribute = assembly.GetCustomAttribute<AssemblyDescriptionAttribute>();
            var description = Resources.ResourceManager.GetString("About_Description", Resources.Culture);
            if (string.IsNullOrWhiteSpace(description))
            {
                description = descriptionAttribute?.Description ?? string.Empty;
            }

            string aboutMessage = string.Format(
                Resources.About_Message,
                Branding.ProductName,
                fileVersion,
                companyName,
                copyright,
                description
            );

            var licenseLine = GetLicenseStatusLine();
            var updatesLine = GetUpdatesStatusLine();
            var licensedToLine = GetLicensedToLine();
            if (!string.IsNullOrWhiteSpace(licenseLine))
            {
                aboutMessage += Environment.NewLine + Environment.NewLine + licenseLine;
            }
            if (!string.IsNullOrWhiteSpace(licensedToLine))
            {
                aboutMessage += Environment.NewLine + licensedToLine;
            }
            if (!string.IsNullOrWhiteSpace(updatesLine))
            {
                aboutMessage += Environment.NewLine + updatesLine;
            }

            // Display information in dialog box
            MessageBox.Show(this,
                aboutMessage,
                Resources.Menu_Help_About,
                MessageBoxButtons.OK,
                MessageBoxIcon.Information
            );
        }

        private bool TryCancelActiveDrawActionWithEscape()
        {
            bool cancelled = false;
            bool drawingWasCancelled = false;

            if (isDrawing)
            {
                isDrawing = false;
                isMarkerCtrlBoxMode = false;
                currentSelection = RectangleF.Empty;
                suppressNextLeftMouseUpAfterEscape = true;
                cancelled = true;
                drawingWasCancelled = true;
            }

            if (isVectorShapeCreationMode)
            {
                if (vectorShapeDraftPoints.Count > 0)
                {
                    vectorShapeDraftPoints.Clear();
                    vectorShapeDraftHoverActive = false;
                    cancelled = true;
                }
                else
                {
                    EndVectorShapeCreationMode();
                    cancelled = true;
                }
            }

            if (isCommentCreationMode && !drawingWasCancelled)
            {
                EndCommentCreationMode();
                cancelled = true;
            }

            if (cancelled)
            {
                pdfViewer.Invalidate();
            }

            return cancelled;
        }

        private bool TryCancelActiveManipulationWithEscape()
        {
            bool cancelled = false;

            if (isMovingObjectGroup || isScalingObjectGroup)
            {
                foreach (GroupMoveEntry entry in groupMoveEntries)
                {
                    if (entry == null)
                    {
                        continue;
                    }

                    switch (entry.Type)
                    {
                        case GroupMoveObjectType.Text:
                            if (entry.Text != null)
                            {
                                entry.Text.AnnotationBounds = entry.Bounds;
                                FontFamily fontFamily = entry.TextFontFamily ?? entry.Text.AnnotationFont?.FontFamily ?? FontFamily.GenericSansSerif;
                                entry.Text.AnnotationFont = new Font(fontFamily, Math.Max(4f, entry.TextFontSize), entry.TextFontStyle, entry.TextFontUnit);
                                entry.Text.AnnotationBorderWidth = Math.Max(0f, entry.TextBorderWidth);
                                entry.Text.AnnotationFrameMargin = Math.Max(0f, entry.TextFrameMargin);
                                if (entry.Text.HasLeaderArrow)
                                {
                                    entry.Text.LeaderEndPoint = entry.TextLeaderEndPoint;
                                    entry.Text.LeaderLineWidth = NormalizeLeaderLineWidth(entry.TextLeaderLineWidth);
                                    entry.Text.LeaderHeadLength = NormalizeTextLeaderHeadLength(entry.TextLeaderHeadLength);
                                    entry.Text.LeaderHeadWidth = NormalizeTextLeaderHeadWidth(entry.TextLeaderHeadWidth);
                                    entry.Text.LeaderAnchorKind = GetClosestTextLeaderAnchorKind(entry.Text, entry.Text.LeaderEndPoint);
                                }
                                TouchTextAnnotation(entry.Text);
                            }
                            break;
                        case GroupMoveObjectType.Raster:
                            if (entry.Raster != null)
                            {
                                entry.Raster.Bounds = entry.Bounds;
                            }
                            break;
                        case GroupMoveObjectType.Arrow:
                            if (entry.Arrow != null)
                            {
                                entry.Arrow.Start = entry.Start;
                                entry.Arrow.End = entry.End;
                                entry.Arrow.Thickness = NormalizeArrowThickness(entry.ArrowThickness);
                                entry.Arrow.BorderWidth = NormalizeArrowBorderWidth(entry.ArrowBorderWidth);
                                entry.Arrow.HeadLength = NormalizeArrowHeadLength(entry.ArrowHeadLength);
                                entry.Arrow.HeadWidth = NormalizeArrowHeadWidth(entry.ArrowHeadWidth);
                            }
                            break;
                        case GroupMoveObjectType.VectorShape:
                            if (entry.VectorShape != null && entry.Points != null)
                            {
                                entry.VectorShape.Points = entry.Points.Select(point => new PointF(point.X, point.Y)).ToList();
                                entry.VectorShape.StrokeWidth = NormalizeVectorStrokeWidth(entry.VectorStrokeWidth);
                                entry.VectorShape.StartLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(entry.VectorStartEndingPrimarySize);
                                entry.VectorShape.StartLineEndingSecondarySize = entry.VectorStartEndingSecondarySize;
                                entry.VectorShape.EndLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(entry.VectorEndEndingPrimarySize);
                                entry.VectorShape.EndLineEndingSecondarySize = entry.VectorEndEndingSecondarySize;
                                NormalizeVectorShape(entry.VectorShape);
                            }
                            break;
                    }
                }

                groupMoveChanged = false;
                groupScaleChanged = false;
                ResetGroupMoveState();
                this.Cursor = Cursors.Default;
                cancelled = true;
            }

            if (isResizingCommentNote && commentNoteToResize != null)
            {
                if (!commentNoteStartRectDoc.IsEmpty)
                {
                    commentNoteToResize.NoteX = commentNoteStartRectDoc.X;
                    commentNoteToResize.NoteY = commentNoteStartRectDoc.Y;
                    commentNoteToResize.NoteWidth = commentNoteStartRectDoc.Width;
                    commentNoteToResize.NoteHeight = commentNoteStartRectDoc.Height;
                }

                ResetCommentNoteMoveState();
                commentNoteRectsDoc.Clear();
                this.Cursor = Cursors.Default;
                cancelled = true;
            }
            else if (isMovingCommentNote && commentNoteToMove != null)
            {
                if (!commentNoteStartRectDoc.IsEmpty)
                {
                    commentNoteToMove.NoteX = commentNoteStartRectDoc.X;
                    commentNoteToMove.NoteY = commentNoteStartRectDoc.Y;
                }

                ResetCommentNoteMoveState();
                commentNoteRectsDoc.Clear();
                this.Cursor = Cursors.Default;
                cancelled = true;
            }

            if ((isRotatingTextAnnotation && annotationToRotate != null) ||
                (isScalingTextAnnotation && annotationToScale != null) ||
                (isDraggingTextLeaderHandle && annotationToAdjustLeader != null))
            {
                TextAnnotation textToRestore = annotationToRotate ?? annotationToScale ?? annotationToAdjustLeader;
                if (isRotatingTextAnnotation && annotationToRotate != null)
                {
                    annotationToRotate.AnnotationRotation = NormalizeRotation(textRotationStartValue);
                }

                if (textToRestore != null && !textScaleStartBounds.IsEmpty)
                {
                    textToRestore.AnnotationBounds = textScaleStartBounds;
                    FontFamily fontFamily = textScaleStartFontFamily ?? textToRestore.AnnotationFont?.FontFamily ?? FontFamily.GenericSansSerif;
                    textToRestore.AnnotationFont = new Font(fontFamily, Math.Max(4f, textScaleStartFontSize), textScaleStartFontStyle, textScaleStartFontUnit);
                    textToRestore.AnnotationBorderWidth = Math.Max(0f, textScaleStartBorderWidth);
                    textToRestore.AnnotationFrameMargin = Math.Max(0f, textScaleStartFrameMargin);
                    if (textToRestore.HasLeaderArrow)
                    {
                        textToRestore.LeaderEndPoint = textScaleStartLeaderEndPoint;
                        textToRestore.LeaderLineWidth = NormalizeLeaderLineWidth(textScaleStartLeaderLineWidth);
                        textToRestore.LeaderHeadLength = NormalizeTextLeaderHeadLength(textScaleStartLeaderHeadLength);
                        textToRestore.LeaderHeadWidth = NormalizeTextLeaderHeadWidth(textScaleStartLeaderHeadWidth);
                    }
                    TouchTextAnnotation(textToRestore);
                }

                if (isRotatingTextAnnotation && !textRotationStartBounds.IsEmpty && annotationToRotate != null)
                {
                    annotationToRotate.AnnotationBounds = textRotationStartBounds;
                }

                if (isDraggingTextLeaderHandle && annotationToAdjustLeader != null)
                {
                    annotationToAdjustLeader.LeaderEndPoint = textLeaderDragStartEndPoint;
                    annotationToAdjustLeader.LeaderAnchorKind = textLeaderDragStartAnchorKind;
                    TouchTextAnnotation(annotationToAdjustLeader);
                }

                textRotationInteractionChanged = false;
                ResetTextRotationInteractionState();
                this.Cursor = Cursors.Default;
                cancelled = true;
            }

            if (isMoving && annotationToMove != null)
            {
                if (!textMoveStartBounds.IsEmpty)
                {
                    annotationToMove.AnnotationBounds = textMoveStartBounds;
                    if (annotationToMove.HasLeaderArrow)
                    {
                        annotationToMove.LeaderEndPoint = textMoveStartLeaderEndPoint;
                    }
                }

                isMoving = false;
                annotationToMove = null;
                textMoveMouseOffset = PointF.Empty;
                textMoveStartBounds = RectangleF.Empty;
                textMoveStartLeaderEndPoint = PointF.Empty;
                this.Cursor = Cursors.Default;
                cancelled = true;
            }

            if (arrowMouseActionInProgress || isMovingArrowObject || isAdjustingArrowHandle || isScalingArrowObject)
            {
                ArrowObject arrowToRestore = arrowObjectToMove ?? arrowObjectToAdjust ?? arrowObjectToScale;
                if (arrowToRestore != null)
                {
                    arrowToRestore.Start = arrowMoveInitialStart;
                    arrowToRestore.End = arrowMoveInitialEnd;
                    arrowToRestore.Thickness = NormalizeArrowThickness(arrowScaleStartThickness > 0f ? arrowScaleStartThickness : arrowToRestore.Thickness);
                    arrowToRestore.BorderWidth = NormalizeArrowBorderWidth(arrowScaleStartBorderWidth >= 0f ? arrowScaleStartBorderWidth : arrowToRestore.BorderWidth);
                    arrowToRestore.HeadLength = NormalizeArrowHeadLength(arrowScaleStartHeadLength > 0f ? arrowScaleStartHeadLength : arrowToRestore.HeadLength);
                    arrowToRestore.HeadWidth = NormalizeArrowHeadWidth(arrowScaleStartHeadWidth > 0f ? arrowScaleStartHeadWidth : arrowToRestore.HeadWidth);
                }

                arrowInteractionChanged = false;
                ResetArrowInteractionState();
                this.Cursor = Cursors.Default;
                cancelled = true;
            }

            if (rasterMouseActionInProgress || isMovingRasterObject || isRotatingRasterObject || isResizingRasterObject)
            {
                if (isMovingRasterObject && rasterObjectToMove != null && HasPositiveSize(rasterMoveStartBounds))
                {
                    rasterObjectToMove.Bounds = rasterMoveStartBounds;
                    ApplyRasterMoveAttachedClipDelta(0f, 0f);
                }

                if (isRotatingRasterObject && rasterObjectToRotate != null)
                {
                    rasterObjectToRotate.Rotation = NormalizeRotation(rasterRotationStartValue);
                    if (HasPositiveSize(rasterRotateStartBounds))
                    {
                        rasterObjectToRotate.Bounds = rasterRotateStartBounds;
                        PointF centerDoc = new PointF(
                            rasterRotateStartBounds.X + (rasterRotateStartBounds.Width / 2f),
                            rasterRotateStartBounds.Y + (rasterRotateStartBounds.Height / 2f));
                        ApplyRasterRotateAttachedClipDelta(0f, centerDoc);
                    }
                }

                if (isResizingRasterObject && rasterObjectToResize != null && HasPositiveSize(rasterResizeStartBounds))
                {
                    rasterObjectToResize.Bounds = rasterResizeStartBounds;
                }

                ResetRasterInteractionState();
                this.Cursor = Cursors.Default;
                cancelled = true;
            }

            if (vectorMouseActionInProgress || isMovingVectorShape || isAdjustingVectorHandle || isRotatingVectorShape || isScalingVectorShape)
            {
                if (isMovingVectorShape && vectorShapeToMove != null && vectorMoveInitialPoints != null && vectorMoveInitialPoints.Count > 0)
                {
                    vectorShapeToMove.Points = vectorMoveInitialPoints.Select(point => new PointF(point.X, point.Y)).ToList();
                }

                if (isAdjustingVectorHandle && vectorShapeToAdjust != null && vectorMoveInitialPoints != null && vectorMoveInitialPoints.Count > 0)
                {
                    vectorShapeToAdjust.Points = vectorMoveInitialPoints.Select(point => new PointF(point.X, point.Y)).ToList();
                }

                if (isRotatingVectorShape && vectorShapeToRotate != null && vectorRotateInitialPoints != null && vectorRotateInitialPoints.Count > 0)
                {
                    vectorShapeToRotate.Points = vectorRotateInitialPoints.Select(point => new PointF(point.X, point.Y)).ToList();
                }

                if (isScalingVectorShape && vectorShapeToScale != null && vectorMoveInitialPoints != null && vectorMoveInitialPoints.Count > 0)
                {
                    vectorShapeToScale.Points = vectorMoveInitialPoints.Select(point => new PointF(point.X, point.Y)).ToList();
                    vectorShapeToScale.StrokeWidth = NormalizeVectorStrokeWidth(vectorScaleStartStrokeWidth > 0f ? vectorScaleStartStrokeWidth : vectorShapeToScale.StrokeWidth);
                    vectorShapeToScale.StartLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(vectorScaleStartStartEndingPrimarySize);
                    vectorShapeToScale.StartLineEndingSecondarySize = vectorScaleStartStartEndingSecondarySize;
                    vectorShapeToScale.EndLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(vectorScaleStartEndEndingPrimarySize);
                    vectorShapeToScale.EndLineEndingSecondarySize = vectorScaleStartEndEndingSecondarySize;
                    NormalizeVectorShape(vectorShapeToScale);
                }

                vectorInteractionChanged = false;
                ResetVectorInteractionState();
                this.Cursor = Cursors.Default;
                cancelled = true;
            }

            if (cancelled)
            {
                suppressNextLeftMouseUpAfterEscape = true;
                pdfViewer.Invalidate();
            }

            return cancelled;
        }

        protected override bool ProcessCmdKey(ref Message msg, Keys keyData)
        {
            if (keyData == (Keys.Control | Keys.Z))
            {
                if (IsTextInputFocused())
                {
                    return base.ProcessCmdKey(ref msg, keyData);
                }

                BeginBusyCursor();
                try
                {
                    if (UndoLastAction())
                    {
                        return true;
                    }
                }
                finally
                {
                    EndBusyCursor();
                }
            }

            if (keyData == (Keys.Control | Keys.Y))
            {
                if (IsTextInputFocused())
                {
                    return base.ProcessCmdKey(ref msg, keyData);
                }

                BeginBusyCursor();
                try
                {
                    if (RedoLastAction())
                    {
                        return true;
                    }
                }
                finally
                {
                    EndBusyCursor();
                }
            }

            if (keyData == Keys.Escape)
            {
                if (TryCancelActiveManipulationWithEscape())
                {
                    return true;
                }

                if (TryCancelActiveDrawActionWithEscape())
                {
                    return true;
                }
            }

            if (keyData == Keys.F11)
            {
                SetFullScreen(!isFullScreen);
                return true;
            }

            if (keyData == Keys.Escape && isFullScreen)
            {
                SetFullScreen(false);
                return true;
            }

            Keys keyCode = keyData & Keys.KeyCode;
            if ((keyCode == Keys.Left || keyCode == Keys.Right || keyCode == Keys.Up || keyCode == Keys.Down) &&
                !IsTextInputFocused() &&
                TryPanDocumentViewport(keyData))
            {
                return true;
            }

            if (keyData == (Keys.Control | Keys.A))
            {
                if (IsTextInputFocused())
                {
                    return base.ProcessCmdKey(ref msg, keyData);
                }

                SelectAllObjectsOnCurrentPage();
                return true;
            }

            if (keyData == (Keys.Control | Keys.Shift | Keys.A))
            {
                if (IsTextInputFocused())
                {
                    return base.ProcessCmdKey(ref msg, keyData);
                }

                AddArrowObject();
                return true;
            }

            if (keyData == (Keys.Control | Keys.F))
            {
                if (IsTextInputFocused())
                {
                    return base.ProcessCmdKey(ref msg, keyData);
                }

                AddShapeToolStripMenuItem_Click(this, EventArgs.Empty);
                return true;
            }

            if (keyData == (Keys.Control | Keys.R))
            {
                if (IsTextInputFocused())
                {
                    return base.ProcessCmdKey(ref msg, keyData);
                }

                BeginUndoCapture("Rotate page");
                RotateCurrentPageClockwise();
                CommitUndoCapture();
                return true;
            }

            if (keyData == (Keys.Control | Keys.G))
            {
                if (IsTextInputFocused())
                {
                    return base.ProcessCmdKey(ref msg, keyData);
                }

                AddRasterImageFromFileDialog();
                return true;
            }

            if (keyData == (Keys.Control | Keys.C))
            {
                if (IsTextInputFocused())
                {
                    return base.ProcessCmdKey(ref msg, keyData);
                }

                if (TryCopySelectedObjectsToClipboard())
                {
                    return true;
                }

                CopyTextsFromAllSelectionsOnCurrentPage();
                return true;
            }

            if (keyData == (Keys.Control | Keys.V))
            {
                if (IsTextInputFocused())
                {
                    return base.ProcessCmdKey(ref msg, keyData);
                }

                BeginUndoCapture("Paste object");
                if (TryPasteObjectsFromSystemClipboard())
                {
                    CommitUndoCapture();
                    return true;
                }

                bool externalClipboardContentAvailable = IsExternalClipboardContentAvailable();
                if (HasNewerExternalClipboardData(externalClipboardContentAvailable) &&
                    TryHandleGlobalPasteShortcut())
                {
                    preferObjectClipboardPaste = false;
                    CommitUndoCapture();
                    return true;
                }

                // If user previously copied app object(s), prefer pasting them
                // unless system clipboard changed afterwards.
                if (preferObjectClipboardPaste && TryPasteObjectsFromInternalClipboard())
                {
                    CommitUndoCapture();
                    return true;
                }

                if (externalClipboardContentAvailable && TryHandleGlobalPasteShortcut())
                {
                    preferObjectClipboardPaste = false;
                    CommitUndoCapture();
                    return true;
                }

                if (TryPasteObjectsFromInternalClipboard())
                {
                    CommitUndoCapture();
                    return true;
                }

                if (!externalClipboardContentAvailable && TryHandleGlobalPasteShortcut())
                {
                    preferObjectClipboardPaste = false;
                    CommitUndoCapture();
                    return true;
                }
                CancelUndoCapture();
            }

            // Check if it's just Delete without modifiers
            if (keyData == Keys.Delete)
            {
                // 1) If focus is in searchTextBox, let textbox delete character:
                if (searchTextBox.Focused)
                    return false;  // we don't handle - pass on to control

                // 2) If any object is active, delete that object first.
                BeginUndoCapture("Delete");
                if (TryDeleteActiveObjectByKeyboard())
                {
                    CommitUndoCapture();
                    return true;
                }

                // 2) Otherwise treat Delete as "delete page":
                BeginUndoCapture("Delete page");
                RemovePage();
                CommitUndoCapture();
                return true;     // handled, don't pass on
            }

            // remaining keys
            return base.ProcessCmdKey(ref msg, keyData);
        }

        private bool TryHandleGlobalPasteShortcut()
        {
            if (pdf == null || numPages <= 0)
            {
                ShowInfoMessage(Resources.Msg_OpenPdfFirst);
                return true;
            }

            try
            {
                IDataObject clipboardData = Clipboard.GetDataObject();
                if (clipboardData == null)
                {
                    return false;
                }

                if (clipboardData.GetDataPresent(DataFormats.UnicodeText) || clipboardData.GetDataPresent(DataFormats.Text))
                {
                    string pastedText = Clipboard.GetText(TextDataFormat.UnicodeText)?.Trim();
                    if (string.IsNullOrWhiteSpace(pastedText))
                    {
                        pastedText = Clipboard.GetText()?.Trim();
                    }

                    if (!string.IsNullOrWhiteSpace(pastedText))
                    {
                        AddEditAnnotation(initialText: pastedText);
                        return true;
                    }
                }

                bool hasRasterGraphic = clipboardData.GetDataPresent(DataFormats.Bitmap) || Clipboard.ContainsImage();
                bool hasVectorGraphic = clipboardData.GetDataPresent(DataFormats.EnhancedMetafile) || clipboardData.GetDataPresent(DataFormats.MetafilePict);

                if (hasRasterGraphic)
                {
                    return TryAddRasterObjectFromClipboard();
                }

                if (hasVectorGraphic)
                {
                    ShowInfoMessage(LocalizedText("Msg_PasteVectorGraphic_NotImplemented"));
                    return true;
                }
            }
            catch (ExternalException)
            {
                ShowInfoMessage(LocalizedText("Msg_ClipboardUnavailable"));
                return true;
            }
            catch (Exception ex)
            {
                LogDebug("Paste shortcut handling failed: " + ex.Message);
            }

            return false;
        }

        private static bool IsExternalClipboardContentAvailable()
        {
            try
            {
                IDataObject clipboardData = Clipboard.GetDataObject();
                if (clipboardData == null)
                {
                    return false;
                }

                return clipboardData.GetDataPresent(AppObjectClipboardFormat) ||
                       clipboardData.GetDataPresent(DataFormats.UnicodeText) ||
                       clipboardData.GetDataPresent(DataFormats.Text) ||
                       clipboardData.GetDataPresent(DataFormats.Bitmap) ||
                       clipboardData.GetDataPresent(DataFormats.EnhancedMetafile) ||
                       clipboardData.GetDataPresent(DataFormats.MetafilePict) ||
                       Clipboard.ContainsImage();
            }
            catch
            {
                return false;
            }
        }

        private bool TryAddRasterObjectFromClipboard()
        {
            if (!EnsureCurrentPageEditable(true))
            {
                return true;
            }

            DrawingImage clipboardImage = Clipboard.GetImage();
            if (clipboardImage == null)
            {
                ShowInfoMessage(LocalizedText("Msg_NoRasterImageInClipboard"));
                return true;
            }

            try
            {
                using (clipboardImage)
                using (var bitmap = new Bitmap(clipboardImage))
                using (var ms = new MemoryStream())
                {
                    bitmap.Save(ms, ImageFormat.Png);
                    byte[] imageBytes = ms.ToArray();
                    AddRasterObject(
                        imageWidth: bitmap.Width,
                        imageHeight: bitmap.Height,
                        sourceType: RasterSourceClipboard,
                        filePath: null,
                        embeddedBytes: imageBytes,
                        mimeType: "image/png",
                        preferOneToOne: true);
                }

                return true;
            }
            catch (Exception ex)
            {
                ShowInfoMessage(LocalizedFormat("Err_RasterImageLoad", ex.Message));
                LogDebug("Paste raster image failed: " + ex);
                return true;
            }
        }

        private void AddRasterImageFromFileDialog()
        {
            DeactivateObjectCreationModes();

            if (pdf == null || numPages <= 0)
            {
                ShowInfoMessage(Resources.Msg_OpenPdfFirst);
                return;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return;
            }

            BeginUndoCapture("Add image");

            using (var openFileDialog = new OpenFileDialog())
            {
                openFileDialog.Filter = LocalizedText("Dialog_Filter_RasterImages");
                openFileDialog.Title = string.Format(LocalizedText("Dialog_Title_AddRasterImage"), Branding.ProductName);
                openFileDialog.CheckFileExists = true;
                openFileDialog.Multiselect = false;

                if (openFileDialog.ShowDialog(this) != DialogResult.OK)
                {
                    CancelUndoCapture();
                    return;
                }

                try
                {
                    string selectedPath = openFileDialog.FileName;
                    using (var image = DrawingImage.FromFile(selectedPath))
                    {
                        AddRasterObject(
                            imageWidth: image.Width,
                            imageHeight: image.Height,
                            sourceType: RasterSourceFile,
                            filePath: selectedPath,
                            embeddedBytes: null,
                            mimeType: GetRasterMimeTypeFromPath(selectedPath),
                            preferOneToOne: false);
                        CommitUndoCapture();
                    }
                }
                catch (Exception ex)
                {
                    CancelUndoCapture();
                    ShowInfoMessage(LocalizedFormat("Err_RasterImageLoad", ex.Message));
                    LogDebug("Add raster image from file failed: " + ex);
                }
            }
        }

        private void AddRasterObject(
            int imageWidth,
            int imageHeight,
            string sourceType,
            string filePath,
            byte[] embeddedBytes,
            string mimeType,
            bool preferOneToOne = false)
        {
            if (imageWidth <= 0 || imageHeight <= 0)
            {
                return;
            }

            RectangleF initialBounds = preferOneToOne
                ? GetInitialRasterBoundsOneToOne(imageWidth, imageHeight)
                : GetInitialRasterBounds(imageWidth, imageHeight);
            var now = DateTime.UtcNow;
            var rasterObject = new RasterObject
            {
                Id = Guid.NewGuid().ToString("N"),
                PageNumber = currentPage,
                LayerId = GetResolvedActiveLayerId(),
                Bounds = initialBounds,
                InitialBounds = initialBounds,
                Rotation = NormalizeRotation(activeRasterDialogDefaults.Rotation),
                Opacity = NormalizeOpacity(activeRasterDialogDefaults.RasterOpacity),
                TransparentBackground = activeRasterDialogDefaults.TransparentBackground,
                LockAspect = activeRasterDialogDefaults.LockAspect,
                IsLocked = activeRasterDialogDefaults.IsLocked,
                SourceType = sourceType,
                FilePath = filePath,
                EmbeddedBytes = embeddedBytes,
                MimeType = mimeType,
                CreatedAtUtc = now,
                UpdatedAtUtc = now
            };

            ConstrainRasterObjectToPage(rasterObject);
            rasterObject.InitialBounds = rasterObject.Bounds;
            rasterObjects.Add(rasterObject);
            DisableRedactionSelectionMode();
            ClearGroupSelection();
            selectedRasterObject = rasterObject;
            selectedTextAnnotation = null;
            selectedArrowObject = null;
            if (currentPage >= 1 && currentPage <= allPageStatuses.Count)
            {
                PageItemStatus status = allPageStatuses[currentPage - 1];
                status.HasObjects = HasAnyObjectsOnPage(currentPage);
                if ((string)filterComboBox.SelectedItem == allComboItem)
                {
                    ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                    UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                    pagesListView.Invalidate(currentItem.Bounds);
                }
                else
                {
                    ApplyFilter((string)filterComboBox.SelectedItem);
                }
            }
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            pdfViewer.Invalidate();
        }

        private void AddArrowObject()
        {
            DeactivateObjectCreationModes();

            if (pdf == null || numPages <= 0)
            {
                ShowInfoMessage(Resources.Msg_OpenPdfFirst);
                return;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return;
            }

            var pageSize = GetPageSizeWithOffset(currentPage);
            if (pageSize.Width <= 0f || pageSize.Height <= 0f)
            {
                return;
            }

            float defaultLength = Math.Max(60f, Math.Min(pageSize.Width, pageSize.Height) * 0.18f);
            var center = new PointF(pageSize.Width / 2f, pageSize.Height / 2f);
            var start = new PointF(center.X - (defaultLength / 2f), center.Y);
            var end = new PointF(center.X + (defaultLength / 2f), center.Y);

            var now = DateTime.UtcNow;
            var arrow = new ArrowObject
            {
                Id = Guid.NewGuid().ToString("N"),
                PageNumber = currentPage,
                LayerId = GetResolvedActiveLayerId(),
                Start = start,
                End = end,
                LineColorArgb = activeArrowDialogDefaults.ArrowColor.ToArgb(),
                Thickness = NormalizeArrowThickness(activeArrowDialogDefaults.ThicknessValue),
                BorderColorArgb = activeArrowDialogDefaults.BorderColor.ToArgb(),
                BorderWidth = NormalizeArrowBorderWidth(activeArrowDialogDefaults.BorderWidthValue),
                HeadLength = NormalizeArrowHeadLength(activeArrowDialogDefaults.HeadLengthValue),
                HeadWidth = NormalizeArrowHeadWidth(activeArrowDialogDefaults.HeadWidthValue),
                IsLocked = activeArrowDialogDefaults.IsLocked,
                CreatedAtUtc = now,
                UpdatedAtUtc = now
            };

            ConstrainArrowToPage(arrow);
            arrowObjects.Add(arrow);
            DisableRedactionSelectionMode();
            ClearGroupSelection();
            selectedArrowObject = arrow;
            selectedRasterObject = null;
            selectedTextAnnotation = null;
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            UpdateCurrentPageObjectsMarker();
            pdfViewer.Invalidate();
        }

        private static bool IsArrowColorValid(ArrowObject arrowObject)
        {
            if (arrowObject == null)
            {
                return false;
            }

            try
            {
                var color = System.Drawing.Color.FromArgb(arrowObject.LineColorArgb);
                return color.A > 0 || color.R > 0 || color.G > 0 || color.B > 0;
            }
            catch
            {
                return false;
            }
        }

        private void EditArrowObject(ArrowObject arrowObject)
        {
            if (arrowObject == null || arrowObject.PageNumber != currentPage)
            {
                return;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return;
            }

            int originalLineColorArgb = arrowObject.LineColorArgb;
            float originalThickness = NormalizeArrowThickness(arrowObject.Thickness);
            int originalBorderColorArgb = arrowObject.BorderColorArgb;
            float originalBorderWidth = NormalizeArrowBorderWidth(arrowObject.BorderWidth);
            float originalHeadLength = NormalizeArrowHeadLength(arrowObject.HeadLength);
            float originalHeadWidth = NormalizeArrowHeadWidth(arrowObject.HeadWidth);
            bool originalIsLocked = arrowObject.IsLocked;
            DateTime originalUpdatedAtUtc = arrowObject.UpdatedAtUtc;

            using (var dlg = new EditArrowDialog())
            {
                dlg.ArrowColor = GetArrowColor(arrowObject);
                dlg.ThicknessValue = NormalizeArrowThickness(arrowObject.Thickness);
                dlg.BorderColor = GetArrowBorderColor(arrowObject);
                dlg.BorderWidthValue = NormalizeArrowBorderWidth(arrowObject.BorderWidth);
                dlg.HeadLengthValue = NormalizeArrowHeadLength(arrowObject.HeadLength);
                dlg.HeadWidthValue = NormalizeArrowHeadWidth(arrowObject.HeadWidth);
                dlg.IsLocked = arrowObject.IsLocked;
                dlg.RestoreDefaultsAction = dialog => ApplyArrowDialogDefaults(dialog, ArrowDialogDefaults.CreateDefault());
                dlg.ApplyChanges = () =>
                {
                    ApplyArrowObjectDialogChanges(arrowObject, dlg, updateThumbnail: false);
                };

                if (dlg.ShowDialog(this) != DialogResult.OK)
                {
                    arrowObject.LineColorArgb = originalLineColorArgb;
                    arrowObject.Thickness = originalThickness;
                    arrowObject.BorderColorArgb = originalBorderColorArgb;
                    arrowObject.BorderWidth = originalBorderWidth;
                    arrowObject.HeadLength = originalHeadLength;
                    arrowObject.HeadWidth = originalHeadWidth;
                    arrowObject.IsLocked = originalIsLocked;
                    arrowObject.UpdatedAtUtc = originalUpdatedAtUtc;
                    pdfViewer.Invalidate();
                    return;
                }

                ApplyArrowObjectDialogChanges(arrowObject, dlg);
                InvalidateThumbnailPage(arrowObject.PageNumber);
                CaptureArrowDialogDefaults(dlg);
            }
        }

        private void ApplyArrowDialogDefaults(EditArrowDialog dialog, ArrowDialogDefaults defaults)
        {
            if (dialog == null || defaults == null)
            {
                return;
            }

            dialog.ArrowColor = defaults.ArrowColor;
            dialog.ThicknessValue = defaults.ThicknessValue;
            dialog.BorderColor = defaults.BorderColor;
            dialog.BorderWidthValue = defaults.BorderWidthValue;
            dialog.HeadLengthValue = defaults.HeadLengthValue;
            dialog.HeadWidthValue = defaults.HeadWidthValue;
            dialog.IsLocked = defaults.IsLocked;
        }

        private void CaptureArrowDialogDefaults(EditArrowDialog dialog)
        {
            if (dialog == null)
            {
                return;
            }

            activeArrowDialogDefaults = new ArrowDialogDefaults
            {
                ArrowColor = dialog.ArrowColor,
                ThicknessValue = NormalizeArrowThickness(dialog.ThicknessValue),
                BorderColor = dialog.BorderColor,
                BorderWidthValue = NormalizeArrowBorderWidth(dialog.BorderWidthValue),
                HeadLengthValue = NormalizeArrowHeadLength(dialog.HeadLengthValue),
                HeadWidthValue = NormalizeArrowHeadWidth(dialog.HeadWidthValue),
                IsLocked = dialog.IsLocked
            };
        }

        private bool ApplyArrowObjectDialogChanges(ArrowObject arrowObject, EditArrowDialog dlg, bool updateThumbnail = true)
        {
            if (arrowObject == null || dlg == null)
            {
                return false;
            }

            int newColorArgb = dlg.ArrowColor.ToArgb();
            float newThickness = NormalizeArrowThickness(dlg.ThicknessValue);
            int newBorderColorArgb = dlg.BorderColor.ToArgb();
            float newBorderWidth = NormalizeArrowBorderWidth(dlg.BorderWidthValue);
            float newHeadLength = NormalizeArrowHeadLength(dlg.HeadLengthValue);
            float newHeadWidth = NormalizeArrowHeadWidth(dlg.HeadWidthValue);
            bool newIsLocked = dlg.IsLocked;

            bool changed =
                arrowObject.LineColorArgb != newColorArgb ||
                !AreSameFloat(NormalizeArrowThickness(arrowObject.Thickness), newThickness) ||
                arrowObject.BorderColorArgb != newBorderColorArgb ||
                !AreSameFloat(NormalizeArrowBorderWidth(arrowObject.BorderWidth), newBorderWidth) ||
                !AreSameFloat(NormalizeArrowHeadLength(arrowObject.HeadLength), newHeadLength) ||
                !AreSameFloat(NormalizeArrowHeadWidth(arrowObject.HeadWidth), newHeadWidth) ||
                arrowObject.IsLocked != newIsLocked;

            if (!changed)
            {
                return false;
            }

            arrowObject.LineColorArgb = newColorArgb;
            arrowObject.Thickness = newThickness;
            arrowObject.BorderColorArgb = newBorderColorArgb;
            arrowObject.BorderWidth = newBorderWidth;
            arrowObject.HeadLength = newHeadLength;
            arrowObject.HeadWidth = newHeadWidth;
            arrowObject.IsLocked = newIsLocked;
            arrowObject.UpdatedAtUtc = DateTime.UtcNow;
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            pdfViewer.Invalidate();
            if (updateThumbnail)
            {
                InvalidateThumbnailPage(arrowObject.PageNumber);
            }
            return true;
        }

        private void EditVectorShapeObject(VectorShapeObject vectorShape)
        {
            if (vectorShape == null || vectorShape.PageNumber != currentPage)
            {
                return;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return;
            }

            string originalShapeType = vectorShape.ShapeType;
            int originalStrokeColorArgb = vectorShape.StrokeColorArgb;
            float originalStrokeWidth = NormalizeVectorStrokeWidth(vectorShape.StrokeWidth);
            int originalFillColorArgb = vectorShape.FillColorArgb;
            int originalFillPatternColorArgb = vectorShape.FillPatternColorArgb;
            float originalFillOpacity = NormalizeVectorFillOpacity(vectorShape.FillOpacity);
            string originalStrokeStyle = vectorShape.StrokeStyle;
            string originalFillPattern = vectorShape.FillPattern;
            bool originalIsRasterClip = vectorShape.IsRasterClip;
            string originalStartLineEnding = vectorShape.StartLineEnding;
            string originalEndLineEnding = vectorShape.EndLineEnding;
            float originalStartLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(vectorShape.StartLineEndingPrimarySize);
            float originalStartLineEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(vectorShape.StartLineEndingSecondarySize);
            float originalEndLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(vectorShape.EndLineEndingPrimarySize);
            float originalEndLineEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(vectorShape.EndLineEndingSecondarySize);
            DateTime originalUpdatedAtUtc = vectorShape.UpdatedAtUtc;

            var initialDefaults = new VectorShapeDefaults
            {
                ShapeType = ParseVectorShapeType(vectorShape.ShapeType),
                LimitsRasterView = vectorShape.IsRasterClip,
                StrokeColorArgb = vectorShape.StrokeColorArgb,
                StrokeWidth = NormalizeVectorStrokeWidth(vectorShape.StrokeWidth),
                FillColorArgb = vectorShape.FillColorArgb,
                FillPatternColorArgb = vectorShape.FillPatternColorArgb,
                FillOpacity = NormalizeVectorFillOpacity(vectorShape.FillOpacity),
                StrokeKind = ParseVectorStrokeKind(vectorShape.StrokeStyle),
                FillPattern = ParseVectorFillPattern(vectorShape.FillPattern),
                StartEnding = ParseVectorLineEndingKind(vectorShape.StartLineEnding),
                EndEnding = ParseVectorLineEndingKind(vectorShape.EndLineEnding),
                StartEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(vectorShape.StartLineEndingPrimarySize),
                StartEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(vectorShape.StartLineEndingSecondarySize),
                EndEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(vectorShape.EndLineEndingPrimarySize),
                EndEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(vectorShape.EndLineEndingSecondarySize)
            };

            if (!TryPromptShapeDefaults(
                out VectorShapeDefaults selectedDefaults,
                initialDefaults,
                lockShapeType: true,
                previewChanges: previewDefaults => ApplyVectorShapeDefaults(vectorShape, previewDefaults, markProjectChanged: false, invalidateThumbnail: false)))
            {
                vectorShape.ShapeType = originalShapeType;
                vectorShape.StrokeColorArgb = originalStrokeColorArgb;
                vectorShape.StrokeWidth = originalStrokeWidth;
                vectorShape.FillColorArgb = originalFillColorArgb;
                vectorShape.FillPatternColorArgb = originalFillPatternColorArgb;
                vectorShape.FillOpacity = originalFillOpacity;
                vectorShape.StrokeStyle = originalStrokeStyle;
                vectorShape.FillPattern = originalFillPattern;
                vectorShape.IsRasterClip = originalIsRasterClip;
                vectorShape.StartLineEnding = originalStartLineEnding;
                vectorShape.EndLineEnding = originalEndLineEnding;
                vectorShape.StartLineEndingPrimarySize = originalStartLineEndingPrimarySize;
                vectorShape.StartLineEndingSecondarySize = originalStartLineEndingSecondarySize;
                vectorShape.EndLineEndingPrimarySize = originalEndLineEndingPrimarySize;
                vectorShape.EndLineEndingSecondarySize = originalEndLineEndingSecondarySize;
                vectorShape.UpdatedAtUtc = originalUpdatedAtUtc;
                NormalizeVectorShape(vectorShape);
                ConstrainVectorShapeToPage(vectorShape);
                pdfViewer.Invalidate();
                return;
            }

            if (selectedDefaults == null)
            {
                return;
            }

            bool changed =
                !string.Equals(originalShapeType ?? string.Empty, selectedDefaults.ShapeType.ToString(), StringComparison.OrdinalIgnoreCase) ||
                originalStrokeColorArgb != selectedDefaults.StrokeColorArgb ||
                !AreSameFloat(originalStrokeWidth, NormalizeVectorStrokeWidth(selectedDefaults.StrokeWidth)) ||
                originalFillColorArgb != selectedDefaults.FillColorArgb ||
                originalFillPatternColorArgb != selectedDefaults.FillPatternColorArgb ||
                !AreSameFloat(originalFillOpacity, NormalizeVectorFillOpacity(selectedDefaults.FillOpacity)) ||
                !string.Equals(originalStrokeStyle ?? string.Empty, selectedDefaults.StrokeKind.ToString(), StringComparison.OrdinalIgnoreCase) ||
                !string.Equals(originalFillPattern ?? string.Empty, selectedDefaults.FillPattern.ToString(), StringComparison.OrdinalIgnoreCase) ||
                originalIsRasterClip != selectedDefaults.LimitsRasterView ||
                !string.Equals(originalStartLineEnding ?? string.Empty, selectedDefaults.StartEnding.ToString(), StringComparison.OrdinalIgnoreCase) ||
                !string.Equals(originalEndLineEnding ?? string.Empty, selectedDefaults.EndEnding.ToString(), StringComparison.OrdinalIgnoreCase) ||
                !AreSameFloat(originalStartLineEndingPrimarySize, NormalizeVectorLineEndingPrimarySize(selectedDefaults.StartEndingPrimarySize)) ||
                !AreSameFloat(originalStartLineEndingSecondarySize, NormalizeVectorLineEndingSecondarySize(selectedDefaults.StartEndingSecondarySize)) ||
                !AreSameFloat(originalEndLineEndingPrimarySize, NormalizeVectorLineEndingPrimarySize(selectedDefaults.EndEndingPrimarySize)) ||
                !AreSameFloat(originalEndLineEndingSecondarySize, NormalizeVectorLineEndingSecondarySize(selectedDefaults.EndEndingSecondarySize));

            if (!changed)
            {
                return;
            }
            activeVectorShapeDefaults = selectedDefaults.Clone();
            ApplyVectorShapeDefaults(vectorShape, selectedDefaults, markProjectChanged: true);
            InvalidateThumbnailPage(vectorShape.PageNumber);
        }

        private void ApplyVectorShapeDefaults(VectorShapeObject vectorShape, VectorShapeDefaults defaults, bool markProjectChanged, bool invalidateThumbnail = true)
        {
            if (vectorShape == null || defaults == null)
            {
                return;
            }

            vectorShape.ShapeType = defaults.ShapeType.ToString();
            vectorShape.StrokeColorArgb = defaults.StrokeColorArgb;
            vectorShape.StrokeWidth = NormalizeVectorStrokeWidth(defaults.StrokeWidth);
            vectorShape.FillColorArgb = defaults.FillColorArgb;
            vectorShape.FillPatternColorArgb = defaults.FillPatternColorArgb;
            vectorShape.FillOpacity = NormalizeVectorFillOpacity(defaults.FillOpacity);
            vectorShape.StrokeStyle = defaults.StrokeKind.ToString();
            vectorShape.FillPattern = defaults.FillPattern.ToString();
            vectorShape.IsRasterClip = defaults.LimitsRasterView;
            vectorShape.StartLineEnding = defaults.StartEnding.ToString();
            vectorShape.EndLineEnding = defaults.EndEnding.ToString();
            vectorShape.StartLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(defaults.StartEndingPrimarySize);
            vectorShape.StartLineEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(defaults.StartEndingSecondarySize);
            vectorShape.EndLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(defaults.EndEndingPrimarySize);
            vectorShape.EndLineEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(defaults.EndEndingSecondarySize);
            NormalizeVectorShape(vectorShape);
            ConstrainVectorShapeToPage(vectorShape);
            vectorShape.UpdatedAtUtc = DateTime.UtcNow;

            if (markProjectChanged)
            {
                projectWasChangedAfterLastSave = true;
                saveProjectButton.Enabled = true;
                saveProjectMenuItem.Enabled = true;
            }

            pdfViewer.Invalidate();
            if (invalidateThumbnail)
            {
                InvalidateThumbnailPage(vectorShape.PageNumber);
            }
        }

        private RectangleF GetInitialRasterBounds(int sourceWidth, int sourceHeight)
        {
            var pageSize = GetPageSizeWithOffset(currentPage);
            if (pageSize.Width <= 0f || pageSize.Height <= 0f)
            {
                return new RectangleF(0f, 0f, sourceWidth, sourceHeight);
            }

            float maxWidth = pageSize.Width * 0.5f;
            float maxHeight = pageSize.Height * 0.5f;
            float scale = Math.Min(maxWidth / sourceWidth, maxHeight / sourceHeight);
            if (float.IsNaN(scale) || float.IsInfinity(scale) || scale <= 0f)
            {
                scale = 1f;
            }

            scale = Math.Min(scale, 1f);
            float width = sourceWidth * scale;
            float height = sourceHeight * scale;
            float x = (pageSize.Width - width) / 2f;
            float y = (pageSize.Height - height) / 2f;
            return new RectangleF(x, y, width, height);
        }

        private RectangleF GetInitialRasterBoundsOneToOne(int sourceWidth, int sourceHeight)
        {
            var pageSize = GetPageSizeWithOffset(currentPage);
            if (pageSize.Width <= 0f || pageSize.Height <= 0f)
            {
                return new RectangleF(0f, 0f, sourceWidth, sourceHeight);
            }

            float viewScale = Math.Max(0.01f, scaleFactor);
            float width = sourceWidth / viewScale;
            float height = sourceHeight / viewScale;
            float x = (pageSize.Width - width) / 2f;
            float y = (pageSize.Height - height) / 2f;
            return new RectangleF(x, y, width, height);
        }

        private static void GetRotatedHalfExtents(float width, float height, int rotationDegrees, out float halfExtentX, out float halfExtentY)
        {
            float halfWidth = width / 2f;
            float halfHeight = height / 2f;
            double radians = (Math.PI / 180d) * rotationDegrees;
            float absCos = Math.Abs((float)Math.Cos(radians));
            float absSin = Math.Abs((float)Math.Sin(radians));
            halfExtentX = (halfWidth * absCos) + (halfHeight * absSin);
            halfExtentY = (halfWidth * absSin) + (halfHeight * absCos);
        }

        private bool ConstrainRasterObjectToPage(RasterObject rasterObject)
        {
            if (rasterObject == null)
            {
                return false;
            }

            var pageSize = GetPageSizeWithOffset(rasterObject.PageNumber);
            if (pageSize.Width <= 0f || pageSize.Height <= 0f)
            {
                return false;
            }

            RectangleF bounds = rasterObject.Bounds;
            if (bounds.Width <= 0f || bounds.Height <= 0f)
            {
                return false;
            }

            int rotation = NormalizeRotation(rasterObject.Rotation);
            bool changed = false;
            GetRotatedHalfExtents(bounds.Width, bounds.Height, rotation, out float halfExtentX, out float halfExtentY);

            float fitScale = 1f;
            if ((halfExtentX * 2f) > pageSize.Width && halfExtentX > 0f)
            {
                fitScale = Math.Min(fitScale, pageSize.Width / (halfExtentX * 2f));
            }
            if ((halfExtentY * 2f) > pageSize.Height && halfExtentY > 0f)
            {
                fitScale = Math.Min(fitScale, pageSize.Height / (halfExtentY * 2f));
            }

            if (fitScale < 1f)
            {
                bounds = new RectangleF(bounds.X, bounds.Y, bounds.Width * fitScale, bounds.Height * fitScale);
                changed = true;
                GetRotatedHalfExtents(bounds.Width, bounds.Height, rotation, out halfExtentX, out halfExtentY);
            }

            float centerX = bounds.X + (bounds.Width / 2f);
            float centerY = bounds.Y + (bounds.Height / 2f);

            float minCenterX = halfExtentX;
            float maxCenterX = pageSize.Width - halfExtentX;
            float minCenterY = halfExtentY;
            float maxCenterY = pageSize.Height - halfExtentY;

            centerX = minCenterX > maxCenterX
                ? pageSize.Width / 2f
                : Math.Max(minCenterX, Math.Min(maxCenterX, centerX));
            centerY = minCenterY > maxCenterY
                ? pageSize.Height / 2f
                : Math.Max(minCenterY, Math.Min(maxCenterY, centerY));

            float newX = centerX - (bounds.Width / 2f);
            float newY = centerY - (bounds.Height / 2f);

            if (Math.Abs(bounds.X - newX) > 0.001f || Math.Abs(bounds.Y - newY) > 0.001f)
            {
                bounds = new RectangleF(newX, newY, bounds.Width, bounds.Height);
                changed = true;
            }

            if (changed)
            {
                rasterObject.Bounds = bounds;
            }

            return changed;
        }

