        private void FinalizeDuplicatedObjectsOnPages(ISet<int> changedPages, bool refreshCommentOverlay)
        {
            if (changedPages == null || changedPages.Count == 0)
            {
                return;
            }

            foreach (int page in changedPages)
            {
                if (page < 1 || page > allPageStatuses.Count)
                {
                    continue;
                }

                allPageStatuses[page - 1].HasObjects = HasAnyObjectsOnPage(page);
            }

            if ((string)filterComboBox.SelectedItem == allComboItem)
            {
                foreach (int page in changedPages.OrderBy(p => p))
                {
                    if (page < 1 || page > pagesListView.Items.Count)
                    {
                        continue;
                    }

                    PageItemStatus status = allPageStatuses[page - 1];
                    ListViewItem pageItem = pagesListView.Items[page - 1];
                    UpdateItemTag(pageItem, page, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                    pagesListView.Invalidate(pageItem.Bounds);
                }
            }
            else
            {
                ApplyFilter((string)filterComboBox.SelectedItem);
            }

            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            if (refreshCommentOverlay)
            {
                commentNoteRectsDoc.Clear();
                ClearCommentPreviewRects();
            }
            renderTimer.Stop();
            renderTimer.Start();
            pdfViewer.Invalidate();
        }

        private static RedactionBlock CloneRedactionBlockForPage(RedactionBlock source, int pageNumber, string duplicateGroupId = null)
        {
            var clone = new RedactionBlock(source.Bounds, pageNumber)
            {
                LayerId = NormalizeLayerIdValue(source.LayerId),
                FootnoteNumber = source.FootnoteNumber,
                ScopeId = string.IsNullOrWhiteSpace(source.ScopeId) ? null : source.ScopeId.Trim(),
                ClassificationSource = string.IsNullOrWhiteSpace(source.ClassificationSource) ? ClassificationSourceNone : source.ClassificationSource.Trim(),
                MatchedTag = string.IsNullOrWhiteSpace(source.MatchedTag) ? null : source.MatchedTag.Trim(),
                InterestSubject = string.IsNullOrWhiteSpace(source.InterestSubject) ? null : source.InterestSubject.Trim(),
                IsMarkerSelection = source.IsMarkerSelection,
                DuplicateGroupId = string.IsNullOrWhiteSpace(duplicateGroupId) ? null : duplicateGroupId.Trim()
            };

            clone.BasisIds = (source.BasisIds ?? new List<string>())
                .Where(id => !string.IsNullOrWhiteSpace(id))
                .Select(id => id.Trim())
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            return clone;
        }

        private static List<int> BuildDuplicateSelectionTargetPages(
            int sourcePage,
            int totalPages,
            int fromPage,
            int toPage)
        {
            var pages = new List<int>();
            if (totalPages <= 1 || sourcePage < 1 || sourcePage > totalPages)
            {
                return pages;
            }

            int startPage = Math.Max(1, Math.Min(totalPages, Math.Min(fromPage, toPage)));
            int endPage = Math.Max(1, Math.Min(totalPages, Math.Max(fromPage, toPage)));
            for (int page = startPage; page <= endPage; page++)
            {
                if (page != sourcePage)
                {
                    pages.Add(page);
                }
            }

            return pages;
        }

        private bool PromptForDuplicateSelectionOptions(
            int totalPages,
            string dialogTitle,
            out int fromPage,
            out int toPage,
            int? defaultFromPage = null,
            int? defaultToPage = null)
        {
            int normalizedDefaultFrom = defaultFromPage ?? 1;
            int normalizedDefaultTo = defaultToPage ?? totalPages;
            normalizedDefaultFrom = Math.Max(1, Math.Min(totalPages, normalizedDefaultFrom));
            normalizedDefaultTo = Math.Max(1, Math.Min(totalPages, normalizedDefaultTo));
            if (normalizedDefaultFrom > normalizedDefaultTo)
            {
                int swap = normalizedDefaultFrom;
                normalizedDefaultFrom = normalizedDefaultTo;
                normalizedDefaultTo = swap;
            }

            fromPage = normalizedDefaultFrom;
            toPage = normalizedDefaultTo;

            using (Form prompt = new Form())
            {
                prompt.Text = string.IsNullOrWhiteSpace(dialogTitle)
                    ? GetDuplicateSelectionDialogTitle()
                    : dialogTitle;
                prompt.StartPosition = FormStartPosition.CenterParent;
                prompt.FormBorderStyle = FormBorderStyle.FixedDialog;
                prompt.ClientSize = new Size(370, 130);
                prompt.MinimizeBox = false;
                prompt.MaximizeBox = false;
                prompt.ShowInTaskbar = false;

                var rangeLabel = new Label
                {
                    Left = 18,
                    Top = 18,
                    AutoSize = true,
                    Text = GetDuplicateSelectionRangeText(),
                };

                var fromPageLabel = new Label
                {
                    Left = 150,
                    Top = 20,
                    AutoSize = true,
                    Text = GetDuplicateSelectionFromPageText()
                };

                var fromPageInput = new NumericUpDown
                {
                    Left = 180,
                    Top = 16,
                    Width = 70,
                    Minimum = 1,
                    Maximum = totalPages,
                    Value = normalizedDefaultFrom
                };

                var toPageLabel = new Label
                {
                    Left = 258,
                    Top = 20,
                    AutoSize = true,
                    Text = GetDuplicateSelectionToPageText()
                };

                var toPageInput = new NumericUpDown
                {
                    Left = 286,
                    Top = 16,
                    Width = 66,
                    Minimum = 1,
                    Maximum = totalPages,
                    Value = normalizedDefaultTo
                };

                var buttonOk = new Button
                {
                    Left = 176,
                    Top = 84,
                    Width = 84,
                    DialogResult = DialogResult.OK,
                    Text = Resources.Merge_OK
                };

                var buttonCancel = new Button
                {
                    Left = 268,
                    Top = 84,
                    Width = 84,
                    DialogResult = DialogResult.Cancel,
                    Text = Resources.Merge_Cancel
                };

                fromPageInput.ValueChanged += (_, __) =>
                {
                    if (fromPageInput.Value > toPageInput.Value)
                    {
                        toPageInput.Value = fromPageInput.Value;
                    }
                };
                toPageInput.ValueChanged += (_, __) =>
                {
                    if (toPageInput.Value < fromPageInput.Value)
                    {
                        fromPageInput.Value = toPageInput.Value;
                    }
                };

                prompt.Controls.Add(rangeLabel);
                prompt.Controls.Add(fromPageLabel);
                prompt.Controls.Add(fromPageInput);
                prompt.Controls.Add(toPageLabel);
                prompt.Controls.Add(toPageInput);
                prompt.Controls.Add(buttonOk);
                prompt.Controls.Add(buttonCancel);
                prompt.AcceptButton = buttonOk;
                prompt.CancelButton = buttonCancel;

                if (prompt.ShowDialog(this) != DialogResult.OK)
                {
                    return false;
                }

                fromPage = (int)fromPageInput.Value;
                toPage = (int)toPageInput.Value;
                return true;
            }
        }

        private bool TryGetArrowHandleAtPoint(ArrowObject arrowObject, Point location, out ArrowHandleType handleType)
        {
            handleType = ArrowHandleType.None;
            if (arrowObject == null || arrowObject.PageNumber != currentPage)
            {
                return false;
            }

            PointF startScreen = GetArrowScreenPoint(arrowObject.Start);
            PointF endScreen = GetArrowScreenPoint(arrowObject.End);
            RectangleF startHandle = BuildHandleRect(startScreen, RasterResizeHandleSize);
            startHandle.Inflate(2f, 2f);
            if (startHandle.Contains(location))
            {
                handleType = ArrowHandleType.Start;
                return true;
            }

            RectangleF endHandle = BuildHandleRect(endScreen, RasterResizeHandleSize);
            endHandle.Inflate(2f, 2f);
            if (endHandle.Contains(location))
            {
                handleType = ArrowHandleType.End;
                return true;
            }

            return false;
        }

        private static float DistancePointToSegment(PointF point, PointF segmentStart, PointF segmentEnd)
        {
            float vx = segmentEnd.X - segmentStart.X;
            float vy = segmentEnd.Y - segmentStart.Y;
            float wx = point.X - segmentStart.X;
            float wy = point.Y - segmentStart.Y;
            float segmentLengthSq = (vx * vx) + (vy * vy);
            if (segmentLengthSq <= 0.0001f)
            {
                float dx = point.X - segmentStart.X;
                float dy = point.Y - segmentStart.Y;
                return (float)Math.Sqrt((dx * dx) + (dy * dy));
            }

            float t = ((wx * vx) + (wy * vy)) / segmentLengthSq;
            t = Math.Max(0f, Math.Min(1f, t));
            float projX = segmentStart.X + (t * vx);
            float projY = segmentStart.Y + (t * vy);
            float px = point.X - projX;
            float py = point.Y - projY;
            return (float)Math.Sqrt((px * px) + (py * py));
        }

        private bool IsPointNearArrowLine(ArrowObject arrowObject, Point location)
        {
            if (arrowObject == null || arrowObject.PageNumber != currentPage)
            {
                return false;
            }

            PointF startScreen = GetArrowScreenPoint(arrowObject.Start);
            PointF endScreen = GetArrowScreenPoint(arrowObject.End);
            float effectiveThickness = NormalizeArrowThickness(arrowObject.Thickness) + (2f * NormalizeArrowBorderWidth(arrowObject.BorderWidth));
            float tolerance = Math.Max(ArrowLineSelectionTolerance, effectiveThickness * scaleFactor * 0.6f + 3f);
            float distance = DistancePointToSegment(location, startScreen, endScreen);
            return distance <= tolerance;
        }

        private Cursor GetVectorHandleCursor(VectorShapeObject vectorShape, int pointIndex)
        {
            if (vectorShape == null || vectorShape.Points == null || pointIndex < 0 || pointIndex >= vectorShape.Points.Count)
            {
                return Cursors.SizeAll;
            }

            PointF handle = vectorShape.Points[pointIndex];
            PointF center = GetVectorShapeCenterDoc(vectorShape);
            float dx = handle.X - center.X;
            float dy = handle.Y - center.Y;
            if (Math.Abs(dx) <= 0.0001f && Math.Abs(dy) <= 0.0001f)
            {
                return Cursors.SizeAll;
            }

            float angle = (float)(Math.Atan2(dy, dx) * (180d / Math.PI));
            return GetDirectionalResizeCursor(angle);
        }

        private Cursor GetArrowHandleCursor(ArrowObject arrowObject, ArrowHandleType handleType)
        {
            if (arrowObject == null || handleType == ArrowHandleType.None)
            {
                return Cursors.SizeAll;
            }

            PointF a;
            PointF b;
            if (handleType == ArrowHandleType.Start)
            {
                a = arrowObject.End;
                b = arrowObject.Start;
            }
            else
            {
                a = arrowObject.Start;
                b = arrowObject.End;
            }

            float dx = b.X - a.X;
            float dy = b.Y - a.Y;
            if (Math.Abs(dx) <= 0.0001f && Math.Abs(dy) <= 0.0001f)
            {
                return Cursors.SizeAll;
            }

            float angle = (float)(Math.Atan2(dy, dx) * (180d / Math.PI));
            return GetDirectionalResizeCursor(angle);
        }

        private bool TryUpdateVectorHoverCursor(Point location)
        {
            if (selectedVectorShape == null || selectedVectorShape.PageNumber != currentPage)
            {
                return false;
            }

            if (!IsVectorShapeEffectivelyLocked(selectedVectorShape) && TryGetVectorHandleAtPoint(selectedVectorShape, location, out int handleIndex))
            {
                this.Cursor = GetVectorHandleCursor(selectedVectorShape, handleIndex);
                return true;
            }

            if (!IsVectorShapeEffectivelyLocked(selectedVectorShape) &&
                TryGetVectorShapeScreenBounds(selectedVectorShape, out RectangleF vectorBounds) &&
                TryGetObjectScaleHandleAtPoint(vectorBounds, location, out ObjectScaleHandleCorner scaleHandleCorner))
            {
                this.Cursor = GetCursorForObjectScaleHandle(scaleHandleCorner);
                return true;
            }

            if (!IsVectorShapeEffectivelyLocked(selectedVectorShape) &&
                TryGetVectorRotationHandleRect(selectedVectorShape, out RectangleF rotationHandleRect, out _) &&
                rotationHandleRect.Contains(location))
            {
                this.Cursor = Cursors.Hand;
                return true;
            }

            if (IsPointNearVectorShape(selectedVectorShape, location))
            {
                this.Cursor = IsVectorShapeEffectivelyLocked(selectedVectorShape) ? Cursors.Default : Cursors.SizeAll;
                return true;
            }

            return false;
        }

        private bool TryUpdateArrowHoverCursor(Point location)
        {
            if (selectedArrowObject == null || selectedArrowObject.PageNumber != currentPage)
            {
                return false;
            }

            if (!IsArrowObjectEffectivelyLocked(selectedArrowObject) && TryGetArrowHandleAtPoint(selectedArrowObject, location, out ArrowHandleType handleType))
            {
                this.Cursor = GetArrowHandleCursor(selectedArrowObject, handleType);
                return true;
            }

            if (!IsArrowObjectEffectivelyLocked(selectedArrowObject) &&
                TryGetArrowScreenBounds(selectedArrowObject, out RectangleF arrowBounds) &&
                TryGetObjectScaleHandleAtPoint(arrowBounds, location, out ObjectScaleHandleCorner scaleHandleCorner))
            {
                this.Cursor = GetCursorForObjectScaleHandle(scaleHandleCorner);
                return true;
            }

            if (IsPointNearArrowLine(selectedArrowObject, location))
            {
                this.Cursor = IsArrowObjectEffectivelyLocked(selectedArrowObject) ? Cursors.Default : Cursors.SizeAll;
                return true;
            }

            return false;
        }

        private bool TryHandleSelectedVectorShapeMouseDown(Point location)
        {
            if (selectedVectorShape == null || selectedVectorShape.PageNumber != currentPage || IsVectorShapeEffectivelyLocked(selectedVectorShape))
            {
                return false;
            }

            if (TryGetVectorHandleAtPoint(selectedVectorShape, location, out int selectedHandleIndex))
            {
                BeginUndoCapture("Edit shape");
                vectorShapeToMove = null;
                vectorShapeToAdjust = selectedVectorShape;
                vectorShapeToRotate = null;
                isMovingVectorShape = false;
                isAdjustingVectorHandle = true;
                isRotatingVectorShape = false;
                vectorHandlePointIndex = selectedHandleIndex;
                vectorMouseActionInProgress = true;
                vectorInteractionChanged = false;
                vectorMoveInitialPoints = (selectedVectorShape.Points ?? new List<PointF>()).Select(p => p).ToList();
                this.Cursor = GetVectorHandleCursor(selectedVectorShape, selectedHandleIndex);
                return true;
            }

            if (TryGetVectorShapeScreenBounds(selectedVectorShape, out RectangleF selectedVectorBounds) &&
                TryGetObjectScaleHandleAtPoint(selectedVectorBounds, location, out ObjectScaleHandleCorner selectedScaleHandle))
            {
                BeginUndoCapture("Scale shape");
                vectorShapeToMove = null;
                vectorShapeToAdjust = null;
                vectorShapeToRotate = null;
                vectorShapeToScale = selectedVectorShape;
                isMovingVectorShape = false;
                isAdjustingVectorHandle = false;
                isRotatingVectorShape = false;
                isScalingVectorShape = true;
                activeObjectScaleHandleCorner = selectedScaleHandle;
                vectorMouseActionInProgress = true;
                vectorInteractionChanged = false;
                vectorMoveInitialPoints = (selectedVectorShape.Points ?? new List<PointF>()).Select(p => p).ToList();
                vectorScaleStartScreenBounds = selectedVectorBounds;
                vectorScaleStartStrokeWidth = NormalizeVectorStrokeWidth(selectedVectorShape.StrokeWidth);
                vectorScaleStartStartEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(selectedVectorShape.StartLineEndingPrimarySize);
                vectorScaleStartStartEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(selectedVectorShape.StartLineEndingSecondarySize);
                vectorScaleStartEndEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(selectedVectorShape.EndLineEndingPrimarySize);
                vectorScaleStartEndEndingSecondarySize = NormalizeVectorLineEndingSecondarySize(selectedVectorShape.EndLineEndingSecondarySize);
                this.Cursor = GetCursorForObjectScaleHandle(selectedScaleHandle);
                return true;
            }

            if (TryGetVectorRotationHandleRect(selectedVectorShape, out RectangleF handleRect, out _) && handleRect.Contains(location))
            {
                BeginUndoCapture("Rotate shape");
                return BeginVectorShapeRotation(selectedVectorShape, location);
            }

            return false;
        }

