        private bool ConstrainArrowToPage(ArrowObject arrowObject)
        {
            if (arrowObject == null)
            {
                return false;
            }

            var pageSize = GetPageSizeWithOffset(arrowObject.PageNumber);
            if (pageSize.Width <= 0f || pageSize.Height <= 0f)
            {
                return false;
            }

            PointF start = arrowObject.Start;
            PointF end = arrowObject.End;
            PointF clampedStart = new PointF(
                Math.Max(0f, Math.Min(pageSize.Width, start.X)),
                Math.Max(0f, Math.Min(pageSize.Height, start.Y)));
            PointF clampedEnd = new PointF(
                Math.Max(0f, Math.Min(pageSize.Width, end.X)),
                Math.Max(0f, Math.Min(pageSize.Height, end.Y)));

            bool changed =
                Math.Abs(clampedStart.X - start.X) > 0.001f ||
                Math.Abs(clampedStart.Y - start.Y) > 0.001f ||
                Math.Abs(clampedEnd.X - end.X) > 0.001f ||
                Math.Abs(clampedEnd.Y - end.Y) > 0.001f;

            if (changed)
            {
                arrowObject.Start = clampedStart;
                arrowObject.End = clampedEnd;
            }

            return changed;
        }

        private static bool TryBuildArrowHead(
            PointF startPoint,
            PointF endPoint,
            float headLength,
            float headWidth,
            out PointF leftPoint,
            out PointF rightPoint,
            out PointF lineEndPoint)
        {
            leftPoint = PointF.Empty;
            rightPoint = PointF.Empty;
            lineEndPoint = endPoint;

            float dx = endPoint.X - startPoint.X;
            float dy = endPoint.Y - startPoint.Y;
            float length = (float)Math.Sqrt((dx * dx) + (dy * dy));
            if (length <= 0.001f)
            {
                return false;
            }

            float ux = dx / length;
            float uy = dy / length;
            float actualHeadLength = Math.Min(headLength, length * 0.9f);
            float halfWidth = headWidth / 2f;
            PointF basePoint = new PointF(
                endPoint.X - (ux * actualHeadLength),
                endPoint.Y - (uy * actualHeadLength));
            PointF perp = new PointF(-uy * halfWidth, ux * halfWidth);
            leftPoint = new PointF(basePoint.X + perp.X, basePoint.Y + perp.Y);
            rightPoint = new PointF(basePoint.X - perp.X, basePoint.Y - perp.Y);
            lineEndPoint = new PointF(
                endPoint.X - (ux * actualHeadLength * 0.85f),
                endPoint.Y - (uy * actualHeadLength * 0.85f));
            return true;
        }

        private static bool TryBuildExpandedArrowHeadTriangle(PointF tip, PointF left, PointF right, float offset, out PointF[] expandedTriangle)
        {
            expandedTriangle = null;
            if (offset <= 0f)
            {
                expandedTriangle = new[] { tip, left, right };
                return true;
            }

            PointF[] polygon = { tip, left, right };
            float signedArea = 0f;
            for (int i = 0; i < polygon.Length; i++)
            {
                PointF current = polygon[i];
                PointF next = polygon[(i + 1) % polygon.Length];
                signedArea += (current.X * next.Y) - (next.X * current.Y);
            }

            if (Math.Abs(signedArea) <= 0.001f)
            {
                return false;
            }

            bool isCounterClockwise = signedArea > 0f;
            PointF[] linePoints = new PointF[polygon.Length];
            PointF[] lineDirections = new PointF[polygon.Length];

            for (int i = 0; i < polygon.Length; i++)
            {
                PointF a = polygon[i];
                PointF b = polygon[(i + 1) % polygon.Length];
                float dx = b.X - a.X;
                float dy = b.Y - a.Y;
                float edgeLength = (float)Math.Sqrt((dx * dx) + (dy * dy));
                if (edgeLength <= 0.001f)
                {
                    return false;
                }

                float nx = isCounterClockwise ? (dy / edgeLength) : (-dy / edgeLength);
                float ny = isCounterClockwise ? (-dx / edgeLength) : (dx / edgeLength);
                linePoints[i] = new PointF(a.X + (nx * offset), a.Y + (ny * offset));
                lineDirections[i] = new PointF(dx, dy);
            }

            expandedTriangle = new PointF[polygon.Length];
            for (int i = 0; i < polygon.Length; i++)
            {
                int previous = (i - 1 + polygon.Length) % polygon.Length;
                PointF intersection;
                if (!TryIntersectInfiniteLines(
                        linePoints[previous],
                        lineDirections[previous],
                        linePoints[i],
                        lineDirections[i],
                        out intersection))
                {
                    return false;
                }

                expandedTriangle[i] = intersection;
            }

            return true;
        }

        private static bool TryIntersectInfiniteLines(
            PointF p,
            PointF r,
            PointF q,
            PointF s,
            out PointF intersection)
        {
            intersection = PointF.Empty;
            float denominator = (r.X * s.Y) - (r.Y * s.X);
            if (Math.Abs(denominator) <= 0.0001f)
            {
                return false;
            }

            float qpx = q.X - p.X;
            float qpy = q.Y - p.Y;
            float t = ((qpx * s.Y) - (qpy * s.X)) / denominator;
            intersection = new PointF(
                p.X + (t * r.X),
                p.Y + (t * r.Y));
            return true;
        }

        private static float NormalizeAngleDelta(float value)
        {
            while (value > 180f)
            {
                value -= 360f;
            }
            while (value < -180f)
            {
                value += 360f;
            }
            return value;
        }

        private static PointF RotateVector(PointF vector, int angleDegrees)
        {
            double radians = (Math.PI / 180d) * angleDegrees;
            float cos = (float)Math.Cos(radians);
            float sin = (float)Math.Sin(radians);
            return new PointF(
                (vector.X * cos) - (vector.Y * sin),
                (vector.X * sin) + (vector.Y * cos));
        }

        private static string FormatRectFInvariant(RectangleF rect)
        {
            return string.Format(
                CultureInfo.InvariantCulture,
                "{{X={0:0.###},Y={1:0.###},W={2:0.###},H={3:0.###}}}",
                rect.X,
                rect.Y,
                rect.Width,
                rect.Height);
        }

        private static string FormatPointFInvariant(PointF point)
        {
            return string.Format(
                CultureInfo.InvariantCulture,
                "{{X={0:0.###},Y={1:0.###}}}",
                point.X,
                point.Y);
        }

        private RectangleF GetRasterObjectScreenBounds(RasterObject rasterObject)
        {
            return new RectangleF(
                rasterObject.Bounds.X * scaleFactor,
                rasterObject.Bounds.Y * scaleFactor,
                rasterObject.Bounds.Width * scaleFactor,
                rasterObject.Bounds.Height * scaleFactor);
        }

        private RectangleF GetRasterObjectScreenFrameBounds(RasterObject rasterObject)
        {
            RectangleF bounds = GetRasterObjectScreenBounds(rasterObject);
            if (bounds.Width <= 0f || bounds.Height <= 0f)
            {
                return RectangleF.Empty;
            }

            PointF center = new PointF(bounds.X + (bounds.Width / 2f), bounds.Y + (bounds.Height / 2f));
            int rotation = NormalizeRotation(rasterObject.Rotation);
            PointF vx = RotateVector(new PointF(bounds.Width / 2f, 0f), rotation);
            PointF vy = RotateVector(new PointF(0f, bounds.Height / 2f), rotation);

            PointF[] corners = new[]
            {
                new PointF(center.X - vx.X - vy.X, center.Y - vx.Y - vy.Y),
                new PointF(center.X + vx.X - vy.X, center.Y + vx.Y - vy.Y),
                new PointF(center.X + vx.X + vy.X, center.Y + vx.Y + vy.Y),
                new PointF(center.X - vx.X + vy.X, center.Y - vx.Y + vy.Y)
            };

            float minX = corners.Min(p => p.X);
            float maxX = corners.Max(p => p.X);
            float minY = corners.Min(p => p.Y);
            float maxY = corners.Max(p => p.Y);
            return new RectangleF(minX, minY, Math.Max(0f, maxX - minX), Math.Max(0f, maxY - minY));
        }

        private PointF GetRasterObjectScreenCenter(RasterObject rasterObject)
        {
            RectangleF bounds = GetRasterObjectScreenBounds(rasterObject);
            return new PointF(bounds.X + (bounds.Width / 2f), bounds.Y + (bounds.Height / 2f));
        }

        private bool TryGetVectorShapeScreenBounds(VectorShapeObject vectorShape, out RectangleF bounds)
        {
            bounds = RectangleF.Empty;
            if (vectorShape == null || vectorShape.PageNumber != currentPage || vectorShape.Points == null || vectorShape.Points.Count < 2)
            {
                return false;
            }

            PointF[] points = BuildVectorShapeRenderPoints(ParseVectorShapeType(vectorShape.ShapeType), vectorShape.Points)
                .Select(p => new PointF(p.X * scaleFactor, p.Y * scaleFactor))
                .ToArray();
            if (points.Length < 2)
            {
                return false;
            }

            float minX = points.Min(p => p.X);
            float maxX = points.Max(p => p.X);
            float minY = points.Min(p => p.Y);
            float maxY = points.Max(p => p.Y);
            float width = Math.Max(0f, maxX - minX);
            float height = Math.Max(0f, maxY - minY);
            if (width <= 0.0001f && height <= 0.0001f)
            {
                return false;
            }

            bounds = new RectangleF(minX, minY, Math.Max(1f, width), Math.Max(1f, height));
            return true;
        }

        private bool TryGetArrowScreenBounds(ArrowObject arrowObject, out RectangleF bounds)
        {
            bounds = RectangleF.Empty;
            if (arrowObject == null || arrowObject.PageNumber != currentPage)
            {
                return false;
            }

            PointF startScreen = GetArrowScreenPoint(arrowObject.Start);
            PointF endScreen = GetArrowScreenPoint(arrowObject.End);
            var points = new List<PointF> { startScreen, endScreen };

            float headLengthPx = Math.Max(4f, NormalizeArrowHeadLength(arrowObject.HeadLength) * scaleFactor);
            float headWidthPx = Math.Max(4f, NormalizeArrowHeadWidth(arrowObject.HeadWidth) * scaleFactor);
            if (TryBuildArrowHead(startScreen, endScreen, headLengthPx, headWidthPx, out PointF leftPoint, out PointF rightPoint, out PointF lineEndPoint))
            {
                points.Add(leftPoint);
                points.Add(rightPoint);
                points.Add(lineEndPoint);
            }

            float inflate = Math.Max(4f, ((NormalizeArrowThickness(arrowObject.Thickness) + (NormalizeArrowBorderWidth(arrowObject.BorderWidth) * 2f)) * scaleFactor) + 2f);
            float minX = points.Min(p => p.X) - inflate;
            float maxX = points.Max(p => p.X) + inflate;
            float minY = points.Min(p => p.Y) - inflate;
            float maxY = points.Max(p => p.Y) + inflate;
            bounds = new RectangleF(minX, minY, Math.Max(1f, maxX - minX), Math.Max(1f, maxY - minY));
            return true;
        }

        private bool TryGetVectorRotationHandleRect(VectorShapeObject vectorShape, out RectangleF handleRect, out PointF connectorPoint)
        {
            handleRect = RectangleF.Empty;
            connectorPoint = PointF.Empty;
            VectorShapeType shapeType = ParseVectorShapeType(vectorShape?.ShapeType);
            if (!ShapeTypeSupportsRotationHandle(shapeType))
            {
                return false;
            }

            if (!TryGetVectorShapeScreenBounds(vectorShape, out RectangleF bounds))
            {
                return false;
            }

            PointF center = new PointF(bounds.X + (bounds.Width / 2f), bounds.Y + (bounds.Height / 2f));
            connectorPoint = new PointF(center.X, bounds.Top);
            PointF handleCenter = new PointF(center.X, bounds.Top - RasterRotateHandleOffset);
            handleRect = new RectangleF(
                handleCenter.X - (RasterRotateHandleSize / 2f),
                handleCenter.Y - (RasterRotateHandleSize / 2f),
                RasterRotateHandleSize,
                RasterRotateHandleSize);
            return true;
        }

        private static PointF GetVectorShapeCenterDoc(VectorShapeObject vectorShape)
        {
            if (vectorShape == null || vectorShape.Points == null || vectorShape.Points.Count == 0)
            {
                return PointF.Empty;
            }

            float minX = vectorShape.Points.Min(p => p.X);
            float maxX = vectorShape.Points.Max(p => p.X);
            float minY = vectorShape.Points.Min(p => p.Y);
            float maxY = vectorShape.Points.Max(p => p.Y);
            return new PointF((minX + maxX) / 2f, (minY + maxY) / 2f);
        }

        private static bool TryGetCircumcenter(PointF a, PointF b, PointF c, out PointF center)
        {
            center = PointF.Empty;
            float d = 2f * ((a.X * (b.Y - c.Y)) + (b.X * (c.Y - a.Y)) + (c.X * (a.Y - b.Y)));
            if (Math.Abs(d) < 0.0001f)
            {
                return false;
            }

            float a2 = (a.X * a.X) + (a.Y * a.Y);
            float b2 = (b.X * b.X) + (b.Y * b.Y);
            float c2 = (c.X * c.X) + (c.Y * c.Y);
            float ux = ((a2 * (b.Y - c.Y)) + (b2 * (c.Y - a.Y)) + (c2 * (a.Y - b.Y))) / d;
            float uy = ((a2 * (c.X - b.X)) + (b2 * (a.X - c.X)) + (c2 * (b.X - a.X))) / d;
            center = new PointF(ux, uy);
            return true;
        }

        private static PointF GetVectorShapeRotationCenterDoc(VectorShapeObject vectorShape)
        {
            if (vectorShape == null || vectorShape.Points == null || vectorShape.Points.Count == 0)
            {
                return PointF.Empty;
            }

            VectorShapeType shapeType = ParseVectorShapeType(vectorShape.ShapeType);
            if (shapeType == VectorShapeType.Arc && vectorShape.Points.Count >= 3)
            {
                if (TryGetCircumcenter(vectorShape.Points[0], vectorShape.Points[1], vectorShape.Points[2], out PointF arcCenter))
                {
                    return arcCenter;
                }
            }

            return GetVectorShapeCenterDoc(vectorShape);
        }

        private bool IsPointInsideRasterObject(RasterObject rasterObject, Point location)
        {
            RectangleF frameBounds = GetRasterObjectScreenFrameBounds(rasterObject);
            if (frameBounds.Width <= 0f || frameBounds.Height <= 0f)
            {
                return false;
            }

            return frameBounds.Contains(location);
        }

        private bool TryGetRasterRotationHandleRect(RasterObject rasterObject, out RectangleF handleRect, out PointF connectorPoint)
        {
            handleRect = RectangleF.Empty;
            connectorPoint = PointF.Empty;
            if (rasterObject == null || rasterObject.PageNumber != currentPage)
            {
                return false;
            }

            RectangleF bounds = GetRasterObjectScreenBounds(rasterObject);
            if (bounds.Width <= 0f || bounds.Height <= 0f)
            {
                return false;
            }

            PointF center = GetRasterObjectScreenCenter(rasterObject);
            PointF topVector = RotateVector(new PointF(0f, -(bounds.Height / 2f)), NormalizeRotation(rasterObject.Rotation));
            PointF handleVector = RotateVector(new PointF(0f, -(bounds.Height / 2f + RasterRotateHandleOffset)), NormalizeRotation(rasterObject.Rotation));

            connectorPoint = new PointF(center.X + topVector.X, center.Y + topVector.Y);
            PointF handleCenter = new PointF(center.X + handleVector.X, center.Y + handleVector.Y);
            handleRect = new RectangleF(
                handleCenter.X - (RasterRotateHandleSize / 2f),
                handleCenter.Y - (RasterRotateHandleSize / 2f),
                RasterRotateHandleSize,
                RasterRotateHandleSize);

            return true;
        }

        private static RectangleF BuildHandleRect(PointF center, float size)
        {
            return new RectangleF(center.X - (size / 2f), center.Y - (size / 2f), size, size);
        }

        private static bool TryGetObjectScaleHandleRects(RectangleF bounds, out Dictionary<ObjectScaleHandleCorner, RectangleF> handles)
        {
            handles = null;
            if (bounds.Width <= 0.0001f || bounds.Height <= 0.0001f)
            {
                return false;
            }

            handles = new Dictionary<ObjectScaleHandleCorner, RectangleF>
            {
                [ObjectScaleHandleCorner.TopLeft] = BuildHandleRect(new PointF(bounds.Left, bounds.Top), RasterResizeHandleSize),
                [ObjectScaleHandleCorner.TopRight] = BuildHandleRect(new PointF(bounds.Right, bounds.Top), RasterResizeHandleSize),
                [ObjectScaleHandleCorner.BottomRight] = BuildHandleRect(new PointF(bounds.Right, bounds.Bottom), RasterResizeHandleSize),
                [ObjectScaleHandleCorner.BottomLeft] = BuildHandleRect(new PointF(bounds.Left, bounds.Bottom), RasterResizeHandleSize)
            };

            return true;
        }

        private static void DrawObjectScaleHandleRects(Graphics graphics, RectangleF bounds)
        {
            if (graphics == null || !TryGetObjectScaleHandleRects(bounds, out Dictionary<ObjectScaleHandleCorner, RectangleF> handles))
            {
                return;
            }

            using (var handleBrush = new SolidBrush(System.Drawing.Color.White))
            using (var handlePen = new Pen(System.Drawing.Color.DodgerBlue, 1.5f))
            {
                foreach (RectangleF rect in handles.Values)
                {
                    graphics.FillRectangle(handleBrush, rect);
                    graphics.DrawRectangle(handlePen, rect.X, rect.Y, rect.Width, rect.Height);
                }
            }
        }

        private static Cursor GetCursorForObjectScaleHandle(ObjectScaleHandleCorner handleCorner)
        {
            switch (handleCorner)
            {
                case ObjectScaleHandleCorner.TopLeft:
                case ObjectScaleHandleCorner.BottomRight:
                    return Cursors.SizeNWSE;
                case ObjectScaleHandleCorner.TopRight:
                case ObjectScaleHandleCorner.BottomLeft:
                    return Cursors.SizeNESW;
                default:
                    return Cursors.Default;
            }
        }

        private static bool TryGetObjectScaleHandleAtPoint(RectangleF bounds, Point location, out ObjectScaleHandleCorner handleCorner)
        {
            handleCorner = ObjectScaleHandleCorner.TopLeft;
            if (!TryGetObjectScaleHandleRects(bounds, out Dictionary<ObjectScaleHandleCorner, RectangleF> handles))
            {
                return false;
            }

            foreach (var entry in handles)
            {
                if (entry.Value.Contains(location))
                {
                    handleCorner = entry.Key;
                    return true;
                }
            }

            return false;
        }

        private static PointF GetObjectScaleAnchorPoint(RectangleF bounds, ObjectScaleHandleCorner handleCorner)
        {
            switch (handleCorner)
            {
                case ObjectScaleHandleCorner.TopLeft:
                    return new PointF(bounds.Right, bounds.Bottom);
                case ObjectScaleHandleCorner.TopRight:
                    return new PointF(bounds.Left, bounds.Bottom);
                case ObjectScaleHandleCorner.BottomRight:
                    return new PointF(bounds.Left, bounds.Top);
                case ObjectScaleHandleCorner.BottomLeft:
                    return new PointF(bounds.Right, bounds.Top);
                default:
                    return new PointF(bounds.Left, bounds.Top);
            }
        }

        private static RectangleF BuildScaledBoundsFromAnchor(RectangleF initialBounds, ObjectScaleHandleCorner handleCorner, Point currentLocation, bool preserveAspectRatio, bool scaleFromCenter)
        {
            if (scaleFromCenter)
            {
                PointF center = new PointF(
                    initialBounds.Left + (initialBounds.Width / 2f),
                    initialBounds.Top + (initialBounds.Height / 2f));
                float halfWidth = Math.Max(4f, Math.Abs(currentLocation.X - center.X));
                float halfHeight = Math.Max(4f, Math.Abs(currentLocation.Y - center.Y));

                if (preserveAspectRatio && initialBounds.Width > 0.001f && initialBounds.Height > 0.001f)
                {
                    float scale = Math.Max((halfWidth * 2f) / initialBounds.Width, (halfHeight * 2f) / initialBounds.Height);
                    scale = Math.Max(8f / Math.Max(initialBounds.Width, initialBounds.Height), scale);
                    halfWidth = Math.Max(4f, (initialBounds.Width * scale) / 2f);
                    halfHeight = Math.Max(4f, (initialBounds.Height * scale) / 2f);
                }

                return RectangleF.FromLTRB(
                    center.X - halfWidth,
                    center.Y - halfHeight,
                    center.X + halfWidth,
                    center.Y + halfHeight);
            }

            PointF anchor = GetObjectScaleAnchorPoint(initialBounds, handleCorner);
            float dx = currentLocation.X - anchor.X;
            float dy = currentLocation.Y - anchor.Y;
            float width = Math.Max(8f, Math.Abs(dx));
            float height = Math.Max(8f, Math.Abs(dy));

            if (preserveAspectRatio && initialBounds.Width > 0.001f && initialBounds.Height > 0.001f)
            {
                float scale = Math.Max(width / initialBounds.Width, height / initialBounds.Height);
                scale = Math.Max(8f / Math.Max(initialBounds.Width, initialBounds.Height), scale);
                width = Math.Max(8f, initialBounds.Width * scale);
                height = Math.Max(8f, initialBounds.Height * scale);
            }

            float left = dx >= 0f ? anchor.X : anchor.X - width;
            float top = dy >= 0f ? anchor.Y : anchor.Y - height;
            return new RectangleF(left, top, width, height);
        }

        private static float GetUniformScaleFactor(float scaleX, float scaleY)
        {
            return Math.Max(0.05f, (Math.Abs(scaleX) + Math.Abs(scaleY)) * 0.5f);
        }

        private static bool HasPositiveSize(RectangleF rect)
        {
            return rect.Width > 0f && rect.Height > 0f;
        }

        private static RectangleF InflateRect(RectangleF rect, float padding)
        {
            return new RectangleF(
                rect.X - padding,
                rect.Y - padding,
                rect.Width + (padding * 2f),
                rect.Height + (padding * 2f));
        }

        private static void DrawGroupSelectionOutline(Graphics graphics, RectangleF rect)
        {
            if (graphics == null || rect.Width <= 0f || rect.Height <= 0f)
            {
                return;
            }

            RectangleF outlineRect = InflateRect(rect, 4f);
            using (var pen = new Pen(GroupSelectionColor, 2f))
            {
                pen.DashStyle = System.Drawing.Drawing2D.DashStyle.Dash;
                graphics.DrawRectangle(pen, outlineRect.X, outlineRect.Y, outlineRect.Width, outlineRect.Height);
            }
        }

        private static float NormalizeOpacity(float opacity)
        {
            if (float.IsNaN(opacity) || float.IsInfinity(opacity))
            {
                return 1f;
            }

            if (opacity < 0f)
            {
                return 0f;
            }

            if (opacity > 1f)
            {
                return 1f;
            }

            return opacity;
        }

        private static RectangleF GetResolvedRasterInitialBounds(RasterObject rasterObject)
        {
            if (rasterObject == null)
            {
                return RectangleF.Empty;
            }

            if (!HasPositiveSize(rasterObject.InitialBounds))
            {
                rasterObject.InitialBounds = rasterObject.Bounds;
            }

            return rasterObject.InitialBounds;
        }

        private void ClearRasterIconClickState()
        {
            isClickOnRasterIcon = false;
            clickedRasterIconType = RasterIconType.None;
            rasterObjectForIcon = null;
        }

        private void ClearArrowIconClickState()
        {
            isClickOnArrowIcon = false;
            clickedArrowIconType = ArrowIconType.None;
            arrowObjectForIcon = null;
        }

        private void ClearVectorIconClickState()
        {
            isClickOnVectorIcon = false;
            clickedVectorIconType = VectorIconType.None;
            vectorShapeForIcon = null;
        }

        private int ResolveObjectToolbarTop(float minY, float maxY, int extraOffset = 0)
        {
            int preferredTop = (int)Math.Round(minY) - annotationsIconSize - annotationsIconPadding - extraOffset;

            int visibleTop = ObjectToolbarViewportPadding;
            int visibleBottom = Math.Max(ObjectToolbarViewportPadding, pdfViewer.ClientSize.Height - annotationsIconSize - ObjectToolbarViewportPadding);
            ZoomPanel panel = GetZoomPanel();
            if (panel != null)
            {
                visibleTop = panel.VerticalScroll.Value + ObjectToolbarViewportPadding;
                visibleBottom = panel.VerticalScroll.Value + Math.Max(ObjectToolbarViewportPadding, panel.ClientSize.Height - annotationsIconSize - ObjectToolbarViewportPadding);
            }

            if (preferredTop >= visibleTop && preferredTop <= visibleBottom)
            {
                return preferredTop;
            }

            if (preferredTop < visibleTop)
            {
                return visibleTop;
            }

            if (preferredTop > visibleBottom)
            {
                return visibleBottom;
            }

            return Math.Max(visibleTop, Math.Min(visibleBottom, preferredTop));
        }

        private int ResolveObjectToolbarRight(float maxX, int totalWidth)
        {
            int preferredRight = (int)Math.Round(maxX);
            int visibleLeft = ObjectToolbarViewportPadding;
            int visibleRight = Math.Max(ObjectToolbarViewportPadding, pdfViewer.ClientSize.Width - ObjectToolbarViewportPadding);
            ZoomPanel panel = GetZoomPanel();
            if (panel != null)
            {
                visibleLeft = panel.HorizontalScroll.Value + ObjectToolbarViewportPadding;
                visibleRight = panel.HorizontalScroll.Value + Math.Max(ObjectToolbarViewportPadding, panel.ClientSize.Width - ObjectToolbarViewportPadding);
            }

            int right = preferredRight;
            if (right > visibleRight)
            {
                right = visibleRight;
            }

            if (right - totalWidth < visibleLeft)
            {
                right = visibleLeft + totalWidth;
            }

            if (right > visibleRight)
            {
                right = visibleRight;
            }

            return right;
        }

        private bool TryGetRasterIconRects(RasterObject rasterObject, out Dictionary<RasterIconType, Rectangle> iconRects)
        {
            iconRects = null;
            if (rasterObject == null || rasterObject.PageNumber != currentPage)
            {
                return false;
            }

            RectangleF bounds = GetRasterObjectScreenBounds(rasterObject);
            if (bounds.Width <= 0f || bounds.Height <= 0f)
            {
                return false;
            }

            PointF center = GetRasterObjectScreenCenter(rasterObject);
            int rotation = NormalizeRotation(rasterObject.Rotation);
            PointF vx = RotateVector(new PointF(bounds.Width / 2f, 0f), rotation);
            PointF vy = RotateVector(new PointF(0f, bounds.Height / 2f), rotation);

            PointF[] corners = new[]
            {
                new PointF(center.X - vx.X - vy.X, center.Y - vx.Y - vy.Y),
                new PointF(center.X + vx.X - vy.X, center.Y + vx.Y - vy.Y),
                new PointF(center.X + vx.X + vy.X, center.Y + vx.Y + vy.Y),
                new PointF(center.X - vx.X + vy.X, center.Y - vx.Y + vy.Y)
            };

            float minY = corners.Min(p => p.Y);
            float maxX = corners.Max(p => p.X);

            const int buttonCount = 6;
            int totalWidth = (buttonCount * annotationsIconSize) + ((buttonCount - 1) * annotationsIconPadding);
            float maxY = corners.Max(p => p.Y);
            int top = ResolveObjectToolbarTop(minY, maxY);
            int right = ResolveObjectToolbarRight(maxX, totalWidth);

            Rectangle BuildRectFromRight(int indexFromRight)
            {
                int x = right - ((indexFromRight + 1) * annotationsIconSize) - (indexFromRight * annotationsIconPadding);
                return new Rectangle(x, top, annotationsIconSize, annotationsIconSize);
            }

            iconRects = new Dictionary<RasterIconType, Rectangle>
            {
                [RasterIconType.Edit] = BuildRectFromRight(5),
                [RasterIconType.Lock] = BuildRectFromRight(4),
                [RasterIconType.Duplicate] = BuildRectFromRight(3),
                [RasterIconType.Order] = BuildRectFromRight(2),
                [RasterIconType.ResetSize] = BuildRectFromRight(1),
                [RasterIconType.Delete] = BuildRectFromRight(0)
            };

            return true;
        }

        private bool TryGetArrowIconRects(ArrowObject arrowObject, out Dictionary<ArrowIconType, Rectangle> iconRects)
        {
            iconRects = null;
            if (arrowObject == null || arrowObject.PageNumber != currentPage)
            {
                return false;
            }

            PointF startScreen = GetArrowScreenPoint(arrowObject.Start);
            PointF endScreen = GetArrowScreenPoint(arrowObject.End);
            float minX = Math.Min(startScreen.X, endScreen.X);
            float maxX = Math.Max(startScreen.X, endScreen.X);
            float minY = Math.Min(startScreen.Y, endScreen.Y);
            float maxY = Math.Max(startScreen.Y, endScreen.Y);
            if ((maxX - minX) < 1f && (maxY - minY) < 1f)
            {
                return false;
            }

            const int buttonCount = 5;
            int totalWidth = (buttonCount * annotationsIconSize) + ((buttonCount - 1) * annotationsIconPadding);
            int top = ResolveObjectToolbarTop(minY, maxY, extraOffset: 8);
            int right = ResolveObjectToolbarRight(maxX, totalWidth);

            Rectangle BuildRectFromRight(int indexFromRight)
            {
                int x = right - ((indexFromRight + 1) * annotationsIconSize) - (indexFromRight * annotationsIconPadding);
                return new Rectangle(x, top, annotationsIconSize, annotationsIconSize);
            }

            iconRects = new Dictionary<ArrowIconType, Rectangle>
            {
                [ArrowIconType.Edit] = BuildRectFromRight(4),
                [ArrowIconType.Lock] = BuildRectFromRight(3),
                [ArrowIconType.Duplicate] = BuildRectFromRight(2),
                [ArrowIconType.Order] = BuildRectFromRight(1),
                [ArrowIconType.Delete] = BuildRectFromRight(0)
            };

            return true;
        }

        private bool TryGetVectorIconRects(VectorShapeObject vectorShape, out Dictionary<VectorIconType, Rectangle> iconRects)
        {
            iconRects = null;
            if (vectorShape == null || vectorShape.PageNumber != currentPage || vectorShape.Points == null || vectorShape.Points.Count < 2)
            {
                return false;
            }

            PointF[] points = BuildVectorShapeRenderPoints(ParseVectorShapeType(vectorShape.ShapeType), vectorShape.Points)
                .Select(p => new PointF(p.X * scaleFactor, p.Y * scaleFactor))
                .ToArray();
            if (points.Length < 2)
            {
                return false;
            }

            float minX = points.Min(p => p.X);
            float maxX = points.Max(p => p.X);
            float minY = points.Min(p => p.Y);
            float maxY = points.Max(p => p.Y);
            if ((maxX - minX) < 1f && (maxY - minY) < 1f)
            {
                return false;
            }

            const int buttonCount = 5;
            int totalWidth = (buttonCount * annotationsIconSize) + ((buttonCount - 1) * annotationsIconPadding);
            int top = ResolveObjectToolbarTop(minY, maxY);
            int right = ResolveObjectToolbarRight(maxX, totalWidth);

            Rectangle BuildRectFromRight(int indexFromRight)
            {
                int x = right - ((indexFromRight + 1) * annotationsIconSize) - (indexFromRight * annotationsIconPadding);
                return new Rectangle(x, top, annotationsIconSize, annotationsIconSize);
            }

            iconRects = new Dictionary<VectorIconType, Rectangle>
            {
                [VectorIconType.Edit] = BuildRectFromRight(4),
                [VectorIconType.Lock] = BuildRectFromRight(3),
                [VectorIconType.Duplicate] = BuildRectFromRight(2),
                [VectorIconType.Order] = BuildRectFromRight(1),
                [VectorIconType.Delete] = BuildRectFromRight(0)
            };

            return true;
        }

        private static void DrawIconButton(Graphics graphics, Rectangle buttonRect, string iconCode)
        {
            System.Drawing.Color buttonBackground = SystemColors.Control;
            System.Drawing.Color buttonBorder = System.Drawing.Color.DarkGray;

            using (SolidBrush bgBrush = new SolidBrush(buttonBackground))
            {
                graphics.FillRectangle(bgBrush, buttonRect);
            }

            using (Pen borderPen = new Pen(buttonBorder, 1))
            {
                graphics.DrawRectangle(borderPen, buttonRect);
            }

            bool useMdl2 =
                !string.IsNullOrEmpty(iconCode) &&
                iconCode.Length == 1 &&
                iconCode[0] >= '\uE000' &&
                iconCode[0] <= '\uF8FF';
            string fontName = useMdl2 ? "Segoe MDL2 Assets" : "Segoe UI";
            float fontSize = useMdl2 ? 12.0F : 8.5F;
            FontStyle fontStyle = useMdl2 ? FontStyle.Regular : FontStyle.Bold;
            using (Font iconFont = new Font(fontName, fontSize, fontStyle, System.Drawing.GraphicsUnit.Point))
            {
                StringFormat iconFormat = new StringFormat
                {
                    Alignment = StringAlignment.Center,
                    LineAlignment = StringAlignment.Center
                };
                using (SolidBrush iconBrush = new SolidBrush(SystemColors.ControlText))
                {
                    Rectangle shiftedRect = new Rectangle(
                        buttonRect.X + 1,
                        buttonRect.Y + (useMdl2 ? 2 : 1),
                        buttonRect.Width,
                        buttonRect.Height
                    );
                    graphics.DrawString(iconCode, iconFont, iconBrush, shiftedRect, iconFormat);
                }
            }
        }

        private void DrawSelectedRasterOverlayOnTop(Graphics graphics)
        {
            if (graphics == null || selectedRasterObject == null || selectedRasterObject.PageNumber != currentPage || GetGroupSelectionCount() != 0 || !IsLayerVisible(selectedRasterObject.LayerId))
            {
                return;
            }

            if (TryGetRasterRotationHandleRect(selectedRasterObject, out RectangleF handleRect, out PointF connectorPoint))
            {
                PointF handleCenter = new PointF(
                    handleRect.X + (handleRect.Width / 2f),
                    handleRect.Y + (handleRect.Height / 2f));
                using (var connectorPen = new Pen(System.Drawing.Color.OrangeRed, 1.5f))
                {
                    graphics.DrawLine(connectorPen, connectorPoint, handleCenter);
                }
                using (var handleBrush = new SolidBrush(System.Drawing.Color.White))
                using (var handlePen = new Pen(System.Drawing.Color.OrangeRed, 2f))
                {
                    graphics.FillEllipse(handleBrush, handleRect);
                    graphics.DrawEllipse(handlePen, handleRect);
                }
            }

            if (TryGetRasterResizeHandleRects(selectedRasterObject, out Dictionary<RasterResizeHandleType, RectangleF> resizeHandles))
            {
                using (var handleBrush = new SolidBrush(System.Drawing.Color.White))
                using (var handlePen = new Pen(System.Drawing.Color.OrangeRed, 1.5f))
                {
                    foreach (var kvp in resizeHandles)
                    {
                        if (kvp.Key == RasterResizeHandleType.None)
                        {
                            continue;
                        }

                        graphics.FillRectangle(handleBrush, kvp.Value);
                        graphics.DrawRectangle(handlePen, kvp.Value.X, kvp.Value.Y, kvp.Value.Width, kvp.Value.Height);
                    }
                }
            }

            if (TryGetRasterIconRects(selectedRasterObject, out Dictionary<RasterIconType, Rectangle> iconRects))
            {
                DrawIconButton(graphics, iconRects[RasterIconType.Edit], "\uE70F");
                DrawIconButton(
                    graphics,
                    iconRects[RasterIconType.Lock],
                    selectedRasterObject.IsLocked ? "\uE72E" : "\uE785");
                DrawIconButton(graphics, iconRects[RasterIconType.Duplicate], "\uE8C8");
                DrawIconButton(graphics, iconRects[RasterIconType.Order], "\u2630");
                DrawIconButton(graphics, iconRects[RasterIconType.ResetSize], "\uE777");
                DrawIconButton(graphics, iconRects[RasterIconType.Delete], "\uE74D");
            }
        }

        private void DrawSelectedArrowOverlayOnTop(Graphics graphics)
        {
            if (graphics == null || selectedArrowObject == null || selectedArrowObject.PageNumber != currentPage || GetGroupSelectionCount() != 0 || !IsLayerVisible(selectedArrowObject.LayerId))
