                DrawIconButton(graphics, arrowIconRects[ArrowIconType.Duplicate], "\uE8C8");
                DrawIconButton(graphics, arrowIconRects[ArrowIconType.Order], "\u2630");
                DrawIconButton(graphics, arrowIconRects[ArrowIconType.Delete], "\uE74D");
