                    graphics.FillEllipse(centerBrush, centerMarkerRect);
                    graphics.DrawEllipse(centerPen, centerMarkerRect);
                    graphics.DrawLine(
                        centerPen,
                        rotationCenterScreen.X - 4f,
                        rotationCenterScreen.Y,
                        rotationCenterScreen.X + 4f,
                        rotationCenterScreen.Y);
                    graphics.DrawLine(
                        centerPen,
                        rotationCenterScreen.X,
                        rotationCenterScreen.Y - 4f,
                        rotationCenterScreen.X,
                        rotationCenterScreen.Y + 4f);
