        private Rectangle GetAnnotationScreenRect(TextAnnotation annotation, float dpiX, float dpiY)
        {
            return new Rectangle(
                (int)(annotation.AnnotationBounds.X * scaleFactor),
                (int)(annotation.AnnotationBounds.Y * scaleFactor),
                (int)(annotation.AnnotationBounds.Width * scaleFactor * 72f / dpiX),
                (int)(annotation.AnnotationBounds.Height * scaleFactor * 72f / dpiY));
        }

        private PointF GetAnnotationScreenCenter(TextAnnotation annotation, float dpiX, float dpiY)
        {
            Rectangle rect = GetAnnotationScreenRect(annotation, dpiX, dpiY);
            return new PointF(rect.Left + (rect.Width / 2f), rect.Top + (rect.Height / 2f));
        }

        private static bool TryGetAnnotationTextFrameGeometryDoc(
            TextAnnotation annotation,
            out PointF[] frameCorners,
            out RectangleF frameBounds,
            out PointF frameCenter,
            out PointF frameTopMid)
        {
            frameCorners = null;
            frameBounds = RectangleF.Empty;
            frameCenter = PointF.Empty;
            frameTopMid = PointF.Empty;

            if (annotation == null)
            {
                return false;
            }

            if (annotation.AnnotationBounds.Width <= 0f || annotation.AnnotationBounds.Height <= 0f)
            {
                return false;
            }

            const float logicalScaleX = 72f / 96f;
            const float logicalScaleY = 72f / 96f;
            int rotation = NormalizeRotation(annotation.AnnotationRotation);
            SizeF contentSize = GetAnnotationContentSize(annotation);
            float padding = GetAnnotationFramePadding(annotation);
            float layoutWidth = Math.Max(1f, (contentSize.Width + (2f * padding)) * logicalScaleX);
            float layoutHeight = Math.Max(1f, (contentSize.Height + (2f * padding)) * logicalScaleY);
            PointF rotationOffset = GetRotationOffsetForBounds(rotation, layoutWidth, layoutHeight);
            float translateX = annotation.AnnotationBounds.X + rotationOffset.X;
            float translateY = annotation.AnnotationBounds.Y + rotationOffset.Y;
            float angleRad = (float)(rotation * Math.PI / 180.0);
            float cos = (float)Math.Cos(angleRad);
            float sin = (float)Math.Sin(angleRad);

            PointF Transform(float x, float y)
            {
                return new PointF(
                    (x * cos) - (y * sin) + translateX,
                    (x * sin) + (y * cos) + translateY);
            }

            PointF p0 = Transform(0f, 0f);
            PointF p1 = Transform(layoutWidth, 0f);
            PointF p2 = Transform(layoutWidth, layoutHeight);
            PointF p3 = Transform(0f, layoutHeight);
            frameCorners = new[] { p0, p1, p2, p3 };

            float minX = frameCorners.Min(p => p.X);
            float maxX = frameCorners.Max(p => p.X);
            float minY = frameCorners.Min(p => p.Y);
            float maxY = frameCorners.Max(p => p.Y);
            frameBounds = new RectangleF(minX, minY, Math.Max(1f, maxX - minX), Math.Max(1f, maxY - minY));
            frameCenter = new PointF(
                (p0.X + p1.X + p2.X + p3.X) / 4f,
                (p0.Y + p1.Y + p2.Y + p3.Y) / 4f);
            frameTopMid = new PointF(
                (p0.X + p1.X) / 2f,
                (p0.Y + p1.Y) / 2f);
            return true;
        }

        private bool TryGetAnnotationTextFrameGeometry(
            TextAnnotation annotation,
            float dpiX,
            float dpiY,
            out PointF[] frameCorners,
            out RectangleF frameBounds,
            out PointF frameCenter,
            out PointF frameTopMid)
        {
            frameCorners = null;
            frameBounds = RectangleF.Empty;
            frameCenter = PointF.Empty;
            frameTopMid = PointF.Empty;

            if (annotation == null || annotation.PageNumber != currentPage)
            {
                return false;
            }

            Rectangle rect = GetAnnotationScreenRect(annotation, dpiX, dpiY);
            if (rect.Width <= 0 || rect.Height <= 0)
            {
                return false;
            }

            float dpiCorrection = 72f / dpiY;
            int rotation = NormalizeRotation(annotation.AnnotationRotation);
            SizeF contentSize = GetAnnotationContentSize(annotation);
            float padding = GetAnnotationFramePadding(annotation);
            float layoutWidth = Math.Max(1f, (contentSize.Width + (2f * padding)) * scaleFactor * 72f / dpiX);
            float layoutHeight = Math.Max(1f, (contentSize.Height + (2f * padding)) * scaleFactor * dpiCorrection);
            if (layoutWidth <= 0f || layoutHeight <= 0f)
            {
                return false;
            }

            PointF rotationOffset = GetRotationOffsetForBounds(rotation, layoutWidth, layoutHeight);
            float translateX = rect.X + rotationOffset.X;
            float translateY = rect.Y + rotationOffset.Y;
            float angleRad = (float)(rotation * Math.PI / 180.0);
            float cos = (float)Math.Cos(angleRad);
            float sin = (float)Math.Sin(angleRad);

            PointF Transform(float x, float y)
            {
                return new PointF(
                    (x * cos) - (y * sin) + translateX,
                    (x * sin) + (y * cos) + translateY);
            }

            PointF p0 = Transform(0f, 0f);
            PointF p1 = Transform(layoutWidth, 0f);
            PointF p2 = Transform(layoutWidth, layoutHeight);
            PointF p3 = Transform(0f, layoutHeight);
            frameCorners = new[] { p0, p1, p2, p3 };

            float minX = frameCorners.Min(p => p.X);
            float maxX = frameCorners.Max(p => p.X);
            float minY = frameCorners.Min(p => p.Y);
            float maxY = frameCorners.Max(p => p.Y);
            frameBounds = new RectangleF(minX, minY, Math.Max(1f, maxX - minX), Math.Max(1f, maxY - minY));

            frameCenter = new PointF(
                (p0.X + p1.X + p2.X + p3.X) / 4f,
                (p0.Y + p1.Y + p2.Y + p3.Y) / 4f);
            frameTopMid = new PointF(
                (p0.X + p1.X) / 2f,
                (p0.Y + p1.Y) / 2f);
            return true;
        }

        private bool TryGetAnnotationRotationHandleRect(TextAnnotation annotation, float dpiX, float dpiY, out RectangleF handleRect, out PointF connectorPoint)
        {
            handleRect = RectangleF.Empty;
            connectorPoint = PointF.Empty;
            if (!TryGetAnnotationTextFrameGeometry(
                    annotation,
                    dpiX,
                    dpiY,
                    out _,
                    out _,
                    out PointF center,
                    out PointF topMid))
            {
                return false;
            }

            float vx = topMid.X - center.X;
            float vy = topMid.Y - center.Y;
            float len = (float)Math.Sqrt((vx * vx) + (vy * vy));
            if (len <= 0.0001f)
            {
                return false;
            }

            float ux = vx / len;
            float uy = vy / len;
            connectorPoint = topMid;
            PointF handleCenter = new PointF(
                connectorPoint.X + (ux * RasterRotateHandleOffset),
                connectorPoint.Y + (uy * RasterRotateHandleOffset));
            handleRect = new RectangleF(
                handleCenter.X - (RasterRotateHandleSize / 2f),
                handleCenter.Y - (RasterRotateHandleSize / 2f),
                RasterRotateHandleSize,
                RasterRotateHandleSize);
            return true;
        }

        private static PointF GetTextLeaderAnchorPoint(PointF[] corners, TextLeaderAnchorKind anchorKind)
        {
            if (corners == null || corners.Length < 4)
            {
                return PointF.Empty;
            }

            PointF topLeft = corners[0];
            PointF topRight = corners[1];
            PointF bottomRight = corners[2];
            PointF bottomLeft = corners[3];

            switch (anchorKind)
            {
                case TextLeaderAnchorKind.TopLeft:
                    return topLeft;
                case TextLeaderAnchorKind.TopCenter:
                    return new PointF((topLeft.X + topRight.X) / 2f, (topLeft.Y + topRight.Y) / 2f);
                case TextLeaderAnchorKind.TopRight:
                    return topRight;
                case TextLeaderAnchorKind.RightCenter:
                    return new PointF((topRight.X + bottomRight.X) / 2f, (topRight.Y + bottomRight.Y) / 2f);
                case TextLeaderAnchorKind.BottomRight:
                    return bottomRight;
                case TextLeaderAnchorKind.BottomCenter:
                    return new PointF((bottomLeft.X + bottomRight.X) / 2f, (bottomLeft.Y + bottomRight.Y) / 2f);
                case TextLeaderAnchorKind.BottomLeft:
                    return bottomLeft;
                case TextLeaderAnchorKind.LeftCenter:
                default:
                    return new PointF((topLeft.X + bottomLeft.X) / 2f, (topLeft.Y + bottomLeft.Y) / 2f);
            }
        }

        private static System.Drawing.Color GetEffectiveTextLeaderLineColor(TextAnnotation annotation)
        {
            if (annotation == null)
            {
                return System.Drawing.Color.Black;
            }

            System.Drawing.Color background = GetAnnotationBackgroundColor(annotation);
            if (background.A > 0)
            {
                return background;
            }

            System.Drawing.Color border = GetAnnotationBorderColor(annotation);
            if (border.A > 0)
            {
                return border;
            }

            return annotation.AnnotationColor;
        }

        private static float GetEffectiveTextLeaderLineWidth(TextAnnotation annotation)
        {
            if (annotation == null)
            {
                return 1.5f;
            }

            return NormalizeLeaderLineWidth(annotation.LeaderLineWidth);
        }

        private static float NormalizeTextLeaderHeadLength(float value)
        {
            return NormalizeArrowHeadLength(value);
        }

        private static float NormalizeTextLeaderHeadWidth(float value)
        {
            return NormalizeArrowHeadWidth(value);
        }

        private static TextLeaderAnchorKind NormalizeTextLeaderAnchorKind(TextLeaderAnchorKind value)
        {
            return Enum.IsDefined(typeof(TextLeaderAnchorKind), value)
                ? value
                : TextLeaderAnchorKind.RightCenter;
        }

        private bool TryGetAnnotationLeaderGeometryDoc(
            TextAnnotation annotation,
            out PointF anchorPoint,
            out PointF endPoint,
            out PointF leftPoint,
            out PointF rightPoint,
            out PointF lineEndPoint)
        {
            anchorPoint = PointF.Empty;
            endPoint = PointF.Empty;
            leftPoint = PointF.Empty;
            rightPoint = PointF.Empty;
            lineEndPoint = PointF.Empty;

            if (annotation == null || annotation.PageNumber != currentPage || !annotation.HasLeaderArrow)
            {
                return false;
            }

            if (!TryGetAnnotationTextFrameGeometryDoc(annotation, out PointF[] frameCorners, out _, out _, out _))
            {
                return false;
            }

            anchorPoint = GetTextLeaderAnchorPoint(frameCorners, NormalizeTextLeaderAnchorKind(annotation.LeaderAnchorKind));
            endPoint = annotation.LeaderEndPoint;
            float headLength = NormalizeTextLeaderHeadLength(annotation.LeaderHeadLength);
            float headWidth = NormalizeTextLeaderHeadWidth(annotation.LeaderHeadWidth);
            return TryBuildArrowHead(anchorPoint, endPoint, headLength, headWidth, out leftPoint, out rightPoint, out lineEndPoint);
        }

        private bool TryGetAnnotationLeaderGeometry(
            TextAnnotation annotation,
            float dpiX,
            float dpiY,
            out PointF anchorPoint,
            out PointF endPoint,
            out PointF leftPoint,
            out PointF rightPoint,
            out PointF lineEndPoint)
        {
            anchorPoint = PointF.Empty;
            endPoint = PointF.Empty;
            leftPoint = PointF.Empty;
            rightPoint = PointF.Empty;
            lineEndPoint = PointF.Empty;

            if (!TryGetAnnotationLeaderGeometryDoc(annotation, out PointF docAnchor, out PointF docEnd, out PointF docLeft, out PointF docRight, out PointF docLineEnd))
            {
                return false;
            }

            float screenScaleX = scaleFactor;
            float screenScaleY = scaleFactor;
            PointF ToScreen(PointF point) => new PointF(point.X * screenScaleX, point.Y * screenScaleY);

            anchorPoint = ToScreen(docAnchor);
            endPoint = ToScreen(docEnd);
            leftPoint = ToScreen(docLeft);
            rightPoint = ToScreen(docRight);
            lineEndPoint = ToScreen(docLineEnd);
            return true;
        }

        private static TextLeaderAnchorKind GetClosestTextLeaderAnchorKind(TextAnnotation annotation, PointF leaderEndPoint)
        {
            if (!TryGetAnnotationTextFrameGeometryDoc(annotation, out PointF[] frameCorners, out _, out _, out _))
            {
                return TextLeaderAnchorKind.RightCenter;
            }

            TextLeaderAnchorKind bestKind = TextLeaderAnchorKind.RightCenter;
            float bestDistance = float.MaxValue;
            foreach (TextLeaderAnchorKind kind in Enum.GetValues(typeof(TextLeaderAnchorKind)))
            {
                PointF candidate = GetTextLeaderAnchorPoint(frameCorners, kind);
                float dx = leaderEndPoint.X - candidate.X;
                float dy = leaderEndPoint.Y - candidate.Y;
                float distance = (dx * dx) + (dy * dy);
                if (distance < bestDistance)
                {
                    bestDistance = distance;
                    bestKind = kind;
                }
            }

            return bestKind;
        }

        private bool TryGetTextAnnotationVisualDocBounds(TextAnnotation annotation, out RectangleF bounds)
        {
            bounds = RectangleF.Empty;
            if (annotation == null)
            {
                return false;
            }

            if (!TryGetAnnotationTextFrameGeometryDoc(annotation, out PointF[] frameCorners, out RectangleF frameBounds, out _, out _))
            {
                bounds = annotation.AnnotationBounds;
                return !bounds.IsEmpty;
            }

            bounds = frameBounds;
            if (!annotation.HasLeaderArrow)
            {
                return true;
            }

            if (!TryGetAnnotationLeaderGeometryDoc(annotation, out PointF anchorPoint, out PointF endPoint, out PointF leftPoint, out PointF rightPoint, out PointF lineEndPoint))
            {
                RectangleF fallbackLineBounds = RectangleF.FromLTRB(
                    Math.Min(anchorPoint.X, annotation.LeaderEndPoint.X),
                    Math.Min(anchorPoint.Y, annotation.LeaderEndPoint.Y),
                    Math.Max(anchorPoint.X, annotation.LeaderEndPoint.X),
                    Math.Max(anchorPoint.Y, annotation.LeaderEndPoint.Y));
                bounds = RectangleF.Union(bounds, fallbackLineBounds);
                return true;
            }

            float inflate = Math.Max(1f, NormalizeAnnotationBorderWidth(annotation.AnnotationBorderWidth) + 1f);
            RectangleF leaderBounds = RectangleF.FromLTRB(
                new[] { anchorPoint.X, endPoint.X, leftPoint.X, rightPoint.X, lineEndPoint.X }.Min() - inflate,
                new[] { anchorPoint.Y, endPoint.Y, leftPoint.Y, rightPoint.Y, lineEndPoint.Y }.Min() - inflate,
                new[] { anchorPoint.X, endPoint.X, leftPoint.X, rightPoint.X, lineEndPoint.X }.Max() + inflate,
                new[] { anchorPoint.Y, endPoint.Y, leftPoint.Y, rightPoint.Y, lineEndPoint.Y }.Max() + inflate);
            bounds = RectangleF.Union(bounds, leaderBounds);
            return true;
        }

        private bool TryGetTextAnnotationVisualScreenBounds(TextAnnotation annotation, float dpiX, float dpiY, out RectangleF bounds)
        {
            bounds = RectangleF.Empty;
            if (!TryGetAnnotationTextFrameGeometry(annotation, dpiX, dpiY, out _, out RectangleF frameBounds, out _, out _))
            {
                return false;
            }

            bounds = frameBounds;
            if (!annotation.HasLeaderArrow)
            {
                return true;
            }

            if (!TryGetAnnotationLeaderGeometry(annotation, dpiX, dpiY, out PointF anchorPoint, out PointF endPoint, out PointF leftPoint, out PointF rightPoint, out PointF lineEndPoint))
            {
                return true;
            }

            float inflate = Math.Max(
                1f,
                Math.Max(1f, NormalizeAnnotationBorderWidth(annotation.AnnotationBorderWidth) * scaleFactor) + 1f);
            RectangleF leaderBounds = RectangleF.FromLTRB(
                new[] { anchorPoint.X, endPoint.X, leftPoint.X, rightPoint.X, lineEndPoint.X }.Min() - inflate,
                new[] { anchorPoint.Y, endPoint.Y, leftPoint.Y, rightPoint.Y, lineEndPoint.Y }.Min() - inflate,
                new[] { anchorPoint.X, endPoint.X, leftPoint.X, rightPoint.X, lineEndPoint.X }.Max() + inflate,
                new[] { anchorPoint.Y, endPoint.Y, leftPoint.Y, rightPoint.Y, lineEndPoint.Y }.Max() + inflate);
            bounds = RectangleF.Union(bounds, leaderBounds);
            return true;
        }

        private bool TryGetTextLeaderHandleRect(TextAnnotation annotation, float dpiX, float dpiY, out RectangleF handleRect)
        {
            handleRect = RectangleF.Empty;
            if (annotation == null || !annotation.HasLeaderArrow || IsTextAnnotationEffectivelyLocked(annotation))
            {
                return false;
            }

            if (!TryGetAnnotationLeaderGeometry(annotation, dpiX, dpiY, out _, out PointF endPoint, out _, out _, out _))
            {
                return false;
            }

            const float handleSize = 10f;
            handleRect = new RectangleF(endPoint.X - (handleSize / 2f), endPoint.Y - (handleSize / 2f), handleSize, handleSize);
            return true;
        }

        private bool IsPointNearTextAnnotation(TextAnnotation annotation, Point location, float dpiX, float dpiY)
        {
            if (annotation == null || annotation.PageNumber != currentPage || !IsLayerVisible(annotation.LayerId))
            {
                return false;
            }

            if (TryGetAnnotationTextFrameGeometry(annotation, dpiX, dpiY, out _, out RectangleF frameBounds, out _, out _) &&
                frameBounds.Contains(location))
            {
                return true;
            }

            if (!annotation.HasLeaderArrow)
            {
                return false;
            }

            if (!TryGetAnnotationLeaderGeometry(annotation, dpiX, dpiY, out PointF anchorPoint, out PointF endPoint, out PointF leftPoint, out PointF rightPoint, out PointF lineEndPoint))
            {
                return false;
            }

            PointF[] head = { endPoint, leftPoint, rightPoint };
            using (var path = new GraphicsPath())
            {
                path.AddPolygon(head);
                if (path.IsVisible(location))
                {
                    return true;
                }
            }

            float tolerance = Math.Max(6f, (NormalizeAnnotationBorderWidth(annotation.AnnotationBorderWidth) * scaleFactor) + 4f);
            return DistancePointToSegment(location, anchorPoint, lineEndPoint) <= tolerance;
        }

        private bool TryGetAnnotationIconRects(TextAnnotation annotation, float dpiX, float dpiY, out Dictionary<IconType, Rectangle> iconRects)
        {
            iconRects = null;
            if (annotation == null || annotation.PageNumber != currentPage)
            {
                return false;
            }

            Rectangle annotationRect = GetAnnotationScreenRect(annotation, dpiX, dpiY);
            if (annotationRect.Width <= 0 || annotationRect.Height <= 0)
            {
                return false;
            }

            int top = ResolveObjectToolbarTop(annotationRect.Top, annotationRect.Bottom);
            const int buttonCount = 5;
            int totalWidth = (buttonCount * annotationsIconSize) + ((buttonCount - 1) * annotationsIconPadding);
            int right = ResolveObjectToolbarRight(annotationRect.Right, totalWidth);

            Rectangle deleteIconRect = new Rectangle(
                right - annotationsIconSize,
                top,
                annotationsIconSize,
                annotationsIconSize);
            Rectangle orderIconRect = new Rectangle(
                right - (annotationsIconSize * 2) - annotationsIconPadding,
                top,
                annotationsIconSize,
                annotationsIconSize);
            Rectangle duplicateIconRect = new Rectangle(
                right - (annotationsIconSize * 3) - (2 * annotationsIconPadding),
                top,
                annotationsIconSize,
                annotationsIconSize);
            Rectangle lockIconRect = new Rectangle(
                right - (annotationsIconSize * 4) - (3 * annotationsIconPadding),
                top,
                annotationsIconSize,
                annotationsIconSize);
            Rectangle editIconRect = new Rectangle(
                right - (annotationsIconSize * 5) - (4 * annotationsIconPadding),
                top,
                annotationsIconSize,
                annotationsIconSize);

            iconRects = new Dictionary<IconType, Rectangle>
            {
                [IconType.Edit] = editIconRect,
                [IconType.Lock] = lockIconRect,
                [IconType.Duplicate] = duplicateIconRect,
                [IconType.Order] = orderIconRect,
                [IconType.Delete] = deleteIconRect
            };
            return true;
        }

        private bool TryGetTextScaleHandleAtPoint(TextAnnotation annotation, Point location, float dpiX, float dpiY, out ObjectScaleHandleCorner handleCorner, out RectangleF bounds)
        {
            handleCorner = ObjectScaleHandleCorner.TopLeft;
            bounds = RectangleF.Empty;
            if (annotation == null || annotation.PageNumber != currentPage)
            {
                return false;
            }

            if (!TryGetAnnotationTextFrameGeometry(annotation, dpiX, dpiY, out _, out bounds, out _, out _))
            {
                return false;
            }

            return TryGetObjectScaleHandleAtPoint(bounds, location, out handleCorner);
        }

        private bool TryUpdateTextHoverCursor(Point location, float dpiX, float dpiY)
        {
            if (selectedTextAnnotation == null || selectedTextAnnotation.PageNumber != currentPage)
            {
                return false;
            }

            if (!IsTextAnnotationEffectivelyLocked(selectedTextAnnotation) &&
                TryGetTextScaleHandleAtPoint(selectedTextAnnotation, location, dpiX, dpiY, out ObjectScaleHandleCorner scaleHandleCorner, out _))
            {
                this.Cursor = GetCursorForObjectScaleHandle(scaleHandleCorner);
                return true;
            }

            if (!IsTextAnnotationEffectivelyLocked(selectedTextAnnotation) &&
                TryGetTextLeaderHandleRect(selectedTextAnnotation, dpiX, dpiY, out RectangleF leaderHandleRect) &&
                leaderHandleRect.Contains(location))
            {
                this.Cursor = Cursors.Hand;
                return true;
            }

            if (!IsTextAnnotationEffectivelyLocked(selectedTextAnnotation) &&
                TryGetAnnotationRotationHandleRect(selectedTextAnnotation, dpiX, dpiY, out RectangleF handleRect, out _) &&
                handleRect.Contains(location))
            {
                this.Cursor = Cursors.Hand;
                return true;
            }

            if (IsPointNearTextAnnotation(selectedTextAnnotation, location, dpiX, dpiY))
            {
                this.Cursor = IsTextAnnotationEffectivelyLocked(selectedTextAnnotation) ? Cursors.Default : Cursors.SizeAll;
                return true;
            }

            return false;
        }

        private bool TryHandleTextRotationMouseDown(Point location, float dpiX, float dpiY)
        {
            if (selectedTextAnnotation == null ||
                selectedTextAnnotation.PageNumber != currentPage ||
                IsTextAnnotationEffectivelyLocked(selectedTextAnnotation))
            {
                return false;
            }

            if (!TryGetAnnotationRotationHandleRect(selectedTextAnnotation, dpiX, dpiY, out RectangleF handleRect, out _) ||
                !handleRect.Contains(location))
            {
                return false;
            }

            annotationToRotate = selectedTextAnnotation;
            BeginUndoCapture("Rotate text");
            isRotatingTextAnnotation = true;
            textRotationInteractionChanged = false;
            textRotationStartValue = NormalizeRotation(selectedTextAnnotation.AnnotationRotation);
            textRotationStartBounds = selectedTextAnnotation.AnnotationBounds;
            textRotationStartCenterDoc = new PointF(
                selectedTextAnnotation.AnnotationBounds.X + (selectedTextAnnotation.AnnotationBounds.Width / 2f),
                selectedTextAnnotation.AnnotationBounds.Y + (selectedTextAnnotation.AnnotationBounds.Height / 2f));
            PointF center = GetAnnotationScreenCenter(selectedTextAnnotation, dpiX, dpiY);
            if (TryGetAnnotationTextFrameGeometry(
                    selectedTextAnnotation,
                    dpiX,
                    dpiY,
                    out _,
                    out _,
                    out PointF frameCenter,
                    out _))
            {
                center = frameCenter;
            }
            textRotationStartAngle = GetAngleDegrees(center, location);
            this.Cursor = Cursors.Hand;
            return true;
        }

        private bool TryHandleTextScaleMouseDown(Point location, float dpiX, float dpiY)
        {
            if (selectedTextAnnotation == null ||
                selectedTextAnnotation.PageNumber != currentPage ||
                IsTextAnnotationEffectivelyLocked(selectedTextAnnotation))
            {
                return false;
            }

            if (!TryGetTextScaleHandleAtPoint(selectedTextAnnotation, location, dpiX, dpiY, out ObjectScaleHandleCorner handleCorner, out RectangleF screenBounds))
            {
                return false;
            }

            BeginUndoCapture("Scale text");
            annotationToScale = selectedTextAnnotation;
            isScalingTextAnnotation = true;
            activeObjectScaleHandleCorner = handleCorner;
            textScaleStartScreenBounds = screenBounds;
            textScaleStartBounds = selectedTextAnnotation.AnnotationBounds;
            textScaleStartFontFamily = selectedTextAnnotation.AnnotationFont?.FontFamily;
            textScaleStartFontStyle = selectedTextAnnotation.AnnotationFont?.Style ?? FontStyle.Regular;
            textScaleStartFontUnit = selectedTextAnnotation.AnnotationFont?.Unit ?? GraphicsUnit.Point;
            textScaleStartFontSize = selectedTextAnnotation.AnnotationFont?.Size ?? 12f;
            textScaleStartBorderWidth = selectedTextAnnotation.AnnotationBorderWidth;
            textScaleStartFrameMargin = selectedTextAnnotation.AnnotationFrameMargin;
            textScaleStartLeaderEndPoint = selectedTextAnnotation.LeaderEndPoint;
            textScaleStartLeaderLineWidth = NormalizeLeaderLineWidth(selectedTextAnnotation.LeaderLineWidth);
            textScaleStartLeaderHeadLength = NormalizeTextLeaderHeadLength(selectedTextAnnotation.LeaderHeadLength);
            textScaleStartLeaderHeadWidth = NormalizeTextLeaderHeadWidth(selectedTextAnnotation.LeaderHeadWidth);
            this.Cursor = GetCursorForObjectScaleHandle(handleCorner);
            return true;
        }

        private bool TryHandleTextLeaderMouseDown(Point location, float dpiX, float dpiY)
        {
            if (selectedTextAnnotation == null ||
                selectedTextAnnotation.PageNumber != currentPage ||
                IsTextAnnotationEffectivelyLocked(selectedTextAnnotation) ||
                !selectedTextAnnotation.HasLeaderArrow)
            {
                return false;
            }

            if (!TryGetTextLeaderHandleRect(selectedTextAnnotation, dpiX, dpiY, out RectangleF handleRect) ||
                !handleRect.Contains(location))
            {
                return false;
            }

            BeginUndoCapture("Move text leader");
            annotationToAdjustLeader = selectedTextAnnotation;
            isDraggingTextLeaderHandle = true;
            textLeaderDragStartEndPoint = selectedTextAnnotation.LeaderEndPoint;
            textLeaderDragStartAnchorKind = NormalizeTextLeaderAnchorKind(selectedTextAnnotation.LeaderAnchorKind);
            this.Cursor = Cursors.Hand;
            return true;
        }

        private bool TryApplyTextScaleFromMouse(Point location)
        {
            if (!isScalingTextAnnotation || annotationToScale == null || textScaleStartScreenBounds.IsEmpty || textScaleStartBounds.IsEmpty)
            {
                return false;
            }

            bool preserveAspectRatio = (Control.ModifierKeys & Keys.Shift) == Keys.Shift;
            bool scaleFromCenter = (Control.ModifierKeys & Keys.Alt) == Keys.Alt;
            RectangleF newScreenBounds = BuildScaledBoundsFromAnchor(textScaleStartScreenBounds, activeObjectScaleHandleCorner, location, preserveAspectRatio, scaleFromCenter);
            float scaleX = newScreenBounds.Width / Math.Max(1f, textScaleStartScreenBounds.Width);
            float scaleY = newScreenBounds.Height / Math.Max(1f, textScaleStartScreenBounds.Height);
            float uniformScale = Math.Max(0.05f, Math.Max(Math.Abs(scaleX), Math.Abs(scaleY)));
            RectangleF effectiveScreenBounds = ScaleRectangleUniformFromHandle(textScaleStartScreenBounds, activeObjectScaleHandleCorner, uniformScale, scaleFromCenter);
            annotationToScale.AnnotationBounds = ScaleRectangleUniformFromHandle(textScaleStartBounds, activeObjectScaleHandleCorner, uniformScale, scaleFromCenter);
            Font baseFont = annotationToScale.AnnotationFont ?? new Font("Arial", 12f, textScaleStartFontStyle, textScaleStartFontUnit);
            float scaledFontSize = Math.Max(4f, textScaleStartFontSize * uniformScale);
            annotationToScale.AnnotationFont = new Font(baseFont.FontFamily, scaledFontSize, textScaleStartFontStyle, textScaleStartFontUnit);
            annotationToScale.AnnotationBorderWidth = Math.Max(0f, textScaleStartBorderWidth * uniformScale);
            annotationToScale.AnnotationFrameMargin = Math.Max(0f, textScaleStartFrameMargin * uniformScale);
            if (annotationToScale.HasLeaderArrow)
            {
                annotationToScale.LeaderEndPoint = ScalePointFromScreenBounds(textScaleStartLeaderEndPoint, textScaleStartScreenBounds, effectiveScreenBounds, scaleFactor);
                annotationToScale.LeaderLineWidth = NormalizeLeaderLineWidth(textScaleStartLeaderLineWidth * uniformScale);
                annotationToScale.LeaderHeadLength = NormalizeTextLeaderHeadLength(textScaleStartLeaderHeadLength * uniformScale);
                annotationToScale.LeaderHeadWidth = NormalizeTextLeaderHeadWidth(textScaleStartLeaderHeadWidth * uniformScale);
                annotationToScale.LeaderAnchorKind = GetClosestTextLeaderAnchorKind(annotationToScale, annotationToScale.LeaderEndPoint);
            }
            TouchTextAnnotation(annotationToScale);
            textRotationInteractionChanged =
                textRotationInteractionChanged ||
                !AreSameFloat(textScaleStartBounds.X, annotationToScale.AnnotationBounds.X) ||
                !AreSameFloat(textScaleStartBounds.Y, annotationToScale.AnnotationBounds.Y) ||
                !AreSameFloat(textScaleStartBounds.Width, annotationToScale.AnnotationBounds.Width) ||
                !AreSameFloat(textScaleStartBounds.Height, annotationToScale.AnnotationBounds.Height) ||
                (annotationToScale.HasLeaderArrow &&
                 (!AreSamePoint(textScaleStartLeaderEndPoint, annotationToScale.LeaderEndPoint) ||
                  !AreSameFloat(textScaleStartLeaderLineWidth, annotationToScale.LeaderLineWidth) ||
                  !AreSameFloat(textScaleStartLeaderHeadLength, annotationToScale.LeaderHeadLength) ||
                  !AreSameFloat(textScaleStartLeaderHeadWidth, annotationToScale.LeaderHeadWidth)));
            this.Cursor = GetCursorForObjectScaleHandle(activeObjectScaleHandleCorner);
            pdfViewer.Invalidate();
            return true;
        }

        private bool TryApplyTextLeaderDragFromMouse(Point location)
        {
            if (!isDraggingTextLeaderHandle || annotationToAdjustLeader == null)
            {
                return false;
            }

            PointF leaderEndPoint = new PointF(location.X / scaleFactor, location.Y / scaleFactor);
            if (snapToGridEnabled)
            {
                leaderEndPoint = new PointF(
                    SnapValueToGrid(leaderEndPoint.X, SnapGridStep),
                    SnapValueToGrid(leaderEndPoint.Y, SnapGridStep));
            }

            annotationToAdjustLeader.LeaderEndPoint = leaderEndPoint;
            annotationToAdjustLeader.LeaderAnchorKind = GetClosestTextLeaderAnchorKind(annotationToAdjustLeader, leaderEndPoint);
            TouchTextAnnotation(annotationToAdjustLeader);
            textRotationInteractionChanged =
                textRotationInteractionChanged ||
                !AreSamePoint(textLeaderDragStartEndPoint, annotationToAdjustLeader.LeaderEndPoint) ||
                textLeaderDragStartAnchorKind != annotationToAdjustLeader.LeaderAnchorKind;
            this.Cursor = Cursors.Hand;
            pdfViewer.Invalidate();
            return true;
        }

        private static PointF ScalePointFromScreenBounds(PointF initialDocPoint, RectangleF initialScreenBounds, RectangleF newScreenBounds, float scaleFactor)
        {
            float initialScreenX = initialDocPoint.X * scaleFactor;
            float initialScreenY = initialDocPoint.Y * scaleFactor;
            float relativeX = initialScreenBounds.Width <= 0.0001f ? 0.5f : (initialScreenX - initialScreenBounds.Left) / initialScreenBounds.Width;
            float relativeY = initialScreenBounds.Height <= 0.0001f ? 0.5f : (initialScreenY - initialScreenBounds.Top) / initialScreenBounds.Height;
            float newScreenX = newScreenBounds.Left + (relativeX * newScreenBounds.Width);
            float newScreenY = newScreenBounds.Top + (relativeY * newScreenBounds.Height);
            return new PointF(newScreenX / scaleFactor, newScreenY / scaleFactor);
        }

        private bool TryApplyArrowScaleFromMouse(Point location)
        {
            if (!isScalingArrowObject || arrowObjectToScale == null || arrowScaleStartScreenBounds.IsEmpty)
            {
                return false;
            }

            bool preserveAspectRatio = (Control.ModifierKeys & Keys.Shift) == Keys.Shift;
            bool scaleFromCenter = (Control.ModifierKeys & Keys.Alt) == Keys.Alt;
            RectangleF newScreenBounds = BuildScaledBoundsFromAnchor(arrowScaleStartScreenBounds, activeObjectScaleHandleCorner, location, preserveAspectRatio, scaleFromCenter);
            float scaleX = newScreenBounds.Width / Math.Max(1f, arrowScaleStartScreenBounds.Width);
            float scaleY = newScreenBounds.Height / Math.Max(1f, arrowScaleStartScreenBounds.Height);
            float uniformScale = GetUniformScaleFactor(scaleX, scaleY);

            arrowObjectToScale.Start = ScalePointFromScreenBounds(arrowMoveInitialStart, arrowScaleStartScreenBounds, newScreenBounds, scaleFactor);
            arrowObjectToScale.End = ScalePointFromScreenBounds(arrowMoveInitialEnd, arrowScaleStartScreenBounds, newScreenBounds, scaleFactor);
            arrowObjectToScale.Thickness = NormalizeArrowThickness(arrowScaleStartThickness * uniformScale);
            arrowObjectToScale.BorderWidth = NormalizeArrowBorderWidth(arrowScaleStartBorderWidth * uniformScale);
            arrowObjectToScale.HeadLength = NormalizeArrowHeadLength(arrowScaleStartHeadLength * uniformScale);
            arrowObjectToScale.HeadWidth = NormalizeArrowHeadWidth(arrowScaleStartHeadWidth * uniformScale);
            ConstrainArrowToPage(arrowObjectToScale);
            arrowObjectToScale.UpdatedAtUtc = DateTime.UtcNow;
            arrowInteractionChanged =
                arrowInteractionChanged ||
                !AreSamePoint(arrowMoveInitialStart, arrowObjectToScale.Start) ||
                !AreSamePoint(arrowMoveInitialEnd, arrowObjectToScale.End) ||
                !AreSameFloat(arrowScaleStartThickness, arrowObjectToScale.Thickness) ||
                !AreSameFloat(arrowScaleStartBorderWidth, arrowObjectToScale.BorderWidth) ||
                !AreSameFloat(arrowScaleStartHeadLength, arrowObjectToScale.HeadLength) ||
                !AreSameFloat(arrowScaleStartHeadWidth, arrowObjectToScale.HeadWidth);
            this.Cursor = GetCursorForObjectScaleHandle(activeObjectScaleHandleCorner);
            pdfViewer.Invalidate();
            return true;
        }

        private bool TryApplyVectorScaleFromMouse(Point location)
        {
            if (!isScalingVectorShape || vectorShapeToScale == null || vectorScaleStartScreenBounds.IsEmpty || vectorMoveInitialPoints == null || vectorMoveInitialPoints.Count == 0)
            {
                return false;
            }

            bool preserveAspectRatio = (Control.ModifierKeys & Keys.Shift) == Keys.Shift;
            bool scaleFromCenter = (Control.ModifierKeys & Keys.Alt) == Keys.Alt;
            RectangleF newScreenBounds = BuildScaledBoundsFromAnchor(vectorScaleStartScreenBounds, activeObjectScaleHandleCorner, location, preserveAspectRatio, scaleFromCenter);
            float scaleX = newScreenBounds.Width / Math.Max(1f, vectorScaleStartScreenBounds.Width);
            float scaleY = newScreenBounds.Height / Math.Max(1f, vectorScaleStartScreenBounds.Height);
            float uniformScale = GetUniformScaleFactor(scaleX, scaleY);

            vectorShapeToScale.Points = vectorMoveInitialPoints
                .Select(point => ScalePointFromScreenBounds(point, vectorScaleStartScreenBounds, newScreenBounds, scaleFactor))
                .ToList();
            vectorShapeToScale.StrokeWidth = NormalizeVectorStrokeWidth(vectorScaleStartStrokeWidth * uniformScale);
            vectorShapeToScale.StartLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(vectorScaleStartStartEndingPrimarySize * uniformScale);
            vectorShapeToScale.EndLineEndingPrimarySize = NormalizeVectorLineEndingPrimarySize(vectorScaleStartEndEndingPrimarySize * uniformScale);
            if (vectorScaleStartStartEndingPrimarySize <= 0f)
            {
                vectorShapeToScale.StartLineEndingPrimarySize = 0f;
            }
            if (vectorScaleStartEndEndingPrimarySize <= 0f)
            {
                vectorShapeToScale.EndLineEndingPrimarySize = 0f;
            }
            vectorShapeToScale.StartLineEndingSecondarySize = vectorScaleStartStartEndingSecondarySize;
            vectorShapeToScale.EndLineEndingSecondarySize = vectorScaleStartEndEndingSecondarySize;
            NormalizeVectorShape(vectorShapeToScale);
            ConstrainVectorShapeToPage(vectorShapeToScale);
            vectorShapeToScale.UpdatedAtUtc = DateTime.UtcNow;
            bool pointsChanged = vectorMoveInitialPoints.Count != (vectorShapeToScale.Points?.Count ?? 0);
            if (!pointsChanged && vectorShapeToScale.Points != null)
            {
                for (int i = 0; i < vectorMoveInitialPoints.Count; i++)
                {
                    if (!AreSamePoint(vectorMoveInitialPoints[i], vectorShapeToScale.Points[i]))
                    {
                        pointsChanged = true;
                        break;
                    }
                }
            }

            vectorInteractionChanged =
                vectorInteractionChanged ||
                !AreSameFloat(vectorScaleStartStrokeWidth, vectorShapeToScale.StrokeWidth) ||
                !AreSameFloat(vectorScaleStartStartEndingPrimarySize, vectorShapeToScale.StartLineEndingPrimarySize) ||
                !AreSameFloat(vectorScaleStartStartEndingSecondarySize, vectorShapeToScale.StartLineEndingSecondarySize) ||
                !AreSameFloat(vectorScaleStartEndEndingPrimarySize, vectorShapeToScale.EndLineEndingPrimarySize) ||
                !AreSameFloat(vectorScaleStartEndEndingSecondarySize, vectorShapeToScale.EndLineEndingSecondarySize) ||
                pointsChanged;
            this.Cursor = GetCursorForObjectScaleHandle(activeObjectScaleHandleCorner);
            pdfViewer.Invalidate();
            return true;
        }

        private bool TryHandleAnnotationIconMouseDown(Point location, float dpiX, float dpiY)
        {
            if (selectedTextAnnotation == null || selectedTextAnnotation.PageNumber != currentPage)
            {
                return false;
            }

            if (!TryGetAnnotationIconRects(selectedTextAnnotation, dpiX, dpiY, out Dictionary<IconType, Rectangle> iconRects))
            {
                return false;
            }

            foreach (var iconRect in iconRects)
            {
                if (!iconRect.Value.Contains(location))
                {
                    continue;
                }

                isClickOnIcon = true;
                clickedIconType = iconRect.Key;
                annotationForIcon = selectedTextAnnotation;
                return true;
            }

            return false;
        }

        private bool TryHandleRasterIconMouseDown(Point location)
        {
            if (selectedRasterObject == null || selectedRasterObject.PageNumber != currentPage)
            {
                return false;
            }

            if (!TryGetRasterIconRects(selectedRasterObject, out Dictionary<RasterIconType, Rectangle> iconRects))
            {
                return false;
            }

            foreach (var iconRect in iconRects)
            {
                if (!iconRect.Value.Contains(location))
                {
                    continue;
                }

                isClickOnRasterIcon = true;
                clickedRasterIconType = iconRect.Key;
                rasterObjectForIcon = selectedRasterObject;
                return true;
            }

            return false;
        }

        private void DuplicateRasterObject(RasterObject source)
        {
            if (source == null || source.PageNumber != currentPage)
            {
                return;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return;
            }

            var now = DateTime.UtcNow;
            string duplicateGroupId = CreateDuplicateGroupId();
            RectangleF copyBounds = source.Bounds;
            copyBounds.Offset(12f, 12f);
            var copy = new RasterObject
            {
                Id = Guid.NewGuid().ToString("N"),
                PageNumber = currentPage,
                LayerId = NormalizeLayerIdValue(source.LayerId),
                Bounds = copyBounds,
                InitialBounds = copyBounds,
                Rotation = source.Rotation,
                Opacity = source.Opacity,
                TransparentBackground = source.TransparentBackground,
                LockAspect = source.LockAspect,
                IsLocked = source.IsLocked,
                SourceType = source.SourceType,
                FilePath = source.FilePath,
                EmbeddedBytes = source.EmbeddedBytes == null ? null : (byte[])source.EmbeddedBytes.Clone(),
                MimeType = source.MimeType,
                CreatedAtUtc = now,
                UpdatedAtUtc = now,
                DuplicateGroupId = duplicateGroupId
            };

            ConstrainRasterObjectToPage(copy);
            copy.InitialBounds = copy.Bounds;
            rasterObjects.Add(copy);
            ClearGroupSelection();
            selectedRasterObject = copy;
            selectedTextAnnotation = null;
            selectedArrowObject = null;
            if (currentPage >= 1 && currentPage <= allPageStatuses.Count)
            {
                PageItemStatus status = allPageStatuses[currentPage - 1];
                status.HasObjects = HasAnyObjectsOnPage(currentPage);
                if ((string)filterComboBox.SelectedItem == allComboItem)
                {
                    ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                    UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                    pagesListView.Invalidate(currentItem.Bounds);
                }
                else
                {
                    ApplyFilter((string)filterComboBox.SelectedItem);
                }
            }
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            pdfViewer.Invalidate();
        }

        private void DuplicateArrowObject(ArrowObject source)
        {
            if (source == null || source.PageNumber != currentPage)
            {
                return;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return;
            }

            PointF start = new PointF(source.Start.X + 12f, source.Start.Y + 12f);
            PointF end = new PointF(source.End.X + 12f, source.End.Y + 12f);
            var now = DateTime.UtcNow;
            string duplicateGroupId = CreateDuplicateGroupId();
            var copy = new ArrowObject
            {
                Id = Guid.NewGuid().ToString("N"),
                PageNumber = currentPage,
                LayerId = NormalizeLayerIdValue(source.LayerId),
                Start = start,
                End = end,
                LineColorArgb = source.LineColorArgb,
                Thickness = NormalizeArrowThickness(source.Thickness),
                BorderColorArgb = source.BorderColorArgb,
                BorderWidth = NormalizeArrowBorderWidth(source.BorderWidth),
                HeadLength = NormalizeArrowHeadLength(source.HeadLength),
                HeadWidth = NormalizeArrowHeadWidth(source.HeadWidth),
                IsLocked = source.IsLocked,
                CreatedAtUtc = now,
                UpdatedAtUtc = now,
                DuplicateGroupId = duplicateGroupId
            };

            ConstrainArrowToPage(copy);
            arrowObjects.Add(copy);
            ClearGroupSelection();
            selectedArrowObject = copy;
            selectedRasterObject = null;
            selectedTextAnnotation = null;
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            UpdateCurrentPageObjectsMarker();
            pdfViewer.Invalidate();
        }

        private static bool AreSameFloat(float a, float b)
        {
            return Math.Abs(a - b) < 0.001f;
        }

        private bool RasterObjectChanged(
            RasterObject rasterObject,
            RectangleF newBounds,
            int newRotation,
            float newOpacity,
            bool newTransparentBackground,
            bool newLockAspect,
            bool newIsLocked,
            string newFilePath)
        {
            if (!AreSameFloat(rasterObject.Bounds.X, newBounds.X) ||
                !AreSameFloat(rasterObject.Bounds.Y, newBounds.Y) ||
                !AreSameFloat(rasterObject.Bounds.Width, newBounds.Width) ||
                !AreSameFloat(rasterObject.Bounds.Height, newBounds.Height))
            {
                return true;
            }

            if (NormalizeRotation(rasterObject.Rotation) != NormalizeRotation(newRotation))
            {
                return true;
            }

            if (!AreSameFloat(NormalizeOpacity(rasterObject.Opacity), NormalizeOpacity(newOpacity)))
            {
                return true;
            }

            if (rasterObject.TransparentBackground != newTransparentBackground)
            {
                return true;
            }

            if (rasterObject.LockAspect != newLockAspect || rasterObject.IsLocked != newIsLocked)
            {
                return true;
            }

            if (!string.Equals(rasterObject.FilePath ?? string.Empty, newFilePath ?? string.Empty, StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }

            return false;
        }

        private bool TryHandleArrowIconMouseDown(Point location)
        {
            if (selectedArrowObject == null || selectedArrowObject.PageNumber != currentPage)
            {
                return false;
            }

            if (!TryGetArrowIconRects(selectedArrowObject, out Dictionary<ArrowIconType, Rectangle> iconRects))
            {
                return false;
            }

            foreach (var iconRect in iconRects)
            {
                if (!iconRect.Value.Contains(location))
                {
                    continue;
                }

                isClickOnArrowIcon = true;
                clickedArrowIconType = iconRect.Key;
                arrowObjectForIcon = selectedArrowObject;
                return true;
            }

            return false;
        }

        private bool TryHandleVectorIconMouseDown(Point location)
        {
            if (selectedVectorShape == null || selectedVectorShape.PageNumber != currentPage)
            {
                return false;
            }

            if (!TryGetVectorIconRects(selectedVectorShape, out Dictionary<VectorIconType, Rectangle> iconRects))
            {
                return false;
            }

            foreach (var iconRect in iconRects)
            {
                if (!iconRect.Value.Contains(location))
                {
                    continue;
                }

                isClickOnVectorIcon = true;
                clickedVectorIconType = iconRect.Key;
                vectorShapeForIcon = selectedVectorShape;
                return true;
            }

            return false;
        }

        private bool TrySelectRasterImagePath(out string selectedPath)
        {
            selectedPath = string.Empty;
            using (var openFileDialog = new OpenFileDialog())
            {
                openFileDialog.Filter = LocalizedText("Dialog_Filter_RasterImages");
                openFileDialog.Title = string.Format(LocalizedText("Dialog_Title_AddRasterImage"), Branding.ProductName);
                openFileDialog.CheckFileExists = true;
                openFileDialog.Multiselect = false;

                if (openFileDialog.ShowDialog(this) != DialogResult.OK)
                {
                    return false;
                }

                selectedPath = openFileDialog.FileName;
                return true;
            }
        }

        private static bool TryGetRasterImageMetrics(RasterObject rasterObject, out int width, out int height, out decimal aspectRatio)
        {
            width = 0;
            height = 0;
            aspectRatio = 0m;
            if (!TryCreateRasterPreviewImage(rasterObject, out DrawingImage previewImage))
            {
                return false;
            }

            using (previewImage)
            {
                if (previewImage.Width <= 0 || previewImage.Height <= 0)
                {
                    return false;
                }

                width = previewImage.Width;
                height = previewImage.Height;
                aspectRatio = (decimal)width / height;
                return aspectRatio > 0m;
            }
        }

        private bool ApplyRasterObjectDialogChanges(RasterObject rasterObject, EditRasterDialog dlg, bool updateThumbnail = true)
        {
            if (rasterObject == null || dlg == null)
            {
                return false;
            }

            RectangleF updatedBounds = new RectangleF(
                dlg.PositionX,
                dlg.PositionY,
                dlg.WidthValue,
                dlg.HeightValue);
            int updatedRotation = NormalizeRotation(dlg.Rotation);
            float updatedOpacity = NormalizeOpacity(dlg.RasterOpacity);
            bool updatedTransparentBackground = dlg.TransparentBackground;
            bool updatedLockAspect = dlg.LockAspect;
            bool updatedLocked = dlg.IsLocked;
            string selectedPathToApply = dlg.ReplacementImagePath;

            try
            {
                if (!string.IsNullOrWhiteSpace(selectedPathToApply))
                {
                    using (var image = DrawingImage.FromFile(selectedPathToApply))
                    {
                        if (image.Width <= 0 || image.Height <= 0)
                        {
                            return false;
                        }
                    }
                }

                bool changed = RasterObjectChanged(
                    rasterObject,
                    updatedBounds,
                    updatedRotation,
                    updatedOpacity,
                    updatedTransparentBackground,
                    updatedLockAspect,
                    updatedLocked,
                    string.IsNullOrWhiteSpace(selectedPathToApply) ? rasterObject.FilePath : selectedPathToApply);
                if (!changed)
                {
                    return false;
                }

                rasterObject.Bounds = updatedBounds;
                rasterObject.Rotation = updatedRotation;
                rasterObject.Opacity = updatedOpacity;
                rasterObject.TransparentBackground = updatedTransparentBackground;
                rasterObject.LockAspect = updatedLockAspect;
                rasterObject.IsLocked = updatedLocked;

                if (!string.IsNullOrWhiteSpace(selectedPathToApply))
                {
                    rasterObject.SourceType = RasterSourceFile;
                    rasterObject.FilePath = selectedPathToApply;
                    rasterObject.EmbeddedBytes = null;
                    rasterObject.MimeType = GetRasterMimeTypeFromPath(selectedPathToApply);
                }

                ConstrainRasterObjectToPage(rasterObject);
                rasterObject.UpdatedAtUtc = DateTime.UtcNow;
                dlg.SyncControlsFromObject(rasterObject);

                projectWasChangedAfterLastSave = true;
                saveProjectButton.Enabled = true;
                saveProjectMenuItem.Enabled = true;
                pdfViewer.Invalidate();
                if (updateThumbnail)
                {
                    InvalidateThumbnailPage(rasterObject.PageNumber);
                }
                return true;
            }
            catch (Exception ex)
            {
                ShowInfoMessage(LocalizedFormat("Err_RasterImageLoad", ex.Message));
                LogDebug("Edit raster object failed: " + ex);
                return false;
            }
        }

        private void EditRasterObject(RasterObject rasterObject)
        {
            if (rasterObject == null || rasterObject.PageNumber != currentPage)
            {
                return;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return;
            }

            using (var dlg = new EditRasterDialog())
            {
                dlg.PositionX = rasterObject.Bounds.X;
                dlg.PositionY = rasterObject.Bounds.Y;
                dlg.WidthValue = rasterObject.Bounds.Width;
                dlg.HeightValue = rasterObject.Bounds.Height;
                dlg.Rotation = NormalizeRotation(rasterObject.Rotation);
                dlg.RasterOpacity = NormalizeOpacity(rasterObject.Opacity);
                dlg.TransparentBackground = rasterObject.TransparentBackground;
                dlg.LockAspect = rasterObject.LockAspect;
                dlg.IsLocked = rasterObject.IsLocked;
                dlg.SourceType = rasterObject.SourceType;
                dlg.FilePath = rasterObject.FilePath;
                dlg.ViewScaleFactor = Math.Max(0.01f, scaleFactor);
                var pageSize = GetPageSizeWithOffset(currentPage);
                dlg.PageWidth = pageSize.Width;
                dlg.PageHeight = pageSize.Height;
                if (TryGetRasterImageMetrics(rasterObject, out int sourcePixelWidth, out int sourcePixelHeight, out decimal sourceAspectRatio))
                {
                    dlg.SourcePixelWidth = sourcePixelWidth;
                    dlg.SourcePixelHeight = sourcePixelHeight;
                    dlg.SourceAspectRatio = sourceAspectRatio;
                }
                dlg.SelectReplacementImage = () =>
                {
                    return TrySelectRasterImagePath(out string selectedPath) ? selectedPath : string.Empty;
                };
                dlg.RestoreDefaultsAction = dialog => ApplyRasterDialogDefaults(dialog, RasterDialogDefaults.CreateDefault());
                dlg.ApplyChanges = () =>
                {
                    ApplyRasterObjectDialogChanges(rasterObject, dlg, updateThumbnail: false);
                };

                if (dlg.ShowDialog(this) != DialogResult.OK)
                {
                    return;
                }

                ApplyRasterObjectDialogChanges(rasterObject, dlg);
                InvalidateThumbnailPage(rasterObject.PageNumber);
                CaptureRasterDialogDefaults(dlg);
            }
        }

        private void ApplyRasterDialogDefaults(EditRasterDialog dialog, RasterDialogDefaults defaults)
        {
            if (dialog == null || defaults == null)
            {
                return;
            }

            dialog.Rotation = defaults.Rotation;
            dialog.RasterOpacity = defaults.RasterOpacity;
            dialog.TransparentBackground = defaults.TransparentBackground;
            dialog.LockAspect = defaults.LockAspect;
            dialog.IsLocked = defaults.IsLocked;
        }

        private void CaptureRasterDialogDefaults(EditRasterDialog dialog)
        {
            if (dialog == null)
            {
                return;
            }

            activeRasterDialogDefaults = new RasterDialogDefaults
            {
                Rotation = NormalizeRotation(dialog.Rotation),
                RasterOpacity = NormalizeOpacity(dialog.RasterOpacity),
                TransparentBackground = dialog.TransparentBackground,
                LockAspect = dialog.LockAspect,
                IsLocked = dialog.IsLocked
            };
        }

        private void ResetRasterObjectSize(RasterObject rasterObject)
        {
            if (rasterObject == null || rasterObject.PageNumber != currentPage)
            {
                return;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return;
            }

            RectangleF initialBounds = GetResolvedRasterInitialBounds(rasterObject);
            if (!HasPositiveSize(initialBounds))
            {
                return;
            }

            RectangleF currentBounds = rasterObject.Bounds;
            float centerX = currentBounds.X + (currentBounds.Width / 2f);
            float centerY = currentBounds.Y + (currentBounds.Height / 2f);
            var resizedBounds = new RectangleF(
                centerX - (initialBounds.Width / 2f),
                centerY - (initialBounds.Height / 2f),
                initialBounds.Width,
                initialBounds.Height);

            if (Math.Abs(currentBounds.Width - resizedBounds.Width) < 0.001f &&
                Math.Abs(currentBounds.Height - resizedBounds.Height) < 0.001f)
            {
                return;
            }

            rasterObject.Bounds = resizedBounds;
            ConstrainRasterObjectToPage(rasterObject);
            rasterObject.UpdatedAtUtc = DateTime.UtcNow;
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            pdfViewer.Invalidate();
            InvalidateThumbnailPage(rasterObject.PageNumber);
        }

        private bool TryGetRasterResizeHandleRects(RasterObject rasterObject, out Dictionary<RasterResizeHandleType, RectangleF> handles)
        {
            handles = null;
            if (rasterObject == null || rasterObject.PageNumber != currentPage)
            {
                return false;
            }

            RectangleF bounds = GetRasterObjectScreenBounds(rasterObject);
            if (bounds.Width <= 0f || bounds.Height <= 0f)
            {
                return false;
            }

            PointF center = GetRasterObjectScreenCenter(rasterObject);
            int rotation = NormalizeRotation(rasterObject.Rotation);
            PointF vx = RotateVector(new PointF(bounds.Width / 2f, 0f), rotation);
            PointF vy = RotateVector(new PointF(0f, bounds.Height / 2f), rotation);

            PointF topLeft = new PointF(center.X - vx.X - vy.X, center.Y - vx.Y - vy.Y);
            PointF top = new PointF(center.X - vy.X, center.Y - vy.Y);
            PointF topRight = new PointF(center.X + vx.X - vy.X, center.Y + vx.Y - vy.Y);
            PointF right = new PointF(center.X + vx.X, center.Y + vx.Y);
            PointF bottomRight = new PointF(center.X + vx.X + vy.X, center.Y + vx.Y + vy.Y);
            PointF bottom = new PointF(center.X + vy.X, center.Y + vy.Y);
            PointF bottomLeft = new PointF(center.X - vx.X + vy.X, center.Y - vx.Y + vy.Y);
            PointF left = new PointF(center.X - vx.X, center.Y - vx.Y);

            handles = new Dictionary<RasterResizeHandleType, RectangleF>
            {
                [RasterResizeHandleType.TopLeft] = BuildHandleRect(topLeft, RasterResizeHandleSize),
                [RasterResizeHandleType.Top] = BuildHandleRect(top, RasterResizeHandleSize),
                [RasterResizeHandleType.TopRight] = BuildHandleRect(topRight, RasterResizeHandleSize),
                [RasterResizeHandleType.Right] = BuildHandleRect(right, RasterResizeHandleSize),
                [RasterResizeHandleType.BottomRight] = BuildHandleRect(bottomRight, RasterResizeHandleSize),
                [RasterResizeHandleType.Bottom] = BuildHandleRect(bottom, RasterResizeHandleSize),
                [RasterResizeHandleType.BottomLeft] = BuildHandleRect(bottomLeft, RasterResizeHandleSize),
                [RasterResizeHandleType.Left] = BuildHandleRect(left, RasterResizeHandleSize)
            };
            return true;
        }

        private bool TryGetRasterResizeHandleAtPoint(RasterObject rasterObject, Point location, out RasterResizeHandleType handle)
        {
            handle = RasterResizeHandleType.None;
            if (!TryGetRasterResizeHandleRects(rasterObject, out Dictionary<RasterResizeHandleType, RectangleF> handles))
            {
                return false;
            }

            foreach (var kvp in handles)
            {
                if (kvp.Value.Contains(location))
                {
                    handle = kvp.Key;
                    return true;
                }
            }

            return false;
        }

        private static RasterResizeHandleType GetOppositeRasterResizeHandle(RasterResizeHandleType handle)
        {
            switch (handle)
            {
                case RasterResizeHandleType.TopLeft:
                    return RasterResizeHandleType.BottomRight;
                case RasterResizeHandleType.Top:
                    return RasterResizeHandleType.Bottom;
                case RasterResizeHandleType.TopRight:
                    return RasterResizeHandleType.BottomLeft;
                case RasterResizeHandleType.Right:
                    return RasterResizeHandleType.Left;
                case RasterResizeHandleType.BottomRight:
                    return RasterResizeHandleType.TopLeft;
                case RasterResizeHandleType.Bottom:
                    return RasterResizeHandleType.Top;
                case RasterResizeHandleType.BottomLeft:
                    return RasterResizeHandleType.TopRight;
                case RasterResizeHandleType.Left:
                    return RasterResizeHandleType.Right;
                default:
                    return RasterResizeHandleType.None;
            }
        }

        private static PointF GetRasterResizeHandleLocalPoint(RasterResizeHandleType handle, float halfWidth, float halfHeight)
        {
            switch (handle)
            {
                case RasterResizeHandleType.TopLeft:
                    return new PointF(-halfWidth, -halfHeight);
                case RasterResizeHandleType.Top:
                    return new PointF(0f, -halfHeight);
                case RasterResizeHandleType.TopRight:
                    return new PointF(halfWidth, -halfHeight);
                case RasterResizeHandleType.Right:
                    return new PointF(halfWidth, 0f);
                case RasterResizeHandleType.BottomRight:
                    return new PointF(halfWidth, halfHeight);
                case RasterResizeHandleType.Bottom:
                    return new PointF(0f, halfHeight);
                case RasterResizeHandleType.BottomLeft:
                    return new PointF(-halfWidth, halfHeight);
                case RasterResizeHandleType.Left:
                    return new PointF(-halfWidth, 0f);
                default:
                    return PointF.Empty;
            }
        }

        private static PointF GetRasterResizeSign(RasterResizeHandleType handle)
        {
            float sx = 0f;
            float sy = 0f;
            switch (handle)
            {
                case RasterResizeHandleType.TopLeft:
                case RasterResizeHandleType.Left:
                case RasterResizeHandleType.BottomLeft:
                    sx = -1f;
                    break;
                case RasterResizeHandleType.TopRight:
                case RasterResizeHandleType.Right:
                case RasterResizeHandleType.BottomRight:
                    sx = 1f;
                    break;
            }

            switch (handle)
            {
                case RasterResizeHandleType.TopLeft:
                case RasterResizeHandleType.Top:
                case RasterResizeHandleType.TopRight:
                    sy = -1f;
                    break;
                case RasterResizeHandleType.BottomLeft:
                case RasterResizeHandleType.Bottom:
                case RasterResizeHandleType.BottomRight:
                    sy = 1f;
                    break;
            }

            return new PointF(sx, sy);
        }

        private static PointF GetRasterResizeHandleWorldPoint(RectangleF bounds, int rotation, RasterResizeHandleType handle)
        {
            PointF center = new PointF(bounds.X + (bounds.Width / 2f), bounds.Y + (bounds.Height / 2f));
            PointF localHandle = GetRasterResizeHandleLocalPoint(handle, bounds.Width / 2f, bounds.Height / 2f);
            PointF rotatedHandle = RotateVector(localHandle, NormalizeRotation(rotation));
            return new PointF(center.X + rotatedHandle.X, center.Y + rotatedHandle.Y);
        }

        private static float NormalizeDegrees(float angle)
        {
            float normalized = angle % 360f;
            if (normalized < 0f)
            {
                normalized += 360f;
            }
            return normalized;
        }

        private static Cursor GetDirectionalResizeCursor(float absoluteAngle)
        {
            // Cursor orientation is symmetric every 180 degrees.
            float angle = NormalizeDegrees(absoluteAngle) % 180f;
            if (angle >= 22.5f && angle < 67.5f)
            {
                return Cursors.SizeNWSE;
            }
            if (angle >= 67.5f && angle < 112.5f)
            {
                return Cursors.SizeNS;
            }
            if (angle >= 112.5f && angle < 157.5f)
            {
                return Cursors.SizeNESW;
            }
            return Cursors.SizeWE;
        }

        private static float GetHandleBaseAngle(RasterResizeHandleType handle)
        {
            switch (handle)
            {
                case RasterResizeHandleType.Right:
                    return 0f;
                case RasterResizeHandleType.TopRight:
                    return 315f;
                case RasterResizeHandleType.Top:
                    return 270f;
                case RasterResizeHandleType.TopLeft:
                    return 225f;
                case RasterResizeHandleType.Left:
                    return 180f;
                case RasterResizeHandleType.BottomLeft:
                    return 135f;
                case RasterResizeHandleType.Bottom:
                    return 90f;
                case RasterResizeHandleType.BottomRight:
                    return 45f;
                default:
                    return 0f;
            }
        }

        private static Cursor GetCursorForRasterResizeHandle(RasterResizeHandleType handle, int rotation)
        {
            if (handle == RasterResizeHandleType.None)
            {
                return Cursors.Default;
            }

            float angle = GetHandleBaseAngle(handle) + NormalizeRotation(rotation);
            return GetDirectionalResizeCursor(angle);
        }

        private bool TryUpdateRasterHoverCursor(Point location)
        {
            if (selectedRasterObject == null || selectedRasterObject.PageNumber != currentPage)
            {
                return false;
            }

            if (IsRasterObjectEffectivelyLocked(selectedRasterObject))
            {
                if (IsPointInsideRasterObject(selectedRasterObject, location))
                {
                    this.Cursor = Cursors.Default;
                    return true;
                }

                return false;
            }

            if (TryGetRasterResizeHandleAtPoint(selectedRasterObject, location, out RasterResizeHandleType handle))
            {
                this.Cursor = GetCursorForRasterResizeHandle(handle, selectedRasterObject.Rotation);
                return true;
            }

            if (TryGetRasterRotationHandleRect(selectedRasterObject, out RectangleF rotationHandleRect, out _) && rotationHandleRect.Contains(location))
            {
                this.Cursor = Cursors.Hand;
                return true;
            }

            if (IsPointInsideRasterObject(selectedRasterObject, location))
            {
                this.Cursor = Cursors.SizeAll;
                return true;
            }

            return false;
        }

        private float GetAngleDegrees(PointF center, Point point)
        {
            return (float)(Math.Atan2(point.Y - center.Y, point.X - center.X) * (180d / Math.PI));
        }

        private bool TryHandleRasterMouseDown(Point location)
        {
            if (selectedRasterObject != null && selectedRasterObject.PageNumber == currentPage && !IsRasterObjectEffectivelyLocked(selectedRasterObject))
            {
                if (TryGetRasterResizeHandleAtPoint(selectedRasterObject, location, out RasterResizeHandleType handle))
                {
                    BeginUndoCapture("Resize image");
                    rasterObjectToResize = selectedRasterObject;
                    isResizingRasterObject = true;
                    rasterResizeHandle = handle;
                    rasterResizeStartBounds = selectedRasterObject.Bounds;
                    rasterResizeStartRotation = NormalizeRotation(selectedRasterObject.Rotation);
                    RasterResizeHandleType oppositeHandle = GetOppositeRasterResizeHandle(handle);
                    rasterResizeAnchorWorld = GetRasterResizeHandleWorldPoint(
                        rasterResizeStartBounds,
                        rasterResizeStartRotation,
                        oppositeHandle);
                    this.Cursor = GetCursorForRasterResizeHandle(handle, selectedRasterObject.Rotation);
                    return true;
                }

                if (TryGetRasterRotationHandleRect(selectedRasterObject, out RectangleF handleRect, out _) && handleRect.Contains(location))
                {
                    BeginUndoCapture("Rotate image");
                    rasterObjectToRotate = selectedRasterObject;
                    isRotatingRasterObject = true;
                    rasterRotationStartValue = NormalizeRotation(selectedRasterObject.Rotation);
                    rasterRotateStartBounds = selectedRasterObject.Bounds;
                    PopulateRasterRotateAttachedClipEntries(selectedRasterObject);
                    rasterRotationStartAngle = GetAngleDegrees(GetRasterObjectScreenCenter(selectedRasterObject), location);
                    this.Cursor = Cursors.Hand;
                    return true;
                }
            }

            RasterObject hitObject = rasterObjects
                .Where(obj => obj != null && obj.PageNumber == currentPage)
                .Reverse()
                .FirstOrDefault(obj => IsPointInsideRasterObject(obj, location));

            if (hitObject == null)
            {
                selectedRasterObject = null;
                ClearRasterIconClickState();
                return false;
            }

            EnsureRasterObjectId(hitObject);
            selectedRasterObject = hitObject;
            selectedVectorShape = null;
            ClearGroupSelection();
            ClearRasterIconClickState();
            if (IsRasterObjectEffectivelyLocked(hitObject))
            {
                return true;
            }

            rasterObjectToMove = hitObject;
            BeginUndoCapture("Move image");
            isMovingRasterObject = true;
            rasterMoveStartBounds = hitObject.Bounds;
            startPoint = location;
            PointF mouseDoc = new PointF(location.X / scaleFactor, location.Y / scaleFactor);
            rasterMoveMouseOffset = new PointF(mouseDoc.X - hitObject.Bounds.X, mouseDoc.Y - hitObject.Bounds.Y);
            PopulateRasterMoveAttachedClipEntries(hitObject);
            this.Cursor = Cursors.SizeAll;
            return true;
        }

        private static Bitmap ApplyTransparentBackgroundFromTopLeft(Bitmap source)
        {
            if (source == null)
            {
                return null;
            }

            Bitmap working = new Bitmap(source.Width, source.Height, PixelFormat.Format32bppArgb);
            using (Graphics g = Graphics.FromImage(working))
            {
                g.DrawImage(source, 0, 0, source.Width, source.Height);
            }

            if (working.Width <= 0 || working.Height <= 0)
            {
                return working;
            }

            Rectangle rect = new Rectangle(0, 0, working.Width, working.Height);
            BitmapData data = null;
            try
            {
                data = working.LockBits(rect, ImageLockMode.ReadWrite, PixelFormat.Format32bppArgb);
                int stride = data.Stride;
                int rowBytes = Math.Abs(stride);
                int totalBytes = rowBytes * working.Height;
                byte[] buffer = new byte[totalBytes];
                Marshal.Copy(data.Scan0, buffer, 0, totalBytes);

                int firstRowStart = stride >= 0 ? 0 : (working.Height - 1) * rowBytes;
                byte keyB = buffer[firstRowStart];
                byte keyG = buffer[firstRowStart + 1];
                byte keyR = buffer[firstRowStart + 2];

                for (int y = 0; y < working.Height; y++)
                {
                    int rowStart = stride >= 0 ? y * rowBytes : (working.Height - 1 - y) * rowBytes;
                    for (int x = 0; x < working.Width; x++)
                    {
                        int idx = rowStart + (x * 4);
                        if (buffer[idx] == keyB && buffer[idx + 1] == keyG && buffer[idx + 2] == keyR)
                        {
                            buffer[idx + 3] = 0;
                        }
                    }
                }

                Marshal.Copy(buffer, 0, data.Scan0, totalBytes);
            }
            finally
            {
                if (data != null)
                {
                    working.UnlockBits(data);
                }
            }

            return working;
        }

        private static bool TryCreateRasterPreviewImage(RasterObject rasterObject, out DrawingImage image)
        {
            image = null;
            if (rasterObject == null)
            {
                return false;
            }

            try
            {
                if (rasterObject.EmbeddedBytes != null && rasterObject.EmbeddedBytes.Length > 0)
                {
                    using (var ms = new MemoryStream(rasterObject.EmbeddedBytes))
                    using (var src = DrawingImage.FromStream(ms))
                    {
                        using (var baseBitmap = new Bitmap(src))
                        {
                            image = rasterObject.TransparentBackground
                                ? ApplyTransparentBackgroundFromTopLeft(baseBitmap)
                                : new Bitmap(baseBitmap);
                        }
                        return true;
                    }
                }

                if (!string.IsNullOrWhiteSpace(rasterObject.FilePath) && File.Exists(rasterObject.FilePath))
                {
                    using (var src = DrawingImage.FromFile(rasterObject.FilePath))
                    {
                        using (var baseBitmap = new Bitmap(src))
                        {
                            image = rasterObject.TransparentBackground
                                ? ApplyTransparentBackgroundFromTopLeft(baseBitmap)
                                : new Bitmap(baseBitmap);
                        }
                        return true;
                    }
                }
            }
            catch
            {
                return false;
            }

            return false;
        }

        private static bool TryCreateRasterImageData(RasterObject rasterObject, out iText.IO.Image.ImageData imageData)
        {
            imageData = null;
            if (rasterObject == null)
            {
                return false;
            }

            try
            {
                if (rasterObject.EmbeddedBytes != null && rasterObject.EmbeddedBytes.Length > 0)
                {
                    if (!rasterObject.TransparentBackground)
                    {
                        imageData = iText.IO.Image.ImageDataFactory.Create(rasterObject.EmbeddedBytes);
                        return true;
                    }

                    using (var ms = new MemoryStream(rasterObject.EmbeddedBytes))
                    using (var src = DrawingImage.FromStream(ms))
                    using (var baseBitmap = new Bitmap(src))
                    using (var transformed = ApplyTransparentBackgroundFromTopLeft(baseBitmap))
                    using (var pngStream = new MemoryStream())
                    {
                        transformed.Save(pngStream, ImageFormat.Png);
                        imageData = iText.IO.Image.ImageDataFactory.Create(pngStream.ToArray());
                    }
                    return true;
                }

                if (!string.IsNullOrWhiteSpace(rasterObject.FilePath) && File.Exists(rasterObject.FilePath))
                {
                    if (!rasterObject.TransparentBackground)
                    {
                        byte[] fileBytes = File.ReadAllBytes(rasterObject.FilePath);
                        imageData = iText.IO.Image.ImageDataFactory.Create(fileBytes);
                        return true;
                    }

                    using (var src = DrawingImage.FromFile(rasterObject.FilePath))
                    using (var baseBitmap = new Bitmap(src))
                    using (var transformed = ApplyTransparentBackgroundFromTopLeft(baseBitmap))
                    using (var pngStream = new MemoryStream())
                    {
                        transformed.Save(pngStream, ImageFormat.Png);
                        imageData = iText.IO.Image.ImageDataFactory.Create(pngStream.ToArray());
                    }
                    return true;
                }
            }
            catch
            {
                return false;
            }

            return false;
        }

        private bool IsTextInputFocused()
        {
            Control focusedControl = GetFocusedControl(this);
            if (focusedControl == null)
            {
                return false;
            }

            if (focusedControl is TextBoxBase || focusedControl is NumericUpDown)
            {
                return true;
            }

            if (focusedControl is ComboBox comboBox && comboBox.DropDownStyle != ComboBoxStyle.DropDownList)
            {
                return true;
            }

            return false;
        }

        private static Control GetFocusedControl(Control root)
        {
            Control current = root;

            while (current is ContainerControl container && container.ActiveControl != null)
            {
                current = container.ActiveControl;
            }

            return current;
        }


        private void PDFForm_KeyDown(object sender, KeyEventArgs e)
        {
            if (pdf == null)
            {
                return;
            }

            switch (e.KeyCode)
            {

                case Keys.PageUp:
                    // Handle PageUp key:
                    PreviousPage(); // Method that goes to previous page
                    e.Handled = true;  // Indicates that event was handled
                    break;

                case Keys.PageDown:
                    // Handle PageDown key:
                    NextPage(); // Method that goes to next page
                    e.Handled = true;
                    break;

                case Keys.Home:
                    if (searchTextBox.Focused)
                    {
                        break;
                    }
                    FirstPage();
                    e.Handled = true;
                    break;

                case Keys.End:
                    if (searchTextBox.Focused)
                    {
                        break;
                    }
                    LastPage();
                    e.Handled = true;
                    break;
            }
        }

        private void OpenLastPdfProjectToolStripMenuItem_Click(object sender, EventArgs e)
        {
            // Get saved paths from Properties.Settings
            string lastPdf = Properties.Settings.Default.LastPdfPath;
            string lastPap = Properties.Settings.Default.LastPapPath;
            bool hasPdf = !string.IsNullOrWhiteSpace(lastPdf) && File.Exists(lastPdf);
            bool hasProject = !string.IsNullOrWhiteSpace(lastPap) && File.Exists(lastPap);
            ResumeState resumeState = LoadResumeState();

            try
            {
                if (hasPdf)
                {
                    // Load PDF
                    inputPdfPath = lastPdf;
                    inputProjectPath = "";
                    lastSavedProjectName = "";
                    LoadPdf();
                    if (hasProject)
                    {
                        bool registerAsProject = !IsAutoResumeProjectPath(lastPap);
                        LoadRedactionBlocks(lastPap, registerAsProject: registerAsProject);
                    }
                    RestoreViewFromResumeStateIfMatches(resumeState);
                }
                else if (hasProject)
                {
                    bool registerAsProject = !IsAutoResumeProjectPath(lastPap);
                    LoadRedactionBlocks(lastPap, registerAsProject: registerAsProject);
                    RestoreViewFromResumeStateIfMatches(resumeState);
                }
                else
                {
                    MessageBox.Show(this, Resources.Msg_CannotLoadRecentFiles, Resources.Title_Warning, MessageBoxButtons.OK, MessageBoxIcon.Warning);
                }
            }
            catch (Exception ex)
            {
                    MessageBox.Show(this, string.Format(Resources.Err_LoadRecentFiles, ex.Message),
                        Resources.Title_Error, MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }

        private List<string> LoadRecentFiles()
        {
            string raw = Properties.Settings.Default.RecentFiles;
            if (string.IsNullOrWhiteSpace(raw))
            {
                return new List<string>();
            }

            try
            {
                var files = JsonConvert.DeserializeObject<List<string>>(raw);
                return files ?? new List<string>();
            }
            catch
            {
                return new List<string>();
            }
        }

        private void SaveRecentFiles(List<string> files)
        {
            Properties.Settings.Default.RecentFiles = JsonConvert.SerializeObject(files);
            Properties.Settings.Default.Save();
        }

        private void AddRecentFile(string filePath)
        {
            if (string.IsNullOrWhiteSpace(filePath))
            {
                return;
            }

            string ext = Path.GetExtension(filePath);
            if (!string.Equals(ext, ".pdf", StringComparison.OrdinalIgnoreCase) &&
                !string.Equals(ext, ProjectFileExtension, StringComparison.OrdinalIgnoreCase) &&
                !string.Equals(ext, LegacyProjectFileExtension, StringComparison.OrdinalIgnoreCase))
            {
                return;
            }

            string fullPath = Path.GetFullPath(filePath);
            var files = LoadRecentFiles();
            files.RemoveAll(path => string.Equals(path, fullPath, StringComparison.OrdinalIgnoreCase));
            files.Insert(0, fullPath);

            while (files.Count > RecentFilesLimit)
            {
                files.RemoveAt(files.Count - 1);
            }

            SaveRecentFiles(files);
            UpdateRecentFilesMenu();
        }

        private void RemoveRecentFile(string filePath)
        {
            if (string.IsNullOrWhiteSpace(filePath))
            {
                return;
            }

            var files = LoadRecentFiles();
            int removedCount = files.RemoveAll(path => string.Equals(path, filePath, StringComparison.OrdinalIgnoreCase));
            if (removedCount > 0)
            {
                SaveRecentFiles(files);
            }
        }

        private void UpdateRecentFilesMenu()
        {
            if (recentFilesMenuItem == null)
            {
                return;
            }

            var theme = CurrentTheme;
            recentFilesMenuItem.DropDownItems.Clear();

            var files = LoadRecentFiles();
            var uniqueFiles = new List<string>();
            var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            foreach (var path in files)
            {
                if (string.IsNullOrWhiteSpace(path))
                {
                    continue;
                }

                string ext = Path.GetExtension(path);
                if (!string.Equals(ext, ".pdf", StringComparison.OrdinalIgnoreCase) &&
                    !string.Equals(ext, ProjectFileExtension, StringComparison.OrdinalIgnoreCase) &&
                    !string.Equals(ext, LegacyProjectFileExtension, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                if (seen.Add(path))
                {
                    uniqueFiles.Add(path);
                }
            }

            if (uniqueFiles.Count == 0)
            {
                var emptyItem = new ToolStripMenuItem(Resources.Menu_RecentFiles_Empty);
                emptyItem.Enabled = false;
                emptyItem.ForeColor = theme.TextSecondaryColor;
                recentFilesMenuItem.DropDownItems.Add(emptyItem);
                recentFilesMenuItem.Enabled = false;
                return;
            }

            recentFilesMenuItem.Enabled = true;

            int count = Math.Min(uniqueFiles.Count, RecentFilesLimit);
            for (int i = 0; i < count; i++)
            {
                string path = uniqueFiles[i];
                string fileName = Path.GetFileName(path);
                var item = new ToolStripMenuItem($"{i + 1}. {fileName}");
                item.Tag = path;
                item.ToolTipText = path;
                item.AutoToolTip = true;
                if (!File.Exists(path))
                {
                    item.ForeColor = theme.TextSecondaryColor;
                }
                else
                {
                    item.ForeColor = theme.TextPrimaryColor;
                }
                item.Click += RecentFileMenuItem_Click;
                recentFilesMenuItem.DropDownItems.Add(item);
            }
        }

        private void RecentFilesMenuItem_DropDownOpening(object sender, EventArgs e)
        {
            UpdateRecentFilesMenu();
        }

        private void RecentFileMenuItem_Click(object sender, EventArgs e)
        {
            if (sender is ToolStripMenuItem menuItem && menuItem.Tag is string filePath)
            {
                OpenRecentFile(filePath);
            }
        }

        private void OpenRecentFile(string filePath)
        {
            if (string.IsNullOrWhiteSpace(filePath))
            {
                return;
            }

            if (!File.Exists(filePath))
            {
                MessageBox.Show(this, Resources.Msg_CannotLoadRecentFiles, Resources.Title_Warning, MessageBoxButtons.OK, MessageBoxIcon.Warning);
                RemoveRecentFile(filePath);
                UpdateRecentFilesMenu();
                return;
            }

            string ext = Path.GetExtension(filePath);
            if (string.Equals(ext, ".pdf", StringComparison.OrdinalIgnoreCase))
            {
                OpenPdfFromPath(filePath);
                return;
            }

            if (string.Equals(ext, ProjectFileExtension, StringComparison.OrdinalIgnoreCase) ||
                string.Equals(ext, LegacyProjectFileExtension, StringComparison.OrdinalIgnoreCase))
            {
                LoadRedactionBlocks(filePath);
            }
        }

