        private string DetectMainFilterForPage(iText.Kernel.Pdf.PdfPage page)
        {
            var resources = page.GetResources();
            if (resources == null)
                return null;

            // Get XObject dictionary
            var xObjects = resources.GetResource(PdfName.XObject);
            if (xObjects == null)
                return null; // no XObjects

            foreach (var xObjName in xObjects.KeySet())
            {
                // Read object's PdfStream
                var xObjStream = xObjects.GetAsStream(xObjName);
                if (xObjStream == null)
                    continue; // can be e.g. Form XObject

                // Check if this is an image at all
                var subtype = xObjStream.GetAsName(PdfName.Subtype);
                if (subtype == null || !subtype.Equals(PdfName.Image))
                    continue; // not Image (may be other XObject type)

                // Get filter (can be PdfName, PdfArray or none)
                var filterObj = xObjStream.Get(PdfName.Filter);
                if (filterObj == null)
                {
                    // No filter -> raw data (sometimes "RawData")
                    return null;
                }

                // If filter is single PdfName...
                if (filterObj.IsName())
                {
                    var singleFilterName = (PdfName)filterObj;
                    return singleFilterName.GetValue();
                    // e.g. "CCITTFaxDecode", "DCTDecode", "FlateDecode", "JBIG2Decode", etc.
                }
                // If filter is array (PdfArray) - in PDF there can be multiple filters
                else if (filterObj.IsArray())
                {
                    var arr = (PdfArray)filterObj;
                    if (arr.Size() > 0)
                    {
                        // Take first filter (or can iterate over all)
                        if (arr.Get(0) is PdfName firstFilter)
                        {
                            return firstFilter.GetValue();
                        }
                    }
                }
            }

            // If we didn't find any image or didn't detect filter:
            return null;
        }

        private RasterPageImageInfo GetPrimaryRasterInfoForPage(iText.Kernel.Pdf.PdfPage page)
        {
            if (page == null)
            {
                return null;
            }

            try
            {
                var pageSize = page.GetPageSize();
                var listener = new RasterImageInfoExtractionListener(pageSize.GetWidth(), pageSize.GetHeight());
                var processor = new PdfCanvasProcessor(listener);
                processor.ProcessPageContent(page);

                return listener.Images
                    .OrderByDescending(img => img.CoverageRatio)
                    .ThenByDescending(img => img.DisplayedWidthPoints * img.DisplayedHeightPoints)
                    .FirstOrDefault();
            }
            catch (Exception ex)
            {
                if (DebugLogEnabled)
                {
                    LogDebug("Raster preflight extraction failed: " + ex.Message);
                }

                return null;
            }
        }

        private static string ExtractFilterName(PdfObject filterObj)
        {
            if (filterObj == null)
            {
                return null;
            }

            if (filterObj.IsName())
            {
                return ((PdfName)filterObj).GetValue();
            }

            if (filterObj.IsArray())
            {
                var arr = (PdfArray)filterObj;
                if (arr.Size() > 0 && arr.Get(0) is PdfName firstFilter)
                {
                    return firstFilter.GetValue();
                }
            }

            return null;
        }

        public bool ReencodePdfKeepOriginalCompression(string inputPdf, string outputPdf, bool reduceFileSizeMode = false)
        {
            bool isReencoded = false;
            reencodedPages.Clear();

            var props = new ReaderProperties();
            if (!string.IsNullOrEmpty(userPassword))
            {
                props.SetPassword(System.Text.Encoding.UTF8.GetBytes(userPassword));
            }

            

            using (PdfReader reader = new PdfReader(inputPdf, props).SetUnethicalReading(Properties.Settings.Default.IgnorePdfRestrictions))
            using (iText.Kernel.Pdf.PdfDocument srcDoc = new iText.Kernel.Pdf.PdfDocument(reader))
            {
                int numberOfPages = srcDoc.GetNumberOfPages();

                // Check reencoding mode â€“ if disabled, return false.
                if (!isReencodingMode)
                    return false;

                // Get filter for each page
                List<string> pageFilters = new List<string>();
                List<RasterPageImageInfo> pagePrimaryImages = new List<RasterPageImageInfo>();
                for (int i = 1; i <= numberOfPages; i++)
                {
                    var page = srcDoc.GetPage(i);
                    RasterPageImageInfo primaryRaster = GetPrimaryRasterInfoForPage(page);
                    pagePrimaryImages.Add(primaryRaster);
                    pageFilters.Add(primaryRaster?.Filter ?? DetectMainFilterForPage(page));
                }

                // If any page doesn't have specified filter â€“ reencoding is not performed
                //if (!(pageFilters.Any(pf => pf != null) || openSavedPDFCheckBox.Checked))
                //    return false;

                // Load PDF with PDFiumSharp to render pages
                var pdfiumDoc = new PDFiumSharp.PdfDocument(inputPdf, userPassword);

                using (PdfWriter writer = new PdfWriter(outputPdf))
                using (iText.Kernel.Pdf.PdfDocument destDoc = new iText.Kernel.Pdf.PdfDocument(writer))
                {
                    for (int i = 0; i < numberOfPages; i++)
                    {
                        int pageNumber = i + 1;
                        RasterPageImageInfo primaryRaster = pagePrimaryImages[i];
                        bool hasRedactionOnPage = redactionBlocks.Any(b => b.PageNumber == pageNumber);
                        bool optimizationMode = reduceFileSizeMode;
                        bool pageHasImageFilter = primaryRaster != null || !string.IsNullOrWhiteSpace(pageFilters[i]);
                        bool pageHasText = false;
                        bool pageLooksLikeScan = false;

                        if (optimizationMode || hasRedactionOnPage)
                        {
                            string extractedText = iText.Kernel.Pdf.Canvas.Parser.PdfTextExtractor.GetTextFromPage(srcDoc.GetPage(pageNumber));
                            pageHasText = !string.IsNullOrWhiteSpace(extractedText);
                            pageLooksLikeScan = pageHasImageFilter && !pageHasText;
                        }

                        bool shouldOptimizePage = optimizationMode && pageLooksLikeScan;

                        // If there are no redactions and page is not a scan candidate, copy page unchanged.
                        if (!hasRedactionOnPage && !shouldOptimizePage)
                        {
                            srcDoc.CopyPagesTo(pageNumber, pageNumber, destDoc);
                            continue;
                        }

                        if (!(safeModeCheckBox.Checked || pdfCleanUpToolError) && !shouldOptimizePage)
                        {
                            // Check if there are text objects on page.
                            if (pageHasText)
                            {
                                srcDoc.CopyPagesTo(pageNumber, pageNumber, destDoc);
                                continue;
                            }

                            // Perform re-encoding only for pages encoded as "CCITTFaxDecode"
                            if (pageFilters[i] != "CCITTFaxDecode")
                            {
                                srcDoc.CopyPagesTo(pageNumber, pageNumber, destDoc);
                                continue;
                            }
                        }


                        // For pages meeting conditions perform reencoding.

                        isReencoded = true;
                        reencodedPages.Add(pageNumber);
                        // Load page from PDFiumSharp:
                        var pdfiumPage = pdfiumDoc.Pages[i];
                        double pageWidthPoints = pdfiumPage.Width;
                        double pageHeightPoints = pdfiumPage.Height;
                        if (DebugLogEnabled)
                        {
                            var srcPage = srcDoc.GetPage(pageNumber);
                            var size = srcPage.GetPageSize();
                            LogDebug($"Reencode page={pageNumber} filter={pageFilters[i] ?? "none"} rotate={srcPage.GetRotation()} itext={size.GetWidth()}x{size.GetHeight()} pdfium={pageWidthPoints}x{pageHeightPoints} safeMode={safeModeCheckBox.Checked} cleanupError={pdfCleanUpToolError}");
                        }

                        int dpi = reencodingDPI;
                        int bmpWidth = (int)(pageWidthPoints * dpi / 72.0);
                        int bmpHeight = (int)(pageHeightPoints * dpi / 72.0);
                        if (DebugLogEnabled)
                        {
                            LogDebug($"Reencode bitmap page={pageNumber} dpi={dpi} size={bmpWidth}x{bmpHeight}");
                        }

                        using (PDFiumBitmap pdfiumBmp = new PDFiumBitmap(bmpWidth, bmpHeight, true))
                        {
                            pdfiumBmp.FillRectangle(0, 0, bmpWidth, bmpHeight, 0xFFFFFFFF);
                            pdfiumPage.Render(renderTarget: pdfiumBmp, flags: PDFiumSharp.Enums.RenderingFlags.Annotations);

                            Bitmap bmp;
                            using (MemoryStream ms = new MemoryStream())
                            {
                                pdfiumBmp.Save(ms);
                                ms.Position = 0;
                                bmp = (Bitmap)System.Drawing.Image.FromStream(ms);
                            }

                            byte[] encodedBytes;
                            string selectedEncodingStrategy = null;
                            RasterOptimizationProfile optimizationProfile = null;
                            if (shouldOptimizePage)
                            {
                                optimizationProfile = BuildRasterOptimizationProfile(
                                    bmp,
                                    primaryRaster,
                                    pageFilters[i],
                                    pageNumber,
                                    dpi,
                                    dpi,
                                    bmpWidth,
                                    bmpHeight,
                                    pageWidthPoints,
                                    pageHeightPoints);
                                encodedBytes = EncodeBestForScannedPage(bmp, optimizationProfile, out selectedEncodingStrategy);
                            }
                            else
                            {
                                // For "CCITTFaxDecode" perform reencoding using TIFF G4.
                                if (pageFilters[i] == "CCITTFaxDecode")
                                {
                                    using (var oneBit = ConvertTo1Bit(bmp, 128))
                                    {
                                        encodedBytes = EncodeToTiffG4(oneBit);
                                    }
                                }
                                else if (pageFilters[i] == "FlateDecode")
                                {
                                    encodedBytes = EncodeToPng(bmp);
                                }
                                else
                                {
                                    encodedBytes = EncodeToJpeg(bmp, quality: 90L);
                                }
                            }

                            if (DebugLogEnabled && shouldOptimizePage)
                            {
                                LogDebug(
                                    $"Reencode profile page={pageNumber} filter={optimizationProfile?.OriginalFilter ?? "none"} " +
                                    $"gray={optimizationProfile?.GrayscaleRatio.ToString("F3", CultureInfo.InvariantCulture) ?? "-"} " +
                                    $"nearGray={optimizationProfile?.NearGrayscaleRatio.ToString("F3", CultureInfo.InvariantCulture) ?? "-"} " +
                                    $"bw={optimizationProfile?.BilevelRatio.ToString("F3", CultureInfo.InvariantCulture) ?? "-"} " +
                                    $"buckets={optimizationProfile?.LuminanceBucketCount.ToString(CultureInfo.InvariantCulture) ?? "-"} " +
                                    $"textScore={optimizationProfile?.TextLikeScore.ToString("F3", CultureInfo.InvariantCulture) ?? "-"} " +
                                    $"photoScore={optimizationProfile?.PhotoLikeScore.ToString("F3", CultureInfo.InvariantCulture) ?? "-"} " +
                                    $"textLike={optimizationProfile?.LooksTextLike.ToString() ?? "-"} " +
                                    $"photoLike={optimizationProfile?.LooksPhotoLike.ToString() ?? "-"} " +
                                    $"fullPage={optimizationProfile?.IsFullPageImage.ToString() ?? "-"} " +
                                    $"downsample={DescribeDownsampleRecommendation(optimizationProfile)} " +
                                    $"workingDpi={optimizationProfile?.WorkingDpiX.ToString("F1", CultureInfo.InvariantCulture) ?? "-"}/{optimizationProfile?.WorkingDpiY.ToString("F1", CultureInfo.InvariantCulture) ?? "-"} " +
                                    $"dpi={optimizationProfile?.EffectiveDpiX.ToString("F1", CultureInfo.InvariantCulture) ?? "-"}/{optimizationProfile?.EffectiveDpiY.ToString("F1", CultureInfo.InvariantCulture) ?? "-"} " +
                                    $"px={optimizationProfile?.WidthPx.ToString(CultureInfo.InvariantCulture) ?? "-"}x{optimizationProfile?.HeightPx.ToString(CultureInfo.InvariantCulture) ?? "-"}");
                                LogDebug($"Reencode optimize page={pageNumber} strategy={selectedEncodingStrategy ?? "default"} bytes={encodedBytes.Length}");
                            }

                            bmp.Dispose();

                            var pageSize = new iText.Kernel.Geom.PageSize((float)pageWidthPoints, (float)pageHeightPoints);
                            var newPage = destDoc.AddNewPage(pageSize);
                            var pdfCanvas = new iText.Kernel.Pdf.Canvas.PdfCanvas(newPage);
                            using (var layoutCanvas = new iText.Layout.Canvas(pdfCanvas, pageSize))
                            {
                                var imgData = iText.IO.Image.ImageDataFactory.Create(encodedBytes);
                                var image = new iText.Layout.Element.Image(imgData)
                                    .ScaleAbsolute((float)pageWidthPoints, (float)pageHeightPoints)
                                    .SetFixedPosition(0, 0);
                                layoutCanvas.Add(image);
                            }
                        }
                    }
                }

                if (reduceFileSizeMode && isReencoded)
                {
                    long originalSize = new FileInfo(inputPdf).Length;
                    long optimizedSize = File.Exists(outputPdf) ? new FileInfo(outputPdf).Length : long.MaxValue;
                    if (optimizedSize >= originalSize)
                    {
                        if (DebugLogEnabled)
                        {
                            LogDebug($"Reencode skipped (no size gain): input={originalSize} output={optimizedSize}");
                        }

                        reencodedPages.Clear();
                        return false;
                    }
                }

                return isReencoded;
            }
        }

        private RasterOptimizationProfile BuildRasterOptimizationProfile(
            Bitmap bmp,
            RasterPageImageInfo primaryRaster,
            string originalFilter,
            int pageNumber,
            int sourceDpiX,
            int sourceDpiY,
            int widthPx,
            int heightPx,
            double renderedWidthPoints,
            double renderedHeightPoints)
        {
            var profile = AnalyzeBitmapForOptimization(bmp);
            profile.PageNumber = pageNumber;
            profile.OriginalFilter = originalFilter;
            profile.SourceDpiX = sourceDpiX;
            profile.SourceDpiY = sourceDpiY;
            profile.WorkingDpiX = sourceDpiX;
            profile.WorkingDpiY = sourceDpiY;
            profile.WidthPx = primaryRaster?.PixelWidth ?? widthPx;
            profile.HeightPx = primaryRaster?.PixelHeight ?? heightPx;
            profile.RenderedWidthPoints = renderedWidthPoints;
            profile.RenderedHeightPoints = renderedHeightPoints;
            double displayedWidthPoints = primaryRaster?.DisplayedWidthPoints > 0d ? primaryRaster.DisplayedWidthPoints : renderedWidthPoints;
            double displayedHeightPoints = primaryRaster?.DisplayedHeightPoints > 0d ? primaryRaster.DisplayedHeightPoints : renderedHeightPoints;
            profile.EffectiveDpiX = displayedWidthPoints > 0.0 ? profile.WidthPx / (displayedWidthPoints / 72.0) : sourceDpiX;
            profile.EffectiveDpiY = displayedHeightPoints > 0.0 ? profile.HeightPx / (displayedHeightPoints / 72.0) : sourceDpiY;
            profile.IsFullPageImage = primaryRaster == null || primaryRaster.CoverageRatio >= 0.85d;
            return profile;
        }

        private byte[] EncodeBestForScannedPage(Bitmap bmp, RasterOptimizationProfile profile, out string selectedStrategy)
        {
            if (profile == null)
            {
                selectedStrategy = "jpeg-color-q90-fallback";
                return EncodeToJpeg(bmp, quality: 90L);
            }

            var candidates = new List<(RasterEncodingCandidate Candidate, byte[] Data)>();
            foreach (var candidate in BuildRasterEncodingCandidates(profile))
            {
                try
                {
                    byte[] data = EncodeRasterWithStrategy(bmp, profile, candidate);
                    if (data == null || data.Length == 0)
                    {
                        continue;
                    }

                    candidates.Add((candidate, data));

                    if (DebugLogEnabled && candidate.Strategy == RasterEncodingStrategy.PngGray2)
                    {
                        try
                        {
                            string previewPath = Path.Combine(Path.GetTempPath(), $"anonpdfpro_preview_p{profile.PageNumber}_gray2.png");
                            File.WriteAllBytes(previewPath, data);
                            LogDebug($"Reencode preview saved strategy={candidate.Label} page={profile.PageNumber} path={previewPath}");
                        }
                        catch (Exception ex)
                        {
                            LogDebug($"Reencode preview save failed strategy={candidate.Label} page={profile.PageNumber}: {ex.Message}");
                        }
                    }
                }
                catch (Exception ex)
                {
                    if (DebugLogEnabled)
                    {
                        LogDebug($"Reencode candidate failed strategy={candidate.Label}: {ex.Message}");
                    }
                }
            }

            if (candidates.Count == 0)
            {
                const string fallbackLabel = "jpeg-color-q90-fallback";
                selectedStrategy = fallbackLabel;
                return EncodeRasterWithStrategy(
                    bmp,
                    profile,
                    CreateRasterEncodingCandidate(RasterEncodingStrategy.JpegColor90Fallback));
            }

            if (DebugLogEnabled)
            {
                foreach (var candidate in candidates)
                {
                    LogDebug($"Reencode candidate strategy={candidate.Candidate.Label} bytes={candidate.Data.Length}");
                }
            }

            var best = candidates.OrderBy(c => c.Data.Length).First();
            selectedStrategy =
                $"{best.Candidate.Label};gray={profile.GrayscaleRatio.ToString("F3", CultureInfo.InvariantCulture)};" +
                $"bw={profile.BilevelRatio.ToString("F3", CultureInfo.InvariantCulture)};" +
                $"text={profile.TextLikeScore.ToString("F3", CultureInfo.InvariantCulture)};" +
                $"photo={profile.PhotoLikeScore.ToString("F3", CultureInfo.InvariantCulture)}";
            return best.Data;
        }

        private IEnumerable<RasterEncodingCandidate> BuildRasterEncodingCandidates(RasterOptimizationProfile profile)
        {
            if (profile == null)
            {
                yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.JpegColor90Fallback);
                yield break;
            }

            bool mostlyGrayscale = IsMostlyGrayscaleRaster(profile);
            bool bilevelCandidate = profile.BilevelRatio >= 0.995;
            bool preferPhotoStrategies = profile.LooksPhotoLike && !profile.LooksTextLike;
            bool allowTextDownsample = IsTextDownsampleCandidate(profile);
            bool preferTextStrategies = (profile.LooksTextLike || allowTextDownsample) && !profile.LooksPhotoLike;
            bool allowPhotoDownsample = profile.LooksPhotoLike &&
                Math.Max(profile.EffectiveDpiX, profile.EffectiveDpiY) > RasterDownsamplePhotoThresholdDpi;

            if (bilevelCandidate || string.Equals(profile.OriginalFilter, "CCITTFaxDecode", StringComparison.OrdinalIgnoreCase))
            {
                yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.TiffG4);
            }

            if (mostlyGrayscale && !preferPhotoStrategies)
            {
                if (allowTextDownsample)
                {
                    yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.PngGray2, RasterDownsampleTextTargetDpi);
                    yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.PngGray4, RasterDownsampleTextTargetDpi);
                    yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.PngGray8, RasterDownsampleTextTargetDpi);
                    yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.JpegGray72, RasterDownsampleTextTargetDpi);
                    yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.JpegGray78, RasterDownsampleTextTargetDpi);
                }

                yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.PngGray2);
                yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.PngGray4);
                yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.PngGray8);
                yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.JpegGray72);
                yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.JpegGray78);
            }

            if (!preferTextStrategies)
            {
                if (allowPhotoDownsample)
                {
                    yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.JpegColor76, RasterDownsamplePhotoTargetDpi);
                    yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.JpegColor82, RasterDownsamplePhotoTargetDpi);
                }

                yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.JpegColor76);
                yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.JpegColor82);
            }
            else
            {
                if (allowTextDownsample && !mostlyGrayscale)
                {
                    yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.JpegColor82, RasterDownsampleTextTargetDpi);
                }

                yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.JpegColor82);
            }

            if (string.Equals(profile.OriginalFilter, "FlateDecode", StringComparison.OrdinalIgnoreCase))
            {
                yield return CreateRasterEncodingCandidate(RasterEncodingStrategy.PngLossless);
            }
        }

        private RasterEncodingCandidate CreateRasterEncodingCandidate(RasterEncodingStrategy strategy, int? targetDpi = null)
        {
            string strategyLabel = GetRasterEncodingStrategyLabel(strategy);
            return new RasterEncodingCandidate
            {
                Strategy = strategy,
                TargetDpi = targetDpi,
                Label = targetDpi.HasValue ? $"{strategyLabel}@{targetDpi.Value}dpi" : strategyLabel
            };
        }

        private static string GetRasterEncodingStrategyLabel(RasterEncodingStrategy strategy)
        {
            switch (strategy)
            {
                case RasterEncodingStrategy.TiffG4:
                    return "tiff-g4";
                case RasterEncodingStrategy.PngGray2:
                    return "png-gray2";
                case RasterEncodingStrategy.PngGray4:
                    return "png-gray4";
                case RasterEncodingStrategy.PngGray8:
                    return "png-gray8";
                case RasterEncodingStrategy.JpegGray72:
                    return "jpeg-gray-q72";
                case RasterEncodingStrategy.JpegGray78:
                    return "jpeg-gray-q78";
                case RasterEncodingStrategy.JpegColor76:
                    return "jpeg-color-q76";
                case RasterEncodingStrategy.JpegColor82:
                    return "jpeg-color-q82";
                case RasterEncodingStrategy.PngLossless:
                    return "png";
                default:
                    return "jpeg-color-q90-fallback";
            }
        }

        private byte[] EncodeRasterWithStrategy(Bitmap bmp, RasterOptimizationProfile profile, RasterEncodingCandidate candidate)
        {
            Bitmap sourceBitmap = bmp;
            Bitmap downsampledBitmap = null;

            try
            {
                if (candidate?.TargetDpi is int targetDpi)
                {
                    downsampledBitmap = DownsampleBitmapForTargetDpi(sourceBitmap, profile, targetDpi, candidate.Label);
                    if (downsampledBitmap != null)
                    {
                        sourceBitmap = downsampledBitmap;
                    }
                }

                switch (candidate?.Strategy ?? RasterEncodingStrategy.JpegColor90Fallback)
                {
                    case RasterEncodingStrategy.TiffG4:
                        using (var oneBit = ConvertTo1Bit(sourceBitmap, 170))
                        {
                            return EncodeToTiffG4(oneBit);
                        }

                    case RasterEncodingStrategy.PngGray2:
                        using (var gray2 = ConvertToGrayscale2(sourceBitmap))
                        {
                            return EncodeToPng(gray2);
                        }

                    case RasterEncodingStrategy.PngGray4:
                        using (var gray4 = ConvertToGrayscale4(sourceBitmap))
                        {
                            return EncodeToPng(gray4);
                        }

                    case RasterEncodingStrategy.PngGray8:
                        using (var gray8 = ConvertToGrayscale8(sourceBitmap))
                        {
                            return EncodeToPng(gray8);
                        }

                    case RasterEncodingStrategy.JpegGray72:
                        return EncodeToJpegGrayscale(sourceBitmap, quality: 72L);

                    case RasterEncodingStrategy.JpegGray78:
                        return EncodeToJpegGrayscale(sourceBitmap, quality: 78L);

                    case RasterEncodingStrategy.JpegColor76:
                        return EncodeToJpeg(sourceBitmap, quality: 76L);

                    case RasterEncodingStrategy.JpegColor82:
                        return EncodeToJpeg(sourceBitmap, quality: 82L);

                    case RasterEncodingStrategy.PngLossless:
                        return EncodeToPng(sourceBitmap);

                    default:
                        return EncodeToJpeg(sourceBitmap, quality: 90L);
                }
            }
            finally
            {
                downsampledBitmap?.Dispose();
            }
        }

        private RasterOptimizationProfile AnalyzeBitmapForOptimization(Bitmap bmp)
        {
            var profile = new RasterOptimizationProfile();

            if (bmp == null || bmp.Width <= 0 || bmp.Height <= 0)
            {
                return profile;
            }

            int width = bmp.Width;
            int height = bmp.Height;
            int stepX = Math.Max(1, width / 600);
            int stepY = Math.Max(1, height / 600);

            DrawingRectangle rect = new DrawingRectangle(0, 0, width, height);
            BitmapData bmpData = null;

            try
            {
                bmpData = bmp.LockBits(rect, ImageLockMode.ReadOnly, bmp.PixelFormat);
                int bpp = Math.Max(1, DrawingImage.GetPixelFormatSize(bmp.PixelFormat) / 8);
                int strideAbs = Math.Abs(bmpData.Stride);
                int totalRows = height;
                byte[] buffer = new byte[strideAbs * totalRows];
                System.Runtime.InteropServices.Marshal.Copy(bmpData.Scan0, buffer, 0, buffer.Length);

                int total = 0;
                int grayLike = 0;
                int nearGrayLike = 0;
                int bilevelLike = 0;
                int horizontalEdgeCount = 0;
                int verticalEdgeCount = 0;
                int highVarianceCount = 0;
                var luminanceBuckets = new HashSet<int>();

                for (int y = 0; y < height; y += stepY)
                {
                    int sourceY = bmpData.Stride < 0 ? (height - 1 - y) : y;
                    int rowStart = sourceY * strideAbs;
                    for (int x = 0; x < width; x += stepX)
                    {
                        int idx = rowStart + x * bpp;
                        if (idx + 2 >= buffer.Length)
                        {
                            continue;
                        }

                        byte b = buffer[idx];
                        byte g = buffer[idx + 1];
                        byte r = buffer[idx + 2];

                        int rgDiff = Math.Abs(r - g);
                        int gbDiff = Math.Abs(g - b);
                        int rbDiff = Math.Abs(r - b);

                        if (rgDiff <= 8 && gbDiff <= 8 && rbDiff <= 8)
                        {
                            grayLike++;
                        }

                        if (rgDiff <= 28 && gbDiff <= 28 && rbDiff <= 28)
                        {
                            nearGrayLike++;
                        }

                        int luminance = (299 * r + 587 * g + 114 * b) / 1000;
                        luminanceBuckets.Add(luminance / 16);
                        if (luminance <= 20 || luminance >= 235)
                        {
                            bilevelLike++;
                        }

                        if (x + stepX < width)
                        {
                            int idxRight = rowStart + (x + stepX) * bpp;
                            if (idxRight + 2 < buffer.Length)
                            {
                                int lumRight = (299 * buffer[idxRight + 2] + 587 * buffer[idxRight + 1] + 114 * buffer[idxRight]) / 1000;
                                if (Math.Abs(luminance - lumRight) >= 28)
                                {
                                    verticalEdgeCount++;
                                }
                            }
                        }

                        if (y + stepY < height)
                        {
                            int nextSourceY = bmpData.Stride < 0 ? (height - 1 - (y + stepY)) : (y + stepY);
                            int idxDown = nextSourceY * strideAbs + x * bpp;
                            if (idxDown + 2 < buffer.Length)
                            {
                                int lumDown = (299 * buffer[idxDown + 2] + 587 * buffer[idxDown + 1] + 114 * buffer[idxDown]) / 1000;
                                if (Math.Abs(luminance - lumDown) >= 28)
                                {
                                    horizontalEdgeCount++;
                                }
                            }
                        }

                        if (luminance > 32 && luminance < 223)
                        {
                            highVarianceCount++;
                        }

                        total++;
                    }
                }

                if (total > 0)
                {
                    profile.GrayscaleRatio = (double)grayLike / total;
                    profile.NearGrayscaleRatio = (double)nearGrayLike / total;
                    profile.BilevelRatio = (double)bilevelLike / total;
                    profile.LuminanceBucketCount = luminanceBuckets.Count;

                    double horizontalEdgeRatio = (double)horizontalEdgeCount / total;
                    double verticalEdgeRatio = (double)verticalEdgeCount / total;
                    double edgeRatio = horizontalEdgeRatio + verticalEdgeRatio;
                    double midToneRatio = (double)highVarianceCount / total;
                    profile.TextLikeScore = Clamp01(
                        (profile.BilevelRatio * 0.45) +
                        ((horizontalEdgeRatio + verticalEdgeRatio) * 1.35) +
                        ((profile.LuminanceBucketCount <= 6 ? 1.0 : 0.0) * 0.25) -
                        (midToneRatio * 0.30));
                    profile.PhotoLikeScore = Clamp01(
                        (midToneRatio * 0.70) +
                        ((profile.LuminanceBucketCount / 16.0) * 0.35) +
                        (edgeRatio * 0.10) -
                        (profile.BilevelRatio * 0.30));
                    profile.LooksTextLike = profile.TextLikeScore >= 0.55;
                    profile.LooksPhotoLike = profile.PhotoLikeScore >= 0.55 && profile.PhotoLikeScore > profile.TextLikeScore;
                }
            }
            finally
            {
                if (bmpData != null)
                {
                    bmp.UnlockBits(bmpData);
                }
            }

            return profile;
        }

        private Bitmap DownsampleBitmapForTargetDpi(Bitmap sourceBitmap, RasterOptimizationProfile profile, int targetDpi, string candidateLabel)
        {
            if (sourceBitmap == null || profile == null || targetDpi <= 0)
            {
                return null;
            }

            double workingDpiX = profile.WorkingDpiX > 0d ? profile.WorkingDpiX : profile.SourceDpiX;
            double workingDpiY = profile.WorkingDpiY > 0d ? profile.WorkingDpiY : profile.SourceDpiY;
            if (workingDpiX <= 0d || workingDpiY <= 0d)
            {
                return null;
            }

            double scaleX = targetDpi / workingDpiX;
            double scaleY = targetDpi / workingDpiY;
            double scale = Math.Min(scaleX, scaleY);
            if (scale >= 0.995d)
            {
                return null;
            }

            int targetWidth = Math.Max(1, (int)Math.Round(sourceBitmap.Width * scale));
            int targetHeight = Math.Max(1, (int)Math.Round(sourceBitmap.Height * scale));
            if (targetWidth >= sourceBitmap.Width || targetHeight >= sourceBitmap.Height)
            {
                return null;
            }

            if (DebugLogEnabled)
            {
                LogDebug(
                    $"Reencode downsample page={profile.PageNumber} strategy={candidateLabel} " +
                    $"fromDpi={workingDpiX.ToString("F1", CultureInfo.InvariantCulture)}/{workingDpiY.ToString("F1", CultureInfo.InvariantCulture)} " +
                    $"toDpi={targetDpi} fromPx={sourceBitmap.Width}x{sourceBitmap.Height} toPx={targetWidth}x{targetHeight}");
            }

            return ResizeBitmapHighQuality(sourceBitmap, targetWidth, targetHeight, targetDpi);
        }

        private string DescribeDownsampleRecommendation(RasterOptimizationProfile profile)
        {
            if (profile == null)
            {
                return "none";
            }

            var recommendations = new List<string>();
            if (IsTextDownsampleCandidate(profile))
            {
                recommendations.Add($"text->{RasterDownsampleTextTargetDpi}");
            }

            double workingDpi = Math.Max(
                profile.WorkingDpiX > 0d ? profile.WorkingDpiX : profile.SourceDpiX,
                profile.WorkingDpiY > 0d ? profile.WorkingDpiY : profile.SourceDpiY);
            if (profile.LooksPhotoLike &&
                Math.Max(profile.EffectiveDpiX, profile.EffectiveDpiY) > RasterDownsamplePhotoThresholdDpi &&
                workingDpi > RasterDownsamplePhotoTargetDpi)
            {
                recommendations.Add($"photo->{RasterDownsamplePhotoTargetDpi}");
            }

            return recommendations.Count == 0 ? "none" : string.Join(",", recommendations);
        }

        private bool IsMostlyGrayscaleRaster(RasterOptimizationProfile profile)
        {
            return profile != null && (profile.GrayscaleRatio >= 0.985 || profile.NearGrayscaleRatio >= 0.96);
        }

        private bool IsTextDownsampleCandidate(RasterOptimizationProfile profile)
        {
            if (profile == null)
            {
                return false;
            }

            double workingDpi = Math.Max(
                profile.WorkingDpiX > 0d ? profile.WorkingDpiX : profile.SourceDpiX,
                profile.WorkingDpiY > 0d ? profile.WorkingDpiY : profile.SourceDpiY);
            if (workingDpi <= RasterDownsampleTextTargetDpi)
            {
                return false;
            }

            double effectiveDpi = Math.Max(profile.EffectiveDpiX, profile.EffectiveDpiY);
            if (effectiveDpi <= RasterDownsampleTextThresholdDpi)
            {
                return false;
            }

            if (!profile.IsFullPageImage || profile.PhotoLikeScore >= 0.15 || profile.BilevelRatio < 0.97)
            {
                return false;
            }

            return profile.LooksTextLike || profile.TextLikeScore >= 0.45 || IsMostlyGrayscaleRaster(profile);
        }

        private Bitmap ResizeBitmapHighQuality(Bitmap sourceBitmap, int targetWidth, int targetHeight, int targetDpi)
        {
            var resized = new Bitmap(targetWidth, targetHeight, PixelFormat.Format24bppRgb);
            resized.SetResolution(targetDpi, targetDpi);

            using (Graphics g = Graphics.FromImage(resized))
            {
                g.Clear(System.Drawing.Color.White);
                g.CompositingMode = CompositingMode.SourceCopy;
                g.CompositingQuality = CompositingQuality.HighQuality;
                g.InterpolationMode = InterpolationMode.HighQualityBicubic;
                g.SmoothingMode = SmoothingMode.HighQuality;
                g.PixelOffsetMode = PixelOffsetMode.HighQuality;
                g.DrawImage(
                    sourceBitmap,
                    new DrawingRectangle(0, 0, targetWidth, targetHeight),
                    new DrawingRectangle(0, 0, sourceBitmap.Width, sourceBitmap.Height),
                    GraphicsUnit.Pixel);
            }

            return resized;
        }

        private static double Clamp01(double value)
        {
            if (value < 0d)
            {
                return 0d;
            }

            if (value > 1d)
            {
                return 1d;
            }

            return value;
        }

        private void FocusDocumentViewport()
        {
            ZoomPanel panel = GetZoomPanel();
            if (panel != null && panel.CanFocus && !panel.Focused)
            {
                panel.Focus();
            }
        }

        private bool IsViewportPanningActive()
        {
            return isMiddleMousePanning || isRightMousePanning;
        }

        private bool IsDocumentViewportFocused()
        {
            ZoomPanel panel = GetZoomPanel();
            if (panel == null)
            {
                return false;
            }

            if (panel.Focused || ReferenceEquals(this.ActiveControl, panel))
            {
                return true;
            }

            Control focusedControl = GetFocusedControl(this);
            while (focusedControl != null)
            {
                if (ReferenceEquals(focusedControl, panel) || ReferenceEquals(focusedControl, pdfViewer))
                {
                    return true;
                }

                focusedControl = focusedControl.Parent;
            }

            return false;
        }

        private bool TryPanDocumentViewport(Keys keyData)
        {
            if (!IsDocumentViewportFocused())
            {
                return false;
            }

            ZoomPanel panel = GetZoomPanel();
            if (panel == null)
            {
                return false;
            }

            Keys keyCode = keyData & Keys.KeyCode;
            bool horizontal = keyCode == Keys.Left || keyCode == Keys.Right;
            bool vertical = keyCode == Keys.Up || keyCode == Keys.Down;
            if (!horizontal && !vertical)
            {
                return false;
            }

            bool canPanX = panel.HorizontalScroll.Visible && GetScrollMaximum(panel.HorizontalScroll) > panel.HorizontalScroll.Minimum;
            bool canPanY = panel.VerticalScroll.Visible && GetScrollMaximum(panel.VerticalScroll) > panel.VerticalScroll.Minimum;

            if ((horizontal && !canPanX) || (vertical && !canPanY))
            {
                return false;
            }

            int step = (keyData & Keys.Shift) == Keys.Shift ? KeyboardViewportPanStep * 3 : KeyboardViewportPanStep;
            int targetX = panel.HorizontalScroll.Value;
            int targetY = panel.VerticalScroll.Value;

            switch (keyCode)
            {
                case Keys.Left:
                    targetX -= step;
                    break;
                case Keys.Right:
                    targetX += step;
                    break;
                case Keys.Up:
                    targetY -= step;
                    break;
                case Keys.Down:
                    targetY += step;
                    break;
            }

            targetX = ClampScrollValue(targetX, panel.HorizontalScroll.Minimum, GetScrollMaximum(panel.HorizontalScroll));
            targetY = ClampScrollValue(targetY, panel.VerticalScroll.Minimum, GetScrollMaximum(panel.VerticalScroll));
            panel.AutoScrollPosition = new Point(targetX, targetY);
            return true;
        }

        private bool IsPointOverInteractiveDocumentContent(Point location)
        {
            if (pdf == null || currentPage <= 0 || currentPage > numPages)
            {
                return false;
            }

            if (TryGetCommentAtPoint(location, out _, out _))
            {
                return true;
            }

            float dpiX;
            float dpiY;
            using (Graphics graphics = pdfViewer.CreateGraphics())
            {
                dpiX = graphics.DpiX;
                dpiY = graphics.DpiY;
            }

            if (TryGetHitTextAtPoint(location, dpiX, dpiY, out _) ||
                TryGetHitRasterAtPoint(location, out _) ||
                TryGetHitArrowAtPoint(location, out _) ||
                TryGetHitVectorShapeAtPoint(location, out _))
            {
                return true;
            }

            if (selectedVectorShape != null && selectedVectorShape.PageNumber == currentPage)
            {
                if (TryGetVectorHandleAtPoint(selectedVectorShape, location, out _) ||
                    TryGetVectorSegmentAtPoint(selectedVectorShape, location, out _))
                {
                    return true;
                }
            }

            if (TryUpdateGroupHoverCursor(location, dpiX, dpiY))
            {
                return true;
            }

            float docX = location.X / scaleFactor;
            float docY = location.Y / scaleFactor;
            return redactionBlocks.Any(block => block != null && block.PageNumber == currentPage && block.Bounds.Contains(docX, docY));
        }


        private Bitmap ConvertTo1Bit(Bitmap img, byte threshold)
        {
            int width = img.Width;
            int height = img.Height;

            // Create 1-bit image
            Bitmap bmp = new Bitmap(width, height, PixelFormat.Format1bppIndexed);
            bmp.SetResolution(img.HorizontalResolution, img.VerticalResolution);

            // Lock bits of the original image
            DrawingRectangle rect = new DrawingRectangle(0, 0, width, height);
            BitmapData imgData = img.LockBits(rect, ImageLockMode.ReadOnly, img.PixelFormat);
            BitmapData bmpData = bmp.LockBits(rect, ImageLockMode.WriteOnly, bmp.PixelFormat);

            int imgBytesPerPixel = DrawingImage.GetPixelFormatSize(img.PixelFormat) / 8;
            int imgStride = imgData.Stride;
            int bmpStride = bmpData.Stride;

            byte[] imgBuffer = new byte[imgStride * height];
            byte[] bmpBuffer = new byte[bmpStride * height];

            // Copy image data into buffer
            System.Runtime.InteropServices.Marshal.Copy(imgData.Scan0, imgBuffer, 0, imgBuffer.Length);

            for (int y = 0; y < height; y++)
            {
                int imgRow = y * imgStride;
                int bmpRow = y * bmpStride;

                for (int x = 0; x < width; x++)
                {
                    int imgIndex = imgRow + x * imgBytesPerPixel;

                    // Get pixel brightness (conversion to grayscale)
                    byte brightness = (byte)(0.299 * imgBuffer[imgIndex + 2] + 0.587 * imgBuffer[imgIndex + 1] + 0.114 * imgBuffer[imgIndex]);

                    // Reverse condition
                    if (brightness < threshold)
                    {
                    // Dark pixel â€” set to white (default is white, so we do nothing)
                    }
                    else
                    {
                        // Bright pixel â€” set to black
                        bmpBuffer[bmpRow + x / 8] |= (byte)(0x80 >> (x % 8));
                    }
                }
            }

            // Copy buffer data back to image
            System.Runtime.InteropServices.Marshal.Copy(bmpBuffer, 0, bmpData.Scan0, bmpBuffer.Length);

            img.UnlockBits(imgData);
            bmp.UnlockBits(bmpData);

            return bmp;
        }

        private Bitmap ConvertToGrayscale8(Bitmap img)
        {
            int width = img.Width;
            int height = img.Height;

            Bitmap gray = new Bitmap(width, height, PixelFormat.Format8bppIndexed);
            gray.SetResolution(img.HorizontalResolution, img.VerticalResolution);

            ColorPalette palette = gray.Palette;
            for (int i = 0; i < 256; i++)
            {
                palette.Entries[i] = System.Drawing.Color.FromArgb(i, i, i);
            }
            gray.Palette = palette;

            DrawingRectangle rect = new DrawingRectangle(0, 0, width, height);
            BitmapData srcData = img.LockBits(rect, ImageLockMode.ReadOnly, img.PixelFormat);
            BitmapData dstData = gray.LockBits(rect, ImageLockMode.WriteOnly, PixelFormat.Format8bppIndexed);

            try
            {
                int srcBpp = Math.Max(1, DrawingImage.GetPixelFormatSize(img.PixelFormat) / 8);
                int srcStrideAbs = Math.Abs(srcData.Stride);
                int dstStrideAbs = Math.Abs(dstData.Stride);

                byte[] srcBuffer = new byte[srcStrideAbs * height];
                byte[] dstBuffer = new byte[dstStrideAbs * height];

                System.Runtime.InteropServices.Marshal.Copy(srcData.Scan0, srcBuffer, 0, srcBuffer.Length);

                for (int y = 0; y < height; y++)
                {
                    int srcY = srcData.Stride < 0 ? (height - 1 - y) : y;
                    int dstY = dstData.Stride < 0 ? (height - 1 - y) : y;
                    int srcRow = srcY * srcStrideAbs;
                    int dstRow = dstY * dstStrideAbs;

                    for (int x = 0; x < width; x++)
                    {
                        int srcIndex = srcRow + x * srcBpp;
                        if (srcIndex + 2 >= srcBuffer.Length)
                        {
                            continue;
                        }

                        byte b = srcBuffer[srcIndex];
                        byte g = srcBuffer[srcIndex + 1];
                        byte r = srcBuffer[srcIndex + 2];
                        byte luminance = (byte)((299 * r + 587 * g + 114 * b) / 1000);
                        dstBuffer[dstRow + x] = luminance;
                    }
                }

                System.Runtime.InteropServices.Marshal.Copy(dstBuffer, 0, dstData.Scan0, dstBuffer.Length);
            }
            finally
            {
                img.UnlockBits(srcData);
                gray.UnlockBits(dstData);
            }

            return gray;
        }

        private Bitmap ConvertToGrayscale2(Bitmap img)
        {
            int width = img.Width;
            int height = img.Height;

            Bitmap gray = new Bitmap(width, height, PixelFormat.Format4bppIndexed);
            gray.SetResolution(img.HorizontalResolution, img.VerticalResolution);

            ColorPalette palette = gray.Palette;
            palette.Entries[0] = System.Drawing.Color.FromArgb(0, 0, 0);
            palette.Entries[1] = System.Drawing.Color.FromArgb(85, 85, 85);
            palette.Entries[2] = System.Drawing.Color.FromArgb(170, 170, 170);
            palette.Entries[3] = System.Drawing.Color.FromArgb(255, 255, 255);
            for (int i = 4; i < palette.Entries.Length; i++)
            {
                palette.Entries[i] = System.Drawing.Color.FromArgb(255, 255, 255);
            }
            gray.Palette = palette;

            DrawingRectangle rect = new DrawingRectangle(0, 0, width, height);
            BitmapData srcData = img.LockBits(rect, ImageLockMode.ReadOnly, img.PixelFormat);
            BitmapData dstData = gray.LockBits(rect, ImageLockMode.WriteOnly, PixelFormat.Format4bppIndexed);

            try
            {
                int srcBpp = Math.Max(1, DrawingImage.GetPixelFormatSize(img.PixelFormat) / 8);
                int srcStrideAbs = Math.Abs(srcData.Stride);
                int dstStrideAbs = Math.Abs(dstData.Stride);

                byte[] srcBuffer = new byte[srcStrideAbs * height];
                byte[] dstBuffer = new byte[dstStrideAbs * height];

                System.Runtime.InteropServices.Marshal.Copy(srcData.Scan0, srcBuffer, 0, srcBuffer.Length);

                for (int y = 0; y < height; y++)
                {
                    int srcY = srcData.Stride < 0 ? (height - 1 - y) : y;
                    int dstY = dstData.Stride < 0 ? (height - 1 - y) : y;
                    int srcRow = srcY * srcStrideAbs;
                    int dstRow = dstY * dstStrideAbs;

                    for (int x = 0; x < width; x++)
                    {
                        int srcIndex = srcRow + x * srcBpp;
                        if (srcIndex + 2 >= srcBuffer.Length)
                        {
                            continue;
                        }

                        byte b = srcBuffer[srcIndex];
                        byte g = srcBuffer[srcIndex + 1];
                        byte r = srcBuffer[srcIndex + 2];
                        int luminance = (299 * r + 587 * g + 114 * b) / 1000;

                        byte paletteIndex;
                        if (luminance < 64)
                        {
                            paletteIndex = 0;
                        }
                        else if (luminance < 128)
                        {
                            paletteIndex = 1;
                        }
                        else if (luminance < 192)
                        {
                            paletteIndex = 2;
                        }
                        else
                        {
                            paletteIndex = 3;
                        }

                        int dstIndex = dstRow + (x >> 1);
                        if ((x & 1) == 0)
                        {
                            dstBuffer[dstIndex] = (byte)((paletteIndex << 4) | (dstBuffer[dstIndex] & 0x0F));
                        }
                        else
                        {
                            dstBuffer[dstIndex] = (byte)((dstBuffer[dstIndex] & 0xF0) | paletteIndex);
                        }
                    }
                }

                System.Runtime.InteropServices.Marshal.Copy(dstBuffer, 0, dstData.Scan0, dstBuffer.Length);
            }
            finally
            {
                img.UnlockBits(srcData);
                gray.UnlockBits(dstData);
            }

            return gray;
        }

        private Bitmap ConvertToGrayscale4(Bitmap img)
        {
            int width = img.Width;
            int height = img.Height;

            Bitmap gray = new Bitmap(width, height, PixelFormat.Format4bppIndexed);
            gray.SetResolution(img.HorizontalResolution, img.VerticalResolution);

            ColorPalette palette = gray.Palette;
            for (int i = 0; i < 16; i++)
            {
                int value = i * 17; // 0..255 in 16 uniform steps
                palette.Entries[i] = System.Drawing.Color.FromArgb(value, value, value);
            }
            gray.Palette = palette;

            DrawingRectangle rect = new DrawingRectangle(0, 0, width, height);
            BitmapData srcData = img.LockBits(rect, ImageLockMode.ReadOnly, img.PixelFormat);
            BitmapData dstData = gray.LockBits(rect, ImageLockMode.WriteOnly, PixelFormat.Format4bppIndexed);

            try
            {
                int srcBpp = Math.Max(1, DrawingImage.GetPixelFormatSize(img.PixelFormat) / 8);
                int srcStrideAbs = Math.Abs(srcData.Stride);
                int dstStrideAbs = Math.Abs(dstData.Stride);

                byte[] srcBuffer = new byte[srcStrideAbs * height];
                byte[] dstBuffer = new byte[dstStrideAbs * height];

                System.Runtime.InteropServices.Marshal.Copy(srcData.Scan0, srcBuffer, 0, srcBuffer.Length);

                for (int y = 0; y < height; y++)
                {
                    int srcY = srcData.Stride < 0 ? (height - 1 - y) : y;
                    int dstY = dstData.Stride < 0 ? (height - 1 - y) : y;
                    int srcRow = srcY * srcStrideAbs;
                    int dstRow = dstY * dstStrideAbs;

                    for (int x = 0; x < width; x++)
                    {
                        int srcIndex = srcRow + x * srcBpp;
                        if (srcIndex + 2 >= srcBuffer.Length)
                        {
                            continue;
                        }

                        byte b = srcBuffer[srcIndex];
                        byte g = srcBuffer[srcIndex + 1];
                        byte r = srcBuffer[srcIndex + 2];
                        int luminance = (299 * r + 587 * g + 114 * b) / 1000;
                        byte paletteIndex = (byte)((luminance + 8) / 17); // round to nearest 0..15
                        if (paletteIndex > 15)
                        {
                            paletteIndex = 15;
                        }

                        int dstIndex = dstRow + (x >> 1);
                        if ((x & 1) == 0)
                        {
                            dstBuffer[dstIndex] = (byte)((paletteIndex << 4) | (dstBuffer[dstIndex] & 0x0F));
                        }
                        else
                        {
                            dstBuffer[dstIndex] = (byte)((dstBuffer[dstIndex] & 0xF0) | paletteIndex);
                        }
                    }
                }

                System.Runtime.InteropServices.Marshal.Copy(dstBuffer, 0, dstData.Scan0, dstBuffer.Length);
            }
            finally
            {
                img.UnlockBits(srcData);
                gray.UnlockBits(dstData);
            }

            return gray;
        }


        private byte[] EncodeToTiffG4(Bitmap oneBitBmp)
        {
            using (MemoryStream ms = new MemoryStream())
            {
                // Find the TIFF codec
                ImageCodecInfo tiffCodec = ImageCodecInfo.GetImageDecoders()
                    .FirstOrDefault(codec => codec.FormatID == ImageFormat.Tiff.Guid);

                if (tiffCodec == null)
                    throw new InvalidOperationException(LocalizedText("Err_Codec_TiffMissing"));

                // Set compression parameter to CCITT Group 4
                var encoderParams = new EncoderParameters(2);
                encoderParams.Param[0] = new EncoderParameter(
                    System.Drawing.Imaging.Encoder.Compression,
                    (long)EncoderValue.CompressionCCITT4
                );
                // Set black and white color mode
                encoderParams.Param[1] = new EncoderParameter(Encoder.ColorDepth, 1L);

                // Write to MemoryStream
                oneBitBmp.Save(ms, tiffCodec, encoderParams);

                return ms.ToArray(); // Return TIFF bytes (CCITT Group 4)
            }
        }

        private byte[] EncodeToJpeg(Bitmap bmp, long quality = 90L)
        {
            using (MemoryStream ms = new MemoryStream())
            {
                // Find the JPEG codec
                var jpegCodec = ImageCodecInfo.GetImageDecoders()
                    .FirstOrDefault(c => c.FormatID == ImageFormat.Jpeg.Guid);

                if (jpegCodec == null)
                    throw new InvalidOperationException(LocalizedText("Err_Codec_JpegMissing"));

                // Compression parameters
                var encoderParams = new EncoderParameters(1);
                encoderParams.Param[0] = new EncoderParameter(
                    System.Drawing.Imaging.Encoder.Quality,
                    quality
                );

                using (Bitmap temp24 = new Bitmap(bmp.Width, bmp.Height, PixelFormat.Format24bppRgb))
                {
                    temp24.SetResolution(bmp.HorizontalResolution, bmp.VerticalResolution);
                    using (Graphics g = Graphics.FromImage(temp24))
                    {
                        g.DrawImage(bmp, 0, 0);
                    }
                    temp24.Save(ms, jpegCodec, encoderParams);
                }

                return ms.ToArray(); // bajty JPEG
            }
        }

        private byte[] EncodeToJpegGrayscale(Bitmap bmp, long quality = 80L)
        {
            using (Bitmap gray = new Bitmap(bmp.Width, bmp.Height, PixelFormat.Format24bppRgb))
            {
                gray.SetResolution(bmp.HorizontalResolution, bmp.VerticalResolution);
                using (Graphics g = Graphics.FromImage(gray))
                using (ImageAttributes imageAttributes = new ImageAttributes())
                {
                    var colorMatrix = new ColorMatrix(new float[][]
                    {
                        new float[] { 0.299f, 0.299f, 0.299f, 0f, 0f },
                        new float[] { 0.587f, 0.587f, 0.587f, 0f, 0f },
                        new float[] { 0.114f, 0.114f, 0.114f, 0f, 0f },
                        new float[] { 0f,     0f,     0f,     1f, 0f },
                        new float[] { 0f,     0f,     0f,     0f, 1f }
                    });
                    imageAttributes.SetColorMatrix(colorMatrix);

                    g.DrawImage(
                        bmp,
                        new DrawingRectangle(0, 0, gray.Width, gray.Height),
                        0,
                        0,
                        bmp.Width,
                        bmp.Height,
                        GraphicsUnit.Pixel,
                        imageAttributes);
                }

                return EncodeToJpeg(gray, quality);
            }
        }

        private byte[] EncodeToPng(Bitmap bmp)
        {
            using (MemoryStream ms = new MemoryStream())
            {
                using (Bitmap temp24 = new Bitmap(bmp.Width, bmp.Height, PixelFormat.Format24bppRgb))
                {
                    temp24.SetResolution(bmp.HorizontalResolution, bmp.VerticalResolution);
                    using (Graphics g = Graphics.FromImage(temp24))
                    {
                        g.DrawImage(bmp, 0, 0);
                    }
                    temp24.Save(ms, ImageFormat.Png);
                }

                return ms.ToArray();
            }
        }

        private void UpdateWindowTitle()
        {

            string titleText = LocalizedFormat("Window_TitleFormat", Branding.ProductName, fileVersion);
            string demoSuffix = GetDemoTitleSuffix();
            if (!string.IsNullOrWhiteSpace(demoSuffix))
            {
                titleText += demoSuffix;
            }
            if (inputPdfPath != "")
            {
                string pdfFileName = ShortenFileName(Path.GetFileName(inputPdfPath));
                titleText += LocalizedFormat("Window_Title_PdfPart", pdfFileName);
            }
            string papText = "";
            if (inputProjectPath != "")
            {
                string papFileName = ShortenFileName(Path.GetFileName(inputProjectPath));
                papText = LocalizedFormat("Window_Title_ProjectPart", papFileName);
            }

            if (lastSavedProjectName != "")
            {
                string papFileName = ShortenFileName(Path.GetFileName(lastSavedProjectName));
                papText = LocalizedFormat("Window_Title_ProjectPart", papFileName);
            }

            if (papText != "")
            {
                titleText += papText;
            }

            if (isPrintInProgress)
            {
                titleText += LocalizedText("Window_Title_PrintingSuffix");
            }

            this.Text = titleText;
        }

        private static string ShortenFileName(string fileName, int maxLength = 40)
        {
            if (string.IsNullOrWhiteSpace(fileName))
            {
                return fileName;
            }

            if (fileName.Length <= maxLength)
            {
                return fileName;
            }

            int suffixLength = 3;
            if (maxLength <= suffixLength)
            {
                return fileName.Substring(0, maxLength);
            }

            return fileName.Substring(0, maxLength - suffixLength) + "...";
        }

        private static string GetDemoTitleSuffix()
        {
            var info = LicenseManager.Current;
            if (info == null || !info.IsSignatureValid || info.Payload == null)
            {
                return string.Empty;
            }

            if (!string.Equals(info.Payload.Edition, "demo", StringComparison.OrdinalIgnoreCase)
                && !LicenseManager.IsUpdateOutOfRangeForCurrentVersion
                && !LicenseManager.IsRevoked)
            {
                return string.Empty;
            }

            if (LicenseManager.IsRevoked)
            {
                return LocalizedText("Demo_TitleSuffix_Revoked");
            }

            if (LicenseManager.IsUpdateOutOfRangeForCurrentVersion)
            {
                return LocalizedText("Demo_TitleSuffix_UpdateOutOfRange");
            }

            var demoUntil = ParseLicenseDate(info.Payload.DemoUntil);
            if (!demoUntil.HasValue)
            {
                return LocalizedText("Demo_TitleSuffix_Default");
            }

            var daysLeft = (int)Math.Ceiling((demoUntil.Value.Date - DateTime.UtcNow.Date).TotalDays);
            if (daysLeft >= 0)
            {
                return LocalizedFormat("Demo_TitleSuffix_DaysLeft", daysLeft);
            }

            return LocalizedFormat("Demo_TitleSuffix_ExpiredOn", demoUntil.Value);
        }

        private static string GetLicenseStatusLine()
        {
            var info = LicenseManager.Current;
            if (info == null)
            {
                return LocalizedText("LicenseStatus_Missing");
            }

            if (!info.IsSignatureValid)
            {
                return LocalizedText("LicenseStatus_Invalid");
            }

            if (info.Payload == null)
            {
                return LocalizedText("LicenseStatus_NoData");
            }

            if (LicenseManager.IsRevoked)
            {
                return LocalizedText("LicenseStatus_Demo_Revoked");
            }

            if (LicenseManager.IsUpdateOutOfRangeForCurrentVersion)
            {
                return LocalizedText("LicenseStatus_Demo_UpdateOutOfRange");
            }

            if (string.Equals(info.Payload.Edition, "demo", StringComparison.OrdinalIgnoreCase))
            {
                var demoUntil = ParseLicenseDate(info.Payload.DemoUntil);
                if (!demoUntil.HasValue)
                {
                    return LocalizedText("LicenseStatus_Demo");
                }

                var daysLeft = (int)Math.Ceiling((demoUntil.Value.Date - DateTime.UtcNow.Date).TotalDays);
                if (daysLeft >= 0)
                {
                    return LocalizedFormat("LicenseStatus_Demo_DaysLeft", daysLeft);
                }

                return LocalizedFormat("LicenseStatus_Demo_ExpiredOn", demoUntil.Value);
            }

            return LocalizedText("LicenseStatus_Pro");
        }

        private static string GetUpdatesStatusLine()
        {
            var info = LicenseManager.Current;
            if (info == null || !info.IsSignatureValid || info.Payload == null)
            {
                return LocalizedText("SupportStatus_NoData");
            }

            var supportUntil = LicenseManager.GetEffectiveSupportUntil();
            if (!supportUntil.HasValue)
            {
                return LocalizedText("SupportStatus_None");
            }

            if (supportUntil.Value.Date >= DateTime.UtcNow.Date)
            {
                return LocalizedFormat("SupportStatus_Until", supportUntil.Value);
            }

            return LocalizedFormat("SupportStatus_ExpiredOn", supportUntil.Value);
        }

        private static string GetLicensedToLine()
        {
            var info = LicenseManager.Current;
            string customer = info?.Payload?.CustomerName;
            if (string.IsNullOrWhiteSpace(customer))
            {
                customer = "-";
            }

            return LocalizedFormat("LicensedTo_Line", customer);
        }

        private static DateTime? ParseLicenseDate(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
            {
                return null;
            }

            if (DateTime.TryParseExact(value, "yyyy-MM-dd", CultureInfo.InvariantCulture,
                DateTimeStyles.AssumeUniversal, out DateTime exact))
            {
                return DateTime.SpecifyKind(exact, DateTimeKind.Utc);
            }

            if (DateTime.TryParse(value, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTime parsed))
            {
                return DateTime.SpecifyKind(parsed, DateTimeKind.Utc);
            }

            return null;
        }

        public void ExtractSignatures()
        {
            signatures.Clear();
            var props = new ReaderProperties();
            if (!string.IsNullOrEmpty(userPassword))
            {
                props.SetPassword(System.Text.Encoding.UTF8.GetBytes(userPassword));
            }
            using (PdfReader reader = new PdfReader(inputPdfPath, props).SetUnethicalReading(Properties.Settings.Default.IgnorePdfRestrictions))
            using (iText.Kernel.Pdf.PdfDocument pdfDoc = new iText.Kernel.Pdf.PdfDocument(reader))
            {
                // Tool for handling signatures
                SignatureUtil signUtil = new SignatureUtil(pdfDoc);

                // Gets list of field names where signature actually exists
                IList<string> sigNames = signUtil.GetSignatureNames();

                foreach (string name in sigNames)
                {
                    PdfPKCS7 pkcs7 = signUtil.ReadSignatureData(name);

                    DateTime signDate = pkcs7.GetSignDate().ToLocalTime();

                    IX509Certificate cert = pkcs7.GetSigningCertificate();
                    var subject = CertificateInfo.GetSubjectFields(cert);

                    string certCn = subject.GetField("CN") ?? "";
                    string certT = subject.GetField("T") ?? "";
                    string certO = subject.GetField("O") ?? "";
                    if (string.IsNullOrWhiteSpace(certO))
                    {
                        certO = subject.GetField("OU") ?? "";
                    }

                    signatures.Add(new SignatureInfo
                    {
                        FieldName = name,
                        SignerName = certCn,
                        SignerTitle = certT,
                        SignerOrganization = certO,
                        SignDate = signDate
                    });
                }
            }

            groupBoxSignatures.Enabled = (signatures.Count > 0);
            if (signatures.Count == 0)
            {
                signaturesToRemove.Clear();
                hasCustomSignatureSelection = false;
            }
            SyncSignatureSelectionWithAvailableSignatures();
            UpdateSignatureSelectionMenuState();
        }

        private void RemovePage()
        {
            if (numPages == 1)
            {
                MessageBox.Show(this, Resources.Err_TooFewPages, Resources.Title_Error, MessageBoxButtons.OK, MessageBoxIcon.Exclamation);
                return;
            }

            bool isMarked = pagesToRemove.Contains(currentPage);

            PageItemStatus status = allPageStatuses[currentPage - 1];
            if (isMarked)
            {
                pagesToRemove.Remove(currentPage);
                UpdateRemovePageButtonVisual(false);
                status.MarkedForDeletion = false;
            }
            else
            {
                UpdateRemovePageButtonVisual(true);
                pagesToRemove.Add(currentPage);
                status.MarkedForDeletion = true;
            }

            if ((string)filterComboBox.SelectedItem == allComboItem)
            {
                // only refresh this row
                ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
            }
            else
            {
                // rebuild list by filter
                ApplyFilter((string)filterComboBox.SelectedItem);
            }


            pagesListView.Invalidate();
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            UpdateNavigationButtons(currentPage);
        }

        private void RemovePageButton_Click(object sender, EventArgs e)
        {
            BeginUndoCapture("Delete page");
            RemovePage();
            CommitUndoCapture();
        }


        private byte[] ExtractPageToBytes(int pageNumber)
        {
            // Check if input file exists
            if (!File.Exists(inputPdfPath))
            {
                throw new FileNotFoundException(LocalizedText("Err_InputFileDoesNotExist"), inputPdfPath);
            }

            using (MemoryStream outputStream = new MemoryStream())
            {
                // Open input PDF file
                var props = new ReaderProperties();
                if (!string.IsNullOrEmpty(userPassword))
                {
                    props.SetPassword(System.Text.Encoding.UTF8.GetBytes(userPassword));
                }
                using (iText.Kernel.Pdf.PdfDocument pdfDoc = new iText.Kernel.Pdf.PdfDocument(new PdfReader(inputPdfPath, props).SetUnethicalReading(Properties.Settings.Default.IgnorePdfRestrictions)))
                {
                    // Check if page number is correct
                    if (pageNumber < 1 || pageNumber > pdfDoc.GetNumberOfPages())
                    {
                        throw new ArgumentOutOfRangeException(
                            nameof(pageNumber),
                            LocalizedFormat("Err_PageNumberOutOfRange", pdfDoc.GetNumberOfPages()));
                    }

                    // Create new PDF document for page
                    using (iText.Kernel.Pdf.PdfDocument extractedPageDoc = new iText.Kernel.Pdf.PdfDocument(new PdfWriter(outputStream)))
                    {
                        // Copy selected page to new document
                        pdfDoc.CopyPagesTo(pageNumber, pageNumber, extractedPageDoc);

                        // Close the new PDF document
                        extractedPageDoc.Close();
                    }
                }

                // Get bytes from memory stream
                return outputStream.ToArray();
            }
        }

        private static byte[] ExtractPageToBytes(int pageNumber, string sourcePdfPath, string password)
        {
            if (string.IsNullOrWhiteSpace(sourcePdfPath) || !File.Exists(sourcePdfPath))
            {
                throw new FileNotFoundException("Input file does not exist.", sourcePdfPath);
            }

            using (MemoryStream outputStream = new MemoryStream())
            {
                var props = new ReaderProperties();
                if (!string.IsNullOrEmpty(password))
                {
                    props.SetPassword(System.Text.Encoding.UTF8.GetBytes(password));
                }

                using (iText.Kernel.Pdf.PdfDocument pdfDoc = new iText.Kernel.Pdf.PdfDocument(
                    new PdfReader(sourcePdfPath, props).SetUnethicalReading(Properties.Settings.Default.IgnorePdfRestrictions)))
                {
                    if (pageNumber < 1 || pageNumber > pdfDoc.GetNumberOfPages())
                    {
                        throw new ArgumentOutOfRangeException(nameof(pageNumber));
                    }

                    using (iText.Kernel.Pdf.PdfDocument extractedPageDoc = new iText.Kernel.Pdf.PdfDocument(new PdfWriter(outputStream)))
                    {
                        pdfDoc.CopyPagesTo(pageNumber, pageNumber, extractedPageDoc);
                        extractedPageDoc.Close();
                    }
                }

                return outputStream.ToArray();
            }
        }

        private void CancelPreviewRender()
        {
            var cts = previewRenderCts;
            previewRenderCts = null;
            if (cts == null)
            {
                return;
            }

            try
            {
                cts.Cancel();
            }
            catch
            {
                // ignore
            }
        }

        private bool HasVisibleCommentsOnPage(int pageNumber)
        {
            return commentAnnotations.Any(c =>
                c != null &&
                c.PageNumber == pageNumber &&
                IsLayerVisible(c.LayerId));
        }

        private void CancelCommentPreviewRects()
        {
            var cts = commentPreviewRectsCts;
            commentPreviewRectsCts = null;
            if (cts == null)
            {
                return;
            }

            try
            {
                cts.Cancel();
            }
            catch
            {
            }
        }

        private void ClearCommentPreviewRects()
        {
            CancelCommentPreviewRects();
            commentPreviewRectsPdf.Clear();
            commentPreviewOverlayReady = false;
        }

        private void EnsureCommentPreviewRectsForPage(int pageNumber)
        {
            if (pageNumber < 1 || !HasVisibleCommentsOnPage(pageNumber))
            {
                return;
            }

            bool missingCache = commentAnnotations.Any(comment =>
                comment != null &&
                comment.PageNumber == pageNumber &&
                IsLayerVisible(comment.LayerId) &&
                !string.IsNullOrWhiteSpace(comment.Id) &&
                !commentPreviewRectsPdf.ContainsKey(comment.Id));
            if (missingCache)
            {
                QueueCommentPreviewRectsForPage(pageNumber);
            }
        }

        private void QueueCommentPreviewRectsForPage(int pageNumber)
        {
            if (pageNumber < 1 || string.IsNullOrWhiteSpace(inputPdfPath) || !File.Exists(inputPdfPath))
            {
                commentPreviewOverlayReady = true;
                delayCommentAndSelectionOverlayUntilPreviewReady = false;
                return;
            }

            var commentsForPage = commentAnnotations
                .Where(comment =>
                    comment != null &&
                    comment.PageNumber == pageNumber &&
                    IsLayerVisible(comment.LayerId) &&
                    !string.IsNullOrWhiteSpace(comment.Id))
                .ToList();

            if (commentsForPage.Count == 0)
            {
                commentPreviewOverlayReady = true;
                delayCommentAndSelectionOverlayUntilPreviewReady = false;
                return;
            }

            var previousCts = commentPreviewRectsCts;
            commentPreviewRectsCts = new System.Threading.CancellationTokenSource();
            int requestId = ++commentPreviewRectsRequestId;
            string sourcePdfPath = inputPdfPath;
            string password = userPassword;
            var token = commentPreviewRectsCts.Token;

            try
            {
                previousCts?.Cancel();
            }
            catch
            {
            }

            Task.Run(() =>
            {
                var results = new Dictionary<string, RectangleF>(StringComparer.Ordinal);
                try
                {
                    var props = new ReaderProperties();
                    if (!string.IsNullOrEmpty(password))
                    {
                        props.SetPassword(System.Text.Encoding.UTF8.GetBytes(password));
                    }

                    using (var reader = new PdfReader(sourcePdfPath, props).SetUnethicalReading(Properties.Settings.Default.IgnorePdfRestrictions))
                    using (var pdfDoc = new iText.Kernel.Pdf.PdfDocument(reader))
                    {
                        if (pageNumber < 1 || pageNumber > pdfDoc.GetNumberOfPages())
                        {
                            return results;
                        }

                        var page = pdfDoc.GetPage(pageNumber);
                        int rotation = GetEffectiveRotationDegrees(pageNumber);
                        foreach (var comment in commentsForPage)
                        {
                            if (token.IsCancellationRequested)
                            {
                                return null;
                            }

                            RectangleF sourcePdfRect = ConvertToPdfCoordinates(comment.Bounds, pageNumber, rotation);
                            var sourceRectangle = ConvertToItTextRectangle(sourcePdfRect);
                            var visualRectangle = ExpandMarkerCleanupRectangleToTextBounds(
                                page,
                                sourceRectangle,
                                pageNumber,
                                rotation,
                                comment.IsMarkerSelection ? "comment-marker-preview" : "comment-box-preview");
                            RectangleF visualPdfRect = ConvertToItTextRectangleF(visualRectangle);
                            if (visualPdfRect.Width > 0f && visualPdfRect.Height > 0f)
                            {
                                results[comment.Id] = visualPdfRect;
                            }
                        }
                    }
                }
                catch (Exception ex)
                {
                    LogDebug("Comment preview marker expansion failed: " + ex.Message);
                }

                return results;
            }, token).ContinueWith(t =>
            {
                if (IsDisposed || Disposing || token.IsCancellationRequested || requestId != commentPreviewRectsRequestId)
                {
                    return;
                }

                if (t.Status == TaskStatus.RanToCompletion && t.Result != null)
                {
                    foreach (var comment in commentsForPage)
                    {
                        commentPreviewRectsPdf.Remove(comment.Id);
                    }

                    foreach (var pair in t.Result)
                    {
                        commentPreviewRectsPdf[pair.Key] = pair.Value;
                    }
                }

                commentPreviewOverlayReady = true;
                delayCommentAndSelectionOverlayUntilPreviewReady = false;
                pdfViewer?.Invalidate();
            }, TaskScheduler.FromCurrentSynchronizationContext());
        }

        private void ClearRedactionPreviewOverlay()
        {
            try
            {
                redactionPreviewOverlayCts?.Cancel();
            }
            catch
            {
            }

            redactionPreviewOverlayCts = null;
            redactionPreviewOverlayRequestId++;

            if (redactionPreviewOverlayBitmap != null)
            {
                redactionPreviewOverlayBitmap.Dispose();
                redactionPreviewOverlayBitmap = null;
            }
        }

        private Bitmap BuildRedactionPreviewOverlayBitmap(
            Bitmap sourceBitmap,
            List<RedactionBlock> blocksForPage,
            float renderScale)
        {
            if (sourceBitmap == null || blocksForPage == null || blocksForPage.Count == 0)
            {
                return null;
            }

            Bitmap overlay = new Bitmap(sourceBitmap.Width, sourceBitmap.Height, PixelFormat.Format32bppArgb);
            DrawingRectangle fullRect = new DrawingRectangle(0, 0, sourceBitmap.Width, sourceBitmap.Height);
            BitmapData sourceData = sourceBitmap.LockBits(fullRect, ImageLockMode.ReadOnly, sourceBitmap.PixelFormat);
            BitmapData overlayData = overlay.LockBits(fullRect, ImageLockMode.WriteOnly, overlay.PixelFormat);

            try
            {
                int sourceBpp = Image.GetPixelFormatSize(sourceBitmap.PixelFormat) / 8;
                int overlayBpp = Image.GetPixelFormatSize(overlay.PixelFormat) / 8;
                int sourceStride = sourceData.Stride;
                int overlayStride = overlayData.Stride;

                unsafe
                {
                    byte* sourcePtr = (byte*)sourceData.Scan0;
                    byte* overlayPtr = (byte*)overlayData.Scan0;

                    foreach (var block in blocksForPage)
                    {
                        if (block?.PreviewTextRectsPdf == null || block.PreviewTextRectsPdf.Count == 0)
                        {
                            continue;
                        }

                        int rotation = GetEffectiveRotationDegrees(block.PageNumber);
                        foreach (RectangleF pdfRect in block.PreviewTextRectsPdf)
                        {
                            RectangleF viewRect = ConvertPdfToViewCoordinates(pdfRect, block.PageNumber, rotation);
                            int left = Math.Max(0, (int)Math.Floor(viewRect.X * renderScale));
                            int top = Math.Max(0, (int)Math.Floor(viewRect.Y * renderScale));
                            int right = Math.Min(sourceBitmap.Width - 1, (int)Math.Ceiling((viewRect.Right * renderScale) - 1));
                            int bottom = Math.Min(sourceBitmap.Height - 1, (int)Math.Ceiling((viewRect.Bottom * renderScale) - 1));
                            if (right < left || bottom < top)
                            {
                                continue;
                            }

                            long sumB = 0;
                            long sumG = 0;
                            long sumR = 0;
                            int sampleCount = 0;
                            for (int x = left; x <= right; x++)
                            {
                                int topIndex = x * sourceBpp;
                                byte* topRow = sourcePtr + (top * sourceStride);
                                sumB += topRow[topIndex];
                                sumG += topRow[topIndex + 1];
                                sumR += topRow[topIndex + 2];
                                sampleCount++;

                                if (bottom != top)
                                {
                                    byte* bottomRow = sourcePtr + (bottom * sourceStride);
                                    int bottomIndex = x * sourceBpp;
                                    sumB += bottomRow[bottomIndex];
                                    sumG += bottomRow[bottomIndex + 1];
                                    sumR += bottomRow[bottomIndex + 2];
                                    sampleCount++;
                                }
                            }

                            for (int y = top + 1; y < bottom; y++)
                            {
                                byte* row = sourcePtr + (y * sourceStride);
                                int leftIndex = left * sourceBpp;
                                sumB += row[leftIndex];
                                sumG += row[leftIndex + 1];
                                sumR += row[leftIndex + 2];
                                sampleCount++;

                                if (right != left)
                                {
                                    int rightIndex = right * sourceBpp;
                                    sumB += row[rightIndex];
                                    sumG += row[rightIndex + 1];
                                    sumR += row[rightIndex + 2];
                                    sampleCount++;
                                }
                            }

                            byte backgroundB = sampleCount > 0 ? (byte)(sumB / sampleCount) : (byte)255;
                            byte backgroundG = sampleCount > 0 ? (byte)(sumG / sampleCount) : (byte)255;
                            byte backgroundR = sampleCount > 0 ? (byte)(sumR / sampleCount) : (byte)255;

                            for (int y = top; y <= bottom; y++)
                            {
                                byte* sourceRow = sourcePtr + (y * sourceStride);
                                byte* overlayRow = overlayPtr + (y * overlayStride);
                                for (int x = left; x <= right; x++)
                                {
                                    int sourceIndex = x * sourceBpp;
                                    int overlayIndex = x * overlayBpp;
                                    byte b = sourceRow[sourceIndex];
                                    byte g = sourceRow[sourceIndex + 1];
                                    byte r = sourceRow[sourceIndex + 2];
                                    int colorDistance =
                                        Math.Abs(r - backgroundR) +
                                        Math.Abs(g - backgroundG) +
                                        Math.Abs(b - backgroundB);
                                    if (colorDistance < 36)
                                    {
                                        continue;
                                    }

                                    int luminance = ((r * 299) + (g * 587) + (b * 114)) / 1000;
                                    byte alpha = (byte)Math.Max(0, Math.Min(220, (255 - luminance) * 5 / 6));
                                    if (alpha == 0)
                                    {
                                        continue;
                                    }

                                    if (overlayRow[overlayIndex + 3] < alpha)
                                    {
                                        overlayRow[overlayIndex] = 220;
                                        overlayRow[overlayIndex + 1] = 220;
                                        overlayRow[overlayIndex + 2] = 220;
                                        overlayRow[overlayIndex + 3] = alpha;
                                    }
                                }
                            }
                        }
                    }
                }
            }
            finally
            {
                sourceBitmap.UnlockBits(sourceData);
                overlay.UnlockBits(overlayData);
            }

            return overlay;
        }

        private void QueueRedactionPreviewOverlayForPage(int pageNumber)
        {
            if (pageNumber < 1 || pageNumber != currentPage)
            {
                return;
            }

            List<RedactionBlock> blocksForPage = redactionBlocks
                .Where(b => b != null &&
                            b.PageNumber == pageNumber &&
                            IsLayerVisible(b.LayerId) &&
                            b.PreviewTextRectsPdf != null &&
                            b.PreviewTextRectsPdf.Count > 0)
                .ToList();

            if (blocksForPage.Count == 0)
            {
                if (redactionPreviewOverlayBitmap != null)
                {
                    redactionPreviewOverlayBitmap.Dispose();
                    redactionPreviewOverlayBitmap = null;
                    pdfViewer.Invalidate();
                }
                return;
            }

            var previousCts = redactionPreviewOverlayCts;
            redactionPreviewOverlayCts = new System.Threading.CancellationTokenSource();
            int requestId = ++redactionPreviewOverlayRequestId;
            float renderScale = scaleFactor;
            var token = redactionPreviewOverlayCts.Token;

            try
            {
                previousCts?.Cancel();
            }
            catch
            {
            }

            Task.Run(() =>
            {
                if (token.IsCancellationRequested)
                {
                    return null;
                }

                using (Bitmap sourceBitmap = new Bitmap(RenderOriginalPageAtScale(pageNumber, renderScale)))
                {
                    if (token.IsCancellationRequested)
                    {
                        return null;
                    }

                    return BuildRedactionPreviewOverlayBitmap(sourceBitmap, blocksForPage, renderScale);
                }
            }, token).ContinueWith(t =>
            {
                if (IsDisposed || token.IsCancellationRequested || t.IsCanceled || requestId != redactionPreviewOverlayRequestId)
                {
                    t.Result?.Dispose();
                    return;
                }

                if (pageNumber != currentPage)
                {
                    t.Result?.Dispose();
                    return;
                }

                if (redactionPreviewOverlayBitmap != null)
                {
                    redactionPreviewOverlayBitmap.Dispose();
                }

                redactionPreviewOverlayBitmap = t.Result;
                pdfViewer.Invalidate();
            }, TaskScheduler.FromCurrentSynchronizationContext());
        }

        private void StartAsyncRedactPreview(
            int pageNumber,
            float renderScale,
            List<RedactionBlock> blocksForPage,
            List<CommentAnnotation> commentsForPage)
        {
            CancelPreviewRender();
            int requestId = ++previewRenderRequestId;
            string sourcePdfPath = inputPdfPath;
            string password = userPassword;
            bool useSafeModeRendering = safeModeCheckBox.Checked || pdfCleanUpToolError;
            bool includeComments = commentsForPage != null && commentsForPage.Count > 0;
            var cts = new System.Threading.CancellationTokenSource();
            var token = cts.Token;
            previewRenderCts = cts;

            Task.Run(() =>
            {
                bool cleanupFailed = false;
                DrawingImage previewImage = null;
                if (token.IsCancellationRequested)
                {
                    return null;
                }

                if (useSafeModeRendering)
                {
                    previewImage = RenderCurrentPageWithSelectionsSnapshot(pageNumber, renderScale, blocksForPage);
                }
                else
                {
                    try
                    {
                        previewImage = RenderCurrentPageWithPdfCleanUpSnapshot(pageNumber, renderScale, blocksForPage, sourcePdfPath, password);
                    }
                    catch
                    {
                        cleanupFailed = true;
                        previewImage = RenderCurrentPageWithSelectionsSnapshot(pageNumber, renderScale, blocksForPage);
                    }
                }

                if (includeComments && previewImage != null)
                {
                    if (token.IsCancellationRequested)
                    {
                        previewImage.Dispose();
                        return null;
                    }

                    DrawingImage withComments = RenderBitmapWithCommentHighlightsSnapshot(
                        previewImage,
                        commentsForPage,
                        pageNumber,
                        renderScale,
                        sourcePdfPath,
                        password);
                    if (!ReferenceEquals(withComments, previewImage))
                    {
                        previewImage.Dispose();
                    }
                    previewImage = withComments;
                }

                if (token.IsCancellationRequested)
                {
                    previewImage?.Dispose();
                    return null;
                }

                return Tuple.Create(previewImage, cleanupFailed);
            }, token).ContinueWith(t =>
            {
                try
                {
                    if (t.IsCanceled || token.IsCancellationRequested)
                    {
                        return;
                    }

                    if (t.IsFaulted)
                    {
                        LogDebug("Async redact preview failed: " + t.Exception?.GetBaseException().Message);
                        return;
                    }

                    if (t.Result == null)
                    {
                        return;
                    }

                    DrawingImage previewImage = t.Result.Item1;
                    bool cleanupFailed = t.Result.Item2;

                    bool requestOutdated =
                        requestId != previewRenderRequestId ||
                        token.IsCancellationRequested ||
                        currentPage != pageNumber ||
                        Math.Abs(scaleFactor - renderScale) > 0.0001f ||
                        !ArePathsEqual(sourcePdfPath, inputPdfPath);
                    if (requestOutdated)
                    {
                        previewImage?.Dispose();
                        return;
                    }

                    if (cleanupFailed)
                    {
                        pdfCleanUpToolError = true;
                    }

                    pdfViewer.Image = previewImage;
                    commentPreviewOverlayReady = includeComments && previewImage != null;
                    delayCommentAndSelectionOverlayUntilPreviewReady = false;
                    pdfViewer.Invalidate();
                }
                finally
                {
                    if (ReferenceEquals(previewRenderCts, cts))
                    {
                        previewRenderCts = null;
                    }
                    cts.Dispose();
                }
            }, TaskScheduler.FromCurrentSynchronizationContext());
        }

        private DrawingImage RenderCurrentPageWithSelectionsSnapshot(int pageNumber, float renderScale, IReadOnlyCollection<RedactionBlock> blocksForPage)
        {
            if (blocksForPage == null || blocksForPage.Count == 0)
            {
                return RenderOriginalPageAtScale(pageNumber, renderScale);
            }

            Bitmap originalBmp = new Bitmap(RenderOriginalPageAtScale(pageNumber, renderScale));
            Bitmap overlayBmp = new Bitmap(originalBmp.Width, originalBmp.Height, PixelFormat.Format32bppArgb);
            using (Graphics g = Graphics.FromImage(overlayBmp))
            {
                g.Clear(System.Drawing.Color.Black);

                foreach (var block in blocksForPage)
                {
                    RectangleF rect = new RectangleF(
                        block.Bounds.X * renderScale,
                        block.Bounds.Y * renderScale,
                        block.Bounds.Width * renderScale,
                        block.Bounds.Height * renderScale);
                    using (SolidBrush brush = new SolidBrush(System.Drawing.Color.White))
                    {
                        g.FillRectangle(brush, rect);
                    }
                }
            }

            Bitmap resultBmp = CombineBitmaps(originalBmp, overlayBmp);
            return resultBmp;
        }

        private DrawingImage RenderCurrentPageWithPdfCleanUpSnapshot(
            int pageNumber,
            float renderScale,
            IReadOnlyCollection<RedactionBlock> blocksForPage,
            string sourcePdfPath,
            string password)
        {
            if (blocksForPage == null || blocksForPage.Count == 0)
            {
                return RenderOriginalPageAtScale(pageNumber, renderScale);
            }

            byte[] pdfBytes = ExtractPageToBytes(pageNumber, sourcePdfPath, password);
            using (MemoryStream inputMemoryStream = new MemoryStream(pdfBytes))
            using (MemoryStream outputMemoryStream = new MemoryStream())
            {
                using (iText.Kernel.Pdf.PdfDocument pdfDoc = new iText.Kernel.Pdf.PdfDocument(
                    new iText.Kernel.Pdf.PdfReader(inputMemoryStream),
                    new iText.Kernel.Pdf.PdfWriter(outputMemoryStream)))
                {
                    PdfCleanUpTool cleanUpTool = new PdfCleanUpTool(pdfDoc);
                    int rotation = GetEffectiveRotationDegrees(pageNumber);
                    foreach (var block in blocksForPage)
                    {
                        RectangleF pdfCoordinates = ConvertToPdfCoordinates(block.Bounds, pageNumber, rotation);
                        iText.Kernel.Geom.Rectangle rectangle = new iText.Kernel.Geom.Rectangle(
                            (int)Math.Round(pdfCoordinates.X),
                            (int)Math.Round(pdfCoordinates.Y),
                            (int)Math.Round(pdfCoordinates.Width),
                            (int)Math.Round(pdfCoordinates.Height));
                        cleanUpTool.AddCleanupLocation(new PdfCleanUpLocation(1, rectangle, new iText.Kernel.Colors.DeviceRgb(255, 255, 255)));
                    }

                    cleanUpTool.CleanUp();
                }

                Bitmap overlayBmp;
                using (var previewPdf = new PDFiumSharp.PdfDocument(data: outputMemoryStream.ToArray(), password: password))
                {
                    var page = previewPdf.Pages[0];
                    int width = Math.Max(1, (int)(page.Width * renderScale));
                    int height = Math.Max(1, (int)(page.Height * renderScale));
                    using (var bmp = new PDFiumBitmap(width, height, true))
                    {
                        bmp.FillRectangle(0, 0, width, height, 0xFFFFFFFF);
                        page.Render(renderTarget: bmp, flags: PDFiumSharp.Enums.RenderingFlags.Annotations);
                        using (MemoryStream ms = new MemoryStream())
                        {
                            bmp.Save(ms);
                            ms.Position = 0;
                            overlayBmp = new Bitmap(DrawingImage.FromStream(ms));
                        }
                    }
                }

                ApplyRotationOffset(overlayBmp, GetRotationOffset(pageNumber));
                Bitmap originalBmp = new Bitmap(RenderOriginalPageAtScale(pageNumber, renderScale));
                Bitmap resultBmp = CombineBitmaps(originalBmp, overlayBmp);
                return resultBmp;
            }
        }

        private void ShowRedactPreview()
        {
            commentNoteRectsDoc.Clear();
            if (!HasVisibleCommentsOnPage(currentPage))
            {
                delayCommentAndSelectionOverlayUntilPreviewReady = false;
                ClearCommentPreviewRects();
                CancelPreviewRender();
                pdfViewer?.Invalidate();
                return;
            }

            commentPreviewOverlayReady = false;
            QueueCommentPreviewRectsForPage(currentPage);
            pdfViewer?.Invalidate();
        }

        private DrawingImage RenderBitmapWithCommentHighlights(DrawingImage sourceImage)
        {
            List<CommentAnnotation> commentsForCurrentPage = commentAnnotations
                .Where(c => c != null && c.PageNumber == currentPage && IsLayerVisible(c.LayerId))
                .Select(c => new CommentAnnotation
                {
                    Id = c.Id,
                    PageNumber = c.PageNumber,
                    LayerId = c.LayerId,
                    Bounds = c.Bounds,
                    HighlightColorArgb = c.HighlightColorArgb,
                    IsMarkerSelection = c.IsMarkerSelection
                })
                .ToList();

            return RenderBitmapWithCommentHighlightsSnapshot(
                sourceImage,
                commentsForCurrentPage,
                currentPage,
                scaleFactor,
                inputPdfPath,
                userPassword);
        }

        private DrawingImage RenderBitmapWithCommentHighlightsSnapshot(
            DrawingImage sourceImage,
            List<CommentAnnotation> comments,
            int pageNumber,
            float renderScale,
            string sourcePdfPath,
            string password)
        {
            if (sourceImage == null)
            {
                return null;
            }
            if (comments == null || comments.Count == 0)
            {
                return sourceImage;
            }

            var visualBoundsByComment = comments.ToDictionary(
                comment => comment,
                comment => comment.Bounds);

            bool requiresTextExpansion = comments.Any(c =>
                c.Bounds.Width > 0f &&
                c.Bounds.Height > 0f);
            if (requiresTextExpansion && !string.IsNullOrWhiteSpace(sourcePdfPath) && File.Exists(sourcePdfPath))
            {
                try
                {
                    var props = new ReaderProperties();
                    if (!string.IsNullOrEmpty(password))
                    {
                        props.SetPassword(System.Text.Encoding.UTF8.GetBytes(password));
                    }

                    using (var reader = new PdfReader(sourcePdfPath, props).SetUnethicalReading(Properties.Settings.Default.IgnorePdfRestrictions))
                    using (var pdfDoc = new iText.Kernel.Pdf.PdfDocument(reader))
                    {
                        if (pageNumber >= 1 && pageNumber <= pdfDoc.GetNumberOfPages())
                        {
                            var page = pdfDoc.GetPage(pageNumber);
                            int rotation = GetEffectiveRotationDegrees(pageNumber);
                            foreach (var comment in comments.Where(c =>
                                c.Bounds.Width > 0f &&
                                c.Bounds.Height > 0f))
                            {
                                RectangleF sourcePdfRect = ConvertToPdfCoordinates(comment.Bounds, pageNumber, rotation);
                                var sourceRectangle = ConvertToItTextRectangle(sourcePdfRect);
                                var visualRectangle = ExpandMarkerCleanupRectangleToTextBounds(
                                    page,
                                    sourceRectangle,
                                    pageNumber,
                                    rotation,
                                    comment.IsMarkerSelection ? "comment-marker-preview" : "comment-box-preview");
                                RectangleF visualViewRect = ConvertPdfToViewCoordinates(
                                    ConvertToItTextRectangleF(visualRectangle),
                                    pageNumber,
                                    rotation);
                                if (visualViewRect.Width > 0f && visualViewRect.Height > 0f)
                                {
                                    visualBoundsByComment[comment] = visualViewRect;
                                }
                            }
                        }
                    }
                }
                catch (Exception ex)
                {
                    LogDebug("Comment preview marker expansion failed: " + ex.Message);
                }
            }

            Bitmap baseBitmap = new Bitmap(sourceImage);
            Bitmap resultBitmap = baseBitmap.PixelFormat == PixelFormat.Format32bppArgb
                ? baseBitmap
                : baseBitmap.Clone(
                    new Rectangle(0, 0, baseBitmap.Width, baseBitmap.Height),
                    PixelFormat.Format32bppArgb);
            if (!ReferenceEquals(resultBitmap, baseBitmap))
            {
                baseBitmap.Dispose();
            }

            Rectangle imageBounds = new Rectangle(0, 0, resultBitmap.Width, resultBitmap.Height);
            const float blendFactor = 0.86f;

            BitmapData data = resultBitmap.LockBits(
                imageBounds,
                ImageLockMode.ReadWrite,
                PixelFormat.Format32bppArgb);

            try
            {
                int stride = data.Stride;
                IntPtr scan0 = data.Scan0;

                foreach (var comment in comments)
                {
                    System.Drawing.Color highlightColor = GetCommentHighlightColor(comment);
                    RectangleF visualBounds = visualBoundsByComment.TryGetValue(comment, out RectangleF cachedBounds)
                        ? cachedBounds
                        : comment.Bounds;
                    Rectangle rect = Rectangle.Round(new RectangleF(
                        visualBounds.X * renderScale,
                        visualBounds.Y * renderScale,
                        visualBounds.Width * renderScale,
                        visualBounds.Height * renderScale));
                    rect.Intersect(imageBounds);
                    if (rect.Width <= 0 || rect.Height <= 0)
                    {
                        continue;
                    }

                    for (int y = rect.Top; y < rect.Bottom; y++)
                    {
                        IntPtr rowPtr = IntPtr.Add(scan0, y * stride);
                        for (int x = rect.Left; x < rect.Right; x++)
                        {
                            int pixelOffset = x * 4;
                            byte b = Marshal.ReadByte(rowPtr, pixelOffset);
                            byte g = Marshal.ReadByte(rowPtr, pixelOffset + 1);
                            byte r = Marshal.ReadByte(rowPtr, pixelOffset + 2);

                            float mulR = (r * highlightColor.R) / 255f;
                            float mulG = (g * highlightColor.G) / 255f;
                            float mulB = (b * highlightColor.B) / 255f;

                            byte outR = (byte)Math.Max(0, Math.Min(255, (r * (1f - blendFactor)) + (mulR * blendFactor)));
                            byte outG = (byte)Math.Max(0, Math.Min(255, (g * (1f - blendFactor)) + (mulG * blendFactor)));
                            byte outB = (byte)Math.Max(0, Math.Min(255, (b * (1f - blendFactor)) + (mulB * blendFactor)));

                            Marshal.WriteByte(rowPtr, pixelOffset, outB);
                            Marshal.WriteByte(rowPtr, pixelOffset + 1, outG);
                            Marshal.WriteByte(rowPtr, pixelOffset + 2, outR);
                        }
                    }
                }
            }
            finally
            {
                resultBitmap.UnlockBits(data);
            }

            return resultBitmap;
        }

        private void RemovePageRangeButton_Click(object sender, EventArgs e)
        {
            if (numPages == 1)
            {
                MessageBox.Show(this, Resources.Err_TooFewPages, Resources.Title_Error, MessageBoxButtons.OK, MessageBoxIcon.Exclamation);
                return;
            }

            // Display dialog with page range, where maximum range is based on numPages variable.
            using (DeletePagesDialog dlg = new DeletePagesDialog(numPages))
            {
                if (dlg.ShowDialog(this) == DialogResult.OK)
                {
                    PageItemStatus status;
                    int step = dlg.StartPage;
                    if (dlg.ApplyDeletion)
                    {
                        // Received page range for removal: dlg.StartPage to dlg.EndPage.
                        // Here you can save this range to variable or perform appropriate action.
                        //MessageBox.Show($"Page range for removal: {dlg.StartPage} - {dlg.EndPage}");
                        // For example, you can add these pages to pagesToRemove set:
                        for (int i = dlg.StartPage; i <= dlg.EndPage; i++)
                        {
                            
                            
                            if (step == i)
                            {
                                step += dlg.Step;
                                if (i == currentPage)
                                {
                                    UpdateRemovePageButtonVisual(true);
                                }

                                //ListViewItem item = pagesListView.Items[i - 1];
                                //int pageNumber = ((PageItemStatus)item.Tag).PageNumber;
                                //bool hasSelections = ((PageItemStatus)item.Tag).HasSelections;
                                //bool hasSearchResults = ((PageItemStatus)item.Tag).HasSearchResults;
                                //bool hasObjects = ((PageItemStatus)item.Tag).HasObjects;
                                //UpdateItemTag(item, pageNumber, hasSelections, hasSearchResults, true, hasObjects);

                                status = allPageStatuses[i - 1];
                                status.MarkedForDeletion = true;
                                int pageNumber = status.PageNumber;
                                if ((string)filterComboBox.SelectedItem == allComboItem)
                                {
                                    // only refresh this row
                                    ListViewItem currentItem = pagesListView.Items[i - 1];
                                    UpdateItemTag(currentItem, pageNumber, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                                    //pagesListView.Invalidate(currentItem.Bounds);
                                }
                                pagesToRemove.Add(i);
                            }

                        }
                        // UI refresh is handled by per-item updates above.

                    }
                    else
                    {
                        for (int i = dlg.StartPage; i <= dlg.EndPage; i++)
                        {
                            if (i == currentPage)
                            {
                                UpdateRemovePageButtonVisual(false);
                            }

                            status = allPageStatuses[i - 1];
                            int pageNumber = status.PageNumber;

                            //ListViewItem item = pagesListView.Items[i - 1];
                            //int pageNumber = ((PageItemStatus)item.Tag).PageNumber;
                            //bool hasSelections = ((PageItemStatus)item.Tag).HasSelections;
                            
                            status.MarkedForDeletion = false;
                            if ((string)filterComboBox.SelectedItem == allComboItem)
                            {
                                // only refresh this row
                                ListViewItem currentItem = pagesListView.Items[i - 1];
                                UpdateItemTag(currentItem, pageNumber, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                                
                            }
                            pagesToRemove.Remove(i);
                        }

                        // User chose not to delete pages â€“ handle accordingly if needed
                    }
                    if ((string)filterComboBox.SelectedItem != allComboItem)
                    {
                        ApplyFilter((string)filterComboBox.SelectedItem);
                    }
                        
                    pagesListView.Invalidate();
                    UpdateNavigationButtons(currentPage);
                }
            }
        }

        private void CenterSearchResult(iText.Kernel.Geom.Rectangle resultRect, int pageNumber)
        {
            // Convert PDF coordinates to control coordinates (e.g. image or panel)
            int rotation = GetEffectiveRotationDegrees(pageNumber);
            RectangleF pdfCoordinates = ConvertPdfToViewCoordinates(new RectangleF(resultRect.GetX(), resultRect.GetY(), resultRect.GetWidth(), resultRect.GetHeight()), pageNumber, rotation);

            // Scale coordinates if using zoom
            RectangleF scaledRect = new RectangleF(pdfCoordinates.X * scaleFactor,
                                                   pdfCoordinates.Y * scaleFactor,
                                                   pdfCoordinates.Width * scaleFactor,
                                                   pdfCoordinates.Height * scaleFactor);

            // Calculate center point of selection
            float centerX = scaledRect.X + scaledRect.Width / 2;
            float centerY = scaledRect.Y + scaledRect.Height / 2;

            ZoomPanel panel = mainAppSplitContainer.Panel2.Controls[0] as ZoomPanel;

            // Get the visible area size of the control (e.g., Panel.ClientSize)
            Size clientSize = panel.ClientSize;

            // Calculate new scroll position: we want point centerX, centerY to be in center of control
            int scrollX = (int)(centerX - clientSize.Width / 2);
            int scrollY = (int)(centerY - clientSize.Height / 2);

            // Set AutoScrollPosition.
            // Note: AutoScrollPosition property interprets values as negative offsets.
            panel.AutoScrollPosition = new Point(scrollX, scrollY);
        }

        private ListViewItem FindListViewItemByPageNumber(int pageNumber)
        {
            return pagesListView.Items
                .Cast<ListViewItem>()
                .FirstOrDefault(item => ((PageItemStatus)item.Tag).PageNumber == pageNumber);
        }

        // Method navigates to specified instance (and changes page if necessary)
        private void GoToLocation(int index)
        {
            if (index < 0 || index >= searchLocations.Count)
                return;

            var location = searchLocations[index];
            if (location.PageNumber != currentPage)
            {
                // Change page
                currentPage = location.PageNumber;
                if ((string)filterComboBox.SelectedItem == allComboItem)
                {
                    pagesListView.Items[currentPage - 1].Selected = true;
                    pagesListView.Items[currentPage - 1].EnsureVisible();
                } else
                {
                    ListViewItem currentItem = FindListViewItemByPageNumber(currentPage);
                    if (currentItem != null)
                    {
                        currentItem.Selected = true;
                        currentItem.EnsureVisible();
                    }
                    else
                    {
                        pagesListView.SelectedItems.Clear();
                    }
                    ReloadRefreshCurrentPage();
                }

                // Update button states
                UpdateNavigationButtons(currentPage);
            }
            CenterSearchResult(location.Rect, location.PageNumber);
            currentLocationIndex = index;
            // Refresh drawing to change highlighting
            pdfViewer.Invalidate();
            UpdateSearchNavigationButtons();
        }


        private async void SearchText()
        {
            string search = searchTextBox.Text.Trim();
            if (!string.IsNullOrEmpty(search))
            {
                ClearSearchResult();
                //this.Cursor = Cursors.WaitCursor;
                groupBoxSearch.Enabled = false;
                searchLocations = await Task.Run(() => PdfTextSearcher.FindTextLocations(inputPdfPath, search, false, userPassword, this));
                groupBoxSearch.Enabled = true;
                searchTextBox.SelectAll();
                searchTextBox.Focus();
                searchResultLabel.Text = LocalizedFormat("Search_ResultCount", searchLocations.Count);
                foreach (var itemSl in searchLocations)
                {
                    if (itemSl is TextLocation searchLocation)
                    {
                        int pageNumber = searchLocation.PageNumber;
                        //UpdateItemTag(item, pageNumber, hasSelections, true, markedForDeletion, hasObjects);
                        

                        PageItemStatus status = allPageStatuses[pageNumber - 1];
                        status.HasSearchResults = true;

                        if ((string)filterComboBox.SelectedItem == allComboItem)
                        {
                            ListViewItem currentItem = pagesListView.Items[pageNumber - 1];
                            UpdateItemTag(currentItem, pageNumber, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                            pagesListView.Invalidate(currentItem.Bounds);
                        }

                    }

                    

                }

                if ((string)filterComboBox.SelectedItem != allComboItem)
                {
                    // rebuild list according to filter
                    ApplyFilter((string)filterComboBox.SelectedItem);
                }

                pdfViewer.Invalidate();
                if (searchLocations.Count == 0)
                {
                    MessageBox.Show(this, string.Format(Resources.Msg_SearchNotFound, search), Resources.Title_Info, MessageBoxButtons.OK, MessageBoxIcon.Information);
                    return;
                }
                else
                {
                    GoToLocation(0);
                }
            }
            searchTextBox.SelectAll();
            UpdateSearchNavigationButtons();
        }

